window.BIBLE = window.BIBLE || {};
window.BIBLE["Psalms"] = {"1":{"chapter":"1","title":"THE TWO WAYS — RIGHTEOUS AND WICKED","verses":{"1":{"text":"Blessed is the man that walketh not in the counsel of the ungodly, nor standeth in the way of sinners, nor sitteth in the seat of the scornful.","ref":"Psalms 1:1","synthesized":"Blessed is the man who does not walk in the counsel of the wicked, or set foot on the path of sinners, or sit in the seat of mockers.","sources":{"KJV":{"text":"Blessed is the man that walketh not in the counsel of the ungodly, nor standeth in the way of sinners, nor sitteth in the seat of the scornful."},"BSB":{"text":"Blessed is the man who does not walk in the counsel of the wicked, or set foot on the path of sinners, or sit in the seat of mockers."}},"definableWords":["blessed","man","walk","or"],"peopleInVerse":[]},"2":{"text":"But his delight is in the law of the LORD; and in his law doth he meditate day and night.","ref":"Psalms 1:2","synthesized":"But his delight is in the Law of the LORD, and on His law he meditates day and night.","sources":{"KJV":{"text":"But his delight is in the law of the LORD; and in his law doth he meditate day and night."},"BSB":{"text":"But his delight is in the Law of the LORD, and on His law he meditates day and night."}},"definableWords":["law","LORD","day","night"],"peopleInVerse":[]},"3":{"text":"And he shall be like a tree planted by the rivers of water, that bringeth forth his fruit in his season; his leaf also shall not wither; and whatsoever he doeth shall prosper.","ref":"Psalms 1:3","synthesized":"He is like a tree planted by streams of water, yielding its fruit in season, whose leaf does not wither, and who prospers in all he does.","sources":{"KJV":{"text":"And he shall be like a tree planted by the rivers of water, that bringeth forth his fruit in his season; his leaf also shall not wither; and whatsoever he doeth shall prosper."},"BSB":{"text":"He is like a tree planted by streams of water, yielding its fruit in season, whose leaf does not wither, and who prospers in all he does."}},"definableWords":["tree","water"],"peopleInVerse":[]},"4":{"text":"The ungodly are not so: but are like the chaff which the wind driveth away.","ref":"Psalms 1:4","synthesized":"Not so the wicked! For they are like chaff driven off by the wind.","sources":{"KJV":{"text":"The ungodly are not so: but are like the chaff which the wind driveth away."},"BSB":{"text":"Not so the wicked! For they are like chaff driven off by the wind."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Therefore the ungodly shall not stand in the judgment, nor sinners in the congregation of the righteous.","ref":"Psalms 1:5","synthesized":"Therefore the wicked will not stand in the judgment, nor sinners in the assembly of the righteous.","sources":{"KJV":{"text":"Therefore the ungodly shall not stand in the judgment, nor sinners in the congregation of the righteous."},"BSB":{"text":"Therefore the wicked will not stand in the judgment, nor sinners in the assembly of the righteous."}},"definableWords":["stand","judgment","righteous"],"peopleInVerse":[]},"6":{"text":"For the LORD knoweth the way of the righteous: but the way of the ungodly shall perish.","ref":"Psalms 1:6","synthesized":"For the LORD guards the path of the righteous, but the way of the wicked will perish.","sources":{"KJV":{"text":"For the LORD knoweth the way of the righteous: but the way of the ungodly shall perish."},"BSB":{"text":"For the LORD guards the path of the righteous, but the way of the wicked will perish."}},"definableWords":["LORD","righteous","way"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"THE MESSIAH AND THE NATIONS","verses":{"1":{"text":"Why do the heathen rage, and the people imagine a vain thing?","ref":"Psalms 2:1","synthesized":"Why do the nations rage and the peoples plot in vain?","sources":{"KJV":{"text":"Why do the heathen rage, and the people imagine a vain thing?"},"BSB":{"text":"Why do the nations rage and the peoples plot in vain?"}},"definableWords":["nations"],"peopleInVerse":[]},"2":{"text":"The kings of the earth set themselves, and the rulers take counsel together, against the LORD, and against his anointed, saying,","ref":"Psalms 2:2","synthesized":"The kings of the earth take their stand and the rulers gather together, against the LORD and against His Anointed One:","sources":{"KJV":{"text":"The kings of the earth set themselves, and the rulers take counsel together, against the LORD, and against his anointed, saying,"},"BSB":{"text":"The kings of the earth take their stand and the rulers gather together, against the LORD and against His Anointed One:"}},"definableWords":["kings","earth","stand","LORD","one"],"peopleInVerse":[]},"3":{"text":"Let us break their bands asunder, and cast away their cords from us.","ref":"Psalms 2:3","synthesized":"“Let us break Their chains and cast away Their cords.”","sources":{"KJV":{"text":"Let us break their bands asunder, and cast away their cords from us."},"BSB":{"text":"“Let us break Their chains and cast away Their cords.”"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"He that sitteth in the heavens shall laugh: the LORD shall have them in derision.","ref":"Psalms 2:4","synthesized":"The One enthroned in heaven laughs; the Lord taunts them.","sources":{"KJV":{"text":"He that sitteth in the heavens shall laugh: the LORD shall have them in derision."},"BSB":{"text":"The One enthroned in heaven laughs; the Lord taunts them."}},"definableWords":["one","heaven","Lord"],"peopleInVerse":[]},"5":{"text":"Then shall he speak unto them in his wrath, and vex them in his sore displeasure.","ref":"Psalms 2:5","synthesized":"Then He rebukes them in His anger, and terrifies them in His fury:","sources":{"KJV":{"text":"Then shall he speak unto them in his wrath, and vex them in his sore displeasure."},"BSB":{"text":"Then He rebukes them in His anger, and terrifies them in His fury:"}},"definableWords":["anger"],"peopleInVerse":[]},"6":{"text":"Yet have I set my king upon my holy hill of Zion.","ref":"Psalms 2:6","synthesized":"“I have installed My King on Zion, upon My holy mountain.”","sources":{"KJV":{"text":"Yet have I set my king upon my holy hill of Zion."},"BSB":{"text":"“I have installed My King on Zion, upon My holy mountain.”"}},"definableWords":["King","Zion","holy"],"peopleInVerse":[]},"7":{"text":"I will declare the decree: the LORD hath said unto me, Thou art my Son; this day have I begotten thee.","ref":"Psalms 2:7","synthesized":"I will proclaim the decree spoken to Me by the LORD: “You are My Son; today I have become Your Father.","sources":{"KJV":{"text":"I will declare the decree: the LORD hath said unto me, Thou art my Son; this day have I begotten thee."},"BSB":{"text":"I will proclaim the decree spoken to Me by the LORD: “You are My Son; today I have become Your Father."}},"definableWords":["LORD","Son","Father"],"peopleInVerse":[]},"8":{"text":"Ask of me, and I shall give thee the heathen for thine inheritance, and the uttermost parts of the earth for thy possession.","ref":"Psalms 2:8","synthesized":"Ask Me, and I will make the nations Your inheritance, the ends of the earth Your possession.","sources":{"KJV":{"text":"Ask of me, and I shall give thee the heathen for thine inheritance, and the uttermost parts of the earth for thy possession."},"BSB":{"text":"Ask Me, and I will make the nations Your inheritance, the ends of the earth Your possession."}},"definableWords":["make","nations","earth"],"peopleInVerse":[]},"9":{"text":"Thou shalt break them with a rod of iron; thou shalt dash them in pieces like a potter’s vessel.","ref":"Psalms 2:9","synthesized":"You will break them with an iron scepter; You will shatter them like pottery.”","sources":{"KJV":{"text":"Thou shalt break them with a rod of iron; thou shalt dash them in pieces like a potter’s vessel."},"BSB":{"text":"You will break them with an iron scepter; You will shatter them like pottery.”"}},"definableWords":["scepter"],"peopleInVerse":[]},"10":{"text":"Be wise now therefore, O ye kings: be instructed, ye judges of the earth.","ref":"Psalms 2:10","synthesized":"Therefore be wise, O kings; be admonished, O judges of the earth.","sources":{"KJV":{"text":"Be wise now therefore, O ye kings: be instructed, ye judges of the earth."},"BSB":{"text":"Therefore be wise, O kings; be admonished, O judges of the earth."}},"definableWords":["kings","earth"],"peopleInVerse":[]},"11":{"text":"Serve the LORD with fear, and rejoice with trembling.","ref":"Psalms 2:11","synthesized":"Serve the LORD with fear, and rejoice with trembling.","sources":{"KJV":{"text":"Serve the LORD with fear, and rejoice with trembling."},"BSB":{"text":"Serve the LORD with fear, and rejoice with trembling."}},"definableWords":["LORD","fear"],"peopleInVerse":[]},"12":{"text":"Kiss the Son, lest he be angry, and ye perish from the way, when his wrath is kindled but a little. Blessed are all they that put their trust in him.","ref":"Psalms 2:12","synthesized":"Kiss the Son, lest He be angry and you perish in your rebellion, when His wrath ignites in an instant.   Blessed are all who take refuge in Him.","sources":{"KJV":{"text":"Kiss the Son, lest he be angry, and ye perish from the way, when his wrath is kindled but a little. Blessed are all they that put their trust in him."},"BSB":{"text":"Kiss the Son, lest He be angry and you perish in your rebellion, when His wrath ignites in an instant.   Blessed are all who take refuge in Him."}},"definableWords":["Son","wrath","blessed"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"WHEN ENEMIES INCREASE","verses":{"1":{"text":"Lord, how are they increased that trouble me! many are they that rise up against me.","ref":"Psalms 3:1","synthesized":"O LORD, how my foes have increased! How many rise up against me!","sources":{"KJV":{"text":"Lord, how are they increased that trouble me! many are they that rise up against me."},"BSB":{"text":"O LORD, how my foes have increased! How many rise up against me!"}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"Many there be which say of my soul, There is no help for him in God. Selah.","ref":"Psalms 3:2","synthesized":"Many say of me, “God will not deliver him.” Selah","sources":{"KJV":{"text":"Many there be which say of my soul, There is no help for him in God. Selah."},"BSB":{"text":"Many say of me, “God will not deliver him.” Selah"}},"definableWords":["God","deliver"],"peopleInVerse":[]},"3":{"text":"But thou, O LORD, art a shield for me; my glory, and the lifter up of mine head.","ref":"Psalms 3:3","synthesized":"But You, O LORD, are a shield around me, my glory, and the One who lifts my head.","sources":{"KJV":{"text":"But thou, O LORD, art a shield for me; my glory, and the lifter up of mine head."},"BSB":{"text":"But You, O LORD, are a shield around me, my glory, and the One who lifts my head."}},"definableWords":["LORD","glory","one"],"peopleInVerse":[]},"4":{"text":"I cried unto the LORD with my voice, and he heard me out of his holy hill. Selah.","ref":"Psalms 3:4","synthesized":"To the LORD I cry aloud, and He answers me from His holy mountain. Selah","sources":{"KJV":{"text":"I cried unto the LORD with my voice, and he heard me out of his holy hill. Selah."},"BSB":{"text":"To the LORD I cry aloud, and He answers me from His holy mountain. Selah"}},"definableWords":["LORD","holy"],"peopleInVerse":[]},"5":{"text":"I laid me down and slept; I awaked; for the LORD sustained me.","ref":"Psalms 3:5","synthesized":"I lie down and sleep; I wake again, for the LORD sustains me.","sources":{"KJV":{"text":"I laid me down and slept; I awaked; for the LORD sustained me."},"BSB":{"text":"I lie down and sleep; I wake again, for the LORD sustains me."}},"definableWords":["LORD"],"peopleInVerse":[]},"6":{"text":"I will not be afraid of ten thousands of people, that have set themselves against me round about.","ref":"Psalms 3:6","synthesized":"I will not fear the myriads set against me on every side.","sources":{"KJV":{"text":"I will not be afraid of ten thousands of people, that have set themselves against me round about."},"BSB":{"text":"I will not fear the myriads set against me on every side."}},"definableWords":["fear"],"peopleInVerse":[]},"7":{"text":"Arise, O LORD; save me, O my God: for thou hast smitten all mine enemies upon the cheek bone; thou hast broken the teeth of the ungodly.","ref":"Psalms 3:7","synthesized":"Arise, O LORD! Save me, O my God! Strike all my enemies on the jaw; break the teeth of the wicked.","sources":{"KJV":{"text":"Arise, O LORD; save me, O my God: for thou hast smitten all mine enemies upon the cheek bone; thou hast broken the teeth of the ungodly."},"BSB":{"text":"Arise, O LORD! Save me, O my God! Strike all my enemies on the jaw; break the teeth of the wicked."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"8":{"text":"Salvation belongeth unto the LORD: thy blessing is upon thy people. Selah.","ref":"Psalms 3:8","synthesized":"Salvation belongs to the LORD; may Your blessing be on Your people. Selah","sources":{"KJV":{"text":"Salvation belongeth unto the LORD: thy blessing is upon thy people. Selah."},"BSB":{"text":"Salvation belongs to the LORD; may Your blessing be on Your people. Selah"}},"definableWords":["salvation","LORD","blessing","people"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"EVENING PRAYER OF PEACE","verses":{"1":{"text":"Hear me when I call, O God of my righteousness: thou hast enlarged me when I was in distress; have mercy upon me, and hear my prayer.","ref":"Psalms 4:1","synthesized":"Answer me when I call, O God of my righteousness! You have relieved my distress; show me grace and hear my prayer.","sources":{"KJV":{"text":"Hear me when I call, O God of my righteousness: thou hast enlarged me when I was in distress; have mercy upon me, and hear my prayer."},"BSB":{"text":"Answer me when I call, O God of my righteousness! You have relieved my distress; show me grace and hear my prayer."}},"definableWords":["God","righteousness","grace","hear","prayer"],"peopleInVerse":[]},"2":{"text":"O ye sons of men, how long will ye turn my glory into shame? how long will ye love vanity, and seek after leasing? Selah.","ref":"Psalms 4:2","synthesized":"How long, O men, will my honor be maligned? How long will you love vanity and seek after lies? Selah","sources":{"KJV":{"text":"O ye sons of men, how long will ye turn my glory into shame? how long will ye love vanity, and seek after leasing? Selah."},"BSB":{"text":"How long, O men, will my honor be maligned? How long will you love vanity and seek after lies? Selah"}},"definableWords":["men","love","seek"],"peopleInVerse":[]},"3":{"text":"But know that the LORD hath set apart him that is godly for himself: the LORD will hear when I call unto him.","ref":"Psalms 4:3","synthesized":"Know that the LORD has set apart the godly for Himself; the LORD hears when I call to Him.","sources":{"KJV":{"text":"But know that the LORD hath set apart him that is godly for himself: the LORD will hear when I call unto him."},"BSB":{"text":"Know that the LORD has set apart the godly for Himself; the LORD hears when I call to Him."}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"4":{"text":"Stand in awe, and sin not: commune with your own heart upon your bed, and be still. Selah.","ref":"Psalms 4:4","synthesized":"Be angry, yet do not sin; on your bed, search your heart and be still. Selah","sources":{"KJV":{"text":"Stand in awe, and sin not: commune with your own heart upon your bed, and be still. Selah."},"BSB":{"text":"Be angry, yet do not sin; on your bed, search your heart and be still. Selah"}},"definableWords":["sin","heart"],"peopleInVerse":[]},"5":{"text":"Offer the sacrifices of righteousness, and put your trust in the LORD.","ref":"Psalms 4:5","synthesized":"Offer the sacrifices of the righteous and trust in the LORD.","sources":{"KJV":{"text":"Offer the sacrifices of righteousness, and put your trust in the LORD."},"BSB":{"text":"Offer the sacrifices of the righteous and trust in the LORD."}},"definableWords":["righteous","trust","LORD"],"peopleInVerse":[]},"6":{"text":"There be many that say, Who will shew us any good? LORD, lift thou up the light of thy countenance upon us.","ref":"Psalms 4:6","synthesized":"Many ask, “Who can show us the good?” Shine the light of Your face upon us, O LORD.","sources":{"KJV":{"text":"There be many that say, Who will shew us any good? LORD, lift thou up the light of thy countenance upon us."},"BSB":{"text":"Many ask, “Who can show us the good?” Shine the light of Your face upon us, O LORD."}},"definableWords":["good","light","LORD"],"peopleInVerse":[]},"7":{"text":"Thou hast put gladness in my heart, more than in the time that their corn and their wine increased.","ref":"Psalms 4:7","synthesized":"You have filled my heart with more joy than when grain and new wine abound.","sources":{"KJV":{"text":"Thou hast put gladness in my heart, more than in the time that their corn and their wine increased."},"BSB":{"text":"You have filled my heart with more joy than when grain and new wine abound."}},"definableWords":["heart","joy"],"peopleInVerse":[]},"8":{"text":"I will both lay me down in peace, and sleep: for thou, LORD, only makest me dwell in safety.","ref":"Psalms 4:8","synthesized":"I will lie down and sleep in peace, for You alone, O LORD, make me dwell in safety.","sources":{"KJV":{"text":"I will both lay me down in peace, and sleep: for thou, LORD, only makest me dwell in safety."},"BSB":{"text":"I will lie down and sleep in peace, for You alone, O LORD, make me dwell in safety."}},"definableWords":["peace","LORD","make"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"MORNING PRAYER FOR GUIDANCE","verses":{"1":{"text":"Give ear to my words, O LORD, consider my meditation.","ref":"Psalms 5:1","synthesized":"Give ear to my words, O LORD; consider my groaning.","sources":{"KJV":{"text":"Give ear to my words, O LORD, consider my meditation."},"BSB":{"text":"Give ear to my words, O LORD; consider my groaning."}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"Hearken unto the voice of my cry, my King, and my God: for unto thee will I pray.","ref":"Psalms 5:2","synthesized":"Attend to the sound of my cry, my King and my God, for to You I pray.","sources":{"KJV":{"text":"Hearken unto the voice of my cry, my King, and my God: for unto thee will I pray."},"BSB":{"text":"Attend to the sound of my cry, my King and my God, for to You I pray."}},"definableWords":["King","God"],"peopleInVerse":[]},"3":{"text":"My voice shalt thou hear in the morning, O LORD; in the morning will I direct my prayer unto thee, and will look up.","ref":"Psalms 5:3","synthesized":"In the morning, O LORD, You hear my voice; at daybreak I lay my plea before You and wait in expectation.","sources":{"KJV":{"text":"My voice shalt thou hear in the morning, O LORD; in the morning will I direct my prayer unto thee, and will look up."},"BSB":{"text":"In the morning, O LORD, You hear my voice; at daybreak I lay my plea before You and wait in expectation."}},"definableWords":["LORD","hear","voice","wait"],"peopleInVerse":[]},"4":{"text":"For thou art not a God that hath pleasure in wickedness: neither shall evil dwell with thee.","ref":"Psalms 5:4","synthesized":"For You are not a God who delights in wickedness; no evil can dwell with You.","sources":{"KJV":{"text":"For thou art not a God that hath pleasure in wickedness: neither shall evil dwell with thee."},"BSB":{"text":"For You are not a God who delights in wickedness; no evil can dwell with You."}},"definableWords":["God","evil"],"peopleInVerse":[]},"5":{"text":"The foolish shall not stand in thy sight: thou hatest all workers of iniquity.","ref":"Psalms 5:5","synthesized":"The boastful cannot stand in Your presence; You hate all workers of iniquity.","sources":{"KJV":{"text":"The foolish shall not stand in thy sight: thou hatest all workers of iniquity."},"BSB":{"text":"The boastful cannot stand in Your presence; You hate all workers of iniquity."}},"definableWords":["stand","iniquity"],"peopleInVerse":[]},"6":{"text":"Thou shalt destroy them that speak leasing: the LORD will abhor the bloody and deceitful man.","ref":"Psalms 5:6","synthesized":"You destroy those who tell lies; the LORD abhors the man of bloodshed and deceit.","sources":{"KJV":{"text":"Thou shalt destroy them that speak leasing: the LORD will abhor the bloody and deceitful man."},"BSB":{"text":"You destroy those who tell lies; the LORD abhors the man of bloodshed and deceit."}},"definableWords":["LORD","man"],"peopleInVerse":[]},"7":{"text":"But as for me, I will come into thy house in the multitude of thy mercy: and in thy fear will I worship toward thy holy temple.","ref":"Psalms 5:7","synthesized":"But I will enter Your house by the abundance of Your loving devotion; in reverence I will bow down toward Your holy temple.","sources":{"KJV":{"text":"But as for me, I will come into thy house in the multitude of thy mercy: and in thy fear will I worship toward thy holy temple."},"BSB":{"text":"But I will enter Your house by the abundance of Your loving devotion; in reverence I will bow down toward Your holy temple."}},"definableWords":["house","holy","temple"],"peopleInVerse":[]},"8":{"text":"Lead me, O LORD, in thy righteousness because of mine enemies; make thy way straight before my face.","ref":"Psalms 5:8","synthesized":"Lead me, O LORD, in Your righteousness because of my enemies; make straight Your way before me.","sources":{"KJV":{"text":"Lead me, O LORD, in thy righteousness because of mine enemies; make thy way straight before my face."},"BSB":{"text":"Lead me, O LORD, in Your righteousness because of my enemies; make straight Your way before me."}},"definableWords":["LORD","righteousness","make","way"],"peopleInVerse":[]},"9":{"text":"For there is no faithfulness in their mouth; their inward part is very wickedness; their throat is an open sepulchre; they flatter with their tongue.","ref":"Psalms 5:9","synthesized":"For not a word they speak can be trusted; destruction lies within them. Their throats are open graves; their tongues practice deceit.","sources":{"KJV":{"text":"For there is no faithfulness in their mouth; their inward part is very wickedness; their throat is an open sepulchre; they flatter with their tongue."},"BSB":{"text":"For not a word they speak can be trusted; destruction lies within them. Their throats are open graves; their tongues practice deceit."}},"definableWords":["word"],"peopleInVerse":[]},"10":{"text":"Destroy thou them, O God; let them fall by their own counsels; cast them out in the multitude of their transgressions; for they have rebelled against thee.","ref":"Psalms 5:10","synthesized":"Declare them guilty, O God; let them fall by their own devices. Drive them out for their many transgressions, for they have rebelled against You.","sources":{"KJV":{"text":"Destroy thou them, O God; let them fall by their own counsels; cast them out in the multitude of their transgressions; for they have rebelled against thee."},"BSB":{"text":"Declare them guilty, O God; let them fall by their own devices. Drive them out for their many transgressions, for they have rebelled against You."}},"definableWords":["God"],"peopleInVerse":[]},"11":{"text":"But let all those that put their trust in thee rejoice: let them ever shout for joy, because thou defendest them: let them also that love thy name be joyful in thee.","ref":"Psalms 5:11","synthesized":"But let all who take refuge in You rejoice; let them ever shout for joy. May You shelter them, that those who love Your name may rejoice in You.","sources":{"KJV":{"text":"But let all those that put their trust in thee rejoice: let them ever shout for joy, because thou defendest them: let them also that love thy name be joyful in thee."},"BSB":{"text":"But let all who take refuge in You rejoice; let them ever shout for joy. May You shelter them, that those who love Your name may rejoice in You."}},"definableWords":["joy","love","name"],"peopleInVerse":[]},"12":{"text":"For thou, LORD, wilt bless the righteous; with favour wilt thou compass him as with a shield.","ref":"Psalms 5:12","synthesized":"For surely You, O LORD, bless the righteous; You surround them with the shield of Your favor.","sources":{"KJV":{"text":"For thou, LORD, wilt bless the righteous; with favour wilt thou compass him as with a shield."},"BSB":{"text":"For surely You, O LORD, bless the righteous; You surround them with the shield of Your favor."}},"definableWords":["LORD","bless","righteous"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"THE FIRST PENITENTIAL PSALM","verses":{"1":{"text":"O LORD, rebuke me not in thine anger, neither chasten me in thy hot displeasure.","ref":"Psalms 6:1","synthesized":"O LORD, do not rebuke me in Your anger or discipline me in Your wrath.","sources":{"KJV":{"text":"O LORD, rebuke me not in thine anger, neither chasten me in thy hot displeasure."},"BSB":{"text":"O LORD, do not rebuke me in Your anger or discipline me in Your wrath."}},"definableWords":["LORD","anger","or","wrath"],"peopleInVerse":[]},"2":{"text":"Have mercy upon me, O LORD; for I am weak: O LORD, heal me; for my bones are vexed.","ref":"Psalms 6:2","synthesized":"Be merciful to me, O LORD, for I am frail; heal me, O LORD, for my bones are in agony.","sources":{"KJV":{"text":"Have mercy upon me, O LORD; for I am weak: O LORD, heal me; for my bones are vexed."},"BSB":{"text":"Be merciful to me, O LORD, for I am frail; heal me, O LORD, for my bones are in agony."}},"definableWords":["LORD","heal","Lord","bones"],"peopleInVerse":[]},"3":{"text":"My soul is also sore vexed: but thou, O LORD, how long?","ref":"Psalms 6:3","synthesized":"My soul is deeply distressed. How long, O LORD, how long?","sources":{"KJV":{"text":"My soul is also sore vexed: but thou, O LORD, how long?"},"BSB":{"text":"My soul is deeply distressed. How long, O LORD, how long?"}},"definableWords":["soul","LORD"],"peopleInVerse":[]},"4":{"text":"Return, O LORD, deliver my soul: oh save me for thy mercies’ sake.","ref":"Psalms 6:4","synthesized":"Turn, O LORD, and deliver my soul; save me because of Your loving devotion.","sources":{"KJV":{"text":"Return, O LORD, deliver my soul: oh save me for thy mercies’ sake."},"BSB":{"text":"Turn, O LORD, and deliver my soul; save me because of Your loving devotion."}},"definableWords":["LORD","deliver","soul"],"peopleInVerse":[]},"5":{"text":"For in death there is no remembrance of thee: in the grave who shall give thee thanks?","ref":"Psalms 6:5","synthesized":"For there is no mention of You in death; who can praise You from Sheol?","sources":{"KJV":{"text":"For in death there is no remembrance of thee: in the grave who shall give thee thanks?"},"BSB":{"text":"For there is no mention of You in death; who can praise You from Sheol?"}},"definableWords":["death","praise"],"peopleInVerse":[]},"6":{"text":"I am weary with my groaning; all the night make I my bed to swim; I water my couch with my tears.","ref":"Psalms 6:6","synthesized":"I am weary from groaning; all night I flood my bed with weeping and drench my couch with tears.","sources":{"KJV":{"text":"I am weary with my groaning; all the night make I my bed to swim; I water my couch with my tears."},"BSB":{"text":"I am weary from groaning; all night I flood my bed with weeping and drench my couch with tears."}},"definableWords":["night","flood"],"peopleInVerse":[]},"7":{"text":"Mine eye is consumed because of grief; it waxeth old because of all mine enemies.","ref":"Psalms 6:7","synthesized":"My eyes fail from grief; they grow dim because of all my foes.","sources":{"KJV":{"text":"Mine eye is consumed because of grief; it waxeth old because of all mine enemies."},"BSB":{"text":"My eyes fail from grief; they grow dim because of all my foes."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Depart from me, all ye workers of iniquity; for the LORD hath heard the voice of my weeping.","ref":"Psalms 6:8","synthesized":"Depart from me, all you workers of iniquity, for the LORD has heard my weeping.","sources":{"KJV":{"text":"Depart from me, all ye workers of iniquity; for the LORD hath heard the voice of my weeping."},"BSB":{"text":"Depart from me, all you workers of iniquity, for the LORD has heard my weeping."}},"definableWords":["iniquity","LORD"],"peopleInVerse":[]},"9":{"text":"The LORD hath heard my supplication; the LORD will receive my prayer.","ref":"Psalms 6:9","synthesized":"The LORD has heard my cry for mercy; the LORD accepts my prayer.","sources":{"KJV":{"text":"The LORD hath heard my supplication; the LORD will receive my prayer."},"BSB":{"text":"The LORD has heard my cry for mercy; the LORD accepts my prayer."}},"definableWords":["LORD","mercy","Lord","prayer"],"peopleInVerse":[]},"10":{"text":"Let all mine enemies be ashamed and sore vexed: let them return and be ashamed suddenly.","ref":"Psalms 6:10","synthesized":"All my enemies will be ashamed and dismayed; they will turn back in sudden disgrace.","sources":{"KJV":{"text":"Let all mine enemies be ashamed and sore vexed: let them return and be ashamed suddenly."},"BSB":{"text":"All my enemies will be ashamed and dismayed; they will turn back in sudden disgrace."}},"definableWords":[],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"IN THEE DO I PUT MY TRUST","verses":{"1":{"text":"O LORD my God, in thee do I put my trust: save me from all them that persecute me, and deliver me:","ref":"Psalms 7:1","synthesized":"O LORD my God, I take refuge in You; save me and deliver me from all my pursuers,","sources":{"KJV":{"text":"O LORD my God, in thee do I put my trust: save me from all them that persecute me, and deliver me:"},"BSB":{"text":"O LORD my God, I take refuge in You; save me and deliver me from all my pursuers,"}},"definableWords":["LORD","God","deliver"],"peopleInVerse":[]},"2":{"text":"Lest he tear my soul like a lion, rending it in pieces, while there is none to deliver.","ref":"Psalms 7:2","synthesized":"or they will shred my soul like a lion and tear me to pieces with no one to rescue me.","sources":{"KJV":{"text":"Lest he tear my soul like a lion, rending it in pieces, while there is none to deliver."},"BSB":{"text":"or they will shred my soul like a lion and tear me to pieces with no one to rescue me."}},"definableWords":["or","soul","lion","one"],"peopleInVerse":[]},"3":{"text":"O LORD my God, if I have done this; if there be iniquity in my hands;","ref":"Psalms 7:3","synthesized":"O LORD my God, if I have done this, if injustice is on my hands,","sources":{"KJV":{"text":"O LORD my God, if I have done this; if there be iniquity in my hands;"},"BSB":{"text":"O LORD my God, if I have done this, if injustice is on my hands,"}},"definableWords":["LORD","God"],"peopleInVerse":[]},"4":{"text":"If I have rewarded evil unto him that was at peace with me; (yea, I have delivered him that without cause is mine enemy:)","ref":"Psalms 7:4","synthesized":"if I have rewarded my ally with evil, if I have plundered my foe without cause,","sources":{"KJV":{"text":"If I have rewarded evil unto him that was at peace with me; (yea, I have delivered him that without cause is mine enemy:)"},"BSB":{"text":"if I have rewarded my ally with evil, if I have plundered my foe without cause,"}},"definableWords":["evil"],"peopleInVerse":[]},"5":{"text":"Let the enemy persecute my soul, and take it; yea, let him tread down my life upon the earth, and lay mine honour in the dust. Selah.","ref":"Psalms 7:5","synthesized":"then may my enemy pursue me and overtake me; may he trample me to the ground and leave my honor in the dust. Selah","sources":{"KJV":{"text":"Let the enemy persecute my soul, and take it; yea, let him tread down my life upon the earth, and lay mine honour in the dust. Selah."},"BSB":{"text":"then may my enemy pursue me and overtake me; may he trample me to the ground and leave my honor in the dust. Selah"}},"definableWords":["ground"],"peopleInVerse":[]},"6":{"text":"Arise, O LORD, in thine anger, lift up thyself because of the rage of mine enemies: and awake for me to the judgment that thou hast commanded.","ref":"Psalms 7:6","synthesized":"Arise, O LORD, in Your anger; rise up against the fury of my enemies. Awake, my God, and ordain judgment.","sources":{"KJV":{"text":"Arise, O LORD, in thine anger, lift up thyself because of the rage of mine enemies: and awake for me to the judgment that thou hast commanded."},"BSB":{"text":"Arise, O LORD, in Your anger; rise up against the fury of my enemies. Awake, my God, and ordain judgment."}},"definableWords":["LORD","anger","God","judgment"],"peopleInVerse":[]},"7":{"text":"So shall the congregation of the people compass thee about: for their sakes therefore return thou on high.","ref":"Psalms 7:7","synthesized":"Let the assembled peoples gather around You; take Your seat over them on high.","sources":{"KJV":{"text":"So shall the congregation of the people compass thee about: for their sakes therefore return thou on high."},"BSB":{"text":"Let the assembled peoples gather around You; take Your seat over them on high."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"The LORD shall judge the people: judge me, O LORD, according to my righteousness, and according to mine integrity that is in me.","ref":"Psalms 7:8","synthesized":"The LORD judges the peoples; vindicate me, O LORD, according to my righteousness and integrity.","sources":{"KJV":{"text":"The LORD shall judge the people: judge me, O LORD, according to my righteousness, and according to mine integrity that is in me."},"BSB":{"text":"The LORD judges the peoples; vindicate me, O LORD, according to my righteousness and integrity."}},"definableWords":["LORD","Lord","righteousness"],"peopleInVerse":[]},"9":{"text":"Oh let the wickedness of the wicked come to an end; but establish the just: for the righteous God trieth the hearts and reins.","ref":"Psalms 7:9","synthesized":"Put an end to the evil of the wicked, but establish the righteous, O righteous God who searches hearts and minds.","sources":{"KJV":{"text":"Oh let the wickedness of the wicked come to an end; but establish the just: for the righteous God trieth the hearts and reins."},"BSB":{"text":"Put an end to the evil of the wicked, but establish the righteous, O righteous God who searches hearts and minds."}},"definableWords":["evil","righteous","God"],"peopleInVerse":[]},"10":{"text":"My defence is of God, which saveth the upright in heart.","ref":"Psalms 7:10","synthesized":"My shield is with God, who saves the upright in heart.","sources":{"KJV":{"text":"My defence is of God, which saveth the upright in heart."},"BSB":{"text":"My shield is with God, who saves the upright in heart."}},"definableWords":["God","heart"],"peopleInVerse":[]},"11":{"text":"God judgeth the righteous, and God is angry with the wicked every day.","ref":"Psalms 7:11","synthesized":"God is a righteous judge and a God who feels indignation each day.","sources":{"KJV":{"text":"God judgeth the righteous, and God is angry with the wicked every day."},"BSB":{"text":"God is a righteous judge and a God who feels indignation each day."}},"definableWords":["God","righteous","day"],"peopleInVerse":[]},"12":{"text":"If he turn not, he will whet his sword; he hath bent his bow, and made it ready.","ref":"Psalms 7:12","synthesized":"If one does not repent, God will sharpen His sword; He has bent and strung His bow.","sources":{"KJV":{"text":"If he turn not, he will whet his sword; he hath bent his bow, and made it ready."},"BSB":{"text":"If one does not repent, God will sharpen His sword; He has bent and strung His bow."}},"definableWords":["one","God"],"peopleInVerse":[]},"13":{"text":"He hath also prepared for him the instruments of death; he ordaineth his arrows against the persecutors.","ref":"Psalms 7:13","synthesized":"He has prepared His deadly weapons; He ordains His arrows with fire.","sources":{"KJV":{"text":"He hath also prepared for him the instruments of death; he ordaineth his arrows against the persecutors."},"BSB":{"text":"He has prepared His deadly weapons; He ordains His arrows with fire."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Behold, he travaileth with iniquity, and hath conceived mischief, and brought forth falsehood.","ref":"Psalms 7:14","synthesized":"Behold, the wicked man travails with evil; he conceives trouble and births falsehood.","sources":{"KJV":{"text":"Behold, he travaileth with iniquity, and hath conceived mischief, and brought forth falsehood."},"BSB":{"text":"Behold, the wicked man travails with evil; he conceives trouble and births falsehood."}},"definableWords":["man","evil"],"peopleInVerse":[]},"15":{"text":"He made a pit, and digged it, and is fallen into the ditch which he made.","ref":"Psalms 7:15","synthesized":"He has dug a hole and hollowed it out; he has fallen into a pit of his own making.","sources":{"KJV":{"text":"He made a pit, and digged it, and is fallen into the ditch which he made."},"BSB":{"text":"He has dug a hole and hollowed it out; he has fallen into a pit of his own making."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"His mischief shall return upon his own head, and his violent dealing shall come down upon his own pate.","ref":"Psalms 7:16","synthesized":"His trouble recoils on himself, and his violence falls on his own head.","sources":{"KJV":{"text":"His mischief shall return upon his own head, and his violent dealing shall come down upon his own pate."},"BSB":{"text":"His trouble recoils on himself, and his violence falls on his own head."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"I will praise the LORD according to his righteousness: and will sing praise to the name of the LORD most high.","ref":"Psalms 7:17","synthesized":"I will thank the LORD for His righteousness and sing praise to the name of the LORD Most High.","sources":{"KJV":{"text":"I will praise the LORD according to his righteousness: and will sing praise to the name of the LORD most high."},"BSB":{"text":"I will thank the LORD for His righteousness and sing praise to the name of the LORD Most High."}},"definableWords":["LORD","righteousness","praise","name","Lord"],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"WHAT IS MAN?","verses":{"1":{"text":"O LORD, our Lord, how excellent is thy name in all the earth! who hast set thy glory above the heavens.","ref":"Psalms 8:1","synthesized":"O LORD, our Lord, how majestic is Your name in all the earth!   You have set Your glory above the heavens.","sources":{"KJV":{"text":"O LORD, our Lord, how excellent is thy name in all the earth! who hast set thy glory above the heavens."},"BSB":{"text":"O LORD, our Lord, how majestic is Your name in all the earth!   You have set Your glory above the heavens."}},"definableWords":["LORD","Lord","name","earth","glory","heavens"],"peopleInVerse":[]},"2":{"text":"Out of the mouth of babes and sucklings hast thou ordained strength because of thine enemies, that thou mightest still the enemy and the avenger.","ref":"Psalms 8:2","synthesized":"From the mouths of children and infants You have ordained praise on account of Your adversaries, to silence the enemy and avenger.","sources":{"KJV":{"text":"Out of the mouth of babes and sucklings hast thou ordained strength because of thine enemies, that thou mightest still the enemy and the avenger."},"BSB":{"text":"From the mouths of children and infants You have ordained praise on account of Your adversaries, to silence the enemy and avenger."}},"definableWords":["praise"],"peopleInVerse":[]},"3":{"text":"When I consider thy heavens, the work of thy fingers, the moon and the stars, which thou hast ordained;","ref":"Psalms 8:3","synthesized":"When I behold Your heavens, the work of Your fingers, the moon and the stars, which You have set in place—","sources":{"KJV":{"text":"When I consider thy heavens, the work of thy fingers, the moon and the stars, which thou hast ordained;"},"BSB":{"text":"When I behold Your heavens, the work of Your fingers, the moon and the stars, which You have set in place—"}},"definableWords":["heavens","work"],"peopleInVerse":[]},"4":{"text":"What is man, that thou art mindful of him? and the son of man, that thou visitest him?","ref":"Psalms 8:4","synthesized":"what is man that You are mindful of him, or the son of man that You care for him?","sources":{"KJV":{"text":"What is man, that thou art mindful of him? and the son of man, that thou visitest him?"},"BSB":{"text":"what is man that You are mindful of him, or the son of man that You care for him?"}},"definableWords":["man","or","son"],"peopleInVerse":[]},"5":{"text":"For thou hast made him a little lower than the angels, and hast crowned him with glory and honour.","ref":"Psalms 8:5","synthesized":"You made him a little lower than the angels; You crowned him with glory and honor.","sources":{"KJV":{"text":"For thou hast made him a little lower than the angels, and hast crowned him with glory and honour."},"BSB":{"text":"You made him a little lower than the angels; You crowned him with glory and honor."}},"definableWords":["made","glory"],"peopleInVerse":[]},"6":{"text":"Thou madest him to have dominion over the works of thy hands; thou hast put all things under his feet:","ref":"Psalms 8:6","synthesized":"You made him ruler of the works of Your hands; You have placed everything under his feet:","sources":{"KJV":{"text":"Thou madest him to have dominion over the works of thy hands; thou hast put all things under his feet:"},"BSB":{"text":"You made him ruler of the works of Your hands; You have placed everything under his feet:"}},"definableWords":["made","ruler","works"],"peopleInVerse":[]},"7":{"text":"All sheep and oxen, yea, and the beasts of the field;","ref":"Psalms 8:7","synthesized":"all sheep and oxen, and even the beasts of the field,","sources":{"KJV":{"text":"All sheep and oxen, yea, and the beasts of the field;"},"BSB":{"text":"all sheep and oxen, and even the beasts of the field,"}},"definableWords":["field"],"peopleInVerse":[]},"8":{"text":"The fowl of the air, and the fish of the sea, and whatsoever passeth through the paths of the seas.","ref":"Psalms 8:8","synthesized":"the birds of the air and the fish of the sea, all that swim the paths of the seas.","sources":{"KJV":{"text":"The fowl of the air, and the fish of the sea, and whatsoever passeth through the paths of the seas."},"BSB":{"text":"the birds of the air and the fish of the sea, all that swim the paths of the seas."}},"definableWords":["birds","fish","sea","seas"],"peopleInVerse":[]},"9":{"text":"O LORD our Lord, how excellent is thy name in all the earth!","ref":"Psalms 8:9","synthesized":"O LORD, our Lord, how majestic is Your name in all the earth!","sources":{"KJV":{"text":"O LORD our Lord, how excellent is thy name in all the earth!"},"BSB":{"text":"O LORD, our Lord, how majestic is Your name in all the earth!"}},"definableWords":["LORD","Lord","name","earth"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"I WILL PRAISE WITH MY WHOLE HEART","verses":{"1":{"text":"I will praise thee, O LORD, with my whole heart; I will shew forth all thy marvellous works.","ref":"Psalms 9:1","synthesized":"I will give thanks to the LORD with all my heart; I will recount all Your wonders.","sources":{"KJV":{"text":"I will praise thee, O LORD, with my whole heart; I will shew forth all thy marvellous works."},"BSB":{"text":"I will give thanks to the LORD with all my heart; I will recount all Your wonders."}},"definableWords":["LORD","heart"],"peopleInVerse":[]},"2":{"text":"I will be glad and rejoice in thee: I will sing praise to thy name, O thou most High.","ref":"Psalms 9:2","synthesized":"I will be glad and rejoice in You; I will sing praise to Your name, O Most High.","sources":{"KJV":{"text":"I will be glad and rejoice in thee: I will sing praise to thy name, O thou most High."},"BSB":{"text":"I will be glad and rejoice in You; I will sing praise to Your name, O Most High."}},"definableWords":["praise","name"],"peopleInVerse":[]},"3":{"text":"When mine enemies are turned back, they shall fall and perish at thy presence.","ref":"Psalms 9:3","synthesized":"When my enemies retreat, they stumble and perish before You.","sources":{"KJV":{"text":"When mine enemies are turned back, they shall fall and perish at thy presence."},"BSB":{"text":"When my enemies retreat, they stumble and perish before You."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"For thou hast maintained my right and my cause; thou satest in the throne judging right.","ref":"Psalms 9:4","synthesized":"For You have upheld my just cause; You sit on Your throne judging righteously.","sources":{"KJV":{"text":"For thou hast maintained my right and my cause; thou satest in the throne judging right."},"BSB":{"text":"For You have upheld my just cause; You sit on Your throne judging righteously."}},"definableWords":["throne"],"peopleInVerse":[]},"5":{"text":"Thou hast rebuked the heathen, thou hast destroyed the wicked, thou hast put out their name for ever and ever.","ref":"Psalms 9:5","synthesized":"You have rebuked the nations; You have destroyed the wicked; You have erased their name forever and ever.","sources":{"KJV":{"text":"Thou hast rebuked the heathen, thou hast destroyed the wicked, thou hast put out their name for ever and ever."},"BSB":{"text":"You have rebuked the nations; You have destroyed the wicked; You have erased their name forever and ever."}},"definableWords":["nations","name"],"peopleInVerse":[]},"6":{"text":"O thou enemy, destructions are come to a perpetual end: and thou hast destroyed cities; their memorial is perished with them.","ref":"Psalms 9:6","synthesized":"The enemy has come to eternal ruin, and You have uprooted their cities; the very memory of them has vanished.","sources":{"KJV":{"text":"O thou enemy, destructions are come to a perpetual end: and thou hast destroyed cities; their memorial is perished with them."},"BSB":{"text":"The enemy has come to eternal ruin, and You have uprooted their cities; the very memory of them has vanished."}},"definableWords":["eternal"],"peopleInVerse":[]},"7":{"text":"But the LORD shall endure for ever: he hath prepared his throne for judgment.","ref":"Psalms 9:7","synthesized":"But the LORD abides forever; He has established His throne for judgment.","sources":{"KJV":{"text":"But the LORD shall endure for ever: he hath prepared his throne for judgment."},"BSB":{"text":"But the LORD abides forever; He has established His throne for judgment."}},"definableWords":["LORD","throne","judgment"],"peopleInVerse":[]},"8":{"text":"And he shall judge the world in righteousness, he shall minister judgment to the people in uprightness.","ref":"Psalms 9:8","synthesized":"He judges the world with justice; He governs the people with equity.","sources":{"KJV":{"text":"And he shall judge the world in righteousness, he shall minister judgment to the people in uprightness."},"BSB":{"text":"He judges the world with justice; He governs the people with equity."}},"definableWords":["justice","people"],"peopleInVerse":[]},"9":{"text":"The LORD also will be a refuge for the oppressed, a refuge in times of trouble.","ref":"Psalms 9:9","synthesized":"The LORD is a refuge for the oppressed, a stronghold in times of trouble.","sources":{"KJV":{"text":"The LORD also will be a refuge for the oppressed, a refuge in times of trouble."},"BSB":{"text":"The LORD is a refuge for the oppressed, a stronghold in times of trouble."}},"definableWords":["LORD"],"peopleInVerse":[]},"10":{"text":"And they that know thy name will put their trust in thee: for thou, LORD, hast not forsaken them that seek thee.","ref":"Psalms 9:10","synthesized":"Those who know Your name trust in You, for You, O LORD, have not forsaken those who seek You.","sources":{"KJV":{"text":"And they that know thy name will put their trust in thee: for thou, LORD, hast not forsaken them that seek thee."},"BSB":{"text":"Those who know Your name trust in You, for You, O LORD, have not forsaken those who seek You."}},"definableWords":["name","trust","LORD","seek"],"peopleInVerse":[]},"11":{"text":"Sing praises to the LORD, which dwelleth in Zion: declare among the people his doings.","ref":"Psalms 9:11","synthesized":"Sing praises to the LORD, who dwells in Zion; proclaim His deeds among the nations.","sources":{"KJV":{"text":"Sing praises to the LORD, which dwelleth in Zion: declare among the people his doings."},"BSB":{"text":"Sing praises to the LORD, who dwells in Zion; proclaim His deeds among the nations."}},"definableWords":["LORD","Zion","nations"],"peopleInVerse":[]},"12":{"text":"When he maketh inquisition for blood, he remembereth them: he forgetteth not the cry of the humble.","ref":"Psalms 9:12","synthesized":"For the Avenger of bloodshed remembers; He does not ignore the cry of the afflicted.","sources":{"KJV":{"text":"When he maketh inquisition for blood, he remembereth them: he forgetteth not the cry of the humble."},"BSB":{"text":"For the Avenger of bloodshed remembers; He does not ignore the cry of the afflicted."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Have mercy upon me, O LORD; consider my trouble which I suffer of them that hate me, thou that liftest me up from the gates of death:","ref":"Psalms 9:13","synthesized":"Be merciful to me, O LORD; see how my enemies afflict me! Lift me up from the gates of death,","sources":{"KJV":{"text":"Have mercy upon me, O LORD; consider my trouble which I suffer of them that hate me, thou that liftest me up from the gates of death:"},"BSB":{"text":"Be merciful to me, O LORD; see how my enemies afflict me! Lift me up from the gates of death,"}},"definableWords":["LORD","see","death"],"peopleInVerse":[]},"14":{"text":"That I may shew forth all thy praise in the gates of the daughter of Zion: I will rejoice in thy salvation.","ref":"Psalms 9:14","synthesized":"that I may declare all Your praises— that within the gates of Daughter Zion I may rejoice in Your salvation.","sources":{"KJV":{"text":"That I may shew forth all thy praise in the gates of the daughter of Zion: I will rejoice in thy salvation."},"BSB":{"text":"that I may declare all Your praises— that within the gates of Daughter Zion I may rejoice in Your salvation."}},"definableWords":["daughter","Zion","salvation"],"peopleInVerse":[]},"15":{"text":"The heathen are sunk down in the pit that they made: in the net which they hid is their own foot taken.","ref":"Psalms 9:15","synthesized":"The nations have fallen into a pit of their making; their feet are caught in the net they have hidden.","sources":{"KJV":{"text":"The heathen are sunk down in the pit that they made: in the net which they hid is their own foot taken."},"BSB":{"text":"The nations have fallen into a pit of their making; their feet are caught in the net they have hidden."}},"definableWords":["nations"],"peopleInVerse":[]},"16":{"text":"The LORD is known by the judgment which he executeth: the wicked is snared in the work of his own hands. Higgaion. Selah.","ref":"Psalms 9:16","synthesized":"The LORD is known by the justice He brings; the wicked are ensnared by the work of their hands. Higgaion Selah","sources":{"KJV":{"text":"The LORD is known by the judgment which he executeth: the wicked is snared in the work of his own hands. Higgaion. Selah."},"BSB":{"text":"The LORD is known by the justice He brings; the wicked are ensnared by the work of their hands. Higgaion Selah"}},"definableWords":["LORD","justice","work"],"peopleInVerse":[]},"17":{"text":"The wicked shall be turned into hell, and all the nations that forget God.","ref":"Psalms 9:17","synthesized":"The wicked will return to Sheol— all the nations who forget God.","sources":{"KJV":{"text":"The wicked shall be turned into hell, and all the nations that forget God."},"BSB":{"text":"The wicked will return to Sheol— all the nations who forget God."}},"definableWords":["nations","God"],"peopleInVerse":[]},"18":{"text":"For the needy shall not alway be forgotten: the expectation of the poor shall not perish for ever.","ref":"Psalms 9:18","synthesized":"For the needy will not always be forgotten; nor the hope of the oppressed forever dashed.","sources":{"KJV":{"text":"For the needy shall not alway be forgotten: the expectation of the poor shall not perish for ever."},"BSB":{"text":"For the needy will not always be forgotten; nor the hope of the oppressed forever dashed."}},"definableWords":["hope"],"peopleInVerse":[]},"19":{"text":"Arise, O LORD; let not man prevail: let the heathen be judged in thy sight.","ref":"Psalms 9:19","synthesized":"Rise up, O LORD, do not let man prevail; let the nations be judged in Your presence.","sources":{"KJV":{"text":"Arise, O LORD; let not man prevail: let the heathen be judged in thy sight."},"BSB":{"text":"Rise up, O LORD, do not let man prevail; let the nations be judged in Your presence."}},"definableWords":["LORD","man","nations"],"peopleInVerse":[]},"20":{"text":"Put them in fear, O LORD: that the nations may know themselves to be but men. Selah.","ref":"Psalms 9:20","synthesized":"Lay terror upon them, O LORD; let the nations know they are but men. Selah","sources":{"KJV":{"text":"Put them in fear, O LORD: that the nations may know themselves to be but men. Selah."},"BSB":{"text":"Lay terror upon them, O LORD; let the nations know they are but men. Selah"}},"definableWords":["LORD","nations","men"],"peopleInVerse":[]}}},"10":{"chapter":"10","title":"WHY STANDEST THOU AFAR OFF?","verses":{"1":{"text":"Why standest thou afar off, O LORD? why hidest thou thyself in times of trouble?","ref":"Psalms 10:1","synthesized":"Why, O LORD, do You stand far off? Why do You hide in times of trouble?","sources":{"KJV":{"text":"Why standest thou afar off, O LORD? why hidest thou thyself in times of trouble?"},"BSB":{"text":"Why, O LORD, do You stand far off? Why do You hide in times of trouble?"}},"definableWords":["LORD","stand"],"peopleInVerse":[]},"2":{"text":"The wicked in his pride doth persecute the poor: let them be taken in the devices that they have imagined.","ref":"Psalms 10:2","synthesized":"In pride the wicked pursue the needy; let them be caught in the schemes they devise.","sources":{"KJV":{"text":"The wicked in his pride doth persecute the poor: let them be taken in the devices that they have imagined."},"BSB":{"text":"In pride the wicked pursue the needy; let them be caught in the schemes they devise."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"For the wicked boasteth of his heart’s desire, and blesseth the covetous, whom the LORD abhorreth.","ref":"Psalms 10:3","synthesized":"For the wicked man boasts in the cravings of his heart; he blesses the greedy and reviles the LORD.","sources":{"KJV":{"text":"For the wicked boasteth of his heart’s desire, and blesseth the covetous, whom the LORD abhorreth."},"BSB":{"text":"For the wicked man boasts in the cravings of his heart; he blesses the greedy and reviles the LORD."}},"definableWords":["man","heart","LORD"],"peopleInVerse":[]},"4":{"text":"The wicked, through the pride of his countenance, will not seek after God: God is not in all his thoughts.","ref":"Psalms 10:4","synthesized":"In his pride the wicked man does not seek Him; in all his schemes there is no God.","sources":{"KJV":{"text":"The wicked, through the pride of his countenance, will not seek after God: God is not in all his thoughts."},"BSB":{"text":"In his pride the wicked man does not seek Him; in all his schemes there is no God."}},"definableWords":["man","seek","God"],"peopleInVerse":[]},"5":{"text":"His ways are always grievous; thy judgments are far above out of his sight: as for all his enemies, he puffeth at them.","ref":"Psalms 10:5","synthesized":"He is secure in his ways at all times; Your lofty judgments are far from him; he sneers at all his foes.","sources":{"KJV":{"text":"His ways are always grievous; thy judgments are far above out of his sight: as for all his enemies, he puffeth at them."},"BSB":{"text":"He is secure in his ways at all times; Your lofty judgments are far from him; he sneers at all his foes."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"He hath said in his heart, I shall not be moved: for I shall never be in adversity.","ref":"Psalms 10:6","synthesized":"He says to himself, “I will not be moved; from age to age I am free of distress.”","sources":{"KJV":{"text":"He hath said in his heart, I shall not be moved: for I shall never be in adversity."},"BSB":{"text":"He says to himself, “I will not be moved; from age to age I am free of distress.”"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"His mouth is full of cursing and deceit and fraud: under his tongue is mischief and vanity.","ref":"Psalms 10:7","synthesized":"His mouth is full of cursing, deceit, and violence; trouble and malice are under his tongue.","sources":{"KJV":{"text":"His mouth is full of cursing and deceit and fraud: under his tongue is mischief and vanity."},"BSB":{"text":"His mouth is full of cursing, deceit, and violence; trouble and malice are under his tongue."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"He sitteth in the lurking places of the villages: in the secret places doth he murder the innocent: his eyes are privily set against the poor.","ref":"Psalms 10:8","synthesized":"He lies in wait near the villages; in ambush he slays the innocent; his eyes watch in stealth for the helpless.","sources":{"KJV":{"text":"He sitteth in the lurking places of the villages: in the secret places doth he murder the innocent: his eyes are privily set against the poor."},"BSB":{"text":"He lies in wait near the villages; in ambush he slays the innocent; his eyes watch in stealth for the helpless."}},"definableWords":["wait"],"peopleInVerse":[]},"9":{"text":"He lieth in wait secretly as a lion in his den: he lieth in wait to catch the poor: he doth catch the poor, when he draweth him into his net.","ref":"Psalms 10:9","synthesized":"He lies in wait like a lion in a thicket; he lurks to seize the oppressed; he catches the lowly in his net.","sources":{"KJV":{"text":"He lieth in wait secretly as a lion in his den: he lieth in wait to catch the poor: he doth catch the poor, when he draweth him into his net."},"BSB":{"text":"He lies in wait like a lion in a thicket; he lurks to seize the oppressed; he catches the lowly in his net."}},"definableWords":["wait","lion"],"peopleInVerse":[]},"10":{"text":"He croucheth, and humbleth himself, that the poor may fall by his strong ones.","ref":"Psalms 10:10","synthesized":"They are crushed and beaten down; the hapless fall prey to his strength.","sources":{"KJV":{"text":"He croucheth, and humbleth himself, that the poor may fall by his strong ones."},"BSB":{"text":"They are crushed and beaten down; the hapless fall prey to his strength."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"He hath said in his heart, God hath forgotten: he hideth his face; he will never see it.","ref":"Psalms 10:11","synthesized":"He says to himself, “God has forgotten; He hides His face and never sees.”","sources":{"KJV":{"text":"He hath said in his heart, God hath forgotten: he hideth his face; he will never see it."},"BSB":{"text":"He says to himself, “God has forgotten; He hides His face and never sees.”"}},"definableWords":["God"],"peopleInVerse":[]},"12":{"text":"Arise, O LORD; O God, lift up thine hand: forget not the humble.","ref":"Psalms 10:12","synthesized":"Arise, O LORD! Lift up Your hand, O God! Do not forget the helpless.","sources":{"KJV":{"text":"Arise, O LORD; O God, lift up thine hand: forget not the humble."},"BSB":{"text":"Arise, O LORD! Lift up Your hand, O God! Do not forget the helpless."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"13":{"text":"Wherefore doth the wicked contemn God? he hath said in his heart, Thou wilt not require it.","ref":"Psalms 10:13","synthesized":"Why has the wicked man renounced God? He says to himself, “You will never call me to account.”","sources":{"KJV":{"text":"Wherefore doth the wicked contemn God? he hath said in his heart, Thou wilt not require it."},"BSB":{"text":"Why has the wicked man renounced God? He says to himself, “You will never call me to account.”"}},"definableWords":["man","God"],"peopleInVerse":[]},"14":{"text":"Thou hast seen it; for thou beholdest mischief and spite, to requite it with thy hand: the poor committeth himself unto thee; thou art the helper of the fatherless.","ref":"Psalms 10:14","synthesized":"But You have regarded trouble and grief; You see to repay it by Your hand. The victim entrusts himself to You; You are the helper of the fatherless.","sources":{"KJV":{"text":"Thou hast seen it; for thou beholdest mischief and spite, to requite it with thy hand: the poor committeth himself unto thee; thou art the helper of the fatherless."},"BSB":{"text":"But You have regarded trouble and grief; You see to repay it by Your hand. The victim entrusts himself to You; You are the helper of the fatherless."}},"definableWords":["see","helper"],"peopleInVerse":[]},"15":{"text":"Break thou the arm of the wicked and the evil man: seek out his wickedness till thou find none.","ref":"Psalms 10:15","synthesized":"Break the arm of the wicked and evildoer; call him to account for his wickedness until none is left to be found.","sources":{"KJV":{"text":"Break thou the arm of the wicked and the evil man: seek out his wickedness till thou find none."},"BSB":{"text":"Break the arm of the wicked and evildoer; call him to account for his wickedness until none is left to be found."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"The LORD is King for ever and ever: the heathen are perished out of his land.","ref":"Psalms 10:16","synthesized":"The LORD is King forever and ever; the nations perish from His land.","sources":{"KJV":{"text":"The LORD is King for ever and ever: the heathen are perished out of his land."},"BSB":{"text":"The LORD is King forever and ever; the nations perish from His land."}},"definableWords":["LORD","King","nations","land"],"peopleInVerse":[]},"17":{"text":"LORD, thou hast heard the desire of the humble: thou wilt prepare their heart, thou wilt cause thine ear to hear:","ref":"Psalms 10:17","synthesized":"You have heard, O LORD, the desire of the humble; You will strengthen their hearts. You will incline Your ear,","sources":{"KJV":{"text":"LORD, thou hast heard the desire of the humble: thou wilt prepare their heart, thou wilt cause thine ear to hear:"},"BSB":{"text":"You have heard, O LORD, the desire of the humble; You will strengthen their hearts. You will incline Your ear,"}},"definableWords":["LORD"],"peopleInVerse":[]},"18":{"text":"To judge the fatherless and the oppressed, that the man of the earth may no more oppress.","ref":"Psalms 10:18","synthesized":"to vindicate the fatherless and oppressed, that the men of the earth may strike terror no more.","sources":{"KJV":{"text":"To judge the fatherless and the oppressed, that the man of the earth may no more oppress."},"BSB":{"text":"to vindicate the fatherless and oppressed, that the men of the earth may strike terror no more."}},"definableWords":["men","earth"],"peopleInVerse":[]}}},"11":{"chapter":"11","title":"IN THE LORD I PUT MY TRUST","verses":{"1":{"text":"In the LORD put I my trust: how say ye to my soul, Flee as a bird to your mountain?","ref":"Psalms 11:1","synthesized":"In the LORD I take refuge. How then can you say to me:   “Flee like a bird to your mountain!","sources":{"KJV":{"text":"In the LORD put I my trust: how say ye to my soul, Flee as a bird to your mountain?"},"BSB":{"text":"In the LORD I take refuge. How then can you say to me:   “Flee like a bird to your mountain!"}},"definableWords":["LORD","bird"],"peopleInVerse":[]},"2":{"text":"For, lo, the wicked bend their bow, they make ready their arrow upon the string, that they may privily shoot at the upright in heart.","ref":"Psalms 11:2","synthesized":"For behold, the wicked bend their bows. They set their arrow on the string to shoot from the shadows at the upright in heart.","sources":{"KJV":{"text":"For, lo, the wicked bend their bow, they make ready their arrow upon the string, that they may privily shoot at the upright in heart."},"BSB":{"text":"For behold, the wicked bend their bows. They set their arrow on the string to shoot from the shadows at the upright in heart."}},"definableWords":["heart"],"peopleInVerse":[]},"3":{"text":"If the foundations be destroyed, what can the righteous do?","ref":"Psalms 11:3","synthesized":"If the foundations are destroyed, what can the righteous do?”","sources":{"KJV":{"text":"If the foundations be destroyed, what can the righteous do?"},"BSB":{"text":"If the foundations are destroyed, what can the righteous do?”"}},"definableWords":["righteous"],"peopleInVerse":[]},"4":{"text":"The LORD is in his holy temple, the LORD’s throne is in heaven: his eyes behold, his eyelids try, the children of men.","ref":"Psalms 11:4","synthesized":"The LORD is in His holy temple; the LORD is on His heavenly throne. His eyes are watching closely; they examine the sons of men.","sources":{"KJV":{"text":"The LORD is in his holy temple, the LORD’s throne is in heaven: his eyes behold, his eyelids try, the children of men."},"BSB":{"text":"The LORD is in His holy temple; the LORD is on His heavenly throne. His eyes are watching closely; they examine the sons of men."}},"definableWords":["LORD","holy","temple","Lord","throne","sons","men"],"peopleInVerse":[]},"5":{"text":"The LORD trieth the righteous: but the wicked and him that loveth violence his soul hateth.","ref":"Psalms 11:5","synthesized":"The LORD tests the righteous and the wicked; His soul hates the lover of violence.","sources":{"KJV":{"text":"The LORD trieth the righteous: but the wicked and him that loveth violence his soul hateth."},"BSB":{"text":"The LORD tests the righteous and the wicked; His soul hates the lover of violence."}},"definableWords":["LORD","righteous","soul"],"peopleInVerse":[]},"6":{"text":"Upon the wicked he shall rain snares, fire and brimstone, and an horrible tempest: this shall be the portion of their cup.","ref":"Psalms 11:6","synthesized":"On the wicked He will rain down fiery coals and sulfur; a scorching wind will be their portion.","sources":{"KJV":{"text":"Upon the wicked he shall rain snares, fire and brimstone, and an horrible tempest: this shall be the portion of their cup."},"BSB":{"text":"On the wicked He will rain down fiery coals and sulfur; a scorching wind will be their portion."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"For the righteous LORD loveth righteousness; his countenance doth behold the upright.","ref":"Psalms 11:7","synthesized":"For the LORD is righteous; He loves justice. The upright will see His face.","sources":{"KJV":{"text":"For the righteous LORD loveth righteousness; his countenance doth behold the upright."},"BSB":{"text":"For the LORD is righteous; He loves justice. The upright will see His face."}},"definableWords":["LORD","righteous","justice","see"],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"THE PURE WORDS OF THE LORD","verses":{"1":{"text":"Help, LORD; for the godly man ceaseth; for the faithful fail from among the children of men.","ref":"Psalms 12:1","synthesized":"Help, O LORD, for the godly are no more; the faithful have vanished from among men.","sources":{"KJV":{"text":"Help, LORD; for the godly man ceaseth; for the faithful fail from among the children of men."},"BSB":{"text":"Help, O LORD, for the godly are no more; the faithful have vanished from among men."}},"definableWords":["LORD","men"],"peopleInVerse":[]},"2":{"text":"They speak vanity every one with his neighbour: with flattering lips and with a double heart do they speak.","ref":"Psalms 12:2","synthesized":"They lie to one another; they speak with flattering lips and a double heart.","sources":{"KJV":{"text":"They speak vanity every one with his neighbour: with flattering lips and with a double heart do they speak."},"BSB":{"text":"They lie to one another; they speak with flattering lips and a double heart."}},"definableWords":["one","heart"],"peopleInVerse":[]},"3":{"text":"The LORD shall cut off all flattering lips, and the tongue that speaketh proud things:","ref":"Psalms 12:3","synthesized":"May the LORD cut off all flattering lips and every boastful tongue.","sources":{"KJV":{"text":"The LORD shall cut off all flattering lips, and the tongue that speaketh proud things:"},"BSB":{"text":"May the LORD cut off all flattering lips and every boastful tongue."}},"definableWords":["LORD"],"peopleInVerse":[]},"4":{"text":"Who have said, With our tongue will we prevail; our lips are our own: who is lord over us?","ref":"Psalms 12:4","synthesized":"They say, “With our tongues we will prevail. We own our lips—who can be our master?”","sources":{"KJV":{"text":"Who have said, With our tongue will we prevail; our lips are our own: who is lord over us?"},"BSB":{"text":"They say, “With our tongues we will prevail. We own our lips—who can be our master?”"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"For the oppression of the poor, for the sighing of the needy, now will I arise, saith the LORD; I will set him in safety from him that puffeth at him.","ref":"Psalms 12:5","synthesized":"“For the cause of the oppressed and for the groaning of the needy, I will now arise,” says the LORD. “I will bring safety to him who yearns.”","sources":{"KJV":{"text":"For the oppression of the poor, for the sighing of the needy, now will I arise, saith the LORD; I will set him in safety from him that puffeth at him."},"BSB":{"text":"“For the cause of the oppressed and for the groaning of the needy, I will now arise,” says the LORD. “I will bring safety to him who yearns.”"}},"definableWords":["LORD"],"peopleInVerse":[]},"6":{"text":"The words of the LORD are pure words: as silver tried in a furnace of earth, purified seven times.","ref":"Psalms 12:6","synthesized":"The words of the LORD are flawless, like silver refined in a furnace, like gold purified sevenfold.","sources":{"KJV":{"text":"The words of the LORD are pure words: as silver tried in a furnace of earth, purified seven times."},"BSB":{"text":"The words of the LORD are flawless, like silver refined in a furnace, like gold purified sevenfold."}},"definableWords":["LORD"],"peopleInVerse":[]},"7":{"text":"Thou shalt keep them, O LORD, thou shalt preserve them from this generation for ever.","ref":"Psalms 12:7","synthesized":"You, O LORD, will keep us; You will forever guard us from this generation.","sources":{"KJV":{"text":"Thou shalt keep them, O LORD, thou shalt preserve them from this generation for ever."},"BSB":{"text":"You, O LORD, will keep us; You will forever guard us from this generation."}},"definableWords":["LORD","keep"],"peopleInVerse":[]},"8":{"text":"The wicked walk on every side, when the vilest men are exalted.","ref":"Psalms 12:8","synthesized":"The wicked wander freely, and vileness is exalted among men.","sources":{"KJV":{"text":"The wicked walk on every side, when the vilest men are exalted."},"BSB":{"text":"The wicked wander freely, and vileness is exalted among men."}},"definableWords":["men"],"peopleInVerse":[]}}},"13":{"chapter":"13","title":"HOW LONG, O LORD?","verses":{"1":{"text":"How long wilt thou forget me, O LORD? for ever? how long wilt thou hide thy face from me?","ref":"Psalms 13:1","synthesized":"How long, O LORD? Will You forget me forever? How long will You hide Your face from me?","sources":{"KJV":{"text":"How long wilt thou forget me, O LORD? for ever? how long wilt thou hide thy face from me?"},"BSB":{"text":"How long, O LORD? Will You forget me forever? How long will You hide Your face from me?"}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"How long shall I take counsel in my soul, having sorrow in my heart daily? how long shall mine enemy be exalted over me?","ref":"Psalms 13:2","synthesized":"How long must I wrestle in my soul, with sorrow in my heart each day? How long will my enemy dominate me?","sources":{"KJV":{"text":"How long shall I take counsel in my soul, having sorrow in my heart daily? how long shall mine enemy be exalted over me?"},"BSB":{"text":"How long must I wrestle in my soul, with sorrow in my heart each day? How long will my enemy dominate me?"}},"definableWords":["soul","heart","day"],"peopleInVerse":[]},"3":{"text":"Consider and hear me, O LORD my God: lighten mine eyes, lest I sleep the sleep of death;","ref":"Psalms 13:3","synthesized":"Consider me and respond, O LORD my God. Give light to my eyes, lest I sleep in death,","sources":{"KJV":{"text":"Consider and hear me, O LORD my God: lighten mine eyes, lest I sleep the sleep of death;"},"BSB":{"text":"Consider me and respond, O LORD my God. Give light to my eyes, lest I sleep in death,"}},"definableWords":["LORD","God","light","death"],"peopleInVerse":[]},"4":{"text":"Lest mine enemy say, I have prevailed against him; and those that trouble me rejoice when I am moved.","ref":"Psalms 13:4","synthesized":"lest my enemy say, “I have overcome him,” and my foes rejoice when I fall.","sources":{"KJV":{"text":"Lest mine enemy say, I have prevailed against him; and those that trouble me rejoice when I am moved."},"BSB":{"text":"lest my enemy say, “I have overcome him,” and my foes rejoice when I fall."}},"definableWords":["overcome"],"peopleInVerse":[]},"5":{"text":"But I have trusted in thy mercy; my heart shall rejoice in thy salvation.","ref":"Psalms 13:5","synthesized":"But I have trusted in Your loving devotion; my heart will rejoice in Your salvation.","sources":{"KJV":{"text":"But I have trusted in thy mercy; my heart shall rejoice in thy salvation."},"BSB":{"text":"But I have trusted in Your loving devotion; my heart will rejoice in Your salvation."}},"definableWords":["heart","salvation"],"peopleInVerse":[]},"6":{"text":"I will sing unto the LORD, because he hath dealt bountifully with me.","ref":"Psalms 13:6","synthesized":"I will sing to the LORD, for He has been good to me.","sources":{"KJV":{"text":"I will sing unto the LORD, because he hath dealt bountifully with me."},"BSB":{"text":"I will sing to the LORD, for He has been good to me."}},"definableWords":["LORD","good"],"peopleInVerse":[]}}},"14":{"chapter":"14","title":"THE FOOL HATH SAID — NO GOD","verses":{"1":{"text":"The fool hath said in his heart, There is no God. They are corrupt, they have done abominable works, there is none that doeth good.","ref":"Psalms 14:1","synthesized":"The fool says in his heart, “There is no God.”   They are corrupt; their acts are vile. There is no one who does good.","sources":{"KJV":{"text":"The fool hath said in his heart, There is no God. They are corrupt, they have done abominable works, there is none that doeth good."},"BSB":{"text":"The fool says in his heart, “There is no God.”   They are corrupt; their acts are vile. There is no one who does good."}},"definableWords":["fool","heart","God","one","good"],"peopleInVerse":[]},"2":{"text":"The LORD looked down from heaven upon the children of men, to see if there were any that did understand, and seek God.","ref":"Psalms 14:2","synthesized":"The LORD looks down from heaven upon the sons of men to see if any understand, if any seek God.","sources":{"KJV":{"text":"The LORD looked down from heaven upon the children of men, to see if there were any that did understand, and seek God."},"BSB":{"text":"The LORD looks down from heaven upon the sons of men to see if any understand, if any seek God."}},"definableWords":["LORD","heaven","sons","men","see","seek","God"],"peopleInVerse":[]},"3":{"text":"They are all gone aside, they are all together become filthy: there is none that doeth good, no, not one.","ref":"Psalms 14:3","synthesized":"All have turned away, they have together become corrupt; there is no one who does good, not even one.","sources":{"KJV":{"text":"They are all gone aside, they are all together become filthy: there is none that doeth good, no, not one."},"BSB":{"text":"All have turned away, they have together become corrupt; there is no one who does good, not even one."}},"definableWords":["one","good"],"peopleInVerse":[]},"4":{"text":"Have all the workers of iniquity no knowledge? who eat up my people as they eat bread, and call not upon the LORD.","ref":"Psalms 14:4","synthesized":"Will the workers of iniquity never learn?   They devour my people like bread; they refuse to call upon the LORD.","sources":{"KJV":{"text":"Have all the workers of iniquity no knowledge? who eat up my people as they eat bread, and call not upon the LORD."},"BSB":{"text":"Will the workers of iniquity never learn?   They devour my people like bread; they refuse to call upon the LORD."}},"definableWords":["iniquity","people","LORD"],"peopleInVerse":[]},"5":{"text":"There were they in great fear: for God is in the generation of the righteous.","ref":"Psalms 14:5","synthesized":"There they are, overwhelmed with dread, for God is in the company of the righteous.","sources":{"KJV":{"text":"There were they in great fear: for God is in the generation of the righteous."},"BSB":{"text":"There they are, overwhelmed with dread, for God is in the company of the righteous."}},"definableWords":["God","righteous"],"peopleInVerse":[]},"6":{"text":"Ye have shamed the counsel of the poor, because the LORD is his refuge.","ref":"Psalms 14:6","synthesized":"You sinners frustrate the plans of the oppressed, yet the LORD is their shelter.","sources":{"KJV":{"text":"Ye have shamed the counsel of the poor, because the LORD is his refuge."},"BSB":{"text":"You sinners frustrate the plans of the oppressed, yet the LORD is their shelter."}},"definableWords":["LORD"],"peopleInVerse":[]},"7":{"text":"Oh that the salvation of Israel were come out of Zion! when the LORD bringeth back the captivity of his people, Jacob shall rejoice, and Israel shall be glad.","ref":"Psalms 14:7","synthesized":"Oh, that the salvation of Israel would come from Zion!   When the LORD restores His captive people, let Jacob rejoice, let Israel be glad!","sources":{"KJV":{"text":"Oh that the salvation of Israel were come out of Zion! when the LORD bringeth back the captivity of his people, Jacob shall rejoice, and Israel shall be glad."},"BSB":{"text":"Oh, that the salvation of Israel would come from Zion!   When the LORD restores His captive people, let Jacob rejoice, let Israel be glad!"}},"definableWords":["salvation","Israel","Zion","LORD","people","Jacob"],"peopleInVerse":["Jacob"]}}},"15":{"chapter":"15","title":"WHO SHALL ABIDE IN THY TABERNACLE?","verses":{"1":{"text":"Lord, who shall abide in thy tabernacle? who shall dwell in thy holy hill?","ref":"Psalms 15:1","synthesized":"O LORD, who may abide in Your tent? Who may dwell on Your holy mountain?","sources":{"KJV":{"text":"Lord, who shall abide in thy tabernacle? who shall dwell in thy holy hill?"},"BSB":{"text":"O LORD, who may abide in Your tent? Who may dwell on Your holy mountain?"}},"definableWords":["LORD","abide","holy"],"peopleInVerse":[]},"2":{"text":"He that walketh uprightly, and worketh righteousness, and speaketh the truth in his heart.","ref":"Psalms 15:2","synthesized":"He who walks with integrity and practices righteousness, who speaks the truth from his heart,","sources":{"KJV":{"text":"He that walketh uprightly, and worketh righteousness, and speaketh the truth in his heart."},"BSB":{"text":"He who walks with integrity and practices righteousness, who speaks the truth from his heart,"}},"definableWords":["righteousness","truth","heart"],"peopleInVerse":[]},"3":{"text":"He that backbiteth not with his tongue, nor doeth evil to his neighbour, nor taketh up a reproach against his neighbour.","ref":"Psalms 15:3","synthesized":"who has no slander on his tongue, who does no harm to his neighbor, who casts no scorn on his friend,","sources":{"KJV":{"text":"He that backbiteth not with his tongue, nor doeth evil to his neighbour, nor taketh up a reproach against his neighbour."},"BSB":{"text":"who has no slander on his tongue, who does no harm to his neighbor, who casts no scorn on his friend,"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"In whose eyes a vile person is contemned; but he honoureth them that fear the LORD. He that sweareth to his own hurt, and changeth not.","ref":"Psalms 15:4","synthesized":"who despises the vile but honors those who fear the LORD, who does not revise a costly oath,","sources":{"KJV":{"text":"In whose eyes a vile person is contemned; but he honoureth them that fear the LORD. He that sweareth to his own hurt, and changeth not."},"BSB":{"text":"who despises the vile but honors those who fear the LORD, who does not revise a costly oath,"}},"definableWords":["fear","LORD"],"peopleInVerse":[]},"5":{"text":"He that putteth not out his money to usury, nor taketh reward against the innocent. He that doeth these things shall never be moved.","ref":"Psalms 15:5","synthesized":"who lends his money without interest and refuses a bribe against the innocent.   He who does these things will never be shaken.","sources":{"KJV":{"text":"He that putteth not out his money to usury, nor taketh reward against the innocent. He that doeth these things shall never be moved."},"BSB":{"text":"who lends his money without interest and refuses a bribe against the innocent.   He who does these things will never be shaken."}},"definableWords":[],"peopleInVerse":[]}}},"16":{"chapter":"16","title":"THOU WILT NOT LEAVE MY SOUL IN HELL","verses":{"1":{"text":"Preserve me, O God: for in thee do I put my trust.","ref":"Psalms 16:1","synthesized":"Preserve me, O God, for in You I take refuge.","sources":{"KJV":{"text":"Preserve me, O God: for in thee do I put my trust."},"BSB":{"text":"Preserve me, O God, for in You I take refuge."}},"definableWords":["God"],"peopleInVerse":[]},"2":{"text":"O my soul, thou hast said unto the LORD, Thou art my Lord: my goodness extendeth not to thee;","ref":"Psalms 16:2","synthesized":"I said to the LORD, “You are my Lord; apart from You I have no good thing.”","sources":{"KJV":{"text":"O my soul, thou hast said unto the LORD, Thou art my Lord: my goodness extendeth not to thee;"},"BSB":{"text":"I said to the LORD, “You are my Lord; apart from You I have no good thing.”"}},"definableWords":["LORD","Lord","good"],"peopleInVerse":[]},"3":{"text":"But to the saints that are in the earth, and to the excellent, in whom is all my delight.","ref":"Psalms 16:3","synthesized":"As for the saints in the land, they are the excellence in whom all my delight resides.","sources":{"KJV":{"text":"But to the saints that are in the earth, and to the excellent, in whom is all my delight."},"BSB":{"text":"As for the saints in the land, they are the excellence in whom all my delight resides."}},"definableWords":["land"],"peopleInVerse":[]},"4":{"text":"Their sorrows shall be multiplied that hasten after another god: their drink offerings of blood will I not offer, nor take up their names into my lips.","ref":"Psalms 16:4","synthesized":"Sorrows will multiply to those who chase other gods. I will not pour out their libations of blood, or speak their names with my lips.","sources":{"KJV":{"text":"Their sorrows shall be multiplied that hasten after another god: their drink offerings of blood will I not offer, nor take up their names into my lips."},"BSB":{"text":"Sorrows will multiply to those who chase other gods. I will not pour out their libations of blood, or speak their names with my lips."}},"definableWords":["multiply","blood","or"],"peopleInVerse":[]},"5":{"text":"The LORD is the portion of mine inheritance and of my cup: thou maintainest my lot.","ref":"Psalms 16:5","synthesized":"The LORD is my chosen portion and my cup; You have made my lot secure.","sources":{"KJV":{"text":"The LORD is the portion of mine inheritance and of my cup: thou maintainest my lot."},"BSB":{"text":"The LORD is my chosen portion and my cup; You have made my lot secure."}},"definableWords":["LORD","made","Lot"],"peopleInVerse":[]},"6":{"text":"The lines are fallen unto me in pleasant places; yea, I have a goodly heritage.","ref":"Psalms 16:6","synthesized":"The lines of my boundary have fallen in pleasant places; surely my inheritance is delightful.","sources":{"KJV":{"text":"The lines are fallen unto me in pleasant places; yea, I have a goodly heritage."},"BSB":{"text":"The lines of my boundary have fallen in pleasant places; surely my inheritance is delightful."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"I will bless the LORD, who hath given me counsel: my reins also instruct me in the night seasons.","ref":"Psalms 16:7","synthesized":"I will bless the LORD who counsels me; even at night my conscience instructs me.","sources":{"KJV":{"text":"I will bless the LORD, who hath given me counsel: my reins also instruct me in the night seasons."},"BSB":{"text":"I will bless the LORD who counsels me; even at night my conscience instructs me."}},"definableWords":["bless","LORD","night"],"peopleInVerse":[]},"8":{"text":"I have set the LORD always before me: because he is at my right hand, I shall not be moved.","ref":"Psalms 16:8","synthesized":"I have set the LORD always before me. Because He is at my right hand, I will not be shaken.","sources":{"KJV":{"text":"I have set the LORD always before me: because he is at my right hand, I shall not be moved."},"BSB":{"text":"I have set the LORD always before me. Because He is at my right hand, I will not be shaken."}},"definableWords":["LORD"],"peopleInVerse":[]},"9":{"text":"Therefore my heart is glad, and my glory rejoiceth: my flesh also shall rest in hope.","ref":"Psalms 16:9","synthesized":"Therefore my heart is glad and my tongue rejoices; my body also will dwell securely.","sources":{"KJV":{"text":"Therefore my heart is glad, and my glory rejoiceth: my flesh also shall rest in hope."},"BSB":{"text":"Therefore my heart is glad and my tongue rejoices; my body also will dwell securely."}},"definableWords":["heart"],"peopleInVerse":[]},"10":{"text":"For thou wilt not leave my soul in hell; neither wilt thou suffer thine Holy One to see corruption.","ref":"Psalms 16:10","synthesized":"For You will not abandon my soul to Sheol, nor will You let Your Holy One see decay.","sources":{"KJV":{"text":"For thou wilt not leave my soul in hell; neither wilt thou suffer thine Holy One to see corruption."},"BSB":{"text":"For You will not abandon my soul to Sheol, nor will You let Your Holy One see decay."}},"definableWords":["soul","holy","one","see"],"peopleInVerse":[]},"11":{"text":"Thou wilt shew me the path of life: in thy presence is fulness of joy; at thy right hand there are pleasures for evermore.","ref":"Psalms 16:11","synthesized":"You have made known to me the path of life; You will fill me with joy in Your presence, with eternal pleasures at Your right hand.","sources":{"KJV":{"text":"Thou wilt shew me the path of life: in thy presence is fulness of joy; at thy right hand there are pleasures for evermore."},"BSB":{"text":"You have made known to me the path of life; You will fill me with joy in Your presence, with eternal pleasures at Your right hand."}},"definableWords":["made","life","fill","joy","eternal"],"peopleInVerse":[]}}},"17":{"chapter":"17","title":"HEAR THE RIGHT, O LORD","verses":{"1":{"text":"Hear the right, O LORD, attend unto my cry, give ear unto my prayer, that goeth not out of feigned lips.","ref":"Psalms 17:1","synthesized":"Hear, O LORD, my righteous plea; listen to my cry. Give ear to my prayer— it comes from lips free of deceit.","sources":{"KJV":{"text":"Hear the right, O LORD, attend unto my cry, give ear unto my prayer, that goeth not out of feigned lips."},"BSB":{"text":"Hear, O LORD, my righteous plea; listen to my cry. Give ear to my prayer— it comes from lips free of deceit."}},"definableWords":["hear","LORD","righteous","prayer"],"peopleInVerse":[]},"2":{"text":"Let my sentence come forth from thy presence; let thine eyes behold the things that are equal.","ref":"Psalms 17:2","synthesized":"May my vindication come from Your presence; may Your eyes see what is right.","sources":{"KJV":{"text":"Let my sentence come forth from thy presence; let thine eyes behold the things that are equal."},"BSB":{"text":"May my vindication come from Your presence; may Your eyes see what is right."}},"definableWords":["see"],"peopleInVerse":[]},"3":{"text":"Thou hast proved mine heart; thou hast visited me in the night; thou hast tried me, and shalt find nothing; I am purposed that my mouth shall not transgress.","ref":"Psalms 17:3","synthesized":"You have tried my heart; You have visited me in the night. You have tested me and found no evil; I have resolved not to sin with my mouth.","sources":{"KJV":{"text":"Thou hast proved mine heart; thou hast visited me in the night; thou hast tried me, and shalt find nothing; I am purposed that my mouth shall not transgress."},"BSB":{"text":"You have tried my heart; You have visited me in the night. You have tested me and found no evil; I have resolved not to sin with my mouth."}},"definableWords":["heart","night","evil","sin"],"peopleInVerse":[]},"4":{"text":"Concerning the works of men, by the word of thy lips I have kept me from the paths of the destroyer.","ref":"Psalms 17:4","synthesized":"As for the deeds of men— by the word of Your lips I have avoided the ways of the violent.","sources":{"KJV":{"text":"Concerning the works of men, by the word of thy lips I have kept me from the paths of the destroyer."},"BSB":{"text":"As for the deeds of men— by the word of Your lips I have avoided the ways of the violent."}},"definableWords":["men","word"],"peopleInVerse":[]},"5":{"text":"Hold up my goings in thy paths, that my footsteps slip not.","ref":"Psalms 17:5","synthesized":"My steps have held to Your paths; my feet have not slipped.","sources":{"KJV":{"text":"Hold up my goings in thy paths, that my footsteps slip not."},"BSB":{"text":"My steps have held to Your paths; my feet have not slipped."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"I have called upon thee, for thou wilt hear me, O God: incline thine ear unto me, and hear my speech.","ref":"Psalms 17:6","synthesized":"I call on You, O God, for You will answer me. Incline Your ear to me; hear my words.","sources":{"KJV":{"text":"I have called upon thee, for thou wilt hear me, O God: incline thine ear unto me, and hear my speech."},"BSB":{"text":"I call on You, O God, for You will answer me. Incline Your ear to me; hear my words."}},"definableWords":["God","hear"],"peopleInVerse":[]},"7":{"text":"Shew thy marvellous lovingkindness, O thou that savest by thy right hand them which put their trust in thee from those that rise up against them.","ref":"Psalms 17:7","synthesized":"Show the wonders of Your loving devotion, You who save by Your right hand those who seek refuge from their foes.","sources":{"KJV":{"text":"Shew thy marvellous lovingkindness, O thou that savest by thy right hand them which put their trust in thee from those that rise up against them."},"BSB":{"text":"Show the wonders of Your loving devotion, You who save by Your right hand those who seek refuge from their foes."}},"definableWords":["seek"],"peopleInVerse":[]},"8":{"text":"Keep me as the apple of the eye, hide me under the shadow of thy wings,","ref":"Psalms 17:8","synthesized":"Keep me as the apple of Your eye; hide me in the shadow of Your wings","sources":{"KJV":{"text":"Keep me as the apple of the eye, hide me under the shadow of thy wings,"},"BSB":{"text":"Keep me as the apple of Your eye; hide me in the shadow of Your wings"}},"definableWords":["keep"],"peopleInVerse":[]},"9":{"text":"From the wicked that oppress me, from my deadly enemies, who compass me about.","ref":"Psalms 17:9","synthesized":"from the wicked who assail me, from my mortal enemies who surround me.","sources":{"KJV":{"text":"From the wicked that oppress me, from my deadly enemies, who compass me about."},"BSB":{"text":"from the wicked who assail me, from my mortal enemies who surround me."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"They are inclosed in their own fat: with their mouth they speak proudly.","ref":"Psalms 17:10","synthesized":"They have closed their callous hearts; their mouths speak with arrogance.","sources":{"KJV":{"text":"They are inclosed in their own fat: with their mouth they speak proudly."},"BSB":{"text":"They have closed their callous hearts; their mouths speak with arrogance."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"They have now compassed us in our steps: they have set their eyes bowing down to the earth;","ref":"Psalms 17:11","synthesized":"They have tracked us down, and now surround us; their eyes are set to cast us to the ground,","sources":{"KJV":{"text":"They have now compassed us in our steps: they have set their eyes bowing down to the earth;"},"BSB":{"text":"They have tracked us down, and now surround us; their eyes are set to cast us to the ground,"}},"definableWords":["ground"],"peopleInVerse":[]},"12":{"text":"Like as a lion that is greedy of his prey, and as it were a young lion lurking in secret places.","ref":"Psalms 17:12","synthesized":"like a lion greedy for prey, like a young lion lurking in ambush.","sources":{"KJV":{"text":"Like as a lion that is greedy of his prey, and as it were a young lion lurking in secret places."},"BSB":{"text":"like a lion greedy for prey, like a young lion lurking in ambush."}},"definableWords":["lion"],"peopleInVerse":[]},"13":{"text":"Arise, O LORD, disappoint him, cast him down: deliver my soul from the wicked, which is thy sword:","ref":"Psalms 17:13","synthesized":"Arise, O LORD, confront them! Bring them to their knees; deliver me from the wicked by Your sword,","sources":{"KJV":{"text":"Arise, O LORD, disappoint him, cast him down: deliver my soul from the wicked, which is thy sword:"},"BSB":{"text":"Arise, O LORD, confront them! Bring them to their knees; deliver me from the wicked by Your sword,"}},"definableWords":["LORD","deliver"],"peopleInVerse":[]},"14":{"text":"From men which are thy hand, O LORD, from men of the world, which have their portion in this life, and whose belly thou fillest with thy hid treasure: they are full of children, and leave the rest of their substance to their babes.","ref":"Psalms 17:14","synthesized":"from such men, O LORD, by Your hand— from men of the world whose portion is in this life. May You fill the bellies of Your treasured ones and satisfy their sons, so they leave their abundance to their children.","sources":{"KJV":{"text":"From men which are thy hand, O LORD, from men of the world, which have their portion in this life, and whose belly thou fillest with thy hid treasure: they are full of children, and leave the rest of their substance to their babes."},"BSB":{"text":"from such men, O LORD, by Your hand— from men of the world whose portion is in this life. May You fill the bellies of Your treasured ones and satisfy their sons, so they leave their abundance to their children."}},"definableWords":["men","LORD","life","fill","sons"],"peopleInVerse":[]},"15":{"text":"As for me, I will behold thy face in righteousness: I shall be satisfied, when I awake, with thy likeness.","ref":"Psalms 17:15","synthesized":"As for me, I will behold Your face in righteousness; when I awake, I will be satisfied in Your presence.","sources":{"KJV":{"text":"As for me, I will behold thy face in righteousness: I shall be satisfied, when I awake, with thy likeness."},"BSB":{"text":"As for me, I will behold Your face in righteousness; when I awake, I will be satisfied in Your presence."}},"definableWords":["righteousness"],"peopleInVerse":[]}}},"18":{"chapter":"18","title":"DAVID'S DELIVERANCE SONG","verses":{"1":{"text":"I will love thee, O LORD, my strength.","ref":"Psalms 18:1","synthesized":"I love You, O LORD, my strength.","sources":{"KJV":{"text":"I will love thee, O LORD, my strength."},"BSB":{"text":"I love You, O LORD, my strength."}},"definableWords":["love","LORD"],"peopleInVerse":[]},"2":{"text":"The LORD is my rock, and my fortress, and my deliverer; my God, my strength, in whom I will trust; my buckler, and the horn of my salvation, and my high tower.","ref":"Psalms 18:2","synthesized":"The LORD is my rock, my fortress, and my deliverer. My God is my rock, in whom I take refuge, my shield, and the horn of my salvation, my stronghold.","sources":{"KJV":{"text":"The LORD is my rock, and my fortress, and my deliverer; my God, my strength, in whom I will trust; my buckler, and the horn of my salvation, and my high tower."},"BSB":{"text":"The LORD is my rock, my fortress, and my deliverer. My God is my rock, in whom I take refuge, my shield, and the horn of my salvation, my stronghold."}},"definableWords":["LORD","God","salvation"],"peopleInVerse":[]},"3":{"text":"I will call upon the LORD, who is worthy to be praised: so shall I be saved from mine enemies.","ref":"Psalms 18:3","synthesized":"I will call upon the LORD, who is worthy to be praised; so shall I be saved from my enemies.","sources":{"KJV":{"text":"I will call upon the LORD, who is worthy to be praised: so shall I be saved from mine enemies."},"BSB":{"text":"I will call upon the LORD, who is worthy to be praised; so shall I be saved from my enemies."}},"definableWords":["LORD"],"peopleInVerse":[]},"4":{"text":"The sorrows of death compassed me, and the floods of ungodly men made me afraid.","ref":"Psalms 18:4","synthesized":"The cords of death encompassed me; the torrents of chaos overwhelmed me.","sources":{"KJV":{"text":"The sorrows of death compassed me, and the floods of ungodly men made me afraid."},"BSB":{"text":"The cords of death encompassed me; the torrents of chaos overwhelmed me."}},"definableWords":["death"],"peopleInVerse":[]},"5":{"text":"The sorrows of hell compassed me about: the snares of death prevented me.","ref":"Psalms 18:5","synthesized":"The cords of Sheol entangled me; the snares of death confronted me.","sources":{"KJV":{"text":"The sorrows of hell compassed me about: the snares of death prevented me."},"BSB":{"text":"The cords of Sheol entangled me; the snares of death confronted me."}},"definableWords":["death"],"peopleInVerse":[]},"6":{"text":"In my distress I called upon the LORD, and cried unto my God: he heard my voice out of his temple, and my cry came before him, even into his ears.","ref":"Psalms 18:6","synthesized":"In my distress I called upon the LORD; I cried to my God for help. From His temple He heard my voice, and my cry for His help reached His ears.","sources":{"KJV":{"text":"In my distress I called upon the LORD, and cried unto my God: he heard my voice out of his temple, and my cry came before him, even into his ears."},"BSB":{"text":"In my distress I called upon the LORD; I cried to my God for help. From His temple He heard my voice, and my cry for His help reached His ears."}},"definableWords":["LORD","God","temple","voice"],"peopleInVerse":[]},"7":{"text":"Then the earth shook and trembled; the foundations also of the hills moved and were shaken, because he was wroth.","ref":"Psalms 18:7","synthesized":"Then the earth shook and quaked, and the foundations of the mountains trembled; they were shaken because He burned with anger.","sources":{"KJV":{"text":"Then the earth shook and trembled; the foundations also of the hills moved and were shaken, because he was wroth."},"BSB":{"text":"Then the earth shook and quaked, and the foundations of the mountains trembled; they were shaken because He burned with anger."}},"definableWords":["earth","anger"],"peopleInVerse":[]},"8":{"text":"There went up a smoke out of his nostrils, and fire out of his mouth devoured: coals were kindled by it.","ref":"Psalms 18:8","synthesized":"Smoke rose from His nostrils, and consuming fire came from His mouth; glowing coals blazed forth.","sources":{"KJV":{"text":"There went up a smoke out of his nostrils, and fire out of his mouth devoured: coals were kindled by it."},"BSB":{"text":"Smoke rose from His nostrils, and consuming fire came from His mouth; glowing coals blazed forth."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"He bowed the heavens also, and came down: and darkness was under his feet.","ref":"Psalms 18:9","synthesized":"He parted the heavens and came down with dark clouds beneath His feet.","sources":{"KJV":{"text":"He bowed the heavens also, and came down: and darkness was under his feet."},"BSB":{"text":"He parted the heavens and came down with dark clouds beneath His feet."}},"definableWords":["heavens"],"peopleInVerse":[]},"10":{"text":"And he rode upon a cherub, and did fly: yea, he did fly upon the wings of the wind.","ref":"Psalms 18:10","synthesized":"He mounted a cherub and flew; He soared on the wings of the wind.","sources":{"KJV":{"text":"And he rode upon a cherub, and did fly: yea, he did fly upon the wings of the wind."},"BSB":{"text":"He mounted a cherub and flew; He soared on the wings of the wind."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"He made darkness his secret place; his pavilion round about him were dark waters and thick clouds of the skies.","ref":"Psalms 18:11","synthesized":"He made darkness His hiding place, and storm clouds a canopy around Him.","sources":{"KJV":{"text":"He made darkness his secret place; his pavilion round about him were dark waters and thick clouds of the skies."},"BSB":{"text":"He made darkness His hiding place, and storm clouds a canopy around Him."}},"definableWords":["made","darkness"],"peopleInVerse":[]},"12":{"text":"At the brightness that was before him his thick clouds passed, hail stones and coals of fire.","ref":"Psalms 18:12","synthesized":"From the brightness of His presence His clouds advanced— hailstones and coals of fire.","sources":{"KJV":{"text":"At the brightness that was before him his thick clouds passed, hail stones and coals of fire."},"BSB":{"text":"From the brightness of His presence His clouds advanced— hailstones and coals of fire."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"The LORD also thundered in the heavens, and the Highest gave his voice; hail stones and coals of fire.","ref":"Psalms 18:13","synthesized":"The LORD thundered from heaven; the voice of the Most High resounded— hailstones and coals of fire.","sources":{"KJV":{"text":"The LORD also thundered in the heavens, and the Highest gave his voice; hail stones and coals of fire."},"BSB":{"text":"The LORD thundered from heaven; the voice of the Most High resounded— hailstones and coals of fire."}},"definableWords":["LORD","heaven","voice"],"peopleInVerse":[]},"14":{"text":"Yea, he sent out his arrows, and scattered them; and he shot out lightnings, and discomfited them.","ref":"Psalms 18:14","synthesized":"He shot His arrows and scattered the foes; He hurled lightning and routed them.","sources":{"KJV":{"text":"Yea, he sent out his arrows, and scattered them; and he shot out lightnings, and discomfited them."},"BSB":{"text":"He shot His arrows and scattered the foes; He hurled lightning and routed them."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Then the channels of waters were seen, and the foundations of the world were discovered at thy rebuke, O LORD, at the blast of the breath of thy nostrils.","ref":"Psalms 18:15","synthesized":"The channels of the sea appeared, and the foundations of the world were exposed, at Your rebuke, O LORD, at the blast of the breath of Your nostrils.","sources":{"KJV":{"text":"Then the channels of waters were seen, and the foundations of the world were discovered at thy rebuke, O LORD, at the blast of the breath of thy nostrils."},"BSB":{"text":"The channels of the sea appeared, and the foundations of the world were exposed, at Your rebuke, O LORD, at the blast of the breath of Your nostrils."}},"definableWords":["sea","LORD","breath"],"peopleInVerse":[]},"16":{"text":"He sent from above, he took me, he drew me out of many waters.","ref":"Psalms 18:16","synthesized":"He reached down from on high and took hold of me; He drew me out of deep waters.","sources":{"KJV":{"text":"He sent from above, he took me, he drew me out of many waters."},"BSB":{"text":"He reached down from on high and took hold of me; He drew me out of deep waters."}},"definableWords":["deep","waters"],"peopleInVerse":[]},"17":{"text":"He delivered me from my strong enemy, and from them which hated me: for they were too strong for me.","ref":"Psalms 18:17","synthesized":"He rescued me from my powerful enemy, from foes too mighty for me.","sources":{"KJV":{"text":"He delivered me from my strong enemy, and from them which hated me: for they were too strong for me."},"BSB":{"text":"He rescued me from my powerful enemy, from foes too mighty for me."}},"definableWords":["mighty"],"peopleInVerse":[]},"18":{"text":"They prevented me in the day of my calamity: but the LORD was my stay.","ref":"Psalms 18:18","synthesized":"They confronted me in my day of calamity, but the LORD was my support.","sources":{"KJV":{"text":"They prevented me in the day of my calamity: but the LORD was my stay."},"BSB":{"text":"They confronted me in my day of calamity, but the LORD was my support."}},"definableWords":["day","LORD"],"peopleInVerse":[]},"19":{"text":"He brought me forth also into a large place; he delivered me, because he delighted in me.","ref":"Psalms 18:19","synthesized":"He brought me out into the open; He rescued me because He delighted in me.","sources":{"KJV":{"text":"He brought me forth also into a large place; he delivered me, because he delighted in me."},"BSB":{"text":"He brought me out into the open; He rescued me because He delighted in me."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"The LORD rewarded me according to my righteousness; according to the cleanness of my hands hath he recompensed me.","ref":"Psalms 18:20","synthesized":"The LORD has rewarded me according to my righteousness; He has repaid me according to the cleanness of my hands.","sources":{"KJV":{"text":"The LORD rewarded me according to my righteousness; according to the cleanness of my hands hath he recompensed me."},"BSB":{"text":"The LORD has rewarded me according to my righteousness; He has repaid me according to the cleanness of my hands."}},"definableWords":["LORD","righteousness"],"peopleInVerse":[]},"21":{"text":"For I have kept the ways of the LORD, and have not wickedly departed from my God.","ref":"Psalms 18:21","synthesized":"For I have kept the ways of the LORD and have not wickedly departed from my God.","sources":{"KJV":{"text":"For I have kept the ways of the LORD, and have not wickedly departed from my God."},"BSB":{"text":"For I have kept the ways of the LORD and have not wickedly departed from my God."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"22":{"text":"For all his judgments were before me, and I did not put away his statutes from me.","ref":"Psalms 18:22","synthesized":"For all His ordinances are before me; I have not disregarded His statutes.","sources":{"KJV":{"text":"For all his judgments were before me, and I did not put away his statutes from me."},"BSB":{"text":"For all His ordinances are before me; I have not disregarded His statutes."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"I was also upright before him, and I kept myself from mine iniquity.","ref":"Psalms 18:23","synthesized":"And I have been blameless before Him and kept myself from iniquity.","sources":{"KJV":{"text":"I was also upright before him, and I kept myself from mine iniquity."},"BSB":{"text":"And I have been blameless before Him and kept myself from iniquity."}},"definableWords":["iniquity"],"peopleInVerse":[]},"24":{"text":"Therefore hath the LORD recompensed me according to my righteousness, according to the cleanness of my hands in his eyesight.","ref":"Psalms 18:24","synthesized":"So the LORD has repaid me according to my righteousness, according to the cleanness of my hands in His sight.","sources":{"KJV":{"text":"Therefore hath the LORD recompensed me according to my righteousness, according to the cleanness of my hands in his eyesight."},"BSB":{"text":"So the LORD has repaid me according to my righteousness, according to the cleanness of my hands in His sight."}},"definableWords":["LORD","righteousness"],"peopleInVerse":[]},"25":{"text":"With the merciful thou wilt shew thyself merciful; with an upright man thou wilt shew thyself upright;","ref":"Psalms 18:25","synthesized":"To the faithful You show Yourself faithful, to the blameless You show Yourself blameless;","sources":{"KJV":{"text":"With the merciful thou wilt shew thyself merciful; with an upright man thou wilt shew thyself upright;"},"BSB":{"text":"To the faithful You show Yourself faithful, to the blameless You show Yourself blameless;"}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"With the pure thou wilt shew thyself pure; and with the froward thou wilt shew thyself froward.","ref":"Psalms 18:26","synthesized":"to the pure You show Yourself pure, but to the crooked You show Yourself shrewd.","sources":{"KJV":{"text":"With the pure thou wilt shew thyself pure; and with the froward thou wilt shew thyself froward."},"BSB":{"text":"to the pure You show Yourself pure, but to the crooked You show Yourself shrewd."}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"For thou wilt save the afflicted people; but wilt bring down high looks.","ref":"Psalms 18:27","synthesized":"For You save an afflicted people, but You humble those with haughty eyes.","sources":{"KJV":{"text":"For thou wilt save the afflicted people; but wilt bring down high looks."},"BSB":{"text":"For You save an afflicted people, but You humble those with haughty eyes."}},"definableWords":["people"],"peopleInVerse":[]},"28":{"text":"For thou wilt light my candle: the LORD my God will enlighten my darkness.","ref":"Psalms 18:28","synthesized":"For You, O LORD, light my lamp; my God lights up my darkness.","sources":{"KJV":{"text":"For thou wilt light my candle: the LORD my God will enlighten my darkness."},"BSB":{"text":"For You, O LORD, light my lamp; my God lights up my darkness."}},"definableWords":["LORD","light","God","darkness"],"peopleInVerse":[]},"29":{"text":"For by thee I have run through a troop; and by my God have I leaped over a wall.","ref":"Psalms 18:29","synthesized":"For in You I can charge an army, and with my God I can scale a wall.","sources":{"KJV":{"text":"For by thee I have run through a troop; and by my God have I leaped over a wall."},"BSB":{"text":"For in You I can charge an army, and with my God I can scale a wall."}},"definableWords":["charge","God"],"peopleInVerse":[]},"30":{"text":"As for God, his way is perfect: the word of the LORD is tried: he is a buckler to all those that trust in him.","ref":"Psalms 18:30","synthesized":"As for God, His way is perfect; the word of the LORD is flawless. He is a shield to all who take refuge in Him.","sources":{"KJV":{"text":"As for God, his way is perfect: the word of the LORD is tried: he is a buckler to all those that trust in him."},"BSB":{"text":"As for God, His way is perfect; the word of the LORD is flawless. He is a shield to all who take refuge in Him."}},"definableWords":["God","way","word","LORD"],"peopleInVerse":[]},"31":{"text":"For who is God save the LORD? or who is a rock save our God?","ref":"Psalms 18:31","synthesized":"For who is God besides the LORD? And who is the Rock except our God?","sources":{"KJV":{"text":"For who is God save the LORD? or who is a rock save our God?"},"BSB":{"text":"For who is God besides the LORD? And who is the Rock except our God?"}},"definableWords":["God","LORD"],"peopleInVerse":[]},"32":{"text":"It is God that girdeth me with strength, and maketh my way perfect.","ref":"Psalms 18:32","synthesized":"It is God who arms me with strength and makes my way clear.","sources":{"KJV":{"text":"It is God that girdeth me with strength, and maketh my way perfect."},"BSB":{"text":"It is God who arms me with strength and makes my way clear."}},"definableWords":["God","way"],"peopleInVerse":[]},"33":{"text":"He maketh my feet like hinds’ feet, and setteth me upon my high places.","ref":"Psalms 18:33","synthesized":"He makes my feet like those of a deer and stations me upon the heights.","sources":{"KJV":{"text":"He maketh my feet like hinds’ feet, and setteth me upon my high places."},"BSB":{"text":"He makes my feet like those of a deer and stations me upon the heights."}},"definableWords":[],"peopleInVerse":[]},"34":{"text":"He teacheth my hands to war, so that a bow of steel is broken by mine arms.","ref":"Psalms 18:34","synthesized":"He trains my hands for battle; my arms can bend a bow of bronze.","sources":{"KJV":{"text":"He teacheth my hands to war, so that a bow of steel is broken by mine arms."},"BSB":{"text":"He trains my hands for battle; my arms can bend a bow of bronze."}},"definableWords":[],"peopleInVerse":[]},"35":{"text":"Thou hast also given me the shield of thy salvation: and thy right hand hath holden me up, and thy gentleness hath made me great.","ref":"Psalms 18:35","synthesized":"You have given me Your shield of salvation; Your right hand upholds me, and Your gentleness exalts me.","sources":{"KJV":{"text":"Thou hast also given me the shield of thy salvation: and thy right hand hath holden me up, and thy gentleness hath made me great."},"BSB":{"text":"You have given me Your shield of salvation; Your right hand upholds me, and Your gentleness exalts me."}},"definableWords":["salvation"],"peopleInVerse":[]},"36":{"text":"Thou hast enlarged my steps under me, that my feet did not slip.","ref":"Psalms 18:36","synthesized":"You broaden the path beneath me so that my ankles do not give way.","sources":{"KJV":{"text":"Thou hast enlarged my steps under me, that my feet did not slip."},"BSB":{"text":"You broaden the path beneath me so that my ankles do not give way."}},"definableWords":["way"],"peopleInVerse":[]},"37":{"text":"I have pursued mine enemies, and overtaken them: neither did I turn again till they were consumed.","ref":"Psalms 18:37","synthesized":"I pursued my enemies and overtook them; I did not turn back until they were consumed.","sources":{"KJV":{"text":"I have pursued mine enemies, and overtaken them: neither did I turn again till they were consumed."},"BSB":{"text":"I pursued my enemies and overtook them; I did not turn back until they were consumed."}},"definableWords":[],"peopleInVerse":[]},"38":{"text":"I have wounded them that they were not able to rise: they are fallen under my feet.","ref":"Psalms 18:38","synthesized":"I crushed them so they could not rise; they have fallen under my feet.","sources":{"KJV":{"text":"I have wounded them that they were not able to rise: they are fallen under my feet."},"BSB":{"text":"I crushed them so they could not rise; they have fallen under my feet."}},"definableWords":[],"peopleInVerse":[]},"39":{"text":"For thou hast girded me with strength unto the battle: thou hast subdued under me those that rose up against me.","ref":"Psalms 18:39","synthesized":"You have armed me with strength for battle; You have subdued my foes beneath me.","sources":{"KJV":{"text":"For thou hast girded me with strength unto the battle: thou hast subdued under me those that rose up against me."},"BSB":{"text":"You have armed me with strength for battle; You have subdued my foes beneath me."}},"definableWords":[],"peopleInVerse":[]},"40":{"text":"Thou hast also given me the necks of mine enemies; that I might destroy them that hate me.","ref":"Psalms 18:40","synthesized":"You have made my enemies retreat before me; I put an end to those who hated me.","sources":{"KJV":{"text":"Thou hast also given me the necks of mine enemies; that I might destroy them that hate me."},"BSB":{"text":"You have made my enemies retreat before me; I put an end to those who hated me."}},"definableWords":["made"],"peopleInVerse":[]},"41":{"text":"They cried, but there was none to save them: even unto the LORD, but he answered them not.","ref":"Psalms 18:41","synthesized":"They cried for help, but there was no one to save them— to the LORD, but He did not answer.","sources":{"KJV":{"text":"They cried, but there was none to save them: even unto the LORD, but he answered them not."},"BSB":{"text":"They cried for help, but there was no one to save them— to the LORD, but He did not answer."}},"definableWords":["one","LORD"],"peopleInVerse":[]},"42":{"text":"Then did I beat them small as the dust before the wind: I did cast them out as the dirt in the streets.","ref":"Psalms 18:42","synthesized":"I ground them as dust in the face of the wind; I trampled them like mud in the streets.","sources":{"KJV":{"text":"Then did I beat them small as the dust before the wind: I did cast them out as the dirt in the streets."},"BSB":{"text":"I ground them as dust in the face of the wind; I trampled them like mud in the streets."}},"definableWords":["ground"],"peopleInVerse":[]},"43":{"text":"Thou hast delivered me from the strivings of the people; and thou hast made me the head of the heathen: a people whom I have not known shall serve me.","ref":"Psalms 18:43","synthesized":"You have delivered me from the strife of the people; You have made me the head of nations; a people I had not known shall serve me.","sources":{"KJV":{"text":"Thou hast delivered me from the strivings of the people; and thou hast made me the head of the heathen: a people whom I have not known shall serve me."},"BSB":{"text":"You have delivered me from the strife of the people; You have made me the head of nations; a people I had not known shall serve me."}},"definableWords":["people","made","nations"],"peopleInVerse":[]},"44":{"text":"As soon as they hear of me, they shall obey me: the strangers shall submit themselves unto me.","ref":"Psalms 18:44","synthesized":"When they hear me, they obey me; foreigners cower before me.","sources":{"KJV":{"text":"As soon as they hear of me, they shall obey me: the strangers shall submit themselves unto me."},"BSB":{"text":"When they hear me, they obey me; foreigners cower before me."}},"definableWords":["hear"],"peopleInVerse":[]},"45":{"text":"The strangers shall fade away, and be afraid out of their close places.","ref":"Psalms 18:45","synthesized":"Foreigners lose heart and come trembling from their strongholds.","sources":{"KJV":{"text":"The strangers shall fade away, and be afraid out of their close places."},"BSB":{"text":"Foreigners lose heart and come trembling from their strongholds."}},"definableWords":["heart"],"peopleInVerse":[]},"46":{"text":"The LORD liveth; and blessed be my rock; and let the God of my salvation be exalted.","ref":"Psalms 18:46","synthesized":"The LORD lives, and blessed be my Rock! And may the God of my salvation be exalted—","sources":{"KJV":{"text":"The LORD liveth; and blessed be my rock; and let the God of my salvation be exalted."},"BSB":{"text":"The LORD lives, and blessed be my Rock! And may the God of my salvation be exalted—"}},"definableWords":["LORD","blessed","God","salvation"],"peopleInVerse":[]},"47":{"text":"It is God that avengeth me, and subdueth the people under me.","ref":"Psalms 18:47","synthesized":"the God who avenges me and subdues nations beneath me,","sources":{"KJV":{"text":"It is God that avengeth me, and subdueth the people under me."},"BSB":{"text":"the God who avenges me and subdues nations beneath me,"}},"definableWords":["God","nations"],"peopleInVerse":[]},"48":{"text":"He delivereth me from mine enemies: yea, thou liftest me up above those that rise up against me: thou hast delivered me from the violent man.","ref":"Psalms 18:48","synthesized":"who delivers me from my enemies. You exalt me above my foes; You rescue me from violent men.","sources":{"KJV":{"text":"He delivereth me from mine enemies: yea, thou liftest me up above those that rise up against me: thou hast delivered me from the violent man."},"BSB":{"text":"who delivers me from my enemies. You exalt me above my foes; You rescue me from violent men."}},"definableWords":["men"],"peopleInVerse":[]},"49":{"text":"Therefore will I give thanks unto thee, O LORD, among the heathen, and sing praises unto thy name.","ref":"Psalms 18:49","synthesized":"Therefore I will praise You, O LORD, among the nations; I will sing praises to Your name.","sources":{"KJV":{"text":"Therefore will I give thanks unto thee, O LORD, among the heathen, and sing praises unto thy name."},"BSB":{"text":"Therefore I will praise You, O LORD, among the nations; I will sing praises to Your name."}},"definableWords":["praise","LORD","nations","name"],"peopleInVerse":[]},"50":{"text":"Great deliverance giveth he to his king; and sheweth mercy to his anointed, to David, and to his seed for evermore.","ref":"Psalms 18:50","synthesized":"Great salvation He brings to His king. He shows loving devotion to His anointed, to David and his descendants forever.","sources":{"KJV":{"text":"Great deliverance giveth he to his king; and sheweth mercy to his anointed, to David, and to his seed for evermore."},"BSB":{"text":"Great salvation He brings to His king. He shows loving devotion to His anointed, to David and his descendants forever."}},"definableWords":["great","salvation","king"],"peopleInVerse":["David"]}}},"19":{"chapter":"19","title":"THE HEAVENS DECLARE","verses":{"1":{"text":"The heavens declare the glory of God; and the firmament sheweth his handywork.","ref":"Psalms 19:1","synthesized":"The heavens declare the glory of God; the skies proclaim the work of His hands.","sources":{"KJV":{"text":"The heavens declare the glory of God; and the firmament sheweth his handywork."},"BSB":{"text":"The heavens declare the glory of God; the skies proclaim the work of His hands."}},"definableWords":["heavens","glory","God","work"],"peopleInVerse":[]},"2":{"text":"Day unto day uttereth speech, and night unto night sheweth knowledge.","ref":"Psalms 19:2","synthesized":"Day after day they pour forth speech; night after night they reveal knowledge.","sources":{"KJV":{"text":"Day unto day uttereth speech, and night unto night sheweth knowledge."},"BSB":{"text":"Day after day they pour forth speech; night after night they reveal knowledge."}},"definableWords":["day","night","knowledge"],"peopleInVerse":[]},"3":{"text":"There is no speech nor language, where their voice is not heard.","ref":"Psalms 19:3","synthesized":"Without speech or language, without a sound to be heard,","sources":{"KJV":{"text":"There is no speech nor language, where their voice is not heard."},"BSB":{"text":"Without speech or language, without a sound to be heard,"}},"definableWords":["or"],"peopleInVerse":[]},"4":{"text":"Their line is gone out through all the earth, and their words to the end of the world. In them hath he set a tabernacle for the sun,","ref":"Psalms 19:4","synthesized":"their voice has gone out into all the earth, their words to the ends of the world.   In the heavens He has pitched a tent for the sun.","sources":{"KJV":{"text":"Their line is gone out through all the earth, and their words to the end of the world. In them hath he set a tabernacle for the sun,"},"BSB":{"text":"their voice has gone out into all the earth, their words to the ends of the world.   In the heavens He has pitched a tent for the sun."}},"definableWords":["voice","earth","heavens"],"peopleInVerse":[]},"5":{"text":"Which is as a bridegroom coming out of his chamber, and rejoiceth as a strong man to run a race.","ref":"Psalms 19:5","synthesized":"Like a bridegroom emerging from his chamber, like a champion rejoicing to run his course,","sources":{"KJV":{"text":"Which is as a bridegroom coming out of his chamber, and rejoiceth as a strong man to run a race."},"BSB":{"text":"Like a bridegroom emerging from his chamber, like a champion rejoicing to run his course,"}},"definableWords":["run"],"peopleInVerse":[]},"6":{"text":"His going forth is from the end of the heaven, and his circuit unto the ends of it: and there is nothing hid from the heat thereof.","ref":"Psalms 19:6","synthesized":"it rises at one end of the heavens and runs its circuit to the other; nothing is deprived of its warmth.","sources":{"KJV":{"text":"His going forth is from the end of the heaven, and his circuit unto the ends of it: and there is nothing hid from the heat thereof."},"BSB":{"text":"it rises at one end of the heavens and runs its circuit to the other; nothing is deprived of its warmth."}},"definableWords":["one","heavens"],"peopleInVerse":[]},"7":{"text":"The law of the LORD is perfect, converting the soul: the testimony of the LORD is sure, making wise the simple.","ref":"Psalms 19:7","synthesized":"The Law of the LORD is perfect, reviving the soul; the testimony of the LORD is trustworthy, making wise the simple.","sources":{"KJV":{"text":"The law of the LORD is perfect, converting the soul: the testimony of the LORD is sure, making wise the simple."},"BSB":{"text":"The Law of the LORD is perfect, reviving the soul; the testimony of the LORD is trustworthy, making wise the simple."}},"definableWords":["law","LORD","soul","Lord"],"peopleInVerse":[]},"8":{"text":"The statutes of the LORD are right, rejoicing the heart: the commandment of the LORD is pure, enlightening the eyes.","ref":"Psalms 19:8","synthesized":"The precepts of the LORD are right, bringing joy to the heart; the commandments of the LORD are radiant, giving light to the eyes.","sources":{"KJV":{"text":"The statutes of the LORD are right, rejoicing the heart: the commandment of the LORD is pure, enlightening the eyes."},"BSB":{"text":"The precepts of the LORD are right, bringing joy to the heart; the commandments of the LORD are radiant, giving light to the eyes."}},"definableWords":["LORD","joy","heart","Lord","light"],"peopleInVerse":[]},"9":{"text":"The fear of the LORD is clean, enduring for ever: the judgments of the LORD are true and righteous altogether.","ref":"Psalms 19:9","synthesized":"The fear of the LORD is pure, enduring forever; the judgments of the LORD are true, being altogether righteous.","sources":{"KJV":{"text":"The fear of the LORD is clean, enduring for ever: the judgments of the LORD are true and righteous altogether."},"BSB":{"text":"The fear of the LORD is pure, enduring forever; the judgments of the LORD are true, being altogether righteous."}},"definableWords":["fear","LORD","Lord","righteous"],"peopleInVerse":[]},"10":{"text":"More to be desired are they than gold, yea, than much fine gold: sweeter also than honey and the honeycomb.","ref":"Psalms 19:10","synthesized":"They are more precious than gold, than much pure gold; they are sweeter than honey, than honey from the comb.","sources":{"KJV":{"text":"More to be desired are they than gold, yea, than much fine gold: sweeter also than honey and the honeycomb."},"BSB":{"text":"They are more precious than gold, than much pure gold; they are sweeter than honey, than honey from the comb."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Moreover by them is thy servant warned: and in keeping of them there is great reward.","ref":"Psalms 19:11","synthesized":"By them indeed Your servant is warned; in keeping them is great reward.","sources":{"KJV":{"text":"Moreover by them is thy servant warned: and in keeping of them there is great reward."},"BSB":{"text":"By them indeed Your servant is warned; in keeping them is great reward."}},"definableWords":["servant","great"],"peopleInVerse":[]},"12":{"text":"Who can understand his errors? cleanse thou me from secret faults.","ref":"Psalms 19:12","synthesized":"Who can discern his own errors? Cleanse me from my hidden faults.","sources":{"KJV":{"text":"Who can understand his errors? cleanse thou me from secret faults."},"BSB":{"text":"Who can discern his own errors? Cleanse me from my hidden faults."}},"definableWords":["cleanse"],"peopleInVerse":[]},"13":{"text":"Keep back thy servant also from presumptuous sins; let them not have dominion over me: then shall I be upright, and I shall be innocent from the great transgression.","ref":"Psalms 19:13","synthesized":"Keep Your servant also from willful sins; may they not rule over me. Then I will be blameless and cleansed of great transgression.","sources":{"KJV":{"text":"Keep back thy servant also from presumptuous sins; let them not have dominion over me: then shall I be upright, and I shall be innocent from the great transgression."},"BSB":{"text":"Keep Your servant also from willful sins; may they not rule over me. Then I will be blameless and cleansed of great transgression."}},"definableWords":["keep","servant","rule","great","transgression"],"peopleInVerse":[]},"14":{"text":"Let the words of my mouth, and the meditation of my heart, be acceptable in thy sight, O LORD, my strength, and my redeemer.","ref":"Psalms 19:14","synthesized":"May the words of my mouth and the meditation of my heart be pleasing in Your sight, O LORD, my Rock and my Redeemer.","sources":{"KJV":{"text":"Let the words of my mouth, and the meditation of my heart, be acceptable in thy sight, O LORD, my strength, and my redeemer."},"BSB":{"text":"May the words of my mouth and the meditation of my heart be pleasing in Your sight, O LORD, my Rock and my Redeemer."}},"definableWords":["heart","LORD","Redeemer"],"peopleInVerse":[]}}},"20":{"chapter":"20","title":"THE LORD HEAR THEE IN DAY OF TROUBLE","verses":{"1":{"text":"The LORD hear thee in the day of trouble; the name of the God of Jacob defend thee;","ref":"Psalms 20:1","synthesized":"May the LORD answer you in the day of trouble; may the name of the God of Jacob protect you.","sources":{"KJV":{"text":"The LORD hear thee in the day of trouble; the name of the God of Jacob defend thee;"},"BSB":{"text":"May the LORD answer you in the day of trouble; may the name of the God of Jacob protect you."}},"definableWords":["LORD","day","name","God","Jacob"],"peopleInVerse":["Jacob"]},"2":{"text":"Send thee help from the sanctuary, and strengthen thee out of Zion;","ref":"Psalms 20:2","synthesized":"May He send you help from the sanctuary and sustain you from Zion.","sources":{"KJV":{"text":"Send thee help from the sanctuary, and strengthen thee out of Zion;"},"BSB":{"text":"May He send you help from the sanctuary and sustain you from Zion."}},"definableWords":["Zion"],"peopleInVerse":[]},"3":{"text":"Remember all thy offerings, and accept thy burnt sacrifice; Selah.","ref":"Psalms 20:3","synthesized":"May He remember all your gifts and look favorably on your burnt offerings. Selah","sources":{"KJV":{"text":"Remember all thy offerings, and accept thy burnt sacrifice; Selah."},"BSB":{"text":"May He remember all your gifts and look favorably on your burnt offerings. Selah"}},"definableWords":["remember"],"peopleInVerse":[]},"4":{"text":"Grant thee according to thine own heart, and fulfil all thy counsel.","ref":"Psalms 20:4","synthesized":"May He give you the desires of your heart and make all your plans succeed.","sources":{"KJV":{"text":"Grant thee according to thine own heart, and fulfil all thy counsel."},"BSB":{"text":"May He give you the desires of your heart and make all your plans succeed."}},"definableWords":["heart","make"],"peopleInVerse":[]},"5":{"text":"We will rejoice in thy salvation, and in the name of our God we will set up our banners: the LORD fulfil all thy petitions.","ref":"Psalms 20:5","synthesized":"May we shout for joy at your victory and raise a banner in the name of our God. May the LORD grant all your petitions.","sources":{"KJV":{"text":"We will rejoice in thy salvation, and in the name of our God we will set up our banners: the LORD fulfil all thy petitions."},"BSB":{"text":"May we shout for joy at your victory and raise a banner in the name of our God. May the LORD grant all your petitions."}},"definableWords":["joy","name","God","LORD"],"peopleInVerse":[]},"6":{"text":"Now know I that the LORD saveth his anointed; he will hear him from his holy heaven with the saving strength of his right hand.","ref":"Psalms 20:6","synthesized":"Now I know that the LORD saves His anointed; He answers him from His holy heaven with the saving power of His right hand.","sources":{"KJV":{"text":"Now know I that the LORD saveth his anointed; he will hear him from his holy heaven with the saving strength of his right hand."},"BSB":{"text":"Now I know that the LORD saves His anointed; He answers him from His holy heaven with the saving power of His right hand."}},"definableWords":["LORD","holy","heaven"],"peopleInVerse":[]},"7":{"text":"Some trust in chariots, and some in horses: but we will remember the name of the LORD our God.","ref":"Psalms 20:7","synthesized":"Some trust in chariots and others in horses, but we trust in the name of the LORD our God.","sources":{"KJV":{"text":"Some trust in chariots, and some in horses: but we will remember the name of the LORD our God."},"BSB":{"text":"Some trust in chariots and others in horses, but we trust in the name of the LORD our God."}},"definableWords":["trust","name","LORD","God"],"peopleInVerse":[]},"8":{"text":"They are brought down and fallen: but we are risen, and stand upright.","ref":"Psalms 20:8","synthesized":"They collapse and fall, but we rise up and stand firm.","sources":{"KJV":{"text":"They are brought down and fallen: but we are risen, and stand upright."},"BSB":{"text":"They collapse and fall, but we rise up and stand firm."}},"definableWords":["stand"],"peopleInVerse":[]},"9":{"text":"Save, LORD: let the king hear us when we call.","ref":"Psalms 20:9","synthesized":"O LORD, save the king. Answer us on the day we call.","sources":{"KJV":{"text":"Save, LORD: let the king hear us when we call."},"BSB":{"text":"O LORD, save the king. Answer us on the day we call."}},"definableWords":["LORD","king","day"],"peopleInVerse":[]}}},"21":{"chapter":"21","title":"THE KING SHALL JOY IN THY STRENGTH","verses":{"1":{"text":"The king shall joy in thy strength, O LORD; and in thy salvation how greatly shall he rejoice!","ref":"Psalms 21:1","synthesized":"O LORD, the king rejoices in Your strength. How greatly he exults in Your salvation!","sources":{"KJV":{"text":"The king shall joy in thy strength, O LORD; and in thy salvation how greatly shall he rejoice!"},"BSB":{"text":"O LORD, the king rejoices in Your strength. How greatly he exults in Your salvation!"}},"definableWords":["LORD","king","salvation"],"peopleInVerse":[]},"2":{"text":"Thou hast given him his heart’s desire, and hast not withholden the request of his lips. Selah.","ref":"Psalms 21:2","synthesized":"You have granted his heart’s desire and have not withheld the request of his lips. Selah","sources":{"KJV":{"text":"Thou hast given him his heart’s desire, and hast not withholden the request of his lips. Selah."},"BSB":{"text":"You have granted his heart’s desire and have not withheld the request of his lips. Selah"}},"definableWords":["heart"],"peopleInVerse":[]},"3":{"text":"For thou preventest him with the blessings of goodness: thou settest a crown of pure gold on his head.","ref":"Psalms 21:3","synthesized":"For You welcomed him with rich blessings; You placed on his head a crown of pure gold.","sources":{"KJV":{"text":"For thou preventest him with the blessings of goodness: thou settest a crown of pure gold on his head."},"BSB":{"text":"For You welcomed him with rich blessings; You placed on his head a crown of pure gold."}},"definableWords":["crown"],"peopleInVerse":[]},"4":{"text":"He asked life of thee, and thou gavest it him, even length of days for ever and ever.","ref":"Psalms 21:4","synthesized":"He asked You for life, and You granted it— length of days, forever and ever.","sources":{"KJV":{"text":"He asked life of thee, and thou gavest it him, even length of days for ever and ever."},"BSB":{"text":"He asked You for life, and You granted it— length of days, forever and ever."}},"definableWords":["life","days"],"peopleInVerse":[]},"5":{"text":"His glory is great in thy salvation: honour and majesty hast thou laid upon him.","ref":"Psalms 21:5","synthesized":"Great is his glory in Your salvation; You bestow on him splendor and majesty.","sources":{"KJV":{"text":"His glory is great in thy salvation: honour and majesty hast thou laid upon him."},"BSB":{"text":"Great is his glory in Your salvation; You bestow on him splendor and majesty."}},"definableWords":["great","glory","salvation"],"peopleInVerse":[]},"6":{"text":"For thou hast made him most blessed for ever: thou hast made him exceeding glad with thy countenance.","ref":"Psalms 21:6","synthesized":"For You grant him blessings forever; You cheer him with joy in Your presence.","sources":{"KJV":{"text":"For thou hast made him most blessed for ever: thou hast made him exceeding glad with thy countenance."},"BSB":{"text":"For You grant him blessings forever; You cheer him with joy in Your presence."}},"definableWords":["joy"],"peopleInVerse":[]},"7":{"text":"For the king trusteth in the LORD, and through the mercy of the most High he shall not be moved.","ref":"Psalms 21:7","synthesized":"For the king trusts in the LORD; through the loving devotion of the Most High, he will not be shaken.","sources":{"KJV":{"text":"For the king trusteth in the LORD, and through the mercy of the most High he shall not be moved."},"BSB":{"text":"For the king trusts in the LORD; through the loving devotion of the Most High, he will not be shaken."}},"definableWords":["king","LORD"],"peopleInVerse":[]},"8":{"text":"Thine hand shall find out all thine enemies: thy right hand shall find out those that hate thee.","ref":"Psalms 21:8","synthesized":"Your hand will apprehend all Your enemies; Your right hand will seize those who hate You.","sources":{"KJV":{"text":"Thine hand shall find out all thine enemies: thy right hand shall find out those that hate thee."},"BSB":{"text":"Your hand will apprehend all Your enemies; Your right hand will seize those who hate You."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Thou shalt make them as a fiery oven in the time of thine anger: the LORD shall swallow them up in his wrath, and the fire shall devour them.","ref":"Psalms 21:9","synthesized":"You will place them in a fiery furnace at the time of Your appearing.   In His wrath the LORD will engulf them, and the fire will consume them.","sources":{"KJV":{"text":"Thou shalt make them as a fiery oven in the time of thine anger: the LORD shall swallow them up in his wrath, and the fire shall devour them."},"BSB":{"text":"You will place them in a fiery furnace at the time of Your appearing.   In His wrath the LORD will engulf them, and the fire will consume them."}},"definableWords":["wrath","LORD"],"peopleInVerse":[]},"10":{"text":"Their fruit shalt thou destroy from the earth, and their seed from among the children of men.","ref":"Psalms 21:10","synthesized":"You will wipe their descendants from the earth, and their offspring from the sons of men.","sources":{"KJV":{"text":"Their fruit shalt thou destroy from the earth, and their seed from among the children of men."},"BSB":{"text":"You will wipe their descendants from the earth, and their offspring from the sons of men."}},"definableWords":["earth","sons","men"],"peopleInVerse":[]},"11":{"text":"For they intended evil against thee: they imagined a mischievous device, which they are not able to perform.","ref":"Psalms 21:11","synthesized":"Though they intend You harm, the schemes they devise will not prevail.","sources":{"KJV":{"text":"For they intended evil against thee: they imagined a mischievous device, which they are not able to perform."},"BSB":{"text":"Though they intend You harm, the schemes they devise will not prevail."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Therefore shalt thou make them turn their back, when thou shalt make ready thine arrows upon thy strings against the face of them.","ref":"Psalms 21:12","synthesized":"For You will put them to flight when Your bow is trained upon them.","sources":{"KJV":{"text":"Therefore shalt thou make them turn their back, when thou shalt make ready thine arrows upon thy strings against the face of them."},"BSB":{"text":"For You will put them to flight when Your bow is trained upon them."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Be thou exalted, LORD, in thine own strength: so will we sing and praise thy power.","ref":"Psalms 21:13","synthesized":"Be exalted, O LORD, in Your strength; we will sing and praise Your power.","sources":{"KJV":{"text":"Be thou exalted, LORD, in thine own strength: so will we sing and praise thy power."},"BSB":{"text":"Be exalted, O LORD, in Your strength; we will sing and praise Your power."}},"definableWords":["LORD","praise"],"peopleInVerse":[]}}},"22":{"chapter":"22","title":"THE CRUCIFIXION PSALM","verses":{"1":{"text":"My God, my God, why hast thou forsaken me? why art thou so far from helping me, and from the words of my roaring?","ref":"Psalms 22:1","synthesized":"My God, my God, why have You forsaken me? Why are You so far from saving me, so far from my words of groaning?","sources":{"KJV":{"text":"My God, my God, why hast thou forsaken me? why art thou so far from helping me, and from the words of my roaring?"},"BSB":{"text":"My God, my God, why have You forsaken me? Why are You so far from saving me, so far from my words of groaning?"}},"definableWords":["God"],"peopleInVerse":[],"kingdomLens":"Psalm 22 opens with 'My God, my God, why hast thou forsaken me?' — the exact words Jesus cried from the cross (Matt 27:46). The psalm describes pierced hands and feet, bones out of joint, garments parted by casting lots — all CENTURIES before crucifixion existed as a Roman execution method. David wrote what he could not have known by experience, but the Holy Spirit foretold.","cultural":{"title":"The crucifixion psalm — written 1,000 years before","detail":"Crucifixion as a Roman execution wasn't developed until ~6th century BC by the Persians and refined by Rome. Psalm 22 (10th century BC) describes it in vivid detail. The Dead Sea Scrolls preserve this psalm in copies older than Christianity — eliminating any possibility of Christian editing.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"O my God, I cry in the day time, but thou hearest not; and in the night season, and am not silent.","ref":"Psalms 22:2","synthesized":"I cry out by day, O my God, but You do not answer, and by night, but I have no rest.","sources":{"KJV":{"text":"O my God, I cry in the day time, but thou hearest not; and in the night season, and am not silent."},"BSB":{"text":"I cry out by day, O my God, but You do not answer, and by night, but I have no rest."}},"definableWords":["day","God","night","rest"],"peopleInVerse":[]},"3":{"text":"But thou art holy, O thou that inhabitest the praises of Israel.","ref":"Psalms 22:3","synthesized":"Yet You are holy, enthroned on the praises of Israel.","sources":{"KJV":{"text":"But thou art holy, O thou that inhabitest the praises of Israel."},"BSB":{"text":"Yet You are holy, enthroned on the praises of Israel."}},"definableWords":["holy","Israel"],"peopleInVerse":[]},"4":{"text":"Our fathers trusted in thee: they trusted, and thou didst deliver them.","ref":"Psalms 22:4","synthesized":"In You our fathers trusted; they trusted and You delivered them.","sources":{"KJV":{"text":"Our fathers trusted in thee: they trusted, and thou didst deliver them."},"BSB":{"text":"In You our fathers trusted; they trusted and You delivered them."}},"definableWords":["fathers"],"peopleInVerse":[]},"5":{"text":"They cried unto thee, and were delivered: they trusted in thee, and were not confounded.","ref":"Psalms 22:5","synthesized":"They cried out to You and were set free; they trusted in You and were not disappointed.","sources":{"KJV":{"text":"They cried unto thee, and were delivered: they trusted in thee, and were not confounded."},"BSB":{"text":"They cried out to You and were set free; they trusted in You and were not disappointed."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"But I am a worm, and no man; a reproach of men, and despised of the people.","ref":"Psalms 22:6","synthesized":"But I am a worm and not a man, scorned by men and despised by the people.","sources":{"KJV":{"text":"But I am a worm, and no man; a reproach of men, and despised of the people."},"BSB":{"text":"But I am a worm and not a man, scorned by men and despised by the people."}},"definableWords":["man","men","people"],"peopleInVerse":[]},"7":{"text":"All they that see me laugh me to scorn: they shoot out the lip, they shake the head, saying,","ref":"Psalms 22:7","synthesized":"All who see me mock me; they sneer and shake their heads:","sources":{"KJV":{"text":"All they that see me laugh me to scorn: they shoot out the lip, they shake the head, saying,"},"BSB":{"text":"All who see me mock me; they sneer and shake their heads:"}},"definableWords":["see"],"peopleInVerse":[]},"8":{"text":"He trusted on the LORD that he would deliver him: let him deliver him, seeing he delighted in him.","ref":"Psalms 22:8","synthesized":"“He trusts in the LORD, let the LORD deliver him; let the LORD rescue him, since He delights in him.”","sources":{"KJV":{"text":"He trusted on the LORD that he would deliver him: let him deliver him, seeing he delighted in him."},"BSB":{"text":"“He trusts in the LORD, let the LORD deliver him; let the LORD rescue him, since He delights in him.”"}},"definableWords":["LORD","Lord","deliver"],"peopleInVerse":[]},"9":{"text":"But thou art he that took me out of the womb: thou didst make me hope when I was upon my mother’s breasts.","ref":"Psalms 22:9","synthesized":"Yet You brought me forth from the womb; You made me secure at my mother’s breast.","sources":{"KJV":{"text":"But thou art he that took me out of the womb: thou didst make me hope when I was upon my mother’s breasts."},"BSB":{"text":"Yet You brought me forth from the womb; You made me secure at my mother’s breast."}},"definableWords":["made","mother"],"peopleInVerse":[]},"10":{"text":"I was cast upon thee from the womb: thou art my God from my mother’s belly.","ref":"Psalms 22:10","synthesized":"From birth I was cast upon You; from my mother’s womb You have been my God.","sources":{"KJV":{"text":"I was cast upon thee from the womb: thou art my God from my mother’s belly."},"BSB":{"text":"From birth I was cast upon You; from my mother’s womb You have been my God."}},"definableWords":["mother","God"],"peopleInVerse":[]},"11":{"text":"Be not far from me; for trouble is near; for there is none to help.","ref":"Psalms 22:11","synthesized":"Be not far from me, for trouble is near and there is no one to help.","sources":{"KJV":{"text":"Be not far from me; for trouble is near; for there is none to help."},"BSB":{"text":"Be not far from me, for trouble is near and there is no one to help."}},"definableWords":["one"],"peopleInVerse":[]},"12":{"text":"Many bulls have compassed me: strong bulls of Bashan have beset me round.","ref":"Psalms 22:12","synthesized":"Many bulls surround me; strong bulls of Bashan encircle me.","sources":{"KJV":{"text":"Many bulls have compassed me: strong bulls of Bashan have beset me round."},"BSB":{"text":"Many bulls surround me; strong bulls of Bashan encircle me."}},"definableWords":["strong"],"peopleInVerse":[]},"13":{"text":"They gaped upon me with their mouths, as a ravening and a roaring lion.","ref":"Psalms 22:13","synthesized":"They open their jaws against me like lions that roar and maul.","sources":{"KJV":{"text":"They gaped upon me with their mouths, as a ravening and a roaring lion."},"BSB":{"text":"They open their jaws against me like lions that roar and maul."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"I am poured out like water, and all my bones are out of joint: my heart is like wax; it is melted in the midst of my bowels.","ref":"Psalms 22:14","synthesized":"I am poured out like water, and all my bones are disjointed. My heart is like wax; it melts away within me.","sources":{"KJV":{"text":"I am poured out like water, and all my bones are out of joint: my heart is like wax; it is melted in the midst of my bowels."},"BSB":{"text":"I am poured out like water, and all my bones are disjointed. My heart is like wax; it melts away within me."}},"definableWords":["water","bones","heart"],"peopleInVerse":[]},"15":{"text":"My strength is dried up like a potsherd; and my tongue cleaveth to my jaws; and thou hast brought me into the dust of death.","ref":"Psalms 22:15","synthesized":"My strength is dried up like a potsherd, and my tongue sticks to the roof of my mouth. You lay me in the dust of death.","sources":{"KJV":{"text":"My strength is dried up like a potsherd; and my tongue cleaveth to my jaws; and thou hast brought me into the dust of death."},"BSB":{"text":"My strength is dried up like a potsherd, and my tongue sticks to the roof of my mouth. You lay me in the dust of death."}},"definableWords":["death"],"peopleInVerse":[]},"16":{"text":"For dogs have compassed me: the assembly of the wicked have inclosed me: they pierced my hands and my feet.","ref":"Psalms 22:16","synthesized":"For dogs surround me; a band of evil men encircles me; they have pierced my hands and feet.","sources":{"KJV":{"text":"For dogs have compassed me: the assembly of the wicked have inclosed me: they pierced my hands and my feet."},"BSB":{"text":"For dogs surround me; a band of evil men encircles me; they have pierced my hands and feet."}},"definableWords":["evil","men"],"peopleInVerse":[]},"17":{"text":"I may tell all my bones: they look and stare upon me.","ref":"Psalms 22:17","synthesized":"I can count all my bones; they stare and gloat over me.","sources":{"KJV":{"text":"I may tell all my bones: they look and stare upon me."},"BSB":{"text":"I can count all my bones; they stare and gloat over me."}},"definableWords":["bones"],"peopleInVerse":[]},"18":{"text":"They part my garments among them, and cast lots upon my vesture.","ref":"Psalms 22:18","synthesized":"They divide my garments among them and cast lots for my clothing.","sources":{"KJV":{"text":"They part my garments among them, and cast lots upon my vesture."},"BSB":{"text":"They divide my garments among them and cast lots for my clothing."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"But be not thou far from me, O LORD: O my strength, haste thee to help me.","ref":"Psalms 22:19","synthesized":"But You, O LORD, be not far off; O my Strength, come quickly to help me.","sources":{"KJV":{"text":"But be not thou far from me, O LORD: O my strength, haste thee to help me."},"BSB":{"text":"But You, O LORD, be not far off; O my Strength, come quickly to help me."}},"definableWords":["LORD"],"peopleInVerse":[]},"20":{"text":"Deliver my soul from the sword; my darling from the power of the dog.","ref":"Psalms 22:20","synthesized":"Deliver my soul from the sword, my precious life from the power of wild dogs.","sources":{"KJV":{"text":"Deliver my soul from the sword; my darling from the power of the dog."},"BSB":{"text":"Deliver my soul from the sword, my precious life from the power of wild dogs."}},"definableWords":["deliver","soul","life"],"peopleInVerse":[]},"21":{"text":"Save me from the lion’s mouth: for thou hast heard me from the horns of the unicorns.","ref":"Psalms 22:21","synthesized":"Save me from the mouth of the lion; at the horns of the wild oxen You have answered me!","sources":{"KJV":{"text":"Save me from the lion’s mouth: for thou hast heard me from the horns of the unicorns."},"BSB":{"text":"Save me from the mouth of the lion; at the horns of the wild oxen You have answered me!"}},"definableWords":["lion"],"peopleInVerse":[]},"22":{"text":"I will declare thy name unto my brethren: in the midst of the congregation will I praise thee.","ref":"Psalms 22:22","synthesized":"I will proclaim Your name to my brothers; I will praise You in the assembly.","sources":{"KJV":{"text":"I will declare thy name unto my brethren: in the midst of the congregation will I praise thee."},"BSB":{"text":"I will proclaim Your name to my brothers; I will praise You in the assembly."}},"definableWords":["name","praise"],"peopleInVerse":[]},"23":{"text":"Ye that fear the LORD, praise him; all ye the seed of Jacob, glorify him; and fear him, all ye the seed of Israel.","ref":"Psalms 22:23","synthesized":"You who fear the LORD, praise Him! All descendants of Jacob, honor Him! All offspring of Israel, revere Him!","sources":{"KJV":{"text":"Ye that fear the LORD, praise him; all ye the seed of Jacob, glorify him; and fear him, all ye the seed of Israel."},"BSB":{"text":"You who fear the LORD, praise Him! All descendants of Jacob, honor Him! All offspring of Israel, revere Him!"}},"definableWords":["fear","LORD","praise","Jacob","Israel"],"peopleInVerse":["Jacob"]},"24":{"text":"For he hath not despised nor abhorred the affliction of the afflicted; neither hath he hid his face from him; but when he cried unto him, he heard.","ref":"Psalms 22:24","synthesized":"For He has not despised or detested the torment of the afflicted. He has not hidden His face from him, but has attended to his cry for help.","sources":{"KJV":{"text":"For he hath not despised nor abhorred the affliction of the afflicted; neither hath he hid his face from him; but when he cried unto him, he heard."},"BSB":{"text":"For He has not despised or detested the torment of the afflicted. He has not hidden His face from him, but has attended to his cry for help."}},"definableWords":["or"],"peopleInVerse":[]},"25":{"text":"My praise shall be of thee in the great congregation: I will pay my vows before them that fear him.","ref":"Psalms 22:25","synthesized":"My praise for You resounds in the great assembly; I will fulfill my vows before those who fear You.","sources":{"KJV":{"text":"My praise shall be of thee in the great congregation: I will pay my vows before them that fear him."},"BSB":{"text":"My praise for You resounds in the great assembly; I will fulfill my vows before those who fear You."}},"definableWords":["praise","great","fear"],"peopleInVerse":[]},"26":{"text":"The meek shall eat and be satisfied: they shall praise the LORD that seek him: your heart shall live for ever.","ref":"Psalms 22:26","synthesized":"The poor will eat and be satisfied; those who seek the LORD will praise Him. May your hearts live forever!","sources":{"KJV":{"text":"The meek shall eat and be satisfied: they shall praise the LORD that seek him: your heart shall live for ever."},"BSB":{"text":"The poor will eat and be satisfied; those who seek the LORD will praise Him. May your hearts live forever!"}},"definableWords":["seek","LORD","praise","live"],"peopleInVerse":[]},"27":{"text":"All the ends of the world shall remember and turn unto the LORD: and all the kindreds of the nations shall worship before thee.","ref":"Psalms 22:27","synthesized":"All the ends of the earth will remember and turn to the LORD. All the families of the nations will bow down before Him.","sources":{"KJV":{"text":"All the ends of the world shall remember and turn unto the LORD: and all the kindreds of the nations shall worship before thee."},"BSB":{"text":"All the ends of the earth will remember and turn to the LORD. All the families of the nations will bow down before Him."}},"definableWords":["earth","remember","LORD","families","nations"],"peopleInVerse":[]},"28":{"text":"For the kingdom is the LORD’s: and he is the governor among the nations.","ref":"Psalms 22:28","synthesized":"For dominion belongs to the LORD and He rules over the nations.","sources":{"KJV":{"text":"For the kingdom is the LORD’s: and he is the governor among the nations."},"BSB":{"text":"For dominion belongs to the LORD and He rules over the nations."}},"definableWords":["dominion","LORD","nations"],"peopleInVerse":[]},"29":{"text":"All they that be fat upon earth shall eat and worship: all they that go down to the dust shall bow before him: and none can keep alive his own soul.","ref":"Psalms 22:29","synthesized":"All the rich of the earth will feast and worship; all who go down to the dust will kneel before Him— even those unable to preserve their lives.","sources":{"KJV":{"text":"All they that be fat upon earth shall eat and worship: all they that go down to the dust shall bow before him: and none can keep alive his own soul."},"BSB":{"text":"All the rich of the earth will feast and worship; all who go down to the dust will kneel before Him— even those unable to preserve their lives."}},"definableWords":["earth","worship"],"peopleInVerse":[]},"30":{"text":"A seed shall serve him; it shall be accounted to the Lord for a generation.","ref":"Psalms 22:30","synthesized":"Posterity will serve Him; they will declare the Lord to a new generation.","sources":{"KJV":{"text":"A seed shall serve him; it shall be accounted to the Lord for a generation."},"BSB":{"text":"Posterity will serve Him; they will declare the Lord to a new generation."}},"definableWords":["Lord"],"peopleInVerse":[]},"31":{"text":"They shall come, and shall declare his righteousness unto a people that shall be born, that he hath done this.","ref":"Psalms 22:31","synthesized":"They will come and proclaim His righteousness to a people yet unborn— all that He has done.","sources":{"KJV":{"text":"They shall come, and shall declare his righteousness unto a people that shall be born, that he hath done this."},"BSB":{"text":"They will come and proclaim His righteousness to a people yet unborn— all that He has done."}},"definableWords":["righteousness","people"],"peopleInVerse":[]}}},"23":{"chapter":"23","title":"THE LORD IS MY SHEPHERD","verses":{"1":{"text":"The LORD is my shepherd; I shall not want.","ref":"Psalms 23:1","synthesized":"The LORD is my shepherd; I shall not want.","sources":{"KJV":{"text":"The LORD is my shepherd; I shall not want."},"BSB":{"text":"The LORD is my shepherd; I shall not want."}},"definableWords":["LORD","shepherd"],"peopleInVerse":[]},"2":{"text":"He maketh me to lie down in green pastures: he leadeth me beside the still waters.","ref":"Psalms 23:2","synthesized":"He makes me lie down in green pastures; He leads me beside quiet waters.","sources":{"KJV":{"text":"He maketh me to lie down in green pastures: he leadeth me beside the still waters."},"BSB":{"text":"He makes me lie down in green pastures; He leads me beside quiet waters."}},"definableWords":["waters"],"peopleInVerse":[]},"3":{"text":"He restoreth my soul: he leadeth me in the paths of righteousness for his name’s sake.","ref":"Psalms 23:3","synthesized":"He restores my soul; He guides me in the paths of righteousness for the sake of His name.","sources":{"KJV":{"text":"He restoreth my soul: he leadeth me in the paths of righteousness for his name’s sake."},"BSB":{"text":"He restores my soul; He guides me in the paths of righteousness for the sake of His name."}},"definableWords":["soul","righteousness","name"],"peopleInVerse":[]},"4":{"text":"Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me; thy rod and thy staff they comfort me.","ref":"Psalms 23:4","synthesized":"Even though I walk through the valley of the shadow of death, I will fear no evil, for You are with me; Your rod and Your staff, they comfort me.","sources":{"KJV":{"text":"Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me; thy rod and thy staff they comfort me."},"BSB":{"text":"Even though I walk through the valley of the shadow of death, I will fear no evil, for You are with me; Your rod and Your staff, they comfort me."}},"definableWords":["walk","death","fear","evil"],"peopleInVerse":[]},"5":{"text":"Thou preparest a table before me in the presence of mine enemies: thou anointest my head with oil; my cup runneth over.","ref":"Psalms 23:5","synthesized":"You prepare a table before me in the presence of my enemies. You anoint my head with oil; my cup overflows.","sources":{"KJV":{"text":"Thou preparest a table before me in the presence of mine enemies: thou anointest my head with oil; my cup runneth over."},"BSB":{"text":"You prepare a table before me in the presence of my enemies. You anoint my head with oil; my cup overflows."}},"definableWords":["anoint"],"peopleInVerse":[]},"6":{"text":"Surely goodness and mercy shall follow me all the days of my life: and I will dwell in the house of the LORD for ever.","ref":"Psalms 23:6","synthesized":"Surely goodness and mercy will follow me all the days of my life, and I will dwell in the house of the LORD forever.","sources":{"KJV":{"text":"Surely goodness and mercy shall follow me all the days of my life: and I will dwell in the house of the LORD for ever."},"BSB":{"text":"Surely goodness and mercy will follow me all the days of my life, and I will dwell in the house of the LORD forever."}},"definableWords":["mercy","days","life","house","LORD"],"peopleInVerse":[]}}},"24":{"chapter":"24","title":"THE KING OF GLORY","verses":{"1":{"text":"The earth is the LORD’s, and the fulness thereof; the world, and they that dwell therein.","ref":"Psalms 24:1","synthesized":"The earth is the LORD’s, and the fullness thereof, the world and all who dwell therein.","sources":{"KJV":{"text":"The earth is the LORD’s, and the fulness thereof; the world, and they that dwell therein."},"BSB":{"text":"The earth is the LORD’s, and the fullness thereof, the world and all who dwell therein."}},"definableWords":["earth","LORD"],"peopleInVerse":[]},"2":{"text":"For he hath founded it upon the seas, and established it upon the floods.","ref":"Psalms 24:2","synthesized":"For He has founded it upon the seas and established it upon the waters.","sources":{"KJV":{"text":"For he hath founded it upon the seas, and established it upon the floods."},"BSB":{"text":"For He has founded it upon the seas and established it upon the waters."}},"definableWords":["seas","waters"],"peopleInVerse":[]},"3":{"text":"Who shall ascend into the hill of the LORD? or who shall stand in his holy place?","ref":"Psalms 24:3","synthesized":"Who may ascend the hill of the LORD? Who may stand in His holy place?","sources":{"KJV":{"text":"Who shall ascend into the hill of the LORD? or who shall stand in his holy place?"},"BSB":{"text":"Who may ascend the hill of the LORD? Who may stand in His holy place?"}},"definableWords":["LORD","stand","holy"],"peopleInVerse":[]},"4":{"text":"He that hath clean hands, and a pure heart; who hath not lifted up his soul unto vanity, nor sworn deceitfully.","ref":"Psalms 24:4","synthesized":"He who has clean hands and a pure heart, who does not lift up his soul to an idol or swear deceitfully.","sources":{"KJV":{"text":"He that hath clean hands, and a pure heart; who hath not lifted up his soul unto vanity, nor sworn deceitfully."},"BSB":{"text":"He who has clean hands and a pure heart, who does not lift up his soul to an idol or swear deceitfully."}},"definableWords":["heart","soul","or"],"peopleInVerse":[]},"5":{"text":"He shall receive the blessing from the LORD, and righteousness from the God of his salvation.","ref":"Psalms 24:5","synthesized":"He will receive blessing from the LORD and vindication from the God of his salvation.","sources":{"KJV":{"text":"He shall receive the blessing from the LORD, and righteousness from the God of his salvation."},"BSB":{"text":"He will receive blessing from the LORD and vindication from the God of his salvation."}},"definableWords":["blessing","LORD","God","salvation"],"peopleInVerse":[]},"6":{"text":"This is the generation of them that seek him, that seek thy face, O Jacob. Selah.","ref":"Psalms 24:6","synthesized":"Such is the generation of those who seek Him, who seek Your face, O God of Jacob. Selah","sources":{"KJV":{"text":"This is the generation of them that seek him, that seek thy face, O Jacob. Selah."},"BSB":{"text":"Such is the generation of those who seek Him, who seek Your face, O God of Jacob. Selah"}},"definableWords":["seek","God","Jacob"],"peopleInVerse":["Jacob"]},"7":{"text":"Lift up your heads, O ye gates; and be ye lift up, ye everlasting doors; and the King of glory shall come in.","ref":"Psalms 24:7","synthesized":"Lift up your heads, O gates! Be lifted up, O ancient doors, that the King of Glory may enter!","sources":{"KJV":{"text":"Lift up your heads, O ye gates; and be ye lift up, ye everlasting doors; and the King of glory shall come in."},"BSB":{"text":"Lift up your heads, O gates! Be lifted up, O ancient doors, that the King of Glory may enter!"}},"definableWords":["King","glory"],"peopleInVerse":[]},"8":{"text":"Who is this King of glory? The LORD strong and mighty, the LORD mighty in battle.","ref":"Psalms 24:8","synthesized":"Who is this King of Glory? The LORD strong and mighty, the LORD mighty in battle.","sources":{"KJV":{"text":"Who is this King of glory? The LORD strong and mighty, the LORD mighty in battle."},"BSB":{"text":"Who is this King of Glory? The LORD strong and mighty, the LORD mighty in battle."}},"definableWords":["King","glory","LORD","strong","mighty","Lord"],"peopleInVerse":[]},"9":{"text":"Lift up your heads, O ye gates; even lift them up, ye everlasting doors; and the King of glory shall come in.","ref":"Psalms 24:9","synthesized":"Lift up your heads, O gates! Be lifted up, O ancient doors, that the King of Glory may enter!","sources":{"KJV":{"text":"Lift up your heads, O ye gates; even lift them up, ye everlasting doors; and the King of glory shall come in."},"BSB":{"text":"Lift up your heads, O gates! Be lifted up, O ancient doors, that the King of Glory may enter!"}},"definableWords":["King","glory"],"peopleInVerse":[]},"10":{"text":"Who is this King of glory? The LORD of hosts, he is the King of glory. Selah.","ref":"Psalms 24:10","synthesized":"Who is He, this King of Glory? The LORD of Hosts— He is the King of Glory. Selah","sources":{"KJV":{"text":"Who is this King of glory? The LORD of hosts, he is the King of glory. Selah."},"BSB":{"text":"Who is He, this King of Glory? The LORD of Hosts— He is the King of Glory. Selah"}},"definableWords":["King","glory","LORD"],"peopleInVerse":[]}}},"25":{"chapter":"25","title":"UNTO THEE, O LORD, I LIFT MY SOUL","verses":{"1":{"text":"Unto thee, O LORD, do I lift up my soul.","ref":"Psalms 25:1","synthesized":"To You, O LORD, I lift up my soul;","sources":{"KJV":{"text":"Unto thee, O LORD, do I lift up my soul."},"BSB":{"text":"To You, O LORD, I lift up my soul;"}},"definableWords":["LORD","soul"],"peopleInVerse":[]},"2":{"text":"O my God, I trust in thee: let me not be ashamed, let not mine enemies triumph over me.","ref":"Psalms 25:2","synthesized":"in You, my God, I trust. Do not let me be put to shame; do not let my enemies exult over me.","sources":{"KJV":{"text":"O my God, I trust in thee: let me not be ashamed, let not mine enemies triumph over me."},"BSB":{"text":"in You, my God, I trust. Do not let me be put to shame; do not let my enemies exult over me."}},"definableWords":["God","trust"],"peopleInVerse":[]},"3":{"text":"Yea, let none that wait on thee be ashamed: let them be ashamed which transgress without cause.","ref":"Psalms 25:3","synthesized":"Surely none who wait for You will be put to shame; but those who are faithless without cause will be disgraced.","sources":{"KJV":{"text":"Yea, let none that wait on thee be ashamed: let them be ashamed which transgress without cause."},"BSB":{"text":"Surely none who wait for You will be put to shame; but those who are faithless without cause will be disgraced."}},"definableWords":["wait"],"peopleInVerse":[]},"4":{"text":"Shew me thy ways, O LORD; teach me thy paths.","ref":"Psalms 25:4","synthesized":"Show me Your ways, O LORD; teach me Your paths.","sources":{"KJV":{"text":"Shew me thy ways, O LORD; teach me thy paths."},"BSB":{"text":"Show me Your ways, O LORD; teach me Your paths."}},"definableWords":["LORD"],"peopleInVerse":[]},"5":{"text":"Lead me in thy truth, and teach me: for thou art the God of my salvation; on thee do I wait all the day.","ref":"Psalms 25:5","synthesized":"Guide me in Your truth and teach me, for You are the God of my salvation; all day long I wait for You.","sources":{"KJV":{"text":"Lead me in thy truth, and teach me: for thou art the God of my salvation; on thee do I wait all the day."},"BSB":{"text":"Guide me in Your truth and teach me, for You are the God of my salvation; all day long I wait for You."}},"definableWords":["truth","God","salvation","day","wait"],"peopleInVerse":[]},"6":{"text":"Remember, O LORD, thy tender mercies and thy lovingkindnesses; for they have been ever of old.","ref":"Psalms 25:6","synthesized":"Remember, O LORD, Your compassion and loving devotion, for they are from age to age.","sources":{"KJV":{"text":"Remember, O LORD, thy tender mercies and thy lovingkindnesses; for they have been ever of old."},"BSB":{"text":"Remember, O LORD, Your compassion and loving devotion, for they are from age to age."}},"definableWords":["remember","LORD"],"peopleInVerse":[]},"7":{"text":"Remember not the sins of my youth, nor my transgressions: according to thy mercy remember thou me for thy goodness’ sake, O LORD.","ref":"Psalms 25:7","synthesized":"Remember not the sins of my youth, nor my rebellious acts; remember me according to Your loving devotion, because of Your goodness, O LORD.","sources":{"KJV":{"text":"Remember not the sins of my youth, nor my transgressions: according to thy mercy remember thou me for thy goodness’ sake, O LORD."},"BSB":{"text":"Remember not the sins of my youth, nor my rebellious acts; remember me according to Your loving devotion, because of Your goodness, O LORD."}},"definableWords":["remember","LORD"],"peopleInVerse":[]},"8":{"text":"Good and upright is the LORD: therefore will he teach sinners in the way.","ref":"Psalms 25:8","synthesized":"Good and upright is the LORD; therefore He shows sinners the way.","sources":{"KJV":{"text":"Good and upright is the LORD: therefore will he teach sinners in the way."},"BSB":{"text":"Good and upright is the LORD; therefore He shows sinners the way."}},"definableWords":["good","LORD","way"],"peopleInVerse":[]},"9":{"text":"The meek will he guide in judgment: and the meek will he teach his way.","ref":"Psalms 25:9","synthesized":"He guides the humble in what is right and teaches them His way.","sources":{"KJV":{"text":"The meek will he guide in judgment: and the meek will he teach his way."},"BSB":{"text":"He guides the humble in what is right and teaches them His way."}},"definableWords":["way"],"peopleInVerse":[]},"10":{"text":"All the paths of the LORD are mercy and truth unto such as keep his covenant and his testimonies.","ref":"Psalms 25:10","synthesized":"All the LORD’s ways are loving and faithful to those who keep His covenant and His decrees.","sources":{"KJV":{"text":"All the paths of the LORD are mercy and truth unto such as keep his covenant and his testimonies."},"BSB":{"text":"All the LORD’s ways are loving and faithful to those who keep His covenant and His decrees."}},"definableWords":["LORD","keep","covenant"],"peopleInVerse":[]},"11":{"text":"For thy name’s sake, O LORD, pardon mine iniquity; for it is great.","ref":"Psalms 25:11","synthesized":"For the sake of Your name, O LORD, forgive my iniquity, for it is great.","sources":{"KJV":{"text":"For thy name’s sake, O LORD, pardon mine iniquity; for it is great."},"BSB":{"text":"For the sake of Your name, O LORD, forgive my iniquity, for it is great."}},"definableWords":["name","LORD","forgive","iniquity","great"],"peopleInVerse":[]},"12":{"text":"What man is he that feareth the LORD? him shall he teach in the way that he shall choose.","ref":"Psalms 25:12","synthesized":"Who is the man who fears the LORD? He will instruct him in the path chosen for him.","sources":{"KJV":{"text":"What man is he that feareth the LORD? him shall he teach in the way that he shall choose."},"BSB":{"text":"Who is the man who fears the LORD? He will instruct him in the path chosen for him."}},"definableWords":["man","LORD"],"peopleInVerse":[]},"13":{"text":"His soul shall dwell at ease; and his seed shall inherit the earth.","ref":"Psalms 25:13","synthesized":"His soul will dwell in prosperity, and his descendants will inherit the land.","sources":{"KJV":{"text":"His soul shall dwell at ease; and his seed shall inherit the earth."},"BSB":{"text":"His soul will dwell in prosperity, and his descendants will inherit the land."}},"definableWords":["soul","inherit","land"],"peopleInVerse":[]},"14":{"text":"The secret of the LORD is with them that fear him; and he will shew them his covenant.","ref":"Psalms 25:14","synthesized":"The LORD confides in those who fear Him, and reveals His covenant to them.","sources":{"KJV":{"text":"The secret of the LORD is with them that fear him; and he will shew them his covenant."},"BSB":{"text":"The LORD confides in those who fear Him, and reveals His covenant to them."}},"definableWords":["LORD","fear","covenant"],"peopleInVerse":[]},"15":{"text":"Mine eyes are ever toward the LORD; for he shall pluck my feet out of the net.","ref":"Psalms 25:15","synthesized":"My eyes are always on the LORD, for He will free my feet from the mesh.","sources":{"KJV":{"text":"Mine eyes are ever toward the LORD; for he shall pluck my feet out of the net."},"BSB":{"text":"My eyes are always on the LORD, for He will free my feet from the mesh."}},"definableWords":["LORD"],"peopleInVerse":[]},"16":{"text":"Turn thee unto me, and have mercy upon me; for I am desolate and afflicted.","ref":"Psalms 25:16","synthesized":"Turn to me and be gracious, for I am lonely and afflicted.","sources":{"KJV":{"text":"Turn thee unto me, and have mercy upon me; for I am desolate and afflicted."},"BSB":{"text":"Turn to me and be gracious, for I am lonely and afflicted."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"The troubles of my heart are enlarged: O bring thou me out of my distresses.","ref":"Psalms 25:17","synthesized":"The troubles of my heart increase; free me from my distress.","sources":{"KJV":{"text":"The troubles of my heart are enlarged: O bring thou me out of my distresses."},"BSB":{"text":"The troubles of my heart increase; free me from my distress."}},"definableWords":["heart"],"peopleInVerse":[]},"18":{"text":"Look upon mine affliction and my pain; and forgive all my sins.","ref":"Psalms 25:18","synthesized":"Consider my affliction and trouble, and take away all my sins.","sources":{"KJV":{"text":"Look upon mine affliction and my pain; and forgive all my sins."},"BSB":{"text":"Consider my affliction and trouble, and take away all my sins."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Consider mine enemies; for they are many; and they hate me with cruel hatred.","ref":"Psalms 25:19","synthesized":"Consider my enemies, for they are many, and they hate me with vicious hatred.","sources":{"KJV":{"text":"Consider mine enemies; for they are many; and they hate me with cruel hatred."},"BSB":{"text":"Consider my enemies, for they are many, and they hate me with vicious hatred."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"O keep my soul, and deliver me: let me not be ashamed; for I put my trust in thee.","ref":"Psalms 25:20","synthesized":"Guard my soul and deliver me; let me not be put to shame, for I take refuge in You.","sources":{"KJV":{"text":"O keep my soul, and deliver me: let me not be ashamed; for I put my trust in thee."},"BSB":{"text":"Guard my soul and deliver me; let me not be put to shame, for I take refuge in You."}},"definableWords":["soul","deliver"],"peopleInVerse":[]},"21":{"text":"Let integrity and uprightness preserve me; for I wait on thee.","ref":"Psalms 25:21","synthesized":"May integrity and uprightness preserve me, because I wait for You.","sources":{"KJV":{"text":"Let integrity and uprightness preserve me; for I wait on thee."},"BSB":{"text":"May integrity and uprightness preserve me, because I wait for You."}},"definableWords":["wait"],"peopleInVerse":[]},"22":{"text":"Redeem Israel, O God, out of all his troubles.","ref":"Psalms 25:22","synthesized":"Redeem Israel, O God, from all its distress.","sources":{"KJV":{"text":"Redeem Israel, O God, out of all his troubles."},"BSB":{"text":"Redeem Israel, O God, from all its distress."}},"definableWords":["Israel","God"],"peopleInVerse":[]}}},"26":{"chapter":"26","title":"JUDGE ME, O LORD","verses":{"1":{"text":"Judge me, O LORD; for I have walked in mine integrity: I have trusted also in the LORD; therefore I shall not slide.","ref":"Psalms 26:1","synthesized":"Vindicate me, O LORD!   For I have walked with integrity; I have trusted in the LORD without wavering.","sources":{"KJV":{"text":"Judge me, O LORD; for I have walked in mine integrity: I have trusted also in the LORD; therefore I shall not slide."},"BSB":{"text":"Vindicate me, O LORD!   For I have walked with integrity; I have trusted in the LORD without wavering."}},"definableWords":["LORD","walked","Lord"],"peopleInVerse":[]},"2":{"text":"Examine me, O LORD, and prove me; try my reins and my heart.","ref":"Psalms 26:2","synthesized":"Test me, O LORD, and try me; examine my heart and mind.","sources":{"KJV":{"text":"Examine me, O LORD, and prove me; try my reins and my heart."},"BSB":{"text":"Test me, O LORD, and try me; examine my heart and mind."}},"definableWords":["LORD","heart","mind"],"peopleInVerse":[]},"3":{"text":"For thy lovingkindness is before mine eyes: and I have walked in thy truth.","ref":"Psalms 26:3","synthesized":"For Your loving devotion is before my eyes, and I have walked in Your truth.","sources":{"KJV":{"text":"For thy lovingkindness is before mine eyes: and I have walked in thy truth."},"BSB":{"text":"For Your loving devotion is before my eyes, and I have walked in Your truth."}},"definableWords":["walked","truth"],"peopleInVerse":[]},"4":{"text":"I have not sat with vain persons, neither will I go in with dissemblers.","ref":"Psalms 26:4","synthesized":"I do not sit with deceitful men, nor keep company with hypocrites.","sources":{"KJV":{"text":"I have not sat with vain persons, neither will I go in with dissemblers."},"BSB":{"text":"I do not sit with deceitful men, nor keep company with hypocrites."}},"definableWords":["men","keep"],"peopleInVerse":[]},"5":{"text":"I have hated the congregation of evil doers; and will not sit with the wicked.","ref":"Psalms 26:5","synthesized":"I hate the mob of evildoers, and refuse to sit with the wicked.","sources":{"KJV":{"text":"I have hated the congregation of evil doers; and will not sit with the wicked."},"BSB":{"text":"I hate the mob of evildoers, and refuse to sit with the wicked."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"I will wash mine hands in innocency: so will I compass thine altar, O LORD:","ref":"Psalms 26:6","synthesized":"I wash my hands in innocence that I may go about Your altar, O LORD,","sources":{"KJV":{"text":"I will wash mine hands in innocency: so will I compass thine altar, O LORD:"},"BSB":{"text":"I wash my hands in innocence that I may go about Your altar, O LORD,"}},"definableWords":["altar","LORD"],"peopleInVerse":[]},"7":{"text":"That I may publish with the voice of thanksgiving, and tell of all thy wondrous works.","ref":"Psalms 26:7","synthesized":"to raise my voice in thanksgiving and declare all Your wonderful works.","sources":{"KJV":{"text":"That I may publish with the voice of thanksgiving, and tell of all thy wondrous works."},"BSB":{"text":"to raise my voice in thanksgiving and declare all Your wonderful works."}},"definableWords":["voice","works"],"peopleInVerse":[]},"8":{"text":"LORD, I have loved the habitation of thy house, and the place where thine honour dwelleth.","ref":"Psalms 26:8","synthesized":"O LORD, I love the house where You dwell, the place where Your glory resides.","sources":{"KJV":{"text":"LORD, I have loved the habitation of thy house, and the place where thine honour dwelleth."},"BSB":{"text":"O LORD, I love the house where You dwell, the place where Your glory resides."}},"definableWords":["LORD","love","house","glory"],"peopleInVerse":[]},"9":{"text":"Gather not my soul with sinners, nor my life with bloody men:","ref":"Psalms 26:9","synthesized":"Do not take my soul away with sinners, or my life with men of bloodshed,","sources":{"KJV":{"text":"Gather not my soul with sinners, nor my life with bloody men:"},"BSB":{"text":"Do not take my soul away with sinners, or my life with men of bloodshed,"}},"definableWords":["soul","or","life","men"],"peopleInVerse":[]},"10":{"text":"In whose hands is mischief, and their right hand is full of bribes.","ref":"Psalms 26:10","synthesized":"in whose hands are wicked schemes, whose right hands are full of bribes.","sources":{"KJV":{"text":"In whose hands is mischief, and their right hand is full of bribes."},"BSB":{"text":"in whose hands are wicked schemes, whose right hands are full of bribes."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"But as for me, I will walk in mine integrity: redeem me, and be merciful unto me.","ref":"Psalms 26:11","synthesized":"But I will walk with integrity; redeem me and be merciful to me.","sources":{"KJV":{"text":"But as for me, I will walk in mine integrity: redeem me, and be merciful unto me."},"BSB":{"text":"But I will walk with integrity; redeem me and be merciful to me."}},"definableWords":["walk"],"peopleInVerse":[]},"12":{"text":"My foot standeth in an even place: in the congregations will I bless the LORD.","ref":"Psalms 26:12","synthesized":"My feet stand on level ground; in the congregations I will bless the LORD.","sources":{"KJV":{"text":"My foot standeth in an even place: in the congregations will I bless the LORD."},"BSB":{"text":"My feet stand on level ground; in the congregations I will bless the LORD."}},"definableWords":["stand","ground","bless","LORD"],"peopleInVerse":[]}}},"27":{"chapter":"27","title":"THE LORD IS MY LIGHT","verses":{"1":{"text":"The LORD is my light and my salvation; whom shall I fear? the LORD is the strength of my life; of whom shall I be afraid?","ref":"Psalms 27:1","synthesized":"The LORD is my light and my salvation— whom shall I fear? The LORD is the stronghold of my life— whom shall I dread?","sources":{"KJV":{"text":"The LORD is my light and my salvation; whom shall I fear? the LORD is the strength of my life; of whom shall I be afraid?"},"BSB":{"text":"The LORD is my light and my salvation— whom shall I fear? The LORD is the stronghold of my life— whom shall I dread?"}},"definableWords":["LORD","light","salvation","fear","Lord","life"],"peopleInVerse":[]},"2":{"text":"When the wicked, even mine enemies and my foes, came upon me to eat up my flesh, they stumbled and fell.","ref":"Psalms 27:2","synthesized":"When the wicked came upon me to devour my flesh, my enemies and foes stumbled and fell.","sources":{"KJV":{"text":"When the wicked, even mine enemies and my foes, came upon me to eat up my flesh, they stumbled and fell."},"BSB":{"text":"When the wicked came upon me to devour my flesh, my enemies and foes stumbled and fell."}},"definableWords":["flesh"],"peopleInVerse":[]},"3":{"text":"Though an host should encamp against me, my heart shall not fear: though war should rise against me, in this will I be confident.","ref":"Psalms 27:3","synthesized":"Though an army encamps around me, my heart will not fear; though a war breaks out against me, I will keep my trust.","sources":{"KJV":{"text":"Though an host should encamp against me, my heart shall not fear: though war should rise against me, in this will I be confident."},"BSB":{"text":"Though an army encamps around me, my heart will not fear; though a war breaks out against me, I will keep my trust."}},"definableWords":["heart","fear","keep","trust"],"peopleInVerse":[]},"4":{"text":"One thing have I desired of the LORD, that will I seek after; that I may dwell in the house of the LORD all the days of my life, to behold the beauty of the LORD, and to enquire in his temple.","ref":"Psalms 27:4","synthesized":"One thing I have asked of the LORD; this is what I desire: to dwell in the house of the LORD all the days of my life, to gaze on the beauty of the LORD and seek Him in His temple.","sources":{"KJV":{"text":"One thing have I desired of the LORD, that will I seek after; that I may dwell in the house of the LORD all the days of my life, to behold the beauty of the LORD, and to enquire in his temple."},"BSB":{"text":"One thing I have asked of the LORD; this is what I desire: to dwell in the house of the LORD all the days of my life, to gaze on the beauty of the LORD and seek Him in His temple."}},"definableWords":["one","LORD","house","Lord","days","life","seek","temple"],"peopleInVerse":[]},"5":{"text":"For in the time of trouble he shall hide me in his pavilion: in the secret of his tabernacle shall he hide me; he shall set me up upon a rock.","ref":"Psalms 27:5","synthesized":"For in the day of trouble He will hide me in His shelter; He will conceal me under the cover of His tent; He will set me high upon a rock.","sources":{"KJV":{"text":"For in the time of trouble he shall hide me in his pavilion: in the secret of his tabernacle shall he hide me; he shall set me up upon a rock."},"BSB":{"text":"For in the day of trouble He will hide me in His shelter; He will conceal me under the cover of His tent; He will set me high upon a rock."}},"definableWords":["day"],"peopleInVerse":[]},"6":{"text":"And now shall mine head be lifted up above mine enemies round about me: therefore will I offer in his tabernacle sacrifices of joy; I will sing, yea, I will sing praises unto the LORD.","ref":"Psalms 27:6","synthesized":"Then my head will be held high above my enemies around me. At His tabernacle I will offer sacrifices with shouts of joy; I will sing and make music to the LORD.","sources":{"KJV":{"text":"And now shall mine head be lifted up above mine enemies round about me: therefore will I offer in his tabernacle sacrifices of joy; I will sing, yea, I will sing praises unto the LORD."},"BSB":{"text":"Then my head will be held high above my enemies around me. At His tabernacle I will offer sacrifices with shouts of joy; I will sing and make music to the LORD."}},"definableWords":["tabernacle","joy","make","LORD"],"peopleInVerse":[]},"7":{"text":"Hear, O LORD, when I cry with my voice: have mercy also upon me, and answer me.","ref":"Psalms 27:7","synthesized":"Hear, O LORD, my voice when I call; be merciful and answer me.","sources":{"KJV":{"text":"Hear, O LORD, when I cry with my voice: have mercy also upon me, and answer me."},"BSB":{"text":"Hear, O LORD, my voice when I call; be merciful and answer me."}},"definableWords":["hear","LORD","voice"],"peopleInVerse":[]},"8":{"text":"When thou saidst, Seek ye my face; my heart said unto thee, Thy face, LORD, will I seek.","ref":"Psalms 27:8","synthesized":"My heart said, “Seek His face.” Your face, O LORD, I will seek.","sources":{"KJV":{"text":"When thou saidst, Seek ye my face; my heart said unto thee, Thy face, LORD, will I seek."},"BSB":{"text":"My heart said, “Seek His face.” Your face, O LORD, I will seek."}},"definableWords":["heart","seek","LORD"],"peopleInVerse":[]},"9":{"text":"Hide not thy face far from me; put not thy servant away in anger: thou hast been my help; leave me not, neither forsake me, O God of my salvation.","ref":"Psalms 27:9","synthesized":"Hide not Your face from me, nor turn away Your servant in anger. You have been my helper; do not leave me or forsake me, O God of my salvation.","sources":{"KJV":{"text":"Hide not thy face far from me; put not thy servant away in anger: thou hast been my help; leave me not, neither forsake me, O God of my salvation."},"BSB":{"text":"Hide not Your face from me, nor turn away Your servant in anger. You have been my helper; do not leave me or forsake me, O God of my salvation."}},"definableWords":["servant","anger","helper","or","God","salvation"],"peopleInVerse":[]},"10":{"text":"When my father and my mother forsake me, then the LORD will take me up.","ref":"Psalms 27:10","synthesized":"Though my father and mother forsake me, the LORD will receive me.","sources":{"KJV":{"text":"When my father and my mother forsake me, then the LORD will take me up."},"BSB":{"text":"Though my father and mother forsake me, the LORD will receive me."}},"definableWords":["father","mother","LORD"],"peopleInVerse":[]},"11":{"text":"Teach me thy way, O LORD, and lead me in a plain path, because of mine enemies.","ref":"Psalms 27:11","synthesized":"Teach me Your way, O LORD, and lead me on a level path, because of my oppressors.","sources":{"KJV":{"text":"Teach me thy way, O LORD, and lead me in a plain path, because of mine enemies."},"BSB":{"text":"Teach me Your way, O LORD, and lead me on a level path, because of my oppressors."}},"definableWords":["way","LORD"],"peopleInVerse":[]},"12":{"text":"Deliver me not over unto the will of mine enemies: for false witnesses are risen up against me, and such as breathe out cruelty.","ref":"Psalms 27:12","synthesized":"Do not hand me over to the will of my foes, for false witnesses rise up against me, breathing out violence.","sources":{"KJV":{"text":"Deliver me not over unto the will of mine enemies: for false witnesses are risen up against me, and such as breathe out cruelty."},"BSB":{"text":"Do not hand me over to the will of my foes, for false witnesses rise up against me, breathing out violence."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"I had fainted, unless I had believed to see the goodness of the LORD in the land of the living.","ref":"Psalms 27:13","synthesized":"Still I am certain to see the goodness of the LORD in the land of the living.","sources":{"KJV":{"text":"I had fainted, unless I had believed to see the goodness of the LORD in the land of the living."},"BSB":{"text":"Still I am certain to see the goodness of the LORD in the land of the living."}},"definableWords":["see","LORD","land","living"],"peopleInVerse":[]},"14":{"text":"Wait on the LORD: be of good courage, and he shall strengthen thine heart: wait, I say, on the LORD.","ref":"Psalms 27:14","synthesized":"Wait patiently for the LORD; be strong and courageous.   Wait patiently for the LORD!","sources":{"KJV":{"text":"Wait on the LORD: be of good courage, and he shall strengthen thine heart: wait, I say, on the LORD."},"BSB":{"text":"Wait patiently for the LORD; be strong and courageous.   Wait patiently for the LORD!"}},"definableWords":["wait","LORD","strong","Lord"],"peopleInVerse":[]}}},"28":{"chapter":"28","title":"UNTO THEE WILL I CRY, O LORD","verses":{"1":{"text":"Unto thee will I cry, O LORD my rock; be not silent to me: lest, if thou be silent to me, I become like them that go down into the pit.","ref":"Psalms 28:1","synthesized":"To You, O LORD, I call; be not deaf to me, O my Rock. For if You remain silent, I will be like those descending to the Pit.","sources":{"KJV":{"text":"Unto thee will I cry, O LORD my rock; be not silent to me: lest, if thou be silent to me, I become like them that go down into the pit."},"BSB":{"text":"To You, O LORD, I call; be not deaf to me, O my Rock. For if You remain silent, I will be like those descending to the Pit."}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"Hear the voice of my supplications, when I cry unto thee, when I lift up my hands toward thy holy oracle.","ref":"Psalms 28:2","synthesized":"Hear my cry for mercy when I call to You for help, when I lift up my hands toward Your holy sanctuary.","sources":{"KJV":{"text":"Hear the voice of my supplications, when I cry unto thee, when I lift up my hands toward thy holy oracle."},"BSB":{"text":"Hear my cry for mercy when I call to You for help, when I lift up my hands toward Your holy sanctuary."}},"definableWords":["hear","mercy","holy"],"peopleInVerse":[]},"3":{"text":"Draw me not away with the wicked, and with the workers of iniquity, which speak peace to their neighbours, but mischief is in their hearts.","ref":"Psalms 28:3","synthesized":"Do not drag me away with the wicked, and with the workers of iniquity, who speak peace to their neighbors while malice is in their hearts.","sources":{"KJV":{"text":"Draw me not away with the wicked, and with the workers of iniquity, which speak peace to their neighbours, but mischief is in their hearts."},"BSB":{"text":"Do not drag me away with the wicked, and with the workers of iniquity, who speak peace to their neighbors while malice is in their hearts."}},"definableWords":["iniquity","peace"],"peopleInVerse":[]},"4":{"text":"Give them according to their deeds, and according to the wickedness of their endeavours: give them after the work of their hands; render to them their desert.","ref":"Psalms 28:4","synthesized":"Repay them according to their deeds and for their works of evil. Repay them for what their hands have done; bring back on them what they deserve.","sources":{"KJV":{"text":"Give them according to their deeds, and according to the wickedness of their endeavours: give them after the work of their hands; render to them their desert."},"BSB":{"text":"Repay them according to their deeds and for their works of evil. Repay them for what their hands have done; bring back on them what they deserve."}},"definableWords":["works","evil"],"peopleInVerse":[]},"5":{"text":"Because they regard not the works of the LORD, nor the operation of his hands, he shall destroy them, and not build them up.","ref":"Psalms 28:5","synthesized":"Since they show no regard for the works of the LORD or what His hands have done, He will tear them down and never rebuild them.","sources":{"KJV":{"text":"Because they regard not the works of the LORD, nor the operation of his hands, he shall destroy them, and not build them up."},"BSB":{"text":"Since they show no regard for the works of the LORD or what His hands have done, He will tear them down and never rebuild them."}},"definableWords":["works","LORD","or"],"peopleInVerse":[]},"6":{"text":"Blessed be the LORD, because he hath heard the voice of my supplications.","ref":"Psalms 28:6","synthesized":"Blessed be the LORD, for He has heard my cry for mercy.","sources":{"KJV":{"text":"Blessed be the LORD, because he hath heard the voice of my supplications."},"BSB":{"text":"Blessed be the LORD, for He has heard my cry for mercy."}},"definableWords":["blessed","LORD","mercy"],"peopleInVerse":[]},"7":{"text":"The LORD is my strength and my shield; my heart trusted in him, and I am helped: therefore my heart greatly rejoiceth; and with my song will I praise him.","ref":"Psalms 28:7","synthesized":"The LORD is my strength and my shield; my heart trusts in Him, and I am helped. Therefore my heart rejoices, and I give thanks to Him with my song.","sources":{"KJV":{"text":"The LORD is my strength and my shield; my heart trusted in him, and I am helped: therefore my heart greatly rejoiceth; and with my song will I praise him."},"BSB":{"text":"The LORD is my strength and my shield; my heart trusts in Him, and I am helped. Therefore my heart rejoices, and I give thanks to Him with my song."}},"definableWords":["LORD","heart"],"peopleInVerse":[]},"8":{"text":"The LORD is their strength, and he is the saving strength of his anointed.","ref":"Psalms 28:8","synthesized":"The LORD is the strength of His people, a stronghold of salvation for His anointed.","sources":{"KJV":{"text":"The LORD is their strength, and he is the saving strength of his anointed."},"BSB":{"text":"The LORD is the strength of His people, a stronghold of salvation for His anointed."}},"definableWords":["LORD","people","salvation"],"peopleInVerse":[]},"9":{"text":"Save thy people, and bless thine inheritance: feed them also, and lift them up for ever.","ref":"Psalms 28:9","synthesized":"Save Your people and bless Your inheritance; shepherd them and carry them forever.","sources":{"KJV":{"text":"Save thy people, and bless thine inheritance: feed them also, and lift them up for ever."},"BSB":{"text":"Save Your people and bless Your inheritance; shepherd them and carry them forever."}},"definableWords":["people","bless","shepherd"],"peopleInVerse":[]}}},"29":{"chapter":"29","title":"THE VOICE OF THE LORD UPON THE WATERS","verses":{"1":{"text":"Give unto the LORD, O ye mighty, give unto the LORD glory and strength.","ref":"Psalms 29:1","synthesized":"Ascribe to the LORD, O heavenly beings, ascribe to the LORD glory and strength.","sources":{"KJV":{"text":"Give unto the LORD, O ye mighty, give unto the LORD glory and strength."},"BSB":{"text":"Ascribe to the LORD, O heavenly beings, ascribe to the LORD glory and strength."}},"definableWords":["LORD","Lord","glory"],"peopleInVerse":[]},"2":{"text":"Give unto the LORD the glory due unto his name; worship the LORD in the beauty of holiness.","ref":"Psalms 29:2","synthesized":"Ascribe to the LORD the glory due His name; worship the LORD in the splendor of His holiness.","sources":{"KJV":{"text":"Give unto the LORD the glory due unto his name; worship the LORD in the beauty of holiness."},"BSB":{"text":"Ascribe to the LORD the glory due His name; worship the LORD in the splendor of His holiness."}},"definableWords":["LORD","glory","name","worship","Lord"],"peopleInVerse":[]},"3":{"text":"The voice of the LORD is upon the waters: the God of glory thundereth: the LORD is upon many waters.","ref":"Psalms 29:3","synthesized":"The voice of the LORD is over the waters; the God of glory thunders; the LORD is heard over many waters.","sources":{"KJV":{"text":"The voice of the LORD is upon the waters: the God of glory thundereth: the LORD is upon many waters."},"BSB":{"text":"The voice of the LORD is over the waters; the God of glory thunders; the LORD is heard over many waters."}},"definableWords":["voice","LORD","waters","God","glory","Lord"],"peopleInVerse":[]},"4":{"text":"The voice of the LORD is powerful; the voice of the LORD is full of majesty.","ref":"Psalms 29:4","synthesized":"The voice of the LORD is powerful; the voice of the LORD is majestic.","sources":{"KJV":{"text":"The voice of the LORD is powerful; the voice of the LORD is full of majesty."},"BSB":{"text":"The voice of the LORD is powerful; the voice of the LORD is majestic."}},"definableWords":["voice","LORD","Lord"],"peopleInVerse":[]},"5":{"text":"The voice of the LORD breaketh the cedars; yea, the LORD breaketh the cedars of Lebanon.","ref":"Psalms 29:5","synthesized":"The voice of the LORD breaks the cedars; the LORD shatters the cedars of Lebanon.","sources":{"KJV":{"text":"The voice of the LORD breaketh the cedars; yea, the LORD breaketh the cedars of Lebanon."},"BSB":{"text":"The voice of the LORD breaks the cedars; the LORD shatters the cedars of Lebanon."}},"definableWords":["voice","LORD","Lord"],"peopleInVerse":[]},"6":{"text":"He maketh them also to skip like a calf; Lebanon and Sirion like a young unicorn.","ref":"Psalms 29:6","synthesized":"He makes Lebanon skip like a calf, and Sirion like a young wild ox.","sources":{"KJV":{"text":"He maketh them also to skip like a calf; Lebanon and Sirion like a young unicorn."},"BSB":{"text":"He makes Lebanon skip like a calf, and Sirion like a young wild ox."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"The voice of the LORD divideth the flames of fire.","ref":"Psalms 29:7","synthesized":"The voice of the LORD strikes with flames of fire.","sources":{"KJV":{"text":"The voice of the LORD divideth the flames of fire."},"BSB":{"text":"The voice of the LORD strikes with flames of fire."}},"definableWords":["voice","LORD"],"peopleInVerse":[]},"8":{"text":"The voice of the LORD shaketh the wilderness; the LORD shaketh the wilderness of Kadesh.","ref":"Psalms 29:8","synthesized":"The voice of the LORD shakes the wilderness; the LORD shakes the Wilderness of Kadesh.","sources":{"KJV":{"text":"The voice of the LORD shaketh the wilderness; the LORD shaketh the wilderness of Kadesh."},"BSB":{"text":"The voice of the LORD shakes the wilderness; the LORD shakes the Wilderness of Kadesh."}},"definableWords":["voice","LORD","Lord"],"peopleInVerse":[]},"9":{"text":"The voice of the LORD maketh the hinds to calve, and discovereth the forests: and in his temple doth every one speak of his glory.","ref":"Psalms 29:9","synthesized":"The voice of the LORD twists the oaks and strips the forests bare. And in His temple all cry, “Glory!”","sources":{"KJV":{"text":"The voice of the LORD maketh the hinds to calve, and discovereth the forests: and in his temple doth every one speak of his glory."},"BSB":{"text":"The voice of the LORD twists the oaks and strips the forests bare. And in His temple all cry, “Glory!”"}},"definableWords":["voice","LORD","temple","glory"],"peopleInVerse":[]},"10":{"text":"The LORD sitteth upon the flood; yea, the LORD sitteth King for ever.","ref":"Psalms 29:10","synthesized":"The LORD sits enthroned over the flood; the LORD is enthroned as King forever.","sources":{"KJV":{"text":"The LORD sitteth upon the flood; yea, the LORD sitteth King for ever."},"BSB":{"text":"The LORD sits enthroned over the flood; the LORD is enthroned as King forever."}},"definableWords":["LORD","flood","Lord","King"],"peopleInVerse":[]},"11":{"text":"The LORD will give strength unto his people; the LORD will bless his people with peace.","ref":"Psalms 29:11","synthesized":"The LORD gives His people strength; the LORD blesses His people with peace.","sources":{"KJV":{"text":"The LORD will give strength unto his people; the LORD will bless his people with peace."},"BSB":{"text":"The LORD gives His people strength; the LORD blesses His people with peace."}},"definableWords":["LORD","people","Lord","peace"],"peopleInVerse":[]}}},"30":{"chapter":"30","title":"WEEPING ENDURES FOR A NIGHT","verses":{"1":{"text":"I will extol thee, O LORD; for thou hast lifted me up, and hast not made my foes to rejoice over me.","ref":"Psalms 30:1","synthesized":"I will exalt You, O LORD, for You have lifted me up and have not allowed my foes to rejoice over me.","sources":{"KJV":{"text":"I will extol thee, O LORD; for thou hast lifted me up, and hast not made my foes to rejoice over me."},"BSB":{"text":"I will exalt You, O LORD, for You have lifted me up and have not allowed my foes to rejoice over me."}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"O LORD my God, I cried unto thee, and thou hast healed me.","ref":"Psalms 30:2","synthesized":"O LORD my God, I cried to You for help, and You healed me.","sources":{"KJV":{"text":"O LORD my God, I cried unto thee, and thou hast healed me."},"BSB":{"text":"O LORD my God, I cried to You for help, and You healed me."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"3":{"text":"O LORD, thou hast brought up my soul from the grave: thou hast kept me alive, that I should not go down to the pit.","ref":"Psalms 30:3","synthesized":"O LORD, You pulled me up from Sheol; You spared me from descending into the Pit.","sources":{"KJV":{"text":"O LORD, thou hast brought up my soul from the grave: thou hast kept me alive, that I should not go down to the pit."},"BSB":{"text":"O LORD, You pulled me up from Sheol; You spared me from descending into the Pit."}},"definableWords":["LORD"],"peopleInVerse":[]},"4":{"text":"Sing unto the LORD, O ye saints of his, and give thanks at the remembrance of his holiness.","ref":"Psalms 30:4","synthesized":"Sing to the LORD, O you His saints, and praise His holy name.","sources":{"KJV":{"text":"Sing unto the LORD, O ye saints of his, and give thanks at the remembrance of his holiness."},"BSB":{"text":"Sing to the LORD, O you His saints, and praise His holy name."}},"definableWords":["LORD","praise","holy","name"],"peopleInVerse":[]},"5":{"text":"For his anger endureth but a moment; in his favour is life: weeping may endure for a night, but joy cometh in the morning.","ref":"Psalms 30:5","synthesized":"For His anger is fleeting, but His favor lasts a lifetime. Weeping may stay the night, but joy comes in the morning.","sources":{"KJV":{"text":"For his anger endureth but a moment; in his favour is life: weeping may endure for a night, but joy cometh in the morning."},"BSB":{"text":"For His anger is fleeting, but His favor lasts a lifetime. Weeping may stay the night, but joy comes in the morning."}},"definableWords":["anger","night","joy"],"peopleInVerse":[]},"6":{"text":"And in my prosperity I said, I shall never be moved.","ref":"Psalms 30:6","synthesized":"In prosperity I said, “I will never be shaken.”","sources":{"KJV":{"text":"And in my prosperity I said, I shall never be moved."},"BSB":{"text":"In prosperity I said, “I will never be shaken.”"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"LORD, by thy favour thou hast made my mountain to stand strong: thou didst hide thy face, and I was troubled.","ref":"Psalms 30:7","synthesized":"O LORD, You favored me; You made my mountain stand strong.   When You hid Your face, I was dismayed.","sources":{"KJV":{"text":"LORD, by thy favour thou hast made my mountain to stand strong: thou didst hide thy face, and I was troubled."},"BSB":{"text":"O LORD, You favored me; You made my mountain stand strong.   When You hid Your face, I was dismayed."}},"definableWords":["LORD","made","stand","strong"],"peopleInVerse":[]},"8":{"text":"I cried to thee, O LORD; and unto the LORD I made supplication.","ref":"Psalms 30:8","synthesized":"To You, O LORD, I called, and I begged my Lord for mercy:","sources":{"KJV":{"text":"I cried to thee, O LORD; and unto the LORD I made supplication."},"BSB":{"text":"To You, O LORD, I called, and I begged my Lord for mercy:"}},"definableWords":["LORD","Lord","mercy"],"peopleInVerse":[]},"9":{"text":"What profit is there in my blood, when I go down to the pit? Shall the dust praise thee? shall it declare thy truth?","ref":"Psalms 30:9","synthesized":"“What gain is there in my bloodshed, in my descent to the Pit? Will the dust praise You? Will it proclaim Your faithfulness?","sources":{"KJV":{"text":"What profit is there in my blood, when I go down to the pit? Shall the dust praise thee? shall it declare thy truth?"},"BSB":{"text":"“What gain is there in my bloodshed, in my descent to the Pit? Will the dust praise You? Will it proclaim Your faithfulness?"}},"definableWords":["praise"],"peopleInVerse":[]},"10":{"text":"Hear, O LORD, and have mercy upon me: LORD, be thou my helper.","ref":"Psalms 30:10","synthesized":"Hear me, O LORD, and have mercy; O LORD, be my helper.”","sources":{"KJV":{"text":"Hear, O LORD, and have mercy upon me: LORD, be thou my helper."},"BSB":{"text":"Hear me, O LORD, and have mercy; O LORD, be my helper.”"}},"definableWords":["hear","LORD","mercy","Lord","helper"],"peopleInVerse":[]},"11":{"text":"Thou hast turned for me my mourning into dancing: thou hast put off my sackcloth, and girded me with gladness;","ref":"Psalms 30:11","synthesized":"You turned my mourning into dancing; You peeled off my sackcloth and clothed me with joy,","sources":{"KJV":{"text":"Thou hast turned for me my mourning into dancing: thou hast put off my sackcloth, and girded me with gladness;"},"BSB":{"text":"You turned my mourning into dancing; You peeled off my sackcloth and clothed me with joy,"}},"definableWords":["joy"],"peopleInVerse":[]},"12":{"text":"To the end that my glory may sing praise to thee, and not be silent. O LORD my God, I will give thanks unto thee for ever.","ref":"Psalms 30:12","synthesized":"that my heart may sing Your praises and not be silent. O LORD my God, I will give thanks forever.","sources":{"KJV":{"text":"To the end that my glory may sing praise to thee, and not be silent. O LORD my God, I will give thanks unto thee for ever."},"BSB":{"text":"that my heart may sing Your praises and not be silent. O LORD my God, I will give thanks forever."}},"definableWords":["heart","LORD","God"],"peopleInVerse":[]}}},"31":{"chapter":"31","title":"INTO THINE HAND I COMMIT MY SPIRIT","verses":{"1":{"text":"In thee, O LORD, do I put my trust; let me never be ashamed: deliver me in thy righteousness.","ref":"Psalms 31:1","synthesized":"In You, O LORD, I have taken refuge; let me never be put to shame; save me by Your righteousness.","sources":{"KJV":{"text":"In thee, O LORD, do I put my trust; let me never be ashamed: deliver me in thy righteousness."},"BSB":{"text":"In You, O LORD, I have taken refuge; let me never be put to shame; save me by Your righteousness."}},"definableWords":["LORD","righteousness"],"peopleInVerse":[]},"2":{"text":"Bow down thine ear to me; deliver me speedily: be thou my strong rock, for an house of defence to save me.","ref":"Psalms 31:2","synthesized":"Incline Your ear to me; come quickly to my rescue. Be my rock of refuge, the stronghold of my deliverance.","sources":{"KJV":{"text":"Bow down thine ear to me; deliver me speedily: be thou my strong rock, for an house of defence to save me."},"BSB":{"text":"Incline Your ear to me; come quickly to my rescue. Be my rock of refuge, the stronghold of my deliverance."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"For thou art my rock and my fortress; therefore for thy name’s sake lead me, and guide me.","ref":"Psalms 31:3","synthesized":"For You are my rock and my fortress; lead me and guide me for the sake of Your name.","sources":{"KJV":{"text":"For thou art my rock and my fortress; therefore for thy name’s sake lead me, and guide me."},"BSB":{"text":"For You are my rock and my fortress; lead me and guide me for the sake of Your name."}},"definableWords":["name"],"peopleInVerse":[]},"4":{"text":"Pull me out of the net that they have laid privily for me: for thou art my strength.","ref":"Psalms 31:4","synthesized":"You free me from the net laid out for me, for You are my refuge.","sources":{"KJV":{"text":"Pull me out of the net that they have laid privily for me: for thou art my strength."},"BSB":{"text":"You free me from the net laid out for me, for You are my refuge."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Into thine hand I commit my spirit: thou hast redeemed me, O LORD God of truth.","ref":"Psalms 31:5","synthesized":"Into Your hands I commit my spirit; You have redeemed me, O LORD, God of truth.","sources":{"KJV":{"text":"Into thine hand I commit my spirit: thou hast redeemed me, O LORD God of truth."},"BSB":{"text":"Into Your hands I commit my spirit; You have redeemed me, O LORD, God of truth."}},"definableWords":["spirit","LORD","God","truth"],"peopleInVerse":[]},"6":{"text":"I have hated them that regard lying vanities: but I trust in the LORD.","ref":"Psalms 31:6","synthesized":"I hate those who cling to worthless idols, but in the LORD I trust.","sources":{"KJV":{"text":"I have hated them that regard lying vanities: but I trust in the LORD."},"BSB":{"text":"I hate those who cling to worthless idols, but in the LORD I trust."}},"definableWords":["LORD","trust"],"peopleInVerse":[]},"7":{"text":"I will be glad and rejoice in thy mercy: for thou hast considered my trouble; thou hast known my soul in adversities;","ref":"Psalms 31:7","synthesized":"I will be glad and rejoice in Your loving devotion, for You have seen my affliction; You have known the anguish of my soul.","sources":{"KJV":{"text":"I will be glad and rejoice in thy mercy: for thou hast considered my trouble; thou hast known my soul in adversities;"},"BSB":{"text":"I will be glad and rejoice in Your loving devotion, for You have seen my affliction; You have known the anguish of my soul."}},"definableWords":["soul"],"peopleInVerse":[]},"8":{"text":"And hast not shut me up into the hand of the enemy: thou hast set my feet in a large room.","ref":"Psalms 31:8","synthesized":"You have not delivered me to the enemy; You have set my feet in the open.","sources":{"KJV":{"text":"And hast not shut me up into the hand of the enemy: thou hast set my feet in a large room."},"BSB":{"text":"You have not delivered me to the enemy; You have set my feet in the open."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Have mercy upon me, O LORD, for I am in trouble: mine eye is consumed with grief, yea, my soul and my belly.","ref":"Psalms 31:9","synthesized":"Be merciful to me, O LORD, for I am in distress; my eyes fail from sorrow, my soul and body as well.","sources":{"KJV":{"text":"Have mercy upon me, O LORD, for I am in trouble: mine eye is consumed with grief, yea, my soul and my belly."},"BSB":{"text":"Be merciful to me, O LORD, for I am in distress; my eyes fail from sorrow, my soul and body as well."}},"definableWords":["LORD","soul"],"peopleInVerse":[]},"10":{"text":"For my life is spent with grief, and my years with sighing: my strength faileth because of mine iniquity, and my bones are consumed.","ref":"Psalms 31:10","synthesized":"For my life is consumed with grief and my years with groaning; my iniquity has drained my strength, and my bones are wasting away.","sources":{"KJV":{"text":"For my life is spent with grief, and my years with sighing: my strength faileth because of mine iniquity, and my bones are consumed."},"BSB":{"text":"For my life is consumed with grief and my years with groaning; my iniquity has drained my strength, and my bones are wasting away."}},"definableWords":["life","years","iniquity","bones"],"peopleInVerse":[]},"11":{"text":"I was a reproach among all mine enemies, but especially among my neighbours, and a fear to mine acquaintance: they that did see me without fled from me.","ref":"Psalms 31:11","synthesized":"Among all my enemies I am a disgrace, and among my neighbors even more. I am dreaded by my friends— they flee when they see me on the street.","sources":{"KJV":{"text":"I was a reproach among all mine enemies, but especially among my neighbours, and a fear to mine acquaintance: they that did see me without fled from me."},"BSB":{"text":"Among all my enemies I am a disgrace, and among my neighbors even more. I am dreaded by my friends— they flee when they see me on the street."}},"definableWords":["see"],"peopleInVerse":[]},"12":{"text":"I am forgotten as a dead man out of mind: I am like a broken vessel.","ref":"Psalms 31:12","synthesized":"I am forgotten like a dead man, out of mind. I am like a broken vessel.","sources":{"KJV":{"text":"I am forgotten as a dead man out of mind: I am like a broken vessel."},"BSB":{"text":"I am forgotten like a dead man, out of mind. I am like a broken vessel."}},"definableWords":["man","mind"],"peopleInVerse":[]},"13":{"text":"For I have heard the slander of many: fear was on every side: while they took counsel together against me, they devised to take away my life.","ref":"Psalms 31:13","synthesized":"For I hear the slander of many; there is terror on every side. They conspire against me and plot to take my life.","sources":{"KJV":{"text":"For I have heard the slander of many: fear was on every side: while they took counsel together against me, they devised to take away my life."},"BSB":{"text":"For I hear the slander of many; there is terror on every side. They conspire against me and plot to take my life."}},"definableWords":["hear","life"],"peopleInVerse":[]},"14":{"text":"But I trusted in thee, O LORD: I said, Thou art my God.","ref":"Psalms 31:14","synthesized":"But I trust in You, O LORD; I say, “You are my God.”","sources":{"KJV":{"text":"But I trusted in thee, O LORD: I said, Thou art my God."},"BSB":{"text":"But I trust in You, O LORD; I say, “You are my God.”"}},"definableWords":["trust","LORD","God"],"peopleInVerse":[]},"15":{"text":"My times are in thy hand: deliver me from the hand of mine enemies, and from them that persecute me.","ref":"Psalms 31:15","synthesized":"My times are in Your hands; deliver me from my enemies and from those who pursue me.","sources":{"KJV":{"text":"My times are in thy hand: deliver me from the hand of mine enemies, and from them that persecute me."},"BSB":{"text":"My times are in Your hands; deliver me from my enemies and from those who pursue me."}},"definableWords":["deliver"],"peopleInVerse":[]},"16":{"text":"Make thy face to shine upon thy servant: save me for thy mercies’ sake.","ref":"Psalms 31:16","synthesized":"Make Your face shine on Your servant; save me by Your loving devotion.","sources":{"KJV":{"text":"Make thy face to shine upon thy servant: save me for thy mercies’ sake."},"BSB":{"text":"Make Your face shine on Your servant; save me by Your loving devotion."}},"definableWords":["make","servant"],"peopleInVerse":[]},"17":{"text":"Let me not be ashamed, O LORD; for I have called upon thee: let the wicked be ashamed, and let them be silent in the grave.","ref":"Psalms 31:17","synthesized":"O LORD, let me not be ashamed, for I have called on You. Let the wicked be put to shame; let them lie silent in Sheol.","sources":{"KJV":{"text":"Let me not be ashamed, O LORD; for I have called upon thee: let the wicked be ashamed, and let them be silent in the grave."},"BSB":{"text":"O LORD, let me not be ashamed, for I have called on You. Let the wicked be put to shame; let them lie silent in Sheol."}},"definableWords":["LORD"],"peopleInVerse":[]},"18":{"text":"Let the lying lips be put to silence; which speak grievous things proudly and contemptuously against the righteous.","ref":"Psalms 31:18","synthesized":"May lying lips be silenced— lips that speak with arrogance against the righteous, full of pride and contempt.","sources":{"KJV":{"text":"Let the lying lips be put to silence; which speak grievous things proudly and contemptuously against the righteous."},"BSB":{"text":"May lying lips be silenced— lips that speak with arrogance against the righteous, full of pride and contempt."}},"definableWords":["righteous"],"peopleInVerse":[]},"19":{"text":"Oh how great is thy goodness, which thou hast laid up for them that fear thee; which thou hast wrought for them that trust in thee before the sons of men!","ref":"Psalms 31:19","synthesized":"How great is Your goodness which You have laid up for those who fear You, which You have bestowed before the sons of men on those who take refuge in You!","sources":{"KJV":{"text":"Oh how great is thy goodness, which thou hast laid up for them that fear thee; which thou hast wrought for them that trust in thee before the sons of men!"},"BSB":{"text":"How great is Your goodness which You have laid up for those who fear You, which You have bestowed before the sons of men on those who take refuge in You!"}},"definableWords":["great","fear","sons","men"],"peopleInVerse":[]},"20":{"text":"Thou shalt hide them in the secret of thy presence from the pride of man: thou shalt keep them secretly in a pavilion from the strife of tongues.","ref":"Psalms 31:20","synthesized":"You hide them in the secret place of Your presence from the schemes of men. You conceal them in Your shelter from accusing tongues.","sources":{"KJV":{"text":"Thou shalt hide them in the secret of thy presence from the pride of man: thou shalt keep them secretly in a pavilion from the strife of tongues."},"BSB":{"text":"You hide them in the secret place of Your presence from the schemes of men. You conceal them in Your shelter from accusing tongues."}},"definableWords":["men"],"peopleInVerse":[]},"21":{"text":"Blessed be the LORD: for he hath shewed me his marvellous kindness in a strong city.","ref":"Psalms 31:21","synthesized":"Blessed be the LORD, for He has shown me His loving devotion in a city under siege.","sources":{"KJV":{"text":"Blessed be the LORD: for he hath shewed me his marvellous kindness in a strong city."},"BSB":{"text":"Blessed be the LORD, for He has shown me His loving devotion in a city under siege."}},"definableWords":["blessed","LORD"],"peopleInVerse":[]},"22":{"text":"For I said in my haste, I am cut off from before thine eyes: nevertheless thou heardest the voice of my supplications when I cried unto thee.","ref":"Psalms 31:22","synthesized":"In my alarm I said, “I am cut off from Your sight!” But You heard my plea for mercy when I called to You for help.","sources":{"KJV":{"text":"For I said in my haste, I am cut off from before thine eyes: nevertheless thou heardest the voice of my supplications when I cried unto thee."},"BSB":{"text":"In my alarm I said, “I am cut off from Your sight!” But You heard my plea for mercy when I called to You for help."}},"definableWords":["mercy"],"peopleInVerse":[]},"23":{"text":"O love the LORD, all ye his saints: for the LORD preserveth the faithful, and plentifully rewardeth the proud doer.","ref":"Psalms 31:23","synthesized":"Love the LORD, all His saints. The LORD preserves the faithful, but fully repays the arrogant.","sources":{"KJV":{"text":"O love the LORD, all ye his saints: for the LORD preserveth the faithful, and plentifully rewardeth the proud doer."},"BSB":{"text":"Love the LORD, all His saints. The LORD preserves the faithful, but fully repays the arrogant."}},"definableWords":["love","LORD","Lord"],"peopleInVerse":[]},"24":{"text":"Be of good courage, and he shall strengthen your heart, all ye that hope in the LORD.","ref":"Psalms 31:24","synthesized":"Be strong and courageous, all you who hope in the LORD.","sources":{"KJV":{"text":"Be of good courage, and he shall strengthen your heart, all ye that hope in the LORD."},"BSB":{"text":"Be strong and courageous, all you who hope in the LORD."}},"definableWords":["strong","hope","LORD"],"peopleInVerse":[]}}},"32":{"chapter":"32","title":"BLESSED IS THE FORGIVEN","verses":{"1":{"text":"Blessed is he whose transgression is forgiven, whose sin is covered.","ref":"Psalms 32:1","synthesized":"Blessed is he whose transgressions are forgiven, whose sins are covered.","sources":{"KJV":{"text":"Blessed is he whose transgression is forgiven, whose sin is covered."},"BSB":{"text":"Blessed is he whose transgressions are forgiven, whose sins are covered."}},"definableWords":["blessed"],"peopleInVerse":[]},"2":{"text":"Blessed is the man unto whom the LORD imputeth not iniquity, and in whose spirit there is no guile.","ref":"Psalms 32:2","synthesized":"Blessed is the man whose iniquity the LORD does not count against him, in whose spirit there is no deceit.","sources":{"KJV":{"text":"Blessed is the man unto whom the LORD imputeth not iniquity, and in whose spirit there is no guile."},"BSB":{"text":"Blessed is the man whose iniquity the LORD does not count against him, in whose spirit there is no deceit."}},"definableWords":["blessed","man","iniquity","LORD","spirit"],"peopleInVerse":[]},"3":{"text":"When I kept silence, my bones waxed old through my roaring all the day long.","ref":"Psalms 32:3","synthesized":"When I kept silent, my bones became brittle from my groaning all day long.","sources":{"KJV":{"text":"When I kept silence, my bones waxed old through my roaring all the day long."},"BSB":{"text":"When I kept silent, my bones became brittle from my groaning all day long."}},"definableWords":["bones","day"],"peopleInVerse":[]},"4":{"text":"For day and night thy hand was heavy upon me: my moisture is turned into the drought of summer. Selah.","ref":"Psalms 32:4","synthesized":"For day and night Your hand was heavy upon me; my strength was drained as in the summer heat. Selah","sources":{"KJV":{"text":"For day and night thy hand was heavy upon me: my moisture is turned into the drought of summer. Selah."},"BSB":{"text":"For day and night Your hand was heavy upon me; my strength was drained as in the summer heat. Selah"}},"definableWords":["day","night"],"peopleInVerse":[]},"5":{"text":"I acknowledged my sin unto thee, and mine iniquity have I not hid. I said, I will confess my transgressions unto the LORD; and thou forgavest the iniquity of my sin. Selah.","ref":"Psalms 32:5","synthesized":"Then I acknowledged my sin to You and did not hide my iniquity. I said, “I will confess my transgressions to the LORD,” and You forgave the guilt of my sin. Selah","sources":{"KJV":{"text":"I acknowledged my sin unto thee, and mine iniquity have I not hid. I said, I will confess my transgressions unto the LORD; and thou forgavest the iniquity of my sin. Selah."},"BSB":{"text":"Then I acknowledged my sin to You and did not hide my iniquity. I said, “I will confess my transgressions to the LORD,” and You forgave the guilt of my sin. Selah"}},"definableWords":["sin","iniquity","LORD"],"peopleInVerse":[]},"6":{"text":"For this shall every one that is godly pray unto thee in a time when thou mayest be found: surely in the floods of great waters they shall not come nigh unto him.","ref":"Psalms 32:6","synthesized":"Therefore let all the godly pray to You while You may be found. Surely when great waters rise, they will not come near.","sources":{"KJV":{"text":"For this shall every one that is godly pray unto thee in a time when thou mayest be found: surely in the floods of great waters they shall not come nigh unto him."},"BSB":{"text":"Therefore let all the godly pray to You while You may be found. Surely when great waters rise, they will not come near."}},"definableWords":["great","waters"],"peopleInVerse":[]},"7":{"text":"Thou art my hiding place; thou shalt preserve me from trouble; thou shalt compass me about with songs of deliverance. Selah.","ref":"Psalms 32:7","synthesized":"You are my hiding place. You protect me from trouble; You surround me with songs of deliverance. Selah","sources":{"KJV":{"text":"Thou art my hiding place; thou shalt preserve me from trouble; thou shalt compass me about with songs of deliverance. Selah."},"BSB":{"text":"You are my hiding place. You protect me from trouble; You surround me with songs of deliverance. Selah"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"I will instruct thee and teach thee in the way which thou shalt go: I will guide thee with mine eye.","ref":"Psalms 32:8","synthesized":"I will instruct you and teach you the way you should go; I will give you counsel and watch over you.","sources":{"KJV":{"text":"I will instruct thee and teach thee in the way which thou shalt go: I will guide thee with mine eye."},"BSB":{"text":"I will instruct you and teach you the way you should go; I will give you counsel and watch over you."}},"definableWords":["way"],"peopleInVerse":[]},"9":{"text":"Be ye not as the horse, or as the mule, which have no understanding: whose mouth must be held in with bit and bridle, lest they come near unto thee.","ref":"Psalms 32:9","synthesized":"Do not be like the horse or mule, which have no understanding; they must be controlled with bit and bridle to make them come to you.","sources":{"KJV":{"text":"Be ye not as the horse, or as the mule, which have no understanding: whose mouth must be held in with bit and bridle, lest they come near unto thee."},"BSB":{"text":"Do not be like the horse or mule, which have no understanding; they must be controlled with bit and bridle to make them come to you."}},"definableWords":["or","make"],"peopleInVerse":[]},"10":{"text":"Many sorrows shall be to the wicked: but he that trusteth in the LORD, mercy shall compass him about.","ref":"Psalms 32:10","synthesized":"Many are the sorrows of the wicked, but loving devotion surrounds him who trusts in the LORD.","sources":{"KJV":{"text":"Many sorrows shall be to the wicked: but he that trusteth in the LORD, mercy shall compass him about."},"BSB":{"text":"Many are the sorrows of the wicked, but loving devotion surrounds him who trusts in the LORD."}},"definableWords":["LORD"],"peopleInVerse":[]},"11":{"text":"Be glad in the LORD, and rejoice, ye righteous: and shout for joy, all ye that are upright in heart.","ref":"Psalms 32:11","synthesized":"Be glad in the LORD and rejoice, O righteous ones; shout for joy, all you upright in heart.","sources":{"KJV":{"text":"Be glad in the LORD, and rejoice, ye righteous: and shout for joy, all ye that are upright in heart."},"BSB":{"text":"Be glad in the LORD and rejoice, O righteous ones; shout for joy, all you upright in heart."}},"definableWords":["LORD","righteous","joy","heart"],"peopleInVerse":[]}}},"33":{"chapter":"33","title":"REJOICE IN THE LORD, O YE RIGHTEOUS","verses":{"1":{"text":"Rejoice in the LORD, O ye righteous: for praise is comely for the upright.","ref":"Psalms 33:1","synthesized":"Rejoice in the LORD, O righteous ones; it is fitting for the upright to praise Him.","sources":{"KJV":{"text":"Rejoice in the LORD, O ye righteous: for praise is comely for the upright."},"BSB":{"text":"Rejoice in the LORD, O righteous ones; it is fitting for the upright to praise Him."}},"definableWords":["LORD","righteous","praise"],"peopleInVerse":[]},"2":{"text":"Praise the LORD with harp: sing unto him with the psaltery and an instrument of ten strings.","ref":"Psalms 33:2","synthesized":"Praise the LORD with the harp; make music to Him with ten strings.","sources":{"KJV":{"text":"Praise the LORD with harp: sing unto him with the psaltery and an instrument of ten strings."},"BSB":{"text":"Praise the LORD with the harp; make music to Him with ten strings."}},"definableWords":["praise","LORD","make"],"peopleInVerse":[]},"3":{"text":"Sing unto him a new song; play skilfully with a loud noise.","ref":"Psalms 33:3","synthesized":"Sing to Him a new song; play skillfully with a shout of joy.","sources":{"KJV":{"text":"Sing unto him a new song; play skilfully with a loud noise."},"BSB":{"text":"Sing to Him a new song; play skillfully with a shout of joy."}},"definableWords":["joy"],"peopleInVerse":[]},"4":{"text":"For the word of the LORD is right; and all his works are done in truth.","ref":"Psalms 33:4","synthesized":"For the word of the LORD is upright, and all His work is trustworthy.","sources":{"KJV":{"text":"For the word of the LORD is right; and all his works are done in truth."},"BSB":{"text":"For the word of the LORD is upright, and all His work is trustworthy."}},"definableWords":["word","LORD","work"],"peopleInVerse":[]},"5":{"text":"He loveth righteousness and judgment: the earth is full of the goodness of the LORD.","ref":"Psalms 33:5","synthesized":"The LORD loves righteousness and justice; the earth is full of His loving devotion.","sources":{"KJV":{"text":"He loveth righteousness and judgment: the earth is full of the goodness of the LORD."},"BSB":{"text":"The LORD loves righteousness and justice; the earth is full of His loving devotion."}},"definableWords":["LORD","righteousness","justice","earth"],"peopleInVerse":[]},"6":{"text":"By the word of the LORD were the heavens made; and all the host of them by the breath of his mouth.","ref":"Psalms 33:6","synthesized":"By the word of the LORD the heavens were made, and all the stars by the breath of His mouth.","sources":{"KJV":{"text":"By the word of the LORD were the heavens made; and all the host of them by the breath of his mouth."},"BSB":{"text":"By the word of the LORD the heavens were made, and all the stars by the breath of His mouth."}},"definableWords":["word","LORD","heavens","made","breath"],"peopleInVerse":[]},"7":{"text":"He gathereth the waters of the sea together as an heap: he layeth up the depth in storehouses.","ref":"Psalms 33:7","synthesized":"He piles up the waters of the sea; He puts the depths into storehouses.","sources":{"KJV":{"text":"He gathereth the waters of the sea together as an heap: he layeth up the depth in storehouses."},"BSB":{"text":"He piles up the waters of the sea; He puts the depths into storehouses."}},"definableWords":["waters","sea"],"peopleInVerse":[]},"8":{"text":"Let all the earth fear the LORD: let all the inhabitants of the world stand in awe of him.","ref":"Psalms 33:8","synthesized":"Let all the earth fear the LORD; let all the people of the world revere Him.","sources":{"KJV":{"text":"Let all the earth fear the LORD: let all the inhabitants of the world stand in awe of him."},"BSB":{"text":"Let all the earth fear the LORD; let all the people of the world revere Him."}},"definableWords":["earth","fear","LORD","people"],"peopleInVerse":[]},"9":{"text":"For he spake, and it was done; he commanded, and it stood fast.","ref":"Psalms 33:9","synthesized":"For He spoke, and it came to be; He commanded, and it stood firm.","sources":{"KJV":{"text":"For he spake, and it was done; he commanded, and it stood fast."},"BSB":{"text":"For He spoke, and it came to be; He commanded, and it stood firm."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"The LORD bringeth the counsel of the heathen to nought: he maketh the devices of the people of none effect.","ref":"Psalms 33:10","synthesized":"The LORD frustrates the plans of the nations; He thwarts the devices of the peoples.","sources":{"KJV":{"text":"The LORD bringeth the counsel of the heathen to nought: he maketh the devices of the people of none effect."},"BSB":{"text":"The LORD frustrates the plans of the nations; He thwarts the devices of the peoples."}},"definableWords":["LORD","nations"],"peopleInVerse":[]},"11":{"text":"The counsel of the LORD standeth for ever, the thoughts of his heart to all generations.","ref":"Psalms 33:11","synthesized":"The counsel of the LORD stands forever, the purposes of His heart to all generations.","sources":{"KJV":{"text":"The counsel of the LORD standeth for ever, the thoughts of his heart to all generations."},"BSB":{"text":"The counsel of the LORD stands forever, the purposes of His heart to all generations."}},"definableWords":["LORD","heart"],"peopleInVerse":[]},"12":{"text":"Blessed is the nation whose God is the LORD; and the people whom he hath chosen for his own inheritance.","ref":"Psalms 33:12","synthesized":"Blessed is the nation whose God is the LORD, the people He has chosen as His inheritance!","sources":{"KJV":{"text":"Blessed is the nation whose God is the LORD; and the people whom he hath chosen for his own inheritance."},"BSB":{"text":"Blessed is the nation whose God is the LORD, the people He has chosen as His inheritance!"}},"definableWords":["blessed","nation","God","LORD","people"],"peopleInVerse":[]},"13":{"text":"The LORD looketh from heaven; he beholdeth all the sons of men.","ref":"Psalms 33:13","synthesized":"The LORD looks down from heaven; He sees all the sons of men.","sources":{"KJV":{"text":"The LORD looketh from heaven; he beholdeth all the sons of men."},"BSB":{"text":"The LORD looks down from heaven; He sees all the sons of men."}},"definableWords":["LORD","heaven","sons","men"],"peopleInVerse":[]},"14":{"text":"From the place of his habitation he looketh upon all the inhabitants of the earth.","ref":"Psalms 33:14","synthesized":"From His dwelling place He gazes on all who inhabit the earth.","sources":{"KJV":{"text":"From the place of his habitation he looketh upon all the inhabitants of the earth."},"BSB":{"text":"From His dwelling place He gazes on all who inhabit the earth."}},"definableWords":["earth"],"peopleInVerse":[]},"15":{"text":"He fashioneth their hearts alike; he considereth all their works.","ref":"Psalms 33:15","synthesized":"He shapes the hearts of each; He considers all their works.","sources":{"KJV":{"text":"He fashioneth their hearts alike; he considereth all their works."},"BSB":{"text":"He shapes the hearts of each; He considers all their works."}},"definableWords":["works"],"peopleInVerse":[]},"16":{"text":"There is no king saved by the multitude of an host: a mighty man is not delivered by much strength.","ref":"Psalms 33:16","synthesized":"No king is saved by his vast army; no warrior is delivered by his great strength.","sources":{"KJV":{"text":"There is no king saved by the multitude of an host: a mighty man is not delivered by much strength."},"BSB":{"text":"No king is saved by his vast army; no warrior is delivered by his great strength."}},"definableWords":["king","great"],"peopleInVerse":[]},"17":{"text":"An horse is a vain thing for safety: neither shall he deliver any by his great strength.","ref":"Psalms 33:17","synthesized":"A horse is a vain hope for salvation; even its great strength cannot save.","sources":{"KJV":{"text":"An horse is a vain thing for safety: neither shall he deliver any by his great strength."},"BSB":{"text":"A horse is a vain hope for salvation; even its great strength cannot save."}},"definableWords":["hope","salvation","great"],"peopleInVerse":[]},"18":{"text":"Behold, the eye of the LORD is upon them that fear him, upon them that hope in his mercy;","ref":"Psalms 33:18","synthesized":"Surely the eyes of the LORD are on those who fear Him, on those whose hope is in His loving devotion","sources":{"KJV":{"text":"Behold, the eye of the LORD is upon them that fear him, upon them that hope in his mercy;"},"BSB":{"text":"Surely the eyes of the LORD are on those who fear Him, on those whose hope is in His loving devotion"}},"definableWords":["LORD","fear","hope"],"peopleInVerse":[]},"19":{"text":"To deliver their soul from death, and to keep them alive in famine.","ref":"Psalms 33:19","synthesized":"to deliver them from death and keep them alive in famine.","sources":{"KJV":{"text":"To deliver their soul from death, and to keep them alive in famine."},"BSB":{"text":"to deliver them from death and keep them alive in famine."}},"definableWords":["deliver","death","keep"],"peopleInVerse":[]},"20":{"text":"Our soul waiteth for the LORD: he is our help and our shield.","ref":"Psalms 33:20","synthesized":"Our soul waits for the LORD; He is our help and our shield.","sources":{"KJV":{"text":"Our soul waiteth for the LORD: he is our help and our shield."},"BSB":{"text":"Our soul waits for the LORD; He is our help and our shield."}},"definableWords":["soul","LORD"],"peopleInVerse":[]},"21":{"text":"For our heart shall rejoice in him, because we have trusted in his holy name.","ref":"Psalms 33:21","synthesized":"For our hearts rejoice in Him, since we trust in His holy name.","sources":{"KJV":{"text":"For our heart shall rejoice in him, because we have trusted in his holy name."},"BSB":{"text":"For our hearts rejoice in Him, since we trust in His holy name."}},"definableWords":["trust","holy","name"],"peopleInVerse":[]},"22":{"text":"Let thy mercy, O LORD, be upon us, according as we hope in thee.","ref":"Psalms 33:22","synthesized":"May Your loving devotion rest on us, O LORD, as we put our hope in You.","sources":{"KJV":{"text":"Let thy mercy, O LORD, be upon us, according as we hope in thee."},"BSB":{"text":"May Your loving devotion rest on us, O LORD, as we put our hope in You."}},"definableWords":["rest","LORD","hope"],"peopleInVerse":[]}}},"34":{"chapter":"34","title":"I WILL BLESS THE LORD AT ALL TIMES","verses":{"1":{"text":"I will bless the LORD at all times: his praise shall continually be in my mouth.","ref":"Psalms 34:1","synthesized":"I will bless the LORD at all times; His praise will always be on my lips.","sources":{"KJV":{"text":"I will bless the LORD at all times: his praise shall continually be in my mouth."},"BSB":{"text":"I will bless the LORD at all times; His praise will always be on my lips."}},"definableWords":["bless","LORD","praise"],"peopleInVerse":[]},"2":{"text":"My soul shall make her boast in the LORD: the humble shall hear thereof, and be glad.","ref":"Psalms 34:2","synthesized":"My soul boasts in the LORD; let the oppressed hear and rejoice.","sources":{"KJV":{"text":"My soul shall make her boast in the LORD: the humble shall hear thereof, and be glad."},"BSB":{"text":"My soul boasts in the LORD; let the oppressed hear and rejoice."}},"definableWords":["soul","LORD","hear"],"peopleInVerse":[]},"3":{"text":"O magnify the LORD with me, and let us exalt his name together.","ref":"Psalms 34:3","synthesized":"Magnify the LORD with me; let us exalt His name together.","sources":{"KJV":{"text":"O magnify the LORD with me, and let us exalt his name together."},"BSB":{"text":"Magnify the LORD with me; let us exalt His name together."}},"definableWords":["LORD","name"],"peopleInVerse":[]},"4":{"text":"I sought the LORD, and he heard me, and delivered me from all my fears.","ref":"Psalms 34:4","synthesized":"I sought the LORD, and He answered me; He delivered me from all my fears.","sources":{"KJV":{"text":"I sought the LORD, and he heard me, and delivered me from all my fears."},"BSB":{"text":"I sought the LORD, and He answered me; He delivered me from all my fears."}},"definableWords":["LORD"],"peopleInVerse":[]},"5":{"text":"They looked unto him, and were lightened: and their faces were not ashamed.","ref":"Psalms 34:5","synthesized":"Those who look to Him are radiant with joy; their faces shall never be ashamed.","sources":{"KJV":{"text":"They looked unto him, and were lightened: and their faces were not ashamed."},"BSB":{"text":"Those who look to Him are radiant with joy; their faces shall never be ashamed."}},"definableWords":["joy"],"peopleInVerse":[]},"6":{"text":"This poor man cried, and the LORD heard him, and saved him out of all his troubles.","ref":"Psalms 34:6","synthesized":"This poor man called out, and the LORD heard him; He saved him from all his troubles.","sources":{"KJV":{"text":"This poor man cried, and the LORD heard him, and saved him out of all his troubles."},"BSB":{"text":"This poor man called out, and the LORD heard him; He saved him from all his troubles."}},"definableWords":["man","LORD"],"peopleInVerse":[]},"7":{"text":"The angel of the LORD encampeth round about them that fear him, and delivereth them.","ref":"Psalms 34:7","synthesized":"The angel of the LORD encamps around those who fear Him, and he delivers them.","sources":{"KJV":{"text":"The angel of the LORD encampeth round about them that fear him, and delivereth them."},"BSB":{"text":"The angel of the LORD encamps around those who fear Him, and he delivers them."}},"definableWords":["angel","LORD","fear"],"peopleInVerse":[]},"8":{"text":"O taste and see that the LORD is good: blessed is the man that trusteth in him.","ref":"Psalms 34:8","synthesized":"Taste and see that the LORD is good; blessed is the man who takes refuge in Him!","sources":{"KJV":{"text":"O taste and see that the LORD is good: blessed is the man that trusteth in him."},"BSB":{"text":"Taste and see that the LORD is good; blessed is the man who takes refuge in Him!"}},"definableWords":["see","LORD","good","blessed","man"],"peopleInVerse":[]},"9":{"text":"O fear the LORD, ye his saints: for there is no want to them that fear him.","ref":"Psalms 34:9","synthesized":"Fear the LORD, you His saints, for those who fear Him lack nothing.","sources":{"KJV":{"text":"O fear the LORD, ye his saints: for there is no want to them that fear him."},"BSB":{"text":"Fear the LORD, you His saints, for those who fear Him lack nothing."}},"definableWords":["fear","LORD"],"peopleInVerse":[]},"10":{"text":"The young lions do lack, and suffer hunger: but they that seek the LORD shall not want any good thing.","ref":"Psalms 34:10","synthesized":"Young lions go lacking and hungry, but those who seek the LORD lack no good thing.","sources":{"KJV":{"text":"The young lions do lack, and suffer hunger: but they that seek the LORD shall not want any good thing."},"BSB":{"text":"Young lions go lacking and hungry, but those who seek the LORD lack no good thing."}},"definableWords":["seek","LORD","good"],"peopleInVerse":[]},"11":{"text":"Come, ye children, hearken unto me: I will teach you the fear of the LORD.","ref":"Psalms 34:11","synthesized":"Come, children, listen to me; I will teach you the fear of the LORD.","sources":{"KJV":{"text":"Come, ye children, hearken unto me: I will teach you the fear of the LORD."},"BSB":{"text":"Come, children, listen to me; I will teach you the fear of the LORD."}},"definableWords":["fear","LORD"],"peopleInVerse":[]},"12":{"text":"What man is he that desireth life, and loveth many days, that he may see good?","ref":"Psalms 34:12","synthesized":"Who is the man who delights in life, who desires to see good days?","sources":{"KJV":{"text":"What man is he that desireth life, and loveth many days, that he may see good?"},"BSB":{"text":"Who is the man who delights in life, who desires to see good days?"}},"definableWords":["man","life","see","good","days"],"peopleInVerse":[]},"13":{"text":"Keep thy tongue from evil, and thy lips from speaking guile.","ref":"Psalms 34:13","synthesized":"Keep your tongue from evil and your lips from deceitful speech.","sources":{"KJV":{"text":"Keep thy tongue from evil, and thy lips from speaking guile."},"BSB":{"text":"Keep your tongue from evil and your lips from deceitful speech."}},"definableWords":["keep","evil"],"peopleInVerse":[]},"14":{"text":"Depart from evil, and do good; seek peace, and pursue it.","ref":"Psalms 34:14","synthesized":"Turn away from evil and do good; seek peace and pursue it.","sources":{"KJV":{"text":"Depart from evil, and do good; seek peace, and pursue it."},"BSB":{"text":"Turn away from evil and do good; seek peace and pursue it."}},"definableWords":["evil","good","seek","peace"],"peopleInVerse":[]},"15":{"text":"The eyes of the LORD are upon the righteous, and his ears are open unto their cry.","ref":"Psalms 34:15","synthesized":"The eyes of the LORD are on the righteous, and His ears are inclined to their cry.","sources":{"KJV":{"text":"The eyes of the LORD are upon the righteous, and his ears are open unto their cry."},"BSB":{"text":"The eyes of the LORD are on the righteous, and His ears are inclined to their cry."}},"definableWords":["LORD","righteous"],"peopleInVerse":[]},"16":{"text":"The face of the LORD is against them that do evil, to cut off the remembrance of them from the earth.","ref":"Psalms 34:16","synthesized":"But the face of the LORD is against those who do evil, to wipe out all memory of them from the earth.","sources":{"KJV":{"text":"The face of the LORD is against them that do evil, to cut off the remembrance of them from the earth."},"BSB":{"text":"But the face of the LORD is against those who do evil, to wipe out all memory of them from the earth."}},"definableWords":["LORD","evil","earth"],"peopleInVerse":[]},"17":{"text":"The righteous cry, and the LORD heareth, and delivereth them out of all their troubles.","ref":"Psalms 34:17","synthesized":"The righteous cry out, and the LORD hears; He delivers them from all their troubles.","sources":{"KJV":{"text":"The righteous cry, and the LORD heareth, and delivereth them out of all their troubles."},"BSB":{"text":"The righteous cry out, and the LORD hears; He delivers them from all their troubles."}},"definableWords":["righteous","LORD"],"peopleInVerse":[]},"18":{"text":"The LORD is nigh unto them that are of a broken heart; and saveth such as be of a contrite spirit.","ref":"Psalms 34:18","synthesized":"The LORD is near to the brokenhearted; He saves the contrite in spirit.","sources":{"KJV":{"text":"The LORD is nigh unto them that are of a broken heart; and saveth such as be of a contrite spirit."},"BSB":{"text":"The LORD is near to the brokenhearted; He saves the contrite in spirit."}},"definableWords":["LORD","spirit"],"peopleInVerse":[]},"19":{"text":"Many are the afflictions of the righteous: but the LORD delivereth him out of them all.","ref":"Psalms 34:19","synthesized":"Many are the afflictions of the righteous, but the LORD delivers him from them all.","sources":{"KJV":{"text":"Many are the afflictions of the righteous: but the LORD delivereth him out of them all."},"BSB":{"text":"Many are the afflictions of the righteous, but the LORD delivers him from them all."}},"definableWords":["righteous","LORD"],"peopleInVerse":[]},"20":{"text":"He keepeth all his bones: not one of them is broken.","ref":"Psalms 34:20","synthesized":"He protects all his bones; not one of them will be broken.","sources":{"KJV":{"text":"He keepeth all his bones: not one of them is broken."},"BSB":{"text":"He protects all his bones; not one of them will be broken."}},"definableWords":["bones","one"],"peopleInVerse":[]},"21":{"text":"Evil shall slay the wicked: and they that hate the righteous shall be desolate.","ref":"Psalms 34:21","synthesized":"Evil will slay the wicked, and the haters of the righteous will be condemned.","sources":{"KJV":{"text":"Evil shall slay the wicked: and they that hate the righteous shall be desolate."},"BSB":{"text":"Evil will slay the wicked, and the haters of the righteous will be condemned."}},"definableWords":["evil","righteous"],"peopleInVerse":[]},"22":{"text":"The LORD redeemeth the soul of his servants: and none of them that trust in him shall be desolate.","ref":"Psalms 34:22","synthesized":"The LORD redeems His servants, and none who take refuge in Him will be condemned.","sources":{"KJV":{"text":"The LORD redeemeth the soul of his servants: and none of them that trust in him shall be desolate."},"BSB":{"text":"The LORD redeems His servants, and none who take refuge in Him will be condemned."}},"definableWords":["LORD","servants"],"peopleInVerse":[]}}},"35":{"chapter":"35","title":"PLEAD MY CAUSE, O LORD","verses":{"1":{"text":"Plead my cause, O LORD, with them that strive with me: fight against them that fight against me.","ref":"Psalms 35:1","synthesized":"Contend with my opponents, O LORD; fight against those who fight against me.","sources":{"KJV":{"text":"Plead my cause, O LORD, with them that strive with me: fight against them that fight against me."},"BSB":{"text":"Contend with my opponents, O LORD; fight against those who fight against me."}},"definableWords":["LORD","fight"],"peopleInVerse":[]},"2":{"text":"Take hold of shield and buckler, and stand up for mine help.","ref":"Psalms 35:2","synthesized":"Take up Your shield and buckler; arise and come to my aid.","sources":{"KJV":{"text":"Take hold of shield and buckler, and stand up for mine help."},"BSB":{"text":"Take up Your shield and buckler; arise and come to my aid."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Draw out also the spear, and stop the way against them that persecute me: say unto my soul, I am thy salvation.","ref":"Psalms 35:3","synthesized":"Draw the spear and javelin against my pursuers; say to my soul: “I am your salvation.”","sources":{"KJV":{"text":"Draw out also the spear, and stop the way against them that persecute me: say unto my soul, I am thy salvation."},"BSB":{"text":"Draw the spear and javelin against my pursuers; say to my soul: “I am your salvation.”"}},"definableWords":["soul","salvation"],"peopleInVerse":[]},"4":{"text":"Let them be confounded and put to shame that seek after my soul: let them be turned back and brought to confusion that devise my hurt.","ref":"Psalms 35:4","synthesized":"May those who seek my life be disgraced and put to shame; may those who plan to harm me be driven back and confounded.","sources":{"KJV":{"text":"Let them be confounded and put to shame that seek after my soul: let them be turned back and brought to confusion that devise my hurt."},"BSB":{"text":"May those who seek my life be disgraced and put to shame; may those who plan to harm me be driven back and confounded."}},"definableWords":["seek","life"],"peopleInVerse":[]},"5":{"text":"Let them be as chaff before the wind: and let the angel of the LORD chase them.","ref":"Psalms 35:5","synthesized":"May they be like chaff in the wind, as the angel of the LORD drives them away.","sources":{"KJV":{"text":"Let them be as chaff before the wind: and let the angel of the LORD chase them."},"BSB":{"text":"May they be like chaff in the wind, as the angel of the LORD drives them away."}},"definableWords":["angel","LORD"],"peopleInVerse":[]},"6":{"text":"Let their way be dark and slippery: and let the angel of the LORD persecute them.","ref":"Psalms 35:6","synthesized":"May their path be dark and slick, as the angel of the LORD pursues.","sources":{"KJV":{"text":"Let their way be dark and slippery: and let the angel of the LORD persecute them."},"BSB":{"text":"May their path be dark and slick, as the angel of the LORD pursues."}},"definableWords":["angel","LORD"],"peopleInVerse":[]},"7":{"text":"For without cause have they hid for me their net in a pit, which without cause they have digged for my soul.","ref":"Psalms 35:7","synthesized":"For without cause they laid their net for me; without reason they dug a pit for my soul.","sources":{"KJV":{"text":"For without cause have they hid for me their net in a pit, which without cause they have digged for my soul."},"BSB":{"text":"For without cause they laid their net for me; without reason they dug a pit for my soul."}},"definableWords":["soul"],"peopleInVerse":[]},"8":{"text":"Let destruction come upon him at unawares; and let his net that he hath hid catch himself: into that very destruction let him fall.","ref":"Psalms 35:8","synthesized":"May ruin befall them by surprise; may the net they hid ensnare them; may they fall into the hazard they created.","sources":{"KJV":{"text":"Let destruction come upon him at unawares; and let his net that he hath hid catch himself: into that very destruction let him fall."},"BSB":{"text":"May ruin befall them by surprise; may the net they hid ensnare them; may they fall into the hazard they created."}},"definableWords":["created"],"peopleInVerse":[]},"9":{"text":"And my soul shall be joyful in the LORD: it shall rejoice in his salvation.","ref":"Psalms 35:9","synthesized":"Then my soul will rejoice in the LORD and exult in His salvation.","sources":{"KJV":{"text":"And my soul shall be joyful in the LORD: it shall rejoice in his salvation."},"BSB":{"text":"Then my soul will rejoice in the LORD and exult in His salvation."}},"definableWords":["soul","LORD","salvation"],"peopleInVerse":[]},"10":{"text":"All my bones shall say, LORD, who is like unto thee, which deliverest the poor from him that is too strong for him, yea, the poor and the needy from him that spoileth him?","ref":"Psalms 35:10","synthesized":"All my bones will exclaim, “Who is like You, O LORD, who delivers the afflicted from the aggressor, the poor and needy from the robber?”","sources":{"KJV":{"text":"All my bones shall say, LORD, who is like unto thee, which deliverest the poor from him that is too strong for him, yea, the poor and the needy from him that spoileth him?"},"BSB":{"text":"All my bones will exclaim, “Who is like You, O LORD, who delivers the afflicted from the aggressor, the poor and needy from the robber?”"}},"definableWords":["bones","LORD"],"peopleInVerse":[]},"11":{"text":"False witnesses did rise up; they laid to my charge things that I knew not.","ref":"Psalms 35:11","synthesized":"Hostile witnesses come forward; they make charges I know nothing about.","sources":{"KJV":{"text":"False witnesses did rise up; they laid to my charge things that I knew not."},"BSB":{"text":"Hostile witnesses come forward; they make charges I know nothing about."}},"definableWords":["make"],"peopleInVerse":[]},"12":{"text":"They rewarded me evil for good to the spoiling of my soul.","ref":"Psalms 35:12","synthesized":"They repay me evil for good, to the bereavement of my soul.","sources":{"KJV":{"text":"They rewarded me evil for good to the spoiling of my soul."},"BSB":{"text":"They repay me evil for good, to the bereavement of my soul."}},"definableWords":["evil","good","soul"],"peopleInVerse":[]},"13":{"text":"But as for me, when they were sick, my clothing was sackcloth: I humbled my soul with fasting; and my prayer returned into mine own bosom.","ref":"Psalms 35:13","synthesized":"Yet when they were ill, I put on sackcloth; I humbled myself with fasting, but my prayers returned unanswered.","sources":{"KJV":{"text":"But as for me, when they were sick, my clothing was sackcloth: I humbled my soul with fasting; and my prayer returned into mine own bosom."},"BSB":{"text":"Yet when they were ill, I put on sackcloth; I humbled myself with fasting, but my prayers returned unanswered."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"I behaved myself as though he had been my friend or brother: I bowed down heavily, as one that mourneth for his mother.","ref":"Psalms 35:14","synthesized":"I paced about as for my friend or brother; I was bowed down with grief, like one mourning for his mother.","sources":{"KJV":{"text":"I behaved myself as though he had been my friend or brother: I bowed down heavily, as one that mourneth for his mother."},"BSB":{"text":"I paced about as for my friend or brother; I was bowed down with grief, like one mourning for his mother."}},"definableWords":["or","brother","one","mother"],"peopleInVerse":[]},"15":{"text":"But in mine adversity they rejoiced, and gathered themselves together: yea, the abjects gathered themselves together against me, and I knew it not; they did tear me, and ceased not:","ref":"Psalms 35:15","synthesized":"But when I stumbled, they assembled in glee; they gathered together against me. Assailants I did not know slandered me without ceasing.","sources":{"KJV":{"text":"But in mine adversity they rejoiced, and gathered themselves together: yea, the abjects gathered themselves together against me, and I knew it not; they did tear me, and ceased not:"},"BSB":{"text":"But when I stumbled, they assembled in glee; they gathered together against me. Assailants I did not know slandered me without ceasing."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"With hypocritical mockers in feasts, they gnashed upon me with their teeth.","ref":"Psalms 35:16","synthesized":"Like godless jesters at a feast, they gnashed their teeth at me.","sources":{"KJV":{"text":"With hypocritical mockers in feasts, they gnashed upon me with their teeth."},"BSB":{"text":"Like godless jesters at a feast, they gnashed their teeth at me."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Lord, how long wilt thou look on? rescue my soul from their destructions, my darling from the lions.","ref":"Psalms 35:17","synthesized":"How long, O Lord, will You look on? Rescue my soul from their ravages, my precious life from these lions.","sources":{"KJV":{"text":"Lord, how long wilt thou look on? rescue my soul from their destructions, my darling from the lions."},"BSB":{"text":"How long, O Lord, will You look on? Rescue my soul from their ravages, my precious life from these lions."}},"definableWords":["Lord","soul","life"],"peopleInVerse":[]},"18":{"text":"I will give thee thanks in the great congregation: I will praise thee among much people.","ref":"Psalms 35:18","synthesized":"Then I will give You thanks in the great assembly; I will praise You among many people.","sources":{"KJV":{"text":"I will give thee thanks in the great congregation: I will praise thee among much people."},"BSB":{"text":"Then I will give You thanks in the great assembly; I will praise You among many people."}},"definableWords":["great","praise","people"],"peopleInVerse":[]},"19":{"text":"Let not them that are mine enemies wrongfully rejoice over me: neither let them wink with the eye that hate me without a cause.","ref":"Psalms 35:19","synthesized":"Let not my enemies gloat over me without cause, nor those who hate me without reason wink in malice.","sources":{"KJV":{"text":"Let not them that are mine enemies wrongfully rejoice over me: neither let them wink with the eye that hate me without a cause."},"BSB":{"text":"Let not my enemies gloat over me without cause, nor those who hate me without reason wink in malice."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"For they speak not peace: but they devise deceitful matters against them that are quiet in the land.","ref":"Psalms 35:20","synthesized":"For they do not speak peace, but they devise deceitful schemes against those who live quietly in the land.","sources":{"KJV":{"text":"For they speak not peace: but they devise deceitful matters against them that are quiet in the land."},"BSB":{"text":"For they do not speak peace, but they devise deceitful schemes against those who live quietly in the land."}},"definableWords":["peace","live","land"],"peopleInVerse":[]},"21":{"text":"Yea, they opened their mouth wide against me, and said, Aha, aha, our eye hath seen it.","ref":"Psalms 35:21","synthesized":"They gape at me and say, “Aha, aha! Our eyes have seen!”","sources":{"KJV":{"text":"Yea, they opened their mouth wide against me, and said, Aha, aha, our eye hath seen it."},"BSB":{"text":"They gape at me and say, “Aha, aha! Our eyes have seen!”"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"This thou hast seen, O LORD: keep not silence: O Lord, be not far from me.","ref":"Psalms 35:22","synthesized":"O LORD, You have seen it; be not silent. O Lord, be not far from me.","sources":{"KJV":{"text":"This thou hast seen, O LORD: keep not silence: O Lord, be not far from me."},"BSB":{"text":"O LORD, You have seen it; be not silent. O Lord, be not far from me."}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"23":{"text":"Stir up thyself, and awake to my judgment, even unto my cause, my God and my Lord.","ref":"Psalms 35:23","synthesized":"Awake and rise to my defense, to my cause, my God and my Lord!","sources":{"KJV":{"text":"Stir up thyself, and awake to my judgment, even unto my cause, my God and my Lord."},"BSB":{"text":"Awake and rise to my defense, to my cause, my God and my Lord!"}},"definableWords":["God","Lord"],"peopleInVerse":[]},"24":{"text":"Judge me, O LORD my God, according to thy righteousness; and let them not rejoice over me.","ref":"Psalms 35:24","synthesized":"Vindicate me by Your righteousness, O LORD my God, and do not let them gloat over me.","sources":{"KJV":{"text":"Judge me, O LORD my God, according to thy righteousness; and let them not rejoice over me."},"BSB":{"text":"Vindicate me by Your righteousness, O LORD my God, and do not let them gloat over me."}},"definableWords":["righteousness","LORD","God"],"peopleInVerse":[]},"25":{"text":"Let them not say in their hearts, Ah, so would we have it: let them not say, We have swallowed him up.","ref":"Psalms 35:25","synthesized":"Let them not say in their hearts, “Aha, just what we wanted!” Let them not say, “We have swallowed him up!”","sources":{"KJV":{"text":"Let them not say in their hearts, Ah, so would we have it: let them not say, We have swallowed him up."},"BSB":{"text":"Let them not say in their hearts, “Aha, just what we wanted!” Let them not say, “We have swallowed him up!”"}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"Let them be ashamed and brought to confusion together that rejoice at mine hurt: let them be clothed with shame and dishonour that magnify themselves against me.","ref":"Psalms 35:26","synthesized":"May those who gloat in my distress be ashamed and confounded; may those who exalt themselves over me be clothed in shame and reproach.","sources":{"KJV":{"text":"Let them be ashamed and brought to confusion together that rejoice at mine hurt: let them be clothed with shame and dishonour that magnify themselves against me."},"BSB":{"text":"May those who gloat in my distress be ashamed and confounded; may those who exalt themselves over me be clothed in shame and reproach."}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"Let them shout for joy, and be glad, that favour my righteous cause: yea, let them say continually, Let the LORD be magnified, which hath pleasure in the prosperity of his servant.","ref":"Psalms 35:27","synthesized":"May those who favor my vindication shout for joy and gladness; may they always say, “Exalted be the LORD who delights in His servant’s well-being.”","sources":{"KJV":{"text":"Let them shout for joy, and be glad, that favour my righteous cause: yea, let them say continually, Let the LORD be magnified, which hath pleasure in the prosperity of his servant."},"BSB":{"text":"May those who favor my vindication shout for joy and gladness; may they always say, “Exalted be the LORD who delights in His servant’s well-being.”"}},"definableWords":["joy","LORD","servant"],"peopleInVerse":[]},"28":{"text":"And my tongue shall speak of thy righteousness and of thy praise all the day long.","ref":"Psalms 35:28","synthesized":"Then my tongue will proclaim Your righteousness and Your praises all day long.","sources":{"KJV":{"text":"And my tongue shall speak of thy righteousness and of thy praise all the day long."},"BSB":{"text":"Then my tongue will proclaim Your righteousness and Your praises all day long."}},"definableWords":["righteousness","day"],"peopleInVerse":[]}}},"36":{"chapter":"36","title":"WICKEDNESS OF MAN — MERCY OF GOD","verses":{"1":{"text":"The transgression of the wicked saith within my heart, that there is no fear of God before his eyes.","ref":"Psalms 36:1","synthesized":"An oracle is in my heart regarding the transgression of the wicked man: There is no fear of God before his eyes.","sources":{"KJV":{"text":"The transgression of the wicked saith within my heart, that there is no fear of God before his eyes."},"BSB":{"text":"An oracle is in my heart regarding the transgression of the wicked man: There is no fear of God before his eyes."}},"definableWords":["heart","transgression","man","fear","God"],"peopleInVerse":[]},"2":{"text":"For he flattereth himself in his own eyes, until his iniquity be found to be hateful.","ref":"Psalms 36:2","synthesized":"For his eyes are too full of conceit to detect or hate his own sin.","sources":{"KJV":{"text":"For he flattereth himself in his own eyes, until his iniquity be found to be hateful."},"BSB":{"text":"For his eyes are too full of conceit to detect or hate his own sin."}},"definableWords":["or","sin"],"peopleInVerse":[]},"3":{"text":"The words of his mouth are iniquity and deceit: he hath left off to be wise, and to do good.","ref":"Psalms 36:3","synthesized":"The words of his mouth are wicked and deceitful; he has ceased to be wise and well-doing.","sources":{"KJV":{"text":"The words of his mouth are iniquity and deceit: he hath left off to be wise, and to do good."},"BSB":{"text":"The words of his mouth are wicked and deceitful; he has ceased to be wise and well-doing."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"He deviseth mischief upon his bed; he setteth himself in a way that is not good; he abhorreth not evil.","ref":"Psalms 36:4","synthesized":"Even on his bed he plots wickedness; he sets himself on a path that is not good; he fails to reject evil.","sources":{"KJV":{"text":"He deviseth mischief upon his bed; he setteth himself in a way that is not good; he abhorreth not evil."},"BSB":{"text":"Even on his bed he plots wickedness; he sets himself on a path that is not good; he fails to reject evil."}},"definableWords":["good","evil"],"peopleInVerse":[]},"5":{"text":"Thy mercy, O LORD, is in the heavens; and thy faithfulness reacheth unto the clouds.","ref":"Psalms 36:5","synthesized":"Your loving devotion, O LORD, reaches to the heavens, Your faithfulness to the clouds.","sources":{"KJV":{"text":"Thy mercy, O LORD, is in the heavens; and thy faithfulness reacheth unto the clouds."},"BSB":{"text":"Your loving devotion, O LORD, reaches to the heavens, Your faithfulness to the clouds."}},"definableWords":["LORD","heavens"],"peopleInVerse":[]},"6":{"text":"Thy righteousness is like the great mountains; thy judgments are a great deep: O LORD, thou preservest man and beast.","ref":"Psalms 36:6","synthesized":"Your righteousness is like the highest mountains; Your judgments are like the deepest sea. O LORD, You preserve man and beast.","sources":{"KJV":{"text":"Thy righteousness is like the great mountains; thy judgments are a great deep: O LORD, thou preservest man and beast."},"BSB":{"text":"Your righteousness is like the highest mountains; Your judgments are like the deepest sea. O LORD, You preserve man and beast."}},"definableWords":["righteousness","sea","LORD","man"],"peopleInVerse":[]},"7":{"text":"How excellent is thy lovingkindness, O God! therefore the children of men put their trust under the shadow of thy wings.","ref":"Psalms 36:7","synthesized":"How precious is Your loving devotion, O God, that the children of men take refuge in the shadow of Your wings!","sources":{"KJV":{"text":"How excellent is thy lovingkindness, O God! therefore the children of men put their trust under the shadow of thy wings."},"BSB":{"text":"How precious is Your loving devotion, O God, that the children of men take refuge in the shadow of Your wings!"}},"definableWords":["God","men"],"peopleInVerse":[]},"8":{"text":"They shall be abundantly satisfied with the fatness of thy house; and thou shalt make them drink of the river of thy pleasures.","ref":"Psalms 36:8","synthesized":"They feast on the abundance of Your house, and You give them drink from Your river of delights.","sources":{"KJV":{"text":"They shall be abundantly satisfied with the fatness of thy house; and thou shalt make them drink of the river of thy pleasures."},"BSB":{"text":"They feast on the abundance of Your house, and You give them drink from Your river of delights."}},"definableWords":["house"],"peopleInVerse":[]},"9":{"text":"For with thee is the fountain of life: in thy light shall we see light.","ref":"Psalms 36:9","synthesized":"For with You is the fountain of life; in Your light we see light.","sources":{"KJV":{"text":"For with thee is the fountain of life: in thy light shall we see light."},"BSB":{"text":"For with You is the fountain of life; in Your light we see light."}},"definableWords":["life","light","see"],"peopleInVerse":[]},"10":{"text":"O continue thy lovingkindness unto them that know thee; and thy righteousness to the upright in heart.","ref":"Psalms 36:10","synthesized":"Extend Your loving devotion to those who know You, and Your righteousness to the upright in heart.","sources":{"KJV":{"text":"O continue thy lovingkindness unto them that know thee; and thy righteousness to the upright in heart."},"BSB":{"text":"Extend Your loving devotion to those who know You, and Your righteousness to the upright in heart."}},"definableWords":["righteousness","heart"],"peopleInVerse":[]},"11":{"text":"Let not the foot of pride come against me, and let not the hand of the wicked remove me.","ref":"Psalms 36:11","synthesized":"Let not the foot of the proud come against me, nor the hand of the wicked drive me away.","sources":{"KJV":{"text":"Let not the foot of pride come against me, and let not the hand of the wicked remove me."},"BSB":{"text":"Let not the foot of the proud come against me, nor the hand of the wicked drive me away."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"There are the workers of iniquity fallen: they are cast down, and shall not be able to rise.","ref":"Psalms 36:12","synthesized":"There the evildoers lie fallen, thrown down and unable to rise.","sources":{"KJV":{"text":"There are the workers of iniquity fallen: they are cast down, and shall not be able to rise."},"BSB":{"text":"There the evildoers lie fallen, thrown down and unable to rise."}},"definableWords":[],"peopleInVerse":[]}}},"37":{"chapter":"37","title":"FRET NOT THYSELF","verses":{"1":{"text":"Fret not thyself because of evildoers, neither be thou envious against the workers of iniquity.","ref":"Psalms 37:1","synthesized":"Do not fret over those who do evil; do not envy those who do wrong.","sources":{"KJV":{"text":"Fret not thyself because of evildoers, neither be thou envious against the workers of iniquity."},"BSB":{"text":"Do not fret over those who do evil; do not envy those who do wrong."}},"definableWords":["evil"],"peopleInVerse":[]},"2":{"text":"For they shall soon be cut down like the grass, and wither as the green herb.","ref":"Psalms 37:2","synthesized":"For they wither quickly like grass and wilt like tender plants.","sources":{"KJV":{"text":"For they shall soon be cut down like the grass, and wither as the green herb."},"BSB":{"text":"For they wither quickly like grass and wilt like tender plants."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Trust in the LORD, and do good; so shalt thou dwell in the land, and verily thou shalt be fed.","ref":"Psalms 37:3","synthesized":"Trust in the LORD and do good; dwell in the land and cultivate faithfulness.","sources":{"KJV":{"text":"Trust in the LORD, and do good; so shalt thou dwell in the land, and verily thou shalt be fed."},"BSB":{"text":"Trust in the LORD and do good; dwell in the land and cultivate faithfulness."}},"definableWords":["trust","LORD","good","land"],"peopleInVerse":[]},"4":{"text":"Delight thyself also in the LORD: and he shall give thee the desires of thine heart.","ref":"Psalms 37:4","synthesized":"Delight yourself in the LORD, and He will give you the desires of your heart.","sources":{"KJV":{"text":"Delight thyself also in the LORD: and he shall give thee the desires of thine heart."},"BSB":{"text":"Delight yourself in the LORD, and He will give you the desires of your heart."}},"definableWords":["LORD","heart"],"peopleInVerse":[]},"5":{"text":"Commit thy way unto the LORD; trust also in him; and he shall bring it to pass.","ref":"Psalms 37:5","synthesized":"Commit your way to the LORD; trust in Him, and He will do it.","sources":{"KJV":{"text":"Commit thy way unto the LORD; trust also in him; and he shall bring it to pass."},"BSB":{"text":"Commit your way to the LORD; trust in Him, and He will do it."}},"definableWords":["way","LORD","trust"],"peopleInVerse":[]},"6":{"text":"And he shall bring forth thy righteousness as the light, and thy judgment as the noonday.","ref":"Psalms 37:6","synthesized":"He will bring forth your righteousness like the dawn, your justice like the noonday sun.","sources":{"KJV":{"text":"And he shall bring forth thy righteousness as the light, and thy judgment as the noonday."},"BSB":{"text":"He will bring forth your righteousness like the dawn, your justice like the noonday sun."}},"definableWords":["righteousness","justice"],"peopleInVerse":[]},"7":{"text":"Rest in the LORD, and wait patiently for him: fret not thyself because of him who prospereth in his way, because of the man who bringeth wicked devices to pass.","ref":"Psalms 37:7","synthesized":"Be still before the LORD and wait patiently for Him; do not fret when men prosper in their ways, when they carry out wicked schemes.","sources":{"KJV":{"text":"Rest in the LORD, and wait patiently for him: fret not thyself because of him who prospereth in his way, because of the man who bringeth wicked devices to pass."},"BSB":{"text":"Be still before the LORD and wait patiently for Him; do not fret when men prosper in their ways, when they carry out wicked schemes."}},"definableWords":["LORD","wait","men"],"peopleInVerse":[]},"8":{"text":"Cease from anger, and forsake wrath: fret not thyself in any wise to do evil.","ref":"Psalms 37:8","synthesized":"Refrain from anger and abandon wrath; do not fret—it can only bring harm.","sources":{"KJV":{"text":"Cease from anger, and forsake wrath: fret not thyself in any wise to do evil."},"BSB":{"text":"Refrain from anger and abandon wrath; do not fret—it can only bring harm."}},"definableWords":["anger","wrath"],"peopleInVerse":[]},"9":{"text":"For evildoers shall be cut off: but those that wait upon the LORD, they shall inherit the earth.","ref":"Psalms 37:9","synthesized":"For the evildoers will be cut off, but those who hope in the LORD will inherit the land.","sources":{"KJV":{"text":"For evildoers shall be cut off: but those that wait upon the LORD, they shall inherit the earth."},"BSB":{"text":"For the evildoers will be cut off, but those who hope in the LORD will inherit the land."}},"definableWords":["hope","LORD","inherit","land"],"peopleInVerse":[]},"10":{"text":"For yet a little while, and the wicked shall not be: yea, thou shalt diligently consider his place, and it shall not be.","ref":"Psalms 37:10","synthesized":"Yet a little while, and the wicked will be no more; though you look for them, they will not be found.","sources":{"KJV":{"text":"For yet a little while, and the wicked shall not be: yea, thou shalt diligently consider his place, and it shall not be."},"BSB":{"text":"Yet a little while, and the wicked will be no more; though you look for them, they will not be found."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"But the meek shall inherit the earth; and shall delight themselves in the abundance of peace.","ref":"Psalms 37:11","synthesized":"But the meek will inherit the land and delight in abundant prosperity.","sources":{"KJV":{"text":"But the meek shall inherit the earth; and shall delight themselves in the abundance of peace."},"BSB":{"text":"But the meek will inherit the land and delight in abundant prosperity."}},"definableWords":["inherit","land"],"peopleInVerse":[]},"12":{"text":"The wicked plotteth against the just, and gnasheth upon him with his teeth.","ref":"Psalms 37:12","synthesized":"The wicked scheme against the righteous and gnash their teeth at them,","sources":{"KJV":{"text":"The wicked plotteth against the just, and gnasheth upon him with his teeth."},"BSB":{"text":"The wicked scheme against the righteous and gnash their teeth at them,"}},"definableWords":["righteous"],"peopleInVerse":[]},"13":{"text":"The LORD shall laugh at him: for he seeth that his day is coming.","ref":"Psalms 37:13","synthesized":"but the Lord laughs, seeing that their day is coming.","sources":{"KJV":{"text":"The LORD shall laugh at him: for he seeth that his day is coming."},"BSB":{"text":"but the Lord laughs, seeing that their day is coming."}},"definableWords":["Lord","day"],"peopleInVerse":[]},"14":{"text":"The wicked have drawn out the sword, and have bent their bow, to cast down the poor and needy, and to slay such as be of upright conversation.","ref":"Psalms 37:14","synthesized":"The wicked have drawn the sword and bent the bow to bring down the poor and needy, to slay those whose ways are upright.","sources":{"KJV":{"text":"The wicked have drawn out the sword, and have bent their bow, to cast down the poor and needy, and to slay such as be of upright conversation."},"BSB":{"text":"The wicked have drawn the sword and bent the bow to bring down the poor and needy, to slay those whose ways are upright."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Their sword shall enter into their own heart, and their bows shall be broken.","ref":"Psalms 37:15","synthesized":"But their swords will pierce their own hearts, and their bows will be broken.","sources":{"KJV":{"text":"Their sword shall enter into their own heart, and their bows shall be broken."},"BSB":{"text":"But their swords will pierce their own hearts, and their bows will be broken."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"A little that a righteous man hath is better than the riches of many wicked.","ref":"Psalms 37:16","synthesized":"Better is the little of the righteous than the abundance of many who are wicked.","sources":{"KJV":{"text":"A little that a righteous man hath is better than the riches of many wicked."},"BSB":{"text":"Better is the little of the righteous than the abundance of many who are wicked."}},"definableWords":["righteous"],"peopleInVerse":[]},"17":{"text":"For the arms of the wicked shall be broken: but the LORD upholdeth the righteous.","ref":"Psalms 37:17","synthesized":"For the arms of the wicked will be broken, but the LORD upholds the righteous.","sources":{"KJV":{"text":"For the arms of the wicked shall be broken: but the LORD upholdeth the righteous."},"BSB":{"text":"For the arms of the wicked will be broken, but the LORD upholds the righteous."}},"definableWords":["LORD","righteous"],"peopleInVerse":[]},"18":{"text":"The LORD knoweth the days of the upright: and their inheritance shall be for ever.","ref":"Psalms 37:18","synthesized":"The LORD knows the days of the blameless, and their inheritance will last forever.","sources":{"KJV":{"text":"The LORD knoweth the days of the upright: and their inheritance shall be for ever."},"BSB":{"text":"The LORD knows the days of the blameless, and their inheritance will last forever."}},"definableWords":["LORD","days"],"peopleInVerse":[]},"19":{"text":"They shall not be ashamed in the evil time: and in the days of famine they shall be satisfied.","ref":"Psalms 37:19","synthesized":"In the time of evil they will not be ashamed, and in the days of famine they will be satisfied.","sources":{"KJV":{"text":"They shall not be ashamed in the evil time: and in the days of famine they shall be satisfied."},"BSB":{"text":"In the time of evil they will not be ashamed, and in the days of famine they will be satisfied."}},"definableWords":["evil","days"],"peopleInVerse":[]},"20":{"text":"But the wicked shall perish, and the enemies of the LORD shall be as the fat of lambs: they shall consume; into smoke shall they consume away.","ref":"Psalms 37:20","synthesized":"But the wicked and enemies of the LORD will perish like the glory of the fields. They will vanish; like smoke they will fade away.","sources":{"KJV":{"text":"But the wicked shall perish, and the enemies of the LORD shall be as the fat of lambs: they shall consume; into smoke shall they consume away."},"BSB":{"text":"But the wicked and enemies of the LORD will perish like the glory of the fields. They will vanish; like smoke they will fade away."}},"definableWords":["LORD","glory"],"peopleInVerse":[]},"21":{"text":"The wicked borroweth, and payeth not again: but the righteous sheweth mercy, and giveth.","ref":"Psalms 37:21","synthesized":"The wicked borrow and do not repay, but the righteous are gracious and giving.","sources":{"KJV":{"text":"The wicked borroweth, and payeth not again: but the righteous sheweth mercy, and giveth."},"BSB":{"text":"The wicked borrow and do not repay, but the righteous are gracious and giving."}},"definableWords":["righteous"],"peopleInVerse":[]},"22":{"text":"For such as be blessed of him shall inherit the earth; and they that be cursed of him shall be cut off.","ref":"Psalms 37:22","synthesized":"Surely those He blesses will inherit the land, but the cursed will be destroyed.","sources":{"KJV":{"text":"For such as be blessed of him shall inherit the earth; and they that be cursed of him shall be cut off."},"BSB":{"text":"Surely those He blesses will inherit the land, but the cursed will be destroyed."}},"definableWords":["inherit","land","cursed"],"peopleInVerse":[]},"23":{"text":"The steps of a good man are ordered by the LORD: and he delighteth in his way.","ref":"Psalms 37:23","synthesized":"The steps of a man are ordered by the LORD who takes delight in his journey.","sources":{"KJV":{"text":"The steps of a good man are ordered by the LORD: and he delighteth in his way."},"BSB":{"text":"The steps of a man are ordered by the LORD who takes delight in his journey."}},"definableWords":["man","LORD"],"peopleInVerse":[]},"24":{"text":"Though he fall, he shall not be utterly cast down: for the LORD upholdeth him with his hand.","ref":"Psalms 37:24","synthesized":"Though he falls, he will not be overwhelmed, for the LORD is holding his hand.","sources":{"KJV":{"text":"Though he fall, he shall not be utterly cast down: for the LORD upholdeth him with his hand."},"BSB":{"text":"Though he falls, he will not be overwhelmed, for the LORD is holding his hand."}},"definableWords":["LORD"],"peopleInVerse":[]},"25":{"text":"I have been young, and now am old; yet have I not seen the righteous forsaken, nor his seed begging bread.","ref":"Psalms 37:25","synthesized":"I once was young and now am old, yet never have I seen the righteous abandoned or their children begging for bread.","sources":{"KJV":{"text":"I have been young, and now am old; yet have I not seen the righteous forsaken, nor his seed begging bread."},"BSB":{"text":"I once was young and now am old, yet never have I seen the righteous abandoned or their children begging for bread."}},"definableWords":["righteous","or"],"peopleInVerse":[]},"26":{"text":"He is ever merciful, and lendeth; and his seed is blessed.","ref":"Psalms 37:26","synthesized":"They are ever generous and quick to lend, and their children are a blessing.","sources":{"KJV":{"text":"He is ever merciful, and lendeth; and his seed is blessed."},"BSB":{"text":"They are ever generous and quick to lend, and their children are a blessing."}},"definableWords":["blessing"],"peopleInVerse":[]},"27":{"text":"Depart from evil, and do good; and dwell for evermore.","ref":"Psalms 37:27","synthesized":"Turn away from evil and do good, so that you will abide forever.","sources":{"KJV":{"text":"Depart from evil, and do good; and dwell for evermore."},"BSB":{"text":"Turn away from evil and do good, so that you will abide forever."}},"definableWords":["evil","good","abide"],"peopleInVerse":[]},"28":{"text":"For the LORD loveth judgment, and forsaketh not his saints; they are preserved for ever: but the seed of the wicked shall be cut off.","ref":"Psalms 37:28","synthesized":"For the LORD loves justice and will not forsake His saints. They are preserved forever, but the offspring of the wicked will be cut off.","sources":{"KJV":{"text":"For the LORD loveth judgment, and forsaketh not his saints; they are preserved for ever: but the seed of the wicked shall be cut off."},"BSB":{"text":"For the LORD loves justice and will not forsake His saints. They are preserved forever, but the offspring of the wicked will be cut off."}},"definableWords":["LORD","justice"],"peopleInVerse":[]},"29":{"text":"The righteous shall inherit the land, and dwell therein for ever.","ref":"Psalms 37:29","synthesized":"The righteous will inherit the land and dwell in it forever.","sources":{"KJV":{"text":"The righteous shall inherit the land, and dwell therein for ever."},"BSB":{"text":"The righteous will inherit the land and dwell in it forever."}},"definableWords":["righteous","inherit","land"],"peopleInVerse":[]},"30":{"text":"The mouth of the righteous speaketh wisdom, and his tongue talketh of judgment.","ref":"Psalms 37:30","synthesized":"The mouth of the righteous man utters wisdom, and his tongue speaks justice.","sources":{"KJV":{"text":"The mouth of the righteous speaketh wisdom, and his tongue talketh of judgment."},"BSB":{"text":"The mouth of the righteous man utters wisdom, and his tongue speaks justice."}},"definableWords":["righteous","man","wisdom","justice"],"peopleInVerse":[]},"31":{"text":"The law of his God is in his heart; none of his steps shall slide.","ref":"Psalms 37:31","synthesized":"The law of his God is in his heart; his steps do not falter.","sources":{"KJV":{"text":"The law of his God is in his heart; none of his steps shall slide."},"BSB":{"text":"The law of his God is in his heart; his steps do not falter."}},"definableWords":["law","God","heart"],"peopleInVerse":[]},"32":{"text":"The wicked watcheth the righteous, and seeketh to slay him.","ref":"Psalms 37:32","synthesized":"Though the wicked lie in wait for the righteous, and seek to slay them,","sources":{"KJV":{"text":"The wicked watcheth the righteous, and seeketh to slay him."},"BSB":{"text":"Though the wicked lie in wait for the righteous, and seek to slay them,"}},"definableWords":["wait","righteous","seek"],"peopleInVerse":[]},"33":{"text":"The LORD will not leave him in his hand, nor condemn him when he is judged.","ref":"Psalms 37:33","synthesized":"the LORD will not leave them in their power or let them be condemned under judgment.","sources":{"KJV":{"text":"The LORD will not leave him in his hand, nor condemn him when he is judged."},"BSB":{"text":"the LORD will not leave them in their power or let them be condemned under judgment."}},"definableWords":["LORD","or","judgment"],"peopleInVerse":[]},"34":{"text":"Wait on the LORD, and keep his way, and he shall exalt thee to inherit the land: when the wicked are cut off, thou shalt see it.","ref":"Psalms 37:34","synthesized":"Wait for the LORD and keep His way, and He will raise you up to inherit the land. When the wicked are cut off, you will see it.","sources":{"KJV":{"text":"Wait on the LORD, and keep his way, and he shall exalt thee to inherit the land: when the wicked are cut off, thou shalt see it."},"BSB":{"text":"Wait for the LORD and keep His way, and He will raise you up to inherit the land. When the wicked are cut off, you will see it."}},"definableWords":["wait","LORD","keep","way","inherit","land","see"],"peopleInVerse":[]},"35":{"text":"I have seen the wicked in great power, and spreading himself like a green bay tree.","ref":"Psalms 37:35","synthesized":"I have seen a wicked, ruthless man flourishing like a well-rooted native tree,","sources":{"KJV":{"text":"I have seen the wicked in great power, and spreading himself like a green bay tree."},"BSB":{"text":"I have seen a wicked, ruthless man flourishing like a well-rooted native tree,"}},"definableWords":["man","tree"],"peopleInVerse":[]},"36":{"text":"Yet he passed away, and, lo, he was not: yea, I sought him, but he could not be found.","ref":"Psalms 37:36","synthesized":"yet he passed away and was no more; though I searched, he could not be found.","sources":{"KJV":{"text":"Yet he passed away, and, lo, he was not: yea, I sought him, but he could not be found."},"BSB":{"text":"yet he passed away and was no more; though I searched, he could not be found."}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"Mark the perfect man, and behold the upright: for the end of that man is peace.","ref":"Psalms 37:37","synthesized":"Consider the blameless and observe the upright, for posterity awaits the man of peace.","sources":{"KJV":{"text":"Mark the perfect man, and behold the upright: for the end of that man is peace."},"BSB":{"text":"Consider the blameless and observe the upright, for posterity awaits the man of peace."}},"definableWords":["man","peace"],"peopleInVerse":[]},"38":{"text":"But the transgressors shall be destroyed together: the end of the wicked shall be cut off.","ref":"Psalms 37:38","synthesized":"But the transgressors will all be destroyed; the future of the wicked will be cut off.","sources":{"KJV":{"text":"But the transgressors shall be destroyed together: the end of the wicked shall be cut off."},"BSB":{"text":"But the transgressors will all be destroyed; the future of the wicked will be cut off."}},"definableWords":[],"peopleInVerse":[]},"39":{"text":"But the salvation of the righteous is of the LORD: he is their strength in the time of trouble.","ref":"Psalms 37:39","synthesized":"The salvation of the righteous is from the LORD; He is their stronghold in time of trouble.","sources":{"KJV":{"text":"But the salvation of the righteous is of the LORD: he is their strength in the time of trouble."},"BSB":{"text":"The salvation of the righteous is from the LORD; He is their stronghold in time of trouble."}},"definableWords":["salvation","righteous","LORD"],"peopleInVerse":[]},"40":{"text":"And the LORD shall help them, and deliver them: he shall deliver them from the wicked, and save them, because they trust in him.","ref":"Psalms 37:40","synthesized":"The LORD helps and delivers them; He rescues and saves them from the wicked, because they take refuge in Him.","sources":{"KJV":{"text":"And the LORD shall help them, and deliver them: he shall deliver them from the wicked, and save them, because they trust in him."},"BSB":{"text":"The LORD helps and delivers them; He rescues and saves them from the wicked, because they take refuge in Him."}},"definableWords":["LORD"],"peopleInVerse":[]}}},"38":{"chapter":"38","title":"REBUKE ME NOT IN THY WRATH","verses":{"1":{"text":"O LORD, rebuke me not in thy wrath: neither chasten me in thy hot displeasure.","ref":"Psalms 38:1","synthesized":"O LORD, do not rebuke me in Your anger or discipline me in Your wrath.","sources":{"KJV":{"text":"O LORD, rebuke me not in thy wrath: neither chasten me in thy hot displeasure."},"BSB":{"text":"O LORD, do not rebuke me in Your anger or discipline me in Your wrath."}},"definableWords":["LORD","anger","or","wrath"],"peopleInVerse":[]},"2":{"text":"For thine arrows stick fast in me, and thy hand presseth me sore.","ref":"Psalms 38:2","synthesized":"For Your arrows have pierced me deeply, and Your hand has pressed down on me.","sources":{"KJV":{"text":"For thine arrows stick fast in me, and thy hand presseth me sore."},"BSB":{"text":"For Your arrows have pierced me deeply, and Your hand has pressed down on me."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"There is no soundness in my flesh because of thine anger; neither is there any rest in my bones because of my sin.","ref":"Psalms 38:3","synthesized":"There is no soundness in my body because of Your anger; there is no rest in my bones because of my sin.","sources":{"KJV":{"text":"There is no soundness in my flesh because of thine anger; neither is there any rest in my bones because of my sin."},"BSB":{"text":"There is no soundness in my body because of Your anger; there is no rest in my bones because of my sin."}},"definableWords":["anger","rest","bones","sin"],"peopleInVerse":[]},"4":{"text":"For mine iniquities are gone over mine head: as an heavy burden they are too heavy for me.","ref":"Psalms 38:4","synthesized":"For my iniquities have overwhelmed me; they are a burden too heavy to bear.","sources":{"KJV":{"text":"For mine iniquities are gone over mine head: as an heavy burden they are too heavy for me."},"BSB":{"text":"For my iniquities have overwhelmed me; they are a burden too heavy to bear."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"My wounds stink and are corrupt because of my foolishness.","ref":"Psalms 38:5","synthesized":"My wounds are foul and festering because of my sinful folly.","sources":{"KJV":{"text":"My wounds stink and are corrupt because of my foolishness."},"BSB":{"text":"My wounds are foul and festering because of my sinful folly."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"I am troubled; I am bowed down greatly; I go mourning all the day long.","ref":"Psalms 38:6","synthesized":"I am bent and brought low; all day long I go about mourning.","sources":{"KJV":{"text":"I am troubled; I am bowed down greatly; I go mourning all the day long."},"BSB":{"text":"I am bent and brought low; all day long I go about mourning."}},"definableWords":["day"],"peopleInVerse":[]},"7":{"text":"For my loins are filled with a loathsome disease: and there is no soundness in my flesh.","ref":"Psalms 38:7","synthesized":"For my loins are full of burning pain, and no soundness remains in my body.","sources":{"KJV":{"text":"For my loins are filled with a loathsome disease: and there is no soundness in my flesh."},"BSB":{"text":"For my loins are full of burning pain, and no soundness remains in my body."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"I am feeble and sore broken: I have roared by reason of the disquietness of my heart.","ref":"Psalms 38:8","synthesized":"I am numb and badly crushed; I groan in anguish of heart.","sources":{"KJV":{"text":"I am feeble and sore broken: I have roared by reason of the disquietness of my heart."},"BSB":{"text":"I am numb and badly crushed; I groan in anguish of heart."}},"definableWords":["heart"],"peopleInVerse":[]},"9":{"text":"Lord, all my desire is before thee; and my groaning is not hid from thee.","ref":"Psalms 38:9","synthesized":"O Lord, my every desire is before You; my groaning is not hidden from You.","sources":{"KJV":{"text":"Lord, all my desire is before thee; and my groaning is not hid from thee."},"BSB":{"text":"O Lord, my every desire is before You; my groaning is not hidden from You."}},"definableWords":["Lord"],"peopleInVerse":[]},"10":{"text":"My heart panteth, my strength faileth me: as for the light of mine eyes, it also is gone from me.","ref":"Psalms 38:10","synthesized":"My heart pounds, my strength fails, and even the light of my eyes has faded.","sources":{"KJV":{"text":"My heart panteth, my strength faileth me: as for the light of mine eyes, it also is gone from me."},"BSB":{"text":"My heart pounds, my strength fails, and even the light of my eyes has faded."}},"definableWords":["heart","light"],"peopleInVerse":[]},"11":{"text":"My lovers and my friends stand aloof from my sore; and my kinsmen stand afar off.","ref":"Psalms 38:11","synthesized":"My beloved and friends shun my disease, and my kinsmen stand at a distance.","sources":{"KJV":{"text":"My lovers and my friends stand aloof from my sore; and my kinsmen stand afar off."},"BSB":{"text":"My beloved and friends shun my disease, and my kinsmen stand at a distance."}},"definableWords":["stand"],"peopleInVerse":[]},"12":{"text":"They also that seek after my life lay snares for me: and they that seek my hurt speak mischievous things, and imagine deceits all the day long.","ref":"Psalms 38:12","synthesized":"Those who seek my life lay snares; those who wish me harm speak destruction, plotting deceit all day long.","sources":{"KJV":{"text":"They also that seek after my life lay snares for me: and they that seek my hurt speak mischievous things, and imagine deceits all the day long."},"BSB":{"text":"Those who seek my life lay snares; those who wish me harm speak destruction, plotting deceit all day long."}},"definableWords":["seek","life","day"],"peopleInVerse":[]},"13":{"text":"But I, as a deaf man, heard not; and I was as a dumb man that openeth not his mouth.","ref":"Psalms 38:13","synthesized":"But like a deaf man, I do not hear; and like a mute man, I do not open my mouth.","sources":{"KJV":{"text":"But I, as a deaf man, heard not; and I was as a dumb man that openeth not his mouth."},"BSB":{"text":"But like a deaf man, I do not hear; and like a mute man, I do not open my mouth."}},"definableWords":["man","hear"],"peopleInVerse":[]},"14":{"text":"Thus I was as a man that heareth not, and in whose mouth are no reproofs.","ref":"Psalms 38:14","synthesized":"I am like a man who cannot hear, whose mouth offers no reply.","sources":{"KJV":{"text":"Thus I was as a man that heareth not, and in whose mouth are no reproofs."},"BSB":{"text":"I am like a man who cannot hear, whose mouth offers no reply."}},"definableWords":["man","hear"],"peopleInVerse":[]},"15":{"text":"For in thee, O LORD, do I hope: thou wilt hear, O Lord my God.","ref":"Psalms 38:15","synthesized":"I wait for You, O LORD; You will answer, O Lord my God.","sources":{"KJV":{"text":"For in thee, O LORD, do I hope: thou wilt hear, O Lord my God."},"BSB":{"text":"I wait for You, O LORD; You will answer, O Lord my God."}},"definableWords":["wait","LORD","Lord","God"],"peopleInVerse":[]},"16":{"text":"For I said, Hear me, lest otherwise they should rejoice over me: when my foot slippeth, they magnify themselves against me.","ref":"Psalms 38:16","synthesized":"For I said, “Let them not gloat over me— those who taunt me when my foot slips.”","sources":{"KJV":{"text":"For I said, Hear me, lest otherwise they should rejoice over me: when my foot slippeth, they magnify themselves against me."},"BSB":{"text":"For I said, “Let them not gloat over me— those who taunt me when my foot slips.”"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"For I am ready to halt, and my sorrow is continually before me.","ref":"Psalms 38:17","synthesized":"For I am ready to fall, and my pain is ever with me.","sources":{"KJV":{"text":"For I am ready to halt, and my sorrow is continually before me."},"BSB":{"text":"For I am ready to fall, and my pain is ever with me."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"For I will declare mine iniquity; I will be sorry for my sin.","ref":"Psalms 38:18","synthesized":"Yes, I confess my iniquity; I am troubled by my sin.","sources":{"KJV":{"text":"For I will declare mine iniquity; I will be sorry for my sin."},"BSB":{"text":"Yes, I confess my iniquity; I am troubled by my sin."}},"definableWords":["iniquity","sin"],"peopleInVerse":[]},"19":{"text":"But mine enemies are lively, and they are strong: and they that hate me wrongfully are multiplied.","ref":"Psalms 38:19","synthesized":"Many are my enemies without cause, and many hate me without reason.","sources":{"KJV":{"text":"But mine enemies are lively, and they are strong: and they that hate me wrongfully are multiplied."},"BSB":{"text":"Many are my enemies without cause, and many hate me without reason."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"They also that render evil for good are mine adversaries; because I follow the thing that good is.","ref":"Psalms 38:20","synthesized":"Those who repay my good with evil attack me for pursuing the good.","sources":{"KJV":{"text":"They also that render evil for good are mine adversaries; because I follow the thing that good is."},"BSB":{"text":"Those who repay my good with evil attack me for pursuing the good."}},"definableWords":["good","evil"],"peopleInVerse":[]},"21":{"text":"Forsake me not, O LORD: O my God, be not far from me.","ref":"Psalms 38:21","synthesized":"Do not forsake me, O LORD; be not far from me, O my God.","sources":{"KJV":{"text":"Forsake me not, O LORD: O my God, be not far from me."},"BSB":{"text":"Do not forsake me, O LORD; be not far from me, O my God."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"22":{"text":"Make haste to help me, O Lord my salvation.","ref":"Psalms 38:22","synthesized":"Come quickly to help me, O Lord my Savior.","sources":{"KJV":{"text":"Make haste to help me, O Lord my salvation."},"BSB":{"text":"Come quickly to help me, O Lord my Savior."}},"definableWords":["Lord"],"peopleInVerse":[]}}},"39":{"chapter":"39","title":"I WILL TAKE HEED TO MY WAYS","verses":{"1":{"text":"I said, I will take heed to my ways, that I sin not with my tongue: I will keep my mouth with a bridle, while the wicked is before me.","ref":"Psalms 39:1","synthesized":"I said, “I will watch my ways so that I will not sin with my tongue; I will guard my mouth with a muzzle as long as the wicked are present.”","sources":{"KJV":{"text":"I said, I will take heed to my ways, that I sin not with my tongue: I will keep my mouth with a bridle, while the wicked is before me."},"BSB":{"text":"I said, “I will watch my ways so that I will not sin with my tongue; I will guard my mouth with a muzzle as long as the wicked are present.”"}},"definableWords":["sin"],"peopleInVerse":[]},"2":{"text":"I was dumb with silence, I held my peace, even from good; and my sorrow was stirred.","ref":"Psalms 39:2","synthesized":"I was speechless and still; I remained silent, even from speaking good, and my sorrow was stirred.","sources":{"KJV":{"text":"I was dumb with silence, I held my peace, even from good; and my sorrow was stirred."},"BSB":{"text":"I was speechless and still; I remained silent, even from speaking good, and my sorrow was stirred."}},"definableWords":["good"],"peopleInVerse":[]},"3":{"text":"My heart was hot within me, while I was musing the fire burned: then spake I with my tongue,","ref":"Psalms 39:3","synthesized":"My heart grew hot within me; as I mused, the fire burned.   Then I spoke with my tongue:","sources":{"KJV":{"text":"My heart was hot within me, while I was musing the fire burned: then spake I with my tongue,"},"BSB":{"text":"My heart grew hot within me; as I mused, the fire burned.   Then I spoke with my tongue:"}},"definableWords":["heart"],"peopleInVerse":[]},"4":{"text":"LORD, make me to know mine end, and the measure of my days, what it is: that I may know how frail I am.","ref":"Psalms 39:4","synthesized":"“Show me, O LORD, my end and the measure of my days. Let me know how fleeting my life is.","sources":{"KJV":{"text":"LORD, make me to know mine end, and the measure of my days, what it is: that I may know how frail I am."},"BSB":{"text":"“Show me, O LORD, my end and the measure of my days. Let me know how fleeting my life is."}},"definableWords":["LORD","days","life"],"peopleInVerse":[]},"5":{"text":"Behold, thou hast made my days as an handbreadth; and mine age is as nothing before thee: verily every man at his best state is altogether vanity. Selah.","ref":"Psalms 39:5","synthesized":"You, indeed, have made my days as handbreadths, and my lifetime as nothing before You. Truly each man at his best exists as but a breath. Selah","sources":{"KJV":{"text":"Behold, thou hast made my days as an handbreadth; and mine age is as nothing before thee: verily every man at his best state is altogether vanity. Selah."},"BSB":{"text":"You, indeed, have made my days as handbreadths, and my lifetime as nothing before You. Truly each man at his best exists as but a breath. Selah"}},"definableWords":["made","days","man","breath"],"peopleInVerse":[]},"6":{"text":"Surely every man walketh in a vain shew: surely they are disquieted in vain: he heapeth up riches, and knoweth not who shall gather them.","ref":"Psalms 39:6","synthesized":"Surely every man goes about like a phantom; surely he bustles in vain; he heaps up riches not knowing who will haul them away.","sources":{"KJV":{"text":"Surely every man walketh in a vain shew: surely they are disquieted in vain: he heapeth up riches, and knoweth not who shall gather them."},"BSB":{"text":"Surely every man goes about like a phantom; surely he bustles in vain; he heaps up riches not knowing who will haul them away."}},"definableWords":["man"],"peopleInVerse":[]},"7":{"text":"And now, Lord, what wait I for? my hope is in thee.","ref":"Psalms 39:7","synthesized":"And now, O Lord, for what do I wait? My hope is in You.","sources":{"KJV":{"text":"And now, Lord, what wait I for? my hope is in thee."},"BSB":{"text":"And now, O Lord, for what do I wait? My hope is in You."}},"definableWords":["Lord","wait","hope"],"peopleInVerse":[]},"8":{"text":"Deliver me from all my transgressions: make me not the reproach of the foolish.","ref":"Psalms 39:8","synthesized":"Deliver me from all my transgressions; do not make me the reproach of fools.","sources":{"KJV":{"text":"Deliver me from all my transgressions: make me not the reproach of the foolish."},"BSB":{"text":"Deliver me from all my transgressions; do not make me the reproach of fools."}},"definableWords":["deliver","make"],"peopleInVerse":[]},"9":{"text":"I was dumb, I opened not my mouth; because thou didst it.","ref":"Psalms 39:9","synthesized":"I have become mute; I do not open my mouth because of what You have done.","sources":{"KJV":{"text":"I was dumb, I opened not my mouth; because thou didst it."},"BSB":{"text":"I have become mute; I do not open my mouth because of what You have done."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Remove thy stroke away from me: I am consumed by the blow of thine hand.","ref":"Psalms 39:10","synthesized":"Remove Your scourge from me; I am perishing by the force of Your hand.","sources":{"KJV":{"text":"Remove thy stroke away from me: I am consumed by the blow of thine hand."},"BSB":{"text":"Remove Your scourge from me; I am perishing by the force of Your hand."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"When thou with rebukes dost correct man for iniquity, thou makest his beauty to consume away like a moth: surely every man is vanity. Selah.","ref":"Psalms 39:11","synthesized":"You discipline and correct a man for his iniquity, consuming like a moth what he holds dear; surely each man is but a vapor. Selah","sources":{"KJV":{"text":"When thou with rebukes dost correct man for iniquity, thou makest his beauty to consume away like a moth: surely every man is vanity. Selah."},"BSB":{"text":"You discipline and correct a man for his iniquity, consuming like a moth what he holds dear; surely each man is but a vapor. Selah"}},"definableWords":["man","iniquity"],"peopleInVerse":[]},"12":{"text":"Hear my prayer, O LORD, and give ear unto my cry; hold not thy peace at my tears: for I am a stranger with thee, and a sojourner, as all my fathers were.","ref":"Psalms 39:12","synthesized":"Hear my prayer, O LORD, and give ear to my cry for help; do not be deaf to my weeping. For I am a foreigner dwelling with You, a stranger like all my fathers.","sources":{"KJV":{"text":"Hear my prayer, O LORD, and give ear unto my cry; hold not thy peace at my tears: for I am a stranger with thee, and a sojourner, as all my fathers were."},"BSB":{"text":"Hear my prayer, O LORD, and give ear to my cry for help; do not be deaf to my weeping. For I am a foreigner dwelling with You, a stranger like all my fathers."}},"definableWords":["hear","prayer","LORD","stranger","fathers"],"peopleInVerse":[]},"13":{"text":"O spare me, that I may recover strength, before I go hence, and be no more.","ref":"Psalms 39:13","synthesized":"Turn Your gaze away from me, that I may again be cheered before I depart and am no more.”","sources":{"KJV":{"text":"O spare me, that I may recover strength, before I go hence, and be no more."},"BSB":{"text":"Turn Your gaze away from me, that I may again be cheered before I depart and am no more.”"}},"definableWords":[],"peopleInVerse":[]}}},"40":{"chapter":"40","title":"HE BROUGHT ME UP FROM A HORRIBLE PIT","verses":{"1":{"text":"I waited patiently for the LORD; and he inclined unto me, and heard my cry.","ref":"Psalms 40:1","synthesized":"I waited patiently for the LORD; He inclined to me and heard my cry.","sources":{"KJV":{"text":"I waited patiently for the LORD; and he inclined unto me, and heard my cry."},"BSB":{"text":"I waited patiently for the LORD; He inclined to me and heard my cry."}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"He brought me up also out of an horrible pit, out of the miry clay, and set my feet upon a rock, and established my goings.","ref":"Psalms 40:2","synthesized":"He lifted me up from the pit of despair, out of the miry clay; He set my feet upon a rock, and made my footsteps firm.","sources":{"KJV":{"text":"He brought me up also out of an horrible pit, out of the miry clay, and set my feet upon a rock, and established my goings."},"BSB":{"text":"He lifted me up from the pit of despair, out of the miry clay; He set my feet upon a rock, and made my footsteps firm."}},"definableWords":["made"],"peopleInVerse":[]},"3":{"text":"And he hath put a new song in my mouth, even praise unto our God: many shall see it, and fear, and shall trust in the LORD.","ref":"Psalms 40:3","synthesized":"He put a new song in my mouth, a hymn of praise to our God. Many will see and fear and put their trust in the LORD.","sources":{"KJV":{"text":"And he hath put a new song in my mouth, even praise unto our God: many shall see it, and fear, and shall trust in the LORD."},"BSB":{"text":"He put a new song in my mouth, a hymn of praise to our God. Many will see and fear and put their trust in the LORD."}},"definableWords":["praise","God","see","fear","trust","LORD"],"peopleInVerse":[]},"4":{"text":"Blessed is that man that maketh the LORD his trust, and respecteth not the proud, nor such as turn aside to lies.","ref":"Psalms 40:4","synthesized":"Blessed is the man who has made the LORD his trust, who has not turned to the proud, nor to those who lapse into falsehood.","sources":{"KJV":{"text":"Blessed is that man that maketh the LORD his trust, and respecteth not the proud, nor such as turn aside to lies."},"BSB":{"text":"Blessed is the man who has made the LORD his trust, who has not turned to the proud, nor to those who lapse into falsehood."}},"definableWords":["blessed","man","made","LORD","trust"],"peopleInVerse":[]},"5":{"text":"Many, O LORD my God, are thy wonderful works which thou hast done, and thy thoughts which are to us-ward: they cannot be reckoned up in order unto thee: if I would declare and speak of them, they are more than can be numbered.","ref":"Psalms 40:5","synthesized":"Many, O LORD my God, are the wonders You have done, and the plans You have for us— none can compare to You— if I proclaim and declare them, they are more than I can count.","sources":{"KJV":{"text":"Many, O LORD my God, are thy wonderful works which thou hast done, and thy thoughts which are to us-ward: they cannot be reckoned up in order unto thee: if I would declare and speak of them, they are more than can be numbered."},"BSB":{"text":"Many, O LORD my God, are the wonders You have done, and the plans You have for us— none can compare to You— if I proclaim and declare them, they are more than I can count."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"6":{"text":"Sacrifice and offering thou didst not desire; mine ears hast thou opened: burnt offering and sin offering hast thou not required.","ref":"Psalms 40:6","synthesized":"Sacrifice and offering You did not desire, but my ears You have opened. Burnt offerings and sin offerings You did not require.","sources":{"KJV":{"text":"Sacrifice and offering thou didst not desire; mine ears hast thou opened: burnt offering and sin offering hast thou not required."},"BSB":{"text":"Sacrifice and offering You did not desire, but my ears You have opened. Burnt offerings and sin offerings You did not require."}},"definableWords":["sacrifice","offering","sin"],"peopleInVerse":[]},"7":{"text":"Then said I, Lo, I come: in the volume of the book it is written of me,","ref":"Psalms 40:7","synthesized":"Then I said, “Here I am, I have come— it is written about me in the scroll:","sources":{"KJV":{"text":"Then said I, Lo, I come: in the volume of the book it is written of me,"},"BSB":{"text":"Then I said, “Here I am, I have come— it is written about me in the scroll:"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"I delight to do thy will, O my God: yea, thy law is within my heart.","ref":"Psalms 40:8","synthesized":"I delight to do Your will, O my God; Your law is within my heart.”","sources":{"KJV":{"text":"I delight to do thy will, O my God: yea, thy law is within my heart."},"BSB":{"text":"I delight to do Your will, O my God; Your law is within my heart.”"}},"definableWords":["God","law","heart"],"peopleInVerse":[]},"9":{"text":"I have preached righteousness in the great congregation: lo, I have not refrained my lips, O LORD, thou knowest.","ref":"Psalms 40:9","synthesized":"I proclaim righteousness in the great assembly; behold, I do not seal my lips, as You, O LORD, do know.","sources":{"KJV":{"text":"I have preached righteousness in the great congregation: lo, I have not refrained my lips, O LORD, thou knowest."},"BSB":{"text":"I proclaim righteousness in the great assembly; behold, I do not seal my lips, as You, O LORD, do know."}},"definableWords":["righteousness","great","LORD"],"peopleInVerse":[]},"10":{"text":"I have not hid thy righteousness within my heart; I have declared thy faithfulness and thy salvation: I have not concealed thy lovingkindness and thy truth from the great congregation.","ref":"Psalms 40:10","synthesized":"I have not covered up Your righteousness in my heart; I have declared Your faithfulness and salvation; I have not concealed Your loving devotion and faithfulness from the great assembly.","sources":{"KJV":{"text":"I have not hid thy righteousness within my heart; I have declared thy faithfulness and thy salvation: I have not concealed thy lovingkindness and thy truth from the great congregation."},"BSB":{"text":"I have not covered up Your righteousness in my heart; I have declared Your faithfulness and salvation; I have not concealed Your loving devotion and faithfulness from the great assembly."}},"definableWords":["righteousness","heart","salvation","great"],"peopleInVerse":[]},"11":{"text":"Withhold not thou thy tender mercies from me, O LORD: let thy lovingkindness and thy truth continually preserve me.","ref":"Psalms 40:11","synthesized":"O LORD, do not withhold Your mercy from me; Your loving devotion and faithfulness will always guard me.","sources":{"KJV":{"text":"Withhold not thou thy tender mercies from me, O LORD: let thy lovingkindness and thy truth continually preserve me."},"BSB":{"text":"O LORD, do not withhold Your mercy from me; Your loving devotion and faithfulness will always guard me."}},"definableWords":["LORD","mercy"],"peopleInVerse":[]},"12":{"text":"For innumerable evils have compassed me about: mine iniquities have taken hold upon me, so that I am not able to look up; they are more than the hairs of mine head: therefore my heart faileth me.","ref":"Psalms 40:12","synthesized":"For evils without number surround me; my sins have overtaken me, so that I cannot see. They are more than the hairs of my head, and my heart has failed within me.","sources":{"KJV":{"text":"For innumerable evils have compassed me about: mine iniquities have taken hold upon me, so that I am not able to look up; they are more than the hairs of mine head: therefore my heart faileth me."},"BSB":{"text":"For evils without number surround me; my sins have overtaken me, so that I cannot see. They are more than the hairs of my head, and my heart has failed within me."}},"definableWords":["see","heart"],"peopleInVerse":[]},"13":{"text":"Be pleased, O LORD, to deliver me: O LORD, make haste to help me.","ref":"Psalms 40:13","synthesized":"Be pleased, O LORD, to deliver me; hurry, O LORD, to help me.","sources":{"KJV":{"text":"Be pleased, O LORD, to deliver me: O LORD, make haste to help me."},"BSB":{"text":"Be pleased, O LORD, to deliver me; hurry, O LORD, to help me."}},"definableWords":["LORD","deliver","Lord"],"peopleInVerse":[]},"14":{"text":"Let them be ashamed and confounded together that seek after my soul to destroy it; let them be driven backward and put to shame that wish me evil.","ref":"Psalms 40:14","synthesized":"May those who seek my life be ashamed and confounded; may those who wish me harm be repelled and humiliated.","sources":{"KJV":{"text":"Let them be ashamed and confounded together that seek after my soul to destroy it; let them be driven backward and put to shame that wish me evil."},"BSB":{"text":"May those who seek my life be ashamed and confounded; may those who wish me harm be repelled and humiliated."}},"definableWords":["seek","life"],"peopleInVerse":[]},"15":{"text":"Let them be desolate for a reward of their shame that say unto me, Aha, aha.","ref":"Psalms 40:15","synthesized":"May those who say to me, “Aha, aha!” be appalled at their own shame.","sources":{"KJV":{"text":"Let them be desolate for a reward of their shame that say unto me, Aha, aha."},"BSB":{"text":"May those who say to me, “Aha, aha!” be appalled at their own shame."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Let all those that seek thee rejoice and be glad in thee: let such as love thy salvation say continually, The LORD be magnified.","ref":"Psalms 40:16","synthesized":"May all who seek You rejoice and be glad in You; may those who love Your salvation always say, “The LORD be magnified!”","sources":{"KJV":{"text":"Let all those that seek thee rejoice and be glad in thee: let such as love thy salvation say continually, The LORD be magnified."},"BSB":{"text":"May all who seek You rejoice and be glad in You; may those who love Your salvation always say, “The LORD be magnified!”"}},"definableWords":["seek","love","salvation","LORD"],"peopleInVerse":[]},"17":{"text":"But I am poor and needy; yet the Lord thinketh upon me: thou art my help and my deliverer; make no tarrying, O my God.","ref":"Psalms 40:17","synthesized":"But I am poor and needy; may the Lord think of me. You are my helper and deliverer; O my God, do not delay.","sources":{"KJV":{"text":"But I am poor and needy; yet the Lord thinketh upon me: thou art my help and my deliverer; make no tarrying, O my God."},"BSB":{"text":"But I am poor and needy; may the Lord think of me. You are my helper and deliverer; O my God, do not delay."}},"definableWords":["Lord","helper","God"],"peopleInVerse":[]}}},"41":{"chapter":"41","title":"BLESSED IS HE THAT CONSIDERETH THE POOR","verses":{"1":{"text":"Blessed is he that considereth the poor: the LORD will deliver him in time of trouble.","ref":"Psalms 41:1","synthesized":"Blessed is the one who cares for the poor; the LORD will deliver him in the day of trouble.","sources":{"KJV":{"text":"Blessed is he that considereth the poor: the LORD will deliver him in time of trouble."},"BSB":{"text":"Blessed is the one who cares for the poor; the LORD will deliver him in the day of trouble."}},"definableWords":["blessed","one","LORD","deliver","day"],"peopleInVerse":[]},"2":{"text":"The LORD will preserve him, and keep him alive; and he shall be blessed upon the earth: and thou wilt not deliver him unto the will of his enemies.","ref":"Psalms 41:2","synthesized":"The LORD will protect and preserve him; He will bless him in the land and refuse to surrender him to the will of his foes.","sources":{"KJV":{"text":"The LORD will preserve him, and keep him alive; and he shall be blessed upon the earth: and thou wilt not deliver him unto the will of his enemies."},"BSB":{"text":"The LORD will protect and preserve him; He will bless him in the land and refuse to surrender him to the will of his foes."}},"definableWords":["LORD","bless","land"],"peopleInVerse":[]},"3":{"text":"The LORD will strengthen him upon the bed of languishing: thou wilt make all his bed in his sickness.","ref":"Psalms 41:3","synthesized":"The LORD will sustain him on his bed of illness and restore him from his bed of sickness.","sources":{"KJV":{"text":"The LORD will strengthen him upon the bed of languishing: thou wilt make all his bed in his sickness."},"BSB":{"text":"The LORD will sustain him on his bed of illness and restore him from his bed of sickness."}},"definableWords":["LORD"],"peopleInVerse":[]},"4":{"text":"I said, LORD, be merciful unto me: heal my soul; for I have sinned against thee.","ref":"Psalms 41:4","synthesized":"I said, “O LORD, be gracious to me; heal me, for I have sinned against You.”","sources":{"KJV":{"text":"I said, LORD, be merciful unto me: heal my soul; for I have sinned against thee."},"BSB":{"text":"I said, “O LORD, be gracious to me; heal me, for I have sinned against You.”"}},"definableWords":["LORD","heal"],"peopleInVerse":[]},"5":{"text":"Mine enemies speak evil of me, When shall he die, and his name perish?","ref":"Psalms 41:5","synthesized":"My enemies say with malice: “When will he die and be forgotten?”","sources":{"KJV":{"text":"Mine enemies speak evil of me, When shall he die, and his name perish?"},"BSB":{"text":"My enemies say with malice: “When will he die and be forgotten?”"}},"definableWords":["die"],"peopleInVerse":[]},"6":{"text":"And if he come to see me, he speaketh vanity: his heart gathereth iniquity to itself; when he goeth abroad, he telleth it.","ref":"Psalms 41:6","synthesized":"My visitor speaks falsehood; he gathers slander in his heart; he goes out and spreads it abroad.","sources":{"KJV":{"text":"And if he come to see me, he speaketh vanity: his heart gathereth iniquity to itself; when he goeth abroad, he telleth it."},"BSB":{"text":"My visitor speaks falsehood; he gathers slander in his heart; he goes out and spreads it abroad."}},"definableWords":["heart"],"peopleInVerse":[]},"7":{"text":"All that hate me whisper together against me: against me do they devise my hurt.","ref":"Psalms 41:7","synthesized":"All who hate me whisper against me; they imagine the worst for me:","sources":{"KJV":{"text":"All that hate me whisper together against me: against me do they devise my hurt."},"BSB":{"text":"All who hate me whisper against me; they imagine the worst for me:"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"An evil disease, say they, cleaveth fast unto him: and now that he lieth he shall rise up no more.","ref":"Psalms 41:8","synthesized":"“A vile disease has been poured into him; he will never get up from where he lies!”","sources":{"KJV":{"text":"An evil disease, say they, cleaveth fast unto him: and now that he lieth he shall rise up no more."},"BSB":{"text":"“A vile disease has been poured into him; he will never get up from where he lies!”"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Yea, mine own familiar friend, in whom I trusted, which did eat of my bread, hath lifted up his heel against me.","ref":"Psalms 41:9","synthesized":"Even my close friend whom I trusted, the one who shared my bread, has lifted up his heel against me.","sources":{"KJV":{"text":"Yea, mine own familiar friend, in whom I trusted, which did eat of my bread, hath lifted up his heel against me."},"BSB":{"text":"Even my close friend whom I trusted, the one who shared my bread, has lifted up his heel against me."}},"definableWords":["one"],"peopleInVerse":[]},"10":{"text":"But thou, O LORD, be merciful unto me, and raise me up, that I may requite them.","ref":"Psalms 41:10","synthesized":"But You, O LORD, be gracious to me and raise me up, that I may repay them.","sources":{"KJV":{"text":"But thou, O LORD, be merciful unto me, and raise me up, that I may requite them."},"BSB":{"text":"But You, O LORD, be gracious to me and raise me up, that I may repay them."}},"definableWords":["LORD"],"peopleInVerse":[]},"11":{"text":"By this I know that thou favourest me, because mine enemy doth not triumph over me.","ref":"Psalms 41:11","synthesized":"By this I know that You delight in me, for my enemy does not triumph over me.","sources":{"KJV":{"text":"By this I know that thou favourest me, because mine enemy doth not triumph over me."},"BSB":{"text":"By this I know that You delight in me, for my enemy does not triumph over me."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"And as for me, thou upholdest me in mine integrity, and settest me before thy face for ever.","ref":"Psalms 41:12","synthesized":"In my integrity You uphold me and set me in Your presence forever.","sources":{"KJV":{"text":"And as for me, thou upholdest me in mine integrity, and settest me before thy face for ever."},"BSB":{"text":"In my integrity You uphold me and set me in Your presence forever."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Blessed be the LORD God of Israel from everlasting, and to everlasting. Amen, and Amen.","ref":"Psalms 41:13","synthesized":"Blessed be the LORD, the God of Israel, from everlasting to everlasting.   Amen and Amen.","sources":{"KJV":{"text":"Blessed be the LORD God of Israel from everlasting, and to everlasting. Amen, and Amen."},"BSB":{"text":"Blessed be the LORD, the God of Israel, from everlasting to everlasting.   Amen and Amen."}},"definableWords":["blessed","LORD","God","Israel","everlasting"],"peopleInVerse":[]}}},"42":{"chapter":"42","title":"AS THE HART PANTETH","verses":{"1":{"text":"As the hart panteth after the water brooks, so panteth my soul after thee, O God.","ref":"Psalms 42:1","synthesized":"As the deer pants for streams of water, so my soul longs after You, O God.","sources":{"KJV":{"text":"As the hart panteth after the water brooks, so panteth my soul after thee, O God."},"BSB":{"text":"As the deer pants for streams of water, so my soul longs after You, O God."}},"definableWords":["water","soul","God"],"peopleInVerse":[]},"2":{"text":"My soul thirsteth for God, for the living God: when shall I come and appear before God?","ref":"Psalms 42:2","synthesized":"My soul thirsts for God, the living God. When shall I come and appear in God’s presence?","sources":{"KJV":{"text":"My soul thirsteth for God, for the living God: when shall I come and appear before God?"},"BSB":{"text":"My soul thirsts for God, the living God. When shall I come and appear in God’s presence?"}},"definableWords":["soul","God","living"],"peopleInVerse":[]},"3":{"text":"My tears have been my meat day and night, while they continually say unto me, Where is thy God?","ref":"Psalms 42:3","synthesized":"My tears have been my food both day and night, while men ask me all day long, “Where is your God?”","sources":{"KJV":{"text":"My tears have been my meat day and night, while they continually say unto me, Where is thy God?"},"BSB":{"text":"My tears have been my food both day and night, while men ask me all day long, “Where is your God?”"}},"definableWords":["day","night","men","God"],"peopleInVerse":[]},"4":{"text":"When I remember these things, I pour out my soul in me: for I had gone with the multitude, I went with them to the house of God, with the voice of joy and praise, with a multitude that kept holyday.","ref":"Psalms 42:4","synthesized":"These things come to mind as I pour out my soul: how I walked with the multitude, leading the procession to the house of God with shouts of joy and praise.","sources":{"KJV":{"text":"When I remember these things, I pour out my soul in me: for I had gone with the multitude, I went with them to the house of God, with the voice of joy and praise, with a multitude that kept holyday."},"BSB":{"text":"These things come to mind as I pour out my soul: how I walked with the multitude, leading the procession to the house of God with shouts of joy and praise."}},"definableWords":["mind","soul","walked","house","God","joy","praise"],"peopleInVerse":[]},"5":{"text":"Why art thou cast down, O my soul? and why art thou disquieted in me? hope thou in God: for I shall yet praise him for the help of his countenance.","ref":"Psalms 42:5","synthesized":"Why are you downcast, O my soul? Why the unease within me? Put your hope in God, for I will yet praise Him for the salvation of His presence.","sources":{"KJV":{"text":"Why art thou cast down, O my soul? and why art thou disquieted in me? hope thou in God: for I shall yet praise him for the help of his countenance."},"BSB":{"text":"Why are you downcast, O my soul? Why the unease within me? Put your hope in God, for I will yet praise Him for the salvation of His presence."}},"definableWords":["soul","hope","God","praise","salvation"],"peopleInVerse":[]},"6":{"text":"O my God, my soul is cast down within me: therefore will I remember thee from the land of Jordan, and of the Hermonites, from the hill Mizar.","ref":"Psalms 42:6","synthesized":"O my God, my soul despairs within me. Therefore I remember You from the land of Jordan and the peaks of Hermon— even from Mount Mizar.","sources":{"KJV":{"text":"O my God, my soul is cast down within me: therefore will I remember thee from the land of Jordan, and of the Hermonites, from the hill Mizar."},"BSB":{"text":"O my God, my soul despairs within me. Therefore I remember You from the land of Jordan and the peaks of Hermon— even from Mount Mizar."}},"definableWords":["God","soul","remember","land"],"peopleInVerse":[]},"7":{"text":"Deep calleth unto deep at the noise of thy waterspouts: all thy waves and thy billows are gone over me.","ref":"Psalms 42:7","synthesized":"Deep calls to deep in the roar of Your waterfalls; all Your breakers and waves have rolled over me.","sources":{"KJV":{"text":"Deep calleth unto deep at the noise of thy waterspouts: all thy waves and thy billows are gone over me."},"BSB":{"text":"Deep calls to deep in the roar of Your waterfalls; all Your breakers and waves have rolled over me."}},"definableWords":["deep"],"peopleInVerse":[]},"8":{"text":"Yet the LORD will command his lovingkindness in the day time, and in the night his song shall be with me, and my prayer unto the God of my life.","ref":"Psalms 42:8","synthesized":"The LORD decrees His loving devotion by day, and at night His song is with me as a prayer to the God of my life.","sources":{"KJV":{"text":"Yet the LORD will command his lovingkindness in the day time, and in the night his song shall be with me, and my prayer unto the God of my life."},"BSB":{"text":"The LORD decrees His loving devotion by day, and at night His song is with me as a prayer to the God of my life."}},"definableWords":["LORD","day","night","prayer","God","life"],"peopleInVerse":[]},"9":{"text":"I will say unto God my rock, Why hast thou forgotten me? why go I mourning because of the oppression of the enemy?","ref":"Psalms 42:9","synthesized":"I say to God my Rock, “Why have You forgotten me? Why must I walk in sorrow because of the enemy’s oppression?”","sources":{"KJV":{"text":"I will say unto God my rock, Why hast thou forgotten me? why go I mourning because of the oppression of the enemy?"},"BSB":{"text":"I say to God my Rock, “Why have You forgotten me? Why must I walk in sorrow because of the enemy’s oppression?”"}},"definableWords":["God","walk"],"peopleInVerse":[]},"10":{"text":"As with a sword in my bones, mine enemies reproach me; while they say daily unto me, Where is thy God?","ref":"Psalms 42:10","synthesized":"Like the crushing of my bones, my enemies taunt me, while they say to me all day long, “Where is your God?”","sources":{"KJV":{"text":"As with a sword in my bones, mine enemies reproach me; while they say daily unto me, Where is thy God?"},"BSB":{"text":"Like the crushing of my bones, my enemies taunt me, while they say to me all day long, “Where is your God?”"}},"definableWords":["bones","day","God"],"peopleInVerse":[]},"11":{"text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope thou in God: for I shall yet praise him, who is the health of my countenance, and my God.","ref":"Psalms 42:11","synthesized":"Why are you downcast, O my soul? Why the unease within me? Put your hope in God, for I will yet praise Him, my Savior and my God.","sources":{"KJV":{"text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope thou in God: for I shall yet praise him, who is the health of my countenance, and my God."},"BSB":{"text":"Why are you downcast, O my soul? Why the unease within me? Put your hope in God, for I will yet praise Him, my Savior and my God."}},"definableWords":["soul","hope","God","praise"],"peopleInVerse":[]}}},"43":{"chapter":"43","title":"VINDICATE ME, O GOD","verses":{"1":{"text":"Judge me, O God, and plead my cause against an ungodly nation: O deliver me from the deceitful and unjust man.","ref":"Psalms 43:1","synthesized":"Vindicate me, O God, and plead my case against an ungodly nation; deliver me from deceitful and unjust men.","sources":{"KJV":{"text":"Judge me, O God, and plead my cause against an ungodly nation: O deliver me from the deceitful and unjust man."},"BSB":{"text":"Vindicate me, O God, and plead my case against an ungodly nation; deliver me from deceitful and unjust men."}},"definableWords":["God","nation","deliver","men"],"peopleInVerse":[]},"2":{"text":"For thou art the God of my strength: why dost thou cast me off? why go I mourning because of the oppression of the enemy?","ref":"Psalms 43:2","synthesized":"For You are the God of my refuge. Why have You rejected me? Why must I walk in sorrow because of the enemy’s oppression?","sources":{"KJV":{"text":"For thou art the God of my strength: why dost thou cast me off? why go I mourning because of the oppression of the enemy?"},"BSB":{"text":"For You are the God of my refuge. Why have You rejected me? Why must I walk in sorrow because of the enemy’s oppression?"}},"definableWords":["God","walk"],"peopleInVerse":[]},"3":{"text":"O send out thy light and thy truth: let them lead me; let them bring me unto thy holy hill, and to thy tabernacles.","ref":"Psalms 43:3","synthesized":"Send out Your light and Your truth; let them lead me. Let them bring me to Your holy mountain, and to the place where You dwell.","sources":{"KJV":{"text":"O send out thy light and thy truth: let them lead me; let them bring me unto thy holy hill, and to thy tabernacles."},"BSB":{"text":"Send out Your light and Your truth; let them lead me. Let them bring me to Your holy mountain, and to the place where You dwell."}},"definableWords":["light","truth","holy"],"peopleInVerse":[]},"4":{"text":"Then will I go unto the altar of God, unto God my exceeding joy: yea, upon the harp will I praise thee, O God my God.","ref":"Psalms 43:4","synthesized":"Then I will go to the altar of God, to God, my greatest joy. I will praise You with the harp, O God, my God.","sources":{"KJV":{"text":"Then will I go unto the altar of God, unto God my exceeding joy: yea, upon the harp will I praise thee, O God my God."},"BSB":{"text":"Then I will go to the altar of God, to God, my greatest joy. I will praise You with the harp, O God, my God."}},"definableWords":["altar","God","joy","praise"],"peopleInVerse":[]},"5":{"text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope in God: for I shall yet praise him, who is the health of my countenance, and my God.","ref":"Psalms 43:5","synthesized":"Why are you downcast, O my soul? Why the unease within me? Put your hope in God, for I will yet praise Him, my Savior and my God.","sources":{"KJV":{"text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope in God: for I shall yet praise him, who is the health of my countenance, and my God."},"BSB":{"text":"Why are you downcast, O my soul? Why the unease within me? Put your hope in God, for I will yet praise Him, my Savior and my God."}},"definableWords":["soul","hope","God","praise"],"peopleInVerse":[]}}},"44":{"chapter":"44","title":"AWAKE, WHY SLEEPEST THOU, O LORD?","verses":{"1":{"text":"We have heard with our ears, O God, our fathers have told us, what work thou didst in their days, in the times of old.","ref":"Psalms 44:1","synthesized":"We have heard with our ears, O God; our fathers have told us the work You did in their days, in the days of old.","sources":{"KJV":{"text":"We have heard with our ears, O God, our fathers have told us, what work thou didst in their days, in the times of old."},"BSB":{"text":"We have heard with our ears, O God; our fathers have told us the work You did in their days, in the days of old."}},"definableWords":["God","fathers","work","days"],"peopleInVerse":[]},"2":{"text":"How thou didst drive out the heathen with thy hand, and plantedst them; how thou didst afflict the people, and cast them out.","ref":"Psalms 44:2","synthesized":"With Your hand You drove out the nations and planted our fathers there; You crushed the peoples and cast them out.","sources":{"KJV":{"text":"How thou didst drive out the heathen with thy hand, and plantedst them; how thou didst afflict the people, and cast them out."},"BSB":{"text":"With Your hand You drove out the nations and planted our fathers there; You crushed the peoples and cast them out."}},"definableWords":["nations","fathers"],"peopleInVerse":[]},"3":{"text":"For they got not the land in possession by their own sword, neither did their own arm save them: but thy right hand, and thine arm, and the light of thy countenance, because thou hadst a favour unto them.","ref":"Psalms 44:3","synthesized":"For it was not by their sword that they took the land; their arm did not bring them victory. It was by Your right hand, Your arm, and the light of Your face, because You favored them.","sources":{"KJV":{"text":"For they got not the land in possession by their own sword, neither did their own arm save them: but thy right hand, and thine arm, and the light of thy countenance, because thou hadst a favour unto them."},"BSB":{"text":"For it was not by their sword that they took the land; their arm did not bring them victory. It was by Your right hand, Your arm, and the light of Your face, because You favored them."}},"definableWords":["land","light"],"peopleInVerse":[]},"4":{"text":"Thou art my King, O God: command deliverances for Jacob.","ref":"Psalms 44:4","synthesized":"You are my King, O God, who ordains victories for Jacob.","sources":{"KJV":{"text":"Thou art my King, O God: command deliverances for Jacob."},"BSB":{"text":"You are my King, O God, who ordains victories for Jacob."}},"definableWords":["King","God","Jacob"],"peopleInVerse":["Jacob"]},"5":{"text":"Through thee will we push down our enemies: through thy name will we tread them under that rise up against us.","ref":"Psalms 44:5","synthesized":"Through You we repel our foes; through Your name we trample our enemies.","sources":{"KJV":{"text":"Through thee will we push down our enemies: through thy name will we tread them under that rise up against us."},"BSB":{"text":"Through You we repel our foes; through Your name we trample our enemies."}},"definableWords":["name"],"peopleInVerse":[]},"6":{"text":"For I will not trust in my bow, neither shall my sword save me.","ref":"Psalms 44:6","synthesized":"For I do not trust in my bow, nor does my sword save me.","sources":{"KJV":{"text":"For I will not trust in my bow, neither shall my sword save me."},"BSB":{"text":"For I do not trust in my bow, nor does my sword save me."}},"definableWords":["trust"],"peopleInVerse":[]},"7":{"text":"But thou hast saved us from our enemies, and hast put them to shame that hated us.","ref":"Psalms 44:7","synthesized":"For You save us from our enemies; You put those who hate us to shame.","sources":{"KJV":{"text":"But thou hast saved us from our enemies, and hast put them to shame that hated us."},"BSB":{"text":"For You save us from our enemies; You put those who hate us to shame."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"In God we boast all the day long, and praise thy name for ever. Selah.","ref":"Psalms 44:8","synthesized":"In God we have boasted all day long, and Your name we will praise forever. Selah","sources":{"KJV":{"text":"In God we boast all the day long, and praise thy name for ever. Selah."},"BSB":{"text":"In God we have boasted all day long, and Your name we will praise forever. Selah"}},"definableWords":["God","day","name","praise"],"peopleInVerse":[]},"9":{"text":"But thou hast cast off, and put us to shame; and goest not forth with our armies.","ref":"Psalms 44:9","synthesized":"But You have rejected and humbled us; You no longer go forth with our armies.","sources":{"KJV":{"text":"But thou hast cast off, and put us to shame; and goest not forth with our armies."},"BSB":{"text":"But You have rejected and humbled us; You no longer go forth with our armies."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Thou makest us to turn back from the enemy: and they which hate us spoil for themselves.","ref":"Psalms 44:10","synthesized":"You have made us retreat from the foe, and those who hate us have plundered us.","sources":{"KJV":{"text":"Thou makest us to turn back from the enemy: and they which hate us spoil for themselves."},"BSB":{"text":"You have made us retreat from the foe, and those who hate us have plundered us."}},"definableWords":["made"],"peopleInVerse":[]},"11":{"text":"Thou hast given us like sheep appointed for meat; and hast scattered us among the heathen.","ref":"Psalms 44:11","synthesized":"You have given us up as sheep to be devoured; You have scattered us among the nations.","sources":{"KJV":{"text":"Thou hast given us like sheep appointed for meat; and hast scattered us among the heathen."},"BSB":{"text":"You have given us up as sheep to be devoured; You have scattered us among the nations."}},"definableWords":["nations"],"peopleInVerse":[]},"12":{"text":"Thou sellest thy people for nought, and dost not increase thy wealth by their price.","ref":"Psalms 44:12","synthesized":"You sell Your people for nothing; no profit do You gain from their sale.","sources":{"KJV":{"text":"Thou sellest thy people for nought, and dost not increase thy wealth by their price."},"BSB":{"text":"You sell Your people for nothing; no profit do You gain from their sale."}},"definableWords":["people"],"peopleInVerse":[]},"13":{"text":"Thou makest us a reproach to our neighbours, a scorn and a derision to them that are round about us.","ref":"Psalms 44:13","synthesized":"You have made us a reproach to our neighbors, a mockery and derision to those around us.","sources":{"KJV":{"text":"Thou makest us a reproach to our neighbours, a scorn and a derision to them that are round about us."},"BSB":{"text":"You have made us a reproach to our neighbors, a mockery and derision to those around us."}},"definableWords":["made"],"peopleInVerse":[]},"14":{"text":"Thou makest us a byword among the heathen, a shaking of the head among the people.","ref":"Psalms 44:14","synthesized":"You have made us a byword among the nations, a laughingstock among the peoples.","sources":{"KJV":{"text":"Thou makest us a byword among the heathen, a shaking of the head among the people."},"BSB":{"text":"You have made us a byword among the nations, a laughingstock among the peoples."}},"definableWords":["made","nations"],"peopleInVerse":[]},"15":{"text":"My confusion is continually before me, and the shame of my face hath covered me,","ref":"Psalms 44:15","synthesized":"All day long my disgrace is before me, and shame has covered my face,","sources":{"KJV":{"text":"My confusion is continually before me, and the shame of my face hath covered me,"},"BSB":{"text":"All day long my disgrace is before me, and shame has covered my face,"}},"definableWords":["day"],"peopleInVerse":[]},"16":{"text":"For the voice of him that reproacheth and blasphemeth; by reason of the enemy and avenger.","ref":"Psalms 44:16","synthesized":"at the voice of the scorner and reviler, because of the enemy, bent on revenge.","sources":{"KJV":{"text":"For the voice of him that reproacheth and blasphemeth; by reason of the enemy and avenger."},"BSB":{"text":"at the voice of the scorner and reviler, because of the enemy, bent on revenge."}},"definableWords":["voice"],"peopleInVerse":[]},"17":{"text":"All this is come upon us; yet have we not forgotten thee, neither have we dealt falsely in thy covenant.","ref":"Psalms 44:17","synthesized":"All this has come upon us, though we have not forgotten You or betrayed Your covenant.","sources":{"KJV":{"text":"All this is come upon us; yet have we not forgotten thee, neither have we dealt falsely in thy covenant."},"BSB":{"text":"All this has come upon us, though we have not forgotten You or betrayed Your covenant."}},"definableWords":["or","covenant"],"peopleInVerse":[]},"18":{"text":"Our heart is not turned back, neither have our steps declined from thy way;","ref":"Psalms 44:18","synthesized":"Our hearts have not turned back; our steps have not strayed from Your path.","sources":{"KJV":{"text":"Our heart is not turned back, neither have our steps declined from thy way;"},"BSB":{"text":"Our hearts have not turned back; our steps have not strayed from Your path."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Though thou hast sore broken us in the place of dragons, and covered us with the shadow of death.","ref":"Psalms 44:19","synthesized":"But You have crushed us in the lair of jackals; You have covered us with deepest darkness.","sources":{"KJV":{"text":"Though thou hast sore broken us in the place of dragons, and covered us with the shadow of death."},"BSB":{"text":"But You have crushed us in the lair of jackals; You have covered us with deepest darkness."}},"definableWords":["darkness"],"peopleInVerse":[]},"20":{"text":"If we have forgotten the name of our God, or stretched out our hands to a strange god;","ref":"Psalms 44:20","synthesized":"If we had forgotten the name of our God or spread out our hands to a foreign god,","sources":{"KJV":{"text":"If we have forgotten the name of our God, or stretched out our hands to a strange god;"},"BSB":{"text":"If we had forgotten the name of our God or spread out our hands to a foreign god,"}},"definableWords":["name","God","or"],"peopleInVerse":[]},"21":{"text":"Shall not God search this out? for he knoweth the secrets of the heart.","ref":"Psalms 44:21","synthesized":"would not God have discovered, since He knows the secrets of the heart?","sources":{"KJV":{"text":"Shall not God search this out? for he knoweth the secrets of the heart."},"BSB":{"text":"would not God have discovered, since He knows the secrets of the heart?"}},"definableWords":["God","heart"],"peopleInVerse":[]},"22":{"text":"Yea, for thy sake are we killed all the day long; we are counted as sheep for the slaughter.","ref":"Psalms 44:22","synthesized":"Yet for Your sake we face death all day long; we are considered as sheep to be slaughtered.","sources":{"KJV":{"text":"Yea, for thy sake are we killed all the day long; we are counted as sheep for the slaughter."},"BSB":{"text":"Yet for Your sake we face death all day long; we are considered as sheep to be slaughtered."}},"definableWords":["death","day"],"peopleInVerse":[]},"23":{"text":"Awake, why sleepest thou, O Lord? arise, cast us not off for ever.","ref":"Psalms 44:23","synthesized":"Wake up, O Lord! Why are You sleeping? Arise! Do not reject us forever.","sources":{"KJV":{"text":"Awake, why sleepest thou, O Lord? arise, cast us not off for ever."},"BSB":{"text":"Wake up, O Lord! Why are You sleeping? Arise! Do not reject us forever."}},"definableWords":["Lord"],"peopleInVerse":[]},"24":{"text":"Wherefore hidest thou thy face, and forgettest our affliction and our oppression?","ref":"Psalms 44:24","synthesized":"Why do You hide Your face and forget our affliction and oppression?","sources":{"KJV":{"text":"Wherefore hidest thou thy face, and forgettest our affliction and our oppression?"},"BSB":{"text":"Why do You hide Your face and forget our affliction and oppression?"}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"For our soul is bowed down to the dust: our belly cleaveth unto the earth.","ref":"Psalms 44:25","synthesized":"For our soul has sunk to the dust; our bodies cling to the earth.","sources":{"KJV":{"text":"For our soul is bowed down to the dust: our belly cleaveth unto the earth."},"BSB":{"text":"For our soul has sunk to the dust; our bodies cling to the earth."}},"definableWords":["soul","earth"],"peopleInVerse":[]},"26":{"text":"Arise for our help, and redeem us for thy mercies’ sake.","ref":"Psalms 44:26","synthesized":"Rise up; be our help! Redeem us on account of Your loving devotion.","sources":{"KJV":{"text":"Arise for our help, and redeem us for thy mercies’ sake."},"BSB":{"text":"Rise up; be our help! Redeem us on account of Your loving devotion."}},"definableWords":[],"peopleInVerse":[]}}},"45":{"chapter":"45","title":"MY HEART IS INDITING A GOOD MATTER","verses":{"1":{"text":"My heart is inditing a good matter: I speak of the things which I have made touching the king: my tongue is the pen of a ready writer.","ref":"Psalms 45:1","synthesized":"My heart is stirred by a noble theme as I recite my verses to the king; my tongue is the pen of a skillful writer.","sources":{"KJV":{"text":"My heart is inditing a good matter: I speak of the things which I have made touching the king: my tongue is the pen of a ready writer."},"BSB":{"text":"My heart is stirred by a noble theme as I recite my verses to the king; my tongue is the pen of a skillful writer."}},"definableWords":["heart","king"],"peopleInVerse":[]},"2":{"text":"Thou art fairer than the children of men: grace is poured into thy lips: therefore God hath blessed thee for ever.","ref":"Psalms 45:2","synthesized":"You are the most handsome of men; grace has anointed your lips, since God has blessed you forever.","sources":{"KJV":{"text":"Thou art fairer than the children of men: grace is poured into thy lips: therefore God hath blessed thee for ever."},"BSB":{"text":"You are the most handsome of men; grace has anointed your lips, since God has blessed you forever."}},"definableWords":["men","grace","God","blessed"],"peopleInVerse":[]},"3":{"text":"Gird thy sword upon thy thigh, O most mighty, with thy glory and thy majesty.","ref":"Psalms 45:3","synthesized":"Strap your sword at your side, O mighty warrior; appear in your majesty and splendor.","sources":{"KJV":{"text":"Gird thy sword upon thy thigh, O most mighty, with thy glory and thy majesty."},"BSB":{"text":"Strap your sword at your side, O mighty warrior; appear in your majesty and splendor."}},"definableWords":["mighty"],"peopleInVerse":[]},"4":{"text":"And in thy majesty ride prosperously because of truth and meekness and righteousness; and thy right hand shall teach thee terrible things.","ref":"Psalms 45:4","synthesized":"In your splendor ride forth in victory on behalf of truth and humility and justice; may your right hand show your awesome deeds.","sources":{"KJV":{"text":"And in thy majesty ride prosperously because of truth and meekness and righteousness; and thy right hand shall teach thee terrible things."},"BSB":{"text":"In your splendor ride forth in victory on behalf of truth and humility and justice; may your right hand show your awesome deeds."}},"definableWords":["truth","justice"],"peopleInVerse":[]},"5":{"text":"Thine arrows are sharp in the heart of the king’s enemies; whereby the people fall under thee.","ref":"Psalms 45:5","synthesized":"Your arrows pierce the hearts of the king’s foes; the nations fall beneath your feet.","sources":{"KJV":{"text":"Thine arrows are sharp in the heart of the king’s enemies; whereby the people fall under thee."},"BSB":{"text":"Your arrows pierce the hearts of the king’s foes; the nations fall beneath your feet."}},"definableWords":["king","nations"],"peopleInVerse":[]},"6":{"text":"Thy throne, O God, is for ever and ever: the sceptre of thy kingdom is a right sceptre.","ref":"Psalms 45:6","synthesized":"Your throne, O God, endures forever and ever, and justice is the scepter of Your kingdom.","sources":{"KJV":{"text":"Thy throne, O God, is for ever and ever: the sceptre of thy kingdom is a right sceptre."},"BSB":{"text":"Your throne, O God, endures forever and ever, and justice is the scepter of Your kingdom."}},"definableWords":["throne","God","justice","scepter","kingdom"],"peopleInVerse":[]},"7":{"text":"Thou lovest righteousness, and hatest wickedness: therefore God, thy God, hath anointed thee with the oil of gladness above thy fellows.","ref":"Psalms 45:7","synthesized":"You have loved righteousness and hated wickedness; therefore God, your God, has anointed you above your companions with the oil of joy.","sources":{"KJV":{"text":"Thou lovest righteousness, and hatest wickedness: therefore God, thy God, hath anointed thee with the oil of gladness above thy fellows."},"BSB":{"text":"You have loved righteousness and hated wickedness; therefore God, your God, has anointed you above your companions with the oil of joy."}},"definableWords":["righteousness","God","joy"],"peopleInVerse":[]},"8":{"text":"All thy garments smell of myrrh, and aloes, and cassia, out of the ivory palaces, whereby they have made thee glad.","ref":"Psalms 45:8","synthesized":"All your garments are fragrant with myrrh and aloes and cassia; from palaces of ivory the harps make you glad.","sources":{"KJV":{"text":"All thy garments smell of myrrh, and aloes, and cassia, out of the ivory palaces, whereby they have made thee glad."},"BSB":{"text":"All your garments are fragrant with myrrh and aloes and cassia; from palaces of ivory the harps make you glad."}},"definableWords":["make"],"peopleInVerse":[]},"9":{"text":"Kings’ daughters were among thy honourable women: upon thy right hand did stand the queen in gold of Ophir.","ref":"Psalms 45:9","synthesized":"The daughters of kings are among your honored women; the queen stands at your right hand, adorned with the gold of Ophir.","sources":{"KJV":{"text":"Kings’ daughters were among thy honourable women: upon thy right hand did stand the queen in gold of Ophir."},"BSB":{"text":"The daughters of kings are among your honored women; the queen stands at your right hand, adorned with the gold of Ophir."}},"definableWords":["daughters","kings","women"],"peopleInVerse":[]},"10":{"text":"Hearken, O daughter, and consider, and incline thine ear; forget also thine own people, and thy father’s house;","ref":"Psalms 45:10","synthesized":"Listen, O daughter! Consider and incline your ear: Forget your people and your father’s house,","sources":{"KJV":{"text":"Hearken, O daughter, and consider, and incline thine ear; forget also thine own people, and thy father’s house;"},"BSB":{"text":"Listen, O daughter! Consider and incline your ear: Forget your people and your father’s house,"}},"definableWords":["daughter","people","father","house"],"peopleInVerse":[]},"11":{"text":"So shall the king greatly desire thy beauty: for he is thy Lord; and worship thou him.","ref":"Psalms 45:11","synthesized":"and the king will desire your beauty; bow to him, for he is your lord.","sources":{"KJV":{"text":"So shall the king greatly desire thy beauty: for he is thy Lord; and worship thou him."},"BSB":{"text":"and the king will desire your beauty; bow to him, for he is your lord."}},"definableWords":["king","Lord"],"peopleInVerse":[]},"12":{"text":"And the daughter of Tyre shall be there with a gift; even the rich among the people shall intreat thy favour.","ref":"Psalms 45:12","synthesized":"The Daughter of Tyre will come with a gift; men of wealth will seek your favor.","sources":{"KJV":{"text":"And the daughter of Tyre shall be there with a gift; even the rich among the people shall intreat thy favour."},"BSB":{"text":"The Daughter of Tyre will come with a gift; men of wealth will seek your favor."}},"definableWords":["daughter","men","seek"],"peopleInVerse":[]},"13":{"text":"The king’s daughter is all glorious within: her clothing is of wrought gold.","ref":"Psalms 45:13","synthesized":"All glorious is the princess in her chamber; her gown is embroidered with gold.","sources":{"KJV":{"text":"The king’s daughter is all glorious within: her clothing is of wrought gold."},"BSB":{"text":"All glorious is the princess in her chamber; her gown is embroidered with gold."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"She shall be brought unto the king in raiment of needlework: the virgins her companions that follow her shall be brought unto thee.","ref":"Psalms 45:14","synthesized":"In colorful garments she is led to the king; her virgin companions are brought before you.","sources":{"KJV":{"text":"She shall be brought unto the king in raiment of needlework: the virgins her companions that follow her shall be brought unto thee."},"BSB":{"text":"In colorful garments she is led to the king; her virgin companions are brought before you."}},"definableWords":["king"],"peopleInVerse":[]},"15":{"text":"With gladness and rejoicing shall they be brought: they shall enter into the king’s palace.","ref":"Psalms 45:15","synthesized":"They are led in with joy and gladness; they enter the palace of the king.","sources":{"KJV":{"text":"With gladness and rejoicing shall they be brought: they shall enter into the king’s palace."},"BSB":{"text":"They are led in with joy and gladness; they enter the palace of the king."}},"definableWords":["joy","king"],"peopleInVerse":[]},"16":{"text":"Instead of thy fathers shall be thy children, whom thou mayest make princes in all the earth.","ref":"Psalms 45:16","synthesized":"Your sons will succeed your fathers; you will make them princes throughout the land.","sources":{"KJV":{"text":"Instead of thy fathers shall be thy children, whom thou mayest make princes in all the earth."},"BSB":{"text":"Your sons will succeed your fathers; you will make them princes throughout the land."}},"definableWords":["sons","fathers","make","land"],"peopleInVerse":[]},"17":{"text":"I will make thy name to be remembered in all generations: therefore shall the people praise thee for ever and ever.","ref":"Psalms 45:17","synthesized":"I will commemorate your name through all generations; therefore the nations will praise you forever and ever.","sources":{"KJV":{"text":"I will make thy name to be remembered in all generations: therefore shall the people praise thee for ever and ever."},"BSB":{"text":"I will commemorate your name through all generations; therefore the nations will praise you forever and ever."}},"definableWords":["name","nations","praise"],"peopleInVerse":[]}}},"46":{"chapter":"46","title":"GOD IS OUR REFUGE","verses":{"1":{"text":"God is our refuge and strength, a very present help in trouble.","ref":"Psalms 46:1","synthesized":"God is our refuge and strength, an ever-present help in times of trouble.","sources":{"KJV":{"text":"God is our refuge and strength, a very present help in trouble."},"BSB":{"text":"God is our refuge and strength, an ever-present help in times of trouble."}},"definableWords":["God"],"peopleInVerse":[]},"2":{"text":"Therefore will not we fear, though the earth be removed, and though the mountains be carried into the midst of the sea;","ref":"Psalms 46:2","synthesized":"Therefore we will not fear, though the earth is transformed and the mountains are toppled into the depths of the seas,","sources":{"KJV":{"text":"Therefore will not we fear, though the earth be removed, and though the mountains be carried into the midst of the sea;"},"BSB":{"text":"Therefore we will not fear, though the earth is transformed and the mountains are toppled into the depths of the seas,"}},"definableWords":["fear","earth","seas"],"peopleInVerse":[]},"3":{"text":"Though the waters thereof roar and be troubled, though the mountains shake with the swelling thereof. Selah.","ref":"Psalms 46:3","synthesized":"though their waters roar and foam and the mountains quake in the surge. Selah","sources":{"KJV":{"text":"Though the waters thereof roar and be troubled, though the mountains shake with the swelling thereof. Selah."},"BSB":{"text":"though their waters roar and foam and the mountains quake in the surge. Selah"}},"definableWords":["waters"],"peopleInVerse":[]},"4":{"text":"There is a river, the streams whereof shall make glad the city of God, the holy place of the tabernacles of the most High.","ref":"Psalms 46:4","synthesized":"There is a river whose streams delight the city of God, the holy place where the Most High dwells.","sources":{"KJV":{"text":"There is a river, the streams whereof shall make glad the city of God, the holy place of the tabernacles of the most High."},"BSB":{"text":"There is a river whose streams delight the city of God, the holy place where the Most High dwells."}},"definableWords":["God","holy"],"peopleInVerse":[]},"5":{"text":"God is in the midst of her; she shall not be moved: God shall help her, and that right early.","ref":"Psalms 46:5","synthesized":"God is within her; she will not be moved. God will help her when morning dawns.","sources":{"KJV":{"text":"God is in the midst of her; she shall not be moved: God shall help her, and that right early."},"BSB":{"text":"God is within her; she will not be moved. God will help her when morning dawns."}},"definableWords":["God"],"peopleInVerse":[]},"6":{"text":"The heathen raged, the kingdoms were moved: he uttered his voice, the earth melted.","ref":"Psalms 46:6","synthesized":"Nations rage, kingdoms crumble; the earth melts when He lifts His voice.","sources":{"KJV":{"text":"The heathen raged, the kingdoms were moved: he uttered his voice, the earth melted."},"BSB":{"text":"Nations rage, kingdoms crumble; the earth melts when He lifts His voice."}},"definableWords":["nations","earth","voice"],"peopleInVerse":[]},"7":{"text":"The LORD of hosts is with us; the God of Jacob is our refuge. Selah.","ref":"Psalms 46:7","synthesized":"The LORD of Hosts is with us; the God of Jacob is our fortress. Selah","sources":{"KJV":{"text":"The LORD of hosts is with us; the God of Jacob is our refuge. Selah."},"BSB":{"text":"The LORD of Hosts is with us; the God of Jacob is our fortress. Selah"}},"definableWords":["LORD","God","Jacob"],"peopleInVerse":["Jacob"]},"8":{"text":"Come, behold the works of the LORD, what desolations he hath made in the earth.","ref":"Psalms 46:8","synthesized":"Come, see the works of the LORD, who brings devastation upon the earth.","sources":{"KJV":{"text":"Come, behold the works of the LORD, what desolations he hath made in the earth."},"BSB":{"text":"Come, see the works of the LORD, who brings devastation upon the earth."}},"definableWords":["see","works","LORD","earth"],"peopleInVerse":[]},"9":{"text":"He maketh wars to cease unto the end of the earth; he breaketh the bow, and cutteth the spear in sunder; he burneth the chariot in the fire.","ref":"Psalms 46:9","synthesized":"He makes wars to cease throughout the earth; He breaks the bow and shatters the spear; He burns the shields in the fire.","sources":{"KJV":{"text":"He maketh wars to cease unto the end of the earth; he breaketh the bow, and cutteth the spear in sunder; he burneth the chariot in the fire."},"BSB":{"text":"He makes wars to cease throughout the earth; He breaks the bow and shatters the spear; He burns the shields in the fire."}},"definableWords":["earth"],"peopleInVerse":[]},"10":{"text":"Be still, and know that I am God: I will be exalted among the heathen, I will be exalted in the earth.","ref":"Psalms 46:10","synthesized":"“Be still and know that I am God; I will be exalted among the nations, I will be exalted over the earth.”","sources":{"KJV":{"text":"Be still, and know that I am God: I will be exalted among the heathen, I will be exalted in the earth."},"BSB":{"text":"“Be still and know that I am God; I will be exalted among the nations, I will be exalted over the earth.”"}},"definableWords":["God","nations","earth"],"peopleInVerse":[]},"11":{"text":"The LORD of hosts is with us; the God of Jacob is our refuge. Selah.","ref":"Psalms 46:11","synthesized":"The LORD of Hosts is with us; the God of Jacob is our fortress. Selah","sources":{"KJV":{"text":"The LORD of hosts is with us; the God of Jacob is our refuge. Selah."},"BSB":{"text":"The LORD of Hosts is with us; the God of Jacob is our fortress. Selah"}},"definableWords":["LORD","God","Jacob"],"peopleInVerse":["Jacob"]}}},"47":{"chapter":"47","title":"CLAP YOUR HANDS, ALL YE PEOPLE","verses":{"1":{"text":"O clap your hands, all ye people; shout unto God with the voice of triumph.","ref":"Psalms 47:1","synthesized":"Clap your hands, all you peoples; shout unto God with a voice of triumph.","sources":{"KJV":{"text":"O clap your hands, all ye people; shout unto God with the voice of triumph."},"BSB":{"text":"Clap your hands, all you peoples; shout unto God with a voice of triumph."}},"definableWords":["God","voice"],"peopleInVerse":[]},"2":{"text":"For the LORD most high is terrible; he is a great King over all the earth.","ref":"Psalms 47:2","synthesized":"How awesome is the LORD Most High, the great King over all the earth!","sources":{"KJV":{"text":"For the LORD most high is terrible; he is a great King over all the earth."},"BSB":{"text":"How awesome is the LORD Most High, the great King over all the earth!"}},"definableWords":["LORD","great","King","earth"],"peopleInVerse":[]},"3":{"text":"He shall subdue the people under us, and the nations under our feet.","ref":"Psalms 47:3","synthesized":"He subdues nations beneath us, and peoples under our feet.","sources":{"KJV":{"text":"He shall subdue the people under us, and the nations under our feet."},"BSB":{"text":"He subdues nations beneath us, and peoples under our feet."}},"definableWords":["nations"],"peopleInVerse":[]},"4":{"text":"He shall choose our inheritance for us, the excellency of Jacob whom he loved. Selah.","ref":"Psalms 47:4","synthesized":"He chooses our inheritance for us, the pride of Jacob, whom He loves. Selah","sources":{"KJV":{"text":"He shall choose our inheritance for us, the excellency of Jacob whom he loved. Selah."},"BSB":{"text":"He chooses our inheritance for us, the pride of Jacob, whom He loves. Selah"}},"definableWords":["Jacob"],"peopleInVerse":["Jacob"]},"5":{"text":"God is gone up with a shout, the LORD with the sound of a trumpet.","ref":"Psalms 47:5","synthesized":"God has ascended amid shouts of joy, the LORD with the sound of the horn.","sources":{"KJV":{"text":"God is gone up with a shout, the LORD with the sound of a trumpet."},"BSB":{"text":"God has ascended amid shouts of joy, the LORD with the sound of the horn."}},"definableWords":["God","joy","LORD"],"peopleInVerse":[]},"6":{"text":"Sing praises to God, sing praises: sing praises unto our King, sing praises.","ref":"Psalms 47:6","synthesized":"Sing praises to God, sing praises; sing praises to our King, sing praises!","sources":{"KJV":{"text":"Sing praises to God, sing praises: sing praises unto our King, sing praises."},"BSB":{"text":"Sing praises to God, sing praises; sing praises to our King, sing praises!"}},"definableWords":["God","King"],"peopleInVerse":[]},"7":{"text":"For God is the King of all the earth: sing ye praises with understanding.","ref":"Psalms 47:7","synthesized":"For God is King of all the earth; sing profound praises to Him.","sources":{"KJV":{"text":"For God is the King of all the earth: sing ye praises with understanding."},"BSB":{"text":"For God is King of all the earth; sing profound praises to Him."}},"definableWords":["God","King","earth"],"peopleInVerse":[]},"8":{"text":"God reigneth over the heathen: God sitteth upon the throne of his holiness.","ref":"Psalms 47:8","synthesized":"God reigns over the nations; God is seated on His holy throne.","sources":{"KJV":{"text":"God reigneth over the heathen: God sitteth upon the throne of his holiness."},"BSB":{"text":"God reigns over the nations; God is seated on His holy throne."}},"definableWords":["God","nations","holy","throne"],"peopleInVerse":[]},"9":{"text":"The princes of the people are gathered together, even the people of the God of Abraham: for the shields of the earth belong unto God: he is greatly exalted.","ref":"Psalms 47:9","synthesized":"The nobles of the nations have assembled as the people of the God of Abraham; for the shields of the earth belong to God; He is highly exalted.","sources":{"KJV":{"text":"The princes of the people are gathered together, even the people of the God of Abraham: for the shields of the earth belong unto God: he is greatly exalted."},"BSB":{"text":"The nobles of the nations have assembled as the people of the God of Abraham; for the shields of the earth belong to God; He is highly exalted."}},"definableWords":["nations","people","God","Abraham","earth"],"peopleInVerse":["Abraham"]}}},"48":{"chapter":"48","title":"GREAT IS THE LORD IN ZION","verses":{"1":{"text":"Great is the LORD, and greatly to be praised in the city of our God, in the mountain of his holiness.","ref":"Psalms 48:1","synthesized":"Great is the LORD, and greatly to be praised in the city of our God, His holy mountain.","sources":{"KJV":{"text":"Great is the LORD, and greatly to be praised in the city of our God, in the mountain of his holiness."},"BSB":{"text":"Great is the LORD, and greatly to be praised in the city of our God, His holy mountain."}},"definableWords":["great","LORD","God","holy"],"peopleInVerse":[]},"2":{"text":"Beautiful for situation, the joy of the whole earth, is mount Zion, on the sides of the north, the city of the great King.","ref":"Psalms 48:2","synthesized":"Beautiful in loftiness, the joy of all the earth, like the peaks of Zaphon is Mount Zion, the city of the great King.","sources":{"KJV":{"text":"Beautiful for situation, the joy of the whole earth, is mount Zion, on the sides of the north, the city of the great King."},"BSB":{"text":"Beautiful in loftiness, the joy of all the earth, like the peaks of Zaphon is Mount Zion, the city of the great King."}},"definableWords":["joy","earth","Zion","great","King"],"peopleInVerse":[]},"3":{"text":"God is known in her palaces for a refuge.","ref":"Psalms 48:3","synthesized":"God is in her citadels; He has shown Himself to be a fortress.","sources":{"KJV":{"text":"God is known in her palaces for a refuge."},"BSB":{"text":"God is in her citadels; He has shown Himself to be a fortress."}},"definableWords":["God"],"peopleInVerse":[]},"4":{"text":"For, lo, the kings were assembled, they passed by together.","ref":"Psalms 48:4","synthesized":"For behold, the kings assembled; they all advanced together.","sources":{"KJV":{"text":"For, lo, the kings were assembled, they passed by together."},"BSB":{"text":"For behold, the kings assembled; they all advanced together."}},"definableWords":["kings"],"peopleInVerse":[]},"5":{"text":"They saw it, and so they marvelled; they were troubled, and hasted away.","ref":"Psalms 48:5","synthesized":"They saw and were astounded; they fled in terror.","sources":{"KJV":{"text":"They saw it, and so they marvelled; they were troubled, and hasted away."},"BSB":{"text":"They saw and were astounded; they fled in terror."}},"definableWords":["saw"],"peopleInVerse":[]},"6":{"text":"Fear took hold upon them there, and pain, as of a woman in travail.","ref":"Psalms 48:6","synthesized":"Trembling seized them there, anguish like a woman in labor.","sources":{"KJV":{"text":"Fear took hold upon them there, and pain, as of a woman in travail."},"BSB":{"text":"Trembling seized them there, anguish like a woman in labor."}},"definableWords":["woman"],"peopleInVerse":[]},"7":{"text":"Thou breakest the ships of Tarshish with an east wind.","ref":"Psalms 48:7","synthesized":"With a wind from the east You wrecked the ships of Tarshish.","sources":{"KJV":{"text":"Thou breakest the ships of Tarshish with an east wind."},"BSB":{"text":"With a wind from the east You wrecked the ships of Tarshish."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"As we have heard, so have we seen in the city of the LORD of hosts, in the city of our God: God will establish it for ever. Selah.","ref":"Psalms 48:8","synthesized":"As we have heard, so we have seen in the city of the LORD of Hosts, in the city of our God: God will establish her forever. Selah","sources":{"KJV":{"text":"As we have heard, so have we seen in the city of the LORD of hosts, in the city of our God: God will establish it for ever. Selah."},"BSB":{"text":"As we have heard, so we have seen in the city of the LORD of Hosts, in the city of our God: God will establish her forever. Selah"}},"definableWords":["LORD","God"],"peopleInVerse":[]},"9":{"text":"We have thought of thy lovingkindness, O God, in the midst of thy temple.","ref":"Psalms 48:9","synthesized":"Within Your temple, O God, we contemplate Your loving devotion.","sources":{"KJV":{"text":"We have thought of thy lovingkindness, O God, in the midst of thy temple."},"BSB":{"text":"Within Your temple, O God, we contemplate Your loving devotion."}},"definableWords":["temple","God"],"peopleInVerse":[]},"10":{"text":"According to thy name, O God, so is thy praise unto the ends of the earth: thy right hand is full of righteousness.","ref":"Psalms 48:10","synthesized":"Your name, O God, like Your praise, reaches to the ends of the earth; Your right hand is full of righteousness.","sources":{"KJV":{"text":"According to thy name, O God, so is thy praise unto the ends of the earth: thy right hand is full of righteousness."},"BSB":{"text":"Your name, O God, like Your praise, reaches to the ends of the earth; Your right hand is full of righteousness."}},"definableWords":["name","God","praise","earth","righteousness"],"peopleInVerse":[]},"11":{"text":"Let mount Zion rejoice, let the daughters of Judah be glad, because of thy judgments.","ref":"Psalms 48:11","synthesized":"Mount Zion is glad, the daughters of Judah rejoice, on account of Your judgments.","sources":{"KJV":{"text":"Let mount Zion rejoice, let the daughters of Judah be glad, because of thy judgments."},"BSB":{"text":"Mount Zion is glad, the daughters of Judah rejoice, on account of Your judgments."}},"definableWords":["Zion","daughters","Judah"],"peopleInVerse":[]},"12":{"text":"Walk about Zion, and go round about her: tell the towers thereof.","ref":"Psalms 48:12","synthesized":"March around Zion, encircle her, count her towers,","sources":{"KJV":{"text":"Walk about Zion, and go round about her: tell the towers thereof."},"BSB":{"text":"March around Zion, encircle her, count her towers,"}},"definableWords":["Zion"],"peopleInVerse":[]},"13":{"text":"Mark ye well her bulwarks, consider her palaces; that ye may tell it to the generation following.","ref":"Psalms 48:13","synthesized":"consider her ramparts, tour her citadels, that you may tell the next generation.","sources":{"KJV":{"text":"Mark ye well her bulwarks, consider her palaces; that ye may tell it to the generation following."},"BSB":{"text":"consider her ramparts, tour her citadels, that you may tell the next generation."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"For this God is our God for ever and ever: he will be our guide even unto death.","ref":"Psalms 48:14","synthesized":"For this God is our God forever and ever; He will be our guide even till death.","sources":{"KJV":{"text":"For this God is our God for ever and ever: he will be our guide even unto death."},"BSB":{"text":"For this God is our God forever and ever; He will be our guide even till death."}},"definableWords":["God","till","death"],"peopleInVerse":[]}}},"49":{"chapter":"49","title":"WEALTH CANNOT REDEEM","verses":{"1":{"text":"Hear this, all ye people; give ear, all ye inhabitants of the world:","ref":"Psalms 49:1","synthesized":"Hear this, all you peoples; listen, all inhabitants of the world,","sources":{"KJV":{"text":"Hear this, all ye people; give ear, all ye inhabitants of the world:"},"BSB":{"text":"Hear this, all you peoples; listen, all inhabitants of the world,"}},"definableWords":["hear"],"peopleInVerse":[]},"2":{"text":"Both low and high, rich and poor, together.","ref":"Psalms 49:2","synthesized":"both low and high, rich and poor alike.","sources":{"KJV":{"text":"Both low and high, rich and poor, together."},"BSB":{"text":"both low and high, rich and poor alike."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"My mouth shall speak of wisdom; and the meditation of my heart shall be of understanding.","ref":"Psalms 49:3","synthesized":"My mouth will impart wisdom, and the meditation of my heart will bring understanding.","sources":{"KJV":{"text":"My mouth shall speak of wisdom; and the meditation of my heart shall be of understanding."},"BSB":{"text":"My mouth will impart wisdom, and the meditation of my heart will bring understanding."}},"definableWords":["wisdom","heart"],"peopleInVerse":[]},"4":{"text":"I will incline mine ear to a parable: I will open my dark saying upon the harp.","ref":"Psalms 49:4","synthesized":"I will incline my ear to a proverb; I will express my riddle with the harp:","sources":{"KJV":{"text":"I will incline mine ear to a parable: I will open my dark saying upon the harp."},"BSB":{"text":"I will incline my ear to a proverb; I will express my riddle with the harp:"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Wherefore should I fear in the days of evil, when the iniquity of my heels shall compass me about?","ref":"Psalms 49:5","synthesized":"Why should I fear in times of trouble, when wicked usurpers surround me?","sources":{"KJV":{"text":"Wherefore should I fear in the days of evil, when the iniquity of my heels shall compass me about?"},"BSB":{"text":"Why should I fear in times of trouble, when wicked usurpers surround me?"}},"definableWords":["fear"],"peopleInVerse":[]},"6":{"text":"They that trust in their wealth, and boast themselves in the multitude of their riches;","ref":"Psalms 49:6","synthesized":"They trust in their wealth and boast in their great riches.","sources":{"KJV":{"text":"They that trust in their wealth, and boast themselves in the multitude of their riches;"},"BSB":{"text":"They trust in their wealth and boast in their great riches."}},"definableWords":["trust","great"],"peopleInVerse":[]},"7":{"text":"None of them can by any means redeem his brother, nor give to God a ransom for him:","ref":"Psalms 49:7","synthesized":"No man can possibly redeem his brother or pay his ransom to God.","sources":{"KJV":{"text":"None of them can by any means redeem his brother, nor give to God a ransom for him:"},"BSB":{"text":"No man can possibly redeem his brother or pay his ransom to God."}},"definableWords":["man","brother","or","God"],"peopleInVerse":[]},"8":{"text":"(For the redemption of their soul is precious, and it ceaseth for ever:)","ref":"Psalms 49:8","synthesized":"For the redemption of his soul is costly, and never can payment suffice,","sources":{"KJV":{"text":"(For the redemption of their soul is precious, and it ceaseth for ever:)"},"BSB":{"text":"For the redemption of his soul is costly, and never can payment suffice,"}},"definableWords":["redemption","soul"],"peopleInVerse":[]},"9":{"text":"That he should still live for ever, and not see corruption.","ref":"Psalms 49:9","synthesized":"that he should live on forever and not see decay.","sources":{"KJV":{"text":"That he should still live for ever, and not see corruption."},"BSB":{"text":"that he should live on forever and not see decay."}},"definableWords":["live","see"],"peopleInVerse":[]},"10":{"text":"For he seeth that wise men die, likewise the fool and the brutish person perish, and leave their wealth to others.","ref":"Psalms 49:10","synthesized":"For it is clear that wise men die, and the foolish and the senseless both perish and leave their wealth to others.","sources":{"KJV":{"text":"For he seeth that wise men die, likewise the fool and the brutish person perish, and leave their wealth to others."},"BSB":{"text":"For it is clear that wise men die, and the foolish and the senseless both perish and leave their wealth to others."}},"definableWords":["men","die"],"peopleInVerse":[]},"11":{"text":"Their inward thought is, that their houses shall continue for ever, and their dwelling places to all generations; they call their lands after their own names.","ref":"Psalms 49:11","synthesized":"Their graves are their eternal homes— their dwellings for endless generations— even though their lands were their namesakes.","sources":{"KJV":{"text":"Their inward thought is, that their houses shall continue for ever, and their dwelling places to all generations; they call their lands after their own names."},"BSB":{"text":"Their graves are their eternal homes— their dwellings for endless generations— even though their lands were their namesakes."}},"definableWords":["eternal"],"peopleInVerse":[]},"12":{"text":"Nevertheless man being in honour abideth not: he is like the beasts that perish.","ref":"Psalms 49:12","synthesized":"But a man, despite his wealth, cannot endure; he is like the beasts that perish.","sources":{"KJV":{"text":"Nevertheless man being in honour abideth not: he is like the beasts that perish."},"BSB":{"text":"But a man, despite his wealth, cannot endure; he is like the beasts that perish."}},"definableWords":["man"],"peopleInVerse":[]},"13":{"text":"This their way is their folly: yet their posterity approve their sayings. Selah.","ref":"Psalms 49:13","synthesized":"This is the fate of the self-confident and their followers who endorse their sayings. Selah","sources":{"KJV":{"text":"This their way is their folly: yet their posterity approve their sayings. Selah."},"BSB":{"text":"This is the fate of the self-confident and their followers who endorse their sayings. Selah"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Like sheep they are laid in the grave; death shall feed on them; and the upright shall have dominion over them in the morning; and their beauty shall consume in the grave from their dwelling.","ref":"Psalms 49:14","synthesized":"Like sheep they are destined for Sheol. Death will be their shepherd. The upright will rule them in the morning, and their form will decay in Sheol, far from their lofty abode.","sources":{"KJV":{"text":"Like sheep they are laid in the grave; death shall feed on them; and the upright shall have dominion over them in the morning; and their beauty shall consume in the grave from their dwelling."},"BSB":{"text":"Like sheep they are destined for Sheol. Death will be their shepherd. The upright will rule them in the morning, and their form will decay in Sheol, far from their lofty abode."}},"definableWords":["death","shepherd","rule","form"],"peopleInVerse":[]},"15":{"text":"But God will redeem my soul from the power of the grave: for he shall receive me. Selah.","ref":"Psalms 49:15","synthesized":"But God will redeem my life from Sheol, for He will surely take me to Himself. Selah","sources":{"KJV":{"text":"But God will redeem my soul from the power of the grave: for he shall receive me. Selah."},"BSB":{"text":"But God will redeem my life from Sheol, for He will surely take me to Himself. Selah"}},"definableWords":["God","life"],"peopleInVerse":[]},"16":{"text":"Be not thou afraid when one is made rich, when the glory of his house is increased;","ref":"Psalms 49:16","synthesized":"Do not be amazed when a man grows rich, when the splendor of his house increases.","sources":{"KJV":{"text":"Be not thou afraid when one is made rich, when the glory of his house is increased;"},"BSB":{"text":"Do not be amazed when a man grows rich, when the splendor of his house increases."}},"definableWords":["man","house"],"peopleInVerse":[]},"17":{"text":"For when he dieth he shall carry nothing away: his glory shall not descend after him.","ref":"Psalms 49:17","synthesized":"For when he dies, he will carry nothing away; his abundance will not follow him down.","sources":{"KJV":{"text":"For when he dieth he shall carry nothing away: his glory shall not descend after him."},"BSB":{"text":"For when he dies, he will carry nothing away; his abundance will not follow him down."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Though while he lived he blessed his soul: and men will praise thee, when thou doest well to thyself.","ref":"Psalms 49:18","synthesized":"Though in his lifetime he blesses his soul— and men praise you when you prosper—","sources":{"KJV":{"text":"Though while he lived he blessed his soul: and men will praise thee, when thou doest well to thyself."},"BSB":{"text":"Though in his lifetime he blesses his soul— and men praise you when you prosper—"}},"definableWords":["soul","men","praise"],"peopleInVerse":[]},"19":{"text":"He shall go to the generation of his fathers; they shall never see light.","ref":"Psalms 49:19","synthesized":"he will join the generation of his fathers, who will never see the light of day.","sources":{"KJV":{"text":"He shall go to the generation of his fathers; they shall never see light."},"BSB":{"text":"he will join the generation of his fathers, who will never see the light of day."}},"definableWords":["fathers","see","light","day"],"peopleInVerse":[]},"20":{"text":"Man that is in honour, and understandeth not, is like the beasts that perish.","ref":"Psalms 49:20","synthesized":"A man who has riches without understanding is like the beasts that perish.","sources":{"KJV":{"text":"Man that is in honour, and understandeth not, is like the beasts that perish."},"BSB":{"text":"A man who has riches without understanding is like the beasts that perish."}},"definableWords":["man"],"peopleInVerse":[]}}},"50":{"chapter":"50","title":"THE MIGHTY GOD, THE LORD, HATH SPOKEN","verses":{"1":{"text":"The mighty God, even the LORD, hath spoken, and called the earth from the rising of the sun unto the going down thereof.","ref":"Psalms 50:1","synthesized":"The Mighty One, God the LORD, speaks and summons the earth from where the sun rises to where it sets.","sources":{"KJV":{"text":"The mighty God, even the LORD, hath spoken, and called the earth from the rising of the sun unto the going down thereof."},"BSB":{"text":"The Mighty One, God the LORD, speaks and summons the earth from where the sun rises to where it sets."}},"definableWords":["mighty","one","God","LORD","earth"],"peopleInVerse":[]},"2":{"text":"Out of Zion, the perfection of beauty, God hath shined.","ref":"Psalms 50:2","synthesized":"From Zion, perfect in beauty, God shines forth.","sources":{"KJV":{"text":"Out of Zion, the perfection of beauty, God hath shined."},"BSB":{"text":"From Zion, perfect in beauty, God shines forth."}},"definableWords":["Zion","God"],"peopleInVerse":[]},"3":{"text":"Our God shall come, and shall not keep silence: a fire shall devour before him, and it shall be very tempestuous round about him.","ref":"Psalms 50:3","synthesized":"Our God approaches and will not be silent! Consuming fire precedes Him, and a tempest rages around Him.","sources":{"KJV":{"text":"Our God shall come, and shall not keep silence: a fire shall devour before him, and it shall be very tempestuous round about him."},"BSB":{"text":"Our God approaches and will not be silent! Consuming fire precedes Him, and a tempest rages around Him."}},"definableWords":["God"],"peopleInVerse":[]},"4":{"text":"He shall call to the heavens from above, and to the earth, that he may judge his people.","ref":"Psalms 50:4","synthesized":"He summons the heavens above, and the earth, that He may judge His people:","sources":{"KJV":{"text":"He shall call to the heavens from above, and to the earth, that he may judge his people."},"BSB":{"text":"He summons the heavens above, and the earth, that He may judge His people:"}},"definableWords":["heavens","earth","people"],"peopleInVerse":[]},"5":{"text":"Gather my saints together unto me; those that have made a covenant with me by sacrifice.","ref":"Psalms 50:5","synthesized":"“Gather to Me My saints, who made a covenant with Me by sacrifice.”","sources":{"KJV":{"text":"Gather my saints together unto me; those that have made a covenant with me by sacrifice."},"BSB":{"text":"“Gather to Me My saints, who made a covenant with Me by sacrifice.”"}},"definableWords":["made","covenant","sacrifice"],"peopleInVerse":[]},"6":{"text":"And the heavens shall declare his righteousness: for God is judge himself. Selah.","ref":"Psalms 50:6","synthesized":"And the heavens proclaim His righteousness, for God Himself is Judge. Selah","sources":{"KJV":{"text":"And the heavens shall declare his righteousness: for God is judge himself. Selah."},"BSB":{"text":"And the heavens proclaim His righteousness, for God Himself is Judge. Selah"}},"definableWords":["heavens","righteousness","God"],"peopleInVerse":[]},"7":{"text":"Hear, O my people, and I will speak; O Israel, and I will testify against thee: I am God, even thy God.","ref":"Psalms 50:7","synthesized":"“Hear, O My people, and I will speak, O Israel, and I will testify against you: I am God, your God.","sources":{"KJV":{"text":"Hear, O my people, and I will speak; O Israel, and I will testify against thee: I am God, even thy God."},"BSB":{"text":"“Hear, O My people, and I will speak, O Israel, and I will testify against you: I am God, your God."}},"definableWords":["hear","people","Israel","God"],"peopleInVerse":[]},"8":{"text":"I will not reprove thee for thy sacrifices or thy burnt offerings, to have been continually before me.","ref":"Psalms 50:8","synthesized":"I do not rebuke you for your sacrifices, and your burnt offerings are ever before Me.","sources":{"KJV":{"text":"I will not reprove thee for thy sacrifices or thy burnt offerings, to have been continually before me."},"BSB":{"text":"I do not rebuke you for your sacrifices, and your burnt offerings are ever before Me."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"I will take no bullock out of thy house, nor he goats out of thy folds.","ref":"Psalms 50:9","synthesized":"I have no need for a bull from your stall or goats from your pens,","sources":{"KJV":{"text":"I will take no bullock out of thy house, nor he goats out of thy folds."},"BSB":{"text":"I have no need for a bull from your stall or goats from your pens,"}},"definableWords":["or"],"peopleInVerse":[]},"10":{"text":"For every beast of the forest is mine, and the cattle upon a thousand hills.","ref":"Psalms 50:10","synthesized":"for every beast of the forest is Mine— the cattle on a thousand hills.","sources":{"KJV":{"text":"For every beast of the forest is mine, and the cattle upon a thousand hills."},"BSB":{"text":"for every beast of the forest is Mine— the cattle on a thousand hills."}},"definableWords":["cattle"],"peopleInVerse":[]},"11":{"text":"I know all the fowls of the mountains: and the wild beasts of the field are mine.","ref":"Psalms 50:11","synthesized":"I know every bird in the mountains, and the creatures of the field are Mine.","sources":{"KJV":{"text":"I know all the fowls of the mountains: and the wild beasts of the field are mine."},"BSB":{"text":"I know every bird in the mountains, and the creatures of the field are Mine."}},"definableWords":["bird","field"],"peopleInVerse":[]},"12":{"text":"If I were hungry, I would not tell thee: for the world is mine, and the fulness thereof.","ref":"Psalms 50:12","synthesized":"If I were hungry, I would not tell you, for the world is Mine, and the fullness thereof.","sources":{"KJV":{"text":"If I were hungry, I would not tell thee: for the world is mine, and the fulness thereof."},"BSB":{"text":"If I were hungry, I would not tell you, for the world is Mine, and the fullness thereof."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Will I eat the flesh of bulls, or drink the blood of goats?","ref":"Psalms 50:13","synthesized":"Do I eat the flesh of bulls, or drink the blood of goats?","sources":{"KJV":{"text":"Will I eat the flesh of bulls, or drink the blood of goats?"},"BSB":{"text":"Do I eat the flesh of bulls, or drink the blood of goats?"}},"definableWords":["flesh","or","blood"],"peopleInVerse":[]},"14":{"text":"Offer unto God thanksgiving; and pay thy vows unto the most High:","ref":"Psalms 50:14","synthesized":"Sacrifice a thank offering to God, and fulfill your vows to the Most High.","sources":{"KJV":{"text":"Offer unto God thanksgiving; and pay thy vows unto the most High:"},"BSB":{"text":"Sacrifice a thank offering to God, and fulfill your vows to the Most High."}},"definableWords":["sacrifice","offering","God"],"peopleInVerse":[]},"15":{"text":"And call upon me in the day of trouble: I will deliver thee, and thou shalt glorify me.","ref":"Psalms 50:15","synthesized":"Call upon Me in the day of trouble; I will deliver you, and you will honor Me.”","sources":{"KJV":{"text":"And call upon me in the day of trouble: I will deliver thee, and thou shalt glorify me."},"BSB":{"text":"Call upon Me in the day of trouble; I will deliver you, and you will honor Me.”"}},"definableWords":["day","deliver"],"peopleInVerse":[]},"16":{"text":"But unto the wicked God saith, What hast thou to do to declare my statutes, or that thou shouldest take my covenant in thy mouth?","ref":"Psalms 50:16","synthesized":"To the wicked, however, God says, “What right have you to recite My statutes and to bear My covenant on your lips?","sources":{"KJV":{"text":"But unto the wicked God saith, What hast thou to do to declare my statutes, or that thou shouldest take my covenant in thy mouth?"},"BSB":{"text":"To the wicked, however, God says, “What right have you to recite My statutes and to bear My covenant on your lips?"}},"definableWords":["God","covenant"],"peopleInVerse":[]},"17":{"text":"Seeing thou hatest instruction, and casteth my words behind thee.","ref":"Psalms 50:17","synthesized":"For you hate My instruction and cast My words behind you.","sources":{"KJV":{"text":"Seeing thou hatest instruction, and casteth my words behind thee."},"BSB":{"text":"For you hate My instruction and cast My words behind you."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"When thou sawest a thief, then thou consentedst with him, and hast been partaker with adulterers.","ref":"Psalms 50:18","synthesized":"When you see a thief, you befriend him, and throw in your lot with adulterers.","sources":{"KJV":{"text":"When thou sawest a thief, then thou consentedst with him, and hast been partaker with adulterers."},"BSB":{"text":"When you see a thief, you befriend him, and throw in your lot with adulterers."}},"definableWords":["see","Lot"],"peopleInVerse":[]},"19":{"text":"Thou givest thy mouth to evil, and thy tongue frameth deceit.","ref":"Psalms 50:19","synthesized":"You unleash your mouth for evil and unharness your tongue for deceit.","sources":{"KJV":{"text":"Thou givest thy mouth to evil, and thy tongue frameth deceit."},"BSB":{"text":"You unleash your mouth for evil and unharness your tongue for deceit."}},"definableWords":["evil"],"peopleInVerse":[]},"20":{"text":"Thou sittest and speakest against thy brother; thou slanderest thine own mother’s son.","ref":"Psalms 50:20","synthesized":"You sit and malign your brother; you slander your own mother’s son.","sources":{"KJV":{"text":"Thou sittest and speakest against thy brother; thou slanderest thine own mother’s son."},"BSB":{"text":"You sit and malign your brother; you slander your own mother’s son."}},"definableWords":["brother","mother","son"],"peopleInVerse":[]},"21":{"text":"These things hast thou done, and I kept silence; thou thoughtest that I was altogether such an one as thyself: but I will reprove thee, and set them in order before thine eyes.","ref":"Psalms 50:21","synthesized":"You have done these things, and I kept silent; you thought I was just like you. But now I rebuke you and accuse you to your face.","sources":{"KJV":{"text":"These things hast thou done, and I kept silence; thou thoughtest that I was altogether such an one as thyself: but I will reprove thee, and set them in order before thine eyes."},"BSB":{"text":"You have done these things, and I kept silent; you thought I was just like you. But now I rebuke you and accuse you to your face."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Now consider this, ye that forget God, lest I tear you in pieces, and there be none to deliver.","ref":"Psalms 50:22","synthesized":"Now consider this, you who forget God, lest I tear you to pieces, with no one to rescue you:","sources":{"KJV":{"text":"Now consider this, ye that forget God, lest I tear you in pieces, and there be none to deliver."},"BSB":{"text":"Now consider this, you who forget God, lest I tear you to pieces, with no one to rescue you:"}},"definableWords":["God","one"],"peopleInVerse":[]},"23":{"text":"Whoso offereth praise glorifieth me: and to him that ordereth his conversation aright will I shew the salvation of God.","ref":"Psalms 50:23","synthesized":"He who sacrifices a thank offering honors Me, and to him who rights his way, I will show the salvation of God.”","sources":{"KJV":{"text":"Whoso offereth praise glorifieth me: and to him that ordereth his conversation aright will I shew the salvation of God."},"BSB":{"text":"He who sacrifices a thank offering honors Me, and to him who rights his way, I will show the salvation of God.”"}},"definableWords":["offering","way","salvation","God"],"peopleInVerse":[]}}},"51":{"chapter":"51","title":"DAVID'S PSALM OF REPENTANCE","verses":{"1":{"text":"Have mercy upon me, O God, according to thy lovingkindness: according unto the multitude of thy tender mercies blot out my transgressions.","ref":"Psalms 51:1","synthesized":"Have mercy on me, O God, according to Your loving devotion; according to Your great compassion, blot out my transgressions.","sources":{"KJV":{"text":"Have mercy upon me, O God, according to thy lovingkindness: according unto the multitude of thy tender mercies blot out my transgressions."},"BSB":{"text":"Have mercy on me, O God, according to Your loving devotion; according to Your great compassion, blot out my transgressions."}},"definableWords":["mercy","God","great"],"peopleInVerse":[]},"2":{"text":"Wash me throughly from mine iniquity, and cleanse me from my sin.","ref":"Psalms 51:2","synthesized":"Wash me clean of my iniquity and cleanse me from my sin.","sources":{"KJV":{"text":"Wash me throughly from mine iniquity, and cleanse me from my sin."},"BSB":{"text":"Wash me clean of my iniquity and cleanse me from my sin."}},"definableWords":["iniquity","cleanse","sin"],"peopleInVerse":[]},"3":{"text":"For I acknowledge my transgressions: and my sin is ever before me.","ref":"Psalms 51:3","synthesized":"For I know my transgressions, and my sin is always before me.","sources":{"KJV":{"text":"For I acknowledge my transgressions: and my sin is ever before me."},"BSB":{"text":"For I know my transgressions, and my sin is always before me."}},"definableWords":["sin"],"peopleInVerse":[]},"4":{"text":"Against thee, thee only, have I sinned, and done this evil in thy sight: that thou mightest be justified when thou speakest, and be clear when thou judgest.","ref":"Psalms 51:4","synthesized":"Against You, You only, have I sinned and done what is evil in Your sight, so that You may be proved right when You speak and blameless when You judge.","sources":{"KJV":{"text":"Against thee, thee only, have I sinned, and done this evil in thy sight: that thou mightest be justified when thou speakest, and be clear when thou judgest."},"BSB":{"text":"Against You, You only, have I sinned and done what is evil in Your sight, so that You may be proved right when You speak and blameless when You judge."}},"definableWords":["evil"],"peopleInVerse":[]},"5":{"text":"Behold, I was shapen in iniquity; and in sin did my mother conceive me.","ref":"Psalms 51:5","synthesized":"Surely I was brought forth in iniquity; I was sinful when my mother conceived me.","sources":{"KJV":{"text":"Behold, I was shapen in iniquity; and in sin did my mother conceive me."},"BSB":{"text":"Surely I was brought forth in iniquity; I was sinful when my mother conceived me."}},"definableWords":["iniquity","mother"],"peopleInVerse":[]},"6":{"text":"Behold, thou desirest truth in the inward parts: and in the hidden part thou shalt make me to know wisdom.","ref":"Psalms 51:6","synthesized":"Surely You desire truth in the inmost being; You teach me wisdom in the inmost place.","sources":{"KJV":{"text":"Behold, thou desirest truth in the inward parts: and in the hidden part thou shalt make me to know wisdom."},"BSB":{"text":"Surely You desire truth in the inmost being; You teach me wisdom in the inmost place."}},"definableWords":["truth","wisdom"],"peopleInVerse":[]},"7":{"text":"Purge me with hyssop, and I shall be clean: wash me, and I shall be whiter than snow.","ref":"Psalms 51:7","synthesized":"Purify me with hyssop, and I will be clean; wash me, and I will be whiter than snow.","sources":{"KJV":{"text":"Purge me with hyssop, and I shall be clean: wash me, and I shall be whiter than snow."},"BSB":{"text":"Purify me with hyssop, and I will be clean; wash me, and I will be whiter than snow."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Make me to hear joy and gladness; that the bones which thou hast broken may rejoice.","ref":"Psalms 51:8","synthesized":"Let me hear joy and gladness; let the bones You have crushed rejoice.","sources":{"KJV":{"text":"Make me to hear joy and gladness; that the bones which thou hast broken may rejoice."},"BSB":{"text":"Let me hear joy and gladness; let the bones You have crushed rejoice."}},"definableWords":["hear","joy","bones"],"peopleInVerse":[]},"9":{"text":"Hide thy face from my sins, and blot out all mine iniquities.","ref":"Psalms 51:9","synthesized":"Hide Your face from my sins and blot out all my iniquities.","sources":{"KJV":{"text":"Hide thy face from my sins, and blot out all mine iniquities."},"BSB":{"text":"Hide Your face from my sins and blot out all my iniquities."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Create in me a clean heart, O God; and renew a right spirit within me.","ref":"Psalms 51:10","synthesized":"Create in me a clean heart, O God, and renew a right spirit within me.","sources":{"KJV":{"text":"Create in me a clean heart, O God; and renew a right spirit within me."},"BSB":{"text":"Create in me a clean heart, O God, and renew a right spirit within me."}},"definableWords":["create","heart","God","spirit"],"peopleInVerse":[]},"11":{"text":"Cast me not away from thy presence; and take not thy holy spirit from me.","ref":"Psalms 51:11","synthesized":"Cast me not away from Your presence; take not Your Holy Spirit from me.","sources":{"KJV":{"text":"Cast me not away from thy presence; and take not thy holy spirit from me."},"BSB":{"text":"Cast me not away from Your presence; take not Your Holy Spirit from me."}},"definableWords":["holy","Spirit"],"peopleInVerse":[]},"12":{"text":"Restore unto me the joy of thy salvation; and uphold me with thy free spirit.","ref":"Psalms 51:12","synthesized":"Restore to me the joy of Your salvation, and sustain me with a willing spirit.","sources":{"KJV":{"text":"Restore unto me the joy of thy salvation; and uphold me with thy free spirit."},"BSB":{"text":"Restore to me the joy of Your salvation, and sustain me with a willing spirit."}},"definableWords":["joy","salvation","spirit"],"peopleInVerse":[]},"13":{"text":"Then will I teach transgressors thy ways; and sinners shall be converted unto thee.","ref":"Psalms 51:13","synthesized":"Then I will teach transgressors Your ways, and sinners will return to You.","sources":{"KJV":{"text":"Then will I teach transgressors thy ways; and sinners shall be converted unto thee."},"BSB":{"text":"Then I will teach transgressors Your ways, and sinners will return to You."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Deliver me from bloodguiltiness, O God, thou God of my salvation: and my tongue shall sing aloud of thy righteousness.","ref":"Psalms 51:14","synthesized":"Deliver me from bloodguilt, O God, the God of my salvation, and my tongue will sing of Your righteousness.","sources":{"KJV":{"text":"Deliver me from bloodguiltiness, O God, thou God of my salvation: and my tongue shall sing aloud of thy righteousness."},"BSB":{"text":"Deliver me from bloodguilt, O God, the God of my salvation, and my tongue will sing of Your righteousness."}},"definableWords":["deliver","God","salvation","righteousness"],"peopleInVerse":[]},"15":{"text":"O Lord, open thou my lips; and my mouth shall shew forth thy praise.","ref":"Psalms 51:15","synthesized":"O Lord, open my lips, and my mouth will declare Your praise.","sources":{"KJV":{"text":"O Lord, open thou my lips; and my mouth shall shew forth thy praise."},"BSB":{"text":"O Lord, open my lips, and my mouth will declare Your praise."}},"definableWords":["Lord","praise"],"peopleInVerse":[]},"16":{"text":"For thou desirest not sacrifice; else would I give it: thou delightest not in burnt offering.","ref":"Psalms 51:16","synthesized":"For You do not delight in sacrifice, or I would bring it; You take no pleasure in burnt offerings.","sources":{"KJV":{"text":"For thou desirest not sacrifice; else would I give it: thou delightest not in burnt offering."},"BSB":{"text":"For You do not delight in sacrifice, or I would bring it; You take no pleasure in burnt offerings."}},"definableWords":["sacrifice","or"],"peopleInVerse":[]},"17":{"text":"The sacrifices of God are a broken spirit: a broken and a contrite heart, O God, thou wilt not despise.","ref":"Psalms 51:17","synthesized":"The sacrifices of God are a broken spirit; a broken and a contrite heart, O God, You will not despise.","sources":{"KJV":{"text":"The sacrifices of God are a broken spirit: a broken and a contrite heart, O God, thou wilt not despise."},"BSB":{"text":"The sacrifices of God are a broken spirit; a broken and a contrite heart, O God, You will not despise."}},"definableWords":["God","spirit","heart"],"peopleInVerse":[]},"18":{"text":"Do good in thy good pleasure unto Zion: build thou the walls of Jerusalem.","ref":"Psalms 51:18","synthesized":"In Your good pleasure, cause Zion to prosper; build up the walls of Jerusalem.","sources":{"KJV":{"text":"Do good in thy good pleasure unto Zion: build thou the walls of Jerusalem."},"BSB":{"text":"In Your good pleasure, cause Zion to prosper; build up the walls of Jerusalem."}},"definableWords":["good","Zion","Jerusalem"],"peopleInVerse":[]},"19":{"text":"Then shalt thou be pleased with the sacrifices of righteousness, with burnt offering and whole burnt offering: then shall they offer bullocks upon thine altar.","ref":"Psalms 51:19","synthesized":"Then You will delight in righteous sacrifices, in whole burnt offerings; then bulls will be offered on Your altar.","sources":{"KJV":{"text":"Then shalt thou be pleased with the sacrifices of righteousness, with burnt offering and whole burnt offering: then shall they offer bullocks upon thine altar."},"BSB":{"text":"Then You will delight in righteous sacrifices, in whole burnt offerings; then bulls will be offered on Your altar."}},"definableWords":["righteous","altar"],"peopleInVerse":[]}}},"52":{"chapter":"52","title":"WHY BOASTEST THOU IN MISCHIEF?","verses":{"1":{"text":"Why boastest thou thyself in mischief, O mighty man? the goodness of God endureth continually.","ref":"Psalms 52:1","synthesized":"Why do you boast of evil, O mighty man? The loving devotion of God endures all day long.","sources":{"KJV":{"text":"Why boastest thou thyself in mischief, O mighty man? the goodness of God endureth continually."},"BSB":{"text":"Why do you boast of evil, O mighty man? The loving devotion of God endures all day long."}},"definableWords":["evil","mighty","man","God","day"],"peopleInVerse":[]},"2":{"text":"Thy tongue deviseth mischiefs; like a sharp razor, working deceitfully.","ref":"Psalms 52:2","synthesized":"Your tongue devises destruction like a sharpened razor, O worker of deceit.","sources":{"KJV":{"text":"Thy tongue deviseth mischiefs; like a sharp razor, working deceitfully."},"BSB":{"text":"Your tongue devises destruction like a sharpened razor, O worker of deceit."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Thou lovest evil more than good; and lying rather than to speak righteousness. Selah.","ref":"Psalms 52:3","synthesized":"You love evil more than good, falsehood more than speaking truth. Selah","sources":{"KJV":{"text":"Thou lovest evil more than good; and lying rather than to speak righteousness. Selah."},"BSB":{"text":"You love evil more than good, falsehood more than speaking truth. Selah"}},"definableWords":["love","evil","good","truth"],"peopleInVerse":[]},"4":{"text":"Thou lovest all devouring words, O thou deceitful tongue.","ref":"Psalms 52:4","synthesized":"You love every word that devours, O deceitful tongue.","sources":{"KJV":{"text":"Thou lovest all devouring words, O thou deceitful tongue."},"BSB":{"text":"You love every word that devours, O deceitful tongue."}},"definableWords":["love","word"],"peopleInVerse":[]},"5":{"text":"God shall likewise destroy thee for ever, he shall take thee away, and pluck thee out of thy dwelling place, and root thee out of the land of the living. Selah.","ref":"Psalms 52:5","synthesized":"Surely God will bring you down to everlasting ruin; He will snatch you up and tear you away from your tent; He will uproot you from the land of the living. Selah","sources":{"KJV":{"text":"God shall likewise destroy thee for ever, he shall take thee away, and pluck thee out of thy dwelling place, and root thee out of the land of the living. Selah."},"BSB":{"text":"Surely God will bring you down to everlasting ruin; He will snatch you up and tear you away from your tent; He will uproot you from the land of the living. Selah"}},"definableWords":["God","everlasting","land","living"],"peopleInVerse":[]},"6":{"text":"The righteous also shall see, and fear, and shall laugh at him:","ref":"Psalms 52:6","synthesized":"The righteous will see and fear; they will mock the evildoer, saying,","sources":{"KJV":{"text":"The righteous also shall see, and fear, and shall laugh at him:"},"BSB":{"text":"The righteous will see and fear; they will mock the evildoer, saying,"}},"definableWords":["righteous","see","fear"],"peopleInVerse":[]},"7":{"text":"Lo, this is the man that made not God his strength; but trusted in the abundance of his riches, and strengthened himself in his wickedness.","ref":"Psalms 52:7","synthesized":"“Look at the man who did not make God his refuge, but trusted in the abundance of his wealth and strengthened himself by destruction.”","sources":{"KJV":{"text":"Lo, this is the man that made not God his strength; but trusted in the abundance of his riches, and strengthened himself in his wickedness."},"BSB":{"text":"“Look at the man who did not make God his refuge, but trusted in the abundance of his wealth and strengthened himself by destruction.”"}},"definableWords":["man","make","God"],"peopleInVerse":[]},"8":{"text":"But I am like a green olive tree in the house of God: I trust in the mercy of God for ever and ever.","ref":"Psalms 52:8","synthesized":"But I am like an olive tree flourishing in the house of God; I trust in the loving devotion of God forever and ever.","sources":{"KJV":{"text":"But I am like a green olive tree in the house of God: I trust in the mercy of God for ever and ever."},"BSB":{"text":"But I am like an olive tree flourishing in the house of God; I trust in the loving devotion of God forever and ever."}},"definableWords":["tree","house","God","trust"],"peopleInVerse":[]},"9":{"text":"I will praise thee for ever, because thou hast done it: and I will wait on thy name; for it is good before thy saints.","ref":"Psalms 52:9","synthesized":"I will praise You forever, because You have done it. I will wait on Your name— for it is good— in the presence of Your saints.","sources":{"KJV":{"text":"I will praise thee for ever, because thou hast done it: and I will wait on thy name; for it is good before thy saints."},"BSB":{"text":"I will praise You forever, because You have done it. I will wait on Your name— for it is good— in the presence of Your saints."}},"definableWords":["praise","wait","name","good"],"peopleInVerse":[]}}},"53":{"chapter":"53","title":"THE FOOL HATH SAID (REPEATED)","verses":{"1":{"text":"The fool hath said in his heart, There is no God. Corrupt are they, and have done abominable iniquity: there is none that doeth good.","ref":"Psalms 53:1","synthesized":"The fool says in his heart, “There is no God.”   They are corrupt; their ways are vile. There is no one who does good.","sources":{"KJV":{"text":"The fool hath said in his heart, There is no God. Corrupt are they, and have done abominable iniquity: there is none that doeth good."},"BSB":{"text":"The fool says in his heart, “There is no God.”   They are corrupt; their ways are vile. There is no one who does good."}},"definableWords":["fool","heart","God","one","good"],"peopleInVerse":[]},"2":{"text":"God looked down from heaven upon the children of men, to see if there were any that did understand, that did seek God.","ref":"Psalms 53:2","synthesized":"God looks down from heaven upon the sons of men to see if any understand, if any seek God.","sources":{"KJV":{"text":"God looked down from heaven upon the children of men, to see if there were any that did understand, that did seek God."},"BSB":{"text":"God looks down from heaven upon the sons of men to see if any understand, if any seek God."}},"definableWords":["God","heaven","sons","men","see","seek"],"peopleInVerse":[]},"3":{"text":"Every one of them is gone back: they are altogether become filthy; there is none that doeth good, no, not one.","ref":"Psalms 53:3","synthesized":"All have turned away, they have together become corrupt; there is no one who does good, not even one.","sources":{"KJV":{"text":"Every one of them is gone back: they are altogether become filthy; there is none that doeth good, no, not one."},"BSB":{"text":"All have turned away, they have together become corrupt; there is no one who does good, not even one."}},"definableWords":["one","good"],"peopleInVerse":[]},"4":{"text":"Have the workers of iniquity no knowledge? who eat up my people as they eat bread: they have not called upon God.","ref":"Psalms 53:4","synthesized":"Will the workers of iniquity never learn?   They devour my people like bread; they refuse to call upon God.","sources":{"KJV":{"text":"Have the workers of iniquity no knowledge? who eat up my people as they eat bread: they have not called upon God."},"BSB":{"text":"Will the workers of iniquity never learn?   They devour my people like bread; they refuse to call upon God."}},"definableWords":["iniquity","people","God"],"peopleInVerse":[]},"5":{"text":"There were they in great fear, where no fear was: for God hath scattered the bones of him that encampeth against thee: thou hast put them to shame, because God hath despised them.","ref":"Psalms 53:5","synthesized":"There they are, overwhelmed with dread, where there was nothing to fear. For God has scattered the bones of those who besieged you. You put them to shame, for God has despised them.","sources":{"KJV":{"text":"There were they in great fear, where no fear was: for God hath scattered the bones of him that encampeth against thee: thou hast put them to shame, because God hath despised them."},"BSB":{"text":"There they are, overwhelmed with dread, where there was nothing to fear. For God has scattered the bones of those who besieged you. You put them to shame, for God has despised them."}},"definableWords":["fear","God","bones"],"peopleInVerse":[]},"6":{"text":"Oh that the salvation of Israel were come out of Zion! When God bringeth back the captivity of his people, Jacob shall rejoice, and Israel shall be glad.","ref":"Psalms 53:6","synthesized":"Oh, that the salvation of Israel would come from Zion!   When God restores His captive people, let Jacob rejoice, let Israel be glad!","sources":{"KJV":{"text":"Oh that the salvation of Israel were come out of Zion! When God bringeth back the captivity of his people, Jacob shall rejoice, and Israel shall be glad."},"BSB":{"text":"Oh, that the salvation of Israel would come from Zion!   When God restores His captive people, let Jacob rejoice, let Israel be glad!"}},"definableWords":["salvation","Israel","Zion","God","people","Jacob"],"peopleInVerse":["Jacob"]}}},"54":{"chapter":"54","title":"SAVE ME, O GOD, BY THY NAME","verses":{"1":{"text":"Save me, O God, by thy name, and judge me by thy strength.","ref":"Psalms 54:1","synthesized":"Save me, O God, by Your name, and vindicate me by Your might!","sources":{"KJV":{"text":"Save me, O God, by thy name, and judge me by thy strength."},"BSB":{"text":"Save me, O God, by Your name, and vindicate me by Your might!"}},"definableWords":["God","name"],"peopleInVerse":[]},"2":{"text":"Hear my prayer, O God; give ear to the words of my mouth.","ref":"Psalms 54:2","synthesized":"Hear my prayer, O God; listen to the words of my mouth.","sources":{"KJV":{"text":"Hear my prayer, O God; give ear to the words of my mouth."},"BSB":{"text":"Hear my prayer, O God; listen to the words of my mouth."}},"definableWords":["hear","prayer","God"],"peopleInVerse":[]},"3":{"text":"For strangers are risen up against me, and oppressors seek after my soul: they have not set God before them. Selah.","ref":"Psalms 54:3","synthesized":"For strangers rise up against me, and ruthless men seek my life— men with no regard for God. Selah","sources":{"KJV":{"text":"For strangers are risen up against me, and oppressors seek after my soul: they have not set God before them. Selah."},"BSB":{"text":"For strangers rise up against me, and ruthless men seek my life— men with no regard for God. Selah"}},"definableWords":["men","seek","life","God"],"peopleInVerse":[]},"4":{"text":"Behold, God is mine helper: the Lord is with them that uphold my soul.","ref":"Psalms 54:4","synthesized":"Surely God is my helper; the Lord is the sustainer of my soul.","sources":{"KJV":{"text":"Behold, God is mine helper: the Lord is with them that uphold my soul."},"BSB":{"text":"Surely God is my helper; the Lord is the sustainer of my soul."}},"definableWords":["God","helper","Lord","soul"],"peopleInVerse":[]},"5":{"text":"He shall reward evil unto mine enemies: cut them off in thy truth.","ref":"Psalms 54:5","synthesized":"He will reward my enemies with evil. In Your faithfulness, destroy them.","sources":{"KJV":{"text":"He shall reward evil unto mine enemies: cut them off in thy truth."},"BSB":{"text":"He will reward my enemies with evil. In Your faithfulness, destroy them."}},"definableWords":["evil"],"peopleInVerse":[]},"6":{"text":"I will freely sacrifice unto thee: I will praise thy name, O LORD; for it is good.","ref":"Psalms 54:6","synthesized":"Freely I will sacrifice to You; I will praise Your name, O LORD, for it is good.","sources":{"KJV":{"text":"I will freely sacrifice unto thee: I will praise thy name, O LORD; for it is good."},"BSB":{"text":"Freely I will sacrifice to You; I will praise Your name, O LORD, for it is good."}},"definableWords":["sacrifice","praise","name","LORD","good"],"peopleInVerse":[]},"7":{"text":"For he hath delivered me out of all trouble: and mine eye hath seen his desire upon mine enemies.","ref":"Psalms 54:7","synthesized":"For He has delivered me from every trouble, and my eyes have stared down my foes.","sources":{"KJV":{"text":"For he hath delivered me out of all trouble: and mine eye hath seen his desire upon mine enemies."},"BSB":{"text":"For He has delivered me from every trouble, and my eyes have stared down my foes."}},"definableWords":[],"peopleInVerse":[]}}},"55":{"chapter":"55","title":"CAST THY BURDEN UPON THE LORD","verses":{"1":{"text":"Give ear to my prayer, O God; and hide not thyself from my supplication.","ref":"Psalms 55:1","synthesized":"Listen to my prayer, O God, and do not ignore my plea.","sources":{"KJV":{"text":"Give ear to my prayer, O God; and hide not thyself from my supplication."},"BSB":{"text":"Listen to my prayer, O God, and do not ignore my plea."}},"definableWords":["prayer","God"],"peopleInVerse":[]},"2":{"text":"Attend unto me, and hear me: I mourn in my complaint, and make a noise;","ref":"Psalms 55:2","synthesized":"Attend to me and answer me. I am restless in my complaint, and distraught","sources":{"KJV":{"text":"Attend unto me, and hear me: I mourn in my complaint, and make a noise;"},"BSB":{"text":"Attend to me and answer me. I am restless in my complaint, and distraught"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Because of the voice of the enemy, because of the oppression of the wicked: for they cast iniquity upon me, and in wrath they hate me.","ref":"Psalms 55:3","synthesized":"at the voice of the enemy, at the pressure of the wicked. For they release disaster upon me and revile me in their anger.","sources":{"KJV":{"text":"Because of the voice of the enemy, because of the oppression of the wicked: for they cast iniquity upon me, and in wrath they hate me."},"BSB":{"text":"at the voice of the enemy, at the pressure of the wicked. For they release disaster upon me and revile me in their anger."}},"definableWords":["voice","anger"],"peopleInVerse":[]},"4":{"text":"My heart is sore pained within me: and the terrors of death are fallen upon me.","ref":"Psalms 55:4","synthesized":"My heart murmurs within me, and the terrors of death assail me.","sources":{"KJV":{"text":"My heart is sore pained within me: and the terrors of death are fallen upon me."},"BSB":{"text":"My heart murmurs within me, and the terrors of death assail me."}},"definableWords":["heart","death"],"peopleInVerse":[]},"5":{"text":"Fearfulness and trembling are come upon me, and horror hath overwhelmed me.","ref":"Psalms 55:5","synthesized":"Fear and trembling grip me, and horror has overwhelmed me.","sources":{"KJV":{"text":"Fearfulness and trembling are come upon me, and horror hath overwhelmed me."},"BSB":{"text":"Fear and trembling grip me, and horror has overwhelmed me."}},"definableWords":["fear"],"peopleInVerse":[]},"6":{"text":"And I said, Oh that I had wings like a dove! for then would I fly away, and be at rest.","ref":"Psalms 55:6","synthesized":"I said, “Oh, that I had wings like a dove! I would fly away and find rest.","sources":{"KJV":{"text":"And I said, Oh that I had wings like a dove! for then would I fly away, and be at rest."},"BSB":{"text":"I said, “Oh, that I had wings like a dove! I would fly away and find rest."}},"definableWords":["rest"],"peopleInVerse":[]},"7":{"text":"Lo, then would I wander far off, and remain in the wilderness. Selah.","ref":"Psalms 55:7","synthesized":"How far away I would flee! In the wilderness I would remain. Selah","sources":{"KJV":{"text":"Lo, then would I wander far off, and remain in the wilderness. Selah."},"BSB":{"text":"How far away I would flee! In the wilderness I would remain. Selah"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"I would hasten my escape from the windy storm and tempest.","ref":"Psalms 55:8","synthesized":"I would hurry to my shelter, far from this raging tempest.”","sources":{"KJV":{"text":"I would hasten my escape from the windy storm and tempest."},"BSB":{"text":"I would hurry to my shelter, far from this raging tempest.”"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Destroy, O Lord, and divide their tongues: for I have seen violence and strife in the city.","ref":"Psalms 55:9","synthesized":"O Lord, confuse and confound their speech, for I see violence and strife in the city.","sources":{"KJV":{"text":"Destroy, O Lord, and divide their tongues: for I have seen violence and strife in the city."},"BSB":{"text":"O Lord, confuse and confound their speech, for I see violence and strife in the city."}},"definableWords":["Lord","see"],"peopleInVerse":[]},"10":{"text":"Day and night they go about it upon the walls thereof: mischief also and sorrow are in the midst of it.","ref":"Psalms 55:10","synthesized":"Day and night they encircle the walls, while malice and trouble lie within.","sources":{"KJV":{"text":"Day and night they go about it upon the walls thereof: mischief also and sorrow are in the midst of it."},"BSB":{"text":"Day and night they encircle the walls, while malice and trouble lie within."}},"definableWords":["day","night"],"peopleInVerse":[]},"11":{"text":"Wickedness is in the midst thereof: deceit and guile depart not from her streets.","ref":"Psalms 55:11","synthesized":"Destruction is within; oppression and deceit never leave the streets.","sources":{"KJV":{"text":"Wickedness is in the midst thereof: deceit and guile depart not from her streets."},"BSB":{"text":"Destruction is within; oppression and deceit never leave the streets."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For it was not an enemy that reproached me; then I could have borne it: neither was it he that hated me that did magnify himself against me; then I would have hid myself from him:","ref":"Psalms 55:12","synthesized":"For it is not an enemy who insults me; that I could endure. It is not a foe who rises against me; from him I could hide.","sources":{"KJV":{"text":"For it was not an enemy that reproached me; then I could have borne it: neither was it he that hated me that did magnify himself against me; then I would have hid myself from him:"},"BSB":{"text":"For it is not an enemy who insults me; that I could endure. It is not a foe who rises against me; from him I could hide."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"But it was thou, a man mine equal, my guide, and mine acquaintance.","ref":"Psalms 55:13","synthesized":"But it is you, a man like myself, my companion and close friend.","sources":{"KJV":{"text":"But it was thou, a man mine equal, my guide, and mine acquaintance."},"BSB":{"text":"But it is you, a man like myself, my companion and close friend."}},"definableWords":["man"],"peopleInVerse":[]},"14":{"text":"We took sweet counsel together, and walked unto the house of God in company.","ref":"Psalms 55:14","synthesized":"We shared sweet fellowship together; we walked with the crowd into the house of God.","sources":{"KJV":{"text":"We took sweet counsel together, and walked unto the house of God in company."},"BSB":{"text":"We shared sweet fellowship together; we walked with the crowd into the house of God."}},"definableWords":["walked","house","God"],"peopleInVerse":[]},"15":{"text":"Let death seize upon them, and let them go down quick into hell: for wickedness is in their dwellings, and among them.","ref":"Psalms 55:15","synthesized":"Let death seize them by surprise; let them go down to Sheol alive, for evil is with them in their homes.","sources":{"KJV":{"text":"Let death seize upon them, and let them go down quick into hell: for wickedness is in their dwellings, and among them."},"BSB":{"text":"Let death seize them by surprise; let them go down to Sheol alive, for evil is with them in their homes."}},"definableWords":["death","evil"],"peopleInVerse":[]},"16":{"text":"As for me, I will call upon God; and the LORD shall save me.","ref":"Psalms 55:16","synthesized":"But I call to God, and the LORD saves me.","sources":{"KJV":{"text":"As for me, I will call upon God; and the LORD shall save me."},"BSB":{"text":"But I call to God, and the LORD saves me."}},"definableWords":["God","LORD"],"peopleInVerse":[]},"17":{"text":"Evening, and morning, and at noon, will I pray, and cry aloud: and he shall hear my voice.","ref":"Psalms 55:17","synthesized":"Morning, noon, and night, I cry out in distress, and He hears my voice.","sources":{"KJV":{"text":"Evening, and morning, and at noon, will I pray, and cry aloud: and he shall hear my voice."},"BSB":{"text":"Morning, noon, and night, I cry out in distress, and He hears my voice."}},"definableWords":["night","voice"],"peopleInVerse":[]},"18":{"text":"He hath delivered my soul in peace from the battle that was against me: for there were many with me.","ref":"Psalms 55:18","synthesized":"He redeems my soul in peace from the battle waged against me, even though many oppose me.","sources":{"KJV":{"text":"He hath delivered my soul in peace from the battle that was against me: for there were many with me."},"BSB":{"text":"He redeems my soul in peace from the battle waged against me, even though many oppose me."}},"definableWords":["soul","peace"],"peopleInVerse":[]},"19":{"text":"God shall hear, and afflict them, even he that abideth of old. Selah. Because they have no changes, therefore they fear not God.","ref":"Psalms 55:19","synthesized":"God will hear and humiliate them— the One enthroned for the ages— Selah because they do not change and they have no fear of God.","sources":{"KJV":{"text":"God shall hear, and afflict them, even he that abideth of old. Selah. Because they have no changes, therefore they fear not God."},"BSB":{"text":"God will hear and humiliate them— the One enthroned for the ages— Selah because they do not change and they have no fear of God."}},"definableWords":["God","hear","one","fear"],"peopleInVerse":[]},"20":{"text":"He hath put forth his hands against such as be at peace with him: he hath broken his covenant.","ref":"Psalms 55:20","synthesized":"My companion attacks his friends; he violates his covenant.","sources":{"KJV":{"text":"He hath put forth his hands against such as be at peace with him: he hath broken his covenant."},"BSB":{"text":"My companion attacks his friends; he violates his covenant."}},"definableWords":["covenant"],"peopleInVerse":[]},"21":{"text":"The words of his mouth were smoother than butter, but war was in his heart: his words were softer than oil, yet were they drawn swords.","ref":"Psalms 55:21","synthesized":"His speech is smooth as butter, but war is in his heart. His words are softer than oil, yet they are swords unsheathed.","sources":{"KJV":{"text":"The words of his mouth were smoother than butter, but war was in his heart: his words were softer than oil, yet were they drawn swords."},"BSB":{"text":"His speech is smooth as butter, but war is in his heart. His words are softer than oil, yet they are swords unsheathed."}},"definableWords":["heart"],"peopleInVerse":[]},"22":{"text":"Cast thy burden upon the LORD, and he shall sustain thee: he shall never suffer the righteous to be moved.","ref":"Psalms 55:22","synthesized":"Cast your burden upon the LORD and He will sustain you; He will never let the righteous be shaken.","sources":{"KJV":{"text":"Cast thy burden upon the LORD, and he shall sustain thee: he shall never suffer the righteous to be moved."},"BSB":{"text":"Cast your burden upon the LORD and He will sustain you; He will never let the righteous be shaken."}},"definableWords":["LORD","righteous"],"peopleInVerse":[]},"23":{"text":"But thou, O God, shalt bring them down into the pit of destruction: bloody and deceitful men shall not live out half their days; but I will trust in thee.","ref":"Psalms 55:23","synthesized":"But You, O God, will bring them down to the Pit of destruction; men of bloodshed and deceit will not live out half their days.   But I will trust in You.","sources":{"KJV":{"text":"But thou, O God, shalt bring them down into the pit of destruction: bloody and deceitful men shall not live out half their days; but I will trust in thee."},"BSB":{"text":"But You, O God, will bring them down to the Pit of destruction; men of bloodshed and deceit will not live out half their days.   But I will trust in You."}},"definableWords":["God","men","live","days","trust"],"peopleInVerse":[]}}},"56":{"chapter":"56","title":"BE MERCIFUL UNTO ME, O GOD","verses":{"1":{"text":"Be merciful unto me, O God: for man would swallow me up; he fighting daily oppresseth me.","ref":"Psalms 56:1","synthesized":"Be merciful to me, O God, for men are hounding me; all day they press their attack.","sources":{"KJV":{"text":"Be merciful unto me, O God: for man would swallow me up; he fighting daily oppresseth me."},"BSB":{"text":"Be merciful to me, O God, for men are hounding me; all day they press their attack."}},"definableWords":["God","men","day"],"peopleInVerse":[]},"2":{"text":"Mine enemies would daily swallow me up: for they be many that fight against me, O thou most High.","ref":"Psalms 56:2","synthesized":"My enemies pursue me all day long, for many proudly assail me.","sources":{"KJV":{"text":"Mine enemies would daily swallow me up: for they be many that fight against me, O thou most High."},"BSB":{"text":"My enemies pursue me all day long, for many proudly assail me."}},"definableWords":["day"],"peopleInVerse":[]},"3":{"text":"What time I am afraid, I will trust in thee.","ref":"Psalms 56:3","synthesized":"When I am afraid, I put my trust in You.","sources":{"KJV":{"text":"What time I am afraid, I will trust in thee."},"BSB":{"text":"When I am afraid, I put my trust in You."}},"definableWords":["trust"],"peopleInVerse":[]},"4":{"text":"In God I will praise his word, in God I have put my trust; I will not fear what flesh can do unto me.","ref":"Psalms 56:4","synthesized":"In God, whose word I praise— in God I trust. I will not be afraid. What can man do to me?","sources":{"KJV":{"text":"In God I will praise his word, in God I have put my trust; I will not fear what flesh can do unto me."},"BSB":{"text":"In God, whose word I praise— in God I trust. I will not be afraid. What can man do to me?"}},"definableWords":["God","word","praise","trust","man"],"peopleInVerse":[]},"5":{"text":"Every day they wrest my words: all their thoughts are against me for evil.","ref":"Psalms 56:5","synthesized":"All day long they twist my words; all their thoughts are on my demise.","sources":{"KJV":{"text":"Every day they wrest my words: all their thoughts are against me for evil."},"BSB":{"text":"All day long they twist my words; all their thoughts are on my demise."}},"definableWords":["day"],"peopleInVerse":[]},"6":{"text":"They gather themselves together, they hide themselves, they mark my steps, when they wait for my soul.","ref":"Psalms 56:6","synthesized":"They conspire, they lurk, they watch my steps while they wait to take my life.","sources":{"KJV":{"text":"They gather themselves together, they hide themselves, they mark my steps, when they wait for my soul."},"BSB":{"text":"They conspire, they lurk, they watch my steps while they wait to take my life."}},"definableWords":["wait","life"],"peopleInVerse":[]},"7":{"text":"Shall they escape by iniquity? in thine anger cast down the people, O God.","ref":"Psalms 56:7","synthesized":"In spite of such sin, will they escape? In Your anger, O God, cast down the nations.","sources":{"KJV":{"text":"Shall they escape by iniquity? in thine anger cast down the people, O God."},"BSB":{"text":"In spite of such sin, will they escape? In Your anger, O God, cast down the nations."}},"definableWords":["sin","anger","God","nations"],"peopleInVerse":[]},"8":{"text":"Thou tellest my wanderings: put thou my tears into thy bottle: are they not in thy book?","ref":"Psalms 56:8","synthesized":"You have taken account of my wanderings. Put my tears in Your bottle— are they not in Your book?","sources":{"KJV":{"text":"Thou tellest my wanderings: put thou my tears into thy bottle: are they not in thy book?"},"BSB":{"text":"You have taken account of my wanderings. Put my tears in Your bottle— are they not in Your book?"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"When I cry unto thee, then shall mine enemies turn back: this I know; for God is for me.","ref":"Psalms 56:9","synthesized":"Then my enemies will retreat on the day I cry for help. By this I will know that God is on my side.","sources":{"KJV":{"text":"When I cry unto thee, then shall mine enemies turn back: this I know; for God is for me."},"BSB":{"text":"Then my enemies will retreat on the day I cry for help. By this I will know that God is on my side."}},"definableWords":["day","God"],"peopleInVerse":[]},"10":{"text":"In God will I praise his word: in the LORD will I praise his word.","ref":"Psalms 56:10","synthesized":"In God, whose word I praise, in the LORD, whose word I praise,","sources":{"KJV":{"text":"In God will I praise his word: in the LORD will I praise his word."},"BSB":{"text":"In God, whose word I praise, in the LORD, whose word I praise,"}},"definableWords":["God","word","praise","LORD"],"peopleInVerse":[]},"11":{"text":"In God have I put my trust: I will not be afraid what man can do unto me.","ref":"Psalms 56:11","synthesized":"in God I trust; I will not be afraid. What can man do to me?","sources":{"KJV":{"text":"In God have I put my trust: I will not be afraid what man can do unto me."},"BSB":{"text":"in God I trust; I will not be afraid. What can man do to me?"}},"definableWords":["God","trust","man"],"peopleInVerse":[]},"12":{"text":"Thy vows are upon me, O God: I will render praises unto thee.","ref":"Psalms 56:12","synthesized":"Your vows are upon me, O God; I will render thank offerings to You.","sources":{"KJV":{"text":"Thy vows are upon me, O God: I will render praises unto thee."},"BSB":{"text":"Your vows are upon me, O God; I will render thank offerings to You."}},"definableWords":["God"],"peopleInVerse":[]},"13":{"text":"For thou hast delivered my soul from death: wilt not thou deliver my feet from falling, that I may walk before God in the light of the living?","ref":"Psalms 56:13","synthesized":"For You have delivered my soul from death, and my feet from stumbling, that I may walk before God in the light of life.","sources":{"KJV":{"text":"For thou hast delivered my soul from death: wilt not thou deliver my feet from falling, that I may walk before God in the light of the living?"},"BSB":{"text":"For You have delivered my soul from death, and my feet from stumbling, that I may walk before God in the light of life."}},"definableWords":["soul","death","walk","God","light","life"],"peopleInVerse":[]}}},"57":{"chapter":"57","title":"MY HEART IS FIXED","verses":{"1":{"text":"Be merciful unto me, O God, be merciful unto me: for my soul trusteth in thee: yea, in the shadow of thy wings will I make my refuge, until these calamities be overpast.","ref":"Psalms 57:1","synthesized":"Have mercy on me, O God, have mercy, for in You my soul takes refuge. In the shadow of Your wings I will take shelter until the danger has passed.","sources":{"KJV":{"text":"Be merciful unto me, O God, be merciful unto me: for my soul trusteth in thee: yea, in the shadow of thy wings will I make my refuge, until these calamities be overpast."},"BSB":{"text":"Have mercy on me, O God, have mercy, for in You my soul takes refuge. In the shadow of Your wings I will take shelter until the danger has passed."}},"definableWords":["mercy","God","soul"],"peopleInVerse":[]},"2":{"text":"I will cry unto God most high; unto God that performeth all things for me.","ref":"Psalms 57:2","synthesized":"I cry out to God Most High, to God who fulfills His purpose for me.","sources":{"KJV":{"text":"I will cry unto God most high; unto God that performeth all things for me."},"BSB":{"text":"I cry out to God Most High, to God who fulfills His purpose for me."}},"definableWords":["God"],"peopleInVerse":[]},"3":{"text":"He shall send from heaven, and save me from the reproach of him that would swallow me up. Selah. God shall send forth his mercy and his truth.","ref":"Psalms 57:3","synthesized":"He reaches down from heaven and saves me; He rebukes those who trample me. Selah God sends forth His loving devotion and His truth.","sources":{"KJV":{"text":"He shall send from heaven, and save me from the reproach of him that would swallow me up. Selah. God shall send forth his mercy and his truth."},"BSB":{"text":"He reaches down from heaven and saves me; He rebukes those who trample me. Selah God sends forth His loving devotion and His truth."}},"definableWords":["heaven","God","truth"],"peopleInVerse":[]},"4":{"text":"My soul is among lions: and I lie even among them that are set on fire, even the sons of men, whose teeth are spears and arrows, and their tongue a sharp sword.","ref":"Psalms 57:4","synthesized":"My soul is among the lions; I lie down with ravenous beasts— with men whose teeth are spears and arrows, whose tongues are sharp swords.","sources":{"KJV":{"text":"My soul is among lions: and I lie even among them that are set on fire, even the sons of men, whose teeth are spears and arrows, and their tongue a sharp sword."},"BSB":{"text":"My soul is among the lions; I lie down with ravenous beasts— with men whose teeth are spears and arrows, whose tongues are sharp swords."}},"definableWords":["soul","men"],"peopleInVerse":[]},"5":{"text":"Be thou exalted, O God, above the heavens; let thy glory be above all the earth.","ref":"Psalms 57:5","synthesized":"Be exalted, O God, above the heavens; may Your glory cover all the earth.","sources":{"KJV":{"text":"Be thou exalted, O God, above the heavens; let thy glory be above all the earth."},"BSB":{"text":"Be exalted, O God, above the heavens; may Your glory cover all the earth."}},"definableWords":["God","heavens","glory","earth"],"peopleInVerse":[]},"6":{"text":"They have prepared a net for my steps; my soul is bowed down: they have digged a pit before me, into the midst whereof they are fallen themselves. Selah.","ref":"Psalms 57:6","synthesized":"They spread a net for my feet; my soul was despondent. They dug a pit before me, but they themselves have fallen into it! Selah","sources":{"KJV":{"text":"They have prepared a net for my steps; my soul is bowed down: they have digged a pit before me, into the midst whereof they are fallen themselves. Selah."},"BSB":{"text":"They spread a net for my feet; my soul was despondent. They dug a pit before me, but they themselves have fallen into it! Selah"}},"definableWords":["soul"],"peopleInVerse":[]},"7":{"text":"My heart is fixed, O God, my heart is fixed: I will sing and give praise.","ref":"Psalms 57:7","synthesized":"My heart is steadfast, O God, my heart is steadfast. I will sing and make music.","sources":{"KJV":{"text":"My heart is fixed, O God, my heart is fixed: I will sing and give praise."},"BSB":{"text":"My heart is steadfast, O God, my heart is steadfast. I will sing and make music."}},"definableWords":["heart","God","make"],"peopleInVerse":[]},"8":{"text":"Awake up, my glory; awake, psaltery and harp: I myself will awake early.","ref":"Psalms 57:8","synthesized":"Awake, my glory! Awake, O harp and lyre! I will awaken the dawn.","sources":{"KJV":{"text":"Awake up, my glory; awake, psaltery and harp: I myself will awake early."},"BSB":{"text":"Awake, my glory! Awake, O harp and lyre! I will awaken the dawn."}},"definableWords":["glory"],"peopleInVerse":[]},"9":{"text":"I will praise thee, O Lord, among the people: I will sing unto thee among the nations.","ref":"Psalms 57:9","synthesized":"I will praise You, O Lord, among the nations; I will sing Your praises among the peoples.","sources":{"KJV":{"text":"I will praise thee, O Lord, among the people: I will sing unto thee among the nations."},"BSB":{"text":"I will praise You, O Lord, among the nations; I will sing Your praises among the peoples."}},"definableWords":["praise","Lord","nations"],"peopleInVerse":[]},"10":{"text":"For thy mercy is great unto the heavens, and thy truth unto the clouds.","ref":"Psalms 57:10","synthesized":"For Your loving devotion reaches to the heavens, and Your faithfulness to the clouds.","sources":{"KJV":{"text":"For thy mercy is great unto the heavens, and thy truth unto the clouds."},"BSB":{"text":"For Your loving devotion reaches to the heavens, and Your faithfulness to the clouds."}},"definableWords":["heavens"],"peopleInVerse":[]},"11":{"text":"Be thou exalted, O God, above the heavens: let thy glory be above all the earth.","ref":"Psalms 57:11","synthesized":"Be exalted, O God, above the heavens; may Your glory cover all the earth.","sources":{"KJV":{"text":"Be thou exalted, O God, above the heavens: let thy glory be above all the earth."},"BSB":{"text":"Be exalted, O God, above the heavens; may Your glory cover all the earth."}},"definableWords":["God","heavens","glory","earth"],"peopleInVerse":[]}}},"58":{"chapter":"58","title":"JUDGES OF THE EARTH","verses":{"1":{"text":"Do ye indeed speak righteousness, O congregation? do ye judge uprightly, O ye sons of men?","ref":"Psalms 58:1","synthesized":"Do you indeed speak justly, O rulers? Do you judge uprightly, O sons of men?","sources":{"KJV":{"text":"Do ye indeed speak righteousness, O congregation? do ye judge uprightly, O ye sons of men?"},"BSB":{"text":"Do you indeed speak justly, O rulers? Do you judge uprightly, O sons of men?"}},"definableWords":["sons","men"],"peopleInVerse":[]},"2":{"text":"Yea, in heart ye work wickedness; ye weigh the violence of your hands in the earth.","ref":"Psalms 58:2","synthesized":"No, in your hearts you devise injustice; with your hands you mete out violence on the earth.","sources":{"KJV":{"text":"Yea, in heart ye work wickedness; ye weigh the violence of your hands in the earth."},"BSB":{"text":"No, in your hearts you devise injustice; with your hands you mete out violence on the earth."}},"definableWords":["earth"],"peopleInVerse":[]},"3":{"text":"The wicked are estranged from the womb: they go astray as soon as they be born, speaking lies.","ref":"Psalms 58:3","synthesized":"The wicked are estranged from the womb; the liars go astray from birth.","sources":{"KJV":{"text":"The wicked are estranged from the womb: they go astray as soon as they be born, speaking lies."},"BSB":{"text":"The wicked are estranged from the womb; the liars go astray from birth."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Their poison is like the poison of a serpent: they are like the deaf adder that stoppeth her ear;","ref":"Psalms 58:4","synthesized":"Their venom is like the venom of a snake, like a cobra that shuts its ears,","sources":{"KJV":{"text":"Their poison is like the poison of a serpent: they are like the deaf adder that stoppeth her ear;"},"BSB":{"text":"Their venom is like the venom of a snake, like a cobra that shuts its ears,"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Which will not hearken to the voice of charmers, charming never so wisely.","ref":"Psalms 58:5","synthesized":"refusing to hear the tune of the charmer who skillfully weaves his spell.","sources":{"KJV":{"text":"Which will not hearken to the voice of charmers, charming never so wisely."},"BSB":{"text":"refusing to hear the tune of the charmer who skillfully weaves his spell."}},"definableWords":["hear"],"peopleInVerse":[]},"6":{"text":"Break their teeth, O God, in their mouth: break out the great teeth of the young lions, O LORD.","ref":"Psalms 58:6","synthesized":"O God, shatter their teeth in their mouths; O LORD, tear out the fangs of the lions.","sources":{"KJV":{"text":"Break their teeth, O God, in their mouth: break out the great teeth of the young lions, O LORD."},"BSB":{"text":"O God, shatter their teeth in their mouths; O LORD, tear out the fangs of the lions."}},"definableWords":["God","LORD"],"peopleInVerse":[]},"7":{"text":"Let them melt away as waters which run continually: when he bendeth his bow to shoot his arrows, let them be as cut in pieces.","ref":"Psalms 58:7","synthesized":"May they vanish like water that runs off; when they draw the bow, may their arrows be blunted.","sources":{"KJV":{"text":"Let them melt away as waters which run continually: when he bendeth his bow to shoot his arrows, let them be as cut in pieces."},"BSB":{"text":"May they vanish like water that runs off; when they draw the bow, may their arrows be blunted."}},"definableWords":["water"],"peopleInVerse":[]},"8":{"text":"As a snail which melteth, let every one of them pass away: like the untimely birth of a woman, that they may not see the sun.","ref":"Psalms 58:8","synthesized":"Like a slug that dissolves in its slime, like a woman’s stillborn child, may they never see the sun.","sources":{"KJV":{"text":"As a snail which melteth, let every one of them pass away: like the untimely birth of a woman, that they may not see the sun."},"BSB":{"text":"Like a slug that dissolves in its slime, like a woman’s stillborn child, may they never see the sun."}},"definableWords":["woman","see"],"peopleInVerse":[]},"9":{"text":"Before your pots can feel the thorns, he shall take them away as with a whirlwind, both living, and in his wrath.","ref":"Psalms 58:9","synthesized":"Before your pots can feel the burning thorns— whether green or dry— He will sweep them away.","sources":{"KJV":{"text":"Before your pots can feel the thorns, he shall take them away as with a whirlwind, both living, and in his wrath."},"BSB":{"text":"Before your pots can feel the burning thorns— whether green or dry— He will sweep them away."}},"definableWords":["or"],"peopleInVerse":[]},"10":{"text":"The righteous shall rejoice when he seeth the vengeance: he shall wash his feet in the blood of the wicked.","ref":"Psalms 58:10","synthesized":"The righteous will rejoice when they see they are avenged; they will wash their feet in the blood of the wicked.","sources":{"KJV":{"text":"The righteous shall rejoice when he seeth the vengeance: he shall wash his feet in the blood of the wicked."},"BSB":{"text":"The righteous will rejoice when they see they are avenged; they will wash their feet in the blood of the wicked."}},"definableWords":["righteous","see","blood"],"peopleInVerse":[]},"11":{"text":"So that a man shall say, Verily there is a reward for the righteous: verily he is a God that judgeth in the earth.","ref":"Psalms 58:11","synthesized":"Then men will say, “There is surely a reward for the righteous! There is surely a God who judges the earth!”","sources":{"KJV":{"text":"So that a man shall say, Verily there is a reward for the righteous: verily he is a God that judgeth in the earth."},"BSB":{"text":"Then men will say, “There is surely a reward for the righteous! There is surely a God who judges the earth!”"}},"definableWords":["men","righteous","God","earth"],"peopleInVerse":[]}}},"59":{"chapter":"59","title":"DELIVER ME FROM MINE ENEMIES","verses":{"1":{"text":"Deliver me from mine enemies, O my God: defend me from them that rise up against me.","ref":"Psalms 59:1","synthesized":"Deliver me from my enemies, O my God; protect me from those who rise against me.","sources":{"KJV":{"text":"Deliver me from mine enemies, O my God: defend me from them that rise up against me."},"BSB":{"text":"Deliver me from my enemies, O my God; protect me from those who rise against me."}},"definableWords":["deliver","God"],"peopleInVerse":[]},"2":{"text":"Deliver me from the workers of iniquity, and save me from bloody men.","ref":"Psalms 59:2","synthesized":"Deliver me from workers of iniquity, and save me from men of bloodshed.","sources":{"KJV":{"text":"Deliver me from the workers of iniquity, and save me from bloody men."},"BSB":{"text":"Deliver me from workers of iniquity, and save me from men of bloodshed."}},"definableWords":["deliver","iniquity","men"],"peopleInVerse":[]},"3":{"text":"For, lo, they lie in wait for my soul: the mighty are gathered against me; not for my transgression, nor for my sin, O LORD.","ref":"Psalms 59:3","synthesized":"See how they lie in wait for me. Fierce men conspire against me for no transgression or sin of my own, O LORD.","sources":{"KJV":{"text":"For, lo, they lie in wait for my soul: the mighty are gathered against me; not for my transgression, nor for my sin, O LORD."},"BSB":{"text":"See how they lie in wait for me. Fierce men conspire against me for no transgression or sin of my own, O LORD."}},"definableWords":["see","wait","men","transgression","or","sin","LORD"],"peopleInVerse":[]},"4":{"text":"They run and prepare themselves without my fault: awake to help me, and behold.","ref":"Psalms 59:4","synthesized":"For no fault of my own, they move swiftly to attack me. Arise to help me, and take notice.","sources":{"KJV":{"text":"They run and prepare themselves without my fault: awake to help me, and behold."},"BSB":{"text":"For no fault of my own, they move swiftly to attack me. Arise to help me, and take notice."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Thou therefore, O LORD God of hosts, the God of Israel, awake to visit all the heathen: be not merciful to any wicked transgressors. Selah.","ref":"Psalms 59:5","synthesized":"O LORD God of Hosts, the God of Israel, rouse Yourself to punish all the nations; show no mercy to the wicked traitors. Selah","sources":{"KJV":{"text":"Thou therefore, O LORD God of hosts, the God of Israel, awake to visit all the heathen: be not merciful to any wicked transgressors. Selah."},"BSB":{"text":"O LORD God of Hosts, the God of Israel, rouse Yourself to punish all the nations; show no mercy to the wicked traitors. Selah"}},"definableWords":["LORD","God","Israel","nations","mercy"],"peopleInVerse":[]},"6":{"text":"They return at evening: they make a noise like a dog, and go round about the city.","ref":"Psalms 59:6","synthesized":"They return in the evening, snarling like dogs and prowling around the city.","sources":{"KJV":{"text":"They return at evening: they make a noise like a dog, and go round about the city."},"BSB":{"text":"They return in the evening, snarling like dogs and prowling around the city."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Behold, they belch out with their mouth: swords are in their lips: for who, say they, doth hear?","ref":"Psalms 59:7","synthesized":"See what they spew from their mouths— sharp words from their lips: “For who can hear us?”","sources":{"KJV":{"text":"Behold, they belch out with their mouth: swords are in their lips: for who, say they, doth hear?"},"BSB":{"text":"See what they spew from their mouths— sharp words from their lips: “For who can hear us?”"}},"definableWords":["see","hear"],"peopleInVerse":[]},"8":{"text":"But thou, O LORD, shalt laugh at them; thou shalt have all the heathen in derision.","ref":"Psalms 59:8","synthesized":"But You, O LORD, laugh at them; You scoff at all the nations.","sources":{"KJV":{"text":"But thou, O LORD, shalt laugh at them; thou shalt have all the heathen in derision."},"BSB":{"text":"But You, O LORD, laugh at them; You scoff at all the nations."}},"definableWords":["LORD","nations"],"peopleInVerse":[]},"9":{"text":"Because of his strength will I wait upon thee: for God is my defence.","ref":"Psalms 59:9","synthesized":"I will keep watch for You, O my strength, because You, O God, are my fortress.","sources":{"KJV":{"text":"Because of his strength will I wait upon thee: for God is my defence."},"BSB":{"text":"I will keep watch for You, O my strength, because You, O God, are my fortress."}},"definableWords":["keep","God"],"peopleInVerse":[]},"10":{"text":"The God of my mercy shall prevent me: God shall let me see my desire upon mine enemies.","ref":"Psalms 59:10","synthesized":"My God of loving devotion will come to meet me; God will let me stare down my foes.","sources":{"KJV":{"text":"The God of my mercy shall prevent me: God shall let me see my desire upon mine enemies."},"BSB":{"text":"My God of loving devotion will come to meet me; God will let me stare down my foes."}},"definableWords":["God"],"peopleInVerse":[]},"11":{"text":"Slay them not, lest my people forget: scatter them by thy power; and bring them down, O Lord our shield.","ref":"Psalms 59:11","synthesized":"Do not kill them, or my people will forget. Scatter them by Your power, and bring them down, O Lord, our shield.","sources":{"KJV":{"text":"Slay them not, lest my people forget: scatter them by thy power; and bring them down, O Lord our shield."},"BSB":{"text":"Do not kill them, or my people will forget. Scatter them by Your power, and bring them down, O Lord, our shield."}},"definableWords":["or","people","Lord"],"peopleInVerse":[]},"12":{"text":"For the sin of their mouth and the words of their lips let them even be taken in their pride: and for cursing and lying which they speak.","ref":"Psalms 59:12","synthesized":"By the sins of their mouths and the words of their lips, let them be trapped in their pride, in the curses and lies they utter.","sources":{"KJV":{"text":"For the sin of their mouth and the words of their lips let them even be taken in their pride: and for cursing and lying which they speak."},"BSB":{"text":"By the sins of their mouths and the words of their lips, let them be trapped in their pride, in the curses and lies they utter."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Consume them in wrath, consume them, that they may not be: and let them know that God ruleth in Jacob unto the ends of the earth. Selah.","ref":"Psalms 59:13","synthesized":"Consume them in wrath; consume them till they are no more, so it may be known to the ends of the earth that God rules over Jacob. Selah","sources":{"KJV":{"text":"Consume them in wrath, consume them, that they may not be: and let them know that God ruleth in Jacob unto the ends of the earth. Selah."},"BSB":{"text":"Consume them in wrath; consume them till they are no more, so it may be known to the ends of the earth that God rules over Jacob. Selah"}},"definableWords":["wrath","till","earth","God","Jacob"],"peopleInVerse":["Jacob"]},"14":{"text":"And at evening let them return; and let them make a noise like a dog, and go round about the city.","ref":"Psalms 59:14","synthesized":"They return in the evening, snarling like dogs and prowling around the city.","sources":{"KJV":{"text":"And at evening let them return; and let them make a noise like a dog, and go round about the city."},"BSB":{"text":"They return in the evening, snarling like dogs and prowling around the city."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Let them wander up and down for meat, and grudge if they be not satisfied.","ref":"Psalms 59:15","synthesized":"They scavenge for food, and growl if they are not satisfied.","sources":{"KJV":{"text":"Let them wander up and down for meat, and grudge if they be not satisfied."},"BSB":{"text":"They scavenge for food, and growl if they are not satisfied."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"But I will sing of thy power; yea, I will sing aloud of thy mercy in the morning: for thou hast been my defence and refuge in the day of my trouble.","ref":"Psalms 59:16","synthesized":"But I will sing of Your strength and proclaim Your loving devotion in the morning. For You are my fortress, my refuge in times of trouble.","sources":{"KJV":{"text":"But I will sing of thy power; yea, I will sing aloud of thy mercy in the morning: for thou hast been my defence and refuge in the day of my trouble."},"BSB":{"text":"But I will sing of Your strength and proclaim Your loving devotion in the morning. For You are my fortress, my refuge in times of trouble."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Unto thee, O my strength, will I sing: for God is my defence, and the God of my mercy.","ref":"Psalms 59:17","synthesized":"To You, O my strength, I sing praises, for You, O God, are my fortress, my God of loving devotion.","sources":{"KJV":{"text":"Unto thee, O my strength, will I sing: for God is my defence, and the God of my mercy."},"BSB":{"text":"To You, O my strength, I sing praises, for You, O God, are my fortress, my God of loving devotion."}},"definableWords":["God"],"peopleInVerse":[]}}},"60":{"chapter":"60","title":"GIVE US HELP FROM TROUBLE","verses":{"1":{"text":"O God, thou hast cast us off, thou hast scattered us, thou hast been displeased; O turn thyself to us again.","ref":"Psalms 60:1","synthesized":"You have rejected us, O God; You have broken us; You have been angry; restore us!","sources":{"KJV":{"text":"O God, thou hast cast us off, thou hast scattered us, thou hast been displeased; O turn thyself to us again."},"BSB":{"text":"You have rejected us, O God; You have broken us; You have been angry; restore us!"}},"definableWords":["God"],"peopleInVerse":[]},"2":{"text":"Thou hast made the earth to tremble; thou hast broken it: heal the breaches thereof; for it shaketh.","ref":"Psalms 60:2","synthesized":"You have shaken the land and torn it open. Heal its fractures, for it is quaking.","sources":{"KJV":{"text":"Thou hast made the earth to tremble; thou hast broken it: heal the breaches thereof; for it shaketh."},"BSB":{"text":"You have shaken the land and torn it open. Heal its fractures, for it is quaking."}},"definableWords":["land","heal"],"peopleInVerse":[]},"3":{"text":"Thou hast shewed thy people hard things: thou hast made us to drink the wine of astonishment.","ref":"Psalms 60:3","synthesized":"You have shown Your people hardship; we are staggered from the wine You made us drink.","sources":{"KJV":{"text":"Thou hast shewed thy people hard things: thou hast made us to drink the wine of astonishment."},"BSB":{"text":"You have shown Your people hardship; we are staggered from the wine You made us drink."}},"definableWords":["people","made"],"peopleInVerse":[]},"4":{"text":"Thou hast given a banner to them that fear thee, that it may be displayed because of the truth. Selah.","ref":"Psalms 60:4","synthesized":"You have raised a banner for those who fear You, that they may flee the bow. Selah","sources":{"KJV":{"text":"Thou hast given a banner to them that fear thee, that it may be displayed because of the truth. Selah."},"BSB":{"text":"You have raised a banner for those who fear You, that they may flee the bow. Selah"}},"definableWords":["fear"],"peopleInVerse":[]},"5":{"text":"That thy beloved may be delivered; save with thy right hand, and hear me.","ref":"Psalms 60:5","synthesized":"Respond and save us with Your right hand, that Your beloved may be delivered.","sources":{"KJV":{"text":"That thy beloved may be delivered; save with thy right hand, and hear me."},"BSB":{"text":"Respond and save us with Your right hand, that Your beloved may be delivered."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"God hath spoken in his holiness; I will rejoice, I will divide Shechem, and mete out the valley of Succoth.","ref":"Psalms 60:6","synthesized":"God has spoken from His sanctuary: “I will triumph! I will parcel out Shechem and apportion the Valley of Succoth.","sources":{"KJV":{"text":"God hath spoken in his holiness; I will rejoice, I will divide Shechem, and mete out the valley of Succoth."},"BSB":{"text":"God has spoken from His sanctuary: “I will triumph! I will parcel out Shechem and apportion the Valley of Succoth."}},"definableWords":["God"],"peopleInVerse":[]},"7":{"text":"Gilead is mine, and Manasseh is mine; Ephraim also is the strength of mine head; Judah is my lawgiver;","ref":"Psalms 60:7","synthesized":"Gilead is Mine, and Manasseh is Mine; Ephraim is My helmet, Judah is My scepter.","sources":{"KJV":{"text":"Gilead is mine, and Manasseh is mine; Ephraim also is the strength of mine head; Judah is my lawgiver;"},"BSB":{"text":"Gilead is Mine, and Manasseh is Mine; Ephraim is My helmet, Judah is My scepter."}},"definableWords":["Judah","scepter"],"peopleInVerse":[]},"8":{"text":"Moab is my washpot; over Edom will I cast out my shoe: Philistia, triumph thou because of me.","ref":"Psalms 60:8","synthesized":"Moab is My washbasin; upon Edom I toss My sandal; over Philistia I shout in triumph.”","sources":{"KJV":{"text":"Moab is my washpot; over Edom will I cast out my shoe: Philistia, triumph thou because of me."},"BSB":{"text":"Moab is My washbasin; upon Edom I toss My sandal; over Philistia I shout in triumph.”"}},"definableWords":["Edom"],"peopleInVerse":[]},"9":{"text":"Who will bring me into the strong city? who will lead me into Edom?","ref":"Psalms 60:9","synthesized":"Who will bring me to the fortified city? Who will lead me to Edom?","sources":{"KJV":{"text":"Who will bring me into the strong city? who will lead me into Edom?"},"BSB":{"text":"Who will bring me to the fortified city? Who will lead me to Edom?"}},"definableWords":["Edom"],"peopleInVerse":[]},"10":{"text":"Wilt not thou, O God, which hadst cast us off? and thou, O God, which didst not go out with our armies?","ref":"Psalms 60:10","synthesized":"Have You not rejected us, O God? Will You no longer march out, O God, with our armies?","sources":{"KJV":{"text":"Wilt not thou, O God, which hadst cast us off? and thou, O God, which didst not go out with our armies?"},"BSB":{"text":"Have You not rejected us, O God? Will You no longer march out, O God, with our armies?"}},"definableWords":["God"],"peopleInVerse":[]},"11":{"text":"Give us help from trouble: for vain is the help of man.","ref":"Psalms 60:11","synthesized":"Give us aid against the enemy, for the help of man is worthless.","sources":{"KJV":{"text":"Give us help from trouble: for vain is the help of man."},"BSB":{"text":"Give us aid against the enemy, for the help of man is worthless."}},"definableWords":["man"],"peopleInVerse":[]},"12":{"text":"Through God we shall do valiantly: for he it is that shall tread down our enemies.","ref":"Psalms 60:12","synthesized":"With God we will perform with valor, and He will trample our enemies.","sources":{"KJV":{"text":"Through God we shall do valiantly: for he it is that shall tread down our enemies."},"BSB":{"text":"With God we will perform with valor, and He will trample our enemies."}},"definableWords":["God"],"peopleInVerse":[]}}},"61":{"chapter":"61","title":"FROM THE END OF THE EARTH","verses":{"1":{"text":"Hear my cry, O God; attend unto my prayer.","ref":"Psalms 61:1","synthesized":"Hear my cry, O God; attend to my prayer.","sources":{"KJV":{"text":"Hear my cry, O God; attend unto my prayer."},"BSB":{"text":"Hear my cry, O God; attend to my prayer."}},"definableWords":["hear","God","prayer"],"peopleInVerse":[]},"2":{"text":"From the end of the earth will I cry unto thee, when my heart is overwhelmed: lead me to the rock that is higher than I.","ref":"Psalms 61:2","synthesized":"From the ends of the earth I call out to You whenever my heart is faint. Lead me to the rock that is higher than I.","sources":{"KJV":{"text":"From the end of the earth will I cry unto thee, when my heart is overwhelmed: lead me to the rock that is higher than I."},"BSB":{"text":"From the ends of the earth I call out to You whenever my heart is faint. Lead me to the rock that is higher than I."}},"definableWords":["earth","heart"],"peopleInVerse":[]},"3":{"text":"For thou hast been a shelter for me, and a strong tower from the enemy.","ref":"Psalms 61:3","synthesized":"For You have been my refuge, a tower of strength against the enemy.","sources":{"KJV":{"text":"For thou hast been a shelter for me, and a strong tower from the enemy."},"BSB":{"text":"For You have been my refuge, a tower of strength against the enemy."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"I will abide in thy tabernacle for ever: I will trust in the covert of thy wings. Selah.","ref":"Psalms 61:4","synthesized":"Let me dwell in Your tent forever and take refuge in the shelter of Your wings. Selah","sources":{"KJV":{"text":"I will abide in thy tabernacle for ever: I will trust in the covert of thy wings. Selah."},"BSB":{"text":"Let me dwell in Your tent forever and take refuge in the shelter of Your wings. Selah"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"For thou, O God, hast heard my vows: thou hast given me the heritage of those that fear thy name.","ref":"Psalms 61:5","synthesized":"For You have heard my vows, O God; You have given me the inheritance reserved for those who fear Your name.","sources":{"KJV":{"text":"For thou, O God, hast heard my vows: thou hast given me the heritage of those that fear thy name."},"BSB":{"text":"For You have heard my vows, O God; You have given me the inheritance reserved for those who fear Your name."}},"definableWords":["God","fear","name"],"peopleInVerse":[]},"6":{"text":"Thou wilt prolong the king’s life: and his years as many generations.","ref":"Psalms 61:6","synthesized":"Increase the days of the king’s life; may his years span many generations.","sources":{"KJV":{"text":"Thou wilt prolong the king’s life: and his years as many generations."},"BSB":{"text":"Increase the days of the king’s life; may his years span many generations."}},"definableWords":["days","king","life","years"],"peopleInVerse":[]},"7":{"text":"He shall abide before God for ever: O prepare mercy and truth, which may preserve him.","ref":"Psalms 61:7","synthesized":"May he sit enthroned in God’s presence forever; appoint Your loving devotion and Your faithfulness to guard him.","sources":{"KJV":{"text":"He shall abide before God for ever: O prepare mercy and truth, which may preserve him."},"BSB":{"text":"May he sit enthroned in God’s presence forever; appoint Your loving devotion and Your faithfulness to guard him."}},"definableWords":["God"],"peopleInVerse":[]},"8":{"text":"So will I sing praise unto thy name for ever, that I may daily perform my vows.","ref":"Psalms 61:8","synthesized":"Then I will ever sing praise to Your name and fulfill my vows day by day.","sources":{"KJV":{"text":"So will I sing praise unto thy name for ever, that I may daily perform my vows."},"BSB":{"text":"Then I will ever sing praise to Your name and fulfill my vows day by day."}},"definableWords":["praise","name","day"],"peopleInVerse":[]}}},"62":{"chapter":"62","title":"MY SOUL WAIT THOU ONLY UPON GOD","verses":{"1":{"text":"Truly my soul waiteth upon God: from him cometh my salvation.","ref":"Psalms 62:1","synthesized":"In God alone my soul finds rest; my salvation comes from Him.","sources":{"KJV":{"text":"Truly my soul waiteth upon God: from him cometh my salvation."},"BSB":{"text":"In God alone my soul finds rest; my salvation comes from Him."}},"definableWords":["God","soul","rest","salvation"],"peopleInVerse":[]},"2":{"text":"He only is my rock and my salvation; he is my defence; I shall not be greatly moved.","ref":"Psalms 62:2","synthesized":"He alone is my rock and my salvation. He is my fortress; I will never be shaken.","sources":{"KJV":{"text":"He only is my rock and my salvation; he is my defence; I shall not be greatly moved."},"BSB":{"text":"He alone is my rock and my salvation. He is my fortress; I will never be shaken."}},"definableWords":["salvation"],"peopleInVerse":[]},"3":{"text":"How long will ye imagine mischief against a man? ye shall be slain all of you: as a bowing wall shall ye be, and as a tottering fence.","ref":"Psalms 62:3","synthesized":"How long will you threaten a man? Will all of you throw him down like a leaning wall or a tottering fence?","sources":{"KJV":{"text":"How long will ye imagine mischief against a man? ye shall be slain all of you: as a bowing wall shall ye be, and as a tottering fence."},"BSB":{"text":"How long will you threaten a man? Will all of you throw him down like a leaning wall or a tottering fence?"}},"definableWords":["man","or"],"peopleInVerse":[]},"4":{"text":"They only consult to cast him down from his excellency: they delight in lies: they bless with their mouth, but they curse inwardly. Selah.","ref":"Psalms 62:4","synthesized":"They fully intend to cast him down from his lofty perch; they delight in lies; with their mouths they bless, but inwardly they curse. Selah","sources":{"KJV":{"text":"They only consult to cast him down from his excellency: they delight in lies: they bless with their mouth, but they curse inwardly. Selah."},"BSB":{"text":"They fully intend to cast him down from his lofty perch; they delight in lies; with their mouths they bless, but inwardly they curse. Selah"}},"definableWords":["bless","curse"],"peopleInVerse":[]},"5":{"text":"My soul, wait thou only upon God; for my expectation is from him.","ref":"Psalms 62:5","synthesized":"Rest in God alone, O my soul, for my hope comes from Him.","sources":{"KJV":{"text":"My soul, wait thou only upon God; for my expectation is from him."},"BSB":{"text":"Rest in God alone, O my soul, for my hope comes from Him."}},"definableWords":["rest","God","soul","hope"],"peopleInVerse":[]},"6":{"text":"He only is my rock and my salvation: he is my defence; I shall not be moved.","ref":"Psalms 62:6","synthesized":"He alone is my rock and my salvation; He is my fortress; I will not be shaken.","sources":{"KJV":{"text":"He only is my rock and my salvation: he is my defence; I shall not be moved."},"BSB":{"text":"He alone is my rock and my salvation; He is my fortress; I will not be shaken."}},"definableWords":["salvation"],"peopleInVerse":[]},"7":{"text":"In God is my salvation and my glory: the rock of my strength, and my refuge, is in God.","ref":"Psalms 62:7","synthesized":"My salvation and my honor rest on God, my strong rock; my refuge is in God.","sources":{"KJV":{"text":"In God is my salvation and my glory: the rock of my strength, and my refuge, is in God."},"BSB":{"text":"My salvation and my honor rest on God, my strong rock; my refuge is in God."}},"definableWords":["salvation","rest","God","strong"],"peopleInVerse":[]},"8":{"text":"Trust in him at all times; ye people, pour out your heart before him: God is a refuge for us. Selah.","ref":"Psalms 62:8","synthesized":"Trust in Him at all times, O people; pour out your hearts before Him. God is our refuge. Selah","sources":{"KJV":{"text":"Trust in him at all times; ye people, pour out your heart before him: God is a refuge for us. Selah."},"BSB":{"text":"Trust in Him at all times, O people; pour out your hearts before Him. God is our refuge. Selah"}},"definableWords":["trust","people","God"],"peopleInVerse":[]},"9":{"text":"Surely men of low degree are vanity, and men of high degree are a lie: to be laid in the balance, they are altogether lighter than vanity.","ref":"Psalms 62:9","synthesized":"Lowborn men are but a vapor, the exalted but a lie. Weighed on the scale, they go up; together they are but a vapor.","sources":{"KJV":{"text":"Surely men of low degree are vanity, and men of high degree are a lie: to be laid in the balance, they are altogether lighter than vanity."},"BSB":{"text":"Lowborn men are but a vapor, the exalted but a lie. Weighed on the scale, they go up; together they are but a vapor."}},"definableWords":["men"],"peopleInVerse":[]},"10":{"text":"Trust not in oppression, and become not vain in robbery: if riches increase, set not your heart upon them.","ref":"Psalms 62:10","synthesized":"Place no trust in extortion, or false hope in stolen goods. If your riches increase, do not set your heart upon them.","sources":{"KJV":{"text":"Trust not in oppression, and become not vain in robbery: if riches increase, set not your heart upon them."},"BSB":{"text":"Place no trust in extortion, or false hope in stolen goods. If your riches increase, do not set your heart upon them."}},"definableWords":["trust","or","hope","heart"],"peopleInVerse":[]},"11":{"text":"God hath spoken once; twice have I heard this; that power belongeth unto God.","ref":"Psalms 62:11","synthesized":"God has spoken once; I have heard this twice: that power belongs to God,","sources":{"KJV":{"text":"God hath spoken once; twice have I heard this; that power belongeth unto God."},"BSB":{"text":"God has spoken once; I have heard this twice: that power belongs to God,"}},"definableWords":["God"],"peopleInVerse":[]},"12":{"text":"Also unto thee, O Lord, belongeth mercy: for thou renderest to every man according to his work.","ref":"Psalms 62:12","synthesized":"and loving devotion to You, O Lord. For You will repay each man according to his deeds.","sources":{"KJV":{"text":"Also unto thee, O Lord, belongeth mercy: for thou renderest to every man according to his work."},"BSB":{"text":"and loving devotion to You, O Lord. For You will repay each man according to his deeds."}},"definableWords":["Lord","man"],"peopleInVerse":[]}}},"63":{"chapter":"63","title":"O GOD, EARLY WILL I SEEK THEE","verses":{"1":{"text":"O God, thou art my God; early will I seek thee: my soul thirsteth for thee, my flesh longeth for thee in a dry and thirsty land, where no water is;","ref":"Psalms 63:1","synthesized":"O God, You are my God. Earnestly I seek You; my soul thirsts for You. My body yearns for You in a dry and weary land without water.","sources":{"KJV":{"text":"O God, thou art my God; early will I seek thee: my soul thirsteth for thee, my flesh longeth for thee in a dry and thirsty land, where no water is;"},"BSB":{"text":"O God, You are my God. Earnestly I seek You; my soul thirsts for You. My body yearns for You in a dry and weary land without water."}},"definableWords":["God","seek","soul","land","water"],"peopleInVerse":[]},"2":{"text":"To see thy power and thy glory, so as I have seen thee in the sanctuary.","ref":"Psalms 63:2","synthesized":"So I have seen You in the sanctuary and beheld Your power and glory.","sources":{"KJV":{"text":"To see thy power and thy glory, so as I have seen thee in the sanctuary."},"BSB":{"text":"So I have seen You in the sanctuary and beheld Your power and glory."}},"definableWords":["glory"],"peopleInVerse":[]},"3":{"text":"Because thy lovingkindness is better than life, my lips shall praise thee.","ref":"Psalms 63:3","synthesized":"Because Your loving devotion is better than life, my lips will glorify You.","sources":{"KJV":{"text":"Because thy lovingkindness is better than life, my lips shall praise thee."},"BSB":{"text":"Because Your loving devotion is better than life, my lips will glorify You."}},"definableWords":["life"],"peopleInVerse":[]},"4":{"text":"Thus will I bless thee while I live: I will lift up my hands in thy name.","ref":"Psalms 63:4","synthesized":"So I will bless You as long as I live; in Your name I will lift my hands.","sources":{"KJV":{"text":"Thus will I bless thee while I live: I will lift up my hands in thy name."},"BSB":{"text":"So I will bless You as long as I live; in Your name I will lift my hands."}},"definableWords":["bless","live","name"],"peopleInVerse":[]},"5":{"text":"My soul shall be satisfied as with marrow and fatness; and my mouth shall praise thee with joyful lips:","ref":"Psalms 63:5","synthesized":"My soul is satisfied as with the richest of foods; with joyful lips my mouth will praise You.","sources":{"KJV":{"text":"My soul shall be satisfied as with marrow and fatness; and my mouth shall praise thee with joyful lips:"},"BSB":{"text":"My soul is satisfied as with the richest of foods; with joyful lips my mouth will praise You."}},"definableWords":["soul","praise"],"peopleInVerse":[]},"6":{"text":"When I remember thee upon my bed, and meditate on thee in the night watches.","ref":"Psalms 63:6","synthesized":"When I remember You on my bed, I think of You through the watches of the night.","sources":{"KJV":{"text":"When I remember thee upon my bed, and meditate on thee in the night watches."},"BSB":{"text":"When I remember You on my bed, I think of You through the watches of the night."}},"definableWords":["remember","night"],"peopleInVerse":[]},"7":{"text":"Because thou hast been my help, therefore in the shadow of thy wings will I rejoice.","ref":"Psalms 63:7","synthesized":"For You are my help; I will sing for joy in the shadow of Your wings.","sources":{"KJV":{"text":"Because thou hast been my help, therefore in the shadow of thy wings will I rejoice."},"BSB":{"text":"For You are my help; I will sing for joy in the shadow of Your wings."}},"definableWords":["joy"],"peopleInVerse":[]},"8":{"text":"My soul followeth hard after thee: thy right hand upholdeth me.","ref":"Psalms 63:8","synthesized":"My soul clings to You; Your right hand upholds me.","sources":{"KJV":{"text":"My soul followeth hard after thee: thy right hand upholdeth me."},"BSB":{"text":"My soul clings to You; Your right hand upholds me."}},"definableWords":["soul"],"peopleInVerse":[]},"9":{"text":"But those that seek my soul, to destroy it, shall go into the lower parts of the earth.","ref":"Psalms 63:9","synthesized":"But those who seek my life to destroy it will go into the depths of the earth.","sources":{"KJV":{"text":"But those that seek my soul, to destroy it, shall go into the lower parts of the earth."},"BSB":{"text":"But those who seek my life to destroy it will go into the depths of the earth."}},"definableWords":["seek","life","earth"],"peopleInVerse":[]},"10":{"text":"They shall fall by the sword: they shall be a portion for foxes.","ref":"Psalms 63:10","synthesized":"They will fall to the power of the sword; they will become a portion for foxes.","sources":{"KJV":{"text":"They shall fall by the sword: they shall be a portion for foxes."},"BSB":{"text":"They will fall to the power of the sword; they will become a portion for foxes."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"But the king shall rejoice in God; every one that sweareth by him shall glory: but the mouth of them that speak lies shall be stopped.","ref":"Psalms 63:11","synthesized":"But the king will rejoice in God; all who swear by Him will exult, for the mouths of liars will be shut.","sources":{"KJV":{"text":"But the king shall rejoice in God; every one that sweareth by him shall glory: but the mouth of them that speak lies shall be stopped."},"BSB":{"text":"But the king will rejoice in God; all who swear by Him will exult, for the mouths of liars will be shut."}},"definableWords":["king","God"],"peopleInVerse":[]}}},"64":{"chapter":"64","title":"HEAR MY VOICE, O GOD","verses":{"1":{"text":"Hear my voice, O God, in my prayer: preserve my life from fear of the enemy.","ref":"Psalms 64:1","synthesized":"Hear, O God, my voice of complaint; preserve my life from dread of the enemy.","sources":{"KJV":{"text":"Hear my voice, O God, in my prayer: preserve my life from fear of the enemy."},"BSB":{"text":"Hear, O God, my voice of complaint; preserve my life from dread of the enemy."}},"definableWords":["hear","God","voice","life"],"peopleInVerse":[]},"2":{"text":"Hide me from the secret counsel of the wicked; from the insurrection of the workers of iniquity:","ref":"Psalms 64:2","synthesized":"Hide me from the scheming of the wicked, from the mob of workers of iniquity,","sources":{"KJV":{"text":"Hide me from the secret counsel of the wicked; from the insurrection of the workers of iniquity:"},"BSB":{"text":"Hide me from the scheming of the wicked, from the mob of workers of iniquity,"}},"definableWords":["iniquity"],"peopleInVerse":[]},"3":{"text":"Who whet their tongue like a sword, and bend their bows to shoot their arrows, even bitter words:","ref":"Psalms 64:3","synthesized":"who sharpen their tongues like swords and aim their bitter words like arrows,","sources":{"KJV":{"text":"Who whet their tongue like a sword, and bend their bows to shoot their arrows, even bitter words:"},"BSB":{"text":"who sharpen their tongues like swords and aim their bitter words like arrows,"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"That they may shoot in secret at the perfect: suddenly do they shoot at him, and fear not.","ref":"Psalms 64:4","synthesized":"ambushing the innocent in seclusion, shooting suddenly, without fear.","sources":{"KJV":{"text":"That they may shoot in secret at the perfect: suddenly do they shoot at him, and fear not."},"BSB":{"text":"ambushing the innocent in seclusion, shooting suddenly, without fear."}},"definableWords":["fear"],"peopleInVerse":[]},"5":{"text":"They encourage themselves in an evil matter: they commune of laying snares privily; they say, Who shall see them?","ref":"Psalms 64:5","synthesized":"They hold fast to their evil purpose; they speak of hiding their snares. “Who will see them?” they say.","sources":{"KJV":{"text":"They encourage themselves in an evil matter: they commune of laying snares privily; they say, Who shall see them?"},"BSB":{"text":"They hold fast to their evil purpose; they speak of hiding their snares. “Who will see them?” they say."}},"definableWords":["fast","evil","see"],"peopleInVerse":[]},"6":{"text":"They search out iniquities; they accomplish a diligent search: both the inward thought of every one of them, and the heart, is deep.","ref":"Psalms 64:6","synthesized":"They devise injustice and say, “We have perfected a secret plan.” For the inner man and the heart are mysterious.","sources":{"KJV":{"text":"They search out iniquities; they accomplish a diligent search: both the inward thought of every one of them, and the heart, is deep."},"BSB":{"text":"They devise injustice and say, “We have perfected a secret plan.” For the inner man and the heart are mysterious."}},"definableWords":["man","heart"],"peopleInVerse":[]},"7":{"text":"But God shall shoot at them with an arrow; suddenly shall they be wounded.","ref":"Psalms 64:7","synthesized":"But God will shoot them with arrows; suddenly they will be wounded.","sources":{"KJV":{"text":"But God shall shoot at them with an arrow; suddenly shall they be wounded."},"BSB":{"text":"But God will shoot them with arrows; suddenly they will be wounded."}},"definableWords":["God"],"peopleInVerse":[]},"8":{"text":"So they shall make their own tongue to fall upon themselves: all that see them shall flee away.","ref":"Psalms 64:8","synthesized":"They will be made to stumble, their own tongues turned against them. All who see will shake their heads.","sources":{"KJV":{"text":"So they shall make their own tongue to fall upon themselves: all that see them shall flee away."},"BSB":{"text":"They will be made to stumble, their own tongues turned against them. All who see will shake their heads."}},"definableWords":["made","see"],"peopleInVerse":[]},"9":{"text":"And all men shall fear, and shall declare the work of God; for they shall wisely consider of his doing.","ref":"Psalms 64:9","synthesized":"Then all mankind will fear and proclaim the work of God; so they will ponder what He has done.","sources":{"KJV":{"text":"And all men shall fear, and shall declare the work of God; for they shall wisely consider of his doing."},"BSB":{"text":"Then all mankind will fear and proclaim the work of God; so they will ponder what He has done."}},"definableWords":["fear","work","God"],"peopleInVerse":[]},"10":{"text":"The righteous shall be glad in the LORD, and shall trust in him; and all the upright in heart shall glory.","ref":"Psalms 64:10","synthesized":"Let the righteous rejoice in the LORD and take refuge in Him; let all the upright in heart exult.","sources":{"KJV":{"text":"The righteous shall be glad in the LORD, and shall trust in him; and all the upright in heart shall glory."},"BSB":{"text":"Let the righteous rejoice in the LORD and take refuge in Him; let all the upright in heart exult."}},"definableWords":["righteous","LORD","heart"],"peopleInVerse":[]}}},"65":{"chapter":"65","title":"PRAISE WAITETH FOR THEE IN ZION","verses":{"1":{"text":"Praise waiteth for thee, O God, in Sion: and unto thee shall the vow be performed.","ref":"Psalms 65:1","synthesized":"Praise awaits You, O God, in Zion; to You our vows will be fulfilled.","sources":{"KJV":{"text":"Praise waiteth for thee, O God, in Sion: and unto thee shall the vow be performed."},"BSB":{"text":"Praise awaits You, O God, in Zion; to You our vows will be fulfilled."}},"definableWords":["praise","God","Zion"],"peopleInVerse":[]},"2":{"text":"O thou that hearest prayer, unto thee shall all flesh come.","ref":"Psalms 65:2","synthesized":"O You who listen to prayer, all people will come to You.","sources":{"KJV":{"text":"O thou that hearest prayer, unto thee shall all flesh come."},"BSB":{"text":"O You who listen to prayer, all people will come to You."}},"definableWords":["prayer","people"],"peopleInVerse":[]},"3":{"text":"Iniquities prevail against me: as for our transgressions, thou shalt purge them away.","ref":"Psalms 65:3","synthesized":"When iniquities prevail against me, You atone for our transgressions.","sources":{"KJV":{"text":"Iniquities prevail against me: as for our transgressions, thou shalt purge them away."},"BSB":{"text":"When iniquities prevail against me, You atone for our transgressions."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Blessed is the man whom thou choosest, and causest to approach unto thee, that he may dwell in thy courts: we shall be satisfied with the goodness of thy house, even of thy holy temple.","ref":"Psalms 65:4","synthesized":"Blessed is the one You choose and bring near to dwell in Your courts! We are filled with the goodness of Your house, the holiness of Your temple.","sources":{"KJV":{"text":"Blessed is the man whom thou choosest, and causest to approach unto thee, that he may dwell in thy courts: we shall be satisfied with the goodness of thy house, even of thy holy temple."},"BSB":{"text":"Blessed is the one You choose and bring near to dwell in Your courts! We are filled with the goodness of Your house, the holiness of Your temple."}},"definableWords":["blessed","one","house","temple"],"peopleInVerse":[]},"5":{"text":"By terrible things in righteousness wilt thou answer us, O God of our salvation; who art the confidence of all the ends of the earth, and of them that are afar off upon the sea:","ref":"Psalms 65:5","synthesized":"With awesome deeds of righteousness You answer us, O God of our salvation, the hope of all the ends of the earth and of the farthest seas.","sources":{"KJV":{"text":"By terrible things in righteousness wilt thou answer us, O God of our salvation; who art the confidence of all the ends of the earth, and of them that are afar off upon the sea:"},"BSB":{"text":"With awesome deeds of righteousness You answer us, O God of our salvation, the hope of all the ends of the earth and of the farthest seas."}},"definableWords":["righteousness","God","salvation","hope","earth","seas"],"peopleInVerse":[]},"6":{"text":"Which by his strength setteth fast the mountains; being girded with power:","ref":"Psalms 65:6","synthesized":"You formed the mountains by Your power, having girded Yourself with might.","sources":{"KJV":{"text":"Which by his strength setteth fast the mountains; being girded with power:"},"BSB":{"text":"You formed the mountains by Your power, having girded Yourself with might."}},"definableWords":["formed"],"peopleInVerse":[]},"7":{"text":"Which stilleth the noise of the seas, the noise of their waves, and the tumult of the people.","ref":"Psalms 65:7","synthesized":"You stilled the roaring of the seas, the pounding of their waves, and the tumult of the nations.","sources":{"KJV":{"text":"Which stilleth the noise of the seas, the noise of their waves, and the tumult of the people."},"BSB":{"text":"You stilled the roaring of the seas, the pounding of their waves, and the tumult of the nations."}},"definableWords":["seas","nations"],"peopleInVerse":[]},"8":{"text":"They also that dwell in the uttermost parts are afraid at thy tokens: thou makest the outgoings of the morning and evening to rejoice.","ref":"Psalms 65:8","synthesized":"Those who live far away fear Your wonders; You make the dawn and sunset shout for joy.","sources":{"KJV":{"text":"They also that dwell in the uttermost parts are afraid at thy tokens: thou makest the outgoings of the morning and evening to rejoice."},"BSB":{"text":"Those who live far away fear Your wonders; You make the dawn and sunset shout for joy."}},"definableWords":["live","fear","make","joy"],"peopleInVerse":[]},"9":{"text":"Thou visitest the earth, and waterest it: thou greatly enrichest it with the river of God, which is full of water: thou preparest them corn, when thou hast so provided for it.","ref":"Psalms 65:9","synthesized":"You attend to the earth and water it; with abundance You enrich it. The streams of God are full of water, for You prepare our grain by providing for the earth.","sources":{"KJV":{"text":"Thou visitest the earth, and waterest it: thou greatly enrichest it with the river of God, which is full of water: thou preparest them corn, when thou hast so provided for it."},"BSB":{"text":"You attend to the earth and water it; with abundance You enrich it. The streams of God are full of water, for You prepare our grain by providing for the earth."}},"definableWords":["earth","water","God"],"peopleInVerse":[]},"10":{"text":"Thou waterest the ridges thereof abundantly: thou settlest the furrows thereof: thou makest it soft with showers: thou blessest the springing thereof.","ref":"Psalms 65:10","synthesized":"You soak its furrows and level its ridges; You soften it with showers and bless its growth.","sources":{"KJV":{"text":"Thou waterest the ridges thereof abundantly: thou settlest the furrows thereof: thou makest it soft with showers: thou blessest the springing thereof."},"BSB":{"text":"You soak its furrows and level its ridges; You soften it with showers and bless its growth."}},"definableWords":["bless"],"peopleInVerse":[]},"11":{"text":"Thou crownest the year with thy goodness; and thy paths drop fatness.","ref":"Psalms 65:11","synthesized":"You crown the year with Your bounty, and Your paths overflow with plenty.","sources":{"KJV":{"text":"Thou crownest the year with thy goodness; and thy paths drop fatness."},"BSB":{"text":"You crown the year with Your bounty, and Your paths overflow with plenty."}},"definableWords":["crown","year"],"peopleInVerse":[]},"12":{"text":"They drop upon the pastures of the wilderness: and the little hills rejoice on every side.","ref":"Psalms 65:12","synthesized":"The pastures of the wilderness overflow; the hills are robed with joy.","sources":{"KJV":{"text":"They drop upon the pastures of the wilderness: and the little hills rejoice on every side."},"BSB":{"text":"The pastures of the wilderness overflow; the hills are robed with joy."}},"definableWords":["joy"],"peopleInVerse":[]},"13":{"text":"The pastures are clothed with flocks; the valleys also are covered over with corn; they shout for joy, they also sing.","ref":"Psalms 65:13","synthesized":"The pastures are clothed with flocks, and the valleys are decked with grain. They shout in triumph; indeed, they sing.","sources":{"KJV":{"text":"The pastures are clothed with flocks; the valleys also are covered over with corn; they shout for joy, they also sing."},"BSB":{"text":"The pastures are clothed with flocks, and the valleys are decked with grain. They shout in triumph; indeed, they sing."}},"definableWords":[],"peopleInVerse":[]}}},"66":{"chapter":"66","title":"MAKE A JOYFUL NOISE UNTO GOD","verses":{"1":{"text":"Make a joyful noise unto God, all ye lands:","ref":"Psalms 66:1","synthesized":"Make a joyful noise to God, all the earth!","sources":{"KJV":{"text":"Make a joyful noise unto God, all ye lands:"},"BSB":{"text":"Make a joyful noise to God, all the earth!"}},"definableWords":["make","God","earth"],"peopleInVerse":[]},"2":{"text":"Sing forth the honour of his name: make his praise glorious.","ref":"Psalms 66:2","synthesized":"Sing the glory of His name; make His praise glorious.","sources":{"KJV":{"text":"Sing forth the honour of his name: make his praise glorious."},"BSB":{"text":"Sing the glory of His name; make His praise glorious."}},"definableWords":["glory","name","make","praise"],"peopleInVerse":[]},"3":{"text":"Say unto God, How terrible art thou in thy works! through the greatness of thy power shall thine enemies submit themselves unto thee.","ref":"Psalms 66:3","synthesized":"Say to God, “How awesome are Your deeds! So great is Your power that Your enemies cower before You.","sources":{"KJV":{"text":"Say unto God, How terrible art thou in thy works! through the greatness of thy power shall thine enemies submit themselves unto thee."},"BSB":{"text":"Say to God, “How awesome are Your deeds! So great is Your power that Your enemies cower before You."}},"definableWords":["God","great"],"peopleInVerse":[]},"4":{"text":"All the earth shall worship thee, and shall sing unto thee; they shall sing to thy name. Selah.","ref":"Psalms 66:4","synthesized":"All the earth bows down to You; they sing praise to You; they sing praise to Your name.” Selah","sources":{"KJV":{"text":"All the earth shall worship thee, and shall sing unto thee; they shall sing to thy name. Selah."},"BSB":{"text":"All the earth bows down to You; they sing praise to You; they sing praise to Your name.” Selah"}},"definableWords":["earth","praise","name"],"peopleInVerse":[]},"5":{"text":"Come and see the works of God: he is terrible in his doing toward the children of men.","ref":"Psalms 66:5","synthesized":"Come and see the works of God; how awesome are His deeds toward mankind.","sources":{"KJV":{"text":"Come and see the works of God: he is terrible in his doing toward the children of men."},"BSB":{"text":"Come and see the works of God; how awesome are His deeds toward mankind."}},"definableWords":["see","works","God"],"peopleInVerse":[]},"6":{"text":"He turned the sea into dry land: they went through the flood on foot: there did we rejoice in him.","ref":"Psalms 66:6","synthesized":"He turned the sea into dry land; they passed through the waters on foot; there we rejoiced in Him.","sources":{"KJV":{"text":"He turned the sea into dry land: they went through the flood on foot: there did we rejoice in him."},"BSB":{"text":"He turned the sea into dry land; they passed through the waters on foot; there we rejoiced in Him."}},"definableWords":["sea","land","waters"],"peopleInVerse":[]},"7":{"text":"He ruleth by his power for ever; his eyes behold the nations: let not the rebellious exalt themselves. Selah.","ref":"Psalms 66:7","synthesized":"He rules forever by His power; His eyes watch the nations. Do not let the rebellious exalt themselves. Selah","sources":{"KJV":{"text":"He ruleth by his power for ever; his eyes behold the nations: let not the rebellious exalt themselves. Selah."},"BSB":{"text":"He rules forever by His power; His eyes watch the nations. Do not let the rebellious exalt themselves. Selah"}},"definableWords":["nations"],"peopleInVerse":[]},"8":{"text":"O bless our God, ye people, and make the voice of his praise to be heard:","ref":"Psalms 66:8","synthesized":"Bless our God, O peoples; let the sound of His praise be heard.","sources":{"KJV":{"text":"O bless our God, ye people, and make the voice of his praise to be heard:"},"BSB":{"text":"Bless our God, O peoples; let the sound of His praise be heard."}},"definableWords":["bless","God","praise"],"peopleInVerse":[]},"9":{"text":"Which holdeth our soul in life, and suffereth not our feet to be moved.","ref":"Psalms 66:9","synthesized":"He preserves our lives and keeps our feet from slipping.","sources":{"KJV":{"text":"Which holdeth our soul in life, and suffereth not our feet to be moved."},"BSB":{"text":"He preserves our lives and keeps our feet from slipping."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For thou, O God, hast proved us: thou hast tried us, as silver is tried.","ref":"Psalms 66:10","synthesized":"For You, O God, have tested us; You have refined us like silver.","sources":{"KJV":{"text":"For thou, O God, hast proved us: thou hast tried us, as silver is tried."},"BSB":{"text":"For You, O God, have tested us; You have refined us like silver."}},"definableWords":["God"],"peopleInVerse":[]},"11":{"text":"Thou broughtest us into the net; thou laidst affliction upon our loins.","ref":"Psalms 66:11","synthesized":"You led us into the net; You laid burdens on our backs.","sources":{"KJV":{"text":"Thou broughtest us into the net; thou laidst affliction upon our loins."},"BSB":{"text":"You led us into the net; You laid burdens on our backs."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Thou hast caused men to ride over our heads; we went through fire and through water: but thou broughtest us out into a wealthy place.","ref":"Psalms 66:12","synthesized":"You let men ride over our heads; we went through fire and water, but You brought us into abundance.","sources":{"KJV":{"text":"Thou hast caused men to ride over our heads; we went through fire and through water: but thou broughtest us out into a wealthy place."},"BSB":{"text":"You let men ride over our heads; we went through fire and water, but You brought us into abundance."}},"definableWords":["men","water"],"peopleInVerse":[]},"13":{"text":"I will go into thy house with burnt offerings: I will pay thee my vows,","ref":"Psalms 66:13","synthesized":"I will enter Your house with burnt offerings; I will fulfill my vows to You—","sources":{"KJV":{"text":"I will go into thy house with burnt offerings: I will pay thee my vows,"},"BSB":{"text":"I will enter Your house with burnt offerings; I will fulfill my vows to You—"}},"definableWords":["house"],"peopleInVerse":[]},"14":{"text":"Which my lips have uttered, and my mouth hath spoken, when I was in trouble.","ref":"Psalms 66:14","synthesized":"the vows that my lips promised and my mouth spoke in my distress.","sources":{"KJV":{"text":"Which my lips have uttered, and my mouth hath spoken, when I was in trouble."},"BSB":{"text":"the vows that my lips promised and my mouth spoke in my distress."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"I will offer unto thee burnt sacrifices of fatlings, with the incense of rams; I will offer bullocks with goats. Selah.","ref":"Psalms 66:15","synthesized":"I will offer You fatlings as burnt offerings, with the fragrant smoke of rams; I will offer bulls and goats. Selah","sources":{"KJV":{"text":"I will offer unto thee burnt sacrifices of fatlings, with the incense of rams; I will offer bullocks with goats. Selah."},"BSB":{"text":"I will offer You fatlings as burnt offerings, with the fragrant smoke of rams; I will offer bulls and goats. Selah"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Come and hear, all ye that fear God, and I will declare what he hath done for my soul.","ref":"Psalms 66:16","synthesized":"Come and listen, all you who fear God, and I will declare what He has done for me.","sources":{"KJV":{"text":"Come and hear, all ye that fear God, and I will declare what he hath done for my soul."},"BSB":{"text":"Come and listen, all you who fear God, and I will declare what He has done for me."}},"definableWords":["fear","God"],"peopleInVerse":[]},"17":{"text":"I cried unto him with my mouth, and he was extolled with my tongue.","ref":"Psalms 66:17","synthesized":"I cried out to Him with my mouth and praised Him with my tongue.","sources":{"KJV":{"text":"I cried unto him with my mouth, and he was extolled with my tongue."},"BSB":{"text":"I cried out to Him with my mouth and praised Him with my tongue."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"If I regard iniquity in my heart, the Lord will not hear me:","ref":"Psalms 66:18","synthesized":"If I had cherished iniquity in my heart, the Lord would not have listened.","sources":{"KJV":{"text":"If I regard iniquity in my heart, the Lord will not hear me:"},"BSB":{"text":"If I had cherished iniquity in my heart, the Lord would not have listened."}},"definableWords":["iniquity","heart","Lord"],"peopleInVerse":[]},"19":{"text":"But verily God hath heard me; he hath attended to the voice of my prayer.","ref":"Psalms 66:19","synthesized":"But God has surely heard; He has attended to the sound of my prayer.","sources":{"KJV":{"text":"But verily God hath heard me; he hath attended to the voice of my prayer."},"BSB":{"text":"But God has surely heard; He has attended to the sound of my prayer."}},"definableWords":["God","prayer"],"peopleInVerse":[]},"20":{"text":"Blessed be God, which hath not turned away my prayer, nor his mercy from me.","ref":"Psalms 66:20","synthesized":"Blessed be God, who has not rejected my prayer or withheld from me His loving devotion!","sources":{"KJV":{"text":"Blessed be God, which hath not turned away my prayer, nor his mercy from me."},"BSB":{"text":"Blessed be God, who has not rejected my prayer or withheld from me His loving devotion!"}},"definableWords":["blessed","God","prayer","or"],"peopleInVerse":[]}}},"67":{"chapter":"67","title":"GOD BE MERCIFUL UNTO US","verses":{"1":{"text":"God be merciful unto us, and bless us; and cause his face to shine upon us; Selah.","ref":"Psalms 67:1","synthesized":"May God be gracious to us and bless us, and cause His face to shine upon us, Selah","sources":{"KJV":{"text":"God be merciful unto us, and bless us; and cause his face to shine upon us; Selah."},"BSB":{"text":"May God be gracious to us and bless us, and cause His face to shine upon us, Selah"}},"definableWords":["God","bless"],"peopleInVerse":[]},"2":{"text":"That thy way may be known upon earth, thy saving health among all nations.","ref":"Psalms 67:2","synthesized":"that Your ways may be known on earth, Your salvation among all nations.","sources":{"KJV":{"text":"That thy way may be known upon earth, thy saving health among all nations."},"BSB":{"text":"that Your ways may be known on earth, Your salvation among all nations."}},"definableWords":["earth","salvation","nations"],"peopleInVerse":[]},"3":{"text":"Let the people praise thee, O God; let all the people praise thee.","ref":"Psalms 67:3","synthesized":"Let the peoples praise You, O God; let all the peoples praise You.","sources":{"KJV":{"text":"Let the people praise thee, O God; let all the people praise thee."},"BSB":{"text":"Let the peoples praise You, O God; let all the peoples praise You."}},"definableWords":["praise","God"],"peopleInVerse":[]},"4":{"text":"O let the nations be glad and sing for joy: for thou shalt judge the people righteously, and govern the nations upon earth. Selah.","ref":"Psalms 67:4","synthesized":"Let the nations be glad and sing for joy, for You judge the peoples justly and lead the nations of the earth. Selah","sources":{"KJV":{"text":"O let the nations be glad and sing for joy: for thou shalt judge the people righteously, and govern the nations upon earth. Selah."},"BSB":{"text":"Let the nations be glad and sing for joy, for You judge the peoples justly and lead the nations of the earth. Selah"}},"definableWords":["nations","joy","earth"],"peopleInVerse":[]},"5":{"text":"Let the people praise thee, O God; let all the people praise thee.","ref":"Psalms 67:5","synthesized":"Let the peoples praise You, O God; let all the peoples praise You.","sources":{"KJV":{"text":"Let the people praise thee, O God; let all the people praise thee."},"BSB":{"text":"Let the peoples praise You, O God; let all the peoples praise You."}},"definableWords":["praise","God"],"peopleInVerse":[]},"6":{"text":"Then shall the earth yield her increase; and God, even our own God, shall bless us.","ref":"Psalms 67:6","synthesized":"The earth has yielded its harvest; God, our God, blesses us.","sources":{"KJV":{"text":"Then shall the earth yield her increase; and God, even our own God, shall bless us."},"BSB":{"text":"The earth has yielded its harvest; God, our God, blesses us."}},"definableWords":["earth","God"],"peopleInVerse":[]},"7":{"text":"God shall bless us; and all the ends of the earth shall fear him.","ref":"Psalms 67:7","synthesized":"God blesses us, that all the ends of the earth shall fear Him.","sources":{"KJV":{"text":"God shall bless us; and all the ends of the earth shall fear him."},"BSB":{"text":"God blesses us, that all the ends of the earth shall fear Him."}},"definableWords":["God","earth","fear"],"peopleInVerse":[]}}},"68":{"chapter":"68","title":"LET GOD ARISE","verses":{"1":{"text":"Let God arise, let his enemies be scattered: let them also that hate him flee before him.","ref":"Psalms 68:1","synthesized":"God arises. His enemies are scattered, and those who hate Him flee His presence.","sources":{"KJV":{"text":"Let God arise, let his enemies be scattered: let them also that hate him flee before him."},"BSB":{"text":"God arises. His enemies are scattered, and those who hate Him flee His presence."}},"definableWords":["God"],"peopleInVerse":[]},"2":{"text":"As smoke is driven away, so drive them away: as wax melteth before the fire, so let the wicked perish at the presence of God.","ref":"Psalms 68:2","synthesized":"As smoke is blown away, You will drive them out; as wax melts before the fire, the wicked will perish in the presence of God.","sources":{"KJV":{"text":"As smoke is driven away, so drive them away: as wax melteth before the fire, so let the wicked perish at the presence of God."},"BSB":{"text":"As smoke is blown away, You will drive them out; as wax melts before the fire, the wicked will perish in the presence of God."}},"definableWords":["God"],"peopleInVerse":[]},"3":{"text":"But let the righteous be glad; let them rejoice before God: yea, let them exceedingly rejoice.","ref":"Psalms 68:3","synthesized":"But the righteous will be glad and rejoice before God; they will celebrate with joy.","sources":{"KJV":{"text":"But let the righteous be glad; let them rejoice before God: yea, let them exceedingly rejoice."},"BSB":{"text":"But the righteous will be glad and rejoice before God; they will celebrate with joy."}},"definableWords":["righteous","God","joy"],"peopleInVerse":[]},"4":{"text":"Sing unto God, sing praises to his name: extol him that rideth upon the heavens by his name JAH, and rejoice before him.","ref":"Psalms 68:4","synthesized":"Sing to God! Sing praises to His name. Exalt Him who rides on the clouds— His name is the LORD— and rejoice before Him.","sources":{"KJV":{"text":"Sing unto God, sing praises to his name: extol him that rideth upon the heavens by his name JAH, and rejoice before him."},"BSB":{"text":"Sing to God! Sing praises to His name. Exalt Him who rides on the clouds— His name is the LORD— and rejoice before Him."}},"definableWords":["God","name","LORD"],"peopleInVerse":[]},"5":{"text":"A father of the fatherless, and a judge of the widows, is God in his holy habitation.","ref":"Psalms 68:5","synthesized":"A father of the fatherless, and a defender of the widows, is God in His holy habitation.","sources":{"KJV":{"text":"A father of the fatherless, and a judge of the widows, is God in his holy habitation."},"BSB":{"text":"A father of the fatherless, and a defender of the widows, is God in His holy habitation."}},"definableWords":["father","God","holy"],"peopleInVerse":[]},"6":{"text":"God setteth the solitary in families: he bringeth out those which are bound with chains: but the rebellious dwell in a dry land.","ref":"Psalms 68:6","synthesized":"God settles the lonely in families; He leads the prisoners out to prosperity, but the rebellious dwell in a sun-scorched land.","sources":{"KJV":{"text":"God setteth the solitary in families: he bringeth out those which are bound with chains: but the rebellious dwell in a dry land."},"BSB":{"text":"God settles the lonely in families; He leads the prisoners out to prosperity, but the rebellious dwell in a sun-scorched land."}},"definableWords":["God","families","land"],"peopleInVerse":[]},"7":{"text":"O God, when thou wentest forth before thy people, when thou didst march through the wilderness; Selah:","ref":"Psalms 68:7","synthesized":"O God, when You went out before Your people, when You marched through the wasteland, Selah","sources":{"KJV":{"text":"O God, when thou wentest forth before thy people, when thou didst march through the wilderness; Selah:"},"BSB":{"text":"O God, when You went out before Your people, when You marched through the wasteland, Selah"}},"definableWords":["God","people"],"peopleInVerse":[]},"8":{"text":"The earth shook, the heavens also dropped at the presence of God: even Sinai itself was moved at the presence of God, the God of Israel.","ref":"Psalms 68:8","synthesized":"the earth shook and the heavens poured down rain before God, the One on Sinai, before God, the God of Israel.","sources":{"KJV":{"text":"The earth shook, the heavens also dropped at the presence of God: even Sinai itself was moved at the presence of God, the God of Israel."},"BSB":{"text":"the earth shook and the heavens poured down rain before God, the One on Sinai, before God, the God of Israel."}},"definableWords":["earth","heavens","God","one","Israel"],"peopleInVerse":[]},"9":{"text":"Thou, O God, didst send a plentiful rain, whereby thou didst confirm thine inheritance, when it was weary.","ref":"Psalms 68:9","synthesized":"You sent abundant rain, O God; You refreshed Your weary inheritance.","sources":{"KJV":{"text":"Thou, O God, didst send a plentiful rain, whereby thou didst confirm thine inheritance, when it was weary."},"BSB":{"text":"You sent abundant rain, O God; You refreshed Your weary inheritance."}},"definableWords":["God"],"peopleInVerse":[]},"10":{"text":"Thy congregation hath dwelt therein: thou, O God, hast prepared of thy goodness for the poor.","ref":"Psalms 68:10","synthesized":"Your flock settled therein; O God, from Your bounty You provided for the poor.","sources":{"KJV":{"text":"Thy congregation hath dwelt therein: thou, O God, hast prepared of thy goodness for the poor."},"BSB":{"text":"Your flock settled therein; O God, from Your bounty You provided for the poor."}},"definableWords":["God"],"peopleInVerse":[]},"11":{"text":"The Lord gave the word: great was the company of those that published it.","ref":"Psalms 68:11","synthesized":"The Lord gives the command; a great company of women proclaim it:","sources":{"KJV":{"text":"The Lord gave the word: great was the company of those that published it."},"BSB":{"text":"The Lord gives the command; a great company of women proclaim it:"}},"definableWords":["Lord","great","women"],"peopleInVerse":[]},"12":{"text":"Kings of armies did flee apace: and she that tarried at home divided the spoil.","ref":"Psalms 68:12","synthesized":"“Kings and their armies flee in haste; she who waits at home divides the plunder.","sources":{"KJV":{"text":"Kings of armies did flee apace: and she that tarried at home divided the spoil."},"BSB":{"text":"“Kings and their armies flee in haste; she who waits at home divides the plunder."}},"definableWords":["kings"],"peopleInVerse":[]},"13":{"text":"Though ye have lien among the pots, yet shall ye be as the wings of a dove covered with silver, and her feathers with yellow gold.","ref":"Psalms 68:13","synthesized":"Though you lie down among the sheepfolds, the wings of the dove are covered with silver, and her feathers with shimmering gold.”","sources":{"KJV":{"text":"Though ye have lien among the pots, yet shall ye be as the wings of a dove covered with silver, and her feathers with yellow gold."},"BSB":{"text":"Though you lie down among the sheepfolds, the wings of the dove are covered with silver, and her feathers with shimmering gold.”"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"When the Almighty scattered kings in it, it was white as snow in Salmon.","ref":"Psalms 68:14","synthesized":"When the Almighty scattered the kings in the land, it was like the snow falling on Zalmon.","sources":{"KJV":{"text":"When the Almighty scattered kings in it, it was white as snow in Salmon."},"BSB":{"text":"When the Almighty scattered the kings in the land, it was like the snow falling on Zalmon."}},"definableWords":["Almighty","kings","land"],"peopleInVerse":[]},"15":{"text":"The hill of God is as the hill of Bashan; an high hill as the hill of Bashan.","ref":"Psalms 68:15","synthesized":"A mountain of God is Mount Bashan; a mountain of many peaks is Mount Bashan.","sources":{"KJV":{"text":"The hill of God is as the hill of Bashan; an high hill as the hill of Bashan."},"BSB":{"text":"A mountain of God is Mount Bashan; a mountain of many peaks is Mount Bashan."}},"definableWords":["God"],"peopleInVerse":[]},"16":{"text":"Why leap ye, ye high hills? this is the hill which God desireth to dwell in; yea, the LORD will dwell in it for ever.","ref":"Psalms 68:16","synthesized":"Why do you gaze in envy, O mountains of many peaks? This is the mountain God chose for His dwelling, where the LORD will surely dwell forever.","sources":{"KJV":{"text":"Why leap ye, ye high hills? this is the hill which God desireth to dwell in; yea, the LORD will dwell in it for ever."},"BSB":{"text":"Why do you gaze in envy, O mountains of many peaks? This is the mountain God chose for His dwelling, where the LORD will surely dwell forever."}},"definableWords":["God","LORD"],"peopleInVerse":[]},"17":{"text":"The chariots of God are twenty thousand, even thousands of angels: the Lord is among them, as in Sinai, in the holy place.","ref":"Psalms 68:17","synthesized":"The chariots of God are tens of thousands— thousands of thousands are they; the Lord is in His sanctuary as He was at Sinai.","sources":{"KJV":{"text":"The chariots of God are twenty thousand, even thousands of angels: the Lord is among them, as in Sinai, in the holy place."},"BSB":{"text":"The chariots of God are tens of thousands— thousands of thousands are they; the Lord is in His sanctuary as He was at Sinai."}},"definableWords":["God","Lord"],"peopleInVerse":[]},"18":{"text":"Thou hast ascended on high, thou hast led captivity captive: thou hast received gifts for men; yea, for the rebellious also, that the LORD God might dwell among them.","ref":"Psalms 68:18","synthesized":"You have ascended on high; You have led captives away. You have received gifts from men, even from the rebellious, that the LORD God may dwell there.","sources":{"KJV":{"text":"Thou hast ascended on high, thou hast led captivity captive: thou hast received gifts for men; yea, for the rebellious also, that the LORD God might dwell among them."},"BSB":{"text":"You have ascended on high; You have led captives away. You have received gifts from men, even from the rebellious, that the LORD God may dwell there."}},"definableWords":["men","LORD","God"],"peopleInVerse":[]},"19":{"text":"Blessed be the Lord, who daily loadeth us with benefits, even the God of our salvation. Selah.","ref":"Psalms 68:19","synthesized":"Blessed be the Lord, who daily bears our burden, the God of our salvation. Selah","sources":{"KJV":{"text":"Blessed be the Lord, who daily loadeth us with benefits, even the God of our salvation. Selah."},"BSB":{"text":"Blessed be the Lord, who daily bears our burden, the God of our salvation. Selah"}},"definableWords":["blessed","Lord","God","salvation"],"peopleInVerse":[]},"20":{"text":"He that is our God is the God of salvation; and unto GOD the Lord belong the issues from death.","ref":"Psalms 68:20","synthesized":"Our God is a God of deliverance; the Lord GOD is our rescuer from death.","sources":{"KJV":{"text":"He that is our God is the God of salvation; and unto GOD the Lord belong the issues from death."},"BSB":{"text":"Our God is a God of deliverance; the Lord GOD is our rescuer from death."}},"definableWords":["God","Lord","death"],"peopleInVerse":[]},"21":{"text":"But God shall wound the head of his enemies, and the hairy scalp of such an one as goeth on still in his trespasses.","ref":"Psalms 68:21","synthesized":"Surely God will crush the heads of His enemies, the hairy crowns of those who persist in guilty ways.","sources":{"KJV":{"text":"But God shall wound the head of his enemies, and the hairy scalp of such an one as goeth on still in his trespasses."},"BSB":{"text":"Surely God will crush the heads of His enemies, the hairy crowns of those who persist in guilty ways."}},"definableWords":["God"],"peopleInVerse":[]},"22":{"text":"The Lord said, I will bring again from Bashan, I will bring my people again from the depths of the sea:","ref":"Psalms 68:22","synthesized":"The Lord said, “I will retrieve them from Bashan, I will bring them up from the depths of the sea,","sources":{"KJV":{"text":"The Lord said, I will bring again from Bashan, I will bring my people again from the depths of the sea:"},"BSB":{"text":"The Lord said, “I will retrieve them from Bashan, I will bring them up from the depths of the sea,"}},"definableWords":["Lord","sea"],"peopleInVerse":[]},"23":{"text":"That thy foot may be dipped in the blood of thine enemies, and the tongue of thy dogs in the same.","ref":"Psalms 68:23","synthesized":"that your foot may be dipped in the blood of your foes— the tongues of your dogs in the same.”","sources":{"KJV":{"text":"That thy foot may be dipped in the blood of thine enemies, and the tongue of thy dogs in the same."},"BSB":{"text":"that your foot may be dipped in the blood of your foes— the tongues of your dogs in the same.”"}},"definableWords":["blood"],"peopleInVerse":[]},"24":{"text":"They have seen thy goings, O God; even the goings of my God, my King, in the sanctuary.","ref":"Psalms 68:24","synthesized":"They have seen Your procession, O God— the march of my God and King into the sanctuary.","sources":{"KJV":{"text":"They have seen thy goings, O God; even the goings of my God, my King, in the sanctuary."},"BSB":{"text":"They have seen Your procession, O God— the march of my God and King into the sanctuary."}},"definableWords":["God","King"],"peopleInVerse":[]},"25":{"text":"The singers went before, the players on instruments followed after; among them were the damsels playing with timbrels.","ref":"Psalms 68:25","synthesized":"The singers lead the way, the musicians follow after, among the maidens playing tambourines.","sources":{"KJV":{"text":"The singers went before, the players on instruments followed after; among them were the damsels playing with timbrels."},"BSB":{"text":"The singers lead the way, the musicians follow after, among the maidens playing tambourines."}},"definableWords":["way"],"peopleInVerse":[]},"26":{"text":"Bless ye God in the congregations, even the Lord, from the fountain of Israel.","ref":"Psalms 68:26","synthesized":"Bless God in the great congregation; bless the LORD from the fountain of Israel.","sources":{"KJV":{"text":"Bless ye God in the congregations, even the Lord, from the fountain of Israel."},"BSB":{"text":"Bless God in the great congregation; bless the LORD from the fountain of Israel."}},"definableWords":["bless","God","great","LORD","Israel"],"peopleInVerse":[]},"27":{"text":"There is little Benjamin with their ruler, the princes of Judah and their council, the princes of Zebulun, and the princes of Naphtali.","ref":"Psalms 68:27","synthesized":"There is Benjamin, the youngest, ruling them, the princes of Judah in their company, the princes of Zebulun and of Naphtali.","sources":{"KJV":{"text":"There is little Benjamin with their ruler, the princes of Judah and their council, the princes of Zebulun, and the princes of Naphtali."},"BSB":{"text":"There is Benjamin, the youngest, ruling them, the princes of Judah in their company, the princes of Zebulun and of Naphtali."}},"definableWords":["Benjamin","Judah"],"peopleInVerse":[]},"28":{"text":"Thy God hath commanded thy strength: strengthen, O God, that which thou hast wrought for us.","ref":"Psalms 68:28","synthesized":"Summon Your power, O God; show Your strength, O God, which You have exerted on our behalf.","sources":{"KJV":{"text":"Thy God hath commanded thy strength: strengthen, O God, that which thou hast wrought for us."},"BSB":{"text":"Summon Your power, O God; show Your strength, O God, which You have exerted on our behalf."}},"definableWords":["God"],"peopleInVerse":[]},"29":{"text":"Because of thy temple at Jerusalem shall kings bring presents unto thee.","ref":"Psalms 68:29","synthesized":"Because of Your temple at Jerusalem kings will bring You gifts.","sources":{"KJV":{"text":"Because of thy temple at Jerusalem shall kings bring presents unto thee."},"BSB":{"text":"Because of Your temple at Jerusalem kings will bring You gifts."}},"definableWords":["temple","Jerusalem","kings"],"peopleInVerse":[]},"30":{"text":"Rebuke the company of spearmen, the multitude of the bulls, with the calves of the people, till every one submit himself with pieces of silver: scatter thou the people that delight in war.","ref":"Psalms 68:30","synthesized":"Rebuke the beast in the reeds, the herd of bulls among the calves of the nations, until it submits, bringing bars of silver. Scatter the nations who delight in war.","sources":{"KJV":{"text":"Rebuke the company of spearmen, the multitude of the bulls, with the calves of the people, till every one submit himself with pieces of silver: scatter thou the people that delight in war."},"BSB":{"text":"Rebuke the beast in the reeds, the herd of bulls among the calves of the nations, until it submits, bringing bars of silver. Scatter the nations who delight in war."}},"definableWords":["nations"],"peopleInVerse":[]},"31":{"text":"Princes shall come out of Egypt; Ethiopia shall soon stretch out her hands unto God.","ref":"Psalms 68:31","synthesized":"Envoys will arrive from Egypt; Cush will stretch out her hands to God.","sources":{"KJV":{"text":"Princes shall come out of Egypt; Ethiopia shall soon stretch out her hands unto God."},"BSB":{"text":"Envoys will arrive from Egypt; Cush will stretch out her hands to God."}},"definableWords":["Egypt","God"],"peopleInVerse":["Cush"]},"32":{"text":"Sing unto God, ye kingdoms of the earth; O sing praises unto the Lord; Selah:","ref":"Psalms 68:32","synthesized":"Sing to God, O kingdoms of the earth; sing praises to the Lord— Selah","sources":{"KJV":{"text":"Sing unto God, ye kingdoms of the earth; O sing praises unto the Lord; Selah:"},"BSB":{"text":"Sing to God, O kingdoms of the earth; sing praises to the Lord— Selah"}},"definableWords":["God","earth","Lord"],"peopleInVerse":[]},"33":{"text":"To him that rideth upon the heavens of heavens, which were of old; lo, he doth send out his voice, and that a mighty voice.","ref":"Psalms 68:33","synthesized":"to Him who rides upon the highest heavens of old; behold, His mighty voice resounds.","sources":{"KJV":{"text":"To him that rideth upon the heavens of heavens, which were of old; lo, he doth send out his voice, and that a mighty voice."},"BSB":{"text":"to Him who rides upon the highest heavens of old; behold, His mighty voice resounds."}},"definableWords":["heavens","mighty","voice"],"peopleInVerse":[]},"34":{"text":"Ascribe ye strength unto God: his excellency is over Israel, and his strength is in the clouds.","ref":"Psalms 68:34","synthesized":"Ascribe the power to God, whose majesty is over Israel, whose strength is in the skies.","sources":{"KJV":{"text":"Ascribe ye strength unto God: his excellency is over Israel, and his strength is in the clouds."},"BSB":{"text":"Ascribe the power to God, whose majesty is over Israel, whose strength is in the skies."}},"definableWords":["God","Israel"],"peopleInVerse":[]},"35":{"text":"O God, thou art terrible out of thy holy places: the God of Israel is he that giveth strength and power unto his people. Blessed be God.","ref":"Psalms 68:35","synthesized":"O God, You are awesome in Your sanctuary; the God of Israel Himself gives strength and power to His people.   Blessed be God!","sources":{"KJV":{"text":"O God, thou art terrible out of thy holy places: the God of Israel is he that giveth strength and power unto his people. Blessed be God."},"BSB":{"text":"O God, You are awesome in Your sanctuary; the God of Israel Himself gives strength and power to His people.   Blessed be God!"}},"definableWords":["God","Israel","people","blessed"],"peopleInVerse":[]}}},"69":{"chapter":"69","title":"SAVE ME, O GOD","verses":{"1":{"text":"Save me, O God; for the waters are come in unto my soul.","ref":"Psalms 69:1","synthesized":"Save me, O God, for the waters are up to my neck.","sources":{"KJV":{"text":"Save me, O God; for the waters are come in unto my soul."},"BSB":{"text":"Save me, O God, for the waters are up to my neck."}},"definableWords":["God","waters"],"peopleInVerse":[]},"2":{"text":"I sink in deep mire, where there is no standing: I am come into deep waters, where the floods overflow me.","ref":"Psalms 69:2","synthesized":"I have sunk into the miry depths, where there is no footing; I have drifted into deep waters, where the flood engulfs me.","sources":{"KJV":{"text":"I sink in deep mire, where there is no standing: I am come into deep waters, where the floods overflow me."},"BSB":{"text":"I have sunk into the miry depths, where there is no footing; I have drifted into deep waters, where the flood engulfs me."}},"definableWords":["deep","waters","flood"],"peopleInVerse":[]},"3":{"text":"I am weary of my crying: my throat is dried: mine eyes fail while I wait for my God.","ref":"Psalms 69:3","synthesized":"I am weary from my crying; my throat is parched. My eyes fail, looking for my God.","sources":{"KJV":{"text":"I am weary of my crying: my throat is dried: mine eyes fail while I wait for my God."},"BSB":{"text":"I am weary from my crying; my throat is parched. My eyes fail, looking for my God."}},"definableWords":["God"],"peopleInVerse":[]},"4":{"text":"They that hate me without a cause are more than the hairs of mine head: they that would destroy me, being mine enemies wrongfully, are mighty: then I restored that which I took not away.","ref":"Psalms 69:4","synthesized":"Those who hate me without cause outnumber the hairs of my head; many are those who would destroy me— my enemies for no reason. Though I did not steal, I must repay.","sources":{"KJV":{"text":"They that hate me without a cause are more than the hairs of mine head: they that would destroy me, being mine enemies wrongfully, are mighty: then I restored that which I took not away."},"BSB":{"text":"Those who hate me without cause outnumber the hairs of my head; many are those who would destroy me— my enemies for no reason. Though I did not steal, I must repay."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"O God, thou knowest my foolishness; and my sins are not hid from thee.","ref":"Psalms 69:5","synthesized":"You know my folly, O God, and my guilt is not hidden from You.","sources":{"KJV":{"text":"O God, thou knowest my foolishness; and my sins are not hid from thee."},"BSB":{"text":"You know my folly, O God, and my guilt is not hidden from You."}},"definableWords":["God"],"peopleInVerse":[]},"6":{"text":"Let not them that wait on thee, O Lord GOD of hosts, be ashamed for my sake: let not those that seek thee be confounded for my sake, O God of Israel.","ref":"Psalms 69:6","synthesized":"May those who hope in You not be ashamed through me, O Lord GOD of Hosts; may those who seek You not be dishonored through me, O God of Israel.","sources":{"KJV":{"text":"Let not them that wait on thee, O Lord GOD of hosts, be ashamed for my sake: let not those that seek thee be confounded for my sake, O God of Israel."},"BSB":{"text":"May those who hope in You not be ashamed through me, O Lord GOD of Hosts; may those who seek You not be dishonored through me, O God of Israel."}},"definableWords":["hope","Lord","God","seek","Israel"],"peopleInVerse":[]},"7":{"text":"Because for thy sake I have borne reproach; shame hath covered my face.","ref":"Psalms 69:7","synthesized":"For I have endured scorn for Your sake, and shame has covered my face.","sources":{"KJV":{"text":"Because for thy sake I have borne reproach; shame hath covered my face."},"BSB":{"text":"For I have endured scorn for Your sake, and shame has covered my face."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"I am become a stranger unto my brethren, and an alien unto my mother’s children.","ref":"Psalms 69:8","synthesized":"I have become a stranger to my brothers and a foreigner to my mother’s sons,","sources":{"KJV":{"text":"I am become a stranger unto my brethren, and an alien unto my mother’s children."},"BSB":{"text":"I have become a stranger to my brothers and a foreigner to my mother’s sons,"}},"definableWords":["stranger","mother","sons"],"peopleInVerse":[]},"9":{"text":"For the zeal of thine house hath eaten me up; and the reproaches of them that reproached thee are fallen upon me.","ref":"Psalms 69:9","synthesized":"because zeal for Your house has consumed me, and the insults of those who insult You have fallen on me.","sources":{"KJV":{"text":"For the zeal of thine house hath eaten me up; and the reproaches of them that reproached thee are fallen upon me."},"BSB":{"text":"because zeal for Your house has consumed me, and the insults of those who insult You have fallen on me."}},"definableWords":["house"],"peopleInVerse":[]},"10":{"text":"When I wept, and chastened my soul with fasting, that was to my reproach.","ref":"Psalms 69:10","synthesized":"I wept and fasted, but it brought me reproach.","sources":{"KJV":{"text":"When I wept, and chastened my soul with fasting, that was to my reproach."},"BSB":{"text":"I wept and fasted, but it brought me reproach."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"I made sackcloth also my garment; and I became a proverb to them.","ref":"Psalms 69:11","synthesized":"I made sackcloth my clothing, and I was sport to them.","sources":{"KJV":{"text":"I made sackcloth also my garment; and I became a proverb to them."},"BSB":{"text":"I made sackcloth my clothing, and I was sport to them."}},"definableWords":["made"],"peopleInVerse":[]},"12":{"text":"They that sit in the gate speak against me; and I was the song of the drunkards.","ref":"Psalms 69:12","synthesized":"Those who sit at the gate mock me, and I am the song of drunkards.","sources":{"KJV":{"text":"They that sit in the gate speak against me; and I was the song of the drunkards."},"BSB":{"text":"Those who sit at the gate mock me, and I am the song of drunkards."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"But as for me, my prayer is unto thee, O LORD, in an acceptable time: O God, in the multitude of thy mercy hear me, in the truth of thy salvation.","ref":"Psalms 69:13","synthesized":"But my prayer to You, O LORD, is for a time of favor. In Your abundant loving devotion, O God, answer me with Your sure salvation.","sources":{"KJV":{"text":"But as for me, my prayer is unto thee, O LORD, in an acceptable time: O God, in the multitude of thy mercy hear me, in the truth of thy salvation."},"BSB":{"text":"But my prayer to You, O LORD, is for a time of favor. In Your abundant loving devotion, O God, answer me with Your sure salvation."}},"definableWords":["prayer","LORD","God","salvation"],"peopleInVerse":[]},"14":{"text":"Deliver me out of the mire, and let me not sink: let me be delivered from them that hate me, and out of the deep waters.","ref":"Psalms 69:14","synthesized":"Rescue me from the mire and do not let me sink; deliver me from my foes and out of the deep waters.","sources":{"KJV":{"text":"Deliver me out of the mire, and let me not sink: let me be delivered from them that hate me, and out of the deep waters."},"BSB":{"text":"Rescue me from the mire and do not let me sink; deliver me from my foes and out of the deep waters."}},"definableWords":["deliver","deep","waters"],"peopleInVerse":[]},"15":{"text":"Let not the waterflood overflow me, neither let the deep swallow me up, and let not the pit shut her mouth upon me.","ref":"Psalms 69:15","synthesized":"Do not let the floods engulf me or the depths swallow me up; let not the Pit close its mouth over me.","sources":{"KJV":{"text":"Let not the waterflood overflow me, neither let the deep swallow me up, and let not the pit shut her mouth upon me."},"BSB":{"text":"Do not let the floods engulf me or the depths swallow me up; let not the Pit close its mouth over me."}},"definableWords":["or"],"peopleInVerse":[]},"16":{"text":"Hear me, O LORD; for thy lovingkindness is good: turn unto me according to the multitude of thy tender mercies.","ref":"Psalms 69:16","synthesized":"Answer me, O LORD, for Your loving devotion is good; turn to me in keeping with Your great compassion.","sources":{"KJV":{"text":"Hear me, O LORD; for thy lovingkindness is good: turn unto me according to the multitude of thy tender mercies."},"BSB":{"text":"Answer me, O LORD, for Your loving devotion is good; turn to me in keeping with Your great compassion."}},"definableWords":["LORD","good","great"],"peopleInVerse":[]},"17":{"text":"And hide not thy face from thy servant; for I am in trouble: hear me speedily.","ref":"Psalms 69:17","synthesized":"Hide not Your face from Your servant, for I am in distress. Answer me quickly!","sources":{"KJV":{"text":"And hide not thy face from thy servant; for I am in trouble: hear me speedily."},"BSB":{"text":"Hide not Your face from Your servant, for I am in distress. Answer me quickly!"}},"definableWords":["servant"],"peopleInVerse":[]},"18":{"text":"Draw nigh unto my soul, and redeem it: deliver me because of mine enemies.","ref":"Psalms 69:18","synthesized":"Draw near to my soul and redeem me; ransom me because of my foes.","sources":{"KJV":{"text":"Draw nigh unto my soul, and redeem it: deliver me because of mine enemies."},"BSB":{"text":"Draw near to my soul and redeem me; ransom me because of my foes."}},"definableWords":["soul"],"peopleInVerse":[]},"19":{"text":"Thou hast known my reproach, and my shame, and my dishonour: mine adversaries are all before thee.","ref":"Psalms 69:19","synthesized":"You know my reproach, my shame and disgrace. All my adversaries are before You.","sources":{"KJV":{"text":"Thou hast known my reproach, and my shame, and my dishonour: mine adversaries are all before thee."},"BSB":{"text":"You know my reproach, my shame and disgrace. All my adversaries are before You."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Reproach hath broken my heart; and I am full of heaviness: and I looked for some to take pity, but there was none; and for comforters, but I found none.","ref":"Psalms 69:20","synthesized":"Insults have broken my heart, and I am in despair. I looked for sympathy, but there was none, for comforters, but I found no one.","sources":{"KJV":{"text":"Reproach hath broken my heart; and I am full of heaviness: and I looked for some to take pity, but there was none; and for comforters, but I found none."},"BSB":{"text":"Insults have broken my heart, and I am in despair. I looked for sympathy, but there was none, for comforters, but I found no one."}},"definableWords":["heart","one"],"peopleInVerse":[]},"21":{"text":"They gave me also gall for my meat; and in my thirst they gave me vinegar to drink.","ref":"Psalms 69:21","synthesized":"They poisoned my food with gall and gave me vinegar to quench my thirst.","sources":{"KJV":{"text":"They gave me also gall for my meat; and in my thirst they gave me vinegar to drink."},"BSB":{"text":"They poisoned my food with gall and gave me vinegar to quench my thirst."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Let their table become a snare before them: and that which should have been for their welfare, let it become a trap.","ref":"Psalms 69:22","synthesized":"May their table become a snare; may it be a retribution and a trap.","sources":{"KJV":{"text":"Let their table become a snare before them: and that which should have been for their welfare, let it become a trap."},"BSB":{"text":"May their table become a snare; may it be a retribution and a trap."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Let their eyes be darkened, that they see not; and make their loins continually to shake.","ref":"Psalms 69:23","synthesized":"May their eyes be darkened so they cannot see, and their backs be bent forever.","sources":{"KJV":{"text":"Let their eyes be darkened, that they see not; and make their loins continually to shake."},"BSB":{"text":"May their eyes be darkened so they cannot see, and their backs be bent forever."}},"definableWords":["see"],"peopleInVerse":[]},"24":{"text":"Pour out thine indignation upon them, and let thy wrathful anger take hold of them.","ref":"Psalms 69:24","synthesized":"Pour out Your wrath upon them, and let Your burning anger overtake them.","sources":{"KJV":{"text":"Pour out thine indignation upon them, and let thy wrathful anger take hold of them."},"BSB":{"text":"Pour out Your wrath upon them, and let Your burning anger overtake them."}},"definableWords":["wrath","anger"],"peopleInVerse":[]},"25":{"text":"Let their habitation be desolate; and let none dwell in their tents.","ref":"Psalms 69:25","synthesized":"May their place be deserted; let there be no one to dwell in their tents.","sources":{"KJV":{"text":"Let their habitation be desolate; and let none dwell in their tents."},"BSB":{"text":"May their place be deserted; let there be no one to dwell in their tents."}},"definableWords":["one"],"peopleInVerse":[]},"26":{"text":"For they persecute him whom thou hast smitten; and they talk to the grief of those whom thou hast wounded.","ref":"Psalms 69:26","synthesized":"For they persecute the one You struck and recount the pain of those You wounded.","sources":{"KJV":{"text":"For they persecute him whom thou hast smitten; and they talk to the grief of those whom thou hast wounded."},"BSB":{"text":"For they persecute the one You struck and recount the pain of those You wounded."}},"definableWords":["one"],"peopleInVerse":[]},"27":{"text":"Add iniquity unto their iniquity: and let them not come into thy righteousness.","ref":"Psalms 69:27","synthesized":"Add iniquity to their iniquity; let them not share in Your righteousness.","sources":{"KJV":{"text":"Add iniquity unto their iniquity: and let them not come into thy righteousness."},"BSB":{"text":"Add iniquity to their iniquity; let them not share in Your righteousness."}},"definableWords":["iniquity","righteousness"],"peopleInVerse":[]},"28":{"text":"Let them be blotted out of the book of the living, and not be written with the righteous.","ref":"Psalms 69:28","synthesized":"May they be blotted out of the Book of Life and not listed with the righteous.","sources":{"KJV":{"text":"Let them be blotted out of the book of the living, and not be written with the righteous."},"BSB":{"text":"May they be blotted out of the Book of Life and not listed with the righteous."}},"definableWords":["life","righteous"],"peopleInVerse":[]},"29":{"text":"But I am poor and sorrowful: let thy salvation, O God, set me up on high.","ref":"Psalms 69:29","synthesized":"But I am in pain and distress; let Your salvation protect me, O God.","sources":{"KJV":{"text":"But I am poor and sorrowful: let thy salvation, O God, set me up on high."},"BSB":{"text":"But I am in pain and distress; let Your salvation protect me, O God."}},"definableWords":["salvation","God"],"peopleInVerse":[]},"30":{"text":"I will praise the name of God with a song, and will magnify him with thanksgiving.","ref":"Psalms 69:30","synthesized":"I will praise God’s name in song and exalt Him with thanksgiving.","sources":{"KJV":{"text":"I will praise the name of God with a song, and will magnify him with thanksgiving."},"BSB":{"text":"I will praise God’s name in song and exalt Him with thanksgiving."}},"definableWords":["praise","God","name"],"peopleInVerse":[]},"31":{"text":"This also shall please the LORD better than an ox or bullock that hath horns and hoofs.","ref":"Psalms 69:31","synthesized":"And this will please the LORD more than an ox, more than a bull with horns and hooves.","sources":{"KJV":{"text":"This also shall please the LORD better than an ox or bullock that hath horns and hoofs."},"BSB":{"text":"And this will please the LORD more than an ox, more than a bull with horns and hooves."}},"definableWords":["LORD"],"peopleInVerse":[]},"32":{"text":"The humble shall see this, and be glad: and your heart shall live that seek God.","ref":"Psalms 69:32","synthesized":"The humble will see and rejoice. You who seek God, let your hearts be revived!","sources":{"KJV":{"text":"The humble shall see this, and be glad: and your heart shall live that seek God."},"BSB":{"text":"The humble will see and rejoice. You who seek God, let your hearts be revived!"}},"definableWords":["see","seek","God"],"peopleInVerse":[]},"33":{"text":"For the LORD heareth the poor, and despiseth not his prisoners.","ref":"Psalms 69:33","synthesized":"For the LORD listens to the needy and does not despise His captive people.","sources":{"KJV":{"text":"For the LORD heareth the poor, and despiseth not his prisoners."},"BSB":{"text":"For the LORD listens to the needy and does not despise His captive people."}},"definableWords":["LORD","people"],"peopleInVerse":[]},"34":{"text":"Let the heaven and earth praise him, the seas, and every thing that moveth therein.","ref":"Psalms 69:34","synthesized":"Let heaven and earth praise Him, the seas and everything that moves in them.","sources":{"KJV":{"text":"Let the heaven and earth praise him, the seas, and every thing that moveth therein."},"BSB":{"text":"Let heaven and earth praise Him, the seas and everything that moves in them."}},"definableWords":["heaven","earth","praise","seas"],"peopleInVerse":[]},"35":{"text":"For God will save Zion, and will build the cities of Judah: that they may dwell there, and have it in possession.","ref":"Psalms 69:35","synthesized":"For God will save Zion and rebuild the cities of Judah, that they may dwell there and possess it.","sources":{"KJV":{"text":"For God will save Zion, and will build the cities of Judah: that they may dwell there, and have it in possession."},"BSB":{"text":"For God will save Zion and rebuild the cities of Judah, that they may dwell there and possess it."}},"definableWords":["God","Zion","Judah"],"peopleInVerse":[]},"36":{"text":"The seed also of his servants shall inherit it: and they that love his name shall dwell therein.","ref":"Psalms 69:36","synthesized":"The descendants of His servants will inherit it, and those who love His name will settle in it.","sources":{"KJV":{"text":"The seed also of his servants shall inherit it: and they that love his name shall dwell therein."},"BSB":{"text":"The descendants of His servants will inherit it, and those who love His name will settle in it."}},"definableWords":["servants","inherit","love","name"],"peopleInVerse":[]}}},"70":{"chapter":"70","title":"MAKE HASTE TO HELP ME","verses":{"1":{"text":"MAKE HASTE, O GOD, TO DELIVER ME; MAKE HASTE TO HELP ME, O LORD.","ref":"Psalms 70:1","synthesized":"Make haste, O God, to deliver me! Hurry, O LORD, to help me!","sources":{"KJV":{"text":"MAKE HASTE, O GOD, TO DELIVER ME; MAKE HASTE TO HELP ME, O LORD."},"BSB":{"text":"Make haste, O God, to deliver me! Hurry, O LORD, to help me!"}},"definableWords":["make","God","deliver","LORD"],"peopleInVerse":[]},"2":{"text":"Let them be ashamed and confounded that seek after my soul: let them be turned backward, and put to confusion, that desire my hurt.","ref":"Psalms 70:2","synthesized":"May those who seek my life be ashamed and confounded; may those who wish me harm be repelled and humiliated.","sources":{"KJV":{"text":"Let them be ashamed and confounded that seek after my soul: let them be turned backward, and put to confusion, that desire my hurt."},"BSB":{"text":"May those who seek my life be ashamed and confounded; may those who wish me harm be repelled and humiliated."}},"definableWords":["seek","life"],"peopleInVerse":[]},"3":{"text":"Let them be turned back for a reward of their shame that say, Aha, aha.","ref":"Psalms 70:3","synthesized":"May those who say, “Aha, aha!” retreat because of their shame.","sources":{"KJV":{"text":"Let them be turned back for a reward of their shame that say, Aha, aha."},"BSB":{"text":"May those who say, “Aha, aha!” retreat because of their shame."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Let all those that seek thee rejoice and be glad in thee: and let such as love thy salvation say continually, Let God be magnified.","ref":"Psalms 70:4","synthesized":"May all who seek You rejoice and be glad in You; may those who love Your salvation always say, “Let God be magnified!”","sources":{"KJV":{"text":"Let all those that seek thee rejoice and be glad in thee: and let such as love thy salvation say continually, Let God be magnified."},"BSB":{"text":"May all who seek You rejoice and be glad in You; may those who love Your salvation always say, “Let God be magnified!”"}},"definableWords":["seek","love","salvation","God"],"peopleInVerse":[]},"5":{"text":"But I am poor and needy: make haste unto me, O God: thou art my help and my deliverer; O LORD, make no tarrying.","ref":"Psalms 70:5","synthesized":"But I am poor and needy; hurry to me, O God. You are my help and my deliverer; O LORD, do not delay.","sources":{"KJV":{"text":"But I am poor and needy: make haste unto me, O God: thou art my help and my deliverer; O LORD, make no tarrying."},"BSB":{"text":"But I am poor and needy; hurry to me, O God. You are my help and my deliverer; O LORD, do not delay."}},"definableWords":["God","LORD"],"peopleInVerse":[]}}},"71":{"chapter":"71","title":"IN THEE, O LORD, DO I PUT MY TRUST","verses":{"1":{"text":"In thee, O LORD, do I put my trust: let me never be put to confusion.","ref":"Psalms 71:1","synthesized":"In You, O LORD, I have taken refuge; let me never be put to shame.","sources":{"KJV":{"text":"In thee, O LORD, do I put my trust: let me never be put to confusion."},"BSB":{"text":"In You, O LORD, I have taken refuge; let me never be put to shame."}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"Deliver me in thy righteousness, and cause me to escape: incline thine ear unto me, and save me.","ref":"Psalms 71:2","synthesized":"In Your justice, rescue and deliver me; incline Your ear and save me.","sources":{"KJV":{"text":"Deliver me in thy righteousness, and cause me to escape: incline thine ear unto me, and save me."},"BSB":{"text":"In Your justice, rescue and deliver me; incline Your ear and save me."}},"definableWords":["justice","deliver"],"peopleInVerse":[]},"3":{"text":"Be thou my strong habitation, whereunto I may continually resort: thou hast given commandment to save me; for thou art my rock and my fortress.","ref":"Psalms 71:3","synthesized":"Be my rock of refuge, where I can always go. Give the command to save me, for You are my rock and my fortress.","sources":{"KJV":{"text":"Be thou my strong habitation, whereunto I may continually resort: thou hast given commandment to save me; for thou art my rock and my fortress."},"BSB":{"text":"Be my rock of refuge, where I can always go. Give the command to save me, for You are my rock and my fortress."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Deliver me, O my God, out of the hand of the wicked, out of the hand of the unrighteous and cruel man.","ref":"Psalms 71:4","synthesized":"Deliver me, O my God, from the hand of the wicked, from the grasp of the unjust and ruthless.","sources":{"KJV":{"text":"Deliver me, O my God, out of the hand of the wicked, out of the hand of the unrighteous and cruel man."},"BSB":{"text":"Deliver me, O my God, from the hand of the wicked, from the grasp of the unjust and ruthless."}},"definableWords":["deliver","God"],"peopleInVerse":[]},"5":{"text":"For thou art my hope, O Lord GOD: thou art my trust from my youth.","ref":"Psalms 71:5","synthesized":"For You are my hope, O Lord GOD, my confidence from my youth.","sources":{"KJV":{"text":"For thou art my hope, O Lord GOD: thou art my trust from my youth."},"BSB":{"text":"For You are my hope, O Lord GOD, my confidence from my youth."}},"definableWords":["hope","Lord","God"],"peopleInVerse":[]},"6":{"text":"By thee have I been holden up from the womb: thou art he that took me out of my mother’s bowels: my praise shall be continually of thee.","ref":"Psalms 71:6","synthesized":"I have leaned on You since birth; You pulled me from my mother’s womb. My praise is always for You.","sources":{"KJV":{"text":"By thee have I been holden up from the womb: thou art he that took me out of my mother’s bowels: my praise shall be continually of thee."},"BSB":{"text":"I have leaned on You since birth; You pulled me from my mother’s womb. My praise is always for You."}},"definableWords":["mother","praise"],"peopleInVerse":[]},"7":{"text":"I am as a wonder unto many; but thou art my strong refuge.","ref":"Psalms 71:7","synthesized":"I have become a portent to many, but You are my strong refuge.","sources":{"KJV":{"text":"I am as a wonder unto many; but thou art my strong refuge."},"BSB":{"text":"I have become a portent to many, but You are my strong refuge."}},"definableWords":["strong"],"peopleInVerse":[]},"8":{"text":"Let my mouth be filled with thy praise and with thy honour all the day.","ref":"Psalms 71:8","synthesized":"My mouth is filled with Your praise and with Your splendor all day long.","sources":{"KJV":{"text":"Let my mouth be filled with thy praise and with thy honour all the day."},"BSB":{"text":"My mouth is filled with Your praise and with Your splendor all day long."}},"definableWords":["praise","day"],"peopleInVerse":[]},"9":{"text":"Cast me not off in the time of old age; forsake me not when my strength faileth.","ref":"Psalms 71:9","synthesized":"Do not discard me in my old age; do not forsake me when my strength fails.","sources":{"KJV":{"text":"Cast me not off in the time of old age; forsake me not when my strength faileth."},"BSB":{"text":"Do not discard me in my old age; do not forsake me when my strength fails."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For mine enemies speak against me; and they that lay wait for my soul take counsel together,","ref":"Psalms 71:10","synthesized":"For my enemies speak against me, and those who lie in wait for my life conspire,","sources":{"KJV":{"text":"For mine enemies speak against me; and they that lay wait for my soul take counsel together,"},"BSB":{"text":"For my enemies speak against me, and those who lie in wait for my life conspire,"}},"definableWords":["wait","life"],"peopleInVerse":[]},"11":{"text":"Saying, God hath forsaken him: persecute and take him; for there is none to deliver him.","ref":"Psalms 71:11","synthesized":"saying, “God has forsaken him; pursue him and seize him, for there is no one to rescue him.”","sources":{"KJV":{"text":"Saying, God hath forsaken him: persecute and take him; for there is none to deliver him."},"BSB":{"text":"saying, “God has forsaken him; pursue him and seize him, for there is no one to rescue him.”"}},"definableWords":["God","one"],"peopleInVerse":[]},"12":{"text":"O God, be not far from me: O my God, make haste for my help.","ref":"Psalms 71:12","synthesized":"Be not far from me, O God. Hurry, O my God, to help me.","sources":{"KJV":{"text":"O God, be not far from me: O my God, make haste for my help."},"BSB":{"text":"Be not far from me, O God. Hurry, O my God, to help me."}},"definableWords":["God"],"peopleInVerse":[]},"13":{"text":"Let them be confounded and consumed that are adversaries to my soul; let them be covered with reproach and dishonour that seek my hurt.","ref":"Psalms 71:13","synthesized":"May the accusers of my soul be ashamed and consumed; may those who seek my harm be covered with scorn and disgrace.","sources":{"KJV":{"text":"Let them be confounded and consumed that are adversaries to my soul; let them be covered with reproach and dishonour that seek my hurt."},"BSB":{"text":"May the accusers of my soul be ashamed and consumed; may those who seek my harm be covered with scorn and disgrace."}},"definableWords":["soul","seek"],"peopleInVerse":[]},"14":{"text":"But I will hope continually, and will yet praise thee more and more.","ref":"Psalms 71:14","synthesized":"But I will always hope and will praise You more and more.","sources":{"KJV":{"text":"But I will hope continually, and will yet praise thee more and more."},"BSB":{"text":"But I will always hope and will praise You more and more."}},"definableWords":["hope","praise"],"peopleInVerse":[]},"15":{"text":"My mouth shall shew forth thy righteousness and thy salvation all the day; for I know not the numbers thereof.","ref":"Psalms 71:15","synthesized":"My mouth will declare Your righteousness and Your salvation all day long, though I cannot know their full measure.","sources":{"KJV":{"text":"My mouth shall shew forth thy righteousness and thy salvation all the day; for I know not the numbers thereof."},"BSB":{"text":"My mouth will declare Your righteousness and Your salvation all day long, though I cannot know their full measure."}},"definableWords":["righteousness","salvation","day"],"peopleInVerse":[]},"16":{"text":"I will go in the strength of the Lord GOD: I will make mention of thy righteousness, even of thine only.","ref":"Psalms 71:16","synthesized":"I will enter in the strength of the Lord GOD; I will proclaim Your righteousness—Yours alone.","sources":{"KJV":{"text":"I will go in the strength of the Lord GOD: I will make mention of thy righteousness, even of thine only."},"BSB":{"text":"I will enter in the strength of the Lord GOD; I will proclaim Your righteousness—Yours alone."}},"definableWords":["Lord","God","righteousness"],"peopleInVerse":[]},"17":{"text":"O God, thou hast taught me from my youth: and hitherto have I declared thy wondrous works.","ref":"Psalms 71:17","synthesized":"O God, You have taught me from my youth, and to this day I proclaim Your marvelous deeds.","sources":{"KJV":{"text":"O God, thou hast taught me from my youth: and hitherto have I declared thy wondrous works."},"BSB":{"text":"O God, You have taught me from my youth, and to this day I proclaim Your marvelous deeds."}},"definableWords":["God","day"],"peopleInVerse":[]},"18":{"text":"Now also when I am old and greyheaded, O God, forsake me not; until I have shewed thy strength unto this generation, and thy power to every one that is to come.","ref":"Psalms 71:18","synthesized":"Even when I am old and gray, do not forsake me, O God, until I proclaim Your power to the next generation, Your might to all who are to come.","sources":{"KJV":{"text":"Now also when I am old and greyheaded, O God, forsake me not; until I have shewed thy strength unto this generation, and thy power to every one that is to come."},"BSB":{"text":"Even when I am old and gray, do not forsake me, O God, until I proclaim Your power to the next generation, Your might to all who are to come."}},"definableWords":["God"],"peopleInVerse":[]},"19":{"text":"Thy righteousness also, O God, is very high, who hast done great things: O God, who is like unto thee!","ref":"Psalms 71:19","synthesized":"Your righteousness reaches to the heavens, O God, You who have done great things. Who, O God, is like You?","sources":{"KJV":{"text":"Thy righteousness also, O God, is very high, who hast done great things: O God, who is like unto thee!"},"BSB":{"text":"Your righteousness reaches to the heavens, O God, You who have done great things. Who, O God, is like You?"}},"definableWords":["righteousness","heavens","God","great"],"peopleInVerse":[]},"20":{"text":"Thou, which hast shewed me great and sore troubles, shalt quicken me again, and shalt bring me up again from the depths of the earth.","ref":"Psalms 71:20","synthesized":"Though You have shown me many troubles and misfortunes, You will revive me once again. Even from the depths of the earth You will bring me back up.","sources":{"KJV":{"text":"Thou, which hast shewed me great and sore troubles, shalt quicken me again, and shalt bring me up again from the depths of the earth."},"BSB":{"text":"Though You have shown me many troubles and misfortunes, You will revive me once again. Even from the depths of the earth You will bring me back up."}},"definableWords":["earth"],"peopleInVerse":[]},"21":{"text":"Thou shalt increase my greatness, and comfort me on every side.","ref":"Psalms 71:21","synthesized":"You will increase my honor and comfort me once again.","sources":{"KJV":{"text":"Thou shalt increase my greatness, and comfort me on every side."},"BSB":{"text":"You will increase my honor and comfort me once again."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"I will also praise thee with the psaltery, even thy truth, O my God: unto thee will I sing with the harp, O thou Holy One of Israel.","ref":"Psalms 71:22","synthesized":"So I will praise You with the harp for Your faithfulness, O my God; I will sing praise to You with the lyre, O Holy One of Israel.","sources":{"KJV":{"text":"I will also praise thee with the psaltery, even thy truth, O my God: unto thee will I sing with the harp, O thou Holy One of Israel."},"BSB":{"text":"So I will praise You with the harp for Your faithfulness, O my God; I will sing praise to You with the lyre, O Holy One of Israel."}},"definableWords":["praise","God","holy","one","Israel"],"peopleInVerse":[]},"23":{"text":"My lips shall greatly rejoice when I sing unto thee; and my soul, which thou hast redeemed.","ref":"Psalms 71:23","synthesized":"When I sing praise to You my lips will shout for joy, along with my soul, which You have redeemed.","sources":{"KJV":{"text":"My lips shall greatly rejoice when I sing unto thee; and my soul, which thou hast redeemed."},"BSB":{"text":"When I sing praise to You my lips will shout for joy, along with my soul, which You have redeemed."}},"definableWords":["praise","joy","soul"],"peopleInVerse":[]},"24":{"text":"My tongue also shall talk of thy righteousness all the day long: for they are confounded, for they are brought unto shame, that seek my hurt.","ref":"Psalms 71:24","synthesized":"My tongue will indeed proclaim Your righteousness all day long, for those who seek my harm are disgraced and confounded.","sources":{"KJV":{"text":"My tongue also shall talk of thy righteousness all the day long: for they are confounded, for they are brought unto shame, that seek my hurt."},"BSB":{"text":"My tongue will indeed proclaim Your righteousness all day long, for those who seek my harm are disgraced and confounded."}},"definableWords":["righteousness","day","seek"],"peopleInVerse":[]}}},"72":{"chapter":"72","title":"THE KING'S SON — A MESSIANIC PSALM","verses":{"1":{"text":"Give the king thy judgments, O God, and thy righteousness unto the king’s son.","ref":"Psalms 72:1","synthesized":"Endow the king with Your justice, O God, and the son of the king with Your righteousness.","sources":{"KJV":{"text":"Give the king thy judgments, O God, and thy righteousness unto the king’s son."},"BSB":{"text":"Endow the king with Your justice, O God, and the son of the king with Your righteousness."}},"definableWords":["king","justice","God","son","King","righteousness"],"peopleInVerse":[]},"2":{"text":"He shall judge thy people with righteousness, and thy poor with judgment.","ref":"Psalms 72:2","synthesized":"May he judge Your people with righteousness and Your afflicted with justice.","sources":{"KJV":{"text":"He shall judge thy people with righteousness, and thy poor with judgment."},"BSB":{"text":"May he judge Your people with righteousness and Your afflicted with justice."}},"definableWords":["people","righteousness","justice"],"peopleInVerse":[]},"3":{"text":"The mountains shall bring peace to the people, and the little hills, by righteousness.","ref":"Psalms 72:3","synthesized":"May the mountains bring peace to the people, and the hills bring righteousness.","sources":{"KJV":{"text":"The mountains shall bring peace to the people, and the little hills, by righteousness."},"BSB":{"text":"May the mountains bring peace to the people, and the hills bring righteousness."}},"definableWords":["peace","people","righteousness"],"peopleInVerse":[]},"4":{"text":"He shall judge the poor of the people, he shall save the children of the needy, and shall break in pieces the oppressor.","ref":"Psalms 72:4","synthesized":"May he vindicate the afflicted among the people; may he save the children of the needy and crush the oppressor.","sources":{"KJV":{"text":"He shall judge the poor of the people, he shall save the children of the needy, and shall break in pieces the oppressor."},"BSB":{"text":"May he vindicate the afflicted among the people; may he save the children of the needy and crush the oppressor."}},"definableWords":["people"],"peopleInVerse":[]},"5":{"text":"They shall fear thee as long as the sun and moon endure, throughout all generations.","ref":"Psalms 72:5","synthesized":"May they fear him as long as the sun shines, as long as the moon remains, through all generations.","sources":{"KJV":{"text":"They shall fear thee as long as the sun and moon endure, throughout all generations."},"BSB":{"text":"May they fear him as long as the sun shines, as long as the moon remains, through all generations."}},"definableWords":["fear"],"peopleInVerse":[]},"6":{"text":"He shall come down like rain upon the mown grass: as showers that water the earth.","ref":"Psalms 72:6","synthesized":"May he be like rain that falls on freshly cut grass, like spring showers that water the earth.","sources":{"KJV":{"text":"He shall come down like rain upon the mown grass: as showers that water the earth."},"BSB":{"text":"May he be like rain that falls on freshly cut grass, like spring showers that water the earth."}},"definableWords":["water","earth"],"peopleInVerse":[]},"7":{"text":"In his days shall the righteous flourish; and abundance of peace so long as the moon endureth.","ref":"Psalms 72:7","synthesized":"May the righteous flourish in his days and prosperity abound, until the moon is no more.","sources":{"KJV":{"text":"In his days shall the righteous flourish; and abundance of peace so long as the moon endureth."},"BSB":{"text":"May the righteous flourish in his days and prosperity abound, until the moon is no more."}},"definableWords":["righteous","days"],"peopleInVerse":[]},"8":{"text":"He shall have dominion also from sea to sea, and from the river unto the ends of the earth.","ref":"Psalms 72:8","synthesized":"May he rule from sea to sea, and from the Euphrates to the ends of the earth.","sources":{"KJV":{"text":"He shall have dominion also from sea to sea, and from the river unto the ends of the earth."},"BSB":{"text":"May he rule from sea to sea, and from the Euphrates to the ends of the earth."}},"definableWords":["rule","sea","earth"],"peopleInVerse":[]},"9":{"text":"They that dwell in the wilderness shall bow before him; and his enemies shall lick the dust.","ref":"Psalms 72:9","synthesized":"May the nomads bow before him, and his enemies lick the dust.","sources":{"KJV":{"text":"They that dwell in the wilderness shall bow before him; and his enemies shall lick the dust."},"BSB":{"text":"May the nomads bow before him, and his enemies lick the dust."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"The kings of Tarshish and of the isles shall bring presents: the kings of Sheba and Seba shall offer gifts.","ref":"Psalms 72:10","synthesized":"May the kings of Tarshish and distant shores bring tribute; may the kings of Sheba and Seba offer gifts.","sources":{"KJV":{"text":"The kings of Tarshish and of the isles shall bring presents: the kings of Sheba and Seba shall offer gifts."},"BSB":{"text":"May the kings of Tarshish and distant shores bring tribute; may the kings of Sheba and Seba offer gifts."}},"definableWords":["kings"],"peopleInVerse":[]},"11":{"text":"Yea, all kings shall fall down before him: all nations shall serve him.","ref":"Psalms 72:11","synthesized":"May all kings bow down to him and all nations serve him.","sources":{"KJV":{"text":"Yea, all kings shall fall down before him: all nations shall serve him."},"BSB":{"text":"May all kings bow down to him and all nations serve him."}},"definableWords":["kings","nations"],"peopleInVerse":[]},"12":{"text":"For he shall deliver the needy when he crieth; the poor also, and him that hath no helper.","ref":"Psalms 72:12","synthesized":"For he will deliver the needy who cry out and the afflicted who have no helper.","sources":{"KJV":{"text":"For he shall deliver the needy when he crieth; the poor also, and him that hath no helper."},"BSB":{"text":"For he will deliver the needy who cry out and the afflicted who have no helper."}},"definableWords":["deliver","helper"],"peopleInVerse":[]},"13":{"text":"He shall spare the poor and needy, and shall save the souls of the needy.","ref":"Psalms 72:13","synthesized":"He will take pity on the poor and needy and save the lives of the oppressed.","sources":{"KJV":{"text":"He shall spare the poor and needy, and shall save the souls of the needy."},"BSB":{"text":"He will take pity on the poor and needy and save the lives of the oppressed."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"He shall redeem their soul from deceit and violence: and precious shall their blood be in his sight.","ref":"Psalms 72:14","synthesized":"He will redeem them from oppression and violence, for their blood is precious in his sight.","sources":{"KJV":{"text":"He shall redeem their soul from deceit and violence: and precious shall their blood be in his sight."},"BSB":{"text":"He will redeem them from oppression and violence, for their blood is precious in his sight."}},"definableWords":["blood"],"peopleInVerse":[]},"15":{"text":"And he shall live, and to him shall be given of the gold of Sheba: prayer also shall be made for him continually; and daily shall he be praised.","ref":"Psalms 72:15","synthesized":"Long may he live! May gold from Sheba be given him. May people ever pray for him; may they bless him all day long.","sources":{"KJV":{"text":"And he shall live, and to him shall be given of the gold of Sheba: prayer also shall be made for him continually; and daily shall he be praised."},"BSB":{"text":"Long may he live! May gold from Sheba be given him. May people ever pray for him; may they bless him all day long."}},"definableWords":["live","people","bless","day"],"peopleInVerse":[]},"16":{"text":"There shall be an handful of corn in the earth upon the top of the mountains; the fruit thereof shall shake like Lebanon: and they of the city shall flourish like grass of the earth.","ref":"Psalms 72:16","synthesized":"May there be an abundance of grain in the land; may it sway atop the hills. May its fruit trees flourish like the forests of Lebanon, and its people like the grass of the field.","sources":{"KJV":{"text":"There shall be an handful of corn in the earth upon the top of the mountains; the fruit thereof shall shake like Lebanon: and they of the city shall flourish like grass of the earth."},"BSB":{"text":"May there be an abundance of grain in the land; may it sway atop the hills. May its fruit trees flourish like the forests of Lebanon, and its people like the grass of the field."}},"definableWords":["land","trees","people","field"],"peopleInVerse":[]},"17":{"text":"His name shall endure for ever: his name shall be continued as long as the sun: and men shall be blessed in him: all nations shall call him blessed.","ref":"Psalms 72:17","synthesized":"May his name endure forever; may his name continue as long as the sun shines. In him may all nations be blessed; may they call him blessed.","sources":{"KJV":{"text":"His name shall endure for ever: his name shall be continued as long as the sun: and men shall be blessed in him: all nations shall call him blessed."},"BSB":{"text":"May his name endure forever; may his name continue as long as the sun shines. In him may all nations be blessed; may they call him blessed."}},"definableWords":["name","nations","blessed"],"peopleInVerse":[]},"18":{"text":"Blessed be the LORD God, the God of Israel, who only doeth wondrous things.","ref":"Psalms 72:18","synthesized":"Blessed be the LORD God, the God of Israel, who alone does marvelous deeds.","sources":{"KJV":{"text":"Blessed be the LORD God, the God of Israel, who only doeth wondrous things."},"BSB":{"text":"Blessed be the LORD God, the God of Israel, who alone does marvelous deeds."}},"definableWords":["blessed","LORD","God","Israel"],"peopleInVerse":[]},"19":{"text":"And blessed be his glorious name for ever: and let the whole earth be filled with his glory; Amen, and Amen.","ref":"Psalms 72:19","synthesized":"And blessed be His glorious name forever; may all the earth be filled with His glory.   Amen and amen.","sources":{"KJV":{"text":"And blessed be his glorious name for ever: and let the whole earth be filled with his glory; Amen, and Amen."},"BSB":{"text":"And blessed be His glorious name forever; may all the earth be filled with His glory.   Amen and amen."}},"definableWords":["blessed","name","earth","glory"],"peopleInVerse":[]},"20":{"text":"The prayers of David the son of Jesse are ended.","ref":"Psalms 72:20","synthesized":"Thus conclude the prayers of David son of Jesse.","sources":{"KJV":{"text":"The prayers of David the son of Jesse are ended."},"BSB":{"text":"Thus conclude the prayers of David son of Jesse."}},"definableWords":["son"],"peopleInVerse":["David"]}}},"73":{"chapter":"73","title":"THE PROSPERITY OF THE WICKED","verses":{"1":{"text":"Truly God is good to Israel, even to such as are of a clean heart.","ref":"Psalms 73:1","synthesized":"Surely God is good to Israel, to those who are pure in heart.","sources":{"KJV":{"text":"Truly God is good to Israel, even to such as are of a clean heart."},"BSB":{"text":"Surely God is good to Israel, to those who are pure in heart."}},"definableWords":["God","good","Israel","heart"],"peopleInVerse":[]},"2":{"text":"But as for me, my feet were almost gone; my steps had well nigh slipped.","ref":"Psalms 73:2","synthesized":"But as for me, my feet had almost stumbled; my steps had nearly slipped.","sources":{"KJV":{"text":"But as for me, my feet were almost gone; my steps had well nigh slipped."},"BSB":{"text":"But as for me, my feet had almost stumbled; my steps had nearly slipped."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"For I was envious at the foolish, when I saw the prosperity of the wicked.","ref":"Psalms 73:3","synthesized":"For I envied the arrogant when I saw the prosperity of the wicked.","sources":{"KJV":{"text":"For I was envious at the foolish, when I saw the prosperity of the wicked."},"BSB":{"text":"For I envied the arrogant when I saw the prosperity of the wicked."}},"definableWords":["saw"],"peopleInVerse":[]},"4":{"text":"For there are no bands in their death: but their strength is firm.","ref":"Psalms 73:4","synthesized":"They have no struggle in their death; their bodies are well-fed.","sources":{"KJV":{"text":"For there are no bands in their death: but their strength is firm."},"BSB":{"text":"They have no struggle in their death; their bodies are well-fed."}},"definableWords":["death"],"peopleInVerse":[]},"5":{"text":"They are not in trouble as other men; neither are they plagued like other men.","ref":"Psalms 73:5","synthesized":"They are free of the burdens others carry; they are not afflicted like other men.","sources":{"KJV":{"text":"They are not in trouble as other men; neither are they plagued like other men."},"BSB":{"text":"They are free of the burdens others carry; they are not afflicted like other men."}},"definableWords":["men"],"peopleInVerse":[]},"6":{"text":"Therefore pride compasseth them about as a chain; violence covereth them as a garment.","ref":"Psalms 73:6","synthesized":"Therefore pride is their necklace; a garment of violence covers them.","sources":{"KJV":{"text":"Therefore pride compasseth them about as a chain; violence covereth them as a garment."},"BSB":{"text":"Therefore pride is their necklace; a garment of violence covers them."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Their eyes stand out with fatness: they have more than heart could wish.","ref":"Psalms 73:7","synthesized":"From their prosperity proceeds iniquity; the imaginations of their hearts run wild.","sources":{"KJV":{"text":"Their eyes stand out with fatness: they have more than heart could wish."},"BSB":{"text":"From their prosperity proceeds iniquity; the imaginations of their hearts run wild."}},"definableWords":["iniquity","run"],"peopleInVerse":[]},"8":{"text":"They are corrupt, and speak wickedly concerning oppression: they speak loftily.","ref":"Psalms 73:8","synthesized":"They mock and speak with malice; with arrogance they threaten oppression.","sources":{"KJV":{"text":"They are corrupt, and speak wickedly concerning oppression: they speak loftily."},"BSB":{"text":"They mock and speak with malice; with arrogance they threaten oppression."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"They set their mouth against the heavens, and their tongue walketh through the earth.","ref":"Psalms 73:9","synthesized":"They set their mouths against the heavens, and their tongues strut across the earth.","sources":{"KJV":{"text":"They set their mouth against the heavens, and their tongue walketh through the earth."},"BSB":{"text":"They set their mouths against the heavens, and their tongues strut across the earth."}},"definableWords":["heavens","earth"],"peopleInVerse":[]},"10":{"text":"Therefore his people return hither: and waters of a full cup are wrung out to them.","ref":"Psalms 73:10","synthesized":"So their people return to this place and drink up waters in abundance.","sources":{"KJV":{"text":"Therefore his people return hither: and waters of a full cup are wrung out to them."},"BSB":{"text":"So their people return to this place and drink up waters in abundance."}},"definableWords":["people","waters"],"peopleInVerse":[]},"11":{"text":"And they say, How doth God know? and is there knowledge in the most High?","ref":"Psalms 73:11","synthesized":"The wicked say, “How can God know? Does the Most High have knowledge?”","sources":{"KJV":{"text":"And they say, How doth God know? and is there knowledge in the most High?"},"BSB":{"text":"The wicked say, “How can God know? Does the Most High have knowledge?”"}},"definableWords":["God","knowledge"],"peopleInVerse":[]},"12":{"text":"Behold, these are the ungodly, who prosper in the world; they increase in riches.","ref":"Psalms 73:12","synthesized":"Behold, these are the wicked— always carefree as they increase their wealth.","sources":{"KJV":{"text":"Behold, these are the ungodly, who prosper in the world; they increase in riches."},"BSB":{"text":"Behold, these are the wicked— always carefree as they increase their wealth."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Verily I have cleansed my heart in vain, and washed my hands in innocency.","ref":"Psalms 73:13","synthesized":"Surely in vain I have kept my heart pure; in innocence I have washed my hands.","sources":{"KJV":{"text":"Verily I have cleansed my heart in vain, and washed my hands in innocency."},"BSB":{"text":"Surely in vain I have kept my heart pure; in innocence I have washed my hands."}},"definableWords":["heart"],"peopleInVerse":[]},"14":{"text":"For all the day long have I been plagued, and chastened every morning.","ref":"Psalms 73:14","synthesized":"For I am afflicted all day long and punished every morning.","sources":{"KJV":{"text":"For all the day long have I been plagued, and chastened every morning."},"BSB":{"text":"For I am afflicted all day long and punished every morning."}},"definableWords":["day"],"peopleInVerse":[]},"15":{"text":"If I say, I will speak thus; behold, I should offend against the generation of thy children.","ref":"Psalms 73:15","synthesized":"If I had said, “I will speak this way,” then I would have betrayed Your children.","sources":{"KJV":{"text":"If I say, I will speak thus; behold, I should offend against the generation of thy children."},"BSB":{"text":"If I had said, “I will speak this way,” then I would have betrayed Your children."}},"definableWords":["way"],"peopleInVerse":[]},"16":{"text":"When I thought to know this, it was too painful for me;","ref":"Psalms 73:16","synthesized":"When I tried to understand all this, it was troublesome in my sight","sources":{"KJV":{"text":"When I thought to know this, it was too painful for me;"},"BSB":{"text":"When I tried to understand all this, it was troublesome in my sight"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Until I went into the sanctuary of God; then understood I their end.","ref":"Psalms 73:17","synthesized":"until I entered God’s sanctuary; then I discerned their end.","sources":{"KJV":{"text":"Until I went into the sanctuary of God; then understood I their end."},"BSB":{"text":"until I entered God’s sanctuary; then I discerned their end."}},"definableWords":["God"],"peopleInVerse":[]},"18":{"text":"Surely thou didst set them in slippery places: thou castedst them down into destruction.","ref":"Psalms 73:18","synthesized":"Surely You set them on slick ground; You cast them down into ruin.","sources":{"KJV":{"text":"Surely thou didst set them in slippery places: thou castedst them down into destruction."},"BSB":{"text":"Surely You set them on slick ground; You cast them down into ruin."}},"definableWords":["ground"],"peopleInVerse":[]},"19":{"text":"How are they brought into desolation, as in a moment! they are utterly consumed with terrors.","ref":"Psalms 73:19","synthesized":"How suddenly they are laid waste, completely swept away by terrors!","sources":{"KJV":{"text":"How are they brought into desolation, as in a moment! they are utterly consumed with terrors."},"BSB":{"text":"How suddenly they are laid waste, completely swept away by terrors!"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"As a dream when one awaketh; so, O Lord, when thou awakest, thou shalt despise their image.","ref":"Psalms 73:20","synthesized":"Like one waking from a dream, so You, O Lord, awaken and despise their form.","sources":{"KJV":{"text":"As a dream when one awaketh; so, O Lord, when thou awakest, thou shalt despise their image."},"BSB":{"text":"Like one waking from a dream, so You, O Lord, awaken and despise their form."}},"definableWords":["one","Lord","form"],"peopleInVerse":[]},"21":{"text":"Thus my heart was grieved, and I was pricked in my reins.","ref":"Psalms 73:21","synthesized":"When my heart was grieved and I was pierced within,","sources":{"KJV":{"text":"Thus my heart was grieved, and I was pricked in my reins."},"BSB":{"text":"When my heart was grieved and I was pierced within,"}},"definableWords":["heart"],"peopleInVerse":[]},"22":{"text":"So foolish was I, and ignorant: I was as a beast before thee.","ref":"Psalms 73:22","synthesized":"I was senseless and ignorant; I was a brute beast before You.","sources":{"KJV":{"text":"So foolish was I, and ignorant: I was as a beast before thee."},"BSB":{"text":"I was senseless and ignorant; I was a brute beast before You."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Nevertheless I am continually with thee: thou hast holden me by my right hand.","ref":"Psalms 73:23","synthesized":"Yet I am always with You; You hold my right hand.","sources":{"KJV":{"text":"Nevertheless I am continually with thee: thou hast holden me by my right hand."},"BSB":{"text":"Yet I am always with You; You hold my right hand."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"Thou shalt guide me with thy counsel, and afterward receive me to glory.","ref":"Psalms 73:24","synthesized":"You guide me with Your counsel, and later receive me in glory.","sources":{"KJV":{"text":"Thou shalt guide me with thy counsel, and afterward receive me to glory."},"BSB":{"text":"You guide me with Your counsel, and later receive me in glory."}},"definableWords":["glory"],"peopleInVerse":[]},"25":{"text":"Whom have I in heaven but thee? and there is none upon earth that I desire beside thee.","ref":"Psalms 73:25","synthesized":"Whom have I in heaven but You? And on earth I desire no one besides You.","sources":{"KJV":{"text":"Whom have I in heaven but thee? and there is none upon earth that I desire beside thee."},"BSB":{"text":"Whom have I in heaven but You? And on earth I desire no one besides You."}},"definableWords":["heaven","earth","one"],"peopleInVerse":[]},"26":{"text":"My flesh and my heart faileth: but God is the strength of my heart, and my portion for ever.","ref":"Psalms 73:26","synthesized":"My flesh and my heart may fail, but God is the strength of my heart and my portion forever.","sources":{"KJV":{"text":"My flesh and my heart faileth: but God is the strength of my heart, and my portion for ever."},"BSB":{"text":"My flesh and my heart may fail, but God is the strength of my heart and my portion forever."}},"definableWords":["flesh","heart","God"],"peopleInVerse":[]},"27":{"text":"For, lo, they that are far from thee shall perish: thou hast destroyed all them that go a whoring from thee.","ref":"Psalms 73:27","synthesized":"Those far from You will surely perish; You destroy all who are unfaithful to You.","sources":{"KJV":{"text":"For, lo, they that are far from thee shall perish: thou hast destroyed all them that go a whoring from thee."},"BSB":{"text":"Those far from You will surely perish; You destroy all who are unfaithful to You."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"But it is good for me to draw near to God: I have put my trust in the Lord GOD, that I may declare all thy works.","ref":"Psalms 73:28","synthesized":"But as for me, it is good to draw near to God. I have made the Lord GOD my refuge, that I may proclaim all Your works.","sources":{"KJV":{"text":"But it is good for me to draw near to God: I have put my trust in the Lord GOD, that I may declare all thy works."},"BSB":{"text":"But as for me, it is good to draw near to God. I have made the Lord GOD my refuge, that I may proclaim all Your works."}},"definableWords":["good","God","made","Lord","works"],"peopleInVerse":[]}}},"74":{"chapter":"74","title":"WHY HAST THOU CAST US OFF?","verses":{"1":{"text":"O God, why hast thou cast us off for ever? why doth thine anger smoke against the sheep of thy pasture?","ref":"Psalms 74:1","synthesized":"Why have You rejected us forever, O God? Why does Your anger smolder against the sheep of Your pasture?","sources":{"KJV":{"text":"O God, why hast thou cast us off for ever? why doth thine anger smoke against the sheep of thy pasture?"},"BSB":{"text":"Why have You rejected us forever, O God? Why does Your anger smolder against the sheep of Your pasture?"}},"definableWords":["God","anger"],"peopleInVerse":[]},"2":{"text":"Remember thy congregation, which thou hast purchased of old; the rod of thine inheritance, which thou hast redeemed; this mount Zion, wherein thou hast dwelt.","ref":"Psalms 74:2","synthesized":"Remember Your congregation, which You purchased long ago and redeemed as the tribe of Your inheritance— Mount Zion where You dwell.","sources":{"KJV":{"text":"Remember thy congregation, which thou hast purchased of old; the rod of thine inheritance, which thou hast redeemed; this mount Zion, wherein thou hast dwelt."},"BSB":{"text":"Remember Your congregation, which You purchased long ago and redeemed as the tribe of Your inheritance— Mount Zion where You dwell."}},"definableWords":["remember","tribe","Zion"],"peopleInVerse":[]},"3":{"text":"Lift up thy feet unto the perpetual desolations; even all that the enemy hath done wickedly in the sanctuary.","ref":"Psalms 74:3","synthesized":"Turn Your steps to the everlasting ruins, to everything in the sanctuary the enemy has destroyed.","sources":{"KJV":{"text":"Lift up thy feet unto the perpetual desolations; even all that the enemy hath done wickedly in the sanctuary."},"BSB":{"text":"Turn Your steps to the everlasting ruins, to everything in the sanctuary the enemy has destroyed."}},"definableWords":["everlasting"],"peopleInVerse":[]},"4":{"text":"Thine enemies roar in the midst of thy congregations; they set up their ensigns for signs.","ref":"Psalms 74:4","synthesized":"Your foes have roared within Your meeting place; they have unfurled their banners as signs,","sources":{"KJV":{"text":"Thine enemies roar in the midst of thy congregations; they set up their ensigns for signs."},"BSB":{"text":"Your foes have roared within Your meeting place; they have unfurled their banners as signs,"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"A man was famous according as he had lifted up axes upon the thick trees.","ref":"Psalms 74:5","synthesized":"like men wielding axes in a thicket of trees","sources":{"KJV":{"text":"A man was famous according as he had lifted up axes upon the thick trees."},"BSB":{"text":"like men wielding axes in a thicket of trees"}},"definableWords":["men","trees"],"peopleInVerse":[]},"6":{"text":"But now they break down the carved work thereof at once with axes and hammers.","ref":"Psalms 74:6","synthesized":"and smashing all the carvings with hatchets and picks.","sources":{"KJV":{"text":"But now they break down the carved work thereof at once with axes and hammers."},"BSB":{"text":"and smashing all the carvings with hatchets and picks."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"They have cast fire into thy sanctuary, they have defiled by casting down the dwelling place of thy name to the ground.","ref":"Psalms 74:7","synthesized":"They have burned Your sanctuary to the ground; they have defiled the dwelling place of Your Name.","sources":{"KJV":{"text":"They have cast fire into thy sanctuary, they have defiled by casting down the dwelling place of thy name to the ground."},"BSB":{"text":"They have burned Your sanctuary to the ground; they have defiled the dwelling place of Your Name."}},"definableWords":["ground","name"],"peopleInVerse":[]},"8":{"text":"They said in their hearts, Let us destroy them together: they have burned up all the synagogues of God in the land.","ref":"Psalms 74:8","synthesized":"They said in their hearts, “We will crush them completely.” They burned down every place where God met us in the land.","sources":{"KJV":{"text":"They said in their hearts, Let us destroy them together: they have burned up all the synagogues of God in the land."},"BSB":{"text":"They said in their hearts, “We will crush them completely.” They burned down every place where God met us in the land."}},"definableWords":["God","land"],"peopleInVerse":[]},"9":{"text":"We see not our signs: there is no more any prophet: neither is there among us any that knoweth how long.","ref":"Psalms 74:9","synthesized":"There are no signs for us to see. There is no longer any prophet. And none of us knows how long this will last.","sources":{"KJV":{"text":"We see not our signs: there is no more any prophet: neither is there among us any that knoweth how long."},"BSB":{"text":"There are no signs for us to see. There is no longer any prophet. And none of us knows how long this will last."}},"definableWords":["see","prophet"],"peopleInVerse":[]},"10":{"text":"O God, how long shall the adversary reproach? shall the enemy blaspheme thy name for ever?","ref":"Psalms 74:10","synthesized":"How long, O God, will the enemy taunt You? Will the foe revile Your name forever?","sources":{"KJV":{"text":"O God, how long shall the adversary reproach? shall the enemy blaspheme thy name for ever?"},"BSB":{"text":"How long, O God, will the enemy taunt You? Will the foe revile Your name forever?"}},"definableWords":["God","name"],"peopleInVerse":[]},"11":{"text":"Why withdrawest thou thy hand, even thy right hand? pluck it out of thy bosom.","ref":"Psalms 74:11","synthesized":"Why do You withdraw Your strong right hand? Stretch it out to destroy them!","sources":{"KJV":{"text":"Why withdrawest thou thy hand, even thy right hand? pluck it out of thy bosom."},"BSB":{"text":"Why do You withdraw Your strong right hand? Stretch it out to destroy them!"}},"definableWords":["strong"],"peopleInVerse":[]},"12":{"text":"For God is my King of old, working salvation in the midst of the earth.","ref":"Psalms 74:12","synthesized":"Yet God is my King from ancient times, working salvation on the earth.","sources":{"KJV":{"text":"For God is my King of old, working salvation in the midst of the earth."},"BSB":{"text":"Yet God is my King from ancient times, working salvation on the earth."}},"definableWords":["God","King","salvation","earth"],"peopleInVerse":[]},"13":{"text":"Thou didst divide the sea by thy strength: thou brakest the heads of the dragons in the waters.","ref":"Psalms 74:13","synthesized":"You divided the sea by Your strength; You smashed the heads of the dragons of the sea;","sources":{"KJV":{"text":"Thou didst divide the sea by thy strength: thou brakest the heads of the dragons in the waters."},"BSB":{"text":"You divided the sea by Your strength; You smashed the heads of the dragons of the sea;"}},"definableWords":["sea"],"peopleInVerse":[]},"14":{"text":"Thou brakest the heads of leviathan in pieces, and gavest him to be meat to the people inhabiting the wilderness.","ref":"Psalms 74:14","synthesized":"You crushed the heads of Leviathan; You fed him to the creatures of the desert.","sources":{"KJV":{"text":"Thou brakest the heads of leviathan in pieces, and gavest him to be meat to the people inhabiting the wilderness."},"BSB":{"text":"You crushed the heads of Leviathan; You fed him to the creatures of the desert."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Thou didst cleave the fountain and the flood: thou driedst up mighty rivers.","ref":"Psalms 74:15","synthesized":"You broke open the fountain and the flood; You dried up the ever-flowing rivers.","sources":{"KJV":{"text":"Thou didst cleave the fountain and the flood: thou driedst up mighty rivers."},"BSB":{"text":"You broke open the fountain and the flood; You dried up the ever-flowing rivers."}},"definableWords":["flood"],"peopleInVerse":[]},"16":{"text":"The day is thine, the night also is thine: thou hast prepared the light and the sun.","ref":"Psalms 74:16","synthesized":"The day is Yours, and also the night; You established the moon and the sun.","sources":{"KJV":{"text":"The day is thine, the night also is thine: thou hast prepared the light and the sun."},"BSB":{"text":"The day is Yours, and also the night; You established the moon and the sun."}},"definableWords":["day","night"],"peopleInVerse":[]},"17":{"text":"Thou hast set all the borders of the earth: thou hast made summer and winter.","ref":"Psalms 74:17","synthesized":"You set all the boundaries of the earth; You made the summer and winter.","sources":{"KJV":{"text":"Thou hast set all the borders of the earth: thou hast made summer and winter."},"BSB":{"text":"You set all the boundaries of the earth; You made the summer and winter."}},"definableWords":["earth","made"],"peopleInVerse":[]},"18":{"text":"Remember this, that the enemy hath reproached, O LORD, and that the foolish people have blasphemed thy name.","ref":"Psalms 74:18","synthesized":"Remember how the enemy has mocked You, O LORD, how a foolish people has spurned Your name.","sources":{"KJV":{"text":"Remember this, that the enemy hath reproached, O LORD, and that the foolish people have blasphemed thy name."},"BSB":{"text":"Remember how the enemy has mocked You, O LORD, how a foolish people has spurned Your name."}},"definableWords":["remember","LORD","people","name"],"peopleInVerse":[]},"19":{"text":"O deliver not the soul of thy turtledove unto the multitude of the wicked: forget not the congregation of thy poor for ever.","ref":"Psalms 74:19","synthesized":"Do not deliver the soul of Your dove to beasts; do not forget the lives of Your afflicted forever.","sources":{"KJV":{"text":"O deliver not the soul of thy turtledove unto the multitude of the wicked: forget not the congregation of thy poor for ever."},"BSB":{"text":"Do not deliver the soul of Your dove to beasts; do not forget the lives of Your afflicted forever."}},"definableWords":["deliver","soul"],"peopleInVerse":[]},"20":{"text":"Have respect unto the covenant: for the dark places of the earth are full of the habitations of cruelty.","ref":"Psalms 74:20","synthesized":"Consider Your covenant, for haunts of violence fill the dark places of the land.","sources":{"KJV":{"text":"Have respect unto the covenant: for the dark places of the earth are full of the habitations of cruelty."},"BSB":{"text":"Consider Your covenant, for haunts of violence fill the dark places of the land."}},"definableWords":["covenant","fill","land"],"peopleInVerse":[]},"21":{"text":"O let not the oppressed return ashamed: let the poor and needy praise thy name.","ref":"Psalms 74:21","synthesized":"Do not let the oppressed retreat in shame; may the poor and needy praise Your name.","sources":{"KJV":{"text":"O let not the oppressed return ashamed: let the poor and needy praise thy name."},"BSB":{"text":"Do not let the oppressed retreat in shame; may the poor and needy praise Your name."}},"definableWords":["praise","name"],"peopleInVerse":[]},"22":{"text":"Arise, O God, plead thine own cause: remember how the foolish man reproacheth thee daily.","ref":"Psalms 74:22","synthesized":"Rise up, O God; defend Your cause! Remember how the fool mocks You all day long.","sources":{"KJV":{"text":"Arise, O God, plead thine own cause: remember how the foolish man reproacheth thee daily."},"BSB":{"text":"Rise up, O God; defend Your cause! Remember how the fool mocks You all day long."}},"definableWords":["God","remember","fool","day"],"peopleInVerse":[]},"23":{"text":"Forget not the voice of thine enemies: the tumult of those that rise up against thee increaseth continually.","ref":"Psalms 74:23","synthesized":"Do not disregard the clamor of Your adversaries, the uproar of Your enemies that ascends continually.","sources":{"KJV":{"text":"Forget not the voice of thine enemies: the tumult of those that rise up against thee increaseth continually."},"BSB":{"text":"Do not disregard the clamor of Your adversaries, the uproar of Your enemies that ascends continually."}},"definableWords":[],"peopleInVerse":[]}}},"75":{"chapter":"75","title":"UNTO THEE WE GIVE THANKS","verses":{"1":{"text":"Unto thee, O God, do we give thanks, unto thee do we give thanks: for that thy name is near thy wondrous works declare.","ref":"Psalms 75:1","synthesized":"We give thanks to You, O God; we give thanks, for Your Name is near. The people declare Your wondrous works.","sources":{"KJV":{"text":"Unto thee, O God, do we give thanks, unto thee do we give thanks: for that thy name is near thy wondrous works declare."},"BSB":{"text":"We give thanks to You, O God; we give thanks, for Your Name is near. The people declare Your wondrous works."}},"definableWords":["God","name","people","works"],"peopleInVerse":[]},"2":{"text":"When I shall receive the congregation I will judge uprightly.","ref":"Psalms 75:2","synthesized":"“When I choose a time, I will judge fairly.","sources":{"KJV":{"text":"When I shall receive the congregation I will judge uprightly."},"BSB":{"text":"“When I choose a time, I will judge fairly."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"The earth and all the inhabitants thereof are dissolved: I bear up the pillars of it. Selah.","ref":"Psalms 75:3","synthesized":"When the earth and all its dwellers quake, it is I who bear up its pillars. Selah","sources":{"KJV":{"text":"The earth and all the inhabitants thereof are dissolved: I bear up the pillars of it. Selah."},"BSB":{"text":"When the earth and all its dwellers quake, it is I who bear up its pillars. Selah"}},"definableWords":["earth"],"peopleInVerse":[]},"4":{"text":"I said unto the fools, Deal not foolishly: and to the wicked, Lift not up the horn:","ref":"Psalms 75:4","synthesized":"I say to the proud, ‘Do not boast,’ and to the wicked, ‘Do not lift up your horn.","sources":{"KJV":{"text":"I said unto the fools, Deal not foolishly: and to the wicked, Lift not up the horn:"},"BSB":{"text":"I say to the proud, ‘Do not boast,’ and to the wicked, ‘Do not lift up your horn."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Lift not up your horn on high: speak not with a stiff neck.","ref":"Psalms 75:5","synthesized":"Do not lift up your horn against heaven or speak with an outstretched neck.’”","sources":{"KJV":{"text":"Lift not up your horn on high: speak not with a stiff neck."},"BSB":{"text":"Do not lift up your horn against heaven or speak with an outstretched neck.’”"}},"definableWords":["heaven","or"],"peopleInVerse":[]},"6":{"text":"For promotion cometh neither from the east, nor from the west, nor from the south.","ref":"Psalms 75:6","synthesized":"For exaltation comes neither from east nor west, nor out of the desert,","sources":{"KJV":{"text":"For promotion cometh neither from the east, nor from the west, nor from the south."},"BSB":{"text":"For exaltation comes neither from east nor west, nor out of the desert,"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"But God is the judge: he putteth down one, and setteth up another.","ref":"Psalms 75:7","synthesized":"but it is God who judges; He brings down one and exalts another.","sources":{"KJV":{"text":"But God is the judge: he putteth down one, and setteth up another."},"BSB":{"text":"but it is God who judges; He brings down one and exalts another."}},"definableWords":["God","one"],"peopleInVerse":[]},"8":{"text":"For in the hand of the LORD there is a cup, and the wine is red; it is full of mixture; and he poureth out of the same: but the dregs thereof, all the wicked of the earth shall wring them out, and drink them.","ref":"Psalms 75:8","synthesized":"For a cup is in the hand of the LORD, full of foaming wine mixed with spices. He pours from His cup, and all the wicked of the earth drink it down to the dregs.","sources":{"KJV":{"text":"For in the hand of the LORD there is a cup, and the wine is red; it is full of mixture; and he poureth out of the same: but the dregs thereof, all the wicked of the earth shall wring them out, and drink them."},"BSB":{"text":"For a cup is in the hand of the LORD, full of foaming wine mixed with spices. He pours from His cup, and all the wicked of the earth drink it down to the dregs."}},"definableWords":["LORD","earth"],"peopleInVerse":[]},"9":{"text":"But I will declare for ever; I will sing praises to the God of Jacob.","ref":"Psalms 75:9","synthesized":"But I will proclaim Him forever; I will sing praise to the God of Jacob.","sources":{"KJV":{"text":"But I will declare for ever; I will sing praises to the God of Jacob."},"BSB":{"text":"But I will proclaim Him forever; I will sing praise to the God of Jacob."}},"definableWords":["praise","God","Jacob"],"peopleInVerse":["Jacob"]},"10":{"text":"All the horns of the wicked also will I cut off; but the horns of the righteous shall be exalted.","ref":"Psalms 75:10","synthesized":"“All the horns of the wicked I will cut off, but the horns of the righteous will be exalted.”","sources":{"KJV":{"text":"All the horns of the wicked also will I cut off; but the horns of the righteous shall be exalted."},"BSB":{"text":"“All the horns of the wicked I will cut off, but the horns of the righteous will be exalted.”"}},"definableWords":["righteous"],"peopleInVerse":[]}}},"76":{"chapter":"76","title":"IN JUDAH IS GOD KNOWN","verses":{"1":{"text":"In Judah is God known: his name is great in Israel.","ref":"Psalms 76:1","synthesized":"God is known in Judah; His name is great in Israel.","sources":{"KJV":{"text":"In Judah is God known: his name is great in Israel."},"BSB":{"text":"God is known in Judah; His name is great in Israel."}},"definableWords":["God","Judah","name","great","Israel"],"peopleInVerse":[]},"2":{"text":"In Salem also is his tabernacle, and his dwelling place in Zion.","ref":"Psalms 76:2","synthesized":"His tent is in Salem, His dwelling place in Zion.","sources":{"KJV":{"text":"In Salem also is his tabernacle, and his dwelling place in Zion."},"BSB":{"text":"His tent is in Salem, His dwelling place in Zion."}},"definableWords":["Salem","Zion"],"peopleInVerse":[]},"3":{"text":"There brake he the arrows of the bow, the shield, and the sword, and the battle. Selah.","ref":"Psalms 76:3","synthesized":"There He shattered the flaming arrows, the shield and sword and weapons of war. Selah","sources":{"KJV":{"text":"There brake he the arrows of the bow, the shield, and the sword, and the battle. Selah."},"BSB":{"text":"There He shattered the flaming arrows, the shield and sword and weapons of war. Selah"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Thou art more glorious and excellent than the mountains of prey.","ref":"Psalms 76:4","synthesized":"You are resplendent with light, more majestic than mountains filled with game.","sources":{"KJV":{"text":"Thou art more glorious and excellent than the mountains of prey."},"BSB":{"text":"You are resplendent with light, more majestic than mountains filled with game."}},"definableWords":["light"],"peopleInVerse":[]},"5":{"text":"The stouthearted are spoiled, they have slept their sleep: and none of the men of might have found their hands.","ref":"Psalms 76:5","synthesized":"The valiant lie plundered; they sleep their last sleep. No men of might could lift a hand.","sources":{"KJV":{"text":"The stouthearted are spoiled, they have slept their sleep: and none of the men of might have found their hands."},"BSB":{"text":"The valiant lie plundered; they sleep their last sleep. No men of might could lift a hand."}},"definableWords":["men"],"peopleInVerse":[]},"6":{"text":"At thy rebuke, O God of Jacob, both the chariot and horse are cast into a dead sleep.","ref":"Psalms 76:6","synthesized":"At Your rebuke, O God of Jacob, both horse and rider lie stunned.","sources":{"KJV":{"text":"At thy rebuke, O God of Jacob, both the chariot and horse are cast into a dead sleep."},"BSB":{"text":"At Your rebuke, O God of Jacob, both horse and rider lie stunned."}},"definableWords":["God","Jacob"],"peopleInVerse":["Jacob"]},"7":{"text":"Thou, even thou, art to be feared: and who may stand in thy sight when once thou art angry?","ref":"Psalms 76:7","synthesized":"You alone are to be feared. When You are angry, who can stand before You?","sources":{"KJV":{"text":"Thou, even thou, art to be feared: and who may stand in thy sight when once thou art angry?"},"BSB":{"text":"You alone are to be feared. When You are angry, who can stand before You?"}},"definableWords":["stand"],"peopleInVerse":[]},"8":{"text":"Thou didst cause judgment to be heard from heaven; the earth feared, and was still,","ref":"Psalms 76:8","synthesized":"From heaven You pronounced judgment, and the earth feared and was still","sources":{"KJV":{"text":"Thou didst cause judgment to be heard from heaven; the earth feared, and was still,"},"BSB":{"text":"From heaven You pronounced judgment, and the earth feared and was still"}},"definableWords":["heaven","judgment","earth"],"peopleInVerse":[]},"9":{"text":"When God arose to judgment, to save all the meek of the earth. Selah.","ref":"Psalms 76:9","synthesized":"when God rose up to judge, to save all the lowly of the earth. Selah","sources":{"KJV":{"text":"When God arose to judgment, to save all the meek of the earth. Selah."},"BSB":{"text":"when God rose up to judge, to save all the lowly of the earth. Selah"}},"definableWords":["God","earth"],"peopleInVerse":[]},"10":{"text":"Surely the wrath of man shall praise thee: the remainder of wrath shalt thou restrain.","ref":"Psalms 76:10","synthesized":"Even the wrath of man shall praise You; with the survivors of wrath You will clothe Yourself.","sources":{"KJV":{"text":"Surely the wrath of man shall praise thee: the remainder of wrath shalt thou restrain."},"BSB":{"text":"Even the wrath of man shall praise You; with the survivors of wrath You will clothe Yourself."}},"definableWords":["wrath","man","praise"],"peopleInVerse":[]},"11":{"text":"Vow, and pay unto the LORD your God: let all that be round about him bring presents unto him that ought to be feared.","ref":"Psalms 76:11","synthesized":"Make and fulfill your vows to the LORD your God; let all the neighboring lands bring tribute to Him who is to be feared.","sources":{"KJV":{"text":"Vow, and pay unto the LORD your God: let all that be round about him bring presents unto him that ought to be feared."},"BSB":{"text":"Make and fulfill your vows to the LORD your God; let all the neighboring lands bring tribute to Him who is to be feared."}},"definableWords":["make","LORD","God"],"peopleInVerse":[]},"12":{"text":"He shall cut off the spirit of princes: he is terrible to the kings of the earth.","ref":"Psalms 76:12","synthesized":"He breaks the spirits of princes; He is feared by the kings of the earth.","sources":{"KJV":{"text":"He shall cut off the spirit of princes: he is terrible to the kings of the earth."},"BSB":{"text":"He breaks the spirits of princes; He is feared by the kings of the earth."}},"definableWords":["kings","earth"],"peopleInVerse":[]}}},"77":{"chapter":"77","title":"I CRIED UNTO GOD WITH MY VOICE","verses":{"1":{"text":"I cried unto God with my voice, even unto God with my voice; and he gave ear unto me.","ref":"Psalms 77:1","synthesized":"I cried out to God; I cried aloud to God to hear me.","sources":{"KJV":{"text":"I cried unto God with my voice, even unto God with my voice; and he gave ear unto me."},"BSB":{"text":"I cried out to God; I cried aloud to God to hear me."}},"definableWords":["God","hear"],"peopleInVerse":[]},"2":{"text":"In the day of my trouble I sought the Lord: my sore ran in the night, and ceased not: my soul refused to be comforted.","ref":"Psalms 77:2","synthesized":"In the day of trouble I sought the Lord; through the night my outstretched hands did not grow weary; my soul refused to be comforted.","sources":{"KJV":{"text":"In the day of my trouble I sought the Lord: my sore ran in the night, and ceased not: my soul refused to be comforted."},"BSB":{"text":"In the day of trouble I sought the Lord; through the night my outstretched hands did not grow weary; my soul refused to be comforted."}},"definableWords":["day","Lord","night","soul"],"peopleInVerse":[]},"3":{"text":"I remembered God, and was troubled: I complained, and my spirit was overwhelmed. Selah.","ref":"Psalms 77:3","synthesized":"I remembered You, O God, and I groaned; I mused and my spirit grew faint. Selah","sources":{"KJV":{"text":"I remembered God, and was troubled: I complained, and my spirit was overwhelmed. Selah."},"BSB":{"text":"I remembered You, O God, and I groaned; I mused and my spirit grew faint. Selah"}},"definableWords":["remembered","God","spirit"],"peopleInVerse":[]},"4":{"text":"Thou holdest mine eyes waking: I am so troubled that I cannot speak.","ref":"Psalms 77:4","synthesized":"You have kept my eyes from closing; I am too troubled to speak.","sources":{"KJV":{"text":"Thou holdest mine eyes waking: I am so troubled that I cannot speak."},"BSB":{"text":"You have kept my eyes from closing; I am too troubled to speak."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"I have considered the days of old, the years of ancient times.","ref":"Psalms 77:5","synthesized":"I considered the days of old, the years long in the past.","sources":{"KJV":{"text":"I have considered the days of old, the years of ancient times."},"BSB":{"text":"I considered the days of old, the years long in the past."}},"definableWords":["days","years"],"peopleInVerse":[]},"6":{"text":"I call to remembrance my song in the night: I commune with mine own heart: and my spirit made diligent search.","ref":"Psalms 77:6","synthesized":"At night I remembered my song; in my heart I mused, and my spirit pondered:","sources":{"KJV":{"text":"I call to remembrance my song in the night: I commune with mine own heart: and my spirit made diligent search."},"BSB":{"text":"At night I remembered my song; in my heart I mused, and my spirit pondered:"}},"definableWords":["night","remembered","heart","spirit"],"peopleInVerse":[]},"7":{"text":"Will the Lord cast off for ever? and will he be favourable no more?","ref":"Psalms 77:7","synthesized":"“Will the Lord spurn us forever and never show His favor again?","sources":{"KJV":{"text":"Will the Lord cast off for ever? and will he be favourable no more?"},"BSB":{"text":"“Will the Lord spurn us forever and never show His favor again?"}},"definableWords":["Lord"],"peopleInVerse":[]},"8":{"text":"Is his mercy clean gone for ever? doth his promise fail for evermore?","ref":"Psalms 77:8","synthesized":"Is His loving devotion gone forever? Has His promise failed for all time?","sources":{"KJV":{"text":"Is his mercy clean gone for ever? doth his promise fail for evermore?"},"BSB":{"text":"Is His loving devotion gone forever? Has His promise failed for all time?"}},"definableWords":["promise"],"peopleInVerse":[]},"9":{"text":"Hath God forgotten to be gracious? hath he in anger shut up his tender mercies? Selah.","ref":"Psalms 77:9","synthesized":"Has God forgotten to be gracious? Has His anger shut off His compassion?” Selah","sources":{"KJV":{"text":"Hath God forgotten to be gracious? hath he in anger shut up his tender mercies? Selah."},"BSB":{"text":"Has God forgotten to be gracious? Has His anger shut off His compassion?” Selah"}},"definableWords":["God","anger"],"peopleInVerse":[]},"10":{"text":"And I said, This is my infirmity: but I will remember the years of the right hand of the most High.","ref":"Psalms 77:10","synthesized":"So I said, “I am grieved that the right hand of the Most High has changed.”","sources":{"KJV":{"text":"And I said, This is my infirmity: but I will remember the years of the right hand of the most High."},"BSB":{"text":"So I said, “I am grieved that the right hand of the Most High has changed.”"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"I will remember the works of the LORD: surely I will remember thy wonders of old.","ref":"Psalms 77:11","synthesized":"I will remember the works of the LORD; yes, I will remember Your wonders of old.","sources":{"KJV":{"text":"I will remember the works of the LORD: surely I will remember thy wonders of old."},"BSB":{"text":"I will remember the works of the LORD; yes, I will remember Your wonders of old."}},"definableWords":["remember","works","LORD"],"peopleInVerse":[]},"12":{"text":"I will meditate also of all thy work, and talk of thy doings.","ref":"Psalms 77:12","synthesized":"I will reflect on all You have done and ponder Your mighty deeds.","sources":{"KJV":{"text":"I will meditate also of all thy work, and talk of thy doings."},"BSB":{"text":"I will reflect on all You have done and ponder Your mighty deeds."}},"definableWords":["mighty"],"peopleInVerse":[]},"13":{"text":"Thy way, O God, is in the sanctuary: who is so great a God as our God?","ref":"Psalms 77:13","synthesized":"Your way, O God, is holy. What god is so great as our God?","sources":{"KJV":{"text":"Thy way, O God, is in the sanctuary: who is so great a God as our God?"},"BSB":{"text":"Your way, O God, is holy. What god is so great as our God?"}},"definableWords":["way","God","holy","great"],"peopleInVerse":[]},"14":{"text":"Thou art the God that doest wonders: thou hast declared thy strength among the people.","ref":"Psalms 77:14","synthesized":"You are the God who works wonders; You display Your strength among the peoples.","sources":{"KJV":{"text":"Thou art the God that doest wonders: thou hast declared thy strength among the people."},"BSB":{"text":"You are the God who works wonders; You display Your strength among the peoples."}},"definableWords":["God","works"],"peopleInVerse":[]},"15":{"text":"Thou hast with thine arm redeemed thy people, the sons of Jacob and Joseph. Selah.","ref":"Psalms 77:15","synthesized":"With power You redeemed Your people, the sons of Jacob and Joseph. Selah","sources":{"KJV":{"text":"Thou hast with thine arm redeemed thy people, the sons of Jacob and Joseph. Selah."},"BSB":{"text":"With power You redeemed Your people, the sons of Jacob and Joseph. Selah"}},"definableWords":["people","sons","Jacob","Joseph"],"peopleInVerse":["Jacob","Joseph"]},"16":{"text":"The waters saw thee, O God, the waters saw thee; they were afraid: the depths also were troubled.","ref":"Psalms 77:16","synthesized":"The waters saw You, O God; the waters saw You and swirled; even the depths were shaken.","sources":{"KJV":{"text":"The waters saw thee, O God, the waters saw thee; they were afraid: the depths also were troubled."},"BSB":{"text":"The waters saw You, O God; the waters saw You and swirled; even the depths were shaken."}},"definableWords":["waters","saw","God"],"peopleInVerse":[]},"17":{"text":"The clouds poured out water: the skies sent out a sound: thine arrows also went abroad.","ref":"Psalms 77:17","synthesized":"The clouds poured down water; the skies resounded with thunder; Your arrows flashed back and forth.","sources":{"KJV":{"text":"The clouds poured out water: the skies sent out a sound: thine arrows also went abroad."},"BSB":{"text":"The clouds poured down water; the skies resounded with thunder; Your arrows flashed back and forth."}},"definableWords":["water"],"peopleInVerse":[]},"18":{"text":"The voice of thy thunder was in the heaven: the lightnings lightened the world: the earth trembled and shook.","ref":"Psalms 77:18","synthesized":"Your thunder resounded in the whirlwind; the lightning lit up the world; the earth trembled and quaked.","sources":{"KJV":{"text":"The voice of thy thunder was in the heaven: the lightnings lightened the world: the earth trembled and shook."},"BSB":{"text":"Your thunder resounded in the whirlwind; the lightning lit up the world; the earth trembled and quaked."}},"definableWords":["earth"],"peopleInVerse":[]},"19":{"text":"Thy way is in the sea, and thy path in the great waters, and thy footsteps are not known.","ref":"Psalms 77:19","synthesized":"Your path led through the sea, Your way through the mighty waters, but Your footprints were not to be found.","sources":{"KJV":{"text":"Thy way is in the sea, and thy path in the great waters, and thy footsteps are not known."},"BSB":{"text":"Your path led through the sea, Your way through the mighty waters, but Your footprints were not to be found."}},"definableWords":["sea","way","mighty","waters"],"peopleInVerse":[]},"20":{"text":"Thou leddest thy people like a flock by the hand of Moses and Aaron.","ref":"Psalms 77:20","synthesized":"You led Your people like a flock by the hand of Moses and Aaron.","sources":{"KJV":{"text":"Thou leddest thy people like a flock by the hand of Moses and Aaron."},"BSB":{"text":"You led Your people like a flock by the hand of Moses and Aaron."}},"definableWords":["people"],"peopleInVerse":["Moses","Aaron"]}}},"78":{"chapter":"78","title":"ISRAEL'S HISTORY REMEMBERED","verses":{"1":{"text":"Give ear, O my people, to my law: incline your ears to the words of my mouth.","ref":"Psalms 78:1","synthesized":"Give ear, O my people, to my instruction; listen to the words of my mouth.","sources":{"KJV":{"text":"Give ear, O my people, to my law: incline your ears to the words of my mouth."},"BSB":{"text":"Give ear, O my people, to my instruction; listen to the words of my mouth."}},"definableWords":["people"],"peopleInVerse":[]},"2":{"text":"I will open my mouth in a parable: I will utter dark sayings of old:","ref":"Psalms 78:2","synthesized":"I will open my mouth in parables; I will utter things hidden from the beginning,","sources":{"KJV":{"text":"I will open my mouth in a parable: I will utter dark sayings of old:"},"BSB":{"text":"I will open my mouth in parables; I will utter things hidden from the beginning,"}},"definableWords":["beginning"],"peopleInVerse":[]},"3":{"text":"Which we have heard and known, and our fathers have told us.","ref":"Psalms 78:3","synthesized":"that we have heard and known and our fathers have relayed to us.","sources":{"KJV":{"text":"Which we have heard and known, and our fathers have told us."},"BSB":{"text":"that we have heard and known and our fathers have relayed to us."}},"definableWords":["fathers"],"peopleInVerse":[]},"4":{"text":"We will not hide them from their children, shewing to the generation to come the praises of the LORD, and his strength, and his wonderful works that he hath done.","ref":"Psalms 78:4","synthesized":"We will not hide them from their children, but will declare to the next generation the praises of the LORD and His might, and the wonders He has performed.","sources":{"KJV":{"text":"We will not hide them from their children, shewing to the generation to come the praises of the LORD, and his strength, and his wonderful works that he hath done."},"BSB":{"text":"We will not hide them from their children, but will declare to the next generation the praises of the LORD and His might, and the wonders He has performed."}},"definableWords":["LORD"],"peopleInVerse":[]},"5":{"text":"For he established a testimony in Jacob, and appointed a law in Israel, which he commanded our fathers, that they should make them known to their children:","ref":"Psalms 78:5","synthesized":"For He established a testimony in Jacob and appointed a law in Israel, which He commanded our fathers to teach to their children,","sources":{"KJV":{"text":"For he established a testimony in Jacob, and appointed a law in Israel, which he commanded our fathers, that they should make them known to their children:"},"BSB":{"text":"For He established a testimony in Jacob and appointed a law in Israel, which He commanded our fathers to teach to their children,"}},"definableWords":["Jacob","law","Israel","fathers"],"peopleInVerse":["Jacob"]},"6":{"text":"That the generation to come might know them, even the children which should be born; who should arise and declare them to their children:","ref":"Psalms 78:6","synthesized":"that the coming generation would know them— even children yet to be born— to arise and tell their own children","sources":{"KJV":{"text":"That the generation to come might know them, even the children which should be born; who should arise and declare them to their children:"},"BSB":{"text":"that the coming generation would know them— even children yet to be born— to arise and tell their own children"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"That they might set their hope in God, and not forget the works of God, but keep his commandments:","ref":"Psalms 78:7","synthesized":"that they should put their confidence in God, not forgetting His works, but keeping His commandments.","sources":{"KJV":{"text":"That they might set their hope in God, and not forget the works of God, but keep his commandments:"},"BSB":{"text":"that they should put their confidence in God, not forgetting His works, but keeping His commandments."}},"definableWords":["God","works"],"peopleInVerse":[]},"8":{"text":"And might not be as their fathers, a stubborn and rebellious generation; a generation that set not their heart aright, and whose spirit was not stedfast with God.","ref":"Psalms 78:8","synthesized":"Then they will not be like their fathers, a stubborn and rebellious generation, whose heart was not loyal, whose spirit was not faithful to God.","sources":{"KJV":{"text":"And might not be as their fathers, a stubborn and rebellious generation; a generation that set not their heart aright, and whose spirit was not stedfast with God."},"BSB":{"text":"Then they will not be like their fathers, a stubborn and rebellious generation, whose heart was not loyal, whose spirit was not faithful to God."}},"definableWords":["fathers","heart","spirit","God"],"peopleInVerse":[]},"9":{"text":"The children of Ephraim, being armed, and carrying bows, turned back in the day of battle.","ref":"Psalms 78:9","synthesized":"The archers of Ephraim turned back on the day of battle.","sources":{"KJV":{"text":"The children of Ephraim, being armed, and carrying bows, turned back in the day of battle."},"BSB":{"text":"The archers of Ephraim turned back on the day of battle."}},"definableWords":["day"],"peopleInVerse":[]},"10":{"text":"They kept not the covenant of God, and refused to walk in his law;","ref":"Psalms 78:10","synthesized":"They failed to keep God’s covenant and refused to live by His law.","sources":{"KJV":{"text":"They kept not the covenant of God, and refused to walk in his law;"},"BSB":{"text":"They failed to keep God’s covenant and refused to live by His law."}},"definableWords":["keep","God","covenant","live","law"],"peopleInVerse":[]},"11":{"text":"And forgat his works, and his wonders that he had shewed them.","ref":"Psalms 78:11","synthesized":"They forgot what He had done, the wonders He had shown them.","sources":{"KJV":{"text":"And forgat his works, and his wonders that he had shewed them."},"BSB":{"text":"They forgot what He had done, the wonders He had shown them."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Marvellous things did he in the sight of their fathers, in the land of Egypt, in the field of Zoan.","ref":"Psalms 78:12","synthesized":"He worked wonders before their fathers in the land of Egypt, in the region of Zoan.","sources":{"KJV":{"text":"Marvellous things did he in the sight of their fathers, in the land of Egypt, in the field of Zoan."},"BSB":{"text":"He worked wonders before their fathers in the land of Egypt, in the region of Zoan."}},"definableWords":["fathers","land","Egypt"],"peopleInVerse":[]},"13":{"text":"He divided the sea, and caused them to pass through; and he made the waters to stand as an heap.","ref":"Psalms 78:13","synthesized":"He split the sea and brought them through; He set the waters upright like a wall.","sources":{"KJV":{"text":"He divided the sea, and caused them to pass through; and he made the waters to stand as an heap."},"BSB":{"text":"He split the sea and brought them through; He set the waters upright like a wall."}},"definableWords":["sea","waters"],"peopleInVerse":[]},"14":{"text":"In the daytime also he led them with a cloud, and all the night with a light of fire.","ref":"Psalms 78:14","synthesized":"He led them with a cloud by day and with a light of fire all night.","sources":{"KJV":{"text":"In the daytime also he led them with a cloud, and all the night with a light of fire."},"BSB":{"text":"He led them with a cloud by day and with a light of fire all night."}},"definableWords":["day","light","night"],"peopleInVerse":[]},"15":{"text":"He clave the rocks in the wilderness, and gave them drink as out of the great depths.","ref":"Psalms 78:15","synthesized":"He split the rocks in the wilderness and gave them drink as abundant as the seas.","sources":{"KJV":{"text":"He clave the rocks in the wilderness, and gave them drink as out of the great depths."},"BSB":{"text":"He split the rocks in the wilderness and gave them drink as abundant as the seas."}},"definableWords":["seas"],"peopleInVerse":[]},"16":{"text":"He brought streams also out of the rock, and caused waters to run down like rivers.","ref":"Psalms 78:16","synthesized":"He brought streams from the stone and made water flow down like rivers.","sources":{"KJV":{"text":"He brought streams also out of the rock, and caused waters to run down like rivers."},"BSB":{"text":"He brought streams from the stone and made water flow down like rivers."}},"definableWords":["stone","made","water"],"peopleInVerse":[]},"17":{"text":"And they sinned yet more against him by provoking the most High in the wilderness.","ref":"Psalms 78:17","synthesized":"But they continued to sin against Him, rebelling in the desert against the Most High.","sources":{"KJV":{"text":"And they sinned yet more against him by provoking the most High in the wilderness."},"BSB":{"text":"But they continued to sin against Him, rebelling in the desert against the Most High."}},"definableWords":["sin"],"peopleInVerse":[]},"18":{"text":"And they tempted God in their heart by asking meat for their lust.","ref":"Psalms 78:18","synthesized":"They willfully tested God by demanding the food they craved.","sources":{"KJV":{"text":"And they tempted God in their heart by asking meat for their lust."},"BSB":{"text":"They willfully tested God by demanding the food they craved."}},"definableWords":["God"],"peopleInVerse":[]},"19":{"text":"Yea, they spake against God; they said, Can God furnish a table in the wilderness?","ref":"Psalms 78:19","synthesized":"They spoke against God, saying, “Can God really prepare a table in the wilderness?","sources":{"KJV":{"text":"Yea, they spake against God; they said, Can God furnish a table in the wilderness?"},"BSB":{"text":"They spoke against God, saying, “Can God really prepare a table in the wilderness?"}},"definableWords":["God"],"peopleInVerse":[]},"20":{"text":"Behold, he smote the rock, that the waters gushed out, and the streams overflowed; can he give bread also? can he provide flesh for his people?","ref":"Psalms 78:20","synthesized":"When He struck the rock, water gushed out and torrents raged. But can He also give bread or supply His people with meat?”","sources":{"KJV":{"text":"Behold, he smote the rock, that the waters gushed out, and the streams overflowed; can he give bread also? can he provide flesh for his people?"},"BSB":{"text":"When He struck the rock, water gushed out and torrents raged. But can He also give bread or supply His people with meat?”"}},"definableWords":["water","or","people"],"peopleInVerse":[]},"21":{"text":"Therefore the LORD heard this, and was wroth: so a fire was kindled against Jacob, and anger also came up against Israel;","ref":"Psalms 78:21","synthesized":"Therefore the LORD heard and was filled with wrath; so a fire was kindled against Jacob, and His anger flared against Israel,","sources":{"KJV":{"text":"Therefore the LORD heard this, and was wroth: so a fire was kindled against Jacob, and anger also came up against Israel;"},"BSB":{"text":"Therefore the LORD heard and was filled with wrath; so a fire was kindled against Jacob, and His anger flared against Israel,"}},"definableWords":["LORD","wrath","Jacob","anger","Israel"],"peopleInVerse":["Jacob"]},"22":{"text":"Because they believed not in God, and trusted not in his salvation:","ref":"Psalms 78:22","synthesized":"because they did not believe God or rely on His salvation.","sources":{"KJV":{"text":"Because they believed not in God, and trusted not in his salvation:"},"BSB":{"text":"because they did not believe God or rely on His salvation."}},"definableWords":["God","or","salvation"],"peopleInVerse":[]},"23":{"text":"Though he had commanded the clouds from above, and opened the doors of heaven,","ref":"Psalms 78:23","synthesized":"Yet He commanded the clouds above and opened the doors of the heavens.","sources":{"KJV":{"text":"Though he had commanded the clouds from above, and opened the doors of heaven,"},"BSB":{"text":"Yet He commanded the clouds above and opened the doors of the heavens."}},"definableWords":["heavens"],"peopleInVerse":[]},"24":{"text":"And had rained down manna upon them to eat, and had given them of the corn of heaven.","ref":"Psalms 78:24","synthesized":"He rained down manna for them to eat; He gave them grain from heaven.","sources":{"KJV":{"text":"And had rained down manna upon them to eat, and had given them of the corn of heaven."},"BSB":{"text":"He rained down manna for them to eat; He gave them grain from heaven."}},"definableWords":["manna","heaven"],"peopleInVerse":[]},"25":{"text":"Man did eat angels’ food: he sent them meat to the full.","ref":"Psalms 78:25","synthesized":"Man ate the bread of angels; He sent them food in abundance.","sources":{"KJV":{"text":"Man did eat angels’ food: he sent them meat to the full."},"BSB":{"text":"Man ate the bread of angels; He sent them food in abundance."}},"definableWords":["man"],"peopleInVerse":[]},"26":{"text":"He caused an east wind to blow in the heaven: and by his power he brought in the south wind.","ref":"Psalms 78:26","synthesized":"He stirred the east wind from the heavens and drove the south wind by His might.","sources":{"KJV":{"text":"He caused an east wind to blow in the heaven: and by his power he brought in the south wind."},"BSB":{"text":"He stirred the east wind from the heavens and drove the south wind by His might."}},"definableWords":["heavens"],"peopleInVerse":[]},"27":{"text":"He rained flesh also upon them as dust, and feathered fowls like as the sand of the sea:","ref":"Psalms 78:27","synthesized":"He rained meat on them like dust, and winged birds like the sand of the sea.","sources":{"KJV":{"text":"He rained flesh also upon them as dust, and feathered fowls like as the sand of the sea:"},"BSB":{"text":"He rained meat on them like dust, and winged birds like the sand of the sea."}},"definableWords":["birds","sea"],"peopleInVerse":[]},"28":{"text":"And he let it fall in the midst of their camp, round about their habitations.","ref":"Psalms 78:28","synthesized":"He felled them in the midst of their camp, all around their dwellings.","sources":{"KJV":{"text":"And he let it fall in the midst of their camp, round about their habitations."},"BSB":{"text":"He felled them in the midst of their camp, all around their dwellings."}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"So they did eat, and were well filled: for he gave them their own desire;","ref":"Psalms 78:29","synthesized":"So they ate and were well filled, for He gave them what they craved.","sources":{"KJV":{"text":"So they did eat, and were well filled: for he gave them their own desire;"},"BSB":{"text":"So they ate and were well filled, for He gave them what they craved."}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"They were not estranged from their lust. But while their meat was yet in their mouths,","ref":"Psalms 78:30","synthesized":"Yet before they had filled their desire, with the food still in their mouths,","sources":{"KJV":{"text":"They were not estranged from their lust. But while their meat was yet in their mouths,"},"BSB":{"text":"Yet before they had filled their desire, with the food still in their mouths,"}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"The wrath of God came upon them, and slew the fattest of them, and smote down the chosen men of Israel.","ref":"Psalms 78:31","synthesized":"God’s anger flared against them, and He put to death their strongest and subdued the young men of Israel.","sources":{"KJV":{"text":"The wrath of God came upon them, and slew the fattest of them, and smote down the chosen men of Israel."},"BSB":{"text":"God’s anger flared against them, and He put to death their strongest and subdued the young men of Israel."}},"definableWords":["God","anger","death","men","Israel"],"peopleInVerse":[]},"32":{"text":"For all this they sinned still, and believed not for his wondrous works.","ref":"Psalms 78:32","synthesized":"In spite of all this, they kept on sinning; despite His wonderful works, they did not believe.","sources":{"KJV":{"text":"For all this they sinned still, and believed not for his wondrous works."},"BSB":{"text":"In spite of all this, they kept on sinning; despite His wonderful works, they did not believe."}},"definableWords":["works"],"peopleInVerse":[]},"33":{"text":"Therefore their days did he consume in vanity, and their years in trouble.","ref":"Psalms 78:33","synthesized":"So He ended their days in futility, and their years in sudden terror.","sources":{"KJV":{"text":"Therefore their days did he consume in vanity, and their years in trouble."},"BSB":{"text":"So He ended their days in futility, and their years in sudden terror."}},"definableWords":["days","years"],"peopleInVerse":[]},"34":{"text":"When he slew them, then they sought him: and they returned and enquired early after God.","ref":"Psalms 78:34","synthesized":"When He slew them, they would seek Him; they repented and searched for God.","sources":{"KJV":{"text":"When he slew them, then they sought him: and they returned and enquired early after God."},"BSB":{"text":"When He slew them, they would seek Him; they repented and searched for God."}},"definableWords":["seek","God"],"peopleInVerse":[]},"35":{"text":"And they remembered that God was their rock, and the high God their redeemer.","ref":"Psalms 78:35","synthesized":"And they remembered that God was their Rock, that God Most High was their Redeemer.","sources":{"KJV":{"text":"And they remembered that God was their rock, and the high God their redeemer."},"BSB":{"text":"And they remembered that God was their Rock, that God Most High was their Redeemer."}},"definableWords":["remembered","God","Redeemer"],"peopleInVerse":[]},"36":{"text":"Nevertheless they did flatter him with their mouth, and they lied unto him with their tongues.","ref":"Psalms 78:36","synthesized":"But they deceived Him with their mouths, and lied to Him with their tongues.","sources":{"KJV":{"text":"Nevertheless they did flatter him with their mouth, and they lied unto him with their tongues."},"BSB":{"text":"But they deceived Him with their mouths, and lied to Him with their tongues."}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"For their heart was not right with him, neither were they stedfast in his covenant.","ref":"Psalms 78:37","synthesized":"Their hearts were disloyal to Him, and they were unfaithful to His covenant.","sources":{"KJV":{"text":"For their heart was not right with him, neither were they stedfast in his covenant."},"BSB":{"text":"Their hearts were disloyal to Him, and they were unfaithful to His covenant."}},"definableWords":["covenant"],"peopleInVerse":[]},"38":{"text":"But he, being full of compassion, forgave their iniquity, and destroyed them not: yea, many a time turned he his anger away, and did not stir up all his wrath.","ref":"Psalms 78:38","synthesized":"And yet He was compassionate; He forgave their iniquity and did not destroy them. He often restrained His anger and did not unleash His full wrath.","sources":{"KJV":{"text":"But he, being full of compassion, forgave their iniquity, and destroyed them not: yea, many a time turned he his anger away, and did not stir up all his wrath."},"BSB":{"text":"And yet He was compassionate; He forgave their iniquity and did not destroy them. He often restrained His anger and did not unleash His full wrath."}},"definableWords":["iniquity","anger","wrath"],"peopleInVerse":[]},"39":{"text":"For he remembered that they were but flesh; a wind that passeth away, and cometh not again.","ref":"Psalms 78:39","synthesized":"He remembered that they were but flesh, a passing breeze that does not return.","sources":{"KJV":{"text":"For he remembered that they were but flesh; a wind that passeth away, and cometh not again."},"BSB":{"text":"He remembered that they were but flesh, a passing breeze that does not return."}},"definableWords":["remembered","flesh"],"peopleInVerse":[]},"40":{"text":"How oft did they provoke him in the wilderness, and grieve him in the desert!","ref":"Psalms 78:40","synthesized":"How often they disobeyed Him in the wilderness and grieved Him in the desert!","sources":{"KJV":{"text":"How oft did they provoke him in the wilderness, and grieve him in the desert!"},"BSB":{"text":"How often they disobeyed Him in the wilderness and grieved Him in the desert!"}},"definableWords":[],"peopleInVerse":[]},"41":{"text":"Yea, they turned back and tempted God, and limited the Holy One of Israel.","ref":"Psalms 78:41","synthesized":"Again and again they tested God and provoked the Holy One of Israel.","sources":{"KJV":{"text":"Yea, they turned back and tempted God, and limited the Holy One of Israel."},"BSB":{"text":"Again and again they tested God and provoked the Holy One of Israel."}},"definableWords":["God","holy","one","Israel"],"peopleInVerse":[]},"42":{"text":"They remembered not his hand, nor the day when he delivered them from the enemy.","ref":"Psalms 78:42","synthesized":"They did not remember His power— the day He redeemed them from the adversary,","sources":{"KJV":{"text":"They remembered not his hand, nor the day when he delivered them from the enemy."},"BSB":{"text":"They did not remember His power— the day He redeemed them from the adversary,"}},"definableWords":["remember","day"],"peopleInVerse":[]},"43":{"text":"How he had wrought his signs in Egypt, and his wonders in the field of Zoan:","ref":"Psalms 78:43","synthesized":"when He performed His signs in Egypt and His wonders in the fields of Zoan.","sources":{"KJV":{"text":"How he had wrought his signs in Egypt, and his wonders in the field of Zoan:"},"BSB":{"text":"when He performed His signs in Egypt and His wonders in the fields of Zoan."}},"definableWords":["Egypt"],"peopleInVerse":[]},"44":{"text":"And had turned their rivers into blood; and their floods, that they could not drink.","ref":"Psalms 78:44","synthesized":"He turned their rivers to blood, and from their streams they could not drink.","sources":{"KJV":{"text":"And had turned their rivers into blood; and their floods, that they could not drink."},"BSB":{"text":"He turned their rivers to blood, and from their streams they could not drink."}},"definableWords":["blood"],"peopleInVerse":[]},"45":{"text":"He sent divers sorts of flies among them, which devoured them; and frogs, which destroyed them.","ref":"Psalms 78:45","synthesized":"He sent swarms of flies that devoured them, and frogs that devastated them.","sources":{"KJV":{"text":"He sent divers sorts of flies among them, which devoured them; and frogs, which destroyed them."},"BSB":{"text":"He sent swarms of flies that devoured them, and frogs that devastated them."}},"definableWords":[],"peopleInVerse":[]},"46":{"text":"He gave also their increase unto the caterpiller, and their labour unto the locust.","ref":"Psalms 78:46","synthesized":"He gave their crops to the grasshopper, the fruit of their labor to the locust.","sources":{"KJV":{"text":"He gave also their increase unto the caterpiller, and their labour unto the locust."},"BSB":{"text":"He gave their crops to the grasshopper, the fruit of their labor to the locust."}},"definableWords":[],"peopleInVerse":[]},"47":{"text":"He destroyed their vines with hail, and their sycomore trees with frost.","ref":"Psalms 78:47","synthesized":"He killed their vines with hailstones and their sycamore-figs with sleet.","sources":{"KJV":{"text":"He destroyed their vines with hail, and their sycomore trees with frost."},"BSB":{"text":"He killed their vines with hailstones and their sycamore-figs with sleet."}},"definableWords":[],"peopleInVerse":[]},"48":{"text":"He gave up their cattle also to the hail, and their flocks to hot thunderbolts.","ref":"Psalms 78:48","synthesized":"He abandoned their cattle to the hail and their livestock to bolts of lightning.","sources":{"KJV":{"text":"He gave up their cattle also to the hail, and their flocks to hot thunderbolts."},"BSB":{"text":"He abandoned their cattle to the hail and their livestock to bolts of lightning."}},"definableWords":["cattle"],"peopleInVerse":[]},"49":{"text":"He cast upon them the fierceness of his anger, wrath, and indignation, and trouble, by sending evil angels among them.","ref":"Psalms 78:49","synthesized":"He unleashed His fury against them, wrath, indignation, and calamity— a band of destroying angels.","sources":{"KJV":{"text":"He cast upon them the fierceness of his anger, wrath, and indignation, and trouble, by sending evil angels among them."},"BSB":{"text":"He unleashed His fury against them, wrath, indignation, and calamity— a band of destroying angels."}},"definableWords":["wrath"],"peopleInVerse":[]},"50":{"text":"He made a way to his anger; he spared not their soul from death, but gave their life over to the pestilence;","ref":"Psalms 78:50","synthesized":"He cleared a path for His anger; He did not spare them from death but delivered their lives to the plague.","sources":{"KJV":{"text":"He made a way to his anger; he spared not their soul from death, but gave their life over to the pestilence;"},"BSB":{"text":"He cleared a path for His anger; He did not spare them from death but delivered their lives to the plague."}},"definableWords":["anger","death"],"peopleInVerse":[]},"51":{"text":"And smote all the firstborn in Egypt; the chief of their strength in the tabernacles of Ham:","ref":"Psalms 78:51","synthesized":"He struck all the firstborn of Egypt, the virility in the tents of Ham.","sources":{"KJV":{"text":"And smote all the firstborn in Egypt; the chief of their strength in the tabernacles of Ham:"},"BSB":{"text":"He struck all the firstborn of Egypt, the virility in the tents of Ham."}},"definableWords":["Egypt","Ham"],"peopleInVerse":[]},"52":{"text":"But made his own people to go forth like sheep, and guided them in the wilderness like a flock.","ref":"Psalms 78:52","synthesized":"He led out His people like sheep and guided them like a flock in the wilderness.","sources":{"KJV":{"text":"But made his own people to go forth like sheep, and guided them in the wilderness like a flock."},"BSB":{"text":"He led out His people like sheep and guided them like a flock in the wilderness."}},"definableWords":["people"],"peopleInVerse":[]},"53":{"text":"And he led them on safely, so that they feared not: but the sea overwhelmed their enemies.","ref":"Psalms 78:53","synthesized":"He led them safely, so they did not fear, but the sea engulfed their enemies.","sources":{"KJV":{"text":"And he led them on safely, so that they feared not: but the sea overwhelmed their enemies."},"BSB":{"text":"He led them safely, so they did not fear, but the sea engulfed their enemies."}},"definableWords":["fear","sea"],"peopleInVerse":[]},"54":{"text":"And he brought them to the border of his sanctuary, even to this mountain, which his right hand had purchased.","ref":"Psalms 78:54","synthesized":"He brought them to His holy land, to the mountain His right hand had acquired.","sources":{"KJV":{"text":"And he brought them to the border of his sanctuary, even to this mountain, which his right hand had purchased."},"BSB":{"text":"He brought them to His holy land, to the mountain His right hand had acquired."}},"definableWords":["holy","land"],"peopleInVerse":[]},"55":{"text":"He cast out the heathen also before them, and divided them an inheritance by line, and made the tribes of Israel to dwell in their tents.","ref":"Psalms 78:55","synthesized":"He drove out nations before them and apportioned their inheritance; He settled the tribes of Israel in their tents.","sources":{"KJV":{"text":"He cast out the heathen also before them, and divided them an inheritance by line, and made the tribes of Israel to dwell in their tents."},"BSB":{"text":"He drove out nations before them and apportioned their inheritance; He settled the tribes of Israel in their tents."}},"definableWords":["nations","Israel"],"peopleInVerse":[]},"56":{"text":"Yet they tempted and provoked the most high God, and kept not his testimonies:","ref":"Psalms 78:56","synthesized":"But they tested and disobeyed God Most High, for they did not keep His decrees.","sources":{"KJV":{"text":"Yet they tempted and provoked the most high God, and kept not his testimonies:"},"BSB":{"text":"But they tested and disobeyed God Most High, for they did not keep His decrees."}},"definableWords":["God","keep"],"peopleInVerse":[]},"57":{"text":"But turned back, and dealt unfaithfully like their fathers: they were turned aside like a deceitful bow.","ref":"Psalms 78:57","synthesized":"They turned back and were faithless like their fathers, twisted like a faulty bow.","sources":{"KJV":{"text":"But turned back, and dealt unfaithfully like their fathers: they were turned aside like a deceitful bow."},"BSB":{"text":"They turned back and were faithless like their fathers, twisted like a faulty bow."}},"definableWords":["fathers"],"peopleInVerse":[]},"58":{"text":"For they provoked him to anger with their high places, and moved him to jealousy with their graven images.","ref":"Psalms 78:58","synthesized":"They enraged Him with their high places and provoked His jealousy with their idols.","sources":{"KJV":{"text":"For they provoked him to anger with their high places, and moved him to jealousy with their graven images."},"BSB":{"text":"They enraged Him with their high places and provoked His jealousy with their idols."}},"definableWords":[],"peopleInVerse":[]},"59":{"text":"When God heard this, he was wroth, and greatly abhorred Israel:","ref":"Psalms 78:59","synthesized":"On hearing it, God was furious and rejected Israel completely.","sources":{"KJV":{"text":"When God heard this, he was wroth, and greatly abhorred Israel:"},"BSB":{"text":"On hearing it, God was furious and rejected Israel completely."}},"definableWords":["God","Israel"],"peopleInVerse":[]},"60":{"text":"So that he forsook the tabernacle of Shiloh, the tent which he placed among men;","ref":"Psalms 78:60","synthesized":"He abandoned the tabernacle of Shiloh, the tent He had pitched among men.","sources":{"KJV":{"text":"So that he forsook the tabernacle of Shiloh, the tent which he placed among men;"},"BSB":{"text":"He abandoned the tabernacle of Shiloh, the tent He had pitched among men."}},"definableWords":["tabernacle","men"],"peopleInVerse":[]},"61":{"text":"And delivered his strength into captivity, and his glory into the enemy’s hand.","ref":"Psalms 78:61","synthesized":"He delivered His strength to captivity, and His splendor to the hand of the adversary.","sources":{"KJV":{"text":"And delivered his strength into captivity, and his glory into the enemy’s hand."},"BSB":{"text":"He delivered His strength to captivity, and His splendor to the hand of the adversary."}},"definableWords":[],"peopleInVerse":[]},"62":{"text":"He gave his people over also unto the sword; and was wroth with his inheritance.","ref":"Psalms 78:62","synthesized":"He surrendered His people to the sword because He was enraged by His heritage.","sources":{"KJV":{"text":"He gave his people over also unto the sword; and was wroth with his inheritance."},"BSB":{"text":"He surrendered His people to the sword because He was enraged by His heritage."}},"definableWords":["people"],"peopleInVerse":[]},"63":{"text":"The fire consumed their young men; and their maidens were not given to marriage.","ref":"Psalms 78:63","synthesized":"Fire consumed His young men, and their maidens were left without wedding songs.","sources":{"KJV":{"text":"The fire consumed their young men; and their maidens were not given to marriage."},"BSB":{"text":"Fire consumed His young men, and their maidens were left without wedding songs."}},"definableWords":["men"],"peopleInVerse":[]},"64":{"text":"Their priests fell by the sword; and their widows made no lamentation.","ref":"Psalms 78:64","synthesized":"His priests fell by the sword, but their widows could not lament.","sources":{"KJV":{"text":"Their priests fell by the sword; and their widows made no lamentation."},"BSB":{"text":"His priests fell by the sword, but their widows could not lament."}},"definableWords":[],"peopleInVerse":[]},"65":{"text":"Then the LORD awaked as one out of sleep, and like a mighty man that shouteth by reason of wine.","ref":"Psalms 78:65","synthesized":"Then the Lord awoke as from sleep, like a mighty warrior overcome by wine.","sources":{"KJV":{"text":"Then the LORD awaked as one out of sleep, and like a mighty man that shouteth by reason of wine."},"BSB":{"text":"Then the Lord awoke as from sleep, like a mighty warrior overcome by wine."}},"definableWords":["Lord","mighty","overcome"],"peopleInVerse":[]},"66":{"text":"And he smote his enemies in the hinder parts: he put them to a perpetual reproach.","ref":"Psalms 78:66","synthesized":"He beat back His foes; He put them to everlasting shame.","sources":{"KJV":{"text":"And he smote his enemies in the hinder parts: he put them to a perpetual reproach."},"BSB":{"text":"He beat back His foes; He put them to everlasting shame."}},"definableWords":["everlasting"],"peopleInVerse":[]},"67":{"text":"Moreover he refused the tabernacle of Joseph, and chose not the tribe of Ephraim:","ref":"Psalms 78:67","synthesized":"He rejected the tent of Joseph and refused the tribe of Ephraim.","sources":{"KJV":{"text":"Moreover he refused the tabernacle of Joseph, and chose not the tribe of Ephraim:"},"BSB":{"text":"He rejected the tent of Joseph and refused the tribe of Ephraim."}},"definableWords":["Joseph","tribe"],"peopleInVerse":["Joseph"]},"68":{"text":"But chose the tribe of Judah, the mount Zion which he loved.","ref":"Psalms 78:68","synthesized":"But He chose the tribe of Judah, Mount Zion, which He loved.","sources":{"KJV":{"text":"But chose the tribe of Judah, the mount Zion which he loved."},"BSB":{"text":"But He chose the tribe of Judah, Mount Zion, which He loved."}},"definableWords":["tribe","Judah","Zion"],"peopleInVerse":[]},"69":{"text":"And he built his sanctuary like high palaces, like the earth which he hath established for ever.","ref":"Psalms 78:69","synthesized":"He built His sanctuary like the heights, like the earth He has established forever.","sources":{"KJV":{"text":"And he built his sanctuary like high palaces, like the earth which he hath established for ever."},"BSB":{"text":"He built His sanctuary like the heights, like the earth He has established forever."}},"definableWords":["earth"],"peopleInVerse":[]},"70":{"text":"He chose David also his servant, and took him from the sheepfolds:","ref":"Psalms 78:70","synthesized":"He chose David His servant and took him from the sheepfolds;","sources":{"KJV":{"text":"He chose David also his servant, and took him from the sheepfolds:"},"BSB":{"text":"He chose David His servant and took him from the sheepfolds;"}},"definableWords":["servant"],"peopleInVerse":["David"]},"71":{"text":"From following the ewes great with young he brought him to feed Jacob his people, and Israel his inheritance.","ref":"Psalms 78:71","synthesized":"from tending the ewes He brought him to be shepherd of His people Jacob, of Israel His inheritance.","sources":{"KJV":{"text":"From following the ewes great with young he brought him to feed Jacob his people, and Israel his inheritance."},"BSB":{"text":"from tending the ewes He brought him to be shepherd of His people Jacob, of Israel His inheritance."}},"definableWords":["shepherd","people","Jacob","Israel"],"peopleInVerse":["Jacob"]},"72":{"text":"So he fed them according to the integrity of his heart; and guided them by the skilfulness of his hands.","ref":"Psalms 78:72","synthesized":"So David shepherded them with integrity of heart and guided them with skillful hands.","sources":{"KJV":{"text":"So he fed them according to the integrity of his heart; and guided them by the skilfulness of his hands."},"BSB":{"text":"So David shepherded them with integrity of heart and guided them with skillful hands."}},"definableWords":["heart"],"peopleInVerse":["David"]}}},"79":{"chapter":"79","title":"HEATHEN COME INTO THINE INHERITANCE","verses":{"1":{"text":"O GOD, the heathen are come into thine inheritance; thy holy temple have they defiled; they have laid Jerusalem on heaps.","ref":"Psalms 79:1","synthesized":"The nations, O God, have invaded Your inheritance; they have defiled Your holy temple and reduced Jerusalem to rubble.","sources":{"KJV":{"text":"O GOD, the heathen are come into thine inheritance; thy holy temple have they defiled; they have laid Jerusalem on heaps."},"BSB":{"text":"The nations, O God, have invaded Your inheritance; they have defiled Your holy temple and reduced Jerusalem to rubble."}},"definableWords":["nations","God","holy","temple","Jerusalem"],"peopleInVerse":[]},"2":{"text":"The dead bodies of thy servants have they given to be meat unto the fowls of the heaven, the flesh of thy saints unto the beasts of the earth.","ref":"Psalms 79:2","synthesized":"They have given the corpses of Your servants as food to the birds of the air, the flesh of Your saints to the beasts of the earth.","sources":{"KJV":{"text":"The dead bodies of thy servants have they given to be meat unto the fowls of the heaven, the flesh of thy saints unto the beasts of the earth."},"BSB":{"text":"They have given the corpses of Your servants as food to the birds of the air, the flesh of Your saints to the beasts of the earth."}},"definableWords":["servants","birds","flesh","earth"],"peopleInVerse":[]},"3":{"text":"Their blood have they shed like water round about Jerusalem; and there was none to bury them.","ref":"Psalms 79:3","synthesized":"They have poured out their blood like water all around Jerusalem, and there is no one to bury the dead.","sources":{"KJV":{"text":"Their blood have they shed like water round about Jerusalem; and there was none to bury them."},"BSB":{"text":"They have poured out their blood like water all around Jerusalem, and there is no one to bury the dead."}},"definableWords":["blood","water","Jerusalem","one"],"peopleInVerse":[]},"4":{"text":"We are become a reproach to our neighbours, a scorn and derision to them that are round about us.","ref":"Psalms 79:4","synthesized":"We have become a reproach to our neighbors, a scorn and derision to those around us.","sources":{"KJV":{"text":"We are become a reproach to our neighbours, a scorn and derision to them that are round about us."},"BSB":{"text":"We have become a reproach to our neighbors, a scorn and derision to those around us."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"How long, LORD? wilt thou be angry for ever? shall thy jealousy burn like fire?","ref":"Psalms 79:5","synthesized":"How long, O LORD? Will You be angry forever? Will Your jealousy burn like fire?","sources":{"KJV":{"text":"How long, LORD? wilt thou be angry for ever? shall thy jealousy burn like fire?"},"BSB":{"text":"How long, O LORD? Will You be angry forever? Will Your jealousy burn like fire?"}},"definableWords":["LORD"],"peopleInVerse":[]},"6":{"text":"Pour out thy wrath upon the heathen that have not known thee, and upon the kingdoms that have not called upon thy name.","ref":"Psalms 79:6","synthesized":"Pour out Your wrath on the nations that do not acknowledge You, on the kingdoms that refuse to call on Your name,","sources":{"KJV":{"text":"Pour out thy wrath upon the heathen that have not known thee, and upon the kingdoms that have not called upon thy name."},"BSB":{"text":"Pour out Your wrath on the nations that do not acknowledge You, on the kingdoms that refuse to call on Your name,"}},"definableWords":["wrath","nations","name"],"peopleInVerse":[]},"7":{"text":"For they have devoured Jacob, and laid waste his dwelling place.","ref":"Psalms 79:7","synthesized":"for they have devoured Jacob and devastated his homeland.","sources":{"KJV":{"text":"For they have devoured Jacob, and laid waste his dwelling place."},"BSB":{"text":"for they have devoured Jacob and devastated his homeland."}},"definableWords":["Jacob"],"peopleInVerse":["Jacob"]},"8":{"text":"O remember not against us former iniquities: let thy tender mercies speedily prevent us: for we are brought very low.","ref":"Psalms 79:8","synthesized":"Do not hold past sins against us; let Your compassion come quickly, for we are brought low.","sources":{"KJV":{"text":"O remember not against us former iniquities: let thy tender mercies speedily prevent us: for we are brought very low."},"BSB":{"text":"Do not hold past sins against us; let Your compassion come quickly, for we are brought low."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Help us, O God of our salvation, for the glory of thy name: and deliver us, and purge away our sins, for thy name’s sake.","ref":"Psalms 79:9","synthesized":"Help us, O God of our salvation, for the glory of Your name; deliver us and atone for our sins, for the sake of Your name.","sources":{"KJV":{"text":"Help us, O God of our salvation, for the glory of thy name: and deliver us, and purge away our sins, for thy name’s sake."},"BSB":{"text":"Help us, O God of our salvation, for the glory of Your name; deliver us and atone for our sins, for the sake of Your name."}},"definableWords":["God","salvation","glory","name","deliver"],"peopleInVerse":[]},"10":{"text":"Wherefore should the heathen say, Where is their God? let him be known among the heathen in our sight by the revenging of the blood of thy servants which is shed.","ref":"Psalms 79:10","synthesized":"Why should the nations ask, “Where is their God?” Before our eyes, make known among the nations Your vengeance for the bloodshed of Your servants.","sources":{"KJV":{"text":"Wherefore should the heathen say, Where is their God? let him be known among the heathen in our sight by the revenging of the blood of thy servants which is shed."},"BSB":{"text":"Why should the nations ask, “Where is their God?” Before our eyes, make known among the nations Your vengeance for the bloodshed of Your servants."}},"definableWords":["nations","God","make","servants"],"peopleInVerse":[]},"11":{"text":"Let the sighing of the prisoner come before thee; according to the greatness of thy power preserve thou those that are appointed to die;","ref":"Psalms 79:11","synthesized":"May the groans of the captives reach You; by the strength of Your arm preserve those condemned to death.","sources":{"KJV":{"text":"Let the sighing of the prisoner come before thee; according to the greatness of thy power preserve thou those that are appointed to die;"},"BSB":{"text":"May the groans of the captives reach You; by the strength of Your arm preserve those condemned to death."}},"definableWords":["death"],"peopleInVerse":[]},"12":{"text":"And render unto our neighbours sevenfold into their bosom their reproach, wherewith they have reproached thee, O Lord.","ref":"Psalms 79:12","synthesized":"Pay back into the laps of our neighbors sevenfold the reproach they hurled at You, O Lord.","sources":{"KJV":{"text":"And render unto our neighbours sevenfold into their bosom their reproach, wherewith they have reproached thee, O Lord."},"BSB":{"text":"Pay back into the laps of our neighbors sevenfold the reproach they hurled at You, O Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"13":{"text":"So we thy people and sheep of thy pasture will give thee thanks for ever: we will shew forth thy praise to all generations.","ref":"Psalms 79:13","synthesized":"Then we Your people, the sheep of Your pasture, will thank You forever; from generation to generation we will declare Your praise.","sources":{"KJV":{"text":"So we thy people and sheep of thy pasture will give thee thanks for ever: we will shew forth thy praise to all generations."},"BSB":{"text":"Then we Your people, the sheep of Your pasture, will thank You forever; from generation to generation we will declare Your praise."}},"definableWords":["people","praise"],"peopleInVerse":[]}}},"80":{"chapter":"80","title":"SHEPHERD OF ISRAEL, HEAR","verses":{"1":{"text":"Give ear, O Shepherd of Israel, thou that leadest Joseph like a flock; thou that dwellest between the cherubims, shine forth.","ref":"Psalms 80:1","synthesized":"Hear us, O Shepherd of Israel, who leads Joseph like a flock; You who sit enthroned between the cherubim, shine forth","sources":{"KJV":{"text":"Give ear, O Shepherd of Israel, thou that leadest Joseph like a flock; thou that dwellest between the cherubims, shine forth."},"BSB":{"text":"Hear us, O Shepherd of Israel, who leads Joseph like a flock; You who sit enthroned between the cherubim, shine forth"}},"definableWords":["hear","shepherd","Israel","Joseph"],"peopleInVerse":["Joseph"]},"2":{"text":"Before Ephraim and Benjamin and Manasseh stir up thy strength, and come and save us.","ref":"Psalms 80:2","synthesized":"before Ephraim, Benjamin, and Manasseh. Rally Your mighty power and come to save us.","sources":{"KJV":{"text":"Before Ephraim and Benjamin and Manasseh stir up thy strength, and come and save us."},"BSB":{"text":"before Ephraim, Benjamin, and Manasseh. Rally Your mighty power and come to save us."}},"definableWords":["Benjamin","mighty"],"peopleInVerse":[]},"3":{"text":"Turn us again, O God, and cause thy face to shine; and we shall be saved.","ref":"Psalms 80:3","synthesized":"Restore us, O God, and cause Your face to shine upon us, that we may be saved.","sources":{"KJV":{"text":"Turn us again, O God, and cause thy face to shine; and we shall be saved."},"BSB":{"text":"Restore us, O God, and cause Your face to shine upon us, that we may be saved."}},"definableWords":["God"],"peopleInVerse":[]},"4":{"text":"O LORD God of hosts, how long wilt thou be angry against the prayer of thy people?","ref":"Psalms 80:4","synthesized":"O LORD God of Hosts, how long will Your anger smolder against the prayers of Your people?","sources":{"KJV":{"text":"O LORD God of hosts, how long wilt thou be angry against the prayer of thy people?"},"BSB":{"text":"O LORD God of Hosts, how long will Your anger smolder against the prayers of Your people?"}},"definableWords":["LORD","God","anger","people"],"peopleInVerse":[]},"5":{"text":"Thou feedest them with the bread of tears; and givest them tears to drink in great measure.","ref":"Psalms 80:5","synthesized":"You fed them with the bread of tears and made them drink the full measure of their tears.","sources":{"KJV":{"text":"Thou feedest them with the bread of tears; and givest them tears to drink in great measure."},"BSB":{"text":"You fed them with the bread of tears and made them drink the full measure of their tears."}},"definableWords":["made"],"peopleInVerse":[]},"6":{"text":"Thou makest us a strife unto our neighbours: and our enemies laugh among themselves.","ref":"Psalms 80:6","synthesized":"You make us contend with our neighbors; our enemies mock us.","sources":{"KJV":{"text":"Thou makest us a strife unto our neighbours: and our enemies laugh among themselves."},"BSB":{"text":"You make us contend with our neighbors; our enemies mock us."}},"definableWords":["make"],"peopleInVerse":[]},"7":{"text":"Turn us again, O God of hosts, and cause thy face to shine; and we shall be saved.","ref":"Psalms 80:7","synthesized":"Restore us, O God of Hosts, and cause Your face to shine upon us, that we may be saved.","sources":{"KJV":{"text":"Turn us again, O God of hosts, and cause thy face to shine; and we shall be saved."},"BSB":{"text":"Restore us, O God of Hosts, and cause Your face to shine upon us, that we may be saved."}},"definableWords":["God"],"peopleInVerse":[]},"8":{"text":"Thou hast brought a vine out of Egypt: thou hast cast out the heathen, and planted it.","ref":"Psalms 80:8","synthesized":"You uprooted a vine from Egypt; You drove out the nations and transplanted it.","sources":{"KJV":{"text":"Thou hast brought a vine out of Egypt: thou hast cast out the heathen, and planted it."},"BSB":{"text":"You uprooted a vine from Egypt; You drove out the nations and transplanted it."}},"definableWords":["Egypt","nations"],"peopleInVerse":[]},"9":{"text":"Thou preparedst room before it, and didst cause it to take deep root, and it filled the land.","ref":"Psalms 80:9","synthesized":"You cleared the ground for it, and it took root and filled the land.","sources":{"KJV":{"text":"Thou preparedst room before it, and didst cause it to take deep root, and it filled the land."},"BSB":{"text":"You cleared the ground for it, and it took root and filled the land."}},"definableWords":["ground","land"],"peopleInVerse":[]},"10":{"text":"The hills were covered with the shadow of it, and the boughs thereof were like the goodly cedars.","ref":"Psalms 80:10","synthesized":"The mountains were covered by its shade, and the mighty cedars with its branches.","sources":{"KJV":{"text":"The hills were covered with the shadow of it, and the boughs thereof were like the goodly cedars."},"BSB":{"text":"The mountains were covered by its shade, and the mighty cedars with its branches."}},"definableWords":["mighty"],"peopleInVerse":[]},"11":{"text":"She sent out her boughs unto the sea, and her branches unto the river.","ref":"Psalms 80:11","synthesized":"It sent out its branches to the Sea, and its shoots toward the River.","sources":{"KJV":{"text":"She sent out her boughs unto the sea, and her branches unto the river."},"BSB":{"text":"It sent out its branches to the Sea, and its shoots toward the River."}},"definableWords":["sea"],"peopleInVerse":[]},"12":{"text":"Why hast thou then broken down her hedges, so that all they which pass by the way do pluck her?","ref":"Psalms 80:12","synthesized":"Why have You broken down its walls, so that all who pass by pick its fruit?","sources":{"KJV":{"text":"Why hast thou then broken down her hedges, so that all they which pass by the way do pluck her?"},"BSB":{"text":"Why have You broken down its walls, so that all who pass by pick its fruit?"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"The boar out of the wood doth waste it, and the wild beast of the field doth devour it.","ref":"Psalms 80:13","synthesized":"The boar from the forest ravages it, and the creatures of the field feed upon it.","sources":{"KJV":{"text":"The boar out of the wood doth waste it, and the wild beast of the field doth devour it."},"BSB":{"text":"The boar from the forest ravages it, and the creatures of the field feed upon it."}},"definableWords":["field"],"peopleInVerse":[]},"14":{"text":"Return, we beseech thee, O God of hosts: look down from heaven, and behold, and visit this vine;","ref":"Psalms 80:14","synthesized":"Return, O God of Hosts, we pray! Look down from heaven and see! Attend to this vine—","sources":{"KJV":{"text":"Return, we beseech thee, O God of hosts: look down from heaven, and behold, and visit this vine;"},"BSB":{"text":"Return, O God of Hosts, we pray! Look down from heaven and see! Attend to this vine—"}},"definableWords":["God","heaven","see"],"peopleInVerse":[]},"15":{"text":"And the vineyard which thy right hand hath planted, and the branch that thou madest strong for thyself.","ref":"Psalms 80:15","synthesized":"the root Your right hand has planted, the son You have raised up for Yourself.","sources":{"KJV":{"text":"And the vineyard which thy right hand hath planted, and the branch that thou madest strong for thyself."},"BSB":{"text":"the root Your right hand has planted, the son You have raised up for Yourself."}},"definableWords":["son"],"peopleInVerse":[]},"16":{"text":"It is burned with fire, it is cut down: they perish at the rebuke of thy countenance.","ref":"Psalms 80:16","synthesized":"Your vine has been cut down and burned; they perish at the rebuke of Your countenance.","sources":{"KJV":{"text":"It is burned with fire, it is cut down: they perish at the rebuke of thy countenance."},"BSB":{"text":"Your vine has been cut down and burned; they perish at the rebuke of Your countenance."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Let thy hand be upon the man of thy right hand, upon the son of man whom thou madest strong for thyself.","ref":"Psalms 80:17","synthesized":"Let Your hand be upon the man at Your right hand, on the son of man You have raised up for Yourself.","sources":{"KJV":{"text":"Let thy hand be upon the man of thy right hand, upon the son of man whom thou madest strong for thyself."},"BSB":{"text":"Let Your hand be upon the man at Your right hand, on the son of man You have raised up for Yourself."}},"definableWords":["man","son"],"peopleInVerse":[]},"18":{"text":"So will not we go back from thee: quicken us, and we will call upon thy name.","ref":"Psalms 80:18","synthesized":"Then we will not turn away from You; revive us, and we will call on Your name.","sources":{"KJV":{"text":"So will not we go back from thee: quicken us, and we will call upon thy name."},"BSB":{"text":"Then we will not turn away from You; revive us, and we will call on Your name."}},"definableWords":["name"],"peopleInVerse":[]},"19":{"text":"Turn us again, O LORD God of hosts, cause thy face to shine; and we shall be saved.","ref":"Psalms 80:19","synthesized":"Restore us, O LORD God of Hosts; cause Your face to shine upon us, that we may be saved.","sources":{"KJV":{"text":"Turn us again, O LORD God of hosts, cause thy face to shine; and we shall be saved."},"BSB":{"text":"Restore us, O LORD God of Hosts; cause Your face to shine upon us, that we may be saved."}},"definableWords":["LORD","God"],"peopleInVerse":[]}}},"81":{"chapter":"81","title":"SING ALOUD UNTO GOD OUR STRENGTH","verses":{"1":{"text":"Sing aloud unto God our strength: make a joyful noise unto the God of Jacob.","ref":"Psalms 81:1","synthesized":"Sing for joy to God our strength; make a joyful noise to the God of Jacob.","sources":{"KJV":{"text":"Sing aloud unto God our strength: make a joyful noise unto the God of Jacob."},"BSB":{"text":"Sing for joy to God our strength; make a joyful noise to the God of Jacob."}},"definableWords":["joy","God","make","Jacob"],"peopleInVerse":["Jacob"]},"2":{"text":"Take a psalm, and bring hither the timbrel, the pleasant harp with the psaltery.","ref":"Psalms 81:2","synthesized":"Lift up a song, strike the tambourine, play the sweet-sounding harp and lyre.","sources":{"KJV":{"text":"Take a psalm, and bring hither the timbrel, the pleasant harp with the psaltery."},"BSB":{"text":"Lift up a song, strike the tambourine, play the sweet-sounding harp and lyre."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Blow up the trumpet in the new moon, in the time appointed, on our solemn feast day.","ref":"Psalms 81:3","synthesized":"Sound the ram’s horn at the New Moon, and at the full moon on the day of our Feast.","sources":{"KJV":{"text":"Blow up the trumpet in the new moon, in the time appointed, on our solemn feast day."},"BSB":{"text":"Sound the ram’s horn at the New Moon, and at the full moon on the day of our Feast."}},"definableWords":["day"],"peopleInVerse":[]},"4":{"text":"For this was a statute for Israel, and a law of the God of Jacob.","ref":"Psalms 81:4","synthesized":"For this is a statute for Israel, an ordinance of the God of Jacob.","sources":{"KJV":{"text":"For this was a statute for Israel, and a law of the God of Jacob."},"BSB":{"text":"For this is a statute for Israel, an ordinance of the God of Jacob."}},"definableWords":["Israel","God","Jacob"],"peopleInVerse":["Jacob"]},"5":{"text":"This he ordained in Joseph for a testimony, when he went out through the land of Egypt: where I heard a language that I understood not.","ref":"Psalms 81:5","synthesized":"He ordained it as a testimony for Joseph when he went out over the land of Egypt, where I heard an unfamiliar language:","sources":{"KJV":{"text":"This he ordained in Joseph for a testimony, when he went out through the land of Egypt: where I heard a language that I understood not."},"BSB":{"text":"He ordained it as a testimony for Joseph when he went out over the land of Egypt, where I heard an unfamiliar language:"}},"definableWords":["Joseph","land","Egypt"],"peopleInVerse":["Joseph"]},"6":{"text":"I removed his shoulder from the burden: his hands were delivered from the pots.","ref":"Psalms 81:6","synthesized":"“I relieved his shoulder of the burden; his hands were freed from the basket.","sources":{"KJV":{"text":"I removed his shoulder from the burden: his hands were delivered from the pots."},"BSB":{"text":"“I relieved his shoulder of the burden; his hands were freed from the basket."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Thou calledst in trouble, and I delivered thee; I answered thee in the secret place of thunder: I proved thee at the waters of Meribah. Selah.","ref":"Psalms 81:7","synthesized":"You called out in distress, and I rescued you; I answered you from the cloud of thunder; I tested you at the waters of Meribah. Selah","sources":{"KJV":{"text":"Thou calledst in trouble, and I delivered thee; I answered thee in the secret place of thunder: I proved thee at the waters of Meribah. Selah."},"BSB":{"text":"You called out in distress, and I rescued you; I answered you from the cloud of thunder; I tested you at the waters of Meribah. Selah"}},"definableWords":["waters"],"peopleInVerse":[]},"8":{"text":"Hear, O my people, and I will testify unto thee: O Israel, if thou wilt hearken unto me;","ref":"Psalms 81:8","synthesized":"Hear, O My people, and I will warn you: O Israel, if only you would listen to Me!","sources":{"KJV":{"text":"Hear, O my people, and I will testify unto thee: O Israel, if thou wilt hearken unto me;"},"BSB":{"text":"Hear, O My people, and I will warn you: O Israel, if only you would listen to Me!"}},"definableWords":["hear","people","Israel"],"peopleInVerse":[]},"9":{"text":"There shall no strange god be in thee; neither shalt thou worship any strange god.","ref":"Psalms 81:9","synthesized":"There must be no strange god among you, nor shall you bow to a foreign god.","sources":{"KJV":{"text":"There shall no strange god be in thee; neither shalt thou worship any strange god."},"BSB":{"text":"There must be no strange god among you, nor shall you bow to a foreign god."}},"definableWords":["God"],"peopleInVerse":[]},"10":{"text":"I am the LORD thy God, which brought thee out of the land of Egypt: open thy mouth wide, and I will fill it.","ref":"Psalms 81:10","synthesized":"I am the LORD your God, who brought you up out of Egypt. Open wide your mouth, and I will fill it.","sources":{"KJV":{"text":"I am the LORD thy God, which brought thee out of the land of Egypt: open thy mouth wide, and I will fill it."},"BSB":{"text":"I am the LORD your God, who brought you up out of Egypt. Open wide your mouth, and I will fill it."}},"definableWords":["LORD","God","Egypt","fill"],"peopleInVerse":[]},"11":{"text":"But my people would not hearken to my voice; and Israel would none of me.","ref":"Psalms 81:11","synthesized":"But My people would not listen to Me, and Israel would not obey Me.","sources":{"KJV":{"text":"But my people would not hearken to my voice; and Israel would none of me."},"BSB":{"text":"But My people would not listen to Me, and Israel would not obey Me."}},"definableWords":["people","Israel"],"peopleInVerse":[]},"12":{"text":"So I gave them up unto their own hearts’ lust: and they walked in their own counsels.","ref":"Psalms 81:12","synthesized":"So I gave them up to their stubborn hearts to follow their own devices.","sources":{"KJV":{"text":"So I gave them up unto their own hearts’ lust: and they walked in their own counsels."},"BSB":{"text":"So I gave them up to their stubborn hearts to follow their own devices."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Oh that my people had hearkened unto me, and Israel had walked in my ways!","ref":"Psalms 81:13","synthesized":"If only My people would listen to Me, if Israel would follow My ways,","sources":{"KJV":{"text":"Oh that my people had hearkened unto me, and Israel had walked in my ways!"},"BSB":{"text":"If only My people would listen to Me, if Israel would follow My ways,"}},"definableWords":["people","Israel"],"peopleInVerse":[]},"14":{"text":"I should soon have subdued their enemies, and turned my hand against their adversaries.","ref":"Psalms 81:14","synthesized":"how soon I would subdue their enemies and turn My hand against their foes!","sources":{"KJV":{"text":"I should soon have subdued their enemies, and turned my hand against their adversaries."},"BSB":{"text":"how soon I would subdue their enemies and turn My hand against their foes!"}},"definableWords":["subdue"],"peopleInVerse":[]},"15":{"text":"The haters of the LORD should have submitted themselves unto him: but their time should have endured for ever.","ref":"Psalms 81:15","synthesized":"Those who hate the LORD would feign obedience, and their doom would last forever.","sources":{"KJV":{"text":"The haters of the LORD should have submitted themselves unto him: but their time should have endured for ever."},"BSB":{"text":"Those who hate the LORD would feign obedience, and their doom would last forever."}},"definableWords":["LORD"],"peopleInVerse":[]},"16":{"text":"He should have fed them also with the finest of the wheat: and with honey out of the rock should I have satisfied thee.","ref":"Psalms 81:16","synthesized":"But I would feed you the finest wheat; with honey from the rock I would satisfy you.”","sources":{"KJV":{"text":"He should have fed them also with the finest of the wheat: and with honey out of the rock should I have satisfied thee."},"BSB":{"text":"But I would feed you the finest wheat; with honey from the rock I would satisfy you.”"}},"definableWords":[],"peopleInVerse":[]}}},"82":{"chapter":"82","title":"GOD STANDETH IN THE CONGREGATION","verses":{"1":{"text":"God standeth in the congregation of the mighty; he judgeth among the gods.","ref":"Psalms 82:1","synthesized":"God presides in the divine assembly; He renders judgment among the gods:","sources":{"KJV":{"text":"God standeth in the congregation of the mighty; he judgeth among the gods."},"BSB":{"text":"God presides in the divine assembly; He renders judgment among the gods:"}},"definableWords":["God","judgment"],"peopleInVerse":[]},"2":{"text":"How long will ye judge unjustly, and accept the persons of the wicked? Selah.","ref":"Psalms 82:2","synthesized":"“How long will you judge unjustly and show partiality to the wicked? Selah","sources":{"KJV":{"text":"How long will ye judge unjustly, and accept the persons of the wicked? Selah."},"BSB":{"text":"“How long will you judge unjustly and show partiality to the wicked? Selah"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Defend the poor and fatherless: do justice to the afflicted and needy.","ref":"Psalms 82:3","synthesized":"Defend the cause of the weak and fatherless; uphold the rights of the afflicted and oppressed.","sources":{"KJV":{"text":"Defend the poor and fatherless: do justice to the afflicted and needy."},"BSB":{"text":"Defend the cause of the weak and fatherless; uphold the rights of the afflicted and oppressed."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Deliver the poor and needy: rid them out of the hand of the wicked.","ref":"Psalms 82:4","synthesized":"Rescue the weak and needy; save them from the hand of the wicked.","sources":{"KJV":{"text":"Deliver the poor and needy: rid them out of the hand of the wicked."},"BSB":{"text":"Rescue the weak and needy; save them from the hand of the wicked."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"They know not, neither will they understand; they walk on in darkness: all the foundations of the earth are out of course.","ref":"Psalms 82:5","synthesized":"They do not know or understand; they wander in the darkness; all the foundations of the earth are shaken.","sources":{"KJV":{"text":"They know not, neither will they understand; they walk on in darkness: all the foundations of the earth are out of course."},"BSB":{"text":"They do not know or understand; they wander in the darkness; all the foundations of the earth are shaken."}},"definableWords":["or","darkness","earth"],"peopleInVerse":[]},"6":{"text":"I have said, Ye are gods; and all of you are children of the most High.","ref":"Psalms 82:6","synthesized":"I have said, ‘You are gods; you are all sons of the Most High.’","sources":{"KJV":{"text":"I have said, Ye are gods; and all of you are children of the most High."},"BSB":{"text":"I have said, ‘You are gods; you are all sons of the Most High.’"}},"definableWords":["sons"],"peopleInVerse":[]},"7":{"text":"But ye shall die like men, and fall like one of the princes.","ref":"Psalms 82:7","synthesized":"But like mortals you will die, and like rulers you will fall.”","sources":{"KJV":{"text":"But ye shall die like men, and fall like one of the princes."},"BSB":{"text":"But like mortals you will die, and like rulers you will fall.”"}},"definableWords":["die"],"peopleInVerse":[]},"8":{"text":"Arise, O God, judge the earth: for thou shalt inherit all nations.","ref":"Psalms 82:8","synthesized":"Arise, O God, judge the earth, for all the nations are Your inheritance.","sources":{"KJV":{"text":"Arise, O God, judge the earth: for thou shalt inherit all nations."},"BSB":{"text":"Arise, O God, judge the earth, for all the nations are Your inheritance."}},"definableWords":["God","earth","nations"],"peopleInVerse":[]}}},"83":{"chapter":"83","title":"KEEP NOT THOU SILENCE, O GOD","verses":{"1":{"text":"Keep not thou silence, O God: hold not thy peace, and be not still, O God.","ref":"Psalms 83:1","synthesized":"O God, be not silent; be not speechless; be not still, O God.","sources":{"KJV":{"text":"Keep not thou silence, O God: hold not thy peace, and be not still, O God."},"BSB":{"text":"O God, be not silent; be not speechless; be not still, O God."}},"definableWords":["God"],"peopleInVerse":[]},"2":{"text":"For, lo, thine enemies make a tumult: and they that hate thee have lifted up the head.","ref":"Psalms 83:2","synthesized":"See how Your enemies rage, how Your foes have reared their heads.","sources":{"KJV":{"text":"For, lo, thine enemies make a tumult: and they that hate thee have lifted up the head."},"BSB":{"text":"See how Your enemies rage, how Your foes have reared their heads."}},"definableWords":["see"],"peopleInVerse":[]},"3":{"text":"They have taken crafty counsel against thy people, and consulted against thy hidden ones.","ref":"Psalms 83:3","synthesized":"With cunning they scheme against Your people and conspire against those You cherish,","sources":{"KJV":{"text":"They have taken crafty counsel against thy people, and consulted against thy hidden ones."},"BSB":{"text":"With cunning they scheme against Your people and conspire against those You cherish,"}},"definableWords":["people"],"peopleInVerse":[]},"4":{"text":"They have said, Come, and let us cut them off from being a nation; that the name of Israel may be no more in remembrance.","ref":"Psalms 83:4","synthesized":"saying, “Come, let us erase them as a nation; may the name of Israel be remembered no more.”","sources":{"KJV":{"text":"They have said, Come, and let us cut them off from being a nation; that the name of Israel may be no more in remembrance."},"BSB":{"text":"saying, “Come, let us erase them as a nation; may the name of Israel be remembered no more.”"}},"definableWords":["nation","name","Israel","remembered"],"peopleInVerse":[]},"5":{"text":"For they have consulted together with one consent: they are confederate against thee:","ref":"Psalms 83:5","synthesized":"For with one mind they plot together, they form an alliance against You—","sources":{"KJV":{"text":"For they have consulted together with one consent: they are confederate against thee:"},"BSB":{"text":"For with one mind they plot together, they form an alliance against You—"}},"definableWords":["one","mind","form"],"peopleInVerse":[]},"6":{"text":"The tabernacles of Edom, and the Ishmaelites; of Moab, and the Hagarenes;","ref":"Psalms 83:6","synthesized":"the tents of Edom and the Ishmaelites, of Moab and the Hagrites,","sources":{"KJV":{"text":"The tabernacles of Edom, and the Ishmaelites; of Moab, and the Hagarenes;"},"BSB":{"text":"the tents of Edom and the Ishmaelites, of Moab and the Hagrites,"}},"definableWords":["Edom"],"peopleInVerse":[]},"7":{"text":"Gebal, and Ammon, and Amalek; the Philistines with the inhabitants of Tyre;","ref":"Psalms 83:7","synthesized":"of Gebal, Ammon, and Amalek, of Philistia with the people of Tyre.","sources":{"KJV":{"text":"Gebal, and Ammon, and Amalek; the Philistines with the inhabitants of Tyre;"},"BSB":{"text":"of Gebal, Ammon, and Amalek, of Philistia with the people of Tyre."}},"definableWords":["people"],"peopleInVerse":[]},"8":{"text":"Assur also is joined with them: they have holpen the children of Lot. Selah.","ref":"Psalms 83:8","synthesized":"Even Assyria has joined them, lending strength to the sons of Lot. Selah","sources":{"KJV":{"text":"Assur also is joined with them: they have holpen the children of Lot. Selah."},"BSB":{"text":"Even Assyria has joined them, lending strength to the sons of Lot. Selah"}},"definableWords":["sons","Lot"],"peopleInVerse":["Lot"]},"9":{"text":"Do unto them as unto the Midianites; as to Sisera, as to Jabin, at the brook of Kison:","ref":"Psalms 83:9","synthesized":"Do to them as You did to Midian, as to Sisera and Jabin at the River Kishon,","sources":{"KJV":{"text":"Do unto them as unto the Midianites; as to Sisera, as to Jabin, at the brook of Kison:"},"BSB":{"text":"Do to them as You did to Midian, as to Sisera and Jabin at the River Kishon,"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Which perished at Endor: they became as dung for the earth.","ref":"Psalms 83:10","synthesized":"who perished at Endor and became like dung on the ground.","sources":{"KJV":{"text":"Which perished at Endor: they became as dung for the earth."},"BSB":{"text":"who perished at Endor and became like dung on the ground."}},"definableWords":["ground"],"peopleInVerse":[]},"11":{"text":"Make their nobles like Oreb, and like Zeeb: yea, all their princes as Zebah, and as Zalmunna:","ref":"Psalms 83:11","synthesized":"Make their nobles like Oreb and Zeeb, and all their princes like Zebah and Zalmunna,","sources":{"KJV":{"text":"Make their nobles like Oreb, and like Zeeb: yea, all their princes as Zebah, and as Zalmunna:"},"BSB":{"text":"Make their nobles like Oreb and Zeeb, and all their princes like Zebah and Zalmunna,"}},"definableWords":["make"],"peopleInVerse":[]},"12":{"text":"Who said, Let us take to ourselves the houses of God in possession.","ref":"Psalms 83:12","synthesized":"who said, “Let us possess for ourselves the pastures of God.”","sources":{"KJV":{"text":"Who said, Let us take to ourselves the houses of God in possession."},"BSB":{"text":"who said, “Let us possess for ourselves the pastures of God.”"}},"definableWords":["God"],"peopleInVerse":[]},"13":{"text":"O my God, make them like a wheel; as the stubble before the wind.","ref":"Psalms 83:13","synthesized":"Make them like tumbleweed, O my God, like chaff before the wind.","sources":{"KJV":{"text":"O my God, make them like a wheel; as the stubble before the wind."},"BSB":{"text":"Make them like tumbleweed, O my God, like chaff before the wind."}},"definableWords":["make","God"],"peopleInVerse":[]},"14":{"text":"As the fire burneth a wood, and as the flame setteth the mountains on fire;","ref":"Psalms 83:14","synthesized":"As fire consumes a forest, as a flame sets the mountains ablaze,","sources":{"KJV":{"text":"As the fire burneth a wood, and as the flame setteth the mountains on fire;"},"BSB":{"text":"As fire consumes a forest, as a flame sets the mountains ablaze,"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"So persecute them with thy tempest, and make them afraid with thy storm.","ref":"Psalms 83:15","synthesized":"so pursue them with Your tempest, and terrify them with Your storm.","sources":{"KJV":{"text":"So persecute them with thy tempest, and make them afraid with thy storm."},"BSB":{"text":"so pursue them with Your tempest, and terrify them with Your storm."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Fill their faces with shame; that they may seek thy name, O LORD.","ref":"Psalms 83:16","synthesized":"Cover their faces with shame, that they may seek Your name, O LORD.","sources":{"KJV":{"text":"Fill their faces with shame; that they may seek thy name, O LORD."},"BSB":{"text":"Cover their faces with shame, that they may seek Your name, O LORD."}},"definableWords":["seek","name","LORD"],"peopleInVerse":[]},"17":{"text":"Let them be confounded and troubled for ever; yea, let them be put to shame, and perish:","ref":"Psalms 83:17","synthesized":"May they be ever ashamed and terrified; may they perish in disgrace.","sources":{"KJV":{"text":"Let them be confounded and troubled for ever; yea, let them be put to shame, and perish:"},"BSB":{"text":"May they be ever ashamed and terrified; may they perish in disgrace."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"That men may know that thou, whose name alone is JEHOVAH, art the most high over all the earth.","ref":"Psalms 83:18","synthesized":"May they know that You alone, whose name is the LORD, are Most High over all the earth.","sources":{"KJV":{"text":"That men may know that thou, whose name alone is JEHOVAH, art the most high over all the earth."},"BSB":{"text":"May they know that You alone, whose name is the LORD, are Most High over all the earth."}},"definableWords":["name","LORD","earth"],"peopleInVerse":[]}}},"84":{"chapter":"84","title":"HOW AMIABLE ARE THY TABERNACLES","verses":{"1":{"text":"How amiable are thy tabernacles, O LORD of hosts!","ref":"Psalms 84:1","synthesized":"How lovely is Your dwelling place, O LORD of Hosts!","sources":{"KJV":{"text":"How amiable are thy tabernacles, O LORD of hosts!"},"BSB":{"text":"How lovely is Your dwelling place, O LORD of Hosts!"}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"My soul longeth, yea, even fainteth for the courts of the LORD: my heart and my flesh crieth out for the living God.","ref":"Psalms 84:2","synthesized":"My soul longs, even faints, for the courts of the LORD; my heart and my flesh cry out for the living God.","sources":{"KJV":{"text":"My soul longeth, yea, even fainteth for the courts of the LORD: my heart and my flesh crieth out for the living God."},"BSB":{"text":"My soul longs, even faints, for the courts of the LORD; my heart and my flesh cry out for the living God."}},"definableWords":["soul","LORD","heart","flesh","living","God"],"peopleInVerse":[]},"3":{"text":"Yea, the sparrow hath found an house, and the swallow a nest for herself, where she may lay her young, even thine altars, O LORD of hosts, my King, and my God.","ref":"Psalms 84:3","synthesized":"Even the sparrow has found a home, and the swallow a nest for herself, where she places her young near Your altars, O LORD of Hosts, my King and my God.","sources":{"KJV":{"text":"Yea, the sparrow hath found an house, and the swallow a nest for herself, where she may lay her young, even thine altars, O LORD of hosts, my King, and my God."},"BSB":{"text":"Even the sparrow has found a home, and the swallow a nest for herself, where she places her young near Your altars, O LORD of Hosts, my King and my God."}},"definableWords":["LORD","King","God"],"peopleInVerse":[]},"4":{"text":"Blessed are they that dwell in thy house: they will be still praising thee. Selah.","ref":"Psalms 84:4","synthesized":"How blessed are those who dwell in Your house! They are ever praising You. Selah","sources":{"KJV":{"text":"Blessed are they that dwell in thy house: they will be still praising thee. Selah."},"BSB":{"text":"How blessed are those who dwell in Your house! They are ever praising You. Selah"}},"definableWords":["blessed","house"],"peopleInVerse":[]},"5":{"text":"Blessed is the man whose strength is in thee; in whose heart are the ways of them.","ref":"Psalms 84:5","synthesized":"Blessed are those whose strength is in You, whose hearts are set on pilgrimage.","sources":{"KJV":{"text":"Blessed is the man whose strength is in thee; in whose heart are the ways of them."},"BSB":{"text":"Blessed are those whose strength is in You, whose hearts are set on pilgrimage."}},"definableWords":["blessed"],"peopleInVerse":[]},"6":{"text":"Who passing through the valley of Baca make it a well; the rain also filleth the pools.","ref":"Psalms 84:6","synthesized":"As they pass through the Valley of Baca, they make it a place of springs; even the autumn rain covers it with pools.","sources":{"KJV":{"text":"Who passing through the valley of Baca make it a well; the rain also filleth the pools."},"BSB":{"text":"As they pass through the Valley of Baca, they make it a place of springs; even the autumn rain covers it with pools."}},"definableWords":["make"],"peopleInVerse":[]},"7":{"text":"They go from strength to strength, every one of them in Zion appeareth before God.","ref":"Psalms 84:7","synthesized":"They go from strength to strength, until each appears before God in Zion.","sources":{"KJV":{"text":"They go from strength to strength, every one of them in Zion appeareth before God."},"BSB":{"text":"They go from strength to strength, until each appears before God in Zion."}},"definableWords":["God","Zion"],"peopleInVerse":[]},"8":{"text":"O LORD God of hosts, hear my prayer: give ear, O God of Jacob. Selah.","ref":"Psalms 84:8","synthesized":"O LORD God of Hosts, hear my prayer; give ear, O God of Jacob. Selah","sources":{"KJV":{"text":"O LORD God of hosts, hear my prayer: give ear, O God of Jacob. Selah."},"BSB":{"text":"O LORD God of Hosts, hear my prayer; give ear, O God of Jacob. Selah"}},"definableWords":["LORD","God","hear","prayer","Jacob"],"peopleInVerse":["Jacob"]},"9":{"text":"Behold, O God our shield, and look upon the face of thine anointed.","ref":"Psalms 84:9","synthesized":"Take notice of our shield, O God, and look with favor on the face of Your anointed.","sources":{"KJV":{"text":"Behold, O God our shield, and look upon the face of thine anointed."},"BSB":{"text":"Take notice of our shield, O God, and look with favor on the face of Your anointed."}},"definableWords":["God"],"peopleInVerse":[]},"10":{"text":"For a day in thy courts is better than a thousand. I had rather be a doorkeeper in the house of my God, than to dwell in the tents of wickedness.","ref":"Psalms 84:10","synthesized":"For better is one day in Your courts than a thousand elsewhere. I would rather be a doorkeeper in the house of my God than dwell in the tents of the wicked.","sources":{"KJV":{"text":"For a day in thy courts is better than a thousand. I had rather be a doorkeeper in the house of my God, than to dwell in the tents of wickedness."},"BSB":{"text":"For better is one day in Your courts than a thousand elsewhere. I would rather be a doorkeeper in the house of my God than dwell in the tents of the wicked."}},"definableWords":["one","day","house","God"],"peopleInVerse":[]},"11":{"text":"For the LORD God is a sun and shield: the LORD will give grace and glory: no good thing will he withhold from them that walk uprightly.","ref":"Psalms 84:11","synthesized":"For the LORD God is a sun and a shield; the LORD gives grace and glory; He withholds no good thing from those who walk with integrity.","sources":{"KJV":{"text":"For the LORD God is a sun and shield: the LORD will give grace and glory: no good thing will he withhold from them that walk uprightly."},"BSB":{"text":"For the LORD God is a sun and a shield; the LORD gives grace and glory; He withholds no good thing from those who walk with integrity."}},"definableWords":["LORD","God","Lord","grace","glory","good","walk"],"peopleInVerse":[]},"12":{"text":"O LORD of hosts, blessed is the man that trusteth in thee.","ref":"Psalms 84:12","synthesized":"O LORD of Hosts, how blessed is the man who trusts in You!","sources":{"KJV":{"text":"O LORD of hosts, blessed is the man that trusteth in thee."},"BSB":{"text":"O LORD of Hosts, how blessed is the man who trusts in You!"}},"definableWords":["LORD","blessed","man"],"peopleInVerse":[]}}},"85":{"chapter":"85","title":"LORD, THOU HAST BEEN FAVOURABLE","verses":{"1":{"text":"Lord, thou hast been favourable unto thy land: thou hast brought back the captivity of Jacob.","ref":"Psalms 85:1","synthesized":"You showed favor to Your land, O LORD; You restored Jacob from captivity.","sources":{"KJV":{"text":"Lord, thou hast been favourable unto thy land: thou hast brought back the captivity of Jacob."},"BSB":{"text":"You showed favor to Your land, O LORD; You restored Jacob from captivity."}},"definableWords":["land","LORD","Jacob"],"peopleInVerse":["Jacob"]},"2":{"text":"Thou hast forgiven the iniquity of thy people, thou hast covered all their sin. Selah.","ref":"Psalms 85:2","synthesized":"You forgave the iniquity of Your people; You covered all their sin. Selah","sources":{"KJV":{"text":"Thou hast forgiven the iniquity of thy people, thou hast covered all their sin. Selah."},"BSB":{"text":"You forgave the iniquity of Your people; You covered all their sin. Selah"}},"definableWords":["iniquity","people","sin"],"peopleInVerse":[]},"3":{"text":"Thou hast taken away all thy wrath: thou hast turned thyself from the fierceness of thine anger.","ref":"Psalms 85:3","synthesized":"You withheld all Your fury; You turned from Your burning anger.","sources":{"KJV":{"text":"Thou hast taken away all thy wrath: thou hast turned thyself from the fierceness of thine anger."},"BSB":{"text":"You withheld all Your fury; You turned from Your burning anger."}},"definableWords":["anger"],"peopleInVerse":[]},"4":{"text":"Turn us, O God of our salvation, and cause thine anger toward us to cease.","ref":"Psalms 85:4","synthesized":"Restore us, O God of our salvation, and put away Your displeasure toward us.","sources":{"KJV":{"text":"Turn us, O God of our salvation, and cause thine anger toward us to cease."},"BSB":{"text":"Restore us, O God of our salvation, and put away Your displeasure toward us."}},"definableWords":["God","salvation"],"peopleInVerse":[]},"5":{"text":"Wilt thou be angry with us for ever? wilt thou draw out thine anger to all generations?","ref":"Psalms 85:5","synthesized":"Will You be angry with us forever? Will You draw out Your anger to all generations?","sources":{"KJV":{"text":"Wilt thou be angry with us for ever? wilt thou draw out thine anger to all generations?"},"BSB":{"text":"Will You be angry with us forever? Will You draw out Your anger to all generations?"}},"definableWords":["anger"],"peopleInVerse":[]},"6":{"text":"Wilt thou not revive us again: that thy people may rejoice in thee?","ref":"Psalms 85:6","synthesized":"Will You not revive us again, that Your people may rejoice in You?","sources":{"KJV":{"text":"Wilt thou not revive us again: that thy people may rejoice in thee?"},"BSB":{"text":"Will You not revive us again, that Your people may rejoice in You?"}},"definableWords":["people"],"peopleInVerse":[]},"7":{"text":"Shew us thy mercy, O LORD, and grant us thy salvation.","ref":"Psalms 85:7","synthesized":"Show us Your loving devotion, O LORD, and grant us Your salvation.","sources":{"KJV":{"text":"Shew us thy mercy, O LORD, and grant us thy salvation."},"BSB":{"text":"Show us Your loving devotion, O LORD, and grant us Your salvation."}},"definableWords":["LORD","salvation"],"peopleInVerse":[]},"8":{"text":"I will hear what God the LORD will speak: for he will speak peace unto his people, and to his saints: but let them not turn again to folly.","ref":"Psalms 85:8","synthesized":"I will listen to what God the LORD will say; for He will surely speak peace to His people and His saints; He will not let them return to folly.","sources":{"KJV":{"text":"I will hear what God the LORD will speak: for he will speak peace unto his people, and to his saints: but let them not turn again to folly."},"BSB":{"text":"I will listen to what God the LORD will say; for He will surely speak peace to His people and His saints; He will not let them return to folly."}},"definableWords":["God","LORD","peace","people"],"peopleInVerse":[]},"9":{"text":"Surely his salvation is nigh them that fear him; that glory may dwell in our land.","ref":"Psalms 85:9","synthesized":"Surely His salvation is near to those who fear Him, that His glory may dwell in our land.","sources":{"KJV":{"text":"Surely his salvation is nigh them that fear him; that glory may dwell in our land."},"BSB":{"text":"Surely His salvation is near to those who fear Him, that His glory may dwell in our land."}},"definableWords":["salvation","fear","glory","land"],"peopleInVerse":[]},"10":{"text":"Mercy and truth are met together; righteousness and peace have kissed each other.","ref":"Psalms 85:10","synthesized":"Loving devotion and faithfulness have joined together; righteousness and peace have kissed.","sources":{"KJV":{"text":"Mercy and truth are met together; righteousness and peace have kissed each other."},"BSB":{"text":"Loving devotion and faithfulness have joined together; righteousness and peace have kissed."}},"definableWords":["righteousness","peace"],"peopleInVerse":[]},"11":{"text":"Truth shall spring out of the earth; and righteousness shall look down from heaven.","ref":"Psalms 85:11","synthesized":"Faithfulness sprouts from the earth, and righteousness looks down from heaven.","sources":{"KJV":{"text":"Truth shall spring out of the earth; and righteousness shall look down from heaven."},"BSB":{"text":"Faithfulness sprouts from the earth, and righteousness looks down from heaven."}},"definableWords":["earth","righteousness","heaven"],"peopleInVerse":[]},"12":{"text":"Yea, the LORD shall give that which is good; and our land shall yield her increase.","ref":"Psalms 85:12","synthesized":"The LORD will indeed provide what is good, and our land will yield its increase.","sources":{"KJV":{"text":"Yea, the LORD shall give that which is good; and our land shall yield her increase."},"BSB":{"text":"The LORD will indeed provide what is good, and our land will yield its increase."}},"definableWords":["LORD","good","land"],"peopleInVerse":[]},"13":{"text":"Righteousness shall go before him; and shall set us in the way of his steps.","ref":"Psalms 85:13","synthesized":"Righteousness will go before Him to prepare the way for His steps.","sources":{"KJV":{"text":"Righteousness shall go before him; and shall set us in the way of his steps."},"BSB":{"text":"Righteousness will go before Him to prepare the way for His steps."}},"definableWords":["righteousness","way"],"peopleInVerse":[]}}},"86":{"chapter":"86","title":"BOW DOWN THINE EAR, O LORD","verses":{"1":{"text":"Bow down thine ear, O LORD, hear me: for I am poor and needy.","ref":"Psalms 86:1","synthesized":"Incline Your ear, O LORD, and answer me, for I am poor and needy.","sources":{"KJV":{"text":"Bow down thine ear, O LORD, hear me: for I am poor and needy."},"BSB":{"text":"Incline Your ear, O LORD, and answer me, for I am poor and needy."}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"Preserve my soul; for I am holy: O thou my God, save thy servant that trusteth in thee.","ref":"Psalms 86:2","synthesized":"Preserve my soul, for I am godly. You are my God; save Your servant who trusts in You.","sources":{"KJV":{"text":"Preserve my soul; for I am holy: O thou my God, save thy servant that trusteth in thee."},"BSB":{"text":"Preserve my soul, for I am godly. You are my God; save Your servant who trusts in You."}},"definableWords":["soul","God","servant"],"peopleInVerse":[]},"3":{"text":"Be merciful unto me, O Lord: for I cry unto thee daily.","ref":"Psalms 86:3","synthesized":"Be merciful to me, O Lord, for I call to You all day long.","sources":{"KJV":{"text":"Be merciful unto me, O Lord: for I cry unto thee daily."},"BSB":{"text":"Be merciful to me, O Lord, for I call to You all day long."}},"definableWords":["Lord","day"],"peopleInVerse":[]},"4":{"text":"Rejoice the soul of thy servant: for unto thee, O Lord, do I lift up my soul.","ref":"Psalms 86:4","synthesized":"Bring joy to Your servant, for to You, O Lord, I lift up my soul.","sources":{"KJV":{"text":"Rejoice the soul of thy servant: for unto thee, O Lord, do I lift up my soul."},"BSB":{"text":"Bring joy to Your servant, for to You, O Lord, I lift up my soul."}},"definableWords":["joy","servant","Lord","soul"],"peopleInVerse":[]},"5":{"text":"For thou, Lord, art good, and ready to forgive; and plenteous in mercy unto all them that call upon thee.","ref":"Psalms 86:5","synthesized":"For You, O Lord, are kind and forgiving, rich in loving devotion to all who call on You.","sources":{"KJV":{"text":"For thou, Lord, art good, and ready to forgive; and plenteous in mercy unto all them that call upon thee."},"BSB":{"text":"For You, O Lord, are kind and forgiving, rich in loving devotion to all who call on You."}},"definableWords":["Lord"],"peopleInVerse":[]},"6":{"text":"Give ear, O LORD, unto my prayer; and attend to the voice of my supplications.","ref":"Psalms 86:6","synthesized":"Hear my prayer, O LORD, and attend to my plea for mercy.","sources":{"KJV":{"text":"Give ear, O LORD, unto my prayer; and attend to the voice of my supplications."},"BSB":{"text":"Hear my prayer, O LORD, and attend to my plea for mercy."}},"definableWords":["hear","prayer","LORD","mercy"],"peopleInVerse":[]},"7":{"text":"In the day of my trouble I will call upon thee: for thou wilt answer me.","ref":"Psalms 86:7","synthesized":"In the day of my distress I call on You, because You answer me.","sources":{"KJV":{"text":"In the day of my trouble I will call upon thee: for thou wilt answer me."},"BSB":{"text":"In the day of my distress I call on You, because You answer me."}},"definableWords":["day"],"peopleInVerse":[]},"8":{"text":"Among the gods there is none like unto thee, O Lord; neither are there any works like unto thy works.","ref":"Psalms 86:8","synthesized":"O Lord, there is none like You among the gods, nor any works like Yours.","sources":{"KJV":{"text":"Among the gods there is none like unto thee, O Lord; neither are there any works like unto thy works."},"BSB":{"text":"O Lord, there is none like You among the gods, nor any works like Yours."}},"definableWords":["Lord","works"],"peopleInVerse":[]},"9":{"text":"All nations whom thou hast made shall come and worship before thee, O Lord; and shall glorify thy name.","ref":"Psalms 86:9","synthesized":"All the nations You have made will come and bow before You, O Lord, and they will glorify Your name.","sources":{"KJV":{"text":"All nations whom thou hast made shall come and worship before thee, O Lord; and shall glorify thy name."},"BSB":{"text":"All the nations You have made will come and bow before You, O Lord, and they will glorify Your name."}},"definableWords":["nations","made","Lord","name"],"peopleInVerse":[]},"10":{"text":"For thou art great, and doest wondrous things: thou art God alone.","ref":"Psalms 86:10","synthesized":"For You are great and perform wonders; You alone are God.","sources":{"KJV":{"text":"For thou art great, and doest wondrous things: thou art God alone."},"BSB":{"text":"For You are great and perform wonders; You alone are God."}},"definableWords":["great","God"],"peopleInVerse":[]},"11":{"text":"Teach me thy way, O LORD; I will walk in thy truth: unite my heart to fear thy name.","ref":"Psalms 86:11","synthesized":"Teach me Your way, O LORD, that I may walk in Your truth. Give me an undivided heart, that I may fear Your name.","sources":{"KJV":{"text":"Teach me thy way, O LORD; I will walk in thy truth: unite my heart to fear thy name."},"BSB":{"text":"Teach me Your way, O LORD, that I may walk in Your truth. Give me an undivided heart, that I may fear Your name."}},"definableWords":["way","LORD","walk","truth","heart","fear","name"],"peopleInVerse":[]},"12":{"text":"I will praise thee, O Lord my God, with all my heart: and I will glorify thy name for evermore.","ref":"Psalms 86:12","synthesized":"I will praise You, O Lord my God, with all my heart; I will glorify Your name forever.","sources":{"KJV":{"text":"I will praise thee, O Lord my God, with all my heart: and I will glorify thy name for evermore."},"BSB":{"text":"I will praise You, O Lord my God, with all my heart; I will glorify Your name forever."}},"definableWords":["praise","Lord","God","heart","name"],"peopleInVerse":[]},"13":{"text":"For great is thy mercy toward me: and thou hast delivered my soul from the lowest hell.","ref":"Psalms 86:13","synthesized":"For great is Your loving devotion to me; You have delivered me from the depths of Sheol.","sources":{"KJV":{"text":"For great is thy mercy toward me: and thou hast delivered my soul from the lowest hell."},"BSB":{"text":"For great is Your loving devotion to me; You have delivered me from the depths of Sheol."}},"definableWords":["great"],"peopleInVerse":[]},"14":{"text":"O God, the proud are risen against me, and the assemblies of violent men have sought after my soul; and have not set thee before them.","ref":"Psalms 86:14","synthesized":"The arrogant rise against me, O God; a band of ruthless men seeks my life, with no regard for You.","sources":{"KJV":{"text":"O God, the proud are risen against me, and the assemblies of violent men have sought after my soul; and have not set thee before them."},"BSB":{"text":"The arrogant rise against me, O God; a band of ruthless men seeks my life, with no regard for You."}},"definableWords":["God","men","life"],"peopleInVerse":[]},"15":{"text":"But thou, O Lord, art a God full of compassion, and gracious, long suffering, and plenteous in mercy and truth.","ref":"Psalms 86:15","synthesized":"But You, O Lord, are a compassionate and gracious God, slow to anger, abounding in loving devotion and faithfulness.","sources":{"KJV":{"text":"But thou, O Lord, art a God full of compassion, and gracious, long suffering, and plenteous in mercy and truth."},"BSB":{"text":"But You, O Lord, are a compassionate and gracious God, slow to anger, abounding in loving devotion and faithfulness."}},"definableWords":["Lord","God","anger"],"peopleInVerse":[]},"16":{"text":"O turn unto me, and have mercy upon me; give thy strength unto thy servant, and save the son of thine handmaid.","ref":"Psalms 86:16","synthesized":"Turn to me and have mercy; grant Your strength to Your servant; save the son of Your maidservant.","sources":{"KJV":{"text":"O turn unto me, and have mercy upon me; give thy strength unto thy servant, and save the son of thine handmaid."},"BSB":{"text":"Turn to me and have mercy; grant Your strength to Your servant; save the son of Your maidservant."}},"definableWords":["mercy","servant","son"],"peopleInVerse":[]},"17":{"text":"Shew me a token for good; that they which hate me may see it, and be ashamed: because thou, LORD, hast holpen me, and comforted me.","ref":"Psalms 86:17","synthesized":"Show me a sign of Your goodness, that my enemies may see and be ashamed; for You, O LORD, have helped me and comforted me.","sources":{"KJV":{"text":"Shew me a token for good; that they which hate me may see it, and be ashamed: because thou, LORD, hast holpen me, and comforted me."},"BSB":{"text":"Show me a sign of Your goodness, that my enemies may see and be ashamed; for You, O LORD, have helped me and comforted me."}},"definableWords":["see","LORD"],"peopleInVerse":[]}}},"87":{"chapter":"87","title":"ZION, CITY OF GOD","verses":{"1":{"text":"His foundation is in the holy mountains.","ref":"Psalms 87:1","synthesized":"He has founded His city on the holy mountains.","sources":{"KJV":{"text":"His foundation is in the holy mountains."},"BSB":{"text":"He has founded His city on the holy mountains."}},"definableWords":["holy"],"peopleInVerse":[]},"2":{"text":"The LORD loveth the gates of Zion more than all the dwellings of Jacob.","ref":"Psalms 87:2","synthesized":"The LORD loves the gates of Zion more than all the dwellings of Jacob.","sources":{"KJV":{"text":"The LORD loveth the gates of Zion more than all the dwellings of Jacob."},"BSB":{"text":"The LORD loves the gates of Zion more than all the dwellings of Jacob."}},"definableWords":["LORD","Zion","Jacob"],"peopleInVerse":["Jacob"]},"3":{"text":"Glorious things are spoken of thee, O city of God. Selah.","ref":"Psalms 87:3","synthesized":"Glorious things are ascribed to you, O city of God. Selah","sources":{"KJV":{"text":"Glorious things are spoken of thee, O city of God. Selah."},"BSB":{"text":"Glorious things are ascribed to you, O city of God. Selah"}},"definableWords":["God"],"peopleInVerse":[]},"4":{"text":"I will make mention of Rahab and Babylon to them that know me: behold Philistia, and Tyre, with Ethiopia; this man was born there.","ref":"Psalms 87:4","synthesized":"“I will mention Rahab and Babylon among those who know Me— along with Philistia, Tyre, and Cush— when I say, ‘This one was born in Zion.’”","sources":{"KJV":{"text":"I will make mention of Rahab and Babylon to them that know me: behold Philistia, and Tyre, with Ethiopia; this man was born there."},"BSB":{"text":"“I will mention Rahab and Babylon among those who know Me— along with Philistia, Tyre, and Cush— when I say, ‘This one was born in Zion.’”"}},"definableWords":["Babylon","one","Zion"],"peopleInVerse":["Rahab","Cush"]},"5":{"text":"And of Zion it shall be said, This and that man was born in her: and the highest himself shall establish her.","ref":"Psalms 87:5","synthesized":"And it will be said of Zion: “This one and that one were born in her, and the Most High Himself will establish her.”","sources":{"KJV":{"text":"And of Zion it shall be said, This and that man was born in her: and the highest himself shall establish her."},"BSB":{"text":"And it will be said of Zion: “This one and that one were born in her, and the Most High Himself will establish her.”"}},"definableWords":["Zion","one"],"peopleInVerse":[]},"6":{"text":"The LORD shall count, when he writeth up the people, that this man was born there. Selah.","ref":"Psalms 87:6","synthesized":"The LORD will record in the register of the peoples: “This one was born in Zion.” Selah","sources":{"KJV":{"text":"The LORD shall count, when he writeth up the people, that this man was born there. Selah."},"BSB":{"text":"The LORD will record in the register of the peoples: “This one was born in Zion.” Selah"}},"definableWords":["LORD","one","Zion"],"peopleInVerse":[]},"7":{"text":"As well the singers as the players on instruments shall be there: all my springs are in thee.","ref":"Psalms 87:7","synthesized":"Singers and pipers will proclaim, “All my springs of joy are in You.”","sources":{"KJV":{"text":"As well the singers as the players on instruments shall be there: all my springs are in thee."},"BSB":{"text":"Singers and pipers will proclaim, “All my springs of joy are in You.”"}},"definableWords":["joy"],"peopleInVerse":[]}}},"88":{"chapter":"88","title":"DARKEST PSALM — A PSALM IN AFFLICTION","verses":{"1":{"text":"O LORD God of my salvation, I have cried day and night before thee:","ref":"Psalms 88:1","synthesized":"O LORD, the God of my salvation, day and night I cry out before You.","sources":{"KJV":{"text":"O LORD God of my salvation, I have cried day and night before thee:"},"BSB":{"text":"O LORD, the God of my salvation, day and night I cry out before You."}},"definableWords":["LORD","God","salvation","day","night"],"peopleInVerse":[]},"2":{"text":"Let my prayer come before thee: incline thine ear unto my cry;","ref":"Psalms 88:2","synthesized":"May my prayer come before You; incline Your ear to my cry.","sources":{"KJV":{"text":"Let my prayer come before thee: incline thine ear unto my cry;"},"BSB":{"text":"May my prayer come before You; incline Your ear to my cry."}},"definableWords":["prayer"],"peopleInVerse":[]},"3":{"text":"For my soul is full of troubles: and my life draweth nigh unto the grave.","ref":"Psalms 88:3","synthesized":"For my soul is full of troubles, and my life draws near to Sheol.","sources":{"KJV":{"text":"For my soul is full of troubles: and my life draweth nigh unto the grave."},"BSB":{"text":"For my soul is full of troubles, and my life draws near to Sheol."}},"definableWords":["soul","life"],"peopleInVerse":[]},"4":{"text":"I am counted with them that go down into the pit: I am as a man that hath no strength:","ref":"Psalms 88:4","synthesized":"I am counted among those descending to the Pit. I am like a man without strength.","sources":{"KJV":{"text":"I am counted with them that go down into the pit: I am as a man that hath no strength:"},"BSB":{"text":"I am counted among those descending to the Pit. I am like a man without strength."}},"definableWords":["man"],"peopleInVerse":[]},"5":{"text":"Free among the dead, like the slain that lie in the grave, whom thou rememberest no more: and they are cut off from thy hand.","ref":"Psalms 88:5","synthesized":"I am forsaken among the dead, like the slain who lie in the grave, whom You remember no more, who are cut off from Your care.","sources":{"KJV":{"text":"Free among the dead, like the slain that lie in the grave, whom thou rememberest no more: and they are cut off from thy hand."},"BSB":{"text":"I am forsaken among the dead, like the slain who lie in the grave, whom You remember no more, who are cut off from Your care."}},"definableWords":["remember"],"peopleInVerse":[]},"6":{"text":"Thou hast laid me in the lowest pit, in darkness, in the deeps.","ref":"Psalms 88:6","synthesized":"You have laid me in the lowest Pit, in the darkest of the depths.","sources":{"KJV":{"text":"Thou hast laid me in the lowest pit, in darkness, in the deeps."},"BSB":{"text":"You have laid me in the lowest Pit, in the darkest of the depths."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Thy wrath lieth hard upon me, and thou hast afflicted me with all thy waves. Selah.","ref":"Psalms 88:7","synthesized":"Your wrath weighs heavily upon me; all Your waves have submerged me. Selah","sources":{"KJV":{"text":"Thy wrath lieth hard upon me, and thou hast afflicted me with all thy waves. Selah."},"BSB":{"text":"Your wrath weighs heavily upon me; all Your waves have submerged me. Selah"}},"definableWords":["wrath"],"peopleInVerse":[]},"8":{"text":"Thou hast put away mine acquaintance far from me; thou hast made me an abomination unto them: I am shut up, and I cannot come forth.","ref":"Psalms 88:8","synthesized":"You have removed my friends from me; You have made me repulsive to them; I am confined and cannot escape.","sources":{"KJV":{"text":"Thou hast put away mine acquaintance far from me; thou hast made me an abomination unto them: I am shut up, and I cannot come forth."},"BSB":{"text":"You have removed my friends from me; You have made me repulsive to them; I am confined and cannot escape."}},"definableWords":["made"],"peopleInVerse":[]},"9":{"text":"Mine eye mourneth by reason of affliction: LORD, I have called daily upon thee, I have stretched out my hands unto thee.","ref":"Psalms 88:9","synthesized":"My eyes grow dim with grief. I call to You daily, O LORD; I spread out my hands to You.","sources":{"KJV":{"text":"Mine eye mourneth by reason of affliction: LORD, I have called daily upon thee, I have stretched out my hands unto thee."},"BSB":{"text":"My eyes grow dim with grief. I call to You daily, O LORD; I spread out my hands to You."}},"definableWords":["LORD"],"peopleInVerse":[]},"10":{"text":"Wilt thou shew wonders to the dead? shall the dead arise and praise thee? Selah.","ref":"Psalms 88:10","synthesized":"Do You work wonders for the dead? Do departed spirits rise up to praise You? Selah","sources":{"KJV":{"text":"Wilt thou shew wonders to the dead? shall the dead arise and praise thee? Selah."},"BSB":{"text":"Do You work wonders for the dead? Do departed spirits rise up to praise You? Selah"}},"definableWords":["work","praise"],"peopleInVerse":[]},"11":{"text":"Shall thy lovingkindness be declared in the grave? or thy faithfulness in destruction?","ref":"Psalms 88:11","synthesized":"Can Your loving devotion be proclaimed in the grave, Your faithfulness in Abaddon?","sources":{"KJV":{"text":"Shall thy lovingkindness be declared in the grave? or thy faithfulness in destruction?"},"BSB":{"text":"Can Your loving devotion be proclaimed in the grave, Your faithfulness in Abaddon?"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Shall thy wonders be known in the dark? and thy righteousness in the land of forgetfulness?","ref":"Psalms 88:12","synthesized":"Will Your wonders be known in the darkness, or Your righteousness in the land of oblivion?","sources":{"KJV":{"text":"Shall thy wonders be known in the dark? and thy righteousness in the land of forgetfulness?"},"BSB":{"text":"Will Your wonders be known in the darkness, or Your righteousness in the land of oblivion?"}},"definableWords":["darkness","or","righteousness","land"],"peopleInVerse":[]},"13":{"text":"But unto thee have I cried, O LORD; and in the morning shall my prayer prevent thee.","ref":"Psalms 88:13","synthesized":"But to You, O LORD, I cry for help; in the morning my prayer comes before You.","sources":{"KJV":{"text":"But unto thee have I cried, O LORD; and in the morning shall my prayer prevent thee."},"BSB":{"text":"But to You, O LORD, I cry for help; in the morning my prayer comes before You."}},"definableWords":["LORD","prayer"],"peopleInVerse":[]},"14":{"text":"LORD, why castest thou off my soul? why hidest thou thy face from me?","ref":"Psalms 88:14","synthesized":"Why, O LORD, do You reject me? Why do You hide Your face from me?","sources":{"KJV":{"text":"LORD, why castest thou off my soul? why hidest thou thy face from me?"},"BSB":{"text":"Why, O LORD, do You reject me? Why do You hide Your face from me?"}},"definableWords":["LORD"],"peopleInVerse":[]},"15":{"text":"I am afflicted and ready to die from my youth up: while I suffer thy terrors I am distracted.","ref":"Psalms 88:15","synthesized":"From my youth I was afflicted and near death. I have borne Your terrors; I am in despair.","sources":{"KJV":{"text":"I am afflicted and ready to die from my youth up: while I suffer thy terrors I am distracted."},"BSB":{"text":"From my youth I was afflicted and near death. I have borne Your terrors; I am in despair."}},"definableWords":["death"],"peopleInVerse":[]},"16":{"text":"Thy fierce wrath goeth over me; thy terrors have cut me off.","ref":"Psalms 88:16","synthesized":"Your wrath has swept over me; Your terrors have destroyed me.","sources":{"KJV":{"text":"Thy fierce wrath goeth over me; thy terrors have cut me off."},"BSB":{"text":"Your wrath has swept over me; Your terrors have destroyed me."}},"definableWords":["wrath"],"peopleInVerse":[]},"17":{"text":"They came round about me daily like water; they compassed me about together.","ref":"Psalms 88:17","synthesized":"All day long they engulf me like water; they enclose me on every side.","sources":{"KJV":{"text":"They came round about me daily like water; they compassed me about together."},"BSB":{"text":"All day long they engulf me like water; they enclose me on every side."}},"definableWords":["day","water"],"peopleInVerse":[]},"18":{"text":"Lover and friend hast thou put far from me, and mine acquaintance into darkness.","ref":"Psalms 88:18","synthesized":"You have removed my beloved and my friend; darkness is my closest companion.","sources":{"KJV":{"text":"Lover and friend hast thou put far from me, and mine acquaintance into darkness."},"BSB":{"text":"You have removed my beloved and my friend; darkness is my closest companion."}},"definableWords":["darkness"],"peopleInVerse":[]}}},"89":{"chapter":"89","title":"I WILL SING OF THE MERCIES OF THE LORD","verses":{"1":{"text":"I will sing of the mercies of the LORD for ever: with my mouth will I make known thy faithfulness to all generations.","ref":"Psalms 89:1","synthesized":"I will sing of the loving devotion of the LORD forever; with my mouth I will proclaim Your faithfulness to all generations.","sources":{"KJV":{"text":"I will sing of the mercies of the LORD for ever: with my mouth will I make known thy faithfulness to all generations."},"BSB":{"text":"I will sing of the loving devotion of the LORD forever; with my mouth I will proclaim Your faithfulness to all generations."}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"For I have said, Mercy shall be built up for ever: thy faithfulness shalt thou establish in the very heavens.","ref":"Psalms 89:2","synthesized":"For I have said, “Loving devotion is built up forever; in the heavens You establish Your faithfulness.”","sources":{"KJV":{"text":"For I have said, Mercy shall be built up for ever: thy faithfulness shalt thou establish in the very heavens."},"BSB":{"text":"For I have said, “Loving devotion is built up forever; in the heavens You establish Your faithfulness.”"}},"definableWords":["heavens"],"peopleInVerse":[]},"3":{"text":"I have made a covenant with my chosen, I have sworn unto David my servant,","ref":"Psalms 89:3","synthesized":"You said, “I have made a covenant with My chosen one, I have sworn to David My servant:","sources":{"KJV":{"text":"I have made a covenant with my chosen, I have sworn unto David my servant,"},"BSB":{"text":"You said, “I have made a covenant with My chosen one, I have sworn to David My servant:"}},"definableWords":["made","covenant","one","servant"],"peopleInVerse":["David"]},"4":{"text":"Thy seed will I establish for ever, and build up thy throne to all generations. Selah.","ref":"Psalms 89:4","synthesized":"‘I will establish your offspring forever and build up your throne for all generations.’” Selah","sources":{"KJV":{"text":"Thy seed will I establish for ever, and build up thy throne to all generations. Selah."},"BSB":{"text":"‘I will establish your offspring forever and build up your throne for all generations.’” Selah"}},"definableWords":["throne"],"peopleInVerse":[]},"5":{"text":"And the heavens shall praise thy wonders, O LORD: thy faithfulness also in the congregation of the saints.","ref":"Psalms 89:5","synthesized":"The heavens praise Your wonders, O LORD— Your faithfulness as well— in the assembly of the holy ones.","sources":{"KJV":{"text":"And the heavens shall praise thy wonders, O LORD: thy faithfulness also in the congregation of the saints."},"BSB":{"text":"The heavens praise Your wonders, O LORD— Your faithfulness as well— in the assembly of the holy ones."}},"definableWords":["heavens","praise","LORD","holy"],"peopleInVerse":[]},"6":{"text":"For who in the heaven can be compared unto the LORD? who among the sons of the mighty can be likened unto the LORD?","ref":"Psalms 89:6","synthesized":"For who in the skies can compare with the LORD? Who among the heavenly beings is like the LORD?","sources":{"KJV":{"text":"For who in the heaven can be compared unto the LORD? who among the sons of the mighty can be likened unto the LORD?"},"BSB":{"text":"For who in the skies can compare with the LORD? Who among the heavenly beings is like the LORD?"}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"7":{"text":"God is greatly to be feared in the assembly of the saints, and to be had in reverence of all them that are about him.","ref":"Psalms 89:7","synthesized":"In the council of the holy ones, God is greatly feared, and awesome above all who surround Him.","sources":{"KJV":{"text":"God is greatly to be feared in the assembly of the saints, and to be had in reverence of all them that are about him."},"BSB":{"text":"In the council of the holy ones, God is greatly feared, and awesome above all who surround Him."}},"definableWords":["holy","God"],"peopleInVerse":[]},"8":{"text":"O LORD God of hosts, who is a strong LORD like unto thee? or to thy faithfulness round about thee?","ref":"Psalms 89:8","synthesized":"O LORD God of Hosts, who is like You? O mighty LORD, Your faithfulness surrounds You.","sources":{"KJV":{"text":"O LORD God of hosts, who is a strong LORD like unto thee? or to thy faithfulness round about thee?"},"BSB":{"text":"O LORD God of Hosts, who is like You? O mighty LORD, Your faithfulness surrounds You."}},"definableWords":["LORD","God","mighty","Lord"],"peopleInVerse":[]},"9":{"text":"Thou rulest the raging of the sea: when the waves thereof arise, thou stillest them.","ref":"Psalms 89:9","synthesized":"You rule the raging sea; when its waves mount up, You still them.","sources":{"KJV":{"text":"Thou rulest the raging of the sea: when the waves thereof arise, thou stillest them."},"BSB":{"text":"You rule the raging sea; when its waves mount up, You still them."}},"definableWords":["rule","sea"],"peopleInVerse":[]},"10":{"text":"Thou hast broken Rahab in pieces, as one that is slain; thou hast scattered thine enemies with thy strong arm.","ref":"Psalms 89:10","synthesized":"You crushed Rahab like a carcass; You scattered Your enemies with Your mighty arm.","sources":{"KJV":{"text":"Thou hast broken Rahab in pieces, as one that is slain; thou hast scattered thine enemies with thy strong arm."},"BSB":{"text":"You crushed Rahab like a carcass; You scattered Your enemies with Your mighty arm."}},"definableWords":["mighty"],"peopleInVerse":["Rahab"]},"11":{"text":"The heavens are thine, the earth also is thine: as for the world and the fulness thereof, thou hast founded them.","ref":"Psalms 89:11","synthesized":"The heavens are Yours, and also the earth. The earth and its fullness You founded.","sources":{"KJV":{"text":"The heavens are thine, the earth also is thine: as for the world and the fulness thereof, thou hast founded them."},"BSB":{"text":"The heavens are Yours, and also the earth. The earth and its fullness You founded."}},"definableWords":["heavens","earth"],"peopleInVerse":[]},"12":{"text":"The north and the south thou hast created them: Tabor and Hermon shall rejoice in thy name.","ref":"Psalms 89:12","synthesized":"North and south You created; Tabor and Hermon shout for joy at Your name.","sources":{"KJV":{"text":"The north and the south thou hast created them: Tabor and Hermon shall rejoice in thy name."},"BSB":{"text":"North and south You created; Tabor and Hermon shout for joy at Your name."}},"definableWords":["created","joy","name"],"peopleInVerse":[]},"13":{"text":"Thou hast a mighty arm: strong is thy hand, and high is thy right hand.","ref":"Psalms 89:13","synthesized":"Mighty is Your arm; strong is Your hand. Your right hand is exalted.","sources":{"KJV":{"text":"Thou hast a mighty arm: strong is thy hand, and high is thy right hand."},"BSB":{"text":"Mighty is Your arm; strong is Your hand. Your right hand is exalted."}},"definableWords":["mighty","strong"],"peopleInVerse":[]},"14":{"text":"Justice and judgment are the habitation of thy throne: mercy and truth shall go before thy face.","ref":"Psalms 89:14","synthesized":"Righteousness and justice are the foundation of Your throne; loving devotion and faithfulness go before You.","sources":{"KJV":{"text":"Justice and judgment are the habitation of thy throne: mercy and truth shall go before thy face."},"BSB":{"text":"Righteousness and justice are the foundation of Your throne; loving devotion and faithfulness go before You."}},"definableWords":["righteousness","justice","throne"],"peopleInVerse":[]},"15":{"text":"Blessed is the people that know the joyful sound: they shall walk, O LORD, in the light of thy countenance.","ref":"Psalms 89:15","synthesized":"Blessed are those who know the joyful sound, who walk, O LORD, in the light of Your presence.","sources":{"KJV":{"text":"Blessed is the people that know the joyful sound: they shall walk, O LORD, in the light of thy countenance."},"BSB":{"text":"Blessed are those who know the joyful sound, who walk, O LORD, in the light of Your presence."}},"definableWords":["blessed","walk","LORD","light"],"peopleInVerse":[]},"16":{"text":"In thy name shall they rejoice all the day: and in thy righteousness shall they be exalted.","ref":"Psalms 89:16","synthesized":"They rejoice in Your name all day long, and in Your righteousness they exult.","sources":{"KJV":{"text":"In thy name shall they rejoice all the day: and in thy righteousness shall they be exalted."},"BSB":{"text":"They rejoice in Your name all day long, and in Your righteousness they exult."}},"definableWords":["name","day","righteousness"],"peopleInVerse":[]},"17":{"text":"For thou art the glory of their strength: and in thy favour our horn shall be exalted.","ref":"Psalms 89:17","synthesized":"For You are the glory of their strength, and by Your favor our horn is exalted.","sources":{"KJV":{"text":"For thou art the glory of their strength: and in thy favour our horn shall be exalted."},"BSB":{"text":"For You are the glory of their strength, and by Your favor our horn is exalted."}},"definableWords":["glory"],"peopleInVerse":[]},"18":{"text":"For the LORD is our defence; and the Holy One of Israel is our king.","ref":"Psalms 89:18","synthesized":"Surely our shield belongs to the LORD, and our king to the Holy One of Israel.","sources":{"KJV":{"text":"For the LORD is our defence; and the Holy One of Israel is our king."},"BSB":{"text":"Surely our shield belongs to the LORD, and our king to the Holy One of Israel."}},"definableWords":["LORD","king","holy","one","Israel"],"peopleInVerse":[]},"19":{"text":"Then thou spakest in vision to thy holy one, and saidst, I have laid help upon one that is mighty; I have exalted one chosen out of the people.","ref":"Psalms 89:19","synthesized":"You once spoke in a vision; to Your godly ones You said, “I have bestowed help on a warrior; I have exalted one chosen from the people.","sources":{"KJV":{"text":"Then thou spakest in vision to thy holy one, and saidst, I have laid help upon one that is mighty; I have exalted one chosen out of the people."},"BSB":{"text":"You once spoke in a vision; to Your godly ones You said, “I have bestowed help on a warrior; I have exalted one chosen from the people."}},"definableWords":["one","people"],"peopleInVerse":[]},"20":{"text":"I have found David my servant; with my holy oil have I anointed him:","ref":"Psalms 89:20","synthesized":"I have found My servant David; with My sacred oil I have anointed him.","sources":{"KJV":{"text":"I have found David my servant; with my holy oil have I anointed him:"},"BSB":{"text":"I have found My servant David; with My sacred oil I have anointed him."}},"definableWords":["servant"],"peopleInVerse":["David"]},"21":{"text":"With whom my hand shall be established: mine arm also shall strengthen him.","ref":"Psalms 89:21","synthesized":"My hand will sustain him; surely My arm will strengthen him.","sources":{"KJV":{"text":"With whom my hand shall be established: mine arm also shall strengthen him."},"BSB":{"text":"My hand will sustain him; surely My arm will strengthen him."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"The enemy shall not exact upon him; nor the son of wickedness afflict him.","ref":"Psalms 89:22","synthesized":"No enemy will exact tribute; no wicked man will oppress him.","sources":{"KJV":{"text":"The enemy shall not exact upon him; nor the son of wickedness afflict him."},"BSB":{"text":"No enemy will exact tribute; no wicked man will oppress him."}},"definableWords":["man"],"peopleInVerse":[]},"23":{"text":"And I will beat down his foes before his face, and plague them that hate him.","ref":"Psalms 89:23","synthesized":"I will crush his foes before him and strike down those who hate him.","sources":{"KJV":{"text":"And I will beat down his foes before his face, and plague them that hate him."},"BSB":{"text":"I will crush his foes before him and strike down those who hate him."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"But my faithfulness and my mercy shall be with him: and in my name shall his horn be exalted.","ref":"Psalms 89:24","synthesized":"My faithfulness and loving devotion will be with him, and through My name his horn will be exalted.","sources":{"KJV":{"text":"But my faithfulness and my mercy shall be with him: and in my name shall his horn be exalted."},"BSB":{"text":"My faithfulness and loving devotion will be with him, and through My name his horn will be exalted."}},"definableWords":["name"],"peopleInVerse":[]},"25":{"text":"I will set his hand also in the sea, and his right hand in the rivers.","ref":"Psalms 89:25","synthesized":"I will set his hand over the sea, and his right hand upon the rivers.","sources":{"KJV":{"text":"I will set his hand also in the sea, and his right hand in the rivers."},"BSB":{"text":"I will set his hand over the sea, and his right hand upon the rivers."}},"definableWords":["sea"],"peopleInVerse":[]},"26":{"text":"He shall cry unto me, Thou art my father, my God, and the rock of my salvation.","ref":"Psalms 89:26","synthesized":"He will call to Me, ‘You are my Father, my God, the Rock of my salvation.’","sources":{"KJV":{"text":"He shall cry unto me, Thou art my father, my God, and the rock of my salvation."},"BSB":{"text":"He will call to Me, ‘You are my Father, my God, the Rock of my salvation.’"}},"definableWords":["Father","God","salvation"],"peopleInVerse":[]},"27":{"text":"Also I will make him my firstborn, higher than the kings of the earth.","ref":"Psalms 89:27","synthesized":"I will indeed appoint him as My firstborn, the highest of the kings of the earth.","sources":{"KJV":{"text":"Also I will make him my firstborn, higher than the kings of the earth."},"BSB":{"text":"I will indeed appoint him as My firstborn, the highest of the kings of the earth."}},"definableWords":["kings","earth"],"peopleInVerse":[]},"28":{"text":"My mercy will I keep for him for evermore, and my covenant shall stand fast with him.","ref":"Psalms 89:28","synthesized":"I will forever preserve My loving devotion for him, and My covenant with him will stand fast.","sources":{"KJV":{"text":"My mercy will I keep for him for evermore, and my covenant shall stand fast with him."},"BSB":{"text":"I will forever preserve My loving devotion for him, and My covenant with him will stand fast."}},"definableWords":["covenant","stand","fast"],"peopleInVerse":[]},"29":{"text":"His seed also will I make to endure for ever, and his throne as the days of heaven.","ref":"Psalms 89:29","synthesized":"I will establish his line forever, his throne as long as the heavens endure.","sources":{"KJV":{"text":"His seed also will I make to endure for ever, and his throne as the days of heaven."},"BSB":{"text":"I will establish his line forever, his throne as long as the heavens endure."}},"definableWords":["throne","heavens"],"peopleInVerse":[]},"30":{"text":"If his children forsake my law, and walk not in my judgments;","ref":"Psalms 89:30","synthesized":"If his sons forsake My law and do not walk in My judgments,","sources":{"KJV":{"text":"If his children forsake my law, and walk not in my judgments;"},"BSB":{"text":"If his sons forsake My law and do not walk in My judgments,"}},"definableWords":["sons","law","walk"],"peopleInVerse":[]},"31":{"text":"If they break my statutes, and keep not my commandments;","ref":"Psalms 89:31","synthesized":"if they violate My statutes and fail to keep My commandments,","sources":{"KJV":{"text":"If they break my statutes, and keep not my commandments;"},"BSB":{"text":"if they violate My statutes and fail to keep My commandments,"}},"definableWords":["keep"],"peopleInVerse":[]},"32":{"text":"Then will I visit their transgression with the rod, and their iniquity with stripes.","ref":"Psalms 89:32","synthesized":"I will attend to their transgression with the rod, and to their iniquity with stripes.","sources":{"KJV":{"text":"Then will I visit their transgression with the rod, and their iniquity with stripes."},"BSB":{"text":"I will attend to their transgression with the rod, and to their iniquity with stripes."}},"definableWords":["transgression","iniquity"],"peopleInVerse":[]},"33":{"text":"Nevertheless my lovingkindness will I not utterly take from him, nor suffer my faithfulness to fail.","ref":"Psalms 89:33","synthesized":"But I will not withdraw My loving devotion from him, nor ever betray My faithfulness.","sources":{"KJV":{"text":"Nevertheless my lovingkindness will I not utterly take from him, nor suffer my faithfulness to fail."},"BSB":{"text":"But I will not withdraw My loving devotion from him, nor ever betray My faithfulness."}},"definableWords":[],"peopleInVerse":[]},"34":{"text":"My covenant will I not break, nor alter the thing that is gone out of my lips.","ref":"Psalms 89:34","synthesized":"I will not violate My covenant or alter the utterance of My lips.","sources":{"KJV":{"text":"My covenant will I not break, nor alter the thing that is gone out of my lips."},"BSB":{"text":"I will not violate My covenant or alter the utterance of My lips."}},"definableWords":["covenant","or"],"peopleInVerse":[]},"35":{"text":"Once have I sworn by my holiness that I will not lie unto David.","ref":"Psalms 89:35","synthesized":"Once and for all I have sworn by My holiness— I will not lie to David—","sources":{"KJV":{"text":"Once have I sworn by my holiness that I will not lie unto David."},"BSB":{"text":"Once and for all I have sworn by My holiness— I will not lie to David—"}},"definableWords":[],"peopleInVerse":["David"]},"36":{"text":"His seed shall endure for ever, and his throne as the sun before me.","ref":"Psalms 89:36","synthesized":"his offspring shall endure forever, and his throne before Me like the sun,","sources":{"KJV":{"text":"His seed shall endure for ever, and his throne as the sun before me."},"BSB":{"text":"his offspring shall endure forever, and his throne before Me like the sun,"}},"definableWords":["throne"],"peopleInVerse":[]},"37":{"text":"It shall be established for ever as the moon, and as a faithful witness in heaven. Selah.","ref":"Psalms 89:37","synthesized":"like the moon, established forever, a faithful witness in the sky.” Selah","sources":{"KJV":{"text":"It shall be established for ever as the moon, and as a faithful witness in heaven. Selah."},"BSB":{"text":"like the moon, established forever, a faithful witness in the sky.” Selah"}},"definableWords":[],"peopleInVerse":[]},"38":{"text":"But thou hast cast off and abhorred, thou hast been wroth with thine anointed.","ref":"Psalms 89:38","synthesized":"Now, however, You have spurned and rejected him; You are enraged by Your anointed one.","sources":{"KJV":{"text":"But thou hast cast off and abhorred, thou hast been wroth with thine anointed."},"BSB":{"text":"Now, however, You have spurned and rejected him; You are enraged by Your anointed one."}},"definableWords":["one"],"peopleInVerse":[]},"39":{"text":"Thou hast made void the covenant of thy servant: thou hast profaned his crown by casting it to the ground.","ref":"Psalms 89:39","synthesized":"You have renounced the covenant with Your servant and sullied his crown in the dust.","sources":{"KJV":{"text":"Thou hast made void the covenant of thy servant: thou hast profaned his crown by casting it to the ground."},"BSB":{"text":"You have renounced the covenant with Your servant and sullied his crown in the dust."}},"definableWords":["covenant","servant","crown"],"peopleInVerse":[]},"40":{"text":"Thou hast broken down all his hedges; thou hast brought his strong holds to ruin.","ref":"Psalms 89:40","synthesized":"You have broken down all his walls; You have reduced his strongholds to rubble.","sources":{"KJV":{"text":"Thou hast broken down all his hedges; thou hast brought his strong holds to ruin."},"BSB":{"text":"You have broken down all his walls; You have reduced his strongholds to rubble."}},"definableWords":[],"peopleInVerse":[]},"41":{"text":"All that pass by the way spoil him: he is a reproach to his neighbours.","ref":"Psalms 89:41","synthesized":"All who pass by plunder him; he has become a reproach to his neighbors.","sources":{"KJV":{"text":"All that pass by the way spoil him: he is a reproach to his neighbours."},"BSB":{"text":"All who pass by plunder him; he has become a reproach to his neighbors."}},"definableWords":[],"peopleInVerse":[]},"42":{"text":"Thou hast set up the right hand of his adversaries; thou hast made all his enemies to rejoice.","ref":"Psalms 89:42","synthesized":"You have exalted the right hand of his foes; You have made all his enemies rejoice.","sources":{"KJV":{"text":"Thou hast set up the right hand of his adversaries; thou hast made all his enemies to rejoice."},"BSB":{"text":"You have exalted the right hand of his foes; You have made all his enemies rejoice."}},"definableWords":["made"],"peopleInVerse":[]},"43":{"text":"Thou hast also turned the edge of his sword, and hast not made him to stand in the battle.","ref":"Psalms 89:43","synthesized":"You have bent the edge of his sword and have not sustained him in battle.","sources":{"KJV":{"text":"Thou hast also turned the edge of his sword, and hast not made him to stand in the battle."},"BSB":{"text":"You have bent the edge of his sword and have not sustained him in battle."}},"definableWords":[],"peopleInVerse":[]},"44":{"text":"Thou hast made his glory to cease, and cast his throne down to the ground.","ref":"Psalms 89:44","synthesized":"You have ended his splendor and cast his throne to the ground.","sources":{"KJV":{"text":"Thou hast made his glory to cease, and cast his throne down to the ground."},"BSB":{"text":"You have ended his splendor and cast his throne to the ground."}},"definableWords":["throne","ground"],"peopleInVerse":[]},"45":{"text":"The days of his youth hast thou shortened: thou hast covered him with shame. Selah.","ref":"Psalms 89:45","synthesized":"You have cut short the days of his youth; You have covered him with shame. Selah","sources":{"KJV":{"text":"The days of his youth hast thou shortened: thou hast covered him with shame. Selah."},"BSB":{"text":"You have cut short the days of his youth; You have covered him with shame. Selah"}},"definableWords":["days"],"peopleInVerse":[]},"46":{"text":"How long, LORD? wilt thou hide thyself for ever? shall thy wrath burn like fire?","ref":"Psalms 89:46","synthesized":"How long, O LORD? Will You hide Yourself forever? Will Your wrath keep burning like fire?","sources":{"KJV":{"text":"How long, LORD? wilt thou hide thyself for ever? shall thy wrath burn like fire?"},"BSB":{"text":"How long, O LORD? Will You hide Yourself forever? Will Your wrath keep burning like fire?"}},"definableWords":["LORD","wrath","keep"],"peopleInVerse":[]},"47":{"text":"Remember how short my time is: wherefore hast thou made all men in vain?","ref":"Psalms 89:47","synthesized":"Remember the briefness of my lifespan! For what futility You have created all men!","sources":{"KJV":{"text":"Remember how short my time is: wherefore hast thou made all men in vain?"},"BSB":{"text":"Remember the briefness of my lifespan! For what futility You have created all men!"}},"definableWords":["remember","created","men"],"peopleInVerse":[]},"48":{"text":"What man is he that liveth, and shall not see death? shall he deliver his soul from the hand of the grave? Selah.","ref":"Psalms 89:48","synthesized":"What man can live and never see death? Can he deliver his soul from the power of Sheol? Selah","sources":{"KJV":{"text":"What man is he that liveth, and shall not see death? shall he deliver his soul from the hand of the grave? Selah."},"BSB":{"text":"What man can live and never see death? Can he deliver his soul from the power of Sheol? Selah"}},"definableWords":["man","live","see","death","deliver","soul"],"peopleInVerse":[]},"49":{"text":"Lord, where are thy former lovingkindnesses, which thou swarest unto David in thy truth?","ref":"Psalms 89:49","synthesized":"Where, O Lord, is Your loving devotion of old, which You faithfully swore to David?","sources":{"KJV":{"text":"Lord, where are thy former lovingkindnesses, which thou swarest unto David in thy truth?"},"BSB":{"text":"Where, O Lord, is Your loving devotion of old, which You faithfully swore to David?"}},"definableWords":["Lord"],"peopleInVerse":["David"]},"50":{"text":"Remember, Lord, the reproach of thy servants; how I do bear in my bosom the reproach of all the mighty people;","ref":"Psalms 89:50","synthesized":"Remember, O Lord, the reproach of Your servants, which I bear in my heart from so many people—","sources":{"KJV":{"text":"Remember, Lord, the reproach of thy servants; how I do bear in my bosom the reproach of all the mighty people;"},"BSB":{"text":"Remember, O Lord, the reproach of Your servants, which I bear in my heart from so many people—"}},"definableWords":["remember","Lord","servants","heart","people"],"peopleInVerse":[]},"51":{"text":"Wherewith thine enemies have reproached, O LORD; wherewith they have reproached the footsteps of thine anointed.","ref":"Psalms 89:51","synthesized":"how Your enemies have taunted, O LORD, and have mocked every step of Your anointed one!","sources":{"KJV":{"text":"Wherewith thine enemies have reproached, O LORD; wherewith they have reproached the footsteps of thine anointed."},"BSB":{"text":"how Your enemies have taunted, O LORD, and have mocked every step of Your anointed one!"}},"definableWords":["LORD","one"],"peopleInVerse":[]},"52":{"text":"Blessed be the LORD for evermore. Amen, and Amen.","ref":"Psalms 89:52","synthesized":"Blessed be the LORD forever!   Amen and amen.","sources":{"KJV":{"text":"Blessed be the LORD for evermore. Amen, and Amen."},"BSB":{"text":"Blessed be the LORD forever!   Amen and amen."}},"definableWords":["blessed","LORD"],"peopleInVerse":[]}}},"90":{"chapter":"90","title":"MOSES' PSALM","verses":{"1":{"text":"Lord, thou hast been our dwelling place in all generations.","ref":"Psalms 90:1","synthesized":"Lord, You have been our dwelling place through all generations.","sources":{"KJV":{"text":"Lord, thou hast been our dwelling place in all generations."},"BSB":{"text":"Lord, You have been our dwelling place through all generations."}},"definableWords":["Lord"],"peopleInVerse":[]},"2":{"text":"Before the mountains were brought forth, or ever thou hadst formed the earth and the world, even from everlasting to everlasting, thou art God.","ref":"Psalms 90:2","synthesized":"Before the mountains were born or You brought forth the earth and the world, from everlasting to everlasting You are God.","sources":{"KJV":{"text":"Before the mountains were brought forth, or ever thou hadst formed the earth and the world, even from everlasting to everlasting, thou art God."},"BSB":{"text":"Before the mountains were born or You brought forth the earth and the world, from everlasting to everlasting You are God."}},"definableWords":["or","earth","everlasting","God"],"peopleInVerse":[]},"3":{"text":"Thou turnest man to destruction; and sayest, Return, ye children of men.","ref":"Psalms 90:3","synthesized":"You return man to dust, saying, “Return, O sons of mortals.”","sources":{"KJV":{"text":"Thou turnest man to destruction; and sayest, Return, ye children of men."},"BSB":{"text":"You return man to dust, saying, “Return, O sons of mortals.”"}},"definableWords":["man","sons"],"peopleInVerse":[]},"4":{"text":"For a thousand years in thy sight are but as yesterday when it is past, and as a watch in the night.","ref":"Psalms 90:4","synthesized":"For in Your sight a thousand years are but a day that passes, or a watch of the night.","sources":{"KJV":{"text":"For a thousand years in thy sight are but as yesterday when it is past, and as a watch in the night."},"BSB":{"text":"For in Your sight a thousand years are but a day that passes, or a watch of the night."}},"definableWords":["years","day","or","night"],"peopleInVerse":[]},"5":{"text":"Thou carriest them away as with a flood; they are as a sleep: in the morning they are like grass which groweth up.","ref":"Psalms 90:5","synthesized":"You whisk them away in their sleep; they are like the new grass of the morning—","sources":{"KJV":{"text":"Thou carriest them away as with a flood; they are as a sleep: in the morning they are like grass which groweth up."},"BSB":{"text":"You whisk them away in their sleep; they are like the new grass of the morning—"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"In the morning it flourisheth, and groweth up; in the evening it is cut down, and withereth.","ref":"Psalms 90:6","synthesized":"in the morning it springs up new, but by evening it fades and withers.","sources":{"KJV":{"text":"In the morning it flourisheth, and groweth up; in the evening it is cut down, and withereth."},"BSB":{"text":"in the morning it springs up new, but by evening it fades and withers."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"For we are consumed by thine anger, and by thy wrath are we troubled.","ref":"Psalms 90:7","synthesized":"For we are consumed by Your anger and terrified by Your wrath.","sources":{"KJV":{"text":"For we are consumed by thine anger, and by thy wrath are we troubled."},"BSB":{"text":"For we are consumed by Your anger and terrified by Your wrath."}},"definableWords":["anger","wrath"],"peopleInVerse":[]},"8":{"text":"Thou hast set our iniquities before thee, our secret sins in the light of thy countenance.","ref":"Psalms 90:8","synthesized":"You have set our iniquities before You, our secret sins in the light of Your presence.","sources":{"KJV":{"text":"Thou hast set our iniquities before thee, our secret sins in the light of thy countenance."},"BSB":{"text":"You have set our iniquities before You, our secret sins in the light of Your presence."}},"definableWords":["light"],"peopleInVerse":[]},"9":{"text":"For all our days are passed away in thy wrath: we spend our years as a tale that is told.","ref":"Psalms 90:9","synthesized":"For all our days decline in Your fury; we finish our years with a sigh.","sources":{"KJV":{"text":"For all our days are passed away in thy wrath: we spend our years as a tale that is told."},"BSB":{"text":"For all our days decline in Your fury; we finish our years with a sigh."}},"definableWords":["days","years"],"peopleInVerse":[]},"10":{"text":"The days of our years are threescore years and ten; and if by reason of strength they be fourscore years, yet is their strength labour and sorrow; for it is soon cut off, and we fly away.","ref":"Psalms 90:10","synthesized":"The length of our days is seventy years— or eighty if we are strong— yet their pride is but labor and sorrow, for they quickly pass, and we fly away.","sources":{"KJV":{"text":"The days of our years are threescore years and ten; and if by reason of strength they be fourscore years, yet is their strength labour and sorrow; for it is soon cut off, and we fly away."},"BSB":{"text":"The length of our days is seventy years— or eighty if we are strong— yet their pride is but labor and sorrow, for they quickly pass, and we fly away."}},"definableWords":["days","years","or","strong"],"peopleInVerse":[]},"11":{"text":"Who knoweth the power of thine anger? even according to thy fear, so is thy wrath.","ref":"Psalms 90:11","synthesized":"Who knows the power of Your anger? Your wrath matches the fear You are due.","sources":{"KJV":{"text":"Who knoweth the power of thine anger? even according to thy fear, so is thy wrath."},"BSB":{"text":"Who knows the power of Your anger? Your wrath matches the fear You are due."}},"definableWords":["anger","wrath","fear"],"peopleInVerse":[]},"12":{"text":"So teach us to number our days, that we may apply our hearts unto wisdom.","ref":"Psalms 90:12","synthesized":"So teach us to number our days, that we may present a heart of wisdom.","sources":{"KJV":{"text":"So teach us to number our days, that we may apply our hearts unto wisdom."},"BSB":{"text":"So teach us to number our days, that we may present a heart of wisdom."}},"definableWords":["days","heart","wisdom"],"peopleInVerse":[]},"13":{"text":"Return, O LORD, how long? and let it repent thee concerning thy servants.","ref":"Psalms 90:13","synthesized":"Return, O LORD! How long will it be? Have compassion on Your servants.","sources":{"KJV":{"text":"Return, O LORD, how long? and let it repent thee concerning thy servants."},"BSB":{"text":"Return, O LORD! How long will it be? Have compassion on Your servants."}},"definableWords":["LORD","servants"],"peopleInVerse":[]},"14":{"text":"O satisfy us early with thy mercy; that we may rejoice and be glad all our days.","ref":"Psalms 90:14","synthesized":"Satisfy us in the morning with Your loving devotion, that we may sing for joy and be glad all our days.","sources":{"KJV":{"text":"O satisfy us early with thy mercy; that we may rejoice and be glad all our days."},"BSB":{"text":"Satisfy us in the morning with Your loving devotion, that we may sing for joy and be glad all our days."}},"definableWords":["joy","days"],"peopleInVerse":[]},"15":{"text":"Make us glad according to the days wherein thou hast afflicted us, and the years wherein we have seen evil.","ref":"Psalms 90:15","synthesized":"Make us glad for as many days as You have afflicted us, for as many years as we have seen evil.","sources":{"KJV":{"text":"Make us glad according to the days wherein thou hast afflicted us, and the years wherein we have seen evil."},"BSB":{"text":"Make us glad for as many days as You have afflicted us, for as many years as we have seen evil."}},"definableWords":["make","days","years","evil"],"peopleInVerse":[]},"16":{"text":"Let thy work appear unto thy servants, and thy glory unto their children.","ref":"Psalms 90:16","synthesized":"May Your work be shown to Your servants, and Your splendor to their children.","sources":{"KJV":{"text":"Let thy work appear unto thy servants, and thy glory unto their children."},"BSB":{"text":"May Your work be shown to Your servants, and Your splendor to their children."}},"definableWords":["work","servants"],"peopleInVerse":[]},"17":{"text":"And let the beauty of the LORD our God be upon us: and establish thou the work of our hands upon us; yea, the work of our hands establish thou it.","ref":"Psalms 90:17","synthesized":"May the favor of the Lord our God rest upon us; establish for us the work of our hands— yes, establish the work of our hands!","sources":{"KJV":{"text":"And let the beauty of the LORD our God be upon us: and establish thou the work of our hands upon us; yea, the work of our hands establish thou it."},"BSB":{"text":"May the favor of the Lord our God rest upon us; establish for us the work of our hands— yes, establish the work of our hands!"}},"definableWords":["Lord","God","rest","work"],"peopleInVerse":[]}}},"91":{"chapter":"91","title":"HE THAT DWELLETH IN THE SECRET PLACE","verses":{"1":{"text":"He that dwelleth in the secret place of the most High shall abide under the shadow of the Almighty.","ref":"Psalms 91:1","synthesized":"He who dwells in the shelter of the Most High will abide in the shadow of the Almighty.","sources":{"KJV":{"text":"He that dwelleth in the secret place of the most High shall abide under the shadow of the Almighty."},"BSB":{"text":"He who dwells in the shelter of the Most High will abide in the shadow of the Almighty."}},"definableWords":["abide","Almighty"],"peopleInVerse":[]},"2":{"text":"I will say of the LORD, He is my refuge and my fortress: my God; in him will I trust.","ref":"Psalms 91:2","synthesized":"I will say to the LORD, “You are my refuge and my fortress, my God, in whom I trust.”","sources":{"KJV":{"text":"I will say of the LORD, He is my refuge and my fortress: my God; in him will I trust."},"BSB":{"text":"I will say to the LORD, “You are my refuge and my fortress, my God, in whom I trust.”"}},"definableWords":["LORD","God","trust"],"peopleInVerse":[]},"3":{"text":"Surely he shall deliver thee from the snare of the fowler, and from the noisome pestilence.","ref":"Psalms 91:3","synthesized":"Surely He will deliver you from the snare of the fowler, and from the deadly plague.","sources":{"KJV":{"text":"Surely he shall deliver thee from the snare of the fowler, and from the noisome pestilence."},"BSB":{"text":"Surely He will deliver you from the snare of the fowler, and from the deadly plague."}},"definableWords":["deliver"],"peopleInVerse":[]},"4":{"text":"He shall cover thee with his feathers, and under his wings shalt thou trust: his truth shall be thy shield and buckler.","ref":"Psalms 91:4","synthesized":"He will cover you with His feathers; under His wings you will find refuge; His faithfulness is a shield and rampart.","sources":{"KJV":{"text":"He shall cover thee with his feathers, and under his wings shalt thou trust: his truth shall be thy shield and buckler."},"BSB":{"text":"He will cover you with His feathers; under His wings you will find refuge; His faithfulness is a shield and rampart."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Thou shalt not be afraid for the terror by night; nor for the arrow that flieth by day;","ref":"Psalms 91:5","synthesized":"You will not fear the terror of the night, nor the arrow that flies by day,","sources":{"KJV":{"text":"Thou shalt not be afraid for the terror by night; nor for the arrow that flieth by day;"},"BSB":{"text":"You will not fear the terror of the night, nor the arrow that flies by day,"}},"definableWords":["fear","night","day"],"peopleInVerse":[]},"6":{"text":"Nor for the pestilence that walketh in darkness; nor for the destruction that wasteth at noonday.","ref":"Psalms 91:6","synthesized":"nor the pestilence that stalks in the darkness, nor the calamity that destroys at noon.","sources":{"KJV":{"text":"Nor for the pestilence that walketh in darkness; nor for the destruction that wasteth at noonday."},"BSB":{"text":"nor the pestilence that stalks in the darkness, nor the calamity that destroys at noon."}},"definableWords":["darkness"],"peopleInVerse":[]},"7":{"text":"A thousand shall fall at thy side, and ten thousand at thy right hand; but it shall not come nigh thee.","ref":"Psalms 91:7","synthesized":"Though a thousand may fall at your side, and ten thousand at your right hand, no harm will come near you.","sources":{"KJV":{"text":"A thousand shall fall at thy side, and ten thousand at thy right hand; but it shall not come nigh thee."},"BSB":{"text":"Though a thousand may fall at your side, and ten thousand at your right hand, no harm will come near you."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Only with thine eyes shalt thou behold and see the reward of the wicked.","ref":"Psalms 91:8","synthesized":"You will only see it with your eyes and witness the punishment of the wicked.","sources":{"KJV":{"text":"Only with thine eyes shalt thou behold and see the reward of the wicked."},"BSB":{"text":"You will only see it with your eyes and witness the punishment of the wicked."}},"definableWords":["see"],"peopleInVerse":[]},"9":{"text":"Because thou hast made the LORD, which is my refuge, even the most High, thy habitation;","ref":"Psalms 91:9","synthesized":"Because you have made the LORD your dwelling— my refuge, the Most High—","sources":{"KJV":{"text":"Because thou hast made the LORD, which is my refuge, even the most High, thy habitation;"},"BSB":{"text":"Because you have made the LORD your dwelling— my refuge, the Most High—"}},"definableWords":["made","LORD"],"peopleInVerse":[]},"10":{"text":"There shall no evil befall thee, neither shall any plague come nigh thy dwelling.","ref":"Psalms 91:10","synthesized":"no evil will befall you, no plague will approach your tent.","sources":{"KJV":{"text":"There shall no evil befall thee, neither shall any plague come nigh thy dwelling."},"BSB":{"text":"no evil will befall you, no plague will approach your tent."}},"definableWords":["evil"],"peopleInVerse":[]},"11":{"text":"For he shall give his angels charge over thee, to keep thee in all thy ways.","ref":"Psalms 91:11","synthesized":"For He will command His angels concerning you to guard you in all your ways.","sources":{"KJV":{"text":"For he shall give his angels charge over thee, to keep thee in all thy ways."},"BSB":{"text":"For He will command His angels concerning you to guard you in all your ways."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"They shall bear thee up in their hands, lest thou dash thy foot against a stone.","ref":"Psalms 91:12","synthesized":"They will lift you up in their hands, so that you will not strike your foot against a stone.","sources":{"KJV":{"text":"They shall bear thee up in their hands, lest thou dash thy foot against a stone."},"BSB":{"text":"They will lift you up in their hands, so that you will not strike your foot against a stone."}},"definableWords":["stone"],"peopleInVerse":[]},"13":{"text":"Thou shalt tread upon the lion and adder: the young lion and the dragon shalt thou trample under feet.","ref":"Psalms 91:13","synthesized":"You will tread on the lion and cobra; you will trample the young lion and serpent.","sources":{"KJV":{"text":"Thou shalt tread upon the lion and adder: the young lion and the dragon shalt thou trample under feet."},"BSB":{"text":"You will tread on the lion and cobra; you will trample the young lion and serpent."}},"definableWords":["lion","serpent"],"peopleInVerse":[]},"14":{"text":"Because he hath set his love upon me, therefore will I deliver him: I will set him on high, because he hath known my name.","ref":"Psalms 91:14","synthesized":"“Because he loves Me, I will deliver him; because he knows My name, I will protect him.","sources":{"KJV":{"text":"Because he hath set his love upon me, therefore will I deliver him: I will set him on high, because he hath known my name."},"BSB":{"text":"“Because he loves Me, I will deliver him; because he knows My name, I will protect him."}},"definableWords":["deliver","name"],"peopleInVerse":[]},"15":{"text":"He shall call upon me, and I will answer him: I will be with him in trouble; I will deliver him, and honour him.","ref":"Psalms 91:15","synthesized":"When he calls out to Me, I will answer him; I will be with him in trouble. I will deliver him and honor him.","sources":{"KJV":{"text":"He shall call upon me, and I will answer him: I will be with him in trouble; I will deliver him, and honour him."},"BSB":{"text":"When he calls out to Me, I will answer him; I will be with him in trouble. I will deliver him and honor him."}},"definableWords":["deliver"],"peopleInVerse":[]},"16":{"text":"With long life will I satisfy him, and shew him my salvation.","ref":"Psalms 91:16","synthesized":"With long life I will satisfy him and show him My salvation.”","sources":{"KJV":{"text":"With long life will I satisfy him, and shew him my salvation."},"BSB":{"text":"With long life I will satisfy him and show him My salvation.”"}},"definableWords":["life","salvation"],"peopleInVerse":[]}}},"92":{"chapter":"92","title":"A SONG FOR THE SABBATH DAY","verses":{"1":{"text":"IT IS A GOOD THING TO GIVE THANKS UNTO THE LORD, AND TO SING PRAISES UNTO THY NAME, O MOST HIGH:","ref":"Psalms 92:1","synthesized":"It is good to praise the LORD, and to sing praises to Your name, O Most High,","sources":{"KJV":{"text":"IT IS A GOOD THING TO GIVE THANKS UNTO THE LORD, AND TO SING PRAISES UNTO THY NAME, O MOST HIGH:"},"BSB":{"text":"It is good to praise the LORD, and to sing praises to Your name, O Most High,"}},"definableWords":["good","praise","LORD","name"],"peopleInVerse":[]},"2":{"text":"To shew forth thy lovingkindness in the morning, and thy faithfulness every night,","ref":"Psalms 92:2","synthesized":"to proclaim Your loving devotion in the morning and Your faithfulness at night","sources":{"KJV":{"text":"To shew forth thy lovingkindness in the morning, and thy faithfulness every night,"},"BSB":{"text":"to proclaim Your loving devotion in the morning and Your faithfulness at night"}},"definableWords":["night"],"peopleInVerse":[]},"3":{"text":"Upon an instrument of ten strings, and upon the psaltery; upon the harp with a solemn sound.","ref":"Psalms 92:3","synthesized":"with the ten-stringed harp and the melody of the lyre.","sources":{"KJV":{"text":"Upon an instrument of ten strings, and upon the psaltery; upon the harp with a solemn sound."},"BSB":{"text":"with the ten-stringed harp and the melody of the lyre."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"For thou, LORD, hast made me glad through thy work: I will triumph in the works of thy hands.","ref":"Psalms 92:4","synthesized":"For You, O LORD, have made me glad by Your deeds; I sing for joy at the works of Your hands.","sources":{"KJV":{"text":"For thou, LORD, hast made me glad through thy work: I will triumph in the works of thy hands."},"BSB":{"text":"For You, O LORD, have made me glad by Your deeds; I sing for joy at the works of Your hands."}},"definableWords":["LORD","made","joy","works"],"peopleInVerse":[]},"5":{"text":"O LORD, how great are thy works! and thy thoughts are very deep.","ref":"Psalms 92:5","synthesized":"How great are Your works, O LORD, how deep are Your thoughts!","sources":{"KJV":{"text":"O LORD, how great are thy works! and thy thoughts are very deep."},"BSB":{"text":"How great are Your works, O LORD, how deep are Your thoughts!"}},"definableWords":["great","works","LORD","deep"],"peopleInVerse":[]},"6":{"text":"A brutish man knoweth not; neither doth a fool understand this.","ref":"Psalms 92:6","synthesized":"A senseless man does not know, and a fool does not understand,","sources":{"KJV":{"text":"A brutish man knoweth not; neither doth a fool understand this."},"BSB":{"text":"A senseless man does not know, and a fool does not understand,"}},"definableWords":["man","fool"],"peopleInVerse":[]},"7":{"text":"When the wicked spring as the grass, and when all the workers of iniquity do flourish; it is that they shall be destroyed for ever:","ref":"Psalms 92:7","synthesized":"that though the wicked sprout like grass, and all evildoers flourish, they will be forever destroyed.","sources":{"KJV":{"text":"When the wicked spring as the grass, and when all the workers of iniquity do flourish; it is that they shall be destroyed for ever:"},"BSB":{"text":"that though the wicked sprout like grass, and all evildoers flourish, they will be forever destroyed."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"But thou, LORD, art most high for evermore.","ref":"Psalms 92:8","synthesized":"But You, O LORD, are exalted forever!","sources":{"KJV":{"text":"But thou, LORD, art most high for evermore."},"BSB":{"text":"But You, O LORD, are exalted forever!"}},"definableWords":["LORD"],"peopleInVerse":[]},"9":{"text":"For, lo, thine enemies, O LORD, for, lo, thine enemies shall perish; all the workers of iniquity shall be scattered.","ref":"Psalms 92:9","synthesized":"For surely Your enemies, O LORD, surely Your enemies will perish; all evildoers will be scattered.","sources":{"KJV":{"text":"For, lo, thine enemies, O LORD, for, lo, thine enemies shall perish; all the workers of iniquity shall be scattered."},"BSB":{"text":"For surely Your enemies, O LORD, surely Your enemies will perish; all evildoers will be scattered."}},"definableWords":["LORD"],"peopleInVerse":[]},"10":{"text":"But my horn shalt thou exalt like the horn of an unicorn: I shall be anointed with fresh oil.","ref":"Psalms 92:10","synthesized":"But You have exalted my horn like that of a wild ox; with fine oil I have been anointed.","sources":{"KJV":{"text":"But my horn shalt thou exalt like the horn of an unicorn: I shall be anointed with fresh oil."},"BSB":{"text":"But You have exalted my horn like that of a wild ox; with fine oil I have been anointed."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Mine eye also shall see my desire on mine enemies, and mine ears shall hear my desire of the wicked that rise up against me.","ref":"Psalms 92:11","synthesized":"My eyes see the downfall of my enemies; my ears hear the wailing of my wicked foes.","sources":{"KJV":{"text":"Mine eye also shall see my desire on mine enemies, and mine ears shall hear my desire of the wicked that rise up against me."},"BSB":{"text":"My eyes see the downfall of my enemies; my ears hear the wailing of my wicked foes."}},"definableWords":["see","hear"],"peopleInVerse":[]},"12":{"text":"The righteous shall flourish like the palm tree: he shall grow like a cedar in Lebanon.","ref":"Psalms 92:12","synthesized":"The righteous will flourish like a palm tree, and grow like a cedar in Lebanon.","sources":{"KJV":{"text":"The righteous shall flourish like the palm tree: he shall grow like a cedar in Lebanon."},"BSB":{"text":"The righteous will flourish like a palm tree, and grow like a cedar in Lebanon."}},"definableWords":["righteous","tree"],"peopleInVerse":[]},"13":{"text":"Those that be planted in the house of the LORD shall flourish in the courts of our God.","ref":"Psalms 92:13","synthesized":"Planted in the house of the LORD, they will flourish in the courts of our God.","sources":{"KJV":{"text":"Those that be planted in the house of the LORD shall flourish in the courts of our God."},"BSB":{"text":"Planted in the house of the LORD, they will flourish in the courts of our God."}},"definableWords":["house","LORD","God"],"peopleInVerse":[]},"14":{"text":"They shall still bring forth fruit in old age; they shall be fat and flourishing;","ref":"Psalms 92:14","synthesized":"In old age they will still bear fruit; healthy and green they will remain,","sources":{"KJV":{"text":"They shall still bring forth fruit in old age; they shall be fat and flourishing;"},"BSB":{"text":"In old age they will still bear fruit; healthy and green they will remain,"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"To shew that the LORD is upright: he is my rock, and there is no unrighteousness in him.","ref":"Psalms 92:15","synthesized":"to proclaim, “The LORD is upright; He is my Rock, and in Him there is no unrighteousness.”","sources":{"KJV":{"text":"To shew that the LORD is upright: he is my rock, and there is no unrighteousness in him."},"BSB":{"text":"to proclaim, “The LORD is upright; He is my Rock, and in Him there is no unrighteousness.”"}},"definableWords":["LORD"],"peopleInVerse":[]}}},"93":{"chapter":"93","title":"THE LORD REIGNETH","verses":{"1":{"text":"The LORD reigneth, he is clothed with majesty; the LORD is clothed with strength, wherewith he hath girded himself: the world also is stablished, that it cannot be moved.","ref":"Psalms 93:1","synthesized":"The LORD reigns! He is robed in majesty; the LORD has clothed and armed Himself with strength. The world indeed is firmly established; it cannot be moved.","sources":{"KJV":{"text":"The LORD reigneth, he is clothed with majesty; the LORD is clothed with strength, wherewith he hath girded himself: the world also is stablished, that it cannot be moved."},"BSB":{"text":"The LORD reigns! He is robed in majesty; the LORD has clothed and armed Himself with strength. The world indeed is firmly established; it cannot be moved."}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"2":{"text":"Thy throne is established of old: thou art from everlasting.","ref":"Psalms 93:2","synthesized":"Your throne was established long ago; You are from all eternity.","sources":{"KJV":{"text":"Thy throne is established of old: thou art from everlasting."},"BSB":{"text":"Your throne was established long ago; You are from all eternity."}},"definableWords":["throne"],"peopleInVerse":[]},"3":{"text":"The floods have lifted up, O LORD, the floods have lifted up their voice; the floods lift up their waves.","ref":"Psalms 93:3","synthesized":"The floodwaters have risen, O LORD; the rivers have raised their voice; the seas lift up their pounding waves.","sources":{"KJV":{"text":"The floods have lifted up, O LORD, the floods have lifted up their voice; the floods lift up their waves."},"BSB":{"text":"The floodwaters have risen, O LORD; the rivers have raised their voice; the seas lift up their pounding waves."}},"definableWords":["LORD","voice","seas"],"peopleInVerse":[]},"4":{"text":"The LORD on high is mightier than the noise of many waters, yea, than the mighty waves of the sea.","ref":"Psalms 93:4","synthesized":"Above the roar of many waters— the mighty breakers of the sea— the LORD on high is majestic.","sources":{"KJV":{"text":"The LORD on high is mightier than the noise of many waters, yea, than the mighty waves of the sea."},"BSB":{"text":"Above the roar of many waters— the mighty breakers of the sea— the LORD on high is majestic."}},"definableWords":["waters","mighty","sea","LORD"],"peopleInVerse":[]},"5":{"text":"Thy testimonies are very sure: holiness becometh thine house, O LORD, for ever.","ref":"Psalms 93:5","synthesized":"Your testimonies are fully confirmed; holiness adorns Your house, O LORD, for all the days to come.","sources":{"KJV":{"text":"Thy testimonies are very sure: holiness becometh thine house, O LORD, for ever."},"BSB":{"text":"Your testimonies are fully confirmed; holiness adorns Your house, O LORD, for all the days to come."}},"definableWords":["house","LORD","days"],"peopleInVerse":[]}}},"94":{"chapter":"94","title":"O LORD GOD, TO WHOM VENGEANCE BELONGETH","verses":{"1":{"text":"O Lord God, to whom vengeance belongeth; O God, to whom vengeance belongeth, shew thyself.","ref":"Psalms 94:1","synthesized":"O LORD, God of vengeance, O God of vengeance, shine forth.","sources":{"KJV":{"text":"O Lord God, to whom vengeance belongeth; O God, to whom vengeance belongeth, shew thyself."},"BSB":{"text":"O LORD, God of vengeance, O God of vengeance, shine forth."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"2":{"text":"Lift up thyself, thou judge of the earth: render a reward to the proud.","ref":"Psalms 94:2","synthesized":"Rise up, O Judge of the earth; render a reward to the proud.","sources":{"KJV":{"text":"Lift up thyself, thou judge of the earth: render a reward to the proud."},"BSB":{"text":"Rise up, O Judge of the earth; render a reward to the proud."}},"definableWords":["earth"],"peopleInVerse":[]},"3":{"text":"LORD, how long shall the wicked, how long shall the wicked triumph?","ref":"Psalms 94:3","synthesized":"How long will the wicked, O LORD, how long will the wicked exult?","sources":{"KJV":{"text":"LORD, how long shall the wicked, how long shall the wicked triumph?"},"BSB":{"text":"How long will the wicked, O LORD, how long will the wicked exult?"}},"definableWords":["LORD"],"peopleInVerse":[]},"4":{"text":"How long shall they utter and speak hard things? and all the workers of iniquity boast themselves?","ref":"Psalms 94:4","synthesized":"They pour out arrogant words; all workers of iniquity boast.","sources":{"KJV":{"text":"How long shall they utter and speak hard things? and all the workers of iniquity boast themselves?"},"BSB":{"text":"They pour out arrogant words; all workers of iniquity boast."}},"definableWords":["iniquity"],"peopleInVerse":[]},"5":{"text":"They break in pieces thy people, O LORD, and afflict thine heritage.","ref":"Psalms 94:5","synthesized":"They crush Your people, O LORD; they oppress Your heritage.","sources":{"KJV":{"text":"They break in pieces thy people, O LORD, and afflict thine heritage."},"BSB":{"text":"They crush Your people, O LORD; they oppress Your heritage."}},"definableWords":["people","LORD"],"peopleInVerse":[]},"6":{"text":"They slay the widow and the stranger, and murder the fatherless.","ref":"Psalms 94:6","synthesized":"They kill the widow and the foreigner; they murder the fatherless.","sources":{"KJV":{"text":"They slay the widow and the stranger, and murder the fatherless."},"BSB":{"text":"They kill the widow and the foreigner; they murder the fatherless."}},"definableWords":["widow"],"peopleInVerse":[]},"7":{"text":"Yet they say, The LORD shall not see, neither shall the God of Jacob regard it.","ref":"Psalms 94:7","synthesized":"They say, “The LORD does not see; the God of Jacob pays no heed.”","sources":{"KJV":{"text":"Yet they say, The LORD shall not see, neither shall the God of Jacob regard it."},"BSB":{"text":"They say, “The LORD does not see; the God of Jacob pays no heed.”"}},"definableWords":["LORD","see","God","Jacob"],"peopleInVerse":["Jacob"]},"8":{"text":"Understand, ye brutish among the people: and ye fools, when will ye be wise?","ref":"Psalms 94:8","synthesized":"Take notice, O senseless among the people! O fools, when will you be wise?","sources":{"KJV":{"text":"Understand, ye brutish among the people: and ye fools, when will ye be wise?"},"BSB":{"text":"Take notice, O senseless among the people! O fools, when will you be wise?"}},"definableWords":["people"],"peopleInVerse":[]},"9":{"text":"He that planted the ear, shall he not hear? he that formed the eye, shall he not see?","ref":"Psalms 94:9","synthesized":"He who affixed the ear, can He not hear? He who formed the eye, can He not see?","sources":{"KJV":{"text":"He that planted the ear, shall he not hear? he that formed the eye, shall he not see?"},"BSB":{"text":"He who affixed the ear, can He not hear? He who formed the eye, can He not see?"}},"definableWords":["hear","formed","see"],"peopleInVerse":[]},"10":{"text":"He that chastiseth the heathen, shall not he correct? he that teacheth man knowledge, shall not he know?","ref":"Psalms 94:10","synthesized":"He who admonishes the nations, does He not discipline? He who teaches man, does He lack knowledge?","sources":{"KJV":{"text":"He that chastiseth the heathen, shall not he correct? he that teacheth man knowledge, shall not he know?"},"BSB":{"text":"He who admonishes the nations, does He not discipline? He who teaches man, does He lack knowledge?"}},"definableWords":["nations","man","knowledge"],"peopleInVerse":[]},"11":{"text":"The LORD knoweth the thoughts of man, that they are vanity.","ref":"Psalms 94:11","synthesized":"The LORD knows the thoughts of man, that they are futile.","sources":{"KJV":{"text":"The LORD knoweth the thoughts of man, that they are vanity."},"BSB":{"text":"The LORD knows the thoughts of man, that they are futile."}},"definableWords":["LORD","man"],"peopleInVerse":[]},"12":{"text":"Blessed is the man whom thou chastenest, O LORD, and teachest him out of thy law;","ref":"Psalms 94:12","synthesized":"Blessed is the man You discipline, O LORD, and teach from Your law,","sources":{"KJV":{"text":"Blessed is the man whom thou chastenest, O LORD, and teachest him out of thy law;"},"BSB":{"text":"Blessed is the man You discipline, O LORD, and teach from Your law,"}},"definableWords":["blessed","man","LORD","law"],"peopleInVerse":[]},"13":{"text":"That thou mayest give him rest from the days of adversity, until the pit be digged for the wicked.","ref":"Psalms 94:13","synthesized":"to grant him relief from days of trouble, until a pit is dug for the wicked.","sources":{"KJV":{"text":"That thou mayest give him rest from the days of adversity, until the pit be digged for the wicked."},"BSB":{"text":"to grant him relief from days of trouble, until a pit is dug for the wicked."}},"definableWords":["days"],"peopleInVerse":[]},"14":{"text":"For the LORD will not cast off his people, neither will he forsake his inheritance.","ref":"Psalms 94:14","synthesized":"For the LORD will not forsake His people; He will never abandon His heritage.","sources":{"KJV":{"text":"For the LORD will not cast off his people, neither will he forsake his inheritance."},"BSB":{"text":"For the LORD will not forsake His people; He will never abandon His heritage."}},"definableWords":["LORD","people"],"peopleInVerse":[]},"15":{"text":"But judgment shall return unto righteousness: and all the upright in heart shall follow it.","ref":"Psalms 94:15","synthesized":"Surely judgment will again be righteous, and all the upright in heart will follow it.","sources":{"KJV":{"text":"But judgment shall return unto righteousness: and all the upright in heart shall follow it."},"BSB":{"text":"Surely judgment will again be righteous, and all the upright in heart will follow it."}},"definableWords":["judgment","righteous","heart"],"peopleInVerse":[]},"16":{"text":"Who will rise up for me against the evildoers? or who will stand up for me against the workers of iniquity?","ref":"Psalms 94:16","synthesized":"Who will rise up for me against the wicked? Who will stand for me against the workers of iniquity?","sources":{"KJV":{"text":"Who will rise up for me against the evildoers? or who will stand up for me against the workers of iniquity?"},"BSB":{"text":"Who will rise up for me against the wicked? Who will stand for me against the workers of iniquity?"}},"definableWords":["stand","iniquity"],"peopleInVerse":[]},"17":{"text":"Unless the LORD had been my help, my soul had almost dwelt in silence.","ref":"Psalms 94:17","synthesized":"Unless the LORD had been my helper, I would soon have dwelt in the abode of silence.","sources":{"KJV":{"text":"Unless the LORD had been my help, my soul had almost dwelt in silence."},"BSB":{"text":"Unless the LORD had been my helper, I would soon have dwelt in the abode of silence."}},"definableWords":["LORD","helper"],"peopleInVerse":[]},"18":{"text":"When I said, My foot slippeth; thy mercy, O LORD, held me up.","ref":"Psalms 94:18","synthesized":"If I say, “My foot is slipping,” Your loving devotion, O LORD, supports me.","sources":{"KJV":{"text":"When I said, My foot slippeth; thy mercy, O LORD, held me up."},"BSB":{"text":"If I say, “My foot is slipping,” Your loving devotion, O LORD, supports me."}},"definableWords":["LORD"],"peopleInVerse":[]},"19":{"text":"In the multitude of my thoughts within me thy comforts delight my soul.","ref":"Psalms 94:19","synthesized":"When anxiety overwhelms me, Your consolation delights my soul.","sources":{"KJV":{"text":"In the multitude of my thoughts within me thy comforts delight my soul."},"BSB":{"text":"When anxiety overwhelms me, Your consolation delights my soul."}},"definableWords":["soul"],"peopleInVerse":[]},"20":{"text":"Shall the throne of iniquity have fellowship with thee, which frameth mischief by a law?","ref":"Psalms 94:20","synthesized":"Can a corrupt throne be Your ally— one devising mischief by decree?","sources":{"KJV":{"text":"Shall the throne of iniquity have fellowship with thee, which frameth mischief by a law?"},"BSB":{"text":"Can a corrupt throne be Your ally— one devising mischief by decree?"}},"definableWords":["throne","one"],"peopleInVerse":[]},"21":{"text":"They gather themselves together against the soul of the righteous, and condemn the innocent blood.","ref":"Psalms 94:21","synthesized":"They band together against the righteous and condemn the innocent to death.","sources":{"KJV":{"text":"They gather themselves together against the soul of the righteous, and condemn the innocent blood."},"BSB":{"text":"They band together against the righteous and condemn the innocent to death."}},"definableWords":["righteous","death"],"peopleInVerse":[]},"22":{"text":"But the LORD is my defence; and my God is the rock of my refuge.","ref":"Psalms 94:22","synthesized":"But the LORD has been my stronghold, and my God is my rock of refuge.","sources":{"KJV":{"text":"But the LORD is my defence; and my God is the rock of my refuge."},"BSB":{"text":"But the LORD has been my stronghold, and my God is my rock of refuge."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"23":{"text":"And he shall bring upon them their own iniquity, and shall cut them off in their own wickedness; yea, the LORD our God shall cut them off.","ref":"Psalms 94:23","synthesized":"He will bring upon them their own iniquity and destroy them for their wickedness. The LORD our God will destroy them.","sources":{"KJV":{"text":"And he shall bring upon them their own iniquity, and shall cut them off in their own wickedness; yea, the LORD our God shall cut them off."},"BSB":{"text":"He will bring upon them their own iniquity and destroy them for their wickedness. The LORD our God will destroy them."}},"definableWords":["iniquity","LORD","God"],"peopleInVerse":[]}}},"95":{"chapter":"95","title":"O COME, LET US SING UNTO THE LORD","verses":{"1":{"text":"O come, let us sing unto the LORD: let us make a joyful noise to the rock of our salvation.","ref":"Psalms 95:1","synthesized":"Come, let us sing for joy to the LORD; let us shout to the Rock of our salvation!","sources":{"KJV":{"text":"O come, let us sing unto the LORD: let us make a joyful noise to the rock of our salvation."},"BSB":{"text":"Come, let us sing for joy to the LORD; let us shout to the Rock of our salvation!"}},"definableWords":["joy","LORD","salvation"],"peopleInVerse":[]},"2":{"text":"Let us come before his presence with thanksgiving, and make a joyful noise unto him with psalms.","ref":"Psalms 95:2","synthesized":"Let us enter His presence with thanksgiving; let us make a joyful noise to Him in song.","sources":{"KJV":{"text":"Let us come before his presence with thanksgiving, and make a joyful noise unto him with psalms."},"BSB":{"text":"Let us enter His presence with thanksgiving; let us make a joyful noise to Him in song."}},"definableWords":["make"],"peopleInVerse":[]},"3":{"text":"For the LORD is a great God, and a great King above all gods.","ref":"Psalms 95:3","synthesized":"For the LORD is a great God, a great King above all gods.","sources":{"KJV":{"text":"For the LORD is a great God, and a great King above all gods."},"BSB":{"text":"For the LORD is a great God, a great King above all gods."}},"definableWords":["LORD","great","God","King"],"peopleInVerse":[]},"4":{"text":"In his hand are the deep places of the earth: the strength of the hills is his also.","ref":"Psalms 95:4","synthesized":"In His hand are the depths of the earth, and the mountain peaks belong to Him.","sources":{"KJV":{"text":"In his hand are the deep places of the earth: the strength of the hills is his also."},"BSB":{"text":"In His hand are the depths of the earth, and the mountain peaks belong to Him."}},"definableWords":["earth"],"peopleInVerse":[]},"5":{"text":"The sea is his, and he made it: and his hands formed the dry land.","ref":"Psalms 95:5","synthesized":"The sea is His, for He made it, and His hands formed the dry land.","sources":{"KJV":{"text":"The sea is his, and he made it: and his hands formed the dry land."},"BSB":{"text":"The sea is His, for He made it, and His hands formed the dry land."}},"definableWords":["sea","made","formed","land"],"peopleInVerse":[]},"6":{"text":"O come, let us worship and bow down: let us kneel before the LORD our maker.","ref":"Psalms 95:6","synthesized":"O come, let us worship and bow down; let us kneel before the LORD our Maker.","sources":{"KJV":{"text":"O come, let us worship and bow down: let us kneel before the LORD our maker."},"BSB":{"text":"O come, let us worship and bow down; let us kneel before the LORD our Maker."}},"definableWords":["worship","LORD"],"peopleInVerse":[]},"7":{"text":"For he is our God; and we are the people of his pasture, and the sheep of his hand. To day if ye will hear his voice,","ref":"Psalms 95:7","synthesized":"For He is our God, and we are the people of His pasture, the sheep under His care.   Today, if you hear His voice,","sources":{"KJV":{"text":"For he is our God; and we are the people of his pasture, and the sheep of his hand. To day if ye will hear his voice,"},"BSB":{"text":"For He is our God, and we are the people of His pasture, the sheep under His care.   Today, if you hear His voice,"}},"definableWords":["God","people","hear","voice"],"peopleInVerse":[]},"8":{"text":"Harden not your heart, as in the provocation, and as in the day of temptation in the wilderness:","ref":"Psalms 95:8","synthesized":"do not harden your hearts as you did at Meribah, in the day at Massah in the wilderness,","sources":{"KJV":{"text":"Harden not your heart, as in the provocation, and as in the day of temptation in the wilderness:"},"BSB":{"text":"do not harden your hearts as you did at Meribah, in the day at Massah in the wilderness,"}},"definableWords":["day"],"peopleInVerse":[]},"9":{"text":"When your fathers tempted me, proved me, and saw my work.","ref":"Psalms 95:9","synthesized":"where your fathers tested and tried Me, though they had seen My work.","sources":{"KJV":{"text":"When your fathers tempted me, proved me, and saw my work."},"BSB":{"text":"where your fathers tested and tried Me, though they had seen My work."}},"definableWords":["fathers","work"],"peopleInVerse":[]},"10":{"text":"Forty years long was I grieved with this generation, and said, It is a people that do err in their heart, and they have not known my ways:","ref":"Psalms 95:10","synthesized":"For forty years I was angry with that generation, and I said, “They are a people whose hearts go astray, and they have not known My ways.”","sources":{"KJV":{"text":"Forty years long was I grieved with this generation, and said, It is a people that do err in their heart, and they have not known my ways:"},"BSB":{"text":"For forty years I was angry with that generation, and I said, “They are a people whose hearts go astray, and they have not known My ways.”"}},"definableWords":["years","people"],"peopleInVerse":[]},"11":{"text":"Unto whom I sware in my wrath that they should not enter into my rest.","ref":"Psalms 95:11","synthesized":"So I swore on oath in My anger, “They shall never enter My rest.”","sources":{"KJV":{"text":"Unto whom I sware in my wrath that they should not enter into my rest."},"BSB":{"text":"So I swore on oath in My anger, “They shall never enter My rest.”"}},"definableWords":["anger","rest"],"peopleInVerse":[]}}},"96":{"chapter":"96","title":"SING UNTO THE LORD A NEW SONG","verses":{"1":{"text":"O sing unto the LORD a new song: sing unto the LORD, all the earth.","ref":"Psalms 96:1","synthesized":"Sing to the LORD a new song; sing to the LORD, all the earth.","sources":{"KJV":{"text":"O sing unto the LORD a new song: sing unto the LORD, all the earth."},"BSB":{"text":"Sing to the LORD a new song; sing to the LORD, all the earth."}},"definableWords":["LORD","Lord","earth"],"peopleInVerse":[]},"2":{"text":"Sing unto the LORD, bless his name; shew forth his salvation from day to day.","ref":"Psalms 96:2","synthesized":"Sing to the LORD, bless His name; proclaim His salvation day after day.","sources":{"KJV":{"text":"Sing unto the LORD, bless his name; shew forth his salvation from day to day."},"BSB":{"text":"Sing to the LORD, bless His name; proclaim His salvation day after day."}},"definableWords":["LORD","bless","name","salvation","day"],"peopleInVerse":[]},"3":{"text":"Declare his glory among the heathen, his wonders among all people.","ref":"Psalms 96:3","synthesized":"Declare His glory among the nations, His wonderful deeds among all peoples.","sources":{"KJV":{"text":"Declare his glory among the heathen, his wonders among all people."},"BSB":{"text":"Declare His glory among the nations, His wonderful deeds among all peoples."}},"definableWords":["glory","nations"],"peopleInVerse":[]},"4":{"text":"For the LORD is great, and greatly to be praised: he is to be feared above all gods.","ref":"Psalms 96:4","synthesized":"For great is the LORD, and greatly to be praised; He is to be feared above all gods.","sources":{"KJV":{"text":"For the LORD is great, and greatly to be praised: he is to be feared above all gods."},"BSB":{"text":"For great is the LORD, and greatly to be praised; He is to be feared above all gods."}},"definableWords":["great","LORD"],"peopleInVerse":[]},"5":{"text":"For all the gods of the nations are idols: but the LORD made the heavens.","ref":"Psalms 96:5","synthesized":"For all the gods of the nations are idols, but it is the LORD who made the heavens.","sources":{"KJV":{"text":"For all the gods of the nations are idols: but the LORD made the heavens."},"BSB":{"text":"For all the gods of the nations are idols, but it is the LORD who made the heavens."}},"definableWords":["nations","LORD","made","heavens"],"peopleInVerse":[]},"6":{"text":"Honour and majesty are before him: strength and beauty are in his sanctuary.","ref":"Psalms 96:6","synthesized":"Splendor and majesty are before Him; strength and beauty fill His sanctuary.","sources":{"KJV":{"text":"Honour and majesty are before him: strength and beauty are in his sanctuary."},"BSB":{"text":"Splendor and majesty are before Him; strength and beauty fill His sanctuary."}},"definableWords":["fill"],"peopleInVerse":[]},"7":{"text":"Give unto the LORD, O ye kindreds of the people, give unto the LORD glory and strength.","ref":"Psalms 96:7","synthesized":"Ascribe to the LORD, O families of the nations, ascribe to the LORD glory and strength.","sources":{"KJV":{"text":"Give unto the LORD, O ye kindreds of the people, give unto the LORD glory and strength."},"BSB":{"text":"Ascribe to the LORD, O families of the nations, ascribe to the LORD glory and strength."}},"definableWords":["LORD","families","nations","Lord","glory"],"peopleInVerse":[]},"8":{"text":"Give unto the LORD the glory due unto his name: bring an offering, and come into his courts.","ref":"Psalms 96:8","synthesized":"Ascribe to the LORD the glory due His name; bring an offering and enter His courts.","sources":{"KJV":{"text":"Give unto the LORD the glory due unto his name: bring an offering, and come into his courts."},"BSB":{"text":"Ascribe to the LORD the glory due His name; bring an offering and enter His courts."}},"definableWords":["LORD","glory","name","offering"],"peopleInVerse":[]},"9":{"text":"O worship the LORD in the beauty of holiness: fear before him, all the earth.","ref":"Psalms 96:9","synthesized":"Worship the LORD in the splendor of His holiness; tremble before Him, all the earth.","sources":{"KJV":{"text":"O worship the LORD in the beauty of holiness: fear before him, all the earth."},"BSB":{"text":"Worship the LORD in the splendor of His holiness; tremble before Him, all the earth."}},"definableWords":["worship","LORD","earth"],"peopleInVerse":[]},"10":{"text":"Say among the heathen that the LORD reigneth: the world also shall be established that it shall not be moved: he shall judge the people righteously.","ref":"Psalms 96:10","synthesized":"Declare among the nations: “The LORD reigns!” The world is firmly established; it cannot be moved; He will judge the peoples with equity.","sources":{"KJV":{"text":"Say among the heathen that the LORD reigneth: the world also shall be established that it shall not be moved: he shall judge the people righteously."},"BSB":{"text":"Declare among the nations: “The LORD reigns!” The world is firmly established; it cannot be moved; He will judge the peoples with equity."}},"definableWords":["nations","LORD"],"peopleInVerse":[]},"11":{"text":"Let the heavens rejoice, and let the earth be glad; let the sea roar, and the fulness thereof.","ref":"Psalms 96:11","synthesized":"Let the heavens be glad and the earth rejoice; let the sea resound, and all that fills it.","sources":{"KJV":{"text":"Let the heavens rejoice, and let the earth be glad; let the sea roar, and the fulness thereof."},"BSB":{"text":"Let the heavens be glad and the earth rejoice; let the sea resound, and all that fills it."}},"definableWords":["heavens","earth","sea"],"peopleInVerse":[]},"12":{"text":"Let the field be joyful, and all that is therein: then shall all the trees of the wood rejoice","ref":"Psalms 96:12","synthesized":"Let the fields exult, and all that is in them. Then all the trees of the forest will sing for joy","sources":{"KJV":{"text":"Let the field be joyful, and all that is therein: then shall all the trees of the wood rejoice"},"BSB":{"text":"Let the fields exult, and all that is in them. Then all the trees of the forest will sing for joy"}},"definableWords":["trees","joy"],"peopleInVerse":[]},"13":{"text":"Before the LORD: for he cometh, for he cometh to judge the earth: he shall judge the world with righteousness, and the people with his truth.","ref":"Psalms 96:13","synthesized":"before the LORD, for He is coming— He is coming to judge the earth. He will judge the world in righteousness and the peoples in His faithfulness.","sources":{"KJV":{"text":"Before the LORD: for he cometh, for he cometh to judge the earth: he shall judge the world with righteousness, and the people with his truth."},"BSB":{"text":"before the LORD, for He is coming— He is coming to judge the earth. He will judge the world in righteousness and the peoples in His faithfulness."}},"definableWords":["LORD","earth","righteousness"],"peopleInVerse":[]}}},"97":{"chapter":"97","title":"THE LORD REIGNETH — LET THE EARTH REJOICE","verses":{"1":{"text":"The LORD reigneth; let the earth rejoice; let the multitude of isles be glad thereof.","ref":"Psalms 97:1","synthesized":"The LORD reigns, let the earth rejoice; let the distant shores be glad.","sources":{"KJV":{"text":"The LORD reigneth; let the earth rejoice; let the multitude of isles be glad thereof."},"BSB":{"text":"The LORD reigns, let the earth rejoice; let the distant shores be glad."}},"definableWords":["LORD","earth"],"peopleInVerse":[]},"2":{"text":"Clouds and darkness are round about him: righteousness and judgment are the habitation of his throne.","ref":"Psalms 97:2","synthesized":"Clouds and darkness surround Him; righteousness and justice are His throne’s foundation.","sources":{"KJV":{"text":"Clouds and darkness are round about him: righteousness and judgment are the habitation of his throne."},"BSB":{"text":"Clouds and darkness surround Him; righteousness and justice are His throne’s foundation."}},"definableWords":["darkness","righteousness","justice","throne"],"peopleInVerse":[]},"3":{"text":"A fire goeth before him, and burneth up his enemies round about.","ref":"Psalms 97:3","synthesized":"Fire goes before Him and consumes His foes on every side.","sources":{"KJV":{"text":"A fire goeth before him, and burneth up his enemies round about."},"BSB":{"text":"Fire goes before Him and consumes His foes on every side."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"His lightnings enlightened the world: the earth saw, and trembled.","ref":"Psalms 97:4","synthesized":"His lightning illuminates the world; the earth sees and trembles.","sources":{"KJV":{"text":"His lightnings enlightened the world: the earth saw, and trembled."},"BSB":{"text":"His lightning illuminates the world; the earth sees and trembles."}},"definableWords":["earth"],"peopleInVerse":[]},"5":{"text":"The hills melted like wax at the presence of the LORD, at the presence of the Lord of the whole earth.","ref":"Psalms 97:5","synthesized":"The mountains melt like wax at the presence of the LORD, before the Lord of all the earth.","sources":{"KJV":{"text":"The hills melted like wax at the presence of the LORD, at the presence of the Lord of the whole earth."},"BSB":{"text":"The mountains melt like wax at the presence of the LORD, before the Lord of all the earth."}},"definableWords":["LORD","Lord","earth"],"peopleInVerse":[]},"6":{"text":"The heavens declare his righteousness, and all the people see his glory.","ref":"Psalms 97:6","synthesized":"The heavens proclaim His righteousness; all the peoples see His glory.","sources":{"KJV":{"text":"The heavens declare his righteousness, and all the people see his glory."},"BSB":{"text":"The heavens proclaim His righteousness; all the peoples see His glory."}},"definableWords":["heavens","righteousness","see","glory"],"peopleInVerse":[]},"7":{"text":"Confounded be all they that serve graven images, that boast themselves of idols: worship him, all ye gods.","ref":"Psalms 97:7","synthesized":"All worshipers of images are put to shame— those who boast in idols. Worship Him, all you gods!","sources":{"KJV":{"text":"Confounded be all they that serve graven images, that boast themselves of idols: worship him, all ye gods."},"BSB":{"text":"All worshipers of images are put to shame— those who boast in idols. Worship Him, all you gods!"}},"definableWords":["worship"],"peopleInVerse":[]},"8":{"text":"Zion heard, and was glad; and the daughters of Judah rejoiced because of thy judgments, O LORD.","ref":"Psalms 97:8","synthesized":"Zion hears and rejoices, and the towns of Judah exult because of Your judgments, O LORD.","sources":{"KJV":{"text":"Zion heard, and was glad; and the daughters of Judah rejoiced because of thy judgments, O LORD."},"BSB":{"text":"Zion hears and rejoices, and the towns of Judah exult because of Your judgments, O LORD."}},"definableWords":["Zion","Judah","LORD"],"peopleInVerse":[]},"9":{"text":"For thou, LORD, art high above all the earth: thou art exalted far above all gods.","ref":"Psalms 97:9","synthesized":"For You, O LORD, are Most High over all the earth; You are exalted far above all gods.","sources":{"KJV":{"text":"For thou, LORD, art high above all the earth: thou art exalted far above all gods."},"BSB":{"text":"For You, O LORD, are Most High over all the earth; You are exalted far above all gods."}},"definableWords":["LORD","earth"],"peopleInVerse":[]},"10":{"text":"Ye that love the LORD, hate evil: he preserveth the souls of his saints; he delivereth them out of the hand of the wicked.","ref":"Psalms 97:10","synthesized":"Hate evil, O you who love the LORD! He preserves the souls of His saints; He delivers them from the hand of the wicked.","sources":{"KJV":{"text":"Ye that love the LORD, hate evil: he preserveth the souls of his saints; he delivereth them out of the hand of the wicked."},"BSB":{"text":"Hate evil, O you who love the LORD! He preserves the souls of His saints; He delivers them from the hand of the wicked."}},"definableWords":["evil","love","LORD"],"peopleInVerse":[]},"11":{"text":"Light is sown for the righteous, and gladness for the upright in heart.","ref":"Psalms 97:11","synthesized":"Light shines on the righteous, gladness on the upright in heart.","sources":{"KJV":{"text":"Light is sown for the righteous, and gladness for the upright in heart."},"BSB":{"text":"Light shines on the righteous, gladness on the upright in heart."}},"definableWords":["light","righteous","heart"],"peopleInVerse":[]},"12":{"text":"Rejoice in the LORD, ye righteous; and give thanks at the remembrance of his holiness.","ref":"Psalms 97:12","synthesized":"Rejoice in the LORD, you righteous ones, and praise His holy name.","sources":{"KJV":{"text":"Rejoice in the LORD, ye righteous; and give thanks at the remembrance of his holiness."},"BSB":{"text":"Rejoice in the LORD, you righteous ones, and praise His holy name."}},"definableWords":["LORD","righteous","praise","holy","name"],"peopleInVerse":[]}}},"98":{"chapter":"98","title":"SING UNTO THE LORD A NEW SONG (II)","verses":{"1":{"text":"O sing unto the LORD a new song; for he hath done marvellous things: his right hand, and his holy arm, hath gotten him the victory.","ref":"Psalms 98:1","synthesized":"Sing to the LORD a new song, for He has done wonders; His right hand and holy arm have gained Him the victory.","sources":{"KJV":{"text":"O sing unto the LORD a new song; for he hath done marvellous things: his right hand, and his holy arm, hath gotten him the victory."},"BSB":{"text":"Sing to the LORD a new song, for He has done wonders; His right hand and holy arm have gained Him the victory."}},"definableWords":["LORD","holy"],"peopleInVerse":[]},"2":{"text":"The LORD hath made known his salvation: his righteousness hath he openly shewed in the sight of the heathen.","ref":"Psalms 98:2","synthesized":"The LORD has proclaimed His salvation and revealed His righteousness to the nations.","sources":{"KJV":{"text":"The LORD hath made known his salvation: his righteousness hath he openly shewed in the sight of the heathen."},"BSB":{"text":"The LORD has proclaimed His salvation and revealed His righteousness to the nations."}},"definableWords":["LORD","salvation","righteousness","nations"],"peopleInVerse":[]},"3":{"text":"He hath remembered his mercy and his truth toward the house of Israel: all the ends of the earth have seen the salvation of our God.","ref":"Psalms 98:3","synthesized":"He has remembered His love and faithfulness to the house of Israel; all the ends of the earth have seen the salvation of our God.","sources":{"KJV":{"text":"He hath remembered his mercy and his truth toward the house of Israel: all the ends of the earth have seen the salvation of our God."},"BSB":{"text":"He has remembered His love and faithfulness to the house of Israel; all the ends of the earth have seen the salvation of our God."}},"definableWords":["remembered","love","house","Israel","earth","salvation","God"],"peopleInVerse":[]},"4":{"text":"Make a joyful noise unto the LORD, all the earth: make a loud noise, and rejoice, and sing praise.","ref":"Psalms 98:4","synthesized":"Make a joyful noise to the LORD, all the earth; break forth—let your cry ring out, and sing praises!","sources":{"KJV":{"text":"Make a joyful noise unto the LORD, all the earth: make a loud noise, and rejoice, and sing praise."},"BSB":{"text":"Make a joyful noise to the LORD, all the earth; break forth—let your cry ring out, and sing praises!"}},"definableWords":["make","LORD","earth"],"peopleInVerse":[]},"5":{"text":"Sing unto the LORD with the harp; with the harp, and the voice of a psalm.","ref":"Psalms 98:5","synthesized":"Sing praises to the LORD with the lyre, in melodious song with the harp.","sources":{"KJV":{"text":"Sing unto the LORD with the harp; with the harp, and the voice of a psalm."},"BSB":{"text":"Sing praises to the LORD with the lyre, in melodious song with the harp."}},"definableWords":["LORD"],"peopleInVerse":[]},"6":{"text":"With trumpets and sound of cornet make a joyful noise before the LORD, the King.","ref":"Psalms 98:6","synthesized":"With trumpets and the blast of the ram’s horn shout for joy before the LORD, the King.","sources":{"KJV":{"text":"With trumpets and sound of cornet make a joyful noise before the LORD, the King."},"BSB":{"text":"With trumpets and the blast of the ram’s horn shout for joy before the LORD, the King."}},"definableWords":["joy","LORD","King"],"peopleInVerse":[]},"7":{"text":"Let the sea roar, and the fulness thereof; the world, and they that dwell therein.","ref":"Psalms 98:7","synthesized":"Let the sea resound, and all that fills it, the world, and all who dwell in it.","sources":{"KJV":{"text":"Let the sea roar, and the fulness thereof; the world, and they that dwell therein."},"BSB":{"text":"Let the sea resound, and all that fills it, the world, and all who dwell in it."}},"definableWords":["sea"],"peopleInVerse":[]},"8":{"text":"Let the floods clap their hands: let the hills be joyful together","ref":"Psalms 98:8","synthesized":"Let the rivers clap their hands, let the mountains sing together for joy","sources":{"KJV":{"text":"Let the floods clap their hands: let the hills be joyful together"},"BSB":{"text":"Let the rivers clap their hands, let the mountains sing together for joy"}},"definableWords":["joy"],"peopleInVerse":[]},"9":{"text":"Before the LORD; for he cometh to judge the earth: with righteousness shall he judge the world, and the people with equity.","ref":"Psalms 98:9","synthesized":"before the LORD, for He comes to judge the earth. He will judge the world with righteousness and the peoples with equity.","sources":{"KJV":{"text":"Before the LORD; for he cometh to judge the earth: with righteousness shall he judge the world, and the people with equity."},"BSB":{"text":"before the LORD, for He comes to judge the earth. He will judge the world with righteousness and the peoples with equity."}},"definableWords":["LORD","earth","righteousness"],"peopleInVerse":[]}}},"99":{"chapter":"99","title":"THE LORD REIGNETH — LET THE PEOPLE TREMBLE","verses":{"1":{"text":"The LORD reigneth; let the people tremble: he sitteth between the cherubims; let the earth be moved.","ref":"Psalms 99:1","synthesized":"The LORD reigns; let the nations tremble! He is enthroned above the cherubim; let the earth quake!","sources":{"KJV":{"text":"The LORD reigneth; let the people tremble: he sitteth between the cherubims; let the earth be moved."},"BSB":{"text":"The LORD reigns; let the nations tremble! He is enthroned above the cherubim; let the earth quake!"}},"definableWords":["LORD","nations","earth"],"peopleInVerse":[]},"2":{"text":"The LORD is great in Zion; and he is high above all the people.","ref":"Psalms 99:2","synthesized":"Great is the LORD in Zion; He is exalted above all the peoples.","sources":{"KJV":{"text":"The LORD is great in Zion; and he is high above all the people."},"BSB":{"text":"Great is the LORD in Zion; He is exalted above all the peoples."}},"definableWords":["great","LORD","Zion"],"peopleInVerse":[]},"3":{"text":"Let them praise thy great and terrible name; for it is holy.","ref":"Psalms 99:3","synthesized":"Let them praise Your great and awesome name— He is holy!","sources":{"KJV":{"text":"Let them praise thy great and terrible name; for it is holy."},"BSB":{"text":"Let them praise Your great and awesome name— He is holy!"}},"definableWords":["praise","great","name","holy"],"peopleInVerse":[]},"4":{"text":"The king’s strength also loveth judgment; thou dost establish equity, thou executest judgment and righteousness in Jacob.","ref":"Psalms 99:4","synthesized":"The mighty King loves justice. You have established equity; You have exercised justice and righteousness in Jacob.","sources":{"KJV":{"text":"The king’s strength also loveth judgment; thou dost establish equity, thou executest judgment and righteousness in Jacob."},"BSB":{"text":"The mighty King loves justice. You have established equity; You have exercised justice and righteousness in Jacob."}},"definableWords":["mighty","King","justice","righteousness","Jacob"],"peopleInVerse":["Jacob"]},"5":{"text":"Exalt ye the LORD our God, and worship at his footstool; for he is holy.","ref":"Psalms 99:5","synthesized":"Exalt the LORD our God, and worship at His footstool; He is holy!","sources":{"KJV":{"text":"Exalt ye the LORD our God, and worship at his footstool; for he is holy."},"BSB":{"text":"Exalt the LORD our God, and worship at His footstool; He is holy!"}},"definableWords":["LORD","God","worship","holy"],"peopleInVerse":[]},"6":{"text":"Moses and Aaron among his priests, and Samuel among them that call upon his name; they called upon the LORD, and he answered them.","ref":"Psalms 99:6","synthesized":"Moses and Aaron were among His priests; Samuel was among those who called on His name. They called to the LORD and He answered.","sources":{"KJV":{"text":"Moses and Aaron among his priests, and Samuel among them that call upon his name; they called upon the LORD, and he answered them."},"BSB":{"text":"Moses and Aaron were among His priests; Samuel was among those who called on His name. They called to the LORD and He answered."}},"definableWords":["name","LORD"],"peopleInVerse":["Moses","Aaron","Samuel"]},"7":{"text":"He spake unto them in the cloudy pillar: they kept his testimonies, and the ordinance that he gave them.","ref":"Psalms 99:7","synthesized":"He spoke to them from the pillar of cloud; they kept His decrees and the statutes He gave them.","sources":{"KJV":{"text":"He spake unto them in the cloudy pillar: they kept his testimonies, and the ordinance that he gave them."},"BSB":{"text":"He spoke to them from the pillar of cloud; they kept His decrees and the statutes He gave them."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Thou answeredst them, O LORD our God: thou wast a God that forgavest them, though thou tookest vengeance of their inventions.","ref":"Psalms 99:8","synthesized":"O LORD our God, You answered them. You were a forgiving God to them, yet an avenger of their misdeeds.","sources":{"KJV":{"text":"Thou answeredst them, O LORD our God: thou wast a God that forgavest them, though thou tookest vengeance of their inventions."},"BSB":{"text":"O LORD our God, You answered them. You were a forgiving God to them, yet an avenger of their misdeeds."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"9":{"text":"Exalt the LORD our God, and worship at his holy hill; for the LORD our God is holy.","ref":"Psalms 99:9","synthesized":"Exalt the LORD our God and worship at His holy mountain, for the LORD our God is holy.","sources":{"KJV":{"text":"Exalt the LORD our God, and worship at his holy hill; for the LORD our God is holy."},"BSB":{"text":"Exalt the LORD our God and worship at His holy mountain, for the LORD our God is holy."}},"definableWords":["LORD","God","worship","holy","Lord"],"peopleInVerse":[]}}},"100":{"chapter":"100","title":"MAKE A JOYFUL NOISE","verses":{"1":{"text":"Make a joyful noise unto the LORD, all ye lands.","ref":"Psalms 100:1","synthesized":"Make a joyful noise to the LORD, all the earth.","sources":{"KJV":{"text":"Make a joyful noise unto the LORD, all ye lands."},"BSB":{"text":"Make a joyful noise to the LORD, all the earth."}},"definableWords":["make","LORD","earth"],"peopleInVerse":[]},"2":{"text":"Serve the LORD with gladness: come before his presence with singing.","ref":"Psalms 100:2","synthesized":"Serve the LORD with gladness; come into His presence with joyful songs.","sources":{"KJV":{"text":"Serve the LORD with gladness: come before his presence with singing."},"BSB":{"text":"Serve the LORD with gladness; come into His presence with joyful songs."}},"definableWords":["LORD"],"peopleInVerse":[]},"3":{"text":"Know ye that the LORD he is God: it is he that hath made us, and not we ourselves; we are his people, and the sheep of his pasture.","ref":"Psalms 100:3","synthesized":"Know that the LORD is God. It is He who made us, and we are His; we are His people, and the sheep of His pasture.","sources":{"KJV":{"text":"Know ye that the LORD he is God: it is he that hath made us, and not we ourselves; we are his people, and the sheep of his pasture."},"BSB":{"text":"Know that the LORD is God. It is He who made us, and we are His; we are His people, and the sheep of His pasture."}},"definableWords":["LORD","God","made","people"],"peopleInVerse":[]},"4":{"text":"Enter into his gates with thanksgiving, and into his courts with praise: be thankful unto him, and bless his name.","ref":"Psalms 100:4","synthesized":"Enter His gates with thanksgiving and His courts with praise; give thanks to Him and bless His name.","sources":{"KJV":{"text":"Enter into his gates with thanksgiving, and into his courts with praise: be thankful unto him, and bless his name."},"BSB":{"text":"Enter His gates with thanksgiving and His courts with praise; give thanks to Him and bless His name."}},"definableWords":["praise","bless","name"],"peopleInVerse":[]},"5":{"text":"For the LORD is good; his mercy is everlasting; and his truth endureth to all generations.","ref":"Psalms 100:5","synthesized":"For the LORD is good, and His loving devotion endures forever; His faithfulness continues to all generations.","sources":{"KJV":{"text":"For the LORD is good; his mercy is everlasting; and his truth endureth to all generations."},"BSB":{"text":"For the LORD is good, and His loving devotion endures forever; His faithfulness continues to all generations."}},"definableWords":["LORD","good"],"peopleInVerse":[]}}},"101":{"chapter":"101","title":"I WILL SING OF MERCY AND JUDGMENT","verses":{"1":{"text":"I will sing of mercy and judgment: unto thee, O LORD, will I sing.","ref":"Psalms 101:1","synthesized":"I will sing of Your loving devotion and justice; to You, O LORD, I will sing praises.","sources":{"KJV":{"text":"I will sing of mercy and judgment: unto thee, O LORD, will I sing."},"BSB":{"text":"I will sing of Your loving devotion and justice; to You, O LORD, I will sing praises."}},"definableWords":["justice","LORD"],"peopleInVerse":[]},"2":{"text":"I will behave myself wisely in a perfect way. O when wilt thou come unto me? I will walk within my house with a perfect heart.","ref":"Psalms 101:2","synthesized":"I will ponder the way that is blameless— when will You come to me? I will walk in my house with integrity of heart.","sources":{"KJV":{"text":"I will behave myself wisely in a perfect way. O when wilt thou come unto me? I will walk within my house with a perfect heart."},"BSB":{"text":"I will ponder the way that is blameless— when will You come to me? I will walk in my house with integrity of heart."}},"definableWords":["way","walk","house","heart"],"peopleInVerse":[]},"3":{"text":"I will set no wicked thing before mine eyes: I hate the work of them that turn aside; it shall not cleave to me.","ref":"Psalms 101:3","synthesized":"I will set no worthless thing before my eyes. I hate the work of those who fall away; it shall not cling to me.","sources":{"KJV":{"text":"I will set no wicked thing before mine eyes: I hate the work of them that turn aside; it shall not cleave to me."},"BSB":{"text":"I will set no worthless thing before my eyes. I hate the work of those who fall away; it shall not cling to me."}},"definableWords":["work"],"peopleInVerse":[]},"4":{"text":"A froward heart shall depart from me: I will not know a wicked person.","ref":"Psalms 101:4","synthesized":"A perverse heart shall depart from me; I will know nothing of evil.","sources":{"KJV":{"text":"A froward heart shall depart from me: I will not know a wicked person."},"BSB":{"text":"A perverse heart shall depart from me; I will know nothing of evil."}},"definableWords":["heart","evil"],"peopleInVerse":[]},"5":{"text":"Whoso privily slandereth his neighbour, him will I cut off: him that hath an high look and a proud heart will not I suffer.","ref":"Psalms 101:5","synthesized":"Whoever slanders his neighbor in secret, I will put to silence; the one with haughty eyes and a proud heart, I will not endure.","sources":{"KJV":{"text":"Whoso privily slandereth his neighbour, him will I cut off: him that hath an high look and a proud heart will not I suffer."},"BSB":{"text":"Whoever slanders his neighbor in secret, I will put to silence; the one with haughty eyes and a proud heart, I will not endure."}},"definableWords":["one","heart"],"peopleInVerse":[]},"6":{"text":"Mine eyes shall be upon the faithful of the land, that they may dwell with me: he that walketh in a perfect way, he shall serve me.","ref":"Psalms 101:6","synthesized":"My eyes favor the faithful of the land, that they may dwell with me; he who walks in the way of integrity shall minister to me.","sources":{"KJV":{"text":"Mine eyes shall be upon the faithful of the land, that they may dwell with me: he that walketh in a perfect way, he shall serve me."},"BSB":{"text":"My eyes favor the faithful of the land, that they may dwell with me; he who walks in the way of integrity shall minister to me."}},"definableWords":["land","way"],"peopleInVerse":[]},"7":{"text":"He that worketh deceit shall not dwell within my house: he that telleth lies shall not tarry in my sight.","ref":"Psalms 101:7","synthesized":"No one who practices deceit shall dwell in my house; no one who tells lies shall stand in my presence.","sources":{"KJV":{"text":"He that worketh deceit shall not dwell within my house: he that telleth lies shall not tarry in my sight."},"BSB":{"text":"No one who practices deceit shall dwell in my house; no one who tells lies shall stand in my presence."}},"definableWords":["one","house","stand"],"peopleInVerse":[]},"8":{"text":"I will early destroy all the wicked of the land; that I may cut off all wicked doers from the city of the LORD.","ref":"Psalms 101:8","synthesized":"Every morning I will remove all the wicked of the land, that I may cut off every evildoer from the city of the LORD.","sources":{"KJV":{"text":"I will early destroy all the wicked of the land; that I may cut off all wicked doers from the city of the LORD."},"BSB":{"text":"Every morning I will remove all the wicked of the land, that I may cut off every evildoer from the city of the LORD."}},"definableWords":["land","LORD"],"peopleInVerse":[]}}},"102":{"chapter":"102","title":"HEAR MY PRAYER, O LORD","verses":{"1":{"text":"Hear my prayer, O LORD, and let my cry come unto thee.","ref":"Psalms 102:1","synthesized":"Hear my prayer, O LORD; let my cry for help come before You.","sources":{"KJV":{"text":"Hear my prayer, O LORD, and let my cry come unto thee."},"BSB":{"text":"Hear my prayer, O LORD; let my cry for help come before You."}},"definableWords":["hear","prayer","LORD"],"peopleInVerse":[]},"2":{"text":"Hide not thy face from me in the day when I am in trouble; incline thine ear unto me: in the day when I call answer me speedily.","ref":"Psalms 102:2","synthesized":"Do not hide Your face from me in my day of distress. Incline Your ear to me; answer me quickly when I call.","sources":{"KJV":{"text":"Hide not thy face from me in the day when I am in trouble; incline thine ear unto me: in the day when I call answer me speedily."},"BSB":{"text":"Do not hide Your face from me in my day of distress. Incline Your ear to me; answer me quickly when I call."}},"definableWords":["day"],"peopleInVerse":[]},"3":{"text":"For my days are consumed like smoke, and my bones are burned as an hearth.","ref":"Psalms 102:3","synthesized":"For my days vanish like smoke, and my bones burn like glowing embers.","sources":{"KJV":{"text":"For my days are consumed like smoke, and my bones are burned as an hearth."},"BSB":{"text":"For my days vanish like smoke, and my bones burn like glowing embers."}},"definableWords":["days","bones"],"peopleInVerse":[]},"4":{"text":"My heart is smitten, and withered like grass; so that I forget to eat my bread.","ref":"Psalms 102:4","synthesized":"My heart is afflicted, and withered like grass; I even forget to eat my bread.","sources":{"KJV":{"text":"My heart is smitten, and withered like grass; so that I forget to eat my bread."},"BSB":{"text":"My heart is afflicted, and withered like grass; I even forget to eat my bread."}},"definableWords":["heart"],"peopleInVerse":[]},"5":{"text":"By reason of the voice of my groaning my bones cleave to my skin.","ref":"Psalms 102:5","synthesized":"Through my loud groaning my flesh clings to my bones.","sources":{"KJV":{"text":"By reason of the voice of my groaning my bones cleave to my skin."},"BSB":{"text":"Through my loud groaning my flesh clings to my bones."}},"definableWords":["flesh","bones"],"peopleInVerse":[]},"6":{"text":"I am like a pelican of the wilderness: I am like an owl of the desert.","ref":"Psalms 102:6","synthesized":"I am like a desert owl, like an owl among the ruins.","sources":{"KJV":{"text":"I am like a pelican of the wilderness: I am like an owl of the desert."},"BSB":{"text":"I am like a desert owl, like an owl among the ruins."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"I watch, and am as a sparrow alone upon the house top.","ref":"Psalms 102:7","synthesized":"I lie awake; I am like a lone bird on a housetop.","sources":{"KJV":{"text":"I watch, and am as a sparrow alone upon the house top."},"BSB":{"text":"I lie awake; I am like a lone bird on a housetop."}},"definableWords":["bird"],"peopleInVerse":[]},"8":{"text":"Mine enemies reproach me all the day; and they that are mad against me are sworn against me.","ref":"Psalms 102:8","synthesized":"All day long my enemies taunt me; they ridicule me and curse me.","sources":{"KJV":{"text":"Mine enemies reproach me all the day; and they that are mad against me are sworn against me."},"BSB":{"text":"All day long my enemies taunt me; they ridicule me and curse me."}},"definableWords":["day","curse"],"peopleInVerse":[]},"9":{"text":"For I have eaten ashes like bread, and mingled my drink with weeping,","ref":"Psalms 102:9","synthesized":"For I have eaten ashes like bread and mixed my drink with tears","sources":{"KJV":{"text":"For I have eaten ashes like bread, and mingled my drink with weeping,"},"BSB":{"text":"For I have eaten ashes like bread and mixed my drink with tears"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Because of thine indignation and thy wrath: for thou hast lifted me up, and cast me down.","ref":"Psalms 102:10","synthesized":"because of Your indignation and wrath, for You have picked me up and cast me aside.","sources":{"KJV":{"text":"Because of thine indignation and thy wrath: for thou hast lifted me up, and cast me down."},"BSB":{"text":"because of Your indignation and wrath, for You have picked me up and cast me aside."}},"definableWords":["wrath"],"peopleInVerse":[]},"11":{"text":"My days are like a shadow that declineth; and I am withered like grass.","ref":"Psalms 102:11","synthesized":"My days are like lengthening shadows, and I wither away like grass.","sources":{"KJV":{"text":"My days are like a shadow that declineth; and I am withered like grass."},"BSB":{"text":"My days are like lengthening shadows, and I wither away like grass."}},"definableWords":["days"],"peopleInVerse":[]},"12":{"text":"But thou, O LORD, shalt endure for ever; and thy remembrance unto all generations.","ref":"Psalms 102:12","synthesized":"But You, O LORD, sit enthroned forever; Your renown endures to all generations.","sources":{"KJV":{"text":"But thou, O LORD, shalt endure for ever; and thy remembrance unto all generations."},"BSB":{"text":"But You, O LORD, sit enthroned forever; Your renown endures to all generations."}},"definableWords":["LORD"],"peopleInVerse":[]},"13":{"text":"Thou shalt arise, and have mercy upon Zion: for the time to favour her, yea, the set time, is come.","ref":"Psalms 102:13","synthesized":"You will rise up and have compassion on Zion, for it is time to show her favor— the appointed time has come.","sources":{"KJV":{"text":"Thou shalt arise, and have mercy upon Zion: for the time to favour her, yea, the set time, is come."},"BSB":{"text":"You will rise up and have compassion on Zion, for it is time to show her favor— the appointed time has come."}},"definableWords":["Zion"],"peopleInVerse":[]},"14":{"text":"For thy servants take pleasure in her stones, and favour the dust thereof.","ref":"Psalms 102:14","synthesized":"For Your servants delight in her stones and take pity on her dust.","sources":{"KJV":{"text":"For thy servants take pleasure in her stones, and favour the dust thereof."},"BSB":{"text":"For Your servants delight in her stones and take pity on her dust."}},"definableWords":["servants"],"peopleInVerse":[]},"15":{"text":"So the heathen shall fear the name of the LORD, and all the kings of the earth thy glory.","ref":"Psalms 102:15","synthesized":"So the nations will fear the name of the LORD, and all the kings of the earth will fear Your glory.","sources":{"KJV":{"text":"So the heathen shall fear the name of the LORD, and all the kings of the earth thy glory."},"BSB":{"text":"So the nations will fear the name of the LORD, and all the kings of the earth will fear Your glory."}},"definableWords":["nations","fear","name","LORD","kings","earth","glory"],"peopleInVerse":[]},"16":{"text":"When the LORD shall build up Zion, he shall appear in his glory.","ref":"Psalms 102:16","synthesized":"For the LORD will rebuild Zion; He has appeared in His glory.","sources":{"KJV":{"text":"When the LORD shall build up Zion, he shall appear in his glory."},"BSB":{"text":"For the LORD will rebuild Zion; He has appeared in His glory."}},"definableWords":["LORD","Zion","glory"],"peopleInVerse":[]},"17":{"text":"He will regard the prayer of the destitute, and not despise their prayer.","ref":"Psalms 102:17","synthesized":"He will turn toward the prayer of the destitute; He will not despise their prayer.","sources":{"KJV":{"text":"He will regard the prayer of the destitute, and not despise their prayer."},"BSB":{"text":"He will turn toward the prayer of the destitute; He will not despise their prayer."}},"definableWords":["prayer"],"peopleInVerse":[]},"18":{"text":"This shall be written for the generation to come: and the people which shall be created shall praise the LORD.","ref":"Psalms 102:18","synthesized":"Let this be written for the generation to come, so that a people not yet created may praise the LORD.","sources":{"KJV":{"text":"This shall be written for the generation to come: and the people which shall be created shall praise the LORD."},"BSB":{"text":"Let this be written for the generation to come, so that a people not yet created may praise the LORD."}},"definableWords":["people","created","praise","LORD"],"peopleInVerse":[]},"19":{"text":"For he hath looked down from the height of his sanctuary; from heaven did the LORD behold the earth;","ref":"Psalms 102:19","synthesized":"For He looked down from the heights of His sanctuary; the LORD gazed out from heaven to earth","sources":{"KJV":{"text":"For he hath looked down from the height of his sanctuary; from heaven did the LORD behold the earth;"},"BSB":{"text":"For He looked down from the heights of His sanctuary; the LORD gazed out from heaven to earth"}},"definableWords":["LORD","heaven","earth"],"peopleInVerse":[]},"20":{"text":"To hear the groaning of the prisoner; to loose those that are appointed to death;","ref":"Psalms 102:20","synthesized":"to hear a prisoner’s groaning, to release those condemned to death,","sources":{"KJV":{"text":"To hear the groaning of the prisoner; to loose those that are appointed to death;"},"BSB":{"text":"to hear a prisoner’s groaning, to release those condemned to death,"}},"definableWords":["hear","death"],"peopleInVerse":[]},"21":{"text":"To declare the name of the LORD in Zion, and his praise in Jerusalem;","ref":"Psalms 102:21","synthesized":"that they may proclaim the name of the LORD in Zion and praise Him in Jerusalem,","sources":{"KJV":{"text":"To declare the name of the LORD in Zion, and his praise in Jerusalem;"},"BSB":{"text":"that they may proclaim the name of the LORD in Zion and praise Him in Jerusalem,"}},"definableWords":["name","LORD","Zion","praise","Jerusalem"],"peopleInVerse":[]},"22":{"text":"When the people are gathered together, and the kingdoms, to serve the LORD.","ref":"Psalms 102:22","synthesized":"when peoples and kingdoms assemble to serve the LORD.","sources":{"KJV":{"text":"When the people are gathered together, and the kingdoms, to serve the LORD."},"BSB":{"text":"when peoples and kingdoms assemble to serve the LORD."}},"definableWords":["LORD"],"peopleInVerse":[]},"23":{"text":"He weakened my strength in the way; he shortened my days.","ref":"Psalms 102:23","synthesized":"He has broken my strength on the way; He has cut short my days.","sources":{"KJV":{"text":"He weakened my strength in the way; he shortened my days."},"BSB":{"text":"He has broken my strength on the way; He has cut short my days."}},"definableWords":["way","days"],"peopleInVerse":[]},"24":{"text":"I said, O my God, take me not away in the midst of my days: thy years are throughout all generations.","ref":"Psalms 102:24","synthesized":"I say: “O my God, do not take me in the midst of my days! Your years go on through all generations.","sources":{"KJV":{"text":"I said, O my God, take me not away in the midst of my days: thy years are throughout all generations."},"BSB":{"text":"I say: “O my God, do not take me in the midst of my days! Your years go on through all generations."}},"definableWords":["God","days","years"],"peopleInVerse":[]},"25":{"text":"Of old hast thou laid the foundation of the earth: and the heavens are the work of thy hands.","ref":"Psalms 102:25","synthesized":"In the beginning You laid the foundations of the earth, and the heavens are the work of Your hands.","sources":{"KJV":{"text":"Of old hast thou laid the foundation of the earth: and the heavens are the work of thy hands."},"BSB":{"text":"In the beginning You laid the foundations of the earth, and the heavens are the work of Your hands."}},"definableWords":["beginning","earth","heavens","work"],"peopleInVerse":[]},"26":{"text":"They shall perish, but thou shalt endure: yea, all of them shall wax old like a garment; as a vesture shalt thou change them, and they shall be changed:","ref":"Psalms 102:26","synthesized":"They will perish, but You remain; they will all wear out like a garment. Like clothing You will change them, and they will be passed on.","sources":{"KJV":{"text":"They shall perish, but thou shalt endure: yea, all of them shall wax old like a garment; as a vesture shalt thou change them, and they shall be changed:"},"BSB":{"text":"They will perish, but You remain; they will all wear out like a garment. Like clothing You will change them, and they will be passed on."}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"But thou art the same, and thy years shall have no end.","ref":"Psalms 102:27","synthesized":"But You remain the same, and Your years will never end.","sources":{"KJV":{"text":"But thou art the same, and thy years shall have no end."},"BSB":{"text":"But You remain the same, and Your years will never end."}},"definableWords":["years"],"peopleInVerse":[]},"28":{"text":"The children of thy servants shall continue, and their seed shall be established before thee.","ref":"Psalms 102:28","synthesized":"The children of Your servants will dwell securely, and their descendants will be established before You.”","sources":{"KJV":{"text":"The children of thy servants shall continue, and their seed shall be established before thee."},"BSB":{"text":"The children of Your servants will dwell securely, and their descendants will be established before You.”"}},"definableWords":["servants"],"peopleInVerse":[]}}},"103":{"chapter":"103","title":"BLESS THE LORD, O MY SOUL","verses":{"1":{"text":"Bless the LORD, O my soul: and all that is within me, bless his holy name.","ref":"Psalms 103:1","synthesized":"Bless the LORD, O my soul; all that is within me, bless His holy name.","sources":{"KJV":{"text":"Bless the LORD, O my soul: and all that is within me, bless his holy name."},"BSB":{"text":"Bless the LORD, O my soul; all that is within me, bless His holy name."}},"definableWords":["bless","LORD","soul","holy","name"],"peopleInVerse":[]},"2":{"text":"Bless the LORD, O my soul, and forget not all his benefits:","ref":"Psalms 103:2","synthesized":"Bless the LORD, O my soul, and do not forget all His kind deeds—","sources":{"KJV":{"text":"Bless the LORD, O my soul, and forget not all his benefits:"},"BSB":{"text":"Bless the LORD, O my soul, and do not forget all His kind deeds—"}},"definableWords":["bless","LORD","soul"],"peopleInVerse":[]},"3":{"text":"Who forgiveth all thine iniquities; who healeth all thy diseases;","ref":"Psalms 103:3","synthesized":"He who forgives all your iniquities and heals all your diseases,","sources":{"KJV":{"text":"Who forgiveth all thine iniquities; who healeth all thy diseases;"},"BSB":{"text":"He who forgives all your iniquities and heals all your diseases,"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Who redeemeth thy life from destruction; who crowneth thee with lovingkindness and tender mercies;","ref":"Psalms 103:4","synthesized":"who redeems your life from the Pit and crowns you with loving devotion and compassion,","sources":{"KJV":{"text":"Who redeemeth thy life from destruction; who crowneth thee with lovingkindness and tender mercies;"},"BSB":{"text":"who redeems your life from the Pit and crowns you with loving devotion and compassion,"}},"definableWords":["life"],"peopleInVerse":[]},"5":{"text":"Who satisfieth thy mouth with good things; so that thy youth is renewed like the eagle’s.","ref":"Psalms 103:5","synthesized":"who satisfies you with good things, so that your youth is renewed like the eagle’s.","sources":{"KJV":{"text":"Who satisfieth thy mouth with good things; so that thy youth is renewed like the eagle’s."},"BSB":{"text":"who satisfies you with good things, so that your youth is renewed like the eagle’s."}},"definableWords":["good"],"peopleInVerse":[]},"6":{"text":"The LORD executeth righteousness and judgment for all that are oppressed.","ref":"Psalms 103:6","synthesized":"The LORD executes righteousness and justice for all the oppressed.","sources":{"KJV":{"text":"The LORD executeth righteousness and judgment for all that are oppressed."},"BSB":{"text":"The LORD executes righteousness and justice for all the oppressed."}},"definableWords":["LORD","righteousness","justice"],"peopleInVerse":[]},"7":{"text":"He made known his ways unto Moses, his acts unto the children of Israel.","ref":"Psalms 103:7","synthesized":"He made known His ways to Moses, His deeds to the people of Israel.","sources":{"KJV":{"text":"He made known his ways unto Moses, his acts unto the children of Israel."},"BSB":{"text":"He made known His ways to Moses, His deeds to the people of Israel."}},"definableWords":["made","people","Israel"],"peopleInVerse":["Moses"]},"8":{"text":"The LORD is merciful and gracious, slow to anger, and plenteous in mercy.","ref":"Psalms 103:8","synthesized":"The LORD is compassionate and gracious, slow to anger, abounding in loving devotion.","sources":{"KJV":{"text":"The LORD is merciful and gracious, slow to anger, and plenteous in mercy."},"BSB":{"text":"The LORD is compassionate and gracious, slow to anger, abounding in loving devotion."}},"definableWords":["LORD","anger"],"peopleInVerse":[]},"9":{"text":"He will not always chide: neither will he keep his anger for ever.","ref":"Psalms 103:9","synthesized":"He will not always accuse us, nor harbor His anger forever.","sources":{"KJV":{"text":"He will not always chide: neither will he keep his anger for ever."},"BSB":{"text":"He will not always accuse us, nor harbor His anger forever."}},"definableWords":["anger"],"peopleInVerse":[]},"10":{"text":"He hath not dealt with us after our sins; nor rewarded us according to our iniquities.","ref":"Psalms 103:10","synthesized":"He has not dealt with us according to our sins or repaid us according to our iniquities.","sources":{"KJV":{"text":"He hath not dealt with us after our sins; nor rewarded us according to our iniquities."},"BSB":{"text":"He has not dealt with us according to our sins or repaid us according to our iniquities."}},"definableWords":["or"],"peopleInVerse":[]},"11":{"text":"For as the heaven is high above the earth, so great is his mercy toward them that fear him.","ref":"Psalms 103:11","synthesized":"For as high as the heavens are above the earth, so great is His loving devotion for those who fear Him.","sources":{"KJV":{"text":"For as the heaven is high above the earth, so great is his mercy toward them that fear him."},"BSB":{"text":"For as high as the heavens are above the earth, so great is His loving devotion for those who fear Him."}},"definableWords":["heavens","earth","great","fear"],"peopleInVerse":[]},"12":{"text":"As far as the east is from the west, so far hath he removed our transgressions from us.","ref":"Psalms 103:12","synthesized":"As far as the east is from the west, so far has He removed our transgressions from us.","sources":{"KJV":{"text":"As far as the east is from the west, so far hath he removed our transgressions from us."},"BSB":{"text":"As far as the east is from the west, so far has He removed our transgressions from us."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Like as a father pitieth his children, so the LORD pitieth them that fear him.","ref":"Psalms 103:13","synthesized":"As a father has compassion on his children, so the LORD has compassion on those who fear Him.","sources":{"KJV":{"text":"Like as a father pitieth his children, so the LORD pitieth them that fear him."},"BSB":{"text":"As a father has compassion on his children, so the LORD has compassion on those who fear Him."}},"definableWords":["father","LORD","fear"],"peopleInVerse":[]},"14":{"text":"For he knoweth our frame; he remembereth that we are dust.","ref":"Psalms 103:14","synthesized":"For He knows our frame; He is mindful that we are dust.","sources":{"KJV":{"text":"For he knoweth our frame; he remembereth that we are dust."},"BSB":{"text":"For He knows our frame; He is mindful that we are dust."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"As for man, his days are as grass: as a flower of the field, so he flourisheth.","ref":"Psalms 103:15","synthesized":"As for man, his days are like grass— he blooms like a flower of the field;","sources":{"KJV":{"text":"As for man, his days are as grass: as a flower of the field, so he flourisheth."},"BSB":{"text":"As for man, his days are like grass— he blooms like a flower of the field;"}},"definableWords":["man","days","field"],"peopleInVerse":[]},"16":{"text":"For the wind passeth over it, and it is gone; and the place thereof shall know it no more.","ref":"Psalms 103:16","synthesized":"when the wind passes over, it vanishes, and its place remembers it no more.","sources":{"KJV":{"text":"For the wind passeth over it, and it is gone; and the place thereof shall know it no more."},"BSB":{"text":"when the wind passes over, it vanishes, and its place remembers it no more."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"But the mercy of the LORD is from everlasting to everlasting upon them that fear him, and his righteousness unto children’s children;","ref":"Psalms 103:17","synthesized":"But from everlasting to everlasting the loving devotion of the LORD extends to those who fear Him, and His righteousness to their children’s children—","sources":{"KJV":{"text":"But the mercy of the LORD is from everlasting to everlasting upon them that fear him, and his righteousness unto children’s children;"},"BSB":{"text":"But from everlasting to everlasting the loving devotion of the LORD extends to those who fear Him, and His righteousness to their children’s children—"}},"definableWords":["everlasting","LORD","fear","righteousness"],"peopleInVerse":[]},"18":{"text":"To such as keep his covenant, and to those that remember his commandments to do them.","ref":"Psalms 103:18","synthesized":"to those who keep His covenant and remember to obey His precepts.","sources":{"KJV":{"text":"To such as keep his covenant, and to those that remember his commandments to do them."},"BSB":{"text":"to those who keep His covenant and remember to obey His precepts."}},"definableWords":["keep","covenant","remember"],"peopleInVerse":[]},"19":{"text":"The LORD hath prepared his throne in the heavens; and his kingdom ruleth over all.","ref":"Psalms 103:19","synthesized":"The LORD has established His throne in heaven, and His kingdom rules over all.","sources":{"KJV":{"text":"The LORD hath prepared his throne in the heavens; and his kingdom ruleth over all."},"BSB":{"text":"The LORD has established His throne in heaven, and His kingdom rules over all."}},"definableWords":["LORD","throne","heaven","kingdom"],"peopleInVerse":[]},"20":{"text":"Bless the LORD, ye his angels, that excel in strength, that do his commandments, hearkening unto the voice of his word.","ref":"Psalms 103:20","synthesized":"Bless the LORD, all His angels mighty in strength who carry out His word, who hearken to the voice of His command.","sources":{"KJV":{"text":"Bless the LORD, ye his angels, that excel in strength, that do his commandments, hearkening unto the voice of his word."},"BSB":{"text":"Bless the LORD, all His angels mighty in strength who carry out His word, who hearken to the voice of His command."}},"definableWords":["bless","LORD","mighty","word","voice"],"peopleInVerse":[]},"21":{"text":"Bless ye the LORD, all ye his hosts; ye ministers of his, that do his pleasure.","ref":"Psalms 103:21","synthesized":"Bless the LORD, all His hosts, you servants who do His will.","sources":{"KJV":{"text":"Bless ye the LORD, all ye his hosts; ye ministers of his, that do his pleasure."},"BSB":{"text":"Bless the LORD, all His hosts, you servants who do His will."}},"definableWords":["bless","LORD","servants"],"peopleInVerse":[]},"22":{"text":"Bless the LORD, all his works in all places of his dominion: bless the LORD, O my soul.","ref":"Psalms 103:22","synthesized":"Bless the LORD, all His works in all places of His dominion.   Bless the LORD, O my soul!","sources":{"KJV":{"text":"Bless the LORD, all his works in all places of his dominion: bless the LORD, O my soul."},"BSB":{"text":"Bless the LORD, all His works in all places of His dominion.   Bless the LORD, O my soul!"}},"definableWords":["bless","LORD","works","dominion","Lord","soul"],"peopleInVerse":[]}}},"104":{"chapter":"104","title":"BLESS THE LORD, O MY SOUL (CREATION)","verses":{"1":{"text":"Bless the LORD, O my soul. O LORD my God, thou art very great; thou art clothed with honour and majesty.","ref":"Psalms 104:1","synthesized":"Bless the LORD, O my soul!   O LORD my God, You are very great; You are clothed with splendor and majesty.","sources":{"KJV":{"text":"Bless the LORD, O my soul. O LORD my God, thou art very great; thou art clothed with honour and majesty."},"BSB":{"text":"Bless the LORD, O my soul!   O LORD my God, You are very great; You are clothed with splendor and majesty."}},"definableWords":["bless","LORD","soul","Lord","God","great"],"peopleInVerse":[]},"2":{"text":"Who coverest thyself with light as with a garment: who stretchest out the heavens like a curtain:","ref":"Psalms 104:2","synthesized":"He wraps Himself in light as with a garment; He stretches out the heavens like a tent,","sources":{"KJV":{"text":"Who coverest thyself with light as with a garment: who stretchest out the heavens like a curtain:"},"BSB":{"text":"He wraps Himself in light as with a garment; He stretches out the heavens like a tent,"}},"definableWords":["light","heavens"],"peopleInVerse":[]},"3":{"text":"Who layeth the beams of his chambers in the waters: who maketh the clouds his chariot: who walketh upon the wings of the wind:","ref":"Psalms 104:3","synthesized":"laying the beams of His chambers in the waters above, making the clouds His chariot, walking on the wings of the wind.","sources":{"KJV":{"text":"Who layeth the beams of his chambers in the waters: who maketh the clouds his chariot: who walketh upon the wings of the wind:"},"BSB":{"text":"laying the beams of His chambers in the waters above, making the clouds His chariot, walking on the wings of the wind."}},"definableWords":["waters"],"peopleInVerse":[]},"4":{"text":"Who maketh his angels spirits; his ministers a flaming fire:","ref":"Psalms 104:4","synthesized":"He makes the winds His messengers, flames of fire His servants.","sources":{"KJV":{"text":"Who maketh his angels spirits; his ministers a flaming fire:"},"BSB":{"text":"He makes the winds His messengers, flames of fire His servants."}},"definableWords":["servants"],"peopleInVerse":[]},"5":{"text":"Who laid the foundations of the earth, that it should not be removed for ever.","ref":"Psalms 104:5","synthesized":"He set the earth on its foundations, never to be moved.","sources":{"KJV":{"text":"Who laid the foundations of the earth, that it should not be removed for ever."},"BSB":{"text":"He set the earth on its foundations, never to be moved."}},"definableWords":["earth"],"peopleInVerse":[]},"6":{"text":"Thou coveredst it with the deep as with a garment: the waters stood above the mountains.","ref":"Psalms 104:6","synthesized":"You covered it with the deep like a garment; the waters stood above the mountains.","sources":{"KJV":{"text":"Thou coveredst it with the deep as with a garment: the waters stood above the mountains."},"BSB":{"text":"You covered it with the deep like a garment; the waters stood above the mountains."}},"definableWords":["deep","waters"],"peopleInVerse":[]},"7":{"text":"At thy rebuke they fled; at the voice of thy thunder they hasted away.","ref":"Psalms 104:7","synthesized":"At Your rebuke the waters fled; at the sound of Your thunder they hurried away—","sources":{"KJV":{"text":"At thy rebuke they fled; at the voice of thy thunder they hasted away."},"BSB":{"text":"At Your rebuke the waters fled; at the sound of Your thunder they hurried away—"}},"definableWords":["waters"],"peopleInVerse":[]},"8":{"text":"They go up by the mountains; they go down by the valleys unto the place which thou hast founded for them.","ref":"Psalms 104:8","synthesized":"the mountains rose and the valleys sank to the place You assigned for them—","sources":{"KJV":{"text":"They go up by the mountains; they go down by the valleys unto the place which thou hast founded for them."},"BSB":{"text":"the mountains rose and the valleys sank to the place You assigned for them—"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Thou hast set a bound that they may not pass over; that they turn not again to cover the earth.","ref":"Psalms 104:9","synthesized":"You set a boundary they cannot cross, that they may never again cover the earth.","sources":{"KJV":{"text":"Thou hast set a bound that they may not pass over; that they turn not again to cover the earth."},"BSB":{"text":"You set a boundary they cannot cross, that they may never again cover the earth."}},"definableWords":["earth"],"peopleInVerse":[]},"10":{"text":"He sendeth the springs into the valleys, which run among the hills.","ref":"Psalms 104:10","synthesized":"He sends forth springs in the valleys; they flow between the mountains.","sources":{"KJV":{"text":"He sendeth the springs into the valleys, which run among the hills."},"BSB":{"text":"He sends forth springs in the valleys; they flow between the mountains."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"They give drink to every beast of the field: the wild asses quench their thirst.","ref":"Psalms 104:11","synthesized":"They give drink to every beast of the field; the wild donkeys quench their thirst.","sources":{"KJV":{"text":"They give drink to every beast of the field: the wild asses quench their thirst."},"BSB":{"text":"They give drink to every beast of the field; the wild donkeys quench their thirst."}},"definableWords":["field"],"peopleInVerse":[]},"12":{"text":"By them shall the fowls of the heaven have their habitation, which sing among the branches.","ref":"Psalms 104:12","synthesized":"The birds of the air nest beside the springs; they sing among the branches.","sources":{"KJV":{"text":"By them shall the fowls of the heaven have their habitation, which sing among the branches."},"BSB":{"text":"The birds of the air nest beside the springs; they sing among the branches."}},"definableWords":["birds"],"peopleInVerse":[]},"13":{"text":"He watereth the hills from his chambers: the earth is satisfied with the fruit of thy works.","ref":"Psalms 104:13","synthesized":"He waters the mountains from His chambers; the earth is satisfied by the fruit of His works.","sources":{"KJV":{"text":"He watereth the hills from his chambers: the earth is satisfied with the fruit of thy works."},"BSB":{"text":"He waters the mountains from His chambers; the earth is satisfied by the fruit of His works."}},"definableWords":["waters","earth","works"],"peopleInVerse":[]},"14":{"text":"He causeth the grass to grow for the cattle, and herb for the service of man: that he may bring forth food out of the earth;","ref":"Psalms 104:14","synthesized":"He makes the grass grow for the livestock and provides crops for man to cultivate, bringing forth food from the earth:","sources":{"KJV":{"text":"He causeth the grass to grow for the cattle, and herb for the service of man: that he may bring forth food out of the earth;"},"BSB":{"text":"He makes the grass grow for the livestock and provides crops for man to cultivate, bringing forth food from the earth:"}},"definableWords":["man","earth"],"peopleInVerse":[]},"15":{"text":"And wine that maketh glad the heart of man, and oil to make his face to shine, and bread which strengtheneth man’s heart.","ref":"Psalms 104:15","synthesized":"wine that gladdens the heart of man, oil that makes his face to shine, and bread that sustains his heart.","sources":{"KJV":{"text":"And wine that maketh glad the heart of man, and oil to make his face to shine, and bread which strengtheneth man’s heart."},"BSB":{"text":"wine that gladdens the heart of man, oil that makes his face to shine, and bread that sustains his heart."}},"definableWords":["heart","man"],"peopleInVerse":[]},"16":{"text":"The trees of the LORD are full of sap; the cedars of Lebanon, which he hath planted;","ref":"Psalms 104:16","synthesized":"The trees of the LORD have their fill, the cedars of Lebanon that He planted,","sources":{"KJV":{"text":"The trees of the LORD are full of sap; the cedars of Lebanon, which he hath planted;"},"BSB":{"text":"The trees of the LORD have their fill, the cedars of Lebanon that He planted,"}},"definableWords":["trees","LORD","fill"],"peopleInVerse":[]},"17":{"text":"Where the birds make their nests: as for the stork, the fir trees are her house.","ref":"Psalms 104:17","synthesized":"where the birds build their nests; the stork makes her home in the cypresses.","sources":{"KJV":{"text":"Where the birds make their nests: as for the stork, the fir trees are her house."},"BSB":{"text":"where the birds build their nests; the stork makes her home in the cypresses."}},"definableWords":["birds"],"peopleInVerse":[]},"18":{"text":"The high hills are a refuge for the wild goats; and the rocks for the conies.","ref":"Psalms 104:18","synthesized":"The high mountains are for the wild goats, the cliffs a refuge for the rock badgers.","sources":{"KJV":{"text":"The high hills are a refuge for the wild goats; and the rocks for the conies."},"BSB":{"text":"The high mountains are for the wild goats, the cliffs a refuge for the rock badgers."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"He appointed the moon for seasons: the sun knoweth his going down.","ref":"Psalms 104:19","synthesized":"He made the moon to mark the seasons; the sun knows when to set.","sources":{"KJV":{"text":"He appointed the moon for seasons: the sun knoweth his going down."},"BSB":{"text":"He made the moon to mark the seasons; the sun knows when to set."}},"definableWords":["made"],"peopleInVerse":[]},"20":{"text":"Thou makest darkness, and it is night: wherein all the beasts of the forest do creep forth.","ref":"Psalms 104:20","synthesized":"You bring darkness, and it becomes night, when all the beasts of the forest prowl.","sources":{"KJV":{"text":"Thou makest darkness, and it is night: wherein all the beasts of the forest do creep forth."},"BSB":{"text":"You bring darkness, and it becomes night, when all the beasts of the forest prowl."}},"definableWords":["darkness","night"],"peopleInVerse":[]},"21":{"text":"The young lions roar after their prey, and seek their meat from God.","ref":"Psalms 104:21","synthesized":"The young lions roar for their prey and seek their food from God.","sources":{"KJV":{"text":"The young lions roar after their prey, and seek their meat from God."},"BSB":{"text":"The young lions roar for their prey and seek their food from God."}},"definableWords":["seek","God"],"peopleInVerse":[]},"22":{"text":"The sun ariseth, they gather themselves together, and lay them down in their dens.","ref":"Psalms 104:22","synthesized":"The sun rises, and they withdraw; they lie down in their dens.","sources":{"KJV":{"text":"The sun ariseth, they gather themselves together, and lay them down in their dens."},"BSB":{"text":"The sun rises, and they withdraw; they lie down in their dens."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Man goeth forth unto his work and to his labour until the evening.","ref":"Psalms 104:23","synthesized":"Man goes forth to his work and to his labor until evening.","sources":{"KJV":{"text":"Man goeth forth unto his work and to his labour until the evening."},"BSB":{"text":"Man goes forth to his work and to his labor until evening."}},"definableWords":["man","work"],"peopleInVerse":[]},"24":{"text":"O LORD, how manifold are thy works! in wisdom hast thou made them all: the earth is full of thy riches.","ref":"Psalms 104:24","synthesized":"How many are Your works, O LORD! In wisdom You have made them all; the earth is full of Your creatures.","sources":{"KJV":{"text":"O LORD, how manifold are thy works! in wisdom hast thou made them all: the earth is full of thy riches."},"BSB":{"text":"How many are Your works, O LORD! In wisdom You have made them all; the earth is full of Your creatures."}},"definableWords":["works","LORD","wisdom","made","earth"],"peopleInVerse":[]},"25":{"text":"So is this great and wide sea, wherein are things creeping innumerable, both small and great beasts.","ref":"Psalms 104:25","synthesized":"Here is the sea, vast and wide, teeming with creatures beyond number, living things both great and small.","sources":{"KJV":{"text":"So is this great and wide sea, wherein are things creeping innumerable, both small and great beasts."},"BSB":{"text":"Here is the sea, vast and wide, teeming with creatures beyond number, living things both great and small."}},"definableWords":["sea","living","great"],"peopleInVerse":[]},"26":{"text":"There go the ships: there is that leviathan, whom thou hast made to play therein.","ref":"Psalms 104:26","synthesized":"There the ships pass, and Leviathan, which You formed to frolic there.","sources":{"KJV":{"text":"There go the ships: there is that leviathan, whom thou hast made to play therein."},"BSB":{"text":"There the ships pass, and Leviathan, which You formed to frolic there."}},"definableWords":["formed"],"peopleInVerse":[]},"27":{"text":"These wait all upon thee; that thou mayest give them their meat in due season.","ref":"Psalms 104:27","synthesized":"All creatures look to You to give them their food in due season.","sources":{"KJV":{"text":"These wait all upon thee; that thou mayest give them their meat in due season."},"BSB":{"text":"All creatures look to You to give them their food in due season."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"That thou givest them they gather: thou openest thine hand, they are filled with good.","ref":"Psalms 104:28","synthesized":"When You give it to them, they gather it up; when You open Your hand, they are satisfied with good things.","sources":{"KJV":{"text":"That thou givest them they gather: thou openest thine hand, they are filled with good."},"BSB":{"text":"When You give it to them, they gather it up; when You open Your hand, they are satisfied with good things."}},"definableWords":["good"],"peopleInVerse":[]},"29":{"text":"Thou hidest thy face, they are troubled: thou takest away their breath, they die, and return to their dust.","ref":"Psalms 104:29","synthesized":"When You hide Your face, they are terrified; when You take away their breath, they die and return to dust.","sources":{"KJV":{"text":"Thou hidest thy face, they are troubled: thou takest away their breath, they die, and return to their dust."},"BSB":{"text":"When You hide Your face, they are terrified; when You take away their breath, they die and return to dust."}},"definableWords":["breath","die"],"peopleInVerse":[]},"30":{"text":"Thou sendest forth thy spirit, they are created: and thou renewest the face of the earth.","ref":"Psalms 104:30","synthesized":"When You send Your Spirit, they are created, and You renew the face of the earth.","sources":{"KJV":{"text":"Thou sendest forth thy spirit, they are created: and thou renewest the face of the earth."},"BSB":{"text":"When You send Your Spirit, they are created, and You renew the face of the earth."}},"definableWords":["Spirit","created","earth"],"peopleInVerse":[]},"31":{"text":"The glory of the LORD shall endure for ever: the LORD shall rejoice in his works.","ref":"Psalms 104:31","synthesized":"May the glory of the LORD endure forever; may the LORD rejoice in His works.","sources":{"KJV":{"text":"The glory of the LORD shall endure for ever: the LORD shall rejoice in his works."},"BSB":{"text":"May the glory of the LORD endure forever; may the LORD rejoice in His works."}},"definableWords":["glory","LORD","Lord","works"],"peopleInVerse":[]},"32":{"text":"He looketh on the earth, and it trembleth: he toucheth the hills, and they smoke.","ref":"Psalms 104:32","synthesized":"He looks on the earth, and it trembles; He touches the mountains, and they smolder.","sources":{"KJV":{"text":"He looketh on the earth, and it trembleth: he toucheth the hills, and they smoke."},"BSB":{"text":"He looks on the earth, and it trembles; He touches the mountains, and they smolder."}},"definableWords":["earth"],"peopleInVerse":[]},"33":{"text":"I will sing unto the LORD as long as I live: I will sing praise to my God while I have my being.","ref":"Psalms 104:33","synthesized":"I will sing to the LORD all my life; I will sing praise to my God while I have my being.","sources":{"KJV":{"text":"I will sing unto the LORD as long as I live: I will sing praise to my God while I have my being."},"BSB":{"text":"I will sing to the LORD all my life; I will sing praise to my God while I have my being."}},"definableWords":["LORD","life","praise","God"],"peopleInVerse":[]},"34":{"text":"My meditation of him shall be sweet: I will be glad in the LORD.","ref":"Psalms 104:34","synthesized":"May my meditation be pleasing to Him, for I rejoice in the LORD.","sources":{"KJV":{"text":"My meditation of him shall be sweet: I will be glad in the LORD."},"BSB":{"text":"May my meditation be pleasing to Him, for I rejoice in the LORD."}},"definableWords":["LORD"],"peopleInVerse":[]},"35":{"text":"Let the sinners be consumed out of the earth, and let the wicked be no more. Bless thou the LORD, O my soul. Praise ye the LORD.","ref":"Psalms 104:35","synthesized":"May sinners vanish from the earth and the wicked be no more.   Bless the LORD, O my soul.   Hallelujah!","sources":{"KJV":{"text":"Let the sinners be consumed out of the earth, and let the wicked be no more. Bless thou the LORD, O my soul. Praise ye the LORD."},"BSB":{"text":"May sinners vanish from the earth and the wicked be no more.   Bless the LORD, O my soul.   Hallelujah!"}},"definableWords":["earth","bless","LORD","soul"],"peopleInVerse":[]}}},"105":{"chapter":"105","title":"GIVE THANKS — REMEMBER HIS WONDERS","verses":{"1":{"text":"O give thanks unto the LORD; call upon his name: make known his deeds among the people.","ref":"Psalms 105:1","synthesized":"Give thanks to the LORD, call upon His name; make known His deeds among the nations.","sources":{"KJV":{"text":"O give thanks unto the LORD; call upon his name: make known his deeds among the people."},"BSB":{"text":"Give thanks to the LORD, call upon His name; make known His deeds among the nations."}},"definableWords":["LORD","name","make","nations"],"peopleInVerse":[]},"2":{"text":"Sing unto him, sing psalms unto him: talk ye of all his wondrous works.","ref":"Psalms 105:2","synthesized":"Sing to Him, sing praises to Him; tell of all His wonders.","sources":{"KJV":{"text":"Sing unto him, sing psalms unto him: talk ye of all his wondrous works."},"BSB":{"text":"Sing to Him, sing praises to Him; tell of all His wonders."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Glory ye in his holy name: let the heart of them rejoice that seek the LORD.","ref":"Psalms 105:3","synthesized":"Glory in His holy name; let the hearts of those who seek the LORD rejoice.","sources":{"KJV":{"text":"Glory ye in his holy name: let the heart of them rejoice that seek the LORD."},"BSB":{"text":"Glory in His holy name; let the hearts of those who seek the LORD rejoice."}},"definableWords":["glory","holy","name","seek","LORD"],"peopleInVerse":[]},"4":{"text":"Seek the LORD, and his strength: seek his face evermore.","ref":"Psalms 105:4","synthesized":"Seek out the LORD and His strength; seek His face always.","sources":{"KJV":{"text":"Seek the LORD, and his strength: seek his face evermore."},"BSB":{"text":"Seek out the LORD and His strength; seek His face always."}},"definableWords":["seek","LORD"],"peopleInVerse":[]},"5":{"text":"Remember his marvellous works that he hath done; his wonders, and the judgments of his mouth;","ref":"Psalms 105:5","synthesized":"Remember the wonders He has done, His marvels, and the judgments He has pronounced,","sources":{"KJV":{"text":"Remember his marvellous works that he hath done; his wonders, and the judgments of his mouth;"},"BSB":{"text":"Remember the wonders He has done, His marvels, and the judgments He has pronounced,"}},"definableWords":["remember"],"peopleInVerse":[]},"6":{"text":"O ye seed of Abraham his servant, ye children of Jacob his chosen.","ref":"Psalms 105:6","synthesized":"O offspring of His servant Abraham, O sons of Jacob, His chosen ones.","sources":{"KJV":{"text":"O ye seed of Abraham his servant, ye children of Jacob his chosen."},"BSB":{"text":"O offspring of His servant Abraham, O sons of Jacob, His chosen ones."}},"definableWords":["servant","Abraham","sons","Jacob"],"peopleInVerse":["Abraham","Jacob"]},"7":{"text":"He is the LORD our God: his judgments are in all the earth.","ref":"Psalms 105:7","synthesized":"He is the LORD our God; His judgments carry throughout the earth.","sources":{"KJV":{"text":"He is the LORD our God: his judgments are in all the earth."},"BSB":{"text":"He is the LORD our God; His judgments carry throughout the earth."}},"definableWords":["LORD","God","earth"],"peopleInVerse":[]},"8":{"text":"He hath remembered his covenant for ever, the word which he commanded to a thousand generations.","ref":"Psalms 105:8","synthesized":"He remembers His covenant forever, the word He ordained for a thousand generations—","sources":{"KJV":{"text":"He hath remembered his covenant for ever, the word which he commanded to a thousand generations."},"BSB":{"text":"He remembers His covenant forever, the word He ordained for a thousand generations—"}},"definableWords":["covenant","word"],"peopleInVerse":[]},"9":{"text":"Which covenant he made with Abraham, and his oath unto Isaac;","ref":"Psalms 105:9","synthesized":"the covenant He made with Abraham, and the oath He swore to Isaac.","sources":{"KJV":{"text":"Which covenant he made with Abraham, and his oath unto Isaac;"},"BSB":{"text":"the covenant He made with Abraham, and the oath He swore to Isaac."}},"definableWords":["covenant","made","Abraham","Isaac"],"peopleInVerse":["Abraham","Isaac"]},"10":{"text":"And confirmed the same unto Jacob for a law, and to Israel for an everlasting covenant:","ref":"Psalms 105:10","synthesized":"He confirmed it to Jacob as a decree, to Israel as an everlasting covenant:","sources":{"KJV":{"text":"And confirmed the same unto Jacob for a law, and to Israel for an everlasting covenant:"},"BSB":{"text":"He confirmed it to Jacob as a decree, to Israel as an everlasting covenant:"}},"definableWords":["Jacob","Israel","everlasting","covenant"],"peopleInVerse":["Jacob"]},"11":{"text":"Saying, Unto thee will I give the land of Canaan, the lot of your inheritance:","ref":"Psalms 105:11","synthesized":"“I will give you the land of Canaan as the portion of your inheritance.”","sources":{"KJV":{"text":"Saying, Unto thee will I give the land of Canaan, the lot of your inheritance:"},"BSB":{"text":"“I will give you the land of Canaan as the portion of your inheritance.”"}},"definableWords":["land","Canaan"],"peopleInVerse":["Canaan"]},"12":{"text":"When they were but a few men in number; yea, very few, and strangers in it.","ref":"Psalms 105:12","synthesized":"When they were few in number, few indeed, and strangers in the land,","sources":{"KJV":{"text":"When they were but a few men in number; yea, very few, and strangers in it."},"BSB":{"text":"When they were few in number, few indeed, and strangers in the land,"}},"definableWords":["land"],"peopleInVerse":[]},"13":{"text":"When they went from one nation to another, from one kingdom to another people;","ref":"Psalms 105:13","synthesized":"they wandered from nation to nation, from one kingdom to another.","sources":{"KJV":{"text":"When they went from one nation to another, from one kingdom to another people;"},"BSB":{"text":"they wandered from nation to nation, from one kingdom to another."}},"definableWords":["nation","one","kingdom"],"peopleInVerse":[]},"14":{"text":"He suffered no man to do them wrong: yea, he reproved kings for their sakes;","ref":"Psalms 105:14","synthesized":"He let no man oppress them; He rebuked kings on their behalf:","sources":{"KJV":{"text":"He suffered no man to do them wrong: yea, he reproved kings for their sakes;"},"BSB":{"text":"He let no man oppress them; He rebuked kings on their behalf:"}},"definableWords":["man","kings"],"peopleInVerse":[]},"15":{"text":"Saying, Touch not mine anointed, and do my prophets no harm.","ref":"Psalms 105:15","synthesized":"“Do not touch My anointed ones! Do no harm to My prophets!”","sources":{"KJV":{"text":"Saying, Touch not mine anointed, and do my prophets no harm."},"BSB":{"text":"“Do not touch My anointed ones! Do no harm to My prophets!”"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Moreover he called for a famine upon the land: he brake the whole staff of bread.","ref":"Psalms 105:16","synthesized":"He called down famine on the land and cut off all their supplies of food.","sources":{"KJV":{"text":"Moreover he called for a famine upon the land: he brake the whole staff of bread."},"BSB":{"text":"He called down famine on the land and cut off all their supplies of food."}},"definableWords":["land"],"peopleInVerse":[]},"17":{"text":"He sent a man before them, even Joseph, who was sold for a servant:","ref":"Psalms 105:17","synthesized":"He sent a man before them— Joseph, sold as a slave.","sources":{"KJV":{"text":"He sent a man before them, even Joseph, who was sold for a servant:"},"BSB":{"text":"He sent a man before them— Joseph, sold as a slave."}},"definableWords":["man","Joseph"],"peopleInVerse":["Joseph"]},"18":{"text":"Whose feet they hurt with fetters: he was laid in iron:","ref":"Psalms 105:18","synthesized":"They bruised his feet with shackles and placed his neck in irons,","sources":{"KJV":{"text":"Whose feet they hurt with fetters: he was laid in iron:"},"BSB":{"text":"They bruised his feet with shackles and placed his neck in irons,"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Until the time that his word came: the word of the LORD tried him.","ref":"Psalms 105:19","synthesized":"until his prediction came true and the word of the LORD proved him right.","sources":{"KJV":{"text":"Until the time that his word came: the word of the LORD tried him."},"BSB":{"text":"until his prediction came true and the word of the LORD proved him right."}},"definableWords":["word","LORD"],"peopleInVerse":[]},"20":{"text":"The king sent and loosed him; even the ruler of the people, and let him go free.","ref":"Psalms 105:20","synthesized":"The king sent and released him; the ruler of peoples set him free.","sources":{"KJV":{"text":"The king sent and loosed him; even the ruler of the people, and let him go free."},"BSB":{"text":"The king sent and released him; the ruler of peoples set him free."}},"definableWords":["king","ruler"],"peopleInVerse":[]},"21":{"text":"He made him lord of his house, and ruler of all his substance:","ref":"Psalms 105:21","synthesized":"He made him master of his household, ruler over all his substance,","sources":{"KJV":{"text":"He made him lord of his house, and ruler of all his substance:"},"BSB":{"text":"He made him master of his household, ruler over all his substance,"}},"definableWords":["made","ruler"],"peopleInVerse":[]},"22":{"text":"To bind his princes at his pleasure; and teach his senators wisdom.","ref":"Psalms 105:22","synthesized":"to instruct his princes as he pleased and teach his elders wisdom.","sources":{"KJV":{"text":"To bind his princes at his pleasure; and teach his senators wisdom."},"BSB":{"text":"to instruct his princes as he pleased and teach his elders wisdom."}},"definableWords":["wisdom"],"peopleInVerse":[]},"23":{"text":"Israel also came into Egypt; and Jacob sojourned in the land of Ham.","ref":"Psalms 105:23","synthesized":"Then Israel entered Egypt; Jacob dwelt in the land of Ham.","sources":{"KJV":{"text":"Israel also came into Egypt; and Jacob sojourned in the land of Ham."},"BSB":{"text":"Then Israel entered Egypt; Jacob dwelt in the land of Ham."}},"definableWords":["Israel","Egypt","Jacob","land","Ham"],"peopleInVerse":["Jacob"]},"24":{"text":"And he increased his people greatly; and made them stronger than their enemies.","ref":"Psalms 105:24","synthesized":"And the LORD made His people very fruitful, more numerous than their foes,","sources":{"KJV":{"text":"And he increased his people greatly; and made them stronger than their enemies."},"BSB":{"text":"And the LORD made His people very fruitful, more numerous than their foes,"}},"definableWords":["LORD","made","people","fruitful"],"peopleInVerse":[]},"25":{"text":"He turned their heart to hate his people, to deal subtilly with his servants.","ref":"Psalms 105:25","synthesized":"whose hearts He turned to hate His people, to conspire against His servants.","sources":{"KJV":{"text":"He turned their heart to hate his people, to deal subtilly with his servants."},"BSB":{"text":"whose hearts He turned to hate His people, to conspire against His servants."}},"definableWords":["people","servants"],"peopleInVerse":[]},"26":{"text":"He sent Moses his servant; and Aaron whom he had chosen.","ref":"Psalms 105:26","synthesized":"He sent Moses His servant, and Aaron, whom He had chosen.","sources":{"KJV":{"text":"He sent Moses his servant; and Aaron whom he had chosen."},"BSB":{"text":"He sent Moses His servant, and Aaron, whom He had chosen."}},"definableWords":["servant"],"peopleInVerse":["Moses","Aaron"]},"27":{"text":"They shewed his signs among them, and wonders in the land of Ham.","ref":"Psalms 105:27","synthesized":"They performed His miraculous signs among them, and wonders in the land of Ham.","sources":{"KJV":{"text":"They shewed his signs among them, and wonders in the land of Ham."},"BSB":{"text":"They performed His miraculous signs among them, and wonders in the land of Ham."}},"definableWords":["land","Ham"],"peopleInVerse":[]},"28":{"text":"He sent darkness, and made it dark; and they rebelled not against his word.","ref":"Psalms 105:28","synthesized":"He sent darkness, and it became dark— yet they defied His words.","sources":{"KJV":{"text":"He sent darkness, and made it dark; and they rebelled not against his word."},"BSB":{"text":"He sent darkness, and it became dark— yet they defied His words."}},"definableWords":["darkness"],"peopleInVerse":[]},"29":{"text":"He turned their waters into blood, and slew their fish.","ref":"Psalms 105:29","synthesized":"He turned their waters to blood and caused their fish to die.","sources":{"KJV":{"text":"He turned their waters into blood, and slew their fish."},"BSB":{"text":"He turned their waters to blood and caused their fish to die."}},"definableWords":["waters","blood","fish","die"],"peopleInVerse":[]},"30":{"text":"Their land brought forth frogs in abundance, in the chambers of their kings.","ref":"Psalms 105:30","synthesized":"Their land teemed with frogs, even in their royal chambers.","sources":{"KJV":{"text":"Their land brought forth frogs in abundance, in the chambers of their kings."},"BSB":{"text":"Their land teemed with frogs, even in their royal chambers."}},"definableWords":["land"],"peopleInVerse":[]},"31":{"text":"He spake, and there came divers sorts of flies, and lice in all their coasts.","ref":"Psalms 105:31","synthesized":"He spoke, and insects swarmed— gnats throughout their country.","sources":{"KJV":{"text":"He spake, and there came divers sorts of flies, and lice in all their coasts."},"BSB":{"text":"He spoke, and insects swarmed— gnats throughout their country."}},"definableWords":[],"peopleInVerse":[]},"32":{"text":"He gave them hail for rain, and flaming fire in their land.","ref":"Psalms 105:32","synthesized":"He gave them hail for rain, with lightning throughout their land.","sources":{"KJV":{"text":"He gave them hail for rain, and flaming fire in their land."},"BSB":{"text":"He gave them hail for rain, with lightning throughout their land."}},"definableWords":["land"],"peopleInVerse":[]},"33":{"text":"He smote their vines also and their fig trees; and brake the trees of their coasts.","ref":"Psalms 105:33","synthesized":"He struck their vines and fig trees and shattered the trees of their country.","sources":{"KJV":{"text":"He smote their vines also and their fig trees; and brake the trees of their coasts."},"BSB":{"text":"He struck their vines and fig trees and shattered the trees of their country."}},"definableWords":["trees"],"peopleInVerse":[]},"34":{"text":"He spake, and the locusts came, and caterpillers, and that without number,","ref":"Psalms 105:34","synthesized":"He spoke, and the locusts came— young locusts without number.","sources":{"KJV":{"text":"He spake, and the locusts came, and caterpillers, and that without number,"},"BSB":{"text":"He spoke, and the locusts came— young locusts without number."}},"definableWords":[],"peopleInVerse":[]},"35":{"text":"And did eat up all the herbs in their land, and devoured the fruit of their ground.","ref":"Psalms 105:35","synthesized":"They devoured every plant in their land and consumed the produce of their soil.","sources":{"KJV":{"text":"And did eat up all the herbs in their land, and devoured the fruit of their ground."},"BSB":{"text":"They devoured every plant in their land and consumed the produce of their soil."}},"definableWords":["land"],"peopleInVerse":[]},"36":{"text":"He smote also all the firstborn in their land, the chief of all their strength.","ref":"Psalms 105:36","synthesized":"Then He struck all the firstborn in their land, the firstfruits of all their vigor.","sources":{"KJV":{"text":"He smote also all the firstborn in their land, the chief of all their strength."},"BSB":{"text":"Then He struck all the firstborn in their land, the firstfruits of all their vigor."}},"definableWords":["land"],"peopleInVerse":[]},"37":{"text":"He brought them forth also with silver and gold: and there was not one feeble person among their tribes.","ref":"Psalms 105:37","synthesized":"He brought Israel out with silver and gold, and none among His tribes stumbled.","sources":{"KJV":{"text":"He brought them forth also with silver and gold: and there was not one feeble person among their tribes."},"BSB":{"text":"He brought Israel out with silver and gold, and none among His tribes stumbled."}},"definableWords":["Israel"],"peopleInVerse":[]},"38":{"text":"Egypt was glad when they departed: for the fear of them fell upon them.","ref":"Psalms 105:38","synthesized":"Egypt was glad when they departed, for the dread of Israel had fallen on them.","sources":{"KJV":{"text":"Egypt was glad when they departed: for the fear of them fell upon them."},"BSB":{"text":"Egypt was glad when they departed, for the dread of Israel had fallen on them."}},"definableWords":["Egypt","Israel"],"peopleInVerse":[]},"39":{"text":"He spread a cloud for a covering; and fire to give light in the night.","ref":"Psalms 105:39","synthesized":"He spread a cloud as a covering and a fire to light up the night.","sources":{"KJV":{"text":"He spread a cloud for a covering; and fire to give light in the night."},"BSB":{"text":"He spread a cloud as a covering and a fire to light up the night."}},"definableWords":["light","night"],"peopleInVerse":[]},"40":{"text":"The people asked, and he brought quails, and satisfied them with the bread of heaven.","ref":"Psalms 105:40","synthesized":"They asked, and He brought quail and satisfied them with the bread of heaven.","sources":{"KJV":{"text":"The people asked, and he brought quails, and satisfied them with the bread of heaven."},"BSB":{"text":"They asked, and He brought quail and satisfied them with the bread of heaven."}},"definableWords":["heaven"],"peopleInVerse":[]},"41":{"text":"He opened the rock, and the waters gushed out; they ran in the dry places like a river.","ref":"Psalms 105:41","synthesized":"He opened a rock, and water gushed out; it flowed like a river in the desert.","sources":{"KJV":{"text":"He opened the rock, and the waters gushed out; they ran in the dry places like a river."},"BSB":{"text":"He opened a rock, and water gushed out; it flowed like a river in the desert."}},"definableWords":["water"],"peopleInVerse":[]},"42":{"text":"For he remembered his holy promise, and Abraham his servant.","ref":"Psalms 105:42","synthesized":"For He remembered His holy promise to Abraham His servant.","sources":{"KJV":{"text":"For he remembered his holy promise, and Abraham his servant."},"BSB":{"text":"For He remembered His holy promise to Abraham His servant."}},"definableWords":["remembered","holy","promise","Abraham","servant"],"peopleInVerse":["Abraham"]},"43":{"text":"And he brought forth his people with joy, and his chosen with gladness:","ref":"Psalms 105:43","synthesized":"He brought forth His people with rejoicing, His chosen with shouts of joy.","sources":{"KJV":{"text":"And he brought forth his people with joy, and his chosen with gladness:"},"BSB":{"text":"He brought forth His people with rejoicing, His chosen with shouts of joy."}},"definableWords":["people","joy"],"peopleInVerse":[]},"44":{"text":"And gave them the lands of the heathen: and they inherited the labour of the people;","ref":"Psalms 105:44","synthesized":"He gave them the lands of the nations, that they might inherit the fruit of others’ labor,","sources":{"KJV":{"text":"And gave them the lands of the heathen: and they inherited the labour of the people;"},"BSB":{"text":"He gave them the lands of the nations, that they might inherit the fruit of others’ labor,"}},"definableWords":["nations","inherit"],"peopleInVerse":[]},"45":{"text":"That they might observe his statutes, and keep his laws. Praise ye the LORD.","ref":"Psalms 105:45","synthesized":"that they might keep His statutes and obey His laws.   Hallelujah!","sources":{"KJV":{"text":"That they might observe his statutes, and keep his laws. Praise ye the LORD."},"BSB":{"text":"that they might keep His statutes and obey His laws.   Hallelujah!"}},"definableWords":["keep"],"peopleInVerse":[]}}},"106":{"chapter":"106","title":"PRAISE YE THE LORD — REMEMBER ME","verses":{"1":{"text":"Praise ye the LORD. O give thanks unto the LORD; for he is good: for his mercy endureth for ever.","ref":"Psalms 106:1","synthesized":"Hallelujah!   Give thanks to the LORD, for He is good; His loving devotion endures forever.","sources":{"KJV":{"text":"Praise ye the LORD. O give thanks unto the LORD; for he is good: for his mercy endureth for ever."},"BSB":{"text":"Hallelujah!   Give thanks to the LORD, for He is good; His loving devotion endures forever."}},"definableWords":["LORD","good"],"peopleInVerse":[]},"2":{"text":"Who can utter the mighty acts of the LORD? who can shew forth all his praise?","ref":"Psalms 106:2","synthesized":"Who can describe the mighty acts of the LORD or fully proclaim His praise?","sources":{"KJV":{"text":"Who can utter the mighty acts of the LORD? who can shew forth all his praise?"},"BSB":{"text":"Who can describe the mighty acts of the LORD or fully proclaim His praise?"}},"definableWords":["mighty","LORD","or","praise"],"peopleInVerse":[]},"3":{"text":"Blessed are they that keep judgment, and he that doeth righteousness at all times.","ref":"Psalms 106:3","synthesized":"Blessed are those who uphold justice, who practice righteousness at all times.","sources":{"KJV":{"text":"Blessed are they that keep judgment, and he that doeth righteousness at all times."},"BSB":{"text":"Blessed are those who uphold justice, who practice righteousness at all times."}},"definableWords":["blessed","justice","righteousness"],"peopleInVerse":[]},"4":{"text":"Remember me, O LORD, with the favour that thou bearest unto thy people: O visit me with thy salvation;","ref":"Psalms 106:4","synthesized":"Remember me, O LORD, in Your favor to Your people; visit me with Your salvation,","sources":{"KJV":{"text":"Remember me, O LORD, with the favour that thou bearest unto thy people: O visit me with thy salvation;"},"BSB":{"text":"Remember me, O LORD, in Your favor to Your people; visit me with Your salvation,"}},"definableWords":["remember","LORD","people","salvation"],"peopleInVerse":[]},"5":{"text":"That I may see the good of thy chosen, that I may rejoice in the gladness of thy nation, that I may glory with thine inheritance.","ref":"Psalms 106:5","synthesized":"that I may see the prosperity of Your chosen ones, and rejoice in the gladness of Your nation, and give glory with Your inheritance.","sources":{"KJV":{"text":"That I may see the good of thy chosen, that I may rejoice in the gladness of thy nation, that I may glory with thine inheritance."},"BSB":{"text":"that I may see the prosperity of Your chosen ones, and rejoice in the gladness of Your nation, and give glory with Your inheritance."}},"definableWords":["see","nation","glory"],"peopleInVerse":[]},"6":{"text":"We have sinned with our fathers, we have committed iniquity, we have done wickedly.","ref":"Psalms 106:6","synthesized":"We have sinned like our fathers; we have done wrong and acted wickedly.","sources":{"KJV":{"text":"We have sinned with our fathers, we have committed iniquity, we have done wickedly."},"BSB":{"text":"We have sinned like our fathers; we have done wrong and acted wickedly."}},"definableWords":["fathers"],"peopleInVerse":[]},"7":{"text":"Our fathers understood not thy wonders in Egypt; they remembered not the multitude of thy mercies; but provoked him at the sea, even at the Red sea.","ref":"Psalms 106:7","synthesized":"Our fathers in Egypt did not grasp Your wonders or remember Your abundant kindness; but they rebelled by the sea, there at the Red Sea.","sources":{"KJV":{"text":"Our fathers understood not thy wonders in Egypt; they remembered not the multitude of thy mercies; but provoked him at the sea, even at the Red sea."},"BSB":{"text":"Our fathers in Egypt did not grasp Your wonders or remember Your abundant kindness; but they rebelled by the sea, there at the Red Sea."}},"definableWords":["fathers","Egypt","or","remember","kindness","sea"],"peopleInVerse":[]},"8":{"text":"Nevertheless he saved them for his name’s sake, that he might make his mighty power to be known.","ref":"Psalms 106:8","synthesized":"Yet He saved them for the sake of His name, to make His power known.","sources":{"KJV":{"text":"Nevertheless he saved them for his name’s sake, that he might make his mighty power to be known."},"BSB":{"text":"Yet He saved them for the sake of His name, to make His power known."}},"definableWords":["name","make"],"peopleInVerse":[]},"9":{"text":"He rebuked the Red sea also, and it was dried up: so he led them through the depths, as through the wilderness.","ref":"Psalms 106:9","synthesized":"He rebuked the Red Sea, and it dried up; He led them through the depths as through a desert.","sources":{"KJV":{"text":"He rebuked the Red sea also, and it was dried up: so he led them through the depths, as through the wilderness."},"BSB":{"text":"He rebuked the Red Sea, and it dried up; He led them through the depths as through a desert."}},"definableWords":["sea"],"peopleInVerse":[]},"10":{"text":"And he saved them from the hand of him that hated them, and redeemed them from the hand of the enemy.","ref":"Psalms 106:10","synthesized":"He saved them from the hand that hated them; He redeemed them from the hand of the enemy.","sources":{"KJV":{"text":"And he saved them from the hand of him that hated them, and redeemed them from the hand of the enemy."},"BSB":{"text":"He saved them from the hand that hated them; He redeemed them from the hand of the enemy."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"And the waters covered their enemies: there was not one of them left.","ref":"Psalms 106:11","synthesized":"The waters covered their foes; not one of them remained.","sources":{"KJV":{"text":"And the waters covered their enemies: there was not one of them left."},"BSB":{"text":"The waters covered their foes; not one of them remained."}},"definableWords":["waters","one"],"peopleInVerse":[]},"12":{"text":"Then believed they his words; they sang his praise.","ref":"Psalms 106:12","synthesized":"Then they believed His promises and sang His praise.","sources":{"KJV":{"text":"Then believed they his words; they sang his praise."},"BSB":{"text":"Then they believed His promises and sang His praise."}},"definableWords":["believed","praise"],"peopleInVerse":[]},"13":{"text":"They soon forgat his works; they waited not for his counsel:","ref":"Psalms 106:13","synthesized":"Yet they soon forgot His works and failed to wait for His counsel.","sources":{"KJV":{"text":"They soon forgat his works; they waited not for his counsel:"},"BSB":{"text":"Yet they soon forgot His works and failed to wait for His counsel."}},"definableWords":["works","wait"],"peopleInVerse":[]},"14":{"text":"But lusted exceedingly in the wilderness, and tempted God in the desert.","ref":"Psalms 106:14","synthesized":"They craved intensely in the wilderness and tested God in the desert.","sources":{"KJV":{"text":"But lusted exceedingly in the wilderness, and tempted God in the desert."},"BSB":{"text":"They craved intensely in the wilderness and tested God in the desert."}},"definableWords":["God"],"peopleInVerse":[]},"15":{"text":"And he gave them their request; but sent leanness into their soul.","ref":"Psalms 106:15","synthesized":"So He granted their request, but sent a wasting disease upon them.","sources":{"KJV":{"text":"And he gave them their request; but sent leanness into their soul."},"BSB":{"text":"So He granted their request, but sent a wasting disease upon them."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"They envied Moses also in the camp, and Aaron the saint of the LORD.","ref":"Psalms 106:16","synthesized":"In the camp they envied Moses, as well as Aaron, the holy one of the LORD.","sources":{"KJV":{"text":"They envied Moses also in the camp, and Aaron the saint of the LORD."},"BSB":{"text":"In the camp they envied Moses, as well as Aaron, the holy one of the LORD."}},"definableWords":["holy","one","LORD"],"peopleInVerse":["Moses","Aaron"]},"17":{"text":"The earth opened and swallowed up Dathan, and covered the company of Abiram.","ref":"Psalms 106:17","synthesized":"The earth opened up and swallowed Dathan; it covered the assembly of Abiram.","sources":{"KJV":{"text":"The earth opened and swallowed up Dathan, and covered the company of Abiram."},"BSB":{"text":"The earth opened up and swallowed Dathan; it covered the assembly of Abiram."}},"definableWords":["earth"],"peopleInVerse":[]},"18":{"text":"And a fire was kindled in their company; the flame burned up the wicked.","ref":"Psalms 106:18","synthesized":"Then fire blazed through their company; flames consumed the wicked.","sources":{"KJV":{"text":"And a fire was kindled in their company; the flame burned up the wicked."},"BSB":{"text":"Then fire blazed through their company; flames consumed the wicked."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"They made a calf in Horeb, and worshipped the molten image.","ref":"Psalms 106:19","synthesized":"At Horeb they made a calf and worshiped a molten image.","sources":{"KJV":{"text":"They made a calf in Horeb, and worshipped the molten image."},"BSB":{"text":"At Horeb they made a calf and worshiped a molten image."}},"definableWords":["made","image"],"peopleInVerse":[]},"20":{"text":"Thus they changed their glory into the similitude of an ox that eateth grass.","ref":"Psalms 106:20","synthesized":"They exchanged their Glory for the image of a grass-eating ox.","sources":{"KJV":{"text":"Thus they changed their glory into the similitude of an ox that eateth grass."},"BSB":{"text":"They exchanged their Glory for the image of a grass-eating ox."}},"definableWords":["glory","image"],"peopleInVerse":[]},"21":{"text":"They forgat God their saviour, which had done great things in Egypt;","ref":"Psalms 106:21","synthesized":"They forgot God their Savior, who did great things in Egypt,","sources":{"KJV":{"text":"They forgat God their saviour, which had done great things in Egypt;"},"BSB":{"text":"They forgot God their Savior, who did great things in Egypt,"}},"definableWords":["God","great","Egypt"],"peopleInVerse":[]},"22":{"text":"Wondrous works in the land of Ham, and terrible things by the Red sea.","ref":"Psalms 106:22","synthesized":"wondrous works in the land of Ham, and awesome deeds by the Red Sea.","sources":{"KJV":{"text":"Wondrous works in the land of Ham, and terrible things by the Red sea."},"BSB":{"text":"wondrous works in the land of Ham, and awesome deeds by the Red Sea."}},"definableWords":["works","land","Ham","sea"],"peopleInVerse":[]},"23":{"text":"Therefore he said that he would destroy them, had not Moses his chosen stood before him in the breach, to turn away his wrath, lest he should destroy them.","ref":"Psalms 106:23","synthesized":"So He said He would destroy them— had not Moses His chosen one stood before Him in the breach to divert His wrath from destroying them.","sources":{"KJV":{"text":"Therefore he said that he would destroy them, had not Moses his chosen stood before him in the breach, to turn away his wrath, lest he should destroy them."},"BSB":{"text":"So He said He would destroy them— had not Moses His chosen one stood before Him in the breach to divert His wrath from destroying them."}},"definableWords":["one","wrath"],"peopleInVerse":["Moses"]},"24":{"text":"Yea, they despised the pleasant land, they believed not his word:","ref":"Psalms 106:24","synthesized":"They despised the pleasant land; they did not believe His promise.","sources":{"KJV":{"text":"Yea, they despised the pleasant land, they believed not his word:"},"BSB":{"text":"They despised the pleasant land; they did not believe His promise."}},"definableWords":["land","promise"],"peopleInVerse":[]},"25":{"text":"But murmured in their tents, and hearkened not unto the voice of the LORD.","ref":"Psalms 106:25","synthesized":"They grumbled in their tents and did not listen to the voice of the LORD.","sources":{"KJV":{"text":"But murmured in their tents, and hearkened not unto the voice of the LORD."},"BSB":{"text":"They grumbled in their tents and did not listen to the voice of the LORD."}},"definableWords":["voice","LORD"],"peopleInVerse":[]},"26":{"text":"Therefore he lifted up his hand against them, to overthrow them in the wilderness:","ref":"Psalms 106:26","synthesized":"So He raised His hand and swore to cast them down in the wilderness,","sources":{"KJV":{"text":"Therefore he lifted up his hand against them, to overthrow them in the wilderness:"},"BSB":{"text":"So He raised His hand and swore to cast them down in the wilderness,"}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"To overthrow their seed also among the nations, and to scatter them in the lands.","ref":"Psalms 106:27","synthesized":"to disperse their offspring among the nations and scatter them throughout the lands.","sources":{"KJV":{"text":"To overthrow their seed also among the nations, and to scatter them in the lands."},"BSB":{"text":"to disperse their offspring among the nations and scatter them throughout the lands."}},"definableWords":["nations"],"peopleInVerse":[]},"28":{"text":"They joined themselves also unto Baalpeor, and ate the sacrifices of the dead.","ref":"Psalms 106:28","synthesized":"They yoked themselves to Baal of Peor and ate sacrifices offered to lifeless gods.","sources":{"KJV":{"text":"They joined themselves also unto Baalpeor, and ate the sacrifices of the dead."},"BSB":{"text":"They yoked themselves to Baal of Peor and ate sacrifices offered to lifeless gods."}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"Thus they provoked him to anger with their inventions: and the plague brake in upon them.","ref":"Psalms 106:29","synthesized":"So they provoked the LORD to anger with their deeds, and a plague broke out among them.","sources":{"KJV":{"text":"Thus they provoked him to anger with their inventions: and the plague brake in upon them."},"BSB":{"text":"So they provoked the LORD to anger with their deeds, and a plague broke out among them."}},"definableWords":["LORD","anger"],"peopleInVerse":[]},"30":{"text":"Then stood up Phinehas, and executed judgment: and so the plague was stayed.","ref":"Psalms 106:30","synthesized":"But Phinehas stood and intervened, and the plague was restrained.","sources":{"KJV":{"text":"Then stood up Phinehas, and executed judgment: and so the plague was stayed."},"BSB":{"text":"But Phinehas stood and intervened, and the plague was restrained."}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"And that was counted unto him for righteousness unto all generations for evermore.","ref":"Psalms 106:31","synthesized":"It was credited to him as righteousness for endless generations to come.","sources":{"KJV":{"text":"And that was counted unto him for righteousness unto all generations for evermore."},"BSB":{"text":"It was credited to him as righteousness for endless generations to come."}},"definableWords":["righteousness"],"peopleInVerse":[]},"32":{"text":"They angered him also at the waters of strife, so that it went ill with Moses for their sakes:","ref":"Psalms 106:32","synthesized":"At the waters of Meribah they angered the LORD, and trouble came to Moses because of them.","sources":{"KJV":{"text":"They angered him also at the waters of strife, so that it went ill with Moses for their sakes:"},"BSB":{"text":"At the waters of Meribah they angered the LORD, and trouble came to Moses because of them."}},"definableWords":["waters","LORD"],"peopleInVerse":["Moses"]},"33":{"text":"Because they provoked his spirit, so that he spake unadvisedly with his lips.","ref":"Psalms 106:33","synthesized":"For they rebelled against His Spirit, and Moses spoke rashly with his lips.","sources":{"KJV":{"text":"Because they provoked his spirit, so that he spake unadvisedly with his lips."},"BSB":{"text":"For they rebelled against His Spirit, and Moses spoke rashly with his lips."}},"definableWords":["Spirit"],"peopleInVerse":["Moses"]},"34":{"text":"They did not destroy the nations, concerning whom the LORD commanded them:","ref":"Psalms 106:34","synthesized":"They did not destroy the peoples as the LORD had commanded them,","sources":{"KJV":{"text":"They did not destroy the nations, concerning whom the LORD commanded them:"},"BSB":{"text":"They did not destroy the peoples as the LORD had commanded them,"}},"definableWords":["LORD"],"peopleInVerse":[]},"35":{"text":"But were mingled among the heathen, and learned their works.","ref":"Psalms 106:35","synthesized":"but they mingled with the nations and adopted their customs.","sources":{"KJV":{"text":"But were mingled among the heathen, and learned their works."},"BSB":{"text":"but they mingled with the nations and adopted their customs."}},"definableWords":["nations"],"peopleInVerse":[]},"36":{"text":"And they served their idols: which were a snare unto them.","ref":"Psalms 106:36","synthesized":"They worshiped their idols, which became a snare to them.","sources":{"KJV":{"text":"And they served their idols: which were a snare unto them."},"BSB":{"text":"They worshiped their idols, which became a snare to them."}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"Yea, they sacrificed their sons and their daughters unto devils,","ref":"Psalms 106:37","synthesized":"They sacrificed their sons and their daughters to demons.","sources":{"KJV":{"text":"Yea, they sacrificed their sons and their daughters unto devils,"},"BSB":{"text":"They sacrificed their sons and their daughters to demons."}},"definableWords":["sons","daughters"],"peopleInVerse":[]},"38":{"text":"And shed innocent blood, even the blood of their sons and of their daughters, whom they sacrificed unto the idols of Canaan: and the land was polluted with blood.","ref":"Psalms 106:38","synthesized":"They shed innocent blood— the blood of their sons and daughters, whom they sacrificed to the idols of Canaan, and the land was polluted with blood.","sources":{"KJV":{"text":"And shed innocent blood, even the blood of their sons and of their daughters, whom they sacrificed unto the idols of Canaan: and the land was polluted with blood."},"BSB":{"text":"They shed innocent blood— the blood of their sons and daughters, whom they sacrificed to the idols of Canaan, and the land was polluted with blood."}},"definableWords":["blood","sons","daughters","Canaan","land"],"peopleInVerse":["Canaan"]},"39":{"text":"Thus were they defiled with their own works, and went a whoring with their own inventions.","ref":"Psalms 106:39","synthesized":"They defiled themselves by their actions and prostituted themselves by their deeds.","sources":{"KJV":{"text":"Thus were they defiled with their own works, and went a whoring with their own inventions."},"BSB":{"text":"They defiled themselves by their actions and prostituted themselves by their deeds."}},"definableWords":[],"peopleInVerse":[]},"40":{"text":"Therefore was the wrath of the LORD kindled against his people, insomuch that he abhorred his own inheritance.","ref":"Psalms 106:40","synthesized":"So the anger of the LORD burned against His people, and He abhorred His own inheritance.","sources":{"KJV":{"text":"Therefore was the wrath of the LORD kindled against his people, insomuch that he abhorred his own inheritance."},"BSB":{"text":"So the anger of the LORD burned against His people, and He abhorred His own inheritance."}},"definableWords":["anger","LORD","people"],"peopleInVerse":[]},"41":{"text":"And he gave them into the hand of the heathen; and they that hated them ruled over them.","ref":"Psalms 106:41","synthesized":"He delivered them into the hand of the nations, and those who hated them ruled over them.","sources":{"KJV":{"text":"And he gave them into the hand of the heathen; and they that hated them ruled over them."},"BSB":{"text":"He delivered them into the hand of the nations, and those who hated them ruled over them."}},"definableWords":["nations"],"peopleInVerse":[]},"42":{"text":"Their enemies also oppressed them, and they were brought into subjection under their hand.","ref":"Psalms 106:42","synthesized":"Their enemies oppressed them, and subdued them under their hand.","sources":{"KJV":{"text":"Their enemies also oppressed them, and they were brought into subjection under their hand."},"BSB":{"text":"Their enemies oppressed them, and subdued them under their hand."}},"definableWords":[],"peopleInVerse":[]},"43":{"text":"Many times did he deliver them; but they provoked him with their counsel, and were brought low for their iniquity.","ref":"Psalms 106:43","synthesized":"Many times He rescued them, but they were bent on rebellion and sank down in their iniquity.","sources":{"KJV":{"text":"Many times did he deliver them; but they provoked him with their counsel, and were brought low for their iniquity."},"BSB":{"text":"Many times He rescued them, but they were bent on rebellion and sank down in their iniquity."}},"definableWords":["iniquity"],"peopleInVerse":[]},"44":{"text":"Nevertheless he regarded their affliction, when he heard their cry:","ref":"Psalms 106:44","synthesized":"Nevertheless He heard their cry; He took note of their distress.","sources":{"KJV":{"text":"Nevertheless he regarded their affliction, when he heard their cry:"},"BSB":{"text":"Nevertheless He heard their cry; He took note of their distress."}},"definableWords":[],"peopleInVerse":[]},"45":{"text":"And he remembered for them his covenant, and repented according to the multitude of his mercies.","ref":"Psalms 106:45","synthesized":"And He remembered His covenant with them, and relented by the abundance of His loving devotion.","sources":{"KJV":{"text":"And he remembered for them his covenant, and repented according to the multitude of his mercies."},"BSB":{"text":"And He remembered His covenant with them, and relented by the abundance of His loving devotion."}},"definableWords":["remembered","covenant"],"peopleInVerse":[]},"46":{"text":"He made them also to be pitied of all those that carried them captives.","ref":"Psalms 106:46","synthesized":"He made them objects of compassion to all who held them captive.","sources":{"KJV":{"text":"He made them also to be pitied of all those that carried them captives."},"BSB":{"text":"He made them objects of compassion to all who held them captive."}},"definableWords":["made"],"peopleInVerse":[]},"47":{"text":"Save us, O LORD our God, and gather us from among the heathen, to give thanks unto thy holy name, and to triumph in thy praise.","ref":"Psalms 106:47","synthesized":"Save us, O LORD our God, and gather us from the nations, that we may give thanks to Your holy name, that we may glory in Your praise.","sources":{"KJV":{"text":"Save us, O LORD our God, and gather us from among the heathen, to give thanks unto thy holy name, and to triumph in thy praise."},"BSB":{"text":"Save us, O LORD our God, and gather us from the nations, that we may give thanks to Your holy name, that we may glory in Your praise."}},"definableWords":["LORD","God","nations","holy","name","glory","praise"],"peopleInVerse":[]},"48":{"text":"Blessed be the LORD God of Israel from everlasting to everlasting: and let all the people say, Amen. Praise ye the LORD.","ref":"Psalms 106:48","synthesized":"Blessed be the LORD, the God of Israel, from everlasting to everlasting.   Let all the people say, “Amen!”   Hallelujah!","sources":{"KJV":{"text":"Blessed be the LORD God of Israel from everlasting to everlasting: and let all the people say, Amen. Praise ye the LORD."},"BSB":{"text":"Blessed be the LORD, the God of Israel, from everlasting to everlasting.   Let all the people say, “Amen!”   Hallelujah!"}},"definableWords":["blessed","LORD","God","Israel","everlasting","people"],"peopleInVerse":[]}}},"107":{"chapter":"107","title":"GIVE THANKS, FOR HE IS GOOD","verses":{"1":{"text":"O give thanks unto the LORD, for he is good: for his mercy endureth for ever.","ref":"Psalms 107:1","synthesized":"Give thanks to the LORD, for He is good; His loving devotion endures forever.","sources":{"KJV":{"text":"O give thanks unto the LORD, for he is good: for his mercy endureth for ever."},"BSB":{"text":"Give thanks to the LORD, for He is good; His loving devotion endures forever."}},"definableWords":["LORD","good"],"peopleInVerse":[]},"2":{"text":"Let the redeemed of the LORD say so, whom he hath redeemed from the hand of the enemy;","ref":"Psalms 107:2","synthesized":"Let the redeemed of the LORD say so, whom He has redeemed from the hand of the enemy","sources":{"KJV":{"text":"Let the redeemed of the LORD say so, whom he hath redeemed from the hand of the enemy;"},"BSB":{"text":"Let the redeemed of the LORD say so, whom He has redeemed from the hand of the enemy"}},"definableWords":["LORD"],"peopleInVerse":[]},"3":{"text":"And gathered them out of the lands, from the east, and from the west, from the north, and from the south.","ref":"Psalms 107:3","synthesized":"and gathered from the lands, from east and west, from north and south.","sources":{"KJV":{"text":"And gathered them out of the lands, from the east, and from the west, from the north, and from the south."},"BSB":{"text":"and gathered from the lands, from east and west, from north and south."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"They wandered in the wilderness in a solitary way; they found no city to dwell in.","ref":"Psalms 107:4","synthesized":"Some wandered in desert wastelands, finding no path to a city in which to dwell.","sources":{"KJV":{"text":"They wandered in the wilderness in a solitary way; they found no city to dwell in."},"BSB":{"text":"Some wandered in desert wastelands, finding no path to a city in which to dwell."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Hungry and thirsty, their soul fainted in them.","ref":"Psalms 107:5","synthesized":"They were hungry and thirsty; their soul fainted within them.","sources":{"KJV":{"text":"Hungry and thirsty, their soul fainted in them."},"BSB":{"text":"They were hungry and thirsty; their soul fainted within them."}},"definableWords":["soul"],"peopleInVerse":[]},"6":{"text":"Then they cried unto the LORD in their trouble, and he delivered them out of their distresses.","ref":"Psalms 107:6","synthesized":"Then they cried out to the LORD in their trouble, and He delivered them from their distress.","sources":{"KJV":{"text":"Then they cried unto the LORD in their trouble, and he delivered them out of their distresses."},"BSB":{"text":"Then they cried out to the LORD in their trouble, and He delivered them from their distress."}},"definableWords":["LORD"],"peopleInVerse":[]},"7":{"text":"And he led them forth by the right way, that they might go to a city of habitation.","ref":"Psalms 107:7","synthesized":"He led them on a straight path to reach a city where they could live.","sources":{"KJV":{"text":"And he led them forth by the right way, that they might go to a city of habitation."},"BSB":{"text":"He led them on a straight path to reach a city where they could live."}},"definableWords":["live"],"peopleInVerse":[]},"8":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!","ref":"Psalms 107:8","synthesized":"Let them give thanks to the LORD for His loving devotion and His wonders to the sons of men.","sources":{"KJV":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!"},"BSB":{"text":"Let them give thanks to the LORD for His loving devotion and His wonders to the sons of men."}},"definableWords":["LORD","sons","men"],"peopleInVerse":[]},"9":{"text":"For he satisfieth the longing soul, and filleth the hungry soul with goodness.","ref":"Psalms 107:9","synthesized":"For He satisfies the thirsty and fills the hungry with good things.","sources":{"KJV":{"text":"For he satisfieth the longing soul, and filleth the hungry soul with goodness."},"BSB":{"text":"For He satisfies the thirsty and fills the hungry with good things."}},"definableWords":["good"],"peopleInVerse":[]},"10":{"text":"Such as sit in darkness and in the shadow of death, being bound in affliction and iron;","ref":"Psalms 107:10","synthesized":"Some sat in darkness and in the shadow of death, prisoners in affliction and chains,","sources":{"KJV":{"text":"Such as sit in darkness and in the shadow of death, being bound in affliction and iron;"},"BSB":{"text":"Some sat in darkness and in the shadow of death, prisoners in affliction and chains,"}},"definableWords":["darkness","death"],"peopleInVerse":[]},"11":{"text":"Because they rebelled against the words of God, and contemned the counsel of the most High:","ref":"Psalms 107:11","synthesized":"because they rebelled against the words of God and despised the counsel of the Most High.","sources":{"KJV":{"text":"Because they rebelled against the words of God, and contemned the counsel of the most High:"},"BSB":{"text":"because they rebelled against the words of God and despised the counsel of the Most High."}},"definableWords":["God"],"peopleInVerse":[]},"12":{"text":"Therefore he brought down their heart with labour; they fell down, and there was none to help.","ref":"Psalms 107:12","synthesized":"He humbled their hearts with hard labor; they stumbled, and there was no one to help.","sources":{"KJV":{"text":"Therefore he brought down their heart with labour; they fell down, and there was none to help."},"BSB":{"text":"He humbled their hearts with hard labor; they stumbled, and there was no one to help."}},"definableWords":["one"],"peopleInVerse":[]},"13":{"text":"Then they cried unto the LORD in their trouble, and he saved them out of their distresses.","ref":"Psalms 107:13","synthesized":"Then they cried out to the LORD in their trouble, and He saved them from their distress.","sources":{"KJV":{"text":"Then they cried unto the LORD in their trouble, and he saved them out of their distresses."},"BSB":{"text":"Then they cried out to the LORD in their trouble, and He saved them from their distress."}},"definableWords":["LORD"],"peopleInVerse":[]},"14":{"text":"He brought them out of darkness and the shadow of death, and brake their bands in sunder.","ref":"Psalms 107:14","synthesized":"He brought them out of darkness and the shadow of death and broke away their chains.","sources":{"KJV":{"text":"He brought them out of darkness and the shadow of death, and brake their bands in sunder."},"BSB":{"text":"He brought them out of darkness and the shadow of death and broke away their chains."}},"definableWords":["darkness","death"],"peopleInVerse":[]},"15":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!","ref":"Psalms 107:15","synthesized":"Let them give thanks to the LORD for His loving devotion and His wonders to the sons of men.","sources":{"KJV":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!"},"BSB":{"text":"Let them give thanks to the LORD for His loving devotion and His wonders to the sons of men."}},"definableWords":["LORD","sons","men"],"peopleInVerse":[]},"16":{"text":"For he hath broken the gates of brass, and cut the bars of iron in sunder.","ref":"Psalms 107:16","synthesized":"For He has broken down the gates of bronze and cut through the bars of iron.","sources":{"KJV":{"text":"For he hath broken the gates of brass, and cut the bars of iron in sunder."},"BSB":{"text":"For He has broken down the gates of bronze and cut through the bars of iron."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Fools because of their transgression, and because of their iniquities, are afflicted.","ref":"Psalms 107:17","synthesized":"Fools, in their rebellious ways, and through their iniquities, suffered affliction.","sources":{"KJV":{"text":"Fools because of their transgression, and because of their iniquities, are afflicted."},"BSB":{"text":"Fools, in their rebellious ways, and through their iniquities, suffered affliction."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Their soul abhorreth all manner of meat; and they draw near unto the gates of death.","ref":"Psalms 107:18","synthesized":"They loathed all food and drew near to the gates of death.","sources":{"KJV":{"text":"Their soul abhorreth all manner of meat; and they draw near unto the gates of death."},"BSB":{"text":"They loathed all food and drew near to the gates of death."}},"definableWords":["death"],"peopleInVerse":[]},"19":{"text":"Then they cry unto the LORD in their trouble, and he saveth them out of their distresses.","ref":"Psalms 107:19","synthesized":"Then they cried out to the LORD in their trouble, and He saved them from their distress.","sources":{"KJV":{"text":"Then they cry unto the LORD in their trouble, and he saveth them out of their distresses."},"BSB":{"text":"Then they cried out to the LORD in their trouble, and He saved them from their distress."}},"definableWords":["LORD"],"peopleInVerse":[]},"20":{"text":"He sent his word, and healed them, and delivered them from their destructions.","ref":"Psalms 107:20","synthesized":"He sent forth His word and healed them; He rescued them from the Pit.","sources":{"KJV":{"text":"He sent his word, and healed them, and delivered them from their destructions."},"BSB":{"text":"He sent forth His word and healed them; He rescued them from the Pit."}},"definableWords":["word"],"peopleInVerse":[]},"21":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!","ref":"Psalms 107:21","synthesized":"Let them give thanks to the LORD for His loving devotion and His wonders to the sons of men.","sources":{"KJV":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!"},"BSB":{"text":"Let them give thanks to the LORD for His loving devotion and His wonders to the sons of men."}},"definableWords":["LORD","sons","men"],"peopleInVerse":[]},"22":{"text":"And let them sacrifice the sacrifices of thanksgiving, and declare his works with rejoicing.","ref":"Psalms 107:22","synthesized":"Let them offer sacrifices of thanksgiving and declare His works with rejoicing.","sources":{"KJV":{"text":"And let them sacrifice the sacrifices of thanksgiving, and declare his works with rejoicing."},"BSB":{"text":"Let them offer sacrifices of thanksgiving and declare His works with rejoicing."}},"definableWords":["works"],"peopleInVerse":[]},"23":{"text":"They that go down to the sea in ships, that do business in great waters;","ref":"Psalms 107:23","synthesized":"Others went out to sea in ships, conducting trade on the mighty waters.","sources":{"KJV":{"text":"They that go down to the sea in ships, that do business in great waters;"},"BSB":{"text":"Others went out to sea in ships, conducting trade on the mighty waters."}},"definableWords":["sea","mighty","waters"],"peopleInVerse":[]},"24":{"text":"These see the works of the LORD, and his wonders in the deep.","ref":"Psalms 107:24","synthesized":"They saw the works of the LORD, and His wonders in the deep.","sources":{"KJV":{"text":"These see the works of the LORD, and his wonders in the deep."},"BSB":{"text":"They saw the works of the LORD, and His wonders in the deep."}},"definableWords":["saw","works","LORD","deep"],"peopleInVerse":[]},"25":{"text":"For he commandeth, and raiseth the stormy wind, which lifteth up the waves thereof.","ref":"Psalms 107:25","synthesized":"For He spoke and raised a tempest that lifted the waves of the sea.","sources":{"KJV":{"text":"For he commandeth, and raiseth the stormy wind, which lifteth up the waves thereof."},"BSB":{"text":"For He spoke and raised a tempest that lifted the waves of the sea."}},"definableWords":["sea"],"peopleInVerse":[]},"26":{"text":"They mount up to the heaven, they go down again to the depths: their soul is melted because of trouble.","ref":"Psalms 107:26","synthesized":"They mounted up to the heavens, then sunk to the depths; their courage melted in their anguish.","sources":{"KJV":{"text":"They mount up to the heaven, they go down again to the depths: their soul is melted because of trouble."},"BSB":{"text":"They mounted up to the heavens, then sunk to the depths; their courage melted in their anguish."}},"definableWords":["heavens"],"peopleInVerse":[]},"27":{"text":"They reel to and fro, and stagger like a drunken man, and are at their wit’s end.","ref":"Psalms 107:27","synthesized":"They reeled and staggered like drunkards, and all their skill was useless.","sources":{"KJV":{"text":"They reel to and fro, and stagger like a drunken man, and are at their wit’s end."},"BSB":{"text":"They reeled and staggered like drunkards, and all their skill was useless."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"Then they cry unto the LORD in their trouble, and he bringeth them out of their distresses.","ref":"Psalms 107:28","synthesized":"Then they cried out to the LORD in their trouble, and He brought them out of their distress.","sources":{"KJV":{"text":"Then they cry unto the LORD in their trouble, and he bringeth them out of their distresses."},"BSB":{"text":"Then they cried out to the LORD in their trouble, and He brought them out of their distress."}},"definableWords":["LORD"],"peopleInVerse":[]},"29":{"text":"He maketh the storm a calm, so that the waves thereof are still.","ref":"Psalms 107:29","synthesized":"He calmed the storm to a whisper, and the waves of the sea were hushed.","sources":{"KJV":{"text":"He maketh the storm a calm, so that the waves thereof are still."},"BSB":{"text":"He calmed the storm to a whisper, and the waves of the sea were hushed."}},"definableWords":["sea"],"peopleInVerse":[]},"30":{"text":"Then are they glad because they be quiet; so he bringeth them unto their desired haven.","ref":"Psalms 107:30","synthesized":"They rejoiced in the silence, and He guided them to the harbor they desired.","sources":{"KJV":{"text":"Then are they glad because they be quiet; so he bringeth them unto their desired haven."},"BSB":{"text":"They rejoiced in the silence, and He guided them to the harbor they desired."}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!","ref":"Psalms 107:31","synthesized":"Let them give thanks to the LORD for His loving devotion and His wonders to the sons of men.","sources":{"KJV":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!"},"BSB":{"text":"Let them give thanks to the LORD for His loving devotion and His wonders to the sons of men."}},"definableWords":["LORD","sons","men"],"peopleInVerse":[]},"32":{"text":"Let them exalt him also in the congregation of the people, and praise him in the assembly of the elders.","ref":"Psalms 107:32","synthesized":"Let them exalt Him in the assembly of the people and praise Him in the council of the elders.","sources":{"KJV":{"text":"Let them exalt him also in the congregation of the people, and praise him in the assembly of the elders."},"BSB":{"text":"Let them exalt Him in the assembly of the people and praise Him in the council of the elders."}},"definableWords":["people","praise"],"peopleInVerse":[]},"33":{"text":"He turneth rivers into a wilderness, and the watersprings into dry ground;","ref":"Psalms 107:33","synthesized":"He turns rivers into deserts, springs of water into thirsty ground,","sources":{"KJV":{"text":"He turneth rivers into a wilderness, and the watersprings into dry ground;"},"BSB":{"text":"He turns rivers into deserts, springs of water into thirsty ground,"}},"definableWords":["water","ground"],"peopleInVerse":[]},"34":{"text":"A fruitful land into barrenness, for the wickedness of them that dwell therein.","ref":"Psalms 107:34","synthesized":"and fruitful land into fields of salt, because of the wickedness of its dwellers.","sources":{"KJV":{"text":"A fruitful land into barrenness, for the wickedness of them that dwell therein."},"BSB":{"text":"and fruitful land into fields of salt, because of the wickedness of its dwellers."}},"definableWords":["fruitful","land"],"peopleInVerse":[]},"35":{"text":"He turneth the wilderness into a standing water, and dry ground into watersprings.","ref":"Psalms 107:35","synthesized":"He turns a desert into pools of water and a dry land into flowing springs.","sources":{"KJV":{"text":"He turneth the wilderness into a standing water, and dry ground into watersprings."},"BSB":{"text":"He turns a desert into pools of water and a dry land into flowing springs."}},"definableWords":["water","land"],"peopleInVerse":[]},"36":{"text":"And there he maketh the hungry to dwell, that they may prepare a city for habitation;","ref":"Psalms 107:36","synthesized":"He causes the hungry to settle there, that they may establish a city in which to dwell.","sources":{"KJV":{"text":"And there he maketh the hungry to dwell, that they may prepare a city for habitation;"},"BSB":{"text":"He causes the hungry to settle there, that they may establish a city in which to dwell."}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"And sow the fields, and plant vineyards, which may yield fruits of increase.","ref":"Psalms 107:37","synthesized":"They sow fields and plant vineyards that yield a fruitful harvest.","sources":{"KJV":{"text":"And sow the fields, and plant vineyards, which may yield fruits of increase."},"BSB":{"text":"They sow fields and plant vineyards that yield a fruitful harvest."}},"definableWords":["fruitful"],"peopleInVerse":[]},"38":{"text":"He blesseth them also, so that they are multiplied greatly; and suffereth not their cattle to decrease.","ref":"Psalms 107:38","synthesized":"He blesses them, and they multiply greatly; He does not let their herds diminish.","sources":{"KJV":{"text":"He blesseth them also, so that they are multiplied greatly; and suffereth not their cattle to decrease."},"BSB":{"text":"He blesses them, and they multiply greatly; He does not let their herds diminish."}},"definableWords":["multiply"],"peopleInVerse":[]},"39":{"text":"Again, they are minished and brought low through oppression, affliction, and sorrow.","ref":"Psalms 107:39","synthesized":"When they are decreased and humbled by oppression, evil, and sorrow,","sources":{"KJV":{"text":"Again, they are minished and brought low through oppression, affliction, and sorrow."},"BSB":{"text":"When they are decreased and humbled by oppression, evil, and sorrow,"}},"definableWords":["evil"],"peopleInVerse":[]},"40":{"text":"He poureth contempt upon princes, and causeth them to wander in the wilderness, where there is no way.","ref":"Psalms 107:40","synthesized":"He pours out contempt on the nobles and makes them wander in a trackless wasteland.","sources":{"KJV":{"text":"He poureth contempt upon princes, and causeth them to wander in the wilderness, where there is no way."},"BSB":{"text":"He pours out contempt on the nobles and makes them wander in a trackless wasteland."}},"definableWords":[],"peopleInVerse":[]},"41":{"text":"Yet setteth he the poor on high from affliction, and maketh him families like a flock.","ref":"Psalms 107:41","synthesized":"But He lifts the needy from affliction and increases their families like flocks.","sources":{"KJV":{"text":"Yet setteth he the poor on high from affliction, and maketh him families like a flock."},"BSB":{"text":"But He lifts the needy from affliction and increases their families like flocks."}},"definableWords":["families"],"peopleInVerse":[]},"42":{"text":"The righteous shall see it, and rejoice: and all iniquity shall stop her mouth.","ref":"Psalms 107:42","synthesized":"The upright see and rejoice, and all iniquity shuts its mouth.","sources":{"KJV":{"text":"The righteous shall see it, and rejoice: and all iniquity shall stop her mouth."},"BSB":{"text":"The upright see and rejoice, and all iniquity shuts its mouth."}},"definableWords":["see","iniquity"],"peopleInVerse":[]},"43":{"text":"Whoso is wise, and will observe these things, even they shall understand the lovingkindness of the LORD.","ref":"Psalms 107:43","synthesized":"Let him who is wise pay heed to these things and consider the loving devotion of the LORD.","sources":{"KJV":{"text":"Whoso is wise, and will observe these things, even they shall understand the lovingkindness of the LORD."},"BSB":{"text":"Let him who is wise pay heed to these things and consider the loving devotion of the LORD."}},"definableWords":["LORD"],"peopleInVerse":[]}}},"108":{"chapter":"108","title":"O GOD, MY HEART IS FIXED","verses":{"1":{"text":"O God, my heart is fixed; I will sing and give praise, even with my glory.","ref":"Psalms 108:1","synthesized":"My heart is steadfast, O God; I will sing and make music with all my being.","sources":{"KJV":{"text":"O God, my heart is fixed; I will sing and give praise, even with my glory."},"BSB":{"text":"My heart is steadfast, O God; I will sing and make music with all my being."}},"definableWords":["heart","God","make"],"peopleInVerse":[]},"2":{"text":"Awake, psaltery and harp: I myself will awake early.","ref":"Psalms 108:2","synthesized":"Awake, O harp and lyre! I will awaken the dawn.","sources":{"KJV":{"text":"Awake, psaltery and harp: I myself will awake early."},"BSB":{"text":"Awake, O harp and lyre! I will awaken the dawn."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"I will praise thee, O LORD, among the people: and I will sing praises unto thee among the nations.","ref":"Psalms 108:3","synthesized":"I will praise You, O LORD, among the nations; I will sing Your praises among the peoples.","sources":{"KJV":{"text":"I will praise thee, O LORD, among the people: and I will sing praises unto thee among the nations."},"BSB":{"text":"I will praise You, O LORD, among the nations; I will sing Your praises among the peoples."}},"definableWords":["praise","LORD","nations"],"peopleInVerse":[]},"4":{"text":"For thy mercy is great above the heavens: and thy truth reacheth unto the clouds.","ref":"Psalms 108:4","synthesized":"For Your loving devotion extends beyond the heavens, and Your faithfulness reaches to the clouds.","sources":{"KJV":{"text":"For thy mercy is great above the heavens: and thy truth reacheth unto the clouds."},"BSB":{"text":"For Your loving devotion extends beyond the heavens, and Your faithfulness reaches to the clouds."}},"definableWords":["heavens"],"peopleInVerse":[]},"5":{"text":"Be thou exalted, O God, above the heavens: and thy glory above all the earth;","ref":"Psalms 108:5","synthesized":"Be exalted, O God, above the heavens; may Your glory cover all the earth.","sources":{"KJV":{"text":"Be thou exalted, O God, above the heavens: and thy glory above all the earth;"},"BSB":{"text":"Be exalted, O God, above the heavens; may Your glory cover all the earth."}},"definableWords":["God","heavens","glory","earth"],"peopleInVerse":[]},"6":{"text":"That thy beloved may be delivered: save with thy right hand, and answer me.","ref":"Psalms 108:6","synthesized":"Respond and save us with Your right hand, that Your beloved may be delivered.","sources":{"KJV":{"text":"That thy beloved may be delivered: save with thy right hand, and answer me."},"BSB":{"text":"Respond and save us with Your right hand, that Your beloved may be delivered."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"God hath spoken in his holiness; I will rejoice, I will divide Shechem, and mete out the valley of Succoth.","ref":"Psalms 108:7","synthesized":"God has spoken from His sanctuary: “I will triumph! I will parcel out Shechem and apportion the Valley of Succoth.","sources":{"KJV":{"text":"God hath spoken in his holiness; I will rejoice, I will divide Shechem, and mete out the valley of Succoth."},"BSB":{"text":"God has spoken from His sanctuary: “I will triumph! I will parcel out Shechem and apportion the Valley of Succoth."}},"definableWords":["God"],"peopleInVerse":[]},"8":{"text":"Gilead is mine; Manasseh is mine; Ephraim also is the strength of mine head; Judah is my lawgiver;","ref":"Psalms 108:8","synthesized":"Gilead is Mine, and Manasseh is Mine; Ephraim is My helmet, Judah is My scepter.","sources":{"KJV":{"text":"Gilead is mine; Manasseh is mine; Ephraim also is the strength of mine head; Judah is my lawgiver;"},"BSB":{"text":"Gilead is Mine, and Manasseh is Mine; Ephraim is My helmet, Judah is My scepter."}},"definableWords":["Judah","scepter"],"peopleInVerse":[]},"9":{"text":"Moab is my washpot; over Edom will I cast out my shoe; over Philistia will I triumph.","ref":"Psalms 108:9","synthesized":"Moab is My washbasin; upon Edom I toss My sandal; over Philistia I shout in triumph.”","sources":{"KJV":{"text":"Moab is my washpot; over Edom will I cast out my shoe; over Philistia will I triumph."},"BSB":{"text":"Moab is My washbasin; upon Edom I toss My sandal; over Philistia I shout in triumph.”"}},"definableWords":["Edom"],"peopleInVerse":[]},"10":{"text":"Who will bring me into the strong city? who will lead me into Edom?","ref":"Psalms 108:10","synthesized":"Who will bring me to the fortified city? Who will lead me to Edom?","sources":{"KJV":{"text":"Who will bring me into the strong city? who will lead me into Edom?"},"BSB":{"text":"Who will bring me to the fortified city? Who will lead me to Edom?"}},"definableWords":["Edom"],"peopleInVerse":[]},"11":{"text":"Wilt not thou, O God, who hast cast us off? and wilt not thou, O God, go forth with our hosts?","ref":"Psalms 108:11","synthesized":"Have You not rejected us, O God? Will You no longer march out, O God, with our armies?","sources":{"KJV":{"text":"Wilt not thou, O God, who hast cast us off? and wilt not thou, O God, go forth with our hosts?"},"BSB":{"text":"Have You not rejected us, O God? Will You no longer march out, O God, with our armies?"}},"definableWords":["God"],"peopleInVerse":[]},"12":{"text":"Give us help from trouble: for vain is the help of man.","ref":"Psalms 108:12","synthesized":"Give us aid against the enemy, for the help of man is worthless.","sources":{"KJV":{"text":"Give us help from trouble: for vain is the help of man."},"BSB":{"text":"Give us aid against the enemy, for the help of man is worthless."}},"definableWords":["man"],"peopleInVerse":[]},"13":{"text":"Through God we shall do valiantly: for he it is that shall tread down our enemies.","ref":"Psalms 108:13","synthesized":"With God we will perform with valor, and He will trample our enemies.","sources":{"KJV":{"text":"Through God we shall do valiantly: for he it is that shall tread down our enemies."},"BSB":{"text":"With God we will perform with valor, and He will trample our enemies."}},"definableWords":["God"],"peopleInVerse":[]}}},"109":{"chapter":"109","title":"HOLD NOT THY PEACE, O GOD","verses":{"1":{"text":"Hold not thy peace, O God of my praise;","ref":"Psalms 109:1","synthesized":"O God of my praise, be not silent.","sources":{"KJV":{"text":"Hold not thy peace, O God of my praise;"},"BSB":{"text":"O God of my praise, be not silent."}},"definableWords":["God","praise"],"peopleInVerse":[]},"2":{"text":"For the mouth of the wicked and the mouth of the deceitful are opened against me: they have spoken against me with a lying tongue.","ref":"Psalms 109:2","synthesized":"For wicked and deceitful mouths open against me; they speak against me with lying tongues.","sources":{"KJV":{"text":"For the mouth of the wicked and the mouth of the deceitful are opened against me: they have spoken against me with a lying tongue."},"BSB":{"text":"For wicked and deceitful mouths open against me; they speak against me with lying tongues."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"They compassed me about also with words of hatred; and fought against me without a cause.","ref":"Psalms 109:3","synthesized":"They surround me with hateful words and attack me without cause.","sources":{"KJV":{"text":"They compassed me about also with words of hatred; and fought against me without a cause."},"BSB":{"text":"They surround me with hateful words and attack me without cause."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"For my love they are my adversaries: but I give myself unto prayer.","ref":"Psalms 109:4","synthesized":"In return for my love they accuse me, but I am a man of prayer.","sources":{"KJV":{"text":"For my love they are my adversaries: but I give myself unto prayer."},"BSB":{"text":"In return for my love they accuse me, but I am a man of prayer."}},"definableWords":["love","man","prayer"],"peopleInVerse":[]},"5":{"text":"And they have rewarded me evil for good, and hatred for my love.","ref":"Psalms 109:5","synthesized":"They repay me evil for good, and hatred for my love.","sources":{"KJV":{"text":"And they have rewarded me evil for good, and hatred for my love."},"BSB":{"text":"They repay me evil for good, and hatred for my love."}},"definableWords":["evil","good","love"],"peopleInVerse":[]},"6":{"text":"Set thou a wicked man over him: and let Satan stand at his right hand.","ref":"Psalms 109:6","synthesized":"Set over him a wicked man; let an accuser stand at his right hand.","sources":{"KJV":{"text":"Set thou a wicked man over him: and let Satan stand at his right hand."},"BSB":{"text":"Set over him a wicked man; let an accuser stand at his right hand."}},"definableWords":["man","stand"],"peopleInVerse":[]},"7":{"text":"When he shall be judged, let him be condemned: and let his prayer become sin.","ref":"Psalms 109:7","synthesized":"When he is tried, let him be found guilty, and may his prayer be regarded as sin.","sources":{"KJV":{"text":"When he shall be judged, let him be condemned: and let his prayer become sin."},"BSB":{"text":"When he is tried, let him be found guilty, and may his prayer be regarded as sin."}},"definableWords":["prayer","sin"],"peopleInVerse":[]},"8":{"text":"Let his days be few; and let another take his office.","ref":"Psalms 109:8","synthesized":"May his days be few; may another take his position.","sources":{"KJV":{"text":"Let his days be few; and let another take his office."},"BSB":{"text":"May his days be few; may another take his position."}},"definableWords":["days"],"peopleInVerse":[]},"9":{"text":"Let his children be fatherless, and his wife a widow.","ref":"Psalms 109:9","synthesized":"May his children be fatherless and his wife a widow.","sources":{"KJV":{"text":"Let his children be fatherless, and his wife a widow."},"BSB":{"text":"May his children be fatherless and his wife a widow."}},"definableWords":["wife","widow"],"peopleInVerse":[]},"10":{"text":"Let his children be continually vagabonds, and beg: let them seek their bread also out of their desolate places.","ref":"Psalms 109:10","synthesized":"May his children wander as beggars, seeking sustenance far from their ruined homes.","sources":{"KJV":{"text":"Let his children be continually vagabonds, and beg: let them seek their bread also out of their desolate places."},"BSB":{"text":"May his children wander as beggars, seeking sustenance far from their ruined homes."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Let the extortioner catch all that he hath; and let the strangers spoil his labour.","ref":"Psalms 109:11","synthesized":"May the creditor seize all he owns, and strangers plunder the fruits of his labor.","sources":{"KJV":{"text":"Let the extortioner catch all that he hath; and let the strangers spoil his labour."},"BSB":{"text":"May the creditor seize all he owns, and strangers plunder the fruits of his labor."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Let there be none to extend mercy unto him: neither let there be any to favour his fatherless children.","ref":"Psalms 109:12","synthesized":"May there be no one to extend kindness to him, and no one to favor his fatherless children.","sources":{"KJV":{"text":"Let there be none to extend mercy unto him: neither let there be any to favour his fatherless children."},"BSB":{"text":"May there be no one to extend kindness to him, and no one to favor his fatherless children."}},"definableWords":["one","kindness"],"peopleInVerse":[]},"13":{"text":"Let his posterity be cut off; and in the generation following let their name be blotted out.","ref":"Psalms 109:13","synthesized":"May his descendants be cut off; may their name be blotted out from the next generation.","sources":{"KJV":{"text":"Let his posterity be cut off; and in the generation following let their name be blotted out."},"BSB":{"text":"May his descendants be cut off; may their name be blotted out from the next generation."}},"definableWords":["name"],"peopleInVerse":[]},"14":{"text":"Let the iniquity of his fathers be remembered with the LORD; and let not the sin of his mother be blotted out.","ref":"Psalms 109:14","synthesized":"May the iniquity of his fathers be remembered before the LORD, and the sin of his mother never be blotted out.","sources":{"KJV":{"text":"Let the iniquity of his fathers be remembered with the LORD; and let not the sin of his mother be blotted out."},"BSB":{"text":"May the iniquity of his fathers be remembered before the LORD, and the sin of his mother never be blotted out."}},"definableWords":["iniquity","fathers","remembered","LORD","sin","mother"],"peopleInVerse":[]},"15":{"text":"Let them be before the LORD continually, that he may cut off the memory of them from the earth.","ref":"Psalms 109:15","synthesized":"May their sins always remain before the LORD, that He may cut off their memory from the earth.","sources":{"KJV":{"text":"Let them be before the LORD continually, that he may cut off the memory of them from the earth."},"BSB":{"text":"May their sins always remain before the LORD, that He may cut off their memory from the earth."}},"definableWords":["LORD","earth"],"peopleInVerse":[]},"16":{"text":"Because that he remembered not to shew mercy, but persecuted the poor and needy man, that he might even slay the broken in heart.","ref":"Psalms 109:16","synthesized":"For he never thought to show kindness, but pursued the poor and needy and brokenhearted, even to their death.","sources":{"KJV":{"text":"Because that he remembered not to shew mercy, but persecuted the poor and needy man, that he might even slay the broken in heart."},"BSB":{"text":"For he never thought to show kindness, but pursued the poor and needy and brokenhearted, even to their death."}},"definableWords":["kindness","death"],"peopleInVerse":[]},"17":{"text":"As he loved cursing, so let it come unto him: as he delighted not in blessing, so let it be far from him.","ref":"Psalms 109:17","synthesized":"The cursing that he loved, may it fall on him; the blessing in which he refused to delight, may it be far from him.","sources":{"KJV":{"text":"As he loved cursing, so let it come unto him: as he delighted not in blessing, so let it be far from him."},"BSB":{"text":"The cursing that he loved, may it fall on him; the blessing in which he refused to delight, may it be far from him."}},"definableWords":["blessing"],"peopleInVerse":[]},"18":{"text":"As he clothed himself with cursing like as with his garment, so let it come into his bowels like water, and like oil into his bones.","ref":"Psalms 109:18","synthesized":"The cursing that he wore like a coat, may it soak into his body like water, and into his bones like oil.","sources":{"KJV":{"text":"As he clothed himself with cursing like as with his garment, so let it come into his bowels like water, and like oil into his bones."},"BSB":{"text":"The cursing that he wore like a coat, may it soak into his body like water, and into his bones like oil."}},"definableWords":["water","bones"],"peopleInVerse":[]},"19":{"text":"Let it be unto him as the garment which covereth him, and for a girdle wherewith he is girded continually.","ref":"Psalms 109:19","synthesized":"May it be like a robe wrapped about him, like a belt tied forever around him.","sources":{"KJV":{"text":"Let it be unto him as the garment which covereth him, and for a girdle wherewith he is girded continually."},"BSB":{"text":"May it be like a robe wrapped about him, like a belt tied forever around him."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Let this be the reward of mine adversaries from the LORD, and of them that speak evil against my soul.","ref":"Psalms 109:20","synthesized":"May this be the LORD’s reward to my accusers, to those who speak evil against me.","sources":{"KJV":{"text":"Let this be the reward of mine adversaries from the LORD, and of them that speak evil against my soul."},"BSB":{"text":"May this be the LORD’s reward to my accusers, to those who speak evil against me."}},"definableWords":["LORD","evil"],"peopleInVerse":[]},"21":{"text":"But do thou for me, O GOD the Lord, for thy name’s sake: because thy mercy is good, deliver thou me.","ref":"Psalms 109:21","synthesized":"But You, O GOD, the Lord, deal kindly with me for the sake of Your name; deliver me by the goodness of Your loving devotion.","sources":{"KJV":{"text":"But do thou for me, O GOD the Lord, for thy name’s sake: because thy mercy is good, deliver thou me."},"BSB":{"text":"But You, O GOD, the Lord, deal kindly with me for the sake of Your name; deliver me by the goodness of Your loving devotion."}},"definableWords":["God","Lord","name","deliver"],"peopleInVerse":[]},"22":{"text":"For I am poor and needy, and my heart is wounded within me.","ref":"Psalms 109:22","synthesized":"For I am poor and needy; my heart is wounded within me.","sources":{"KJV":{"text":"For I am poor and needy, and my heart is wounded within me."},"BSB":{"text":"For I am poor and needy; my heart is wounded within me."}},"definableWords":["heart"],"peopleInVerse":[]},"23":{"text":"I am gone like the shadow when it declineth: I am tossed up and down as the locust.","ref":"Psalms 109:23","synthesized":"I am fading away like a lengthening shadow; I am shaken off like a locust.","sources":{"KJV":{"text":"I am gone like the shadow when it declineth: I am tossed up and down as the locust."},"BSB":{"text":"I am fading away like a lengthening shadow; I am shaken off like a locust."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"My knees are weak through fasting; and my flesh faileth of fatness.","ref":"Psalms 109:24","synthesized":"My knees are weak from fasting, and my body grows lean and gaunt.","sources":{"KJV":{"text":"My knees are weak through fasting; and my flesh faileth of fatness."},"BSB":{"text":"My knees are weak from fasting, and my body grows lean and gaunt."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"I became also a reproach unto them: when they looked upon me they shaked their heads.","ref":"Psalms 109:25","synthesized":"I am an object of scorn to my accusers; when they see me, they shake their heads.","sources":{"KJV":{"text":"I became also a reproach unto them: when they looked upon me they shaked their heads."},"BSB":{"text":"I am an object of scorn to my accusers; when they see me, they shake their heads."}},"definableWords":["see"],"peopleInVerse":[]},"26":{"text":"Help me, O LORD my God: O save me according to thy mercy:","ref":"Psalms 109:26","synthesized":"Help me, O LORD my God; save me according to Your loving devotion.","sources":{"KJV":{"text":"Help me, O LORD my God: O save me according to thy mercy:"},"BSB":{"text":"Help me, O LORD my God; save me according to Your loving devotion."}},"definableWords":["LORD","God"],"peopleInVerse":[]},"27":{"text":"That they may know that this is thy hand; that thou, LORD, hast done it.","ref":"Psalms 109:27","synthesized":"Let them know that this is Your hand, that You, O LORD, have done it.","sources":{"KJV":{"text":"That they may know that this is thy hand; that thou, LORD, hast done it."},"BSB":{"text":"Let them know that this is Your hand, that You, O LORD, have done it."}},"definableWords":["LORD"],"peopleInVerse":[]},"28":{"text":"Let them curse, but bless thou: when they arise, let them be ashamed; but let thy servant rejoice.","ref":"Psalms 109:28","synthesized":"Though they curse, You will bless. When they rise up, they will be put to shame, but Your servant will rejoice.","sources":{"KJV":{"text":"Let them curse, but bless thou: when they arise, let them be ashamed; but let thy servant rejoice."},"BSB":{"text":"Though they curse, You will bless. When they rise up, they will be put to shame, but Your servant will rejoice."}},"definableWords":["curse","bless","servant"],"peopleInVerse":[]},"29":{"text":"Let mine adversaries be clothed with shame, and let them cover themselves with their own confusion, as with a mantle.","ref":"Psalms 109:29","synthesized":"May my accusers be clothed with disgrace; may they wear their shame like a robe.","sources":{"KJV":{"text":"Let mine adversaries be clothed with shame, and let them cover themselves with their own confusion, as with a mantle."},"BSB":{"text":"May my accusers be clothed with disgrace; may they wear their shame like a robe."}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"I will greatly praise the LORD with my mouth; yea, I will praise him among the multitude.","ref":"Psalms 109:30","synthesized":"With my mouth I will thank the LORD profusely; I will praise Him in the presence of many.","sources":{"KJV":{"text":"I will greatly praise the LORD with my mouth; yea, I will praise him among the multitude."},"BSB":{"text":"With my mouth I will thank the LORD profusely; I will praise Him in the presence of many."}},"definableWords":["LORD","praise"],"peopleInVerse":[]},"31":{"text":"For he shall stand at the right hand of the poor, to save him from those that condemn his soul.","ref":"Psalms 109:31","synthesized":"For He stands at the right hand of the needy one, to save him from the condemners of his soul.","sources":{"KJV":{"text":"For he shall stand at the right hand of the poor, to save him from those that condemn his soul."},"BSB":{"text":"For He stands at the right hand of the needy one, to save him from the condemners of his soul."}},"definableWords":["one","soul"],"peopleInVerse":[]}}},"110":{"chapter":"110","title":"THE LORD SAID UNTO MY LORD","verses":{"1":{"text":"The LORD said unto my Lord, Sit thou at my right hand, until I make thine enemies thy footstool.","ref":"Psalms 110:1","synthesized":"The LORD said to my Lord: “Sit at My right hand until I make Your enemies a footstool for Your feet.”","sources":{"KJV":{"text":"The LORD said unto my Lord, Sit thou at my right hand, until I make thine enemies thy footstool."},"BSB":{"text":"The LORD said to my Lord: “Sit at My right hand until I make Your enemies a footstool for Your feet.”"}},"definableWords":["LORD","Lord","make"],"peopleInVerse":[]},"2":{"text":"The LORD shall send the rod of thy strength out of Zion: rule thou in the midst of thine enemies.","ref":"Psalms 110:2","synthesized":"The LORD extends Your mighty scepter from Zion: “Rule in the midst of Your enemies.”","sources":{"KJV":{"text":"The LORD shall send the rod of thy strength out of Zion: rule thou in the midst of thine enemies."},"BSB":{"text":"The LORD extends Your mighty scepter from Zion: “Rule in the midst of Your enemies.”"}},"definableWords":["LORD","mighty","scepter","Zion","rule"],"peopleInVerse":[]},"3":{"text":"Thy people shall be willing in the day of thy power, in the beauties of holiness from the womb of the morning: thou hast the dew of thy youth.","ref":"Psalms 110:3","synthesized":"Your people shall be willing on Your day of battle. Arrayed in holy splendor, from the womb of the dawn, to You belongs the dew of Your youth.","sources":{"KJV":{"text":"Thy people shall be willing in the day of thy power, in the beauties of holiness from the womb of the morning: thou hast the dew of thy youth."},"BSB":{"text":"Your people shall be willing on Your day of battle. Arrayed in holy splendor, from the womb of the dawn, to You belongs the dew of Your youth."}},"definableWords":["people","day","holy"],"peopleInVerse":[]},"4":{"text":"The LORD hath sworn, and will not repent, Thou art a priest for ever after the order of Melchizedek.","ref":"Psalms 110:4","synthesized":"The LORD has sworn and will not change His mind: “You are a priest forever in the order of Melchizedek.”","sources":{"KJV":{"text":"The LORD hath sworn, and will not repent, Thou art a priest for ever after the order of Melchizedek."},"BSB":{"text":"The LORD has sworn and will not change His mind: “You are a priest forever in the order of Melchizedek.”"}},"definableWords":["LORD","mind","priest","Melchizedek"],"peopleInVerse":[]},"5":{"text":"The Lord at thy right hand shall strike through kings in the day of his wrath.","ref":"Psalms 110:5","synthesized":"The Lord is at Your right hand; He will crush kings in the day of His wrath.","sources":{"KJV":{"text":"The Lord at thy right hand shall strike through kings in the day of his wrath."},"BSB":{"text":"The Lord is at Your right hand; He will crush kings in the day of His wrath."}},"definableWords":["Lord","kings","day","wrath"],"peopleInVerse":[]},"6":{"text":"He shall judge among the heathen, he shall fill the places with the dead bodies; he shall wound the heads over many countries.","ref":"Psalms 110:6","synthesized":"He will judge the nations, heaping up the dead; He will crush the leaders far and wide.","sources":{"KJV":{"text":"He shall judge among the heathen, he shall fill the places with the dead bodies; he shall wound the heads over many countries."},"BSB":{"text":"He will judge the nations, heaping up the dead; He will crush the leaders far and wide."}},"definableWords":["nations"],"peopleInVerse":[]},"7":{"text":"He shall drink of the brook in the way: therefore shall he lift up the head.","ref":"Psalms 110:7","synthesized":"He will drink from the brook by the road; therefore He will lift up His head.","sources":{"KJV":{"text":"He shall drink of the brook in the way: therefore shall he lift up the head."},"BSB":{"text":"He will drink from the brook by the road; therefore He will lift up His head."}},"definableWords":[],"peopleInVerse":[]}}},"111":{"chapter":"111","title":"PRAISE YE THE LORD WITH WHOLE HEART","verses":{"1":{"text":"Praise ye the LORD. I will praise the LORD with my whole heart, in the assembly of the upright, and in the congregation.","ref":"Psalms 111:1","synthesized":"Hallelujah!   I will give thanks to the LORD with all my heart in the council of the upright and in the assembly.","sources":{"KJV":{"text":"Praise ye the LORD. I will praise the LORD with my whole heart, in the assembly of the upright, and in the congregation."},"BSB":{"text":"Hallelujah!   I will give thanks to the LORD with all my heart in the council of the upright and in the assembly."}},"definableWords":["LORD","heart"],"peopleInVerse":[]},"2":{"text":"The works of the LORD are great, sought out of all them that have pleasure therein.","ref":"Psalms 111:2","synthesized":"Great are the works of the LORD; they are pondered by all who delight in them.","sources":{"KJV":{"text":"The works of the LORD are great, sought out of all them that have pleasure therein."},"BSB":{"text":"Great are the works of the LORD; they are pondered by all who delight in them."}},"definableWords":["great","works","LORD"],"peopleInVerse":[]},"3":{"text":"His work is honourable and glorious: and his righteousness endureth for ever.","ref":"Psalms 111:3","synthesized":"Splendid and majestic is His work; His righteousness endures forever.","sources":{"KJV":{"text":"His work is honourable and glorious: and his righteousness endureth for ever."},"BSB":{"text":"Splendid and majestic is His work; His righteousness endures forever."}},"definableWords":["work","righteousness"],"peopleInVerse":[]},"4":{"text":"He hath made his wonderful works to be remembered: the LORD is gracious and full of compassion.","ref":"Psalms 111:4","synthesized":"He has caused His wonders to be remembered; the LORD is gracious and compassionate.","sources":{"KJV":{"text":"He hath made his wonderful works to be remembered: the LORD is gracious and full of compassion."},"BSB":{"text":"He has caused His wonders to be remembered; the LORD is gracious and compassionate."}},"definableWords":["remembered","LORD"],"peopleInVerse":[]},"5":{"text":"He hath given meat unto them that fear him: he will ever be mindful of his covenant.","ref":"Psalms 111:5","synthesized":"He provides food for those who fear Him; He remembers His covenant forever.","sources":{"KJV":{"text":"He hath given meat unto them that fear him: he will ever be mindful of his covenant."},"BSB":{"text":"He provides food for those who fear Him; He remembers His covenant forever."}},"definableWords":["fear","covenant"],"peopleInVerse":[]},"6":{"text":"He hath shewed his people the power of his works, that he may give them the heritage of the heathen.","ref":"Psalms 111:6","synthesized":"He has shown His people the power of His works by giving them the inheritance of the nations.","sources":{"KJV":{"text":"He hath shewed his people the power of his works, that he may give them the heritage of the heathen."},"BSB":{"text":"He has shown His people the power of His works by giving them the inheritance of the nations."}},"definableWords":["people","works","nations"],"peopleInVerse":[]},"7":{"text":"The works of his hands are verity and judgment; all his commandments are sure.","ref":"Psalms 111:7","synthesized":"The works of His hands are truth and justice; all His precepts are trustworthy.","sources":{"KJV":{"text":"The works of his hands are verity and judgment; all his commandments are sure."},"BSB":{"text":"The works of His hands are truth and justice; all His precepts are trustworthy."}},"definableWords":["works","truth","justice"],"peopleInVerse":[]},"8":{"text":"They stand fast for ever and ever, and are done in truth and uprightness.","ref":"Psalms 111:8","synthesized":"They are upheld forever and ever, enacted in truth and uprightness.","sources":{"KJV":{"text":"They stand fast for ever and ever, and are done in truth and uprightness."},"BSB":{"text":"They are upheld forever and ever, enacted in truth and uprightness."}},"definableWords":["truth"],"peopleInVerse":[]},"9":{"text":"He sent redemption unto his people: he hath commanded his covenant for ever: holy and reverend is his name.","ref":"Psalms 111:9","synthesized":"He has sent redemption to His people; He has ordained His covenant forever; holy and awesome is His name.","sources":{"KJV":{"text":"He sent redemption unto his people: he hath commanded his covenant for ever: holy and reverend is his name."},"BSB":{"text":"He has sent redemption to His people; He has ordained His covenant forever; holy and awesome is His name."}},"definableWords":["redemption","people","covenant","holy","name"],"peopleInVerse":[]},"10":{"text":"The fear of the LORD is the beginning of wisdom: a good understanding have all they that do his commandments: his praise endureth for ever.","ref":"Psalms 111:10","synthesized":"The fear of the LORD is the beginning of wisdom; all who follow His precepts gain rich understanding.   His praise endures forever!","sources":{"KJV":{"text":"The fear of the LORD is the beginning of wisdom: a good understanding have all they that do his commandments: his praise endureth for ever."},"BSB":{"text":"The fear of the LORD is the beginning of wisdom; all who follow His precepts gain rich understanding.   His praise endures forever!"}},"definableWords":["fear","LORD","beginning","wisdom","praise"],"peopleInVerse":[]}}},"112":{"chapter":"112","title":"BLESSED IS THE MAN THAT FEARETH THE LORD","verses":{"1":{"text":"Praise ye the LORD. Blessed is the man that feareth the LORD, that delighteth greatly in his commandments.","ref":"Psalms 112:1","synthesized":"Hallelujah!   Blessed is the man who fears the LORD, who greatly delights in His commandments.","sources":{"KJV":{"text":"Praise ye the LORD. Blessed is the man that feareth the LORD, that delighteth greatly in his commandments."},"BSB":{"text":"Hallelujah!   Blessed is the man who fears the LORD, who greatly delights in His commandments."}},"definableWords":["blessed","man","LORD"],"peopleInVerse":[]},"2":{"text":"His seed shall be mighty upon earth: the generation of the upright shall be blessed.","ref":"Psalms 112:2","synthesized":"His descendants will be mighty in the land; the generation of the upright will be blessed.","sources":{"KJV":{"text":"His seed shall be mighty upon earth: the generation of the upright shall be blessed."},"BSB":{"text":"His descendants will be mighty in the land; the generation of the upright will be blessed."}},"definableWords":["mighty","land","blessed"],"peopleInVerse":[]},"3":{"text":"Wealth and riches shall be in his house: and his righteousness endureth for ever.","ref":"Psalms 112:3","synthesized":"Wealth and riches are in his house, and his righteousness endures forever.","sources":{"KJV":{"text":"Wealth and riches shall be in his house: and his righteousness endureth for ever."},"BSB":{"text":"Wealth and riches are in his house, and his righteousness endures forever."}},"definableWords":["house","righteousness"],"peopleInVerse":[]},"4":{"text":"Unto the upright there ariseth light in the darkness: he is gracious, and full of compassion, and righteous.","ref":"Psalms 112:4","synthesized":"Light dawns in the darkness for the upright— for the gracious, compassionate, and righteous.","sources":{"KJV":{"text":"Unto the upright there ariseth light in the darkness: he is gracious, and full of compassion, and righteous."},"BSB":{"text":"Light dawns in the darkness for the upright— for the gracious, compassionate, and righteous."}},"definableWords":["light","darkness","righteous"],"peopleInVerse":[]},"5":{"text":"A good man sheweth favour, and lendeth: he will guide his affairs with discretion.","ref":"Psalms 112:5","synthesized":"It is well with the man who is generous and lends freely, whose affairs are guided by justice.","sources":{"KJV":{"text":"A good man sheweth favour, and lendeth: he will guide his affairs with discretion."},"BSB":{"text":"It is well with the man who is generous and lends freely, whose affairs are guided by justice."}},"definableWords":["man","justice"],"peopleInVerse":[]},"6":{"text":"Surely he shall not be moved for ever: the righteous shall be in everlasting remembrance.","ref":"Psalms 112:6","synthesized":"Surely he will never be shaken; the righteous man will be remembered forever.","sources":{"KJV":{"text":"Surely he shall not be moved for ever: the righteous shall be in everlasting remembrance."},"BSB":{"text":"Surely he will never be shaken; the righteous man will be remembered forever."}},"definableWords":["righteous","man","remembered"],"peopleInVerse":[]},"7":{"text":"He shall not be afraid of evil tidings: his heart is fixed, trusting in the LORD.","ref":"Psalms 112:7","synthesized":"He does not fear bad news; his heart is steadfast, trusting in the LORD.","sources":{"KJV":{"text":"He shall not be afraid of evil tidings: his heart is fixed, trusting in the LORD."},"BSB":{"text":"He does not fear bad news; his heart is steadfast, trusting in the LORD."}},"definableWords":["fear","heart","LORD"],"peopleInVerse":[]},"8":{"text":"His heart is established, he shall not be afraid, until he see his desire upon his enemies.","ref":"Psalms 112:8","synthesized":"His heart is assured; he does not fear, until he looks in triumph on his foes.","sources":{"KJV":{"text":"His heart is established, he shall not be afraid, until he see his desire upon his enemies."},"BSB":{"text":"His heart is assured; he does not fear, until he looks in triumph on his foes."}},"definableWords":["heart","fear"],"peopleInVerse":[]},"9":{"text":"He hath dispersed, he hath given to the poor; his righteousness endureth for ever; his horn shall be exalted with honour.","ref":"Psalms 112:9","synthesized":"He has scattered abroad his gifts to the poor; his righteousness endures forever; his horn will be lifted high in honor.","sources":{"KJV":{"text":"He hath dispersed, he hath given to the poor; his righteousness endureth for ever; his horn shall be exalted with honour."},"BSB":{"text":"He has scattered abroad his gifts to the poor; his righteousness endures forever; his horn will be lifted high in honor."}},"definableWords":["righteousness"],"peopleInVerse":[]},"10":{"text":"The wicked shall see it, and be grieved; he shall gnash with his teeth, and melt away: the desire of the wicked shall perish.","ref":"Psalms 112:10","synthesized":"The wicked man will see and be grieved; he will gnash his teeth and waste away; the desires of the wicked will perish.","sources":{"KJV":{"text":"The wicked shall see it, and be grieved; he shall gnash with his teeth, and melt away: the desire of the wicked shall perish."},"BSB":{"text":"The wicked man will see and be grieved; he will gnash his teeth and waste away; the desires of the wicked will perish."}},"definableWords":["man","see"],"peopleInVerse":[]}}},"113":{"chapter":"113","title":"PRAISE, O YE SERVANTS OF THE LORD","verses":{"1":{"text":"Praise ye the LORD. Praise, O ye servants of the LORD, praise the name of the LORD.","ref":"Psalms 113:1","synthesized":"Hallelujah!   Give praise, O servants of the LORD; praise the name of the LORD.","sources":{"KJV":{"text":"Praise ye the LORD. Praise, O ye servants of the LORD, praise the name of the LORD."},"BSB":{"text":"Hallelujah!   Give praise, O servants of the LORD; praise the name of the LORD."}},"definableWords":["praise","servants","LORD","name","Lord"],"peopleInVerse":[]},"2":{"text":"Blessed be the name of the LORD from this time forth and for evermore.","ref":"Psalms 113:2","synthesized":"Blessed be the name of the LORD both now and forevermore.","sources":{"KJV":{"text":"Blessed be the name of the LORD from this time forth and for evermore."},"BSB":{"text":"Blessed be the name of the LORD both now and forevermore."}},"definableWords":["blessed","name","LORD"],"peopleInVerse":[]},"3":{"text":"From the rising of the sun unto the going down of the same the LORD’s name is to be praised.","ref":"Psalms 113:3","synthesized":"From where the sun rises to where it sets, the name of the LORD is praised.","sources":{"KJV":{"text":"From the rising of the sun unto the going down of the same the LORD’s name is to be praised."},"BSB":{"text":"From where the sun rises to where it sets, the name of the LORD is praised."}},"definableWords":["name","LORD"],"peopleInVerse":[]},"4":{"text":"The LORD is high above all nations, and his glory above the heavens.","ref":"Psalms 113:4","synthesized":"The LORD is exalted over all the nations, His glory above the heavens.","sources":{"KJV":{"text":"The LORD is high above all nations, and his glory above the heavens."},"BSB":{"text":"The LORD is exalted over all the nations, His glory above the heavens."}},"definableWords":["LORD","nations","glory","heavens"],"peopleInVerse":[]},"5":{"text":"Who is like unto the LORD our God, who dwelleth on high,","ref":"Psalms 113:5","synthesized":"Who is like the LORD our God, the One enthroned on high?","sources":{"KJV":{"text":"Who is like unto the LORD our God, who dwelleth on high,"},"BSB":{"text":"Who is like the LORD our God, the One enthroned on high?"}},"definableWords":["LORD","God","one"],"peopleInVerse":[]},"6":{"text":"Who humbleth himself to behold the things that are in heaven, and in the earth!","ref":"Psalms 113:6","synthesized":"He humbles Himself to behold the heavens and the earth.","sources":{"KJV":{"text":"Who humbleth himself to behold the things that are in heaven, and in the earth!"},"BSB":{"text":"He humbles Himself to behold the heavens and the earth."}},"definableWords":["heavens","earth"],"peopleInVerse":[]},"7":{"text":"He raiseth up the poor out of the dust, and lifteth the needy out of the dunghill;","ref":"Psalms 113:7","synthesized":"He raises the poor from the dust and lifts the needy from the dump","sources":{"KJV":{"text":"He raiseth up the poor out of the dust, and lifteth the needy out of the dunghill;"},"BSB":{"text":"He raises the poor from the dust and lifts the needy from the dump"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"That he may set him with princes, even with the princes of his people.","ref":"Psalms 113:8","synthesized":"to seat them with nobles, with the princes of His people.","sources":{"KJV":{"text":"That he may set him with princes, even with the princes of his people."},"BSB":{"text":"to seat them with nobles, with the princes of His people."}},"definableWords":["people"],"peopleInVerse":[]},"9":{"text":"He maketh the barren woman to keep house, and to be a joyful mother of children. Praise ye the LORD.","ref":"Psalms 113:9","synthesized":"He settles the barren woman in her home as a joyful mother to her children.   Hallelujah!","sources":{"KJV":{"text":"He maketh the barren woman to keep house, and to be a joyful mother of children. Praise ye the LORD."},"BSB":{"text":"He settles the barren woman in her home as a joyful mother to her children.   Hallelujah!"}},"definableWords":["woman","mother"],"peopleInVerse":[]}}},"114":{"chapter":"114","title":"WHEN ISRAEL WENT OUT OF EGYPT","verses":{"1":{"text":"When Israel went out of Egypt, the house of Jacob from a people of strange language;","ref":"Psalms 114:1","synthesized":"When Israel departed from Egypt, the house of Jacob from a people of foreign tongue,","sources":{"KJV":{"text":"When Israel went out of Egypt, the house of Jacob from a people of strange language;"},"BSB":{"text":"When Israel departed from Egypt, the house of Jacob from a people of foreign tongue,"}},"definableWords":["Israel","Egypt","house","Jacob","people"],"peopleInVerse":["Jacob"]},"2":{"text":"Judah was his sanctuary, and Israel his dominion.","ref":"Psalms 114:2","synthesized":"Judah became God’s sanctuary, and Israel His dominion.","sources":{"KJV":{"text":"Judah was his sanctuary, and Israel his dominion."},"BSB":{"text":"Judah became God’s sanctuary, and Israel His dominion."}},"definableWords":["Judah","God","Israel","dominion"],"peopleInVerse":[]},"3":{"text":"The sea saw it, and fled: Jordan was driven back.","ref":"Psalms 114:3","synthesized":"The sea observed and fled; the Jordan turned back;","sources":{"KJV":{"text":"The sea saw it, and fled: Jordan was driven back."},"BSB":{"text":"The sea observed and fled; the Jordan turned back;"}},"definableWords":["sea"],"peopleInVerse":[]},"4":{"text":"The mountains skipped like rams, and the little hills like lambs.","ref":"Psalms 114:4","synthesized":"the mountains skipped like rams, the hills like lambs.","sources":{"KJV":{"text":"The mountains skipped like rams, and the little hills like lambs."},"BSB":{"text":"the mountains skipped like rams, the hills like lambs."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"What ailed thee, O thou sea, that thou fleddest? thou Jordan, that thou wast driven back?","ref":"Psalms 114:5","synthesized":"Why was it, O sea, that you fled, O Jordan, that you turned back,","sources":{"KJV":{"text":"What ailed thee, O thou sea, that thou fleddest? thou Jordan, that thou wast driven back?"},"BSB":{"text":"Why was it, O sea, that you fled, O Jordan, that you turned back,"}},"definableWords":["sea"],"peopleInVerse":[]},"6":{"text":"Ye mountains, that ye skipped like rams; and ye little hills, like lambs?","ref":"Psalms 114:6","synthesized":"O mountains, that you skipped like rams, O hills, like lambs?","sources":{"KJV":{"text":"Ye mountains, that ye skipped like rams; and ye little hills, like lambs?"},"BSB":{"text":"O mountains, that you skipped like rams, O hills, like lambs?"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Tremble, thou earth, at the presence of the Lord, at the presence of the God of Jacob;","ref":"Psalms 114:7","synthesized":"Tremble, O earth, at the presence of the Lord, at the presence of the God of Jacob,","sources":{"KJV":{"text":"Tremble, thou earth, at the presence of the Lord, at the presence of the God of Jacob;"},"BSB":{"text":"Tremble, O earth, at the presence of the Lord, at the presence of the God of Jacob,"}},"definableWords":["earth","Lord","God","Jacob"],"peopleInVerse":["Jacob"]},"8":{"text":"Which turned the rock into a standing water, the flint into a fountain of waters.","ref":"Psalms 114:8","synthesized":"who turned the rock into a pool, the flint into a fountain of water!","sources":{"KJV":{"text":"Which turned the rock into a standing water, the flint into a fountain of waters."},"BSB":{"text":"who turned the rock into a pool, the flint into a fountain of water!"}},"definableWords":["water"],"peopleInVerse":[]}}},"115":{"chapter":"115","title":"NOT UNTO US, O LORD","verses":{"1":{"text":"Not unto us, O LORD, not unto us, but unto thy name give glory, for thy mercy, and for thy truth’s sake.","ref":"Psalms 115:1","synthesized":"Not to us, O LORD, not to us, but to Your name be the glory, because of Your loving devotion, because of Your faithfulness.","sources":{"KJV":{"text":"Not unto us, O LORD, not unto us, but unto thy name give glory, for thy mercy, and for thy truth’s sake."},"BSB":{"text":"Not to us, O LORD, not to us, but to Your name be the glory, because of Your loving devotion, because of Your faithfulness."}},"definableWords":["LORD","name","glory"],"peopleInVerse":[]},"2":{"text":"Wherefore should the heathen say, Where is now their God?","ref":"Psalms 115:2","synthesized":"Why should the nations say, “Where is their God?”","sources":{"KJV":{"text":"Wherefore should the heathen say, Where is now their God?"},"BSB":{"text":"Why should the nations say, “Where is their God?”"}},"definableWords":["nations","God"],"peopleInVerse":[]},"3":{"text":"But our God is in the heavens: he hath done whatsoever he hath pleased.","ref":"Psalms 115:3","synthesized":"Our God is in heaven; He does as He pleases.","sources":{"KJV":{"text":"But our God is in the heavens: he hath done whatsoever he hath pleased."},"BSB":{"text":"Our God is in heaven; He does as He pleases."}},"definableWords":["God","heaven"],"peopleInVerse":[]},"4":{"text":"Their idols are silver and gold, the work of men’s hands.","ref":"Psalms 115:4","synthesized":"Their idols are silver and gold, made by the hands of men.","sources":{"KJV":{"text":"Their idols are silver and gold, the work of men’s hands."},"BSB":{"text":"Their idols are silver and gold, made by the hands of men."}},"definableWords":["made","men"],"peopleInVerse":[]},"5":{"text":"They have mouths, but they speak not: eyes have they, but they see not:","ref":"Psalms 115:5","synthesized":"They have mouths, but cannot speak; they have eyes, but cannot see;","sources":{"KJV":{"text":"They have mouths, but they speak not: eyes have they, but they see not:"},"BSB":{"text":"They have mouths, but cannot speak; they have eyes, but cannot see;"}},"definableWords":["see"],"peopleInVerse":[]},"6":{"text":"They have ears, but they hear not: noses have they, but they smell not:","ref":"Psalms 115:6","synthesized":"they have ears, but cannot hear; they have noses, but cannot smell;","sources":{"KJV":{"text":"They have ears, but they hear not: noses have they, but they smell not:"},"BSB":{"text":"they have ears, but cannot hear; they have noses, but cannot smell;"}},"definableWords":["hear"],"peopleInVerse":[]},"7":{"text":"They have hands, but they handle not: feet have they, but they walk not: neither speak they through their throat.","ref":"Psalms 115:7","synthesized":"they have hands, but cannot feel; they have feet, but cannot walk; they cannot even clear their throats.","sources":{"KJV":{"text":"They have hands, but they handle not: feet have they, but they walk not: neither speak they through their throat."},"BSB":{"text":"they have hands, but cannot feel; they have feet, but cannot walk; they cannot even clear their throats."}},"definableWords":["walk"],"peopleInVerse":[]},"8":{"text":"They that make them are like unto them; so is every one that trusteth in them.","ref":"Psalms 115:8","synthesized":"Those who make them become like them, as do all who trust in them.","sources":{"KJV":{"text":"They that make them are like unto them; so is every one that trusteth in them."},"BSB":{"text":"Those who make them become like them, as do all who trust in them."}},"definableWords":["make","trust"],"peopleInVerse":[]},"9":{"text":"O Israel, trust thou in the LORD: he is their help and their shield.","ref":"Psalms 115:9","synthesized":"O Israel, trust in the LORD! He is their help and shield.","sources":{"KJV":{"text":"O Israel, trust thou in the LORD: he is their help and their shield."},"BSB":{"text":"O Israel, trust in the LORD! He is their help and shield."}},"definableWords":["Israel","trust","LORD"],"peopleInVerse":[]},"10":{"text":"O house of Aaron, trust in the LORD: he is their help and their shield.","ref":"Psalms 115:10","synthesized":"O house of Aaron, trust in the LORD! He is their help and shield.","sources":{"KJV":{"text":"O house of Aaron, trust in the LORD: he is their help and their shield."},"BSB":{"text":"O house of Aaron, trust in the LORD! He is their help and shield."}},"definableWords":["house","trust","LORD"],"peopleInVerse":["Aaron"]},"11":{"text":"Ye that fear the LORD, trust in the LORD: he is their help and their shield.","ref":"Psalms 115:11","synthesized":"You who fear the LORD, trust in the LORD! He is their help and shield.","sources":{"KJV":{"text":"Ye that fear the LORD, trust in the LORD: he is their help and their shield."},"BSB":{"text":"You who fear the LORD, trust in the LORD! He is their help and shield."}},"definableWords":["fear","LORD","trust","Lord"],"peopleInVerse":[]},"12":{"text":"The LORD hath been mindful of us: he will bless us; he will bless the house of Israel; he will bless the house of Aaron.","ref":"Psalms 115:12","synthesized":"The LORD is mindful of us; He will bless us. He will bless the house of Israel; He will bless the house of Aaron;","sources":{"KJV":{"text":"The LORD hath been mindful of us: he will bless us; he will bless the house of Israel; he will bless the house of Aaron."},"BSB":{"text":"The LORD is mindful of us; He will bless us. He will bless the house of Israel; He will bless the house of Aaron;"}},"definableWords":["LORD","bless","house","Israel"],"peopleInVerse":["Aaron"]},"13":{"text":"He will bless them that fear the LORD, both small and great.","ref":"Psalms 115:13","synthesized":"He will bless those who fear the LORD— small and great alike.","sources":{"KJV":{"text":"He will bless them that fear the LORD, both small and great."},"BSB":{"text":"He will bless those who fear the LORD— small and great alike."}},"definableWords":["bless","fear","LORD","great"],"peopleInVerse":[]},"14":{"text":"The LORD shall increase you more and more, you and your children.","ref":"Psalms 115:14","synthesized":"May the LORD give you increase, both you and your children.","sources":{"KJV":{"text":"The LORD shall increase you more and more, you and your children."},"BSB":{"text":"May the LORD give you increase, both you and your children."}},"definableWords":["LORD"],"peopleInVerse":[]},"15":{"text":"Ye are blessed of the LORD which made heaven and earth.","ref":"Psalms 115:15","synthesized":"May you be blessed by the LORD, the Maker of heaven and earth.","sources":{"KJV":{"text":"Ye are blessed of the LORD which made heaven and earth."},"BSB":{"text":"May you be blessed by the LORD, the Maker of heaven and earth."}},"definableWords":["blessed","LORD","heaven","earth"],"peopleInVerse":[]},"16":{"text":"The heaven, even the heavens, are the LORD’s: but the earth hath he given to the children of men.","ref":"Psalms 115:16","synthesized":"The highest heavens belong to the LORD, but the earth He has given to mankind.","sources":{"KJV":{"text":"The heaven, even the heavens, are the LORD’s: but the earth hath he given to the children of men."},"BSB":{"text":"The highest heavens belong to the LORD, but the earth He has given to mankind."}},"definableWords":["heavens","LORD","earth"],"peopleInVerse":[]},"17":{"text":"The dead praise not the LORD, neither any that go down into silence.","ref":"Psalms 115:17","synthesized":"It is not the dead who praise the LORD, nor any who descend into silence.","sources":{"KJV":{"text":"The dead praise not the LORD, neither any that go down into silence."},"BSB":{"text":"It is not the dead who praise the LORD, nor any who descend into silence."}},"definableWords":["praise","LORD"],"peopleInVerse":[]},"18":{"text":"But we will bless the LORD from this time forth and for evermore. Praise the LORD.","ref":"Psalms 115:18","synthesized":"But it is we who will bless the LORD, both now and forevermore.   Hallelujah!","sources":{"KJV":{"text":"But we will bless the LORD from this time forth and for evermore. Praise the LORD."},"BSB":{"text":"But it is we who will bless the LORD, both now and forevermore.   Hallelujah!"}},"definableWords":["bless","LORD"],"peopleInVerse":[]}}},"116":{"chapter":"116","title":"I LOVE THE LORD","verses":{"1":{"text":"I love the LORD, because he hath heard my voice and my supplications.","ref":"Psalms 116:1","synthesized":"I love the LORD, for He has heard my voice— my appeal for mercy.","sources":{"KJV":{"text":"I love the LORD, because he hath heard my voice and my supplications."},"BSB":{"text":"I love the LORD, for He has heard my voice— my appeal for mercy."}},"definableWords":["love","LORD","voice","mercy"],"peopleInVerse":[]},"2":{"text":"Because he hath inclined his ear unto me, therefore will I call upon him as long as I live.","ref":"Psalms 116:2","synthesized":"Because He has inclined His ear to me, I will call on Him as long as I live.","sources":{"KJV":{"text":"Because he hath inclined his ear unto me, therefore will I call upon him as long as I live."},"BSB":{"text":"Because He has inclined His ear to me, I will call on Him as long as I live."}},"definableWords":["live"],"peopleInVerse":[]},"3":{"text":"The sorrows of death compassed me, and the pains of hell gat hold upon me: I found trouble and sorrow.","ref":"Psalms 116:3","synthesized":"The ropes of death entangled me; the anguish of Sheol overcame me; I was confronted by trouble and sorrow.","sources":{"KJV":{"text":"The sorrows of death compassed me, and the pains of hell gat hold upon me: I found trouble and sorrow."},"BSB":{"text":"The ropes of death entangled me; the anguish of Sheol overcame me; I was confronted by trouble and sorrow."}},"definableWords":["death"],"peopleInVerse":[]},"4":{"text":"Then called I upon the name of the LORD; O LORD, I beseech thee, deliver my soul.","ref":"Psalms 116:4","synthesized":"Then I called on the name of the LORD: “O LORD, deliver my soul!”","sources":{"KJV":{"text":"Then called I upon the name of the LORD; O LORD, I beseech thee, deliver my soul."},"BSB":{"text":"Then I called on the name of the LORD: “O LORD, deliver my soul!”"}},"definableWords":["name","LORD","Lord","deliver","soul"],"peopleInVerse":[]},"5":{"text":"Gracious is the LORD, and righteous; yea, our God is merciful.","ref":"Psalms 116:5","synthesized":"The LORD is gracious and righteous; our God is full of compassion.","sources":{"KJV":{"text":"Gracious is the LORD, and righteous; yea, our God is merciful."},"BSB":{"text":"The LORD is gracious and righteous; our God is full of compassion."}},"definableWords":["LORD","righteous","God"],"peopleInVerse":[]},"6":{"text":"The LORD preserveth the simple: I was brought low, and he helped me.","ref":"Psalms 116:6","synthesized":"The LORD preserves the simplehearted; I was helpless, and He saved me.","sources":{"KJV":{"text":"The LORD preserveth the simple: I was brought low, and he helped me."},"BSB":{"text":"The LORD preserves the simplehearted; I was helpless, and He saved me."}},"definableWords":["LORD"],"peopleInVerse":[]},"7":{"text":"Return unto thy rest, O my soul; for the LORD hath dealt bountifully with thee.","ref":"Psalms 116:7","synthesized":"Return to your rest, O my soul, for the LORD has been good to you.","sources":{"KJV":{"text":"Return unto thy rest, O my soul; for the LORD hath dealt bountifully with thee."},"BSB":{"text":"Return to your rest, O my soul, for the LORD has been good to you."}},"definableWords":["rest","soul","LORD","good"],"peopleInVerse":[]},"8":{"text":"For thou hast delivered my soul from death, mine eyes from tears, and my feet from falling.","ref":"Psalms 116:8","synthesized":"For You have delivered my soul from death, my eyes from tears, my feet from stumbling.","sources":{"KJV":{"text":"For thou hast delivered my soul from death, mine eyes from tears, and my feet from falling."},"BSB":{"text":"For You have delivered my soul from death, my eyes from tears, my feet from stumbling."}},"definableWords":["soul","death"],"peopleInVerse":[]},"9":{"text":"I will walk before the LORD in the land of the living.","ref":"Psalms 116:9","synthesized":"I will walk before the LORD in the land of the living.","sources":{"KJV":{"text":"I will walk before the LORD in the land of the living."},"BSB":{"text":"I will walk before the LORD in the land of the living."}},"definableWords":["walk","LORD","land","living"],"peopleInVerse":[]},"10":{"text":"I believed, therefore have I spoken: I was greatly afflicted:","ref":"Psalms 116:10","synthesized":"I believed, therefore I said, “I am greatly afflicted.”","sources":{"KJV":{"text":"I believed, therefore have I spoken: I was greatly afflicted:"},"BSB":{"text":"I believed, therefore I said, “I am greatly afflicted.”"}},"definableWords":["believed"],"peopleInVerse":[]},"11":{"text":"I said in my haste, All men are liars.","ref":"Psalms 116:11","synthesized":"In my alarm I said, “All men are liars!”","sources":{"KJV":{"text":"I said in my haste, All men are liars."},"BSB":{"text":"In my alarm I said, “All men are liars!”"}},"definableWords":["men"],"peopleInVerse":[]},"12":{"text":"What shall I render unto the LORD for all his benefits toward me?","ref":"Psalms 116:12","synthesized":"How can I repay the LORD for all His goodness to me?","sources":{"KJV":{"text":"What shall I render unto the LORD for all his benefits toward me?"},"BSB":{"text":"How can I repay the LORD for all His goodness to me?"}},"definableWords":["LORD"],"peopleInVerse":[]},"13":{"text":"I will take the cup of salvation, and call upon the name of the LORD.","ref":"Psalms 116:13","synthesized":"I will lift the cup of salvation and call on the name of the LORD.","sources":{"KJV":{"text":"I will take the cup of salvation, and call upon the name of the LORD."},"BSB":{"text":"I will lift the cup of salvation and call on the name of the LORD."}},"definableWords":["salvation","name","LORD"],"peopleInVerse":[]},"14":{"text":"I will pay my vows unto the LORD now in the presence of all his people.","ref":"Psalms 116:14","synthesized":"I will fulfill my vows to the LORD in the presence of all His people.","sources":{"KJV":{"text":"I will pay my vows unto the LORD now in the presence of all his people."},"BSB":{"text":"I will fulfill my vows to the LORD in the presence of all His people."}},"definableWords":["LORD","people"],"peopleInVerse":[]},"15":{"text":"Precious in the sight of the LORD is the death of his saints.","ref":"Psalms 116:15","synthesized":"Precious in the sight of the LORD is the death of His saints.","sources":{"KJV":{"text":"Precious in the sight of the LORD is the death of his saints."},"BSB":{"text":"Precious in the sight of the LORD is the death of His saints."}},"definableWords":["LORD","death"],"peopleInVerse":[]},"16":{"text":"O LORD, truly I am thy servant; I am thy servant, and the son of thine handmaid: thou hast loosed my bonds.","ref":"Psalms 116:16","synthesized":"Truly, O LORD, I am Your servant; I am Your servant, the son of Your maidservant; You have broken my bonds.","sources":{"KJV":{"text":"O LORD, truly I am thy servant; I am thy servant, and the son of thine handmaid: thou hast loosed my bonds."},"BSB":{"text":"Truly, O LORD, I am Your servant; I am Your servant, the son of Your maidservant; You have broken my bonds."}},"definableWords":["LORD","servant","son"],"peopleInVerse":[]},"17":{"text":"I will offer to thee the sacrifice of thanksgiving, and will call upon the name of the LORD.","ref":"Psalms 116:17","synthesized":"I will offer to You a sacrifice of thanksgiving and call on the name of the LORD.","sources":{"KJV":{"text":"I will offer to thee the sacrifice of thanksgiving, and will call upon the name of the LORD."},"BSB":{"text":"I will offer to You a sacrifice of thanksgiving and call on the name of the LORD."}},"definableWords":["sacrifice","name","LORD"],"peopleInVerse":[]},"18":{"text":"I will pay my vows unto the LORD now in the presence of all his people,","ref":"Psalms 116:18","synthesized":"I will fulfill my vows to the LORD in the presence of all His people,","sources":{"KJV":{"text":"I will pay my vows unto the LORD now in the presence of all his people,"},"BSB":{"text":"I will fulfill my vows to the LORD in the presence of all His people,"}},"definableWords":["LORD","people"],"peopleInVerse":[]},"19":{"text":"In the courts of the LORD’s house, in the midst of thee, O Jerusalem. Praise ye the LORD.","ref":"Psalms 116:19","synthesized":"in the courts of the LORD’s house, in your midst, O Jerusalem.   Hallelujah!","sources":{"KJV":{"text":"In the courts of the LORD’s house, in the midst of thee, O Jerusalem. Praise ye the LORD."},"BSB":{"text":"in the courts of the LORD’s house, in your midst, O Jerusalem.   Hallelujah!"}},"definableWords":["LORD","house","Jerusalem"],"peopleInVerse":[]}}},"117":{"chapter":"117","title":"THE SHORTEST CHAPTER IN THE BIBLE","verses":{"1":{"text":"O Praise the LORD, all ye nations: praise him, all ye people.","ref":"Psalms 117:1","synthesized":"Praise the LORD, all you nations! Extol Him, all you peoples!","sources":{"KJV":{"text":"O Praise the LORD, all ye nations: praise him, all ye people."},"BSB":{"text":"Praise the LORD, all you nations! Extol Him, all you peoples!"}},"definableWords":["praise","LORD","nations"],"peopleInVerse":[]},"2":{"text":"For his merciful kindness is great toward us: and the truth of the LORD endureth for ever. Praise ye the LORD.","ref":"Psalms 117:2","synthesized":"For great is His loving devotion toward us, and the faithfulness of the LORD endures forever.   Hallelujah!","sources":{"KJV":{"text":"For his merciful kindness is great toward us: and the truth of the LORD endureth for ever. Praise ye the LORD."},"BSB":{"text":"For great is His loving devotion toward us, and the faithfulness of the LORD endures forever.   Hallelujah!"}},"definableWords":["great","LORD"],"peopleInVerse":[]}}},"118":{"chapter":"118","title":"THE STONE THE BUILDERS REJECTED","verses":{"1":{"text":"O give thanks unto the LORD; for he is good: because his mercy endureth for ever.","ref":"Psalms 118:1","synthesized":"Give thanks to the LORD, for He is good; His loving devotion endures forever.","sources":{"KJV":{"text":"O give thanks unto the LORD; for he is good: because his mercy endureth for ever."},"BSB":{"text":"Give thanks to the LORD, for He is good; His loving devotion endures forever."}},"definableWords":["LORD","good"],"peopleInVerse":[]},"2":{"text":"Let Israel now say, that his mercy endureth for ever.","ref":"Psalms 118:2","synthesized":"Let Israel say, “His loving devotion endures forever.”","sources":{"KJV":{"text":"Let Israel now say, that his mercy endureth for ever."},"BSB":{"text":"Let Israel say, “His loving devotion endures forever.”"}},"definableWords":["Israel"],"peopleInVerse":[]},"3":{"text":"Let the house of Aaron now say, that his mercy endureth for ever.","ref":"Psalms 118:3","synthesized":"Let the house of Aaron say, “His loving devotion endures forever.”","sources":{"KJV":{"text":"Let the house of Aaron now say, that his mercy endureth for ever."},"BSB":{"text":"Let the house of Aaron say, “His loving devotion endures forever.”"}},"definableWords":["house"],"peopleInVerse":["Aaron"]},"4":{"text":"Let them now that fear the LORD say, that his mercy endureth for ever.","ref":"Psalms 118:4","synthesized":"Let those who fear the LORD say, “His loving devotion endures forever.”","sources":{"KJV":{"text":"Let them now that fear the LORD say, that his mercy endureth for ever."},"BSB":{"text":"Let those who fear the LORD say, “His loving devotion endures forever.”"}},"definableWords":["fear","LORD"],"peopleInVerse":[]},"5":{"text":"I called upon the LORD in distress: the LORD answered me, and set me in a large place.","ref":"Psalms 118:5","synthesized":"In my distress I called to the LORD, and He answered and set me free.","sources":{"KJV":{"text":"I called upon the LORD in distress: the LORD answered me, and set me in a large place."},"BSB":{"text":"In my distress I called to the LORD, and He answered and set me free."}},"definableWords":["LORD"],"peopleInVerse":[]},"6":{"text":"The LORD is on my side; I will not fear: what can man do unto me?","ref":"Psalms 118:6","synthesized":"The LORD is on my side; I will not be afraid. What can man do to me?","sources":{"KJV":{"text":"The LORD is on my side; I will not fear: what can man do unto me?"},"BSB":{"text":"The LORD is on my side; I will not be afraid. What can man do to me?"}},"definableWords":["LORD","man"],"peopleInVerse":[]},"7":{"text":"The LORD taketh my part with them that help me: therefore shall I see my desire upon them that hate me.","ref":"Psalms 118:7","synthesized":"The LORD is on my side; He is my helper. Therefore I will look in triumph on those who hate me.","sources":{"KJV":{"text":"The LORD taketh my part with them that help me: therefore shall I see my desire upon them that hate me."},"BSB":{"text":"The LORD is on my side; He is my helper. Therefore I will look in triumph on those who hate me."}},"definableWords":["LORD","helper"],"peopleInVerse":[]},"8":{"text":"It is better to trust in the LORD than to put confidence in man.","ref":"Psalms 118:8","synthesized":"It is better to take refuge in the LORD than to trust in man.","sources":{"KJV":{"text":"It is better to trust in the LORD than to put confidence in man."},"BSB":{"text":"It is better to take refuge in the LORD than to trust in man."}},"definableWords":["LORD","trust","man"],"peopleInVerse":[]},"9":{"text":"It is better to trust in the LORD than to put confidence in princes.","ref":"Psalms 118:9","synthesized":"It is better to take refuge in the LORD than to trust in princes.","sources":{"KJV":{"text":"It is better to trust in the LORD than to put confidence in princes."},"BSB":{"text":"It is better to take refuge in the LORD than to trust in princes."}},"definableWords":["LORD","trust"],"peopleInVerse":[]},"10":{"text":"All nations compassed me about: but in the name of the LORD will I destroy them.","ref":"Psalms 118:10","synthesized":"All the nations surrounded me, but in the name of the LORD I cut them off.","sources":{"KJV":{"text":"All nations compassed me about: but in the name of the LORD will I destroy them."},"BSB":{"text":"All the nations surrounded me, but in the name of the LORD I cut them off."}},"definableWords":["nations","name","LORD"],"peopleInVerse":[]},"11":{"text":"They compassed me about; yea, they compassed me about: but in the name of the LORD I will destroy them.","ref":"Psalms 118:11","synthesized":"They surrounded me on every side, but in the name of the LORD I cut them off.","sources":{"KJV":{"text":"They compassed me about; yea, they compassed me about: but in the name of the LORD I will destroy them."},"BSB":{"text":"They surrounded me on every side, but in the name of the LORD I cut them off."}},"definableWords":["name","LORD"],"peopleInVerse":[]},"12":{"text":"They compassed me about like bees; they are quenched as the fire of thorns: for in the name of the LORD I will destroy them.","ref":"Psalms 118:12","synthesized":"They swarmed around me like bees, but they were extinguished like burning thorns; in the name of the LORD I cut them off.","sources":{"KJV":{"text":"They compassed me about like bees; they are quenched as the fire of thorns: for in the name of the LORD I will destroy them."},"BSB":{"text":"They swarmed around me like bees, but they were extinguished like burning thorns; in the name of the LORD I cut them off."}},"definableWords":["name","LORD"],"peopleInVerse":[]},"13":{"text":"Thou hast thrust sore at me that I might fall: but the LORD helped me.","ref":"Psalms 118:13","synthesized":"I was pushed so hard I was falling, but the LORD helped me.","sources":{"KJV":{"text":"Thou hast thrust sore at me that I might fall: but the LORD helped me."},"BSB":{"text":"I was pushed so hard I was falling, but the LORD helped me."}},"definableWords":["LORD"],"peopleInVerse":[]},"14":{"text":"The LORD is my strength and song, and is become my salvation.","ref":"Psalms 118:14","synthesized":"The LORD is my strength and my song, and He has become my salvation.","sources":{"KJV":{"text":"The LORD is my strength and song, and is become my salvation."},"BSB":{"text":"The LORD is my strength and my song, and He has become my salvation."}},"definableWords":["LORD","salvation"],"peopleInVerse":[]},"15":{"text":"The voice of rejoicing and salvation is in the tabernacles of the righteous: the right hand of the LORD doeth valiantly.","ref":"Psalms 118:15","synthesized":"Shouts of joy and salvation resound in the tents of the righteous: “The right hand of the LORD performs with valor!","sources":{"KJV":{"text":"The voice of rejoicing and salvation is in the tabernacles of the righteous: the right hand of the LORD doeth valiantly."},"BSB":{"text":"Shouts of joy and salvation resound in the tents of the righteous: “The right hand of the LORD performs with valor!"}},"definableWords":["joy","salvation","righteous","LORD"],"peopleInVerse":[]},"16":{"text":"The right hand of the LORD is exalted: the right hand of the LORD doeth valiantly.","ref":"Psalms 118:16","synthesized":"The right hand of the LORD is exalted! The right hand of the LORD performs with valor!”","sources":{"KJV":{"text":"The right hand of the LORD is exalted: the right hand of the LORD doeth valiantly."},"BSB":{"text":"The right hand of the LORD is exalted! The right hand of the LORD performs with valor!”"}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"17":{"text":"I shall not die, but live, and declare the works of the LORD.","ref":"Psalms 118:17","synthesized":"I will not die, but I will live and proclaim what the LORD has done.","sources":{"KJV":{"text":"I shall not die, but live, and declare the works of the LORD."},"BSB":{"text":"I will not die, but I will live and proclaim what the LORD has done."}},"definableWords":["die","live","LORD"],"peopleInVerse":[]},"18":{"text":"The LORD hath chastened me sore: but he hath not given me over unto death.","ref":"Psalms 118:18","synthesized":"The LORD disciplined me severely, but He has not given me over to death.","sources":{"KJV":{"text":"The LORD hath chastened me sore: but he hath not given me over unto death."},"BSB":{"text":"The LORD disciplined me severely, but He has not given me over to death."}},"definableWords":["LORD","death"],"peopleInVerse":[]},"19":{"text":"Open to me the gates of righteousness: I will go into them, and I will praise the LORD:","ref":"Psalms 118:19","synthesized":"Open to me the gates of righteousness, that I may enter and give thanks to the LORD.","sources":{"KJV":{"text":"Open to me the gates of righteousness: I will go into them, and I will praise the LORD:"},"BSB":{"text":"Open to me the gates of righteousness, that I may enter and give thanks to the LORD."}},"definableWords":["righteousness","LORD"],"peopleInVerse":[]},"20":{"text":"This gate of the LORD, into which the righteous shall enter.","ref":"Psalms 118:20","synthesized":"This is the gate of the LORD; the righteous shall enter through it.","sources":{"KJV":{"text":"This gate of the LORD, into which the righteous shall enter."},"BSB":{"text":"This is the gate of the LORD; the righteous shall enter through it."}},"definableWords":["LORD","righteous"],"peopleInVerse":[]},"21":{"text":"I will praise thee: for thou hast heard me, and art become my salvation.","ref":"Psalms 118:21","synthesized":"I will give You thanks, for You have answered me, and You have become my salvation.","sources":{"KJV":{"text":"I will praise thee: for thou hast heard me, and art become my salvation."},"BSB":{"text":"I will give You thanks, for You have answered me, and You have become my salvation."}},"definableWords":["salvation"],"peopleInVerse":[]},"22":{"text":"The stone which the builders refused is become the head stone of the corner.","ref":"Psalms 118:22","synthesized":"The stone the builders rejected has become the cornerstone.","sources":{"KJV":{"text":"The stone which the builders refused is become the head stone of the corner."},"BSB":{"text":"The stone the builders rejected has become the cornerstone."}},"definableWords":["stone"],"peopleInVerse":[]},"23":{"text":"This is the LORD’s doing; it is marvellous in our eyes.","ref":"Psalms 118:23","synthesized":"This is from the LORD, and it is marvelous in our eyes.","sources":{"KJV":{"text":"This is the LORD’s doing; it is marvellous in our eyes."},"BSB":{"text":"This is from the LORD, and it is marvelous in our eyes."}},"definableWords":["LORD"],"peopleInVerse":[]},"24":{"text":"This is the day which the LORD hath made; we will rejoice and be glad in it.","ref":"Psalms 118:24","synthesized":"This is the day that the LORD has made; we will rejoice and be glad in it.","sources":{"KJV":{"text":"This is the day which the LORD hath made; we will rejoice and be glad in it."},"BSB":{"text":"This is the day that the LORD has made; we will rejoice and be glad in it."}},"definableWords":["day","LORD","made"],"peopleInVerse":[]},"25":{"text":"Save now, I beseech thee, O LORD: O LORD, I beseech thee, send now prosperity.","ref":"Psalms 118:25","synthesized":"O LORD, save us, we pray. We beseech You, O LORD, cause us to prosper!","sources":{"KJV":{"text":"Save now, I beseech thee, O LORD: O LORD, I beseech thee, send now prosperity."},"BSB":{"text":"O LORD, save us, we pray. We beseech You, O LORD, cause us to prosper!"}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"26":{"text":"Blessed be he that cometh in the name of the LORD: we have blessed you out of the house of the LORD.","ref":"Psalms 118:26","synthesized":"Blessed is he who comes in the name of the LORD. From the house of the LORD we bless you.","sources":{"KJV":{"text":"Blessed be he that cometh in the name of the LORD: we have blessed you out of the house of the LORD."},"BSB":{"text":"Blessed is he who comes in the name of the LORD. From the house of the LORD we bless you."}},"definableWords":["blessed","name","LORD","house","Lord","bless"],"peopleInVerse":[]},"27":{"text":"God is the LORD, which hath shewed us light: bind the sacrifice with cords, even unto the horns of the altar.","ref":"Psalms 118:27","synthesized":"The LORD is God; He has made His light to shine upon us. Bind the festal sacrifice with cords to the horns of the altar.","sources":{"KJV":{"text":"God is the LORD, which hath shewed us light: bind the sacrifice with cords, even unto the horns of the altar."},"BSB":{"text":"The LORD is God; He has made His light to shine upon us. Bind the festal sacrifice with cords to the horns of the altar."}},"definableWords":["LORD","God","made","light","sacrifice","altar"],"peopleInVerse":[]},"28":{"text":"Thou art my God, and I will praise thee: thou art my God, I will exalt thee.","ref":"Psalms 118:28","synthesized":"You are my God, and I will give You thanks. You are my God, and I will exalt You.","sources":{"KJV":{"text":"Thou art my God, and I will praise thee: thou art my God, I will exalt thee."},"BSB":{"text":"You are my God, and I will give You thanks. You are my God, and I will exalt You."}},"definableWords":["God"],"peopleInVerse":[]},"29":{"text":"O give thanks unto the LORD; for he is good: for his mercy endureth for ever.","ref":"Psalms 118:29","synthesized":"Give thanks to the LORD, for He is good; His loving devotion endures forever.","sources":{"KJV":{"text":"O give thanks unto the LORD; for he is good: for his mercy endureth for ever."},"BSB":{"text":"Give thanks to the LORD, for He is good; His loving devotion endures forever."}},"definableWords":["LORD","good"],"peopleInVerse":[]}}},"119":{"chapter":"119","title":"THE LONGEST PSALM — LOVE OF THE LAW","verses":{"1":{"text":"Blessed are the undefiled in the way, who walk in the law of the LORD.","ref":"Psalms 119:1","synthesized":"Blessed are those whose way is blameless, who walk in the Law of the LORD.","sources":{"KJV":{"text":"Blessed are the undefiled in the way, who walk in the law of the LORD."},"BSB":{"text":"Blessed are those whose way is blameless, who walk in the Law of the LORD."}},"definableWords":["blessed","way","walk","law","LORD"],"peopleInVerse":[]},"2":{"text":"Blessed are they that keep his testimonies, and that seek him with the whole heart.","ref":"Psalms 119:2","synthesized":"Blessed are those who keep His testimonies and seek Him with all their heart.","sources":{"KJV":{"text":"Blessed are they that keep his testimonies, and that seek him with the whole heart."},"BSB":{"text":"Blessed are those who keep His testimonies and seek Him with all their heart."}},"definableWords":["blessed","keep","seek","heart"],"peopleInVerse":[]},"3":{"text":"They also do no iniquity: they walk in his ways.","ref":"Psalms 119:3","synthesized":"They do no iniquity; they walk in His ways.","sources":{"KJV":{"text":"They also do no iniquity: they walk in his ways."},"BSB":{"text":"They do no iniquity; they walk in His ways."}},"definableWords":["iniquity","walk"],"peopleInVerse":[]},"4":{"text":"Thou hast commanded us to keep thy precepts diligently.","ref":"Psalms 119:4","synthesized":"You have ordained Your precepts, that we should keep them diligently.","sources":{"KJV":{"text":"Thou hast commanded us to keep thy precepts diligently."},"BSB":{"text":"You have ordained Your precepts, that we should keep them diligently."}},"definableWords":["keep"],"peopleInVerse":[]},"5":{"text":"O that my ways were directed to keep thy statutes!","ref":"Psalms 119:5","synthesized":"Oh, that my ways were committed to keeping Your statutes!","sources":{"KJV":{"text":"O that my ways were directed to keep thy statutes!"},"BSB":{"text":"Oh, that my ways were committed to keeping Your statutes!"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Then shall I not be ashamed, when I have respect unto all thy commandments.","ref":"Psalms 119:6","synthesized":"Then I would not be ashamed when I consider all Your commandments.","sources":{"KJV":{"text":"Then shall I not be ashamed, when I have respect unto all thy commandments."},"BSB":{"text":"Then I would not be ashamed when I consider all Your commandments."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"I will praise thee with uprightness of heart, when I shall have learned thy righteous judgments.","ref":"Psalms 119:7","synthesized":"I will praise You with an upright heart when I learn Your righteous judgments.","sources":{"KJV":{"text":"I will praise thee with uprightness of heart, when I shall have learned thy righteous judgments."},"BSB":{"text":"I will praise You with an upright heart when I learn Your righteous judgments."}},"definableWords":["praise","heart","righteous"],"peopleInVerse":[]},"8":{"text":"I will keep thy statutes: O forsake me not utterly.","ref":"Psalms 119:8","synthesized":"I will keep Your statutes; do not utterly forsake me.","sources":{"KJV":{"text":"I will keep thy statutes: O forsake me not utterly."},"BSB":{"text":"I will keep Your statutes; do not utterly forsake me."}},"definableWords":["keep"],"peopleInVerse":[]},"9":{"text":"Wherewithal shall a young man cleanse his way? by taking heed thereto according to thy word.","ref":"Psalms 119:9","synthesized":"How can a young man keep his way pure? By guarding it according to Your word.","sources":{"KJV":{"text":"Wherewithal shall a young man cleanse his way? by taking heed thereto according to thy word."},"BSB":{"text":"How can a young man keep his way pure? By guarding it according to Your word."}},"definableWords":["man","keep","way","word"],"peopleInVerse":[]},"10":{"text":"With my whole heart have I sought thee: O let me not wander from thy commandments.","ref":"Psalms 119:10","synthesized":"With all my heart I have sought You; do not let me stray from Your commandments.","sources":{"KJV":{"text":"With my whole heart have I sought thee: O let me not wander from thy commandments."},"BSB":{"text":"With all my heart I have sought You; do not let me stray from Your commandments."}},"definableWords":["heart"],"peopleInVerse":[]},"11":{"text":"Thy word have I hid in mine heart, that I might not sin against thee.","ref":"Psalms 119:11","synthesized":"I have hidden Your word in my heart that I might not sin against You.","sources":{"KJV":{"text":"Thy word have I hid in mine heart, that I might not sin against thee."},"BSB":{"text":"I have hidden Your word in my heart that I might not sin against You."}},"definableWords":["word","heart","sin"],"peopleInVerse":[]},"12":{"text":"Blessed art thou, O LORD: teach me thy statutes.","ref":"Psalms 119:12","synthesized":"Blessed are You, O LORD; teach me Your statutes.","sources":{"KJV":{"text":"Blessed art thou, O LORD: teach me thy statutes."},"BSB":{"text":"Blessed are You, O LORD; teach me Your statutes."}},"definableWords":["blessed","LORD"],"peopleInVerse":[]},"13":{"text":"With my lips have I declared all the judgments of thy mouth.","ref":"Psalms 119:13","synthesized":"With my lips I proclaim all the judgments of Your mouth.","sources":{"KJV":{"text":"With my lips have I declared all the judgments of thy mouth."},"BSB":{"text":"With my lips I proclaim all the judgments of Your mouth."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"I have rejoiced in the way of thy testimonies, as much as in all riches.","ref":"Psalms 119:14","synthesized":"I rejoice in the way of Your testimonies as much as in all riches.","sources":{"KJV":{"text":"I have rejoiced in the way of thy testimonies, as much as in all riches."},"BSB":{"text":"I rejoice in the way of Your testimonies as much as in all riches."}},"definableWords":["way"],"peopleInVerse":[]},"15":{"text":"I will meditate in thy precepts, and have respect unto thy ways.","ref":"Psalms 119:15","synthesized":"I will meditate on Your precepts and regard Your ways.","sources":{"KJV":{"text":"I will meditate in thy precepts, and have respect unto thy ways."},"BSB":{"text":"I will meditate on Your precepts and regard Your ways."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"I will delight myself in thy statutes: I will not forget thy word.","ref":"Psalms 119:16","synthesized":"I will delight in Your statutes; I will not forget Your word.","sources":{"KJV":{"text":"I will delight myself in thy statutes: I will not forget thy word."},"BSB":{"text":"I will delight in Your statutes; I will not forget Your word."}},"definableWords":["word"],"peopleInVerse":[]},"17":{"text":"Deal bountifully with thy servant, that I may live, and keep thy word.","ref":"Psalms 119:17","synthesized":"Deal bountifully with Your servant, that I may live and keep Your word.","sources":{"KJV":{"text":"Deal bountifully with thy servant, that I may live, and keep thy word."},"BSB":{"text":"Deal bountifully with Your servant, that I may live and keep Your word."}},"definableWords":["servant","live","keep","word"],"peopleInVerse":[]},"18":{"text":"Open thou mine eyes, that I may behold wondrous things out of thy law.","ref":"Psalms 119:18","synthesized":"Open my eyes that I may see wondrous things from Your law.","sources":{"KJV":{"text":"Open thou mine eyes, that I may behold wondrous things out of thy law."},"BSB":{"text":"Open my eyes that I may see wondrous things from Your law."}},"definableWords":["see","law"],"peopleInVerse":[]},"19":{"text":"I am a stranger in the earth: hide not thy commandments from me.","ref":"Psalms 119:19","synthesized":"I am a stranger on the earth; do not hide Your commandments from me.","sources":{"KJV":{"text":"I am a stranger in the earth: hide not thy commandments from me."},"BSB":{"text":"I am a stranger on the earth; do not hide Your commandments from me."}},"definableWords":["stranger","earth"],"peopleInVerse":[]},"20":{"text":"My soul breaketh for the longing that it hath unto thy judgments at all times.","ref":"Psalms 119:20","synthesized":"My soul is consumed with longing for Your judgments at all times.","sources":{"KJV":{"text":"My soul breaketh for the longing that it hath unto thy judgments at all times."},"BSB":{"text":"My soul is consumed with longing for Your judgments at all times."}},"definableWords":["soul"],"peopleInVerse":[]},"21":{"text":"Thou hast rebuked the proud that are cursed, which do err from thy commandments.","ref":"Psalms 119:21","synthesized":"You rebuke the arrogant— the cursed who stray from Your commandments.","sources":{"KJV":{"text":"Thou hast rebuked the proud that are cursed, which do err from thy commandments."},"BSB":{"text":"You rebuke the arrogant— the cursed who stray from Your commandments."}},"definableWords":["cursed"],"peopleInVerse":[]},"22":{"text":"Remove from me reproach and contempt; for I have kept thy testimonies.","ref":"Psalms 119:22","synthesized":"Remove my scorn and contempt, for I have kept Your testimonies.","sources":{"KJV":{"text":"Remove from me reproach and contempt; for I have kept thy testimonies."},"BSB":{"text":"Remove my scorn and contempt, for I have kept Your testimonies."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Princes also did sit and speak against me: but thy servant did meditate in thy statutes.","ref":"Psalms 119:23","synthesized":"Though rulers sit and slander me, Your servant meditates on Your statutes.","sources":{"KJV":{"text":"Princes also did sit and speak against me: but thy servant did meditate in thy statutes."},"BSB":{"text":"Though rulers sit and slander me, Your servant meditates on Your statutes."}},"definableWords":["servant"],"peopleInVerse":[]},"24":{"text":"Thy testimonies also are my delight and my counsellors.","ref":"Psalms 119:24","synthesized":"Your testimonies are indeed my delight; they are my counselors.","sources":{"KJV":{"text":"Thy testimonies also are my delight and my counsellors."},"BSB":{"text":"Your testimonies are indeed my delight; they are my counselors."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"My soul cleaveth unto the dust: quicken thou me according to thy word.","ref":"Psalms 119:25","synthesized":"My soul cleaves to the dust; revive me according to Your word.","sources":{"KJV":{"text":"My soul cleaveth unto the dust: quicken thou me according to thy word."},"BSB":{"text":"My soul cleaves to the dust; revive me according to Your word."}},"definableWords":["soul","word"],"peopleInVerse":[]},"26":{"text":"I have declared my ways, and thou heardest me: teach me thy statutes.","ref":"Psalms 119:26","synthesized":"I recounted my ways, and You answered me; teach me Your statutes.","sources":{"KJV":{"text":"I have declared my ways, and thou heardest me: teach me thy statutes."},"BSB":{"text":"I recounted my ways, and You answered me; teach me Your statutes."}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"Make me to understand the way of thy precepts: so shall I talk of thy wondrous works.","ref":"Psalms 119:27","synthesized":"Make clear to me the way of Your precepts; then I will meditate on Your wonders.","sources":{"KJV":{"text":"Make me to understand the way of thy precepts: so shall I talk of thy wondrous works."},"BSB":{"text":"Make clear to me the way of Your precepts; then I will meditate on Your wonders."}},"definableWords":["make","way"],"peopleInVerse":[]},"28":{"text":"My soul melteth for heaviness: strengthen thou me according unto thy word.","ref":"Psalms 119:28","synthesized":"My soul melts with sorrow; strengthen me according to Your word.","sources":{"KJV":{"text":"My soul melteth for heaviness: strengthen thou me according unto thy word."},"BSB":{"text":"My soul melts with sorrow; strengthen me according to Your word."}},"definableWords":["soul","word"],"peopleInVerse":[]},"29":{"text":"Remove from me the way of lying: and grant me thy law graciously.","ref":"Psalms 119:29","synthesized":"Remove me from the path of deceit and graciously grant me Your law.","sources":{"KJV":{"text":"Remove from me the way of lying: and grant me thy law graciously."},"BSB":{"text":"Remove me from the path of deceit and graciously grant me Your law."}},"definableWords":["law"],"peopleInVerse":[]},"30":{"text":"I have chosen the way of truth: thy judgments have I laid before me.","ref":"Psalms 119:30","synthesized":"I have chosen the way of truth; I have set Your ordinances before me.","sources":{"KJV":{"text":"I have chosen the way of truth: thy judgments have I laid before me."},"BSB":{"text":"I have chosen the way of truth; I have set Your ordinances before me."}},"definableWords":["way","truth"],"peopleInVerse":[]},"31":{"text":"I have stuck unto thy testimonies: O LORD, put me not to shame.","ref":"Psalms 119:31","synthesized":"I cling to Your testimonies, O LORD; let me not be put to shame.","sources":{"KJV":{"text":"I have stuck unto thy testimonies: O LORD, put me not to shame."},"BSB":{"text":"I cling to Your testimonies, O LORD; let me not be put to shame."}},"definableWords":["LORD"],"peopleInVerse":[]},"32":{"text":"I will run the way of thy commandments, when thou shalt enlarge my heart.","ref":"Psalms 119:32","synthesized":"I run in the path of Your commandments, for You will enlarge my heart.","sources":{"KJV":{"text":"I will run the way of thy commandments, when thou shalt enlarge my heart."},"BSB":{"text":"I run in the path of Your commandments, for You will enlarge my heart."}},"definableWords":["run","heart"],"peopleInVerse":[]},"33":{"text":"Teach me, O LORD, the way of thy statutes; and I shall keep it unto the end.","ref":"Psalms 119:33","synthesized":"Teach me, O LORD, the way of Your statutes, and I will keep them to the end.","sources":{"KJV":{"text":"Teach me, O LORD, the way of thy statutes; and I shall keep it unto the end."},"BSB":{"text":"Teach me, O LORD, the way of Your statutes, and I will keep them to the end."}},"definableWords":["LORD","way","keep"],"peopleInVerse":[]},"34":{"text":"Give me understanding, and I shall keep thy law; yea, I shall observe it with my whole heart.","ref":"Psalms 119:34","synthesized":"Give me understanding that I may obey Your law, and follow it with all my heart.","sources":{"KJV":{"text":"Give me understanding, and I shall keep thy law; yea, I shall observe it with my whole heart."},"BSB":{"text":"Give me understanding that I may obey Your law, and follow it with all my heart."}},"definableWords":["law","heart"],"peopleInVerse":[]},"35":{"text":"Make me to go in the path of thy commandments; for therein do I delight.","ref":"Psalms 119:35","synthesized":"Direct me in the path of Your commandments, for there I find delight.","sources":{"KJV":{"text":"Make me to go in the path of thy commandments; for therein do I delight."},"BSB":{"text":"Direct me in the path of Your commandments, for there I find delight."}},"definableWords":[],"peopleInVerse":[]},"36":{"text":"Incline my heart unto thy testimonies, and not to covetousness.","ref":"Psalms 119:36","synthesized":"Turn my heart to Your testimonies and not to covetous gain.","sources":{"KJV":{"text":"Incline my heart unto thy testimonies, and not to covetousness."},"BSB":{"text":"Turn my heart to Your testimonies and not to covetous gain."}},"definableWords":["heart"],"peopleInVerse":[]},"37":{"text":"Turn away mine eyes from beholding vanity; and quicken thou me in thy way.","ref":"Psalms 119:37","synthesized":"Turn my eyes away from worthless things; revive me with Your word.","sources":{"KJV":{"text":"Turn away mine eyes from beholding vanity; and quicken thou me in thy way."},"BSB":{"text":"Turn my eyes away from worthless things; revive me with Your word."}},"definableWords":["word"],"peopleInVerse":[]},"38":{"text":"Stablish thy word unto thy servant, who is devoted to thy fear.","ref":"Psalms 119:38","synthesized":"Establish Your word to Your servant, to produce reverence for You.","sources":{"KJV":{"text":"Stablish thy word unto thy servant, who is devoted to thy fear."},"BSB":{"text":"Establish Your word to Your servant, to produce reverence for You."}},"definableWords":["word","servant"],"peopleInVerse":[]},"39":{"text":"Turn away my reproach which I fear: for thy judgments are good.","ref":"Psalms 119:39","synthesized":"Turn away the disgrace I dread, for Your judgments are good.","sources":{"KJV":{"text":"Turn away my reproach which I fear: for thy judgments are good."},"BSB":{"text":"Turn away the disgrace I dread, for Your judgments are good."}},"definableWords":["good"],"peopleInVerse":[]},"40":{"text":"Behold, I have longed after thy precepts: quicken me in thy righteousness.","ref":"Psalms 119:40","synthesized":"How I long for Your precepts! Revive me in Your righteousness.","sources":{"KJV":{"text":"Behold, I have longed after thy precepts: quicken me in thy righteousness."},"BSB":{"text":"How I long for Your precepts! Revive me in Your righteousness."}},"definableWords":["righteousness"],"peopleInVerse":[]},"41":{"text":"Let thy mercies come also unto me, O LORD, even thy salvation, according to thy word.","ref":"Psalms 119:41","synthesized":"May Your loving devotion come to me, O LORD, Your salvation, according to Your promise.","sources":{"KJV":{"text":"Let thy mercies come also unto me, O LORD, even thy salvation, according to thy word."},"BSB":{"text":"May Your loving devotion come to me, O LORD, Your salvation, according to Your promise."}},"definableWords":["LORD","salvation","promise"],"peopleInVerse":[]},"42":{"text":"So shall I have wherewith to answer him that reproacheth me: for I trust in thy word.","ref":"Psalms 119:42","synthesized":"Then I can answer him who taunts, for I trust in Your word.","sources":{"KJV":{"text":"So shall I have wherewith to answer him that reproacheth me: for I trust in thy word."},"BSB":{"text":"Then I can answer him who taunts, for I trust in Your word."}},"definableWords":["trust","word"],"peopleInVerse":[]},"43":{"text":"And take not the word of truth utterly out of my mouth; for I have hoped in thy judgments.","ref":"Psalms 119:43","synthesized":"Never take Your word of truth from my mouth, for I hope in Your judgments.","sources":{"KJV":{"text":"And take not the word of truth utterly out of my mouth; for I have hoped in thy judgments."},"BSB":{"text":"Never take Your word of truth from my mouth, for I hope in Your judgments."}},"definableWords":["word","truth","hope"],"peopleInVerse":[]},"44":{"text":"So shall I keep thy law continually for ever and ever.","ref":"Psalms 119:44","synthesized":"I will always obey Your law, forever and ever.","sources":{"KJV":{"text":"So shall I keep thy law continually for ever and ever."},"BSB":{"text":"I will always obey Your law, forever and ever."}},"definableWords":["law"],"peopleInVerse":[]},"45":{"text":"And I will walk at liberty: for I seek thy precepts.","ref":"Psalms 119:45","synthesized":"And I will walk in freedom, for I have sought Your precepts.","sources":{"KJV":{"text":"And I will walk at liberty: for I seek thy precepts."},"BSB":{"text":"And I will walk in freedom, for I have sought Your precepts."}},"definableWords":["walk"],"peopleInVerse":[]},"46":{"text":"I will speak of thy testimonies also before kings, and will not be ashamed.","ref":"Psalms 119:46","synthesized":"I will speak of Your testimonies before kings, and I will not be ashamed.","sources":{"KJV":{"text":"I will speak of thy testimonies also before kings, and will not be ashamed."},"BSB":{"text":"I will speak of Your testimonies before kings, and I will not be ashamed."}},"definableWords":["kings"],"peopleInVerse":[]},"47":{"text":"And I will delight myself in thy commandments, which I have loved.","ref":"Psalms 119:47","synthesized":"I delight in Your commandments because I love them.","sources":{"KJV":{"text":"And I will delight myself in thy commandments, which I have loved."},"BSB":{"text":"I delight in Your commandments because I love them."}},"definableWords":["love"],"peopleInVerse":[]},"48":{"text":"My hands also will I lift up unto thy commandments, which I have loved; and I will meditate in thy statutes.","ref":"Psalms 119:48","synthesized":"I lift up my hands to Your commandments, which I love, and I meditate on Your statutes.","sources":{"KJV":{"text":"My hands also will I lift up unto thy commandments, which I have loved; and I will meditate in thy statutes."},"BSB":{"text":"I lift up my hands to Your commandments, which I love, and I meditate on Your statutes."}},"definableWords":["love"],"peopleInVerse":[]},"49":{"text":"Remember the word unto thy servant, upon which thou hast caused me to hope.","ref":"Psalms 119:49","synthesized":"Remember Your word to Your servant, upon which You have given me hope.","sources":{"KJV":{"text":"Remember the word unto thy servant, upon which thou hast caused me to hope."},"BSB":{"text":"Remember Your word to Your servant, upon which You have given me hope."}},"definableWords":["remember","word","servant","hope"],"peopleInVerse":[]},"50":{"text":"This is my comfort in my affliction: for thy word hath quickened me.","ref":"Psalms 119:50","synthesized":"This is my comfort in affliction, that Your promise has given me life.","sources":{"KJV":{"text":"This is my comfort in my affliction: for thy word hath quickened me."},"BSB":{"text":"This is my comfort in affliction, that Your promise has given me life."}},"definableWords":["promise","life"],"peopleInVerse":[]},"51":{"text":"The proud have had me greatly in derision: yet have I not declined from thy law.","ref":"Psalms 119:51","synthesized":"The arrogant utterly deride me, but I do not turn from Your law.","sources":{"KJV":{"text":"The proud have had me greatly in derision: yet have I not declined from thy law."},"BSB":{"text":"The arrogant utterly deride me, but I do not turn from Your law."}},"definableWords":["law"],"peopleInVerse":[]},"52":{"text":"I remembered thy judgments of old, O LORD; and have comforted myself.","ref":"Psalms 119:52","synthesized":"I remember Your judgments of old, O LORD, and in them I find comfort.","sources":{"KJV":{"text":"I remembered thy judgments of old, O LORD; and have comforted myself."},"BSB":{"text":"I remember Your judgments of old, O LORD, and in them I find comfort."}},"definableWords":["remember","LORD"],"peopleInVerse":[]},"53":{"text":"Horror hath taken hold upon me because of the wicked that forsake thy law.","ref":"Psalms 119:53","synthesized":"Rage has taken hold of me because of the wicked who reject Your law.","sources":{"KJV":{"text":"Horror hath taken hold upon me because of the wicked that forsake thy law."},"BSB":{"text":"Rage has taken hold of me because of the wicked who reject Your law."}},"definableWords":["law"],"peopleInVerse":[]},"54":{"text":"Thy statutes have been my songs in the house of my pilgrimage.","ref":"Psalms 119:54","synthesized":"Your statutes are songs to me in the house of my pilgrimage.","sources":{"KJV":{"text":"Thy statutes have been my songs in the house of my pilgrimage."},"BSB":{"text":"Your statutes are songs to me in the house of my pilgrimage."}},"definableWords":["house"],"peopleInVerse":[]},"55":{"text":"I have remembered thy name, O LORD, in the night, and have kept thy law.","ref":"Psalms 119:55","synthesized":"In the night, O LORD, I remember Your name, that I may keep Your law.","sources":{"KJV":{"text":"I have remembered thy name, O LORD, in the night, and have kept thy law."},"BSB":{"text":"In the night, O LORD, I remember Your name, that I may keep Your law."}},"definableWords":["night","LORD","remember","name","keep","law"],"peopleInVerse":[]},"56":{"text":"This I had, because I kept thy precepts.","ref":"Psalms 119:56","synthesized":"This is my practice, for I obey Your precepts.","sources":{"KJV":{"text":"This I had, because I kept thy precepts."},"BSB":{"text":"This is my practice, for I obey Your precepts."}},"definableWords":[],"peopleInVerse":[]},"57":{"text":"Thou art my portion, O LORD: I have said that I would keep thy words.","ref":"Psalms 119:57","synthesized":"The LORD is my portion; I have promised to keep Your words.","sources":{"KJV":{"text":"Thou art my portion, O LORD: I have said that I would keep thy words."},"BSB":{"text":"The LORD is my portion; I have promised to keep Your words."}},"definableWords":["LORD","keep"],"peopleInVerse":[]},"58":{"text":"I intreated thy favour with my whole heart: be merciful unto me according to thy word.","ref":"Psalms 119:58","synthesized":"I have sought Your face with all my heart; be gracious to me according to Your promise.","sources":{"KJV":{"text":"I intreated thy favour with my whole heart: be merciful unto me according to thy word."},"BSB":{"text":"I have sought Your face with all my heart; be gracious to me according to Your promise."}},"definableWords":["heart","promise"],"peopleInVerse":[]},"59":{"text":"I thought on my ways, and turned my feet unto thy testimonies.","ref":"Psalms 119:59","synthesized":"I considered my ways and turned my steps to Your testimonies.","sources":{"KJV":{"text":"I thought on my ways, and turned my feet unto thy testimonies."},"BSB":{"text":"I considered my ways and turned my steps to Your testimonies."}},"definableWords":[],"peopleInVerse":[]},"60":{"text":"I made haste, and delayed not to keep thy commandments.","ref":"Psalms 119:60","synthesized":"I hurried without hesitating to keep Your commandments.","sources":{"KJV":{"text":"I made haste, and delayed not to keep thy commandments."},"BSB":{"text":"I hurried without hesitating to keep Your commandments."}},"definableWords":["keep"],"peopleInVerse":[]},"61":{"text":"The bands of the wicked have robbed me: but I have not forgotten thy law.","ref":"Psalms 119:61","synthesized":"Though the ropes of the wicked bind me, I do not forget Your law.","sources":{"KJV":{"text":"The bands of the wicked have robbed me: but I have not forgotten thy law."},"BSB":{"text":"Though the ropes of the wicked bind me, I do not forget Your law."}},"definableWords":["law"],"peopleInVerse":[]},"62":{"text":"At midnight I will rise to give thanks unto thee because of thy righteous judgments.","ref":"Psalms 119:62","synthesized":"At midnight I rise to give You thanks for Your righteous judgments.","sources":{"KJV":{"text":"At midnight I will rise to give thanks unto thee because of thy righteous judgments."},"BSB":{"text":"At midnight I rise to give You thanks for Your righteous judgments."}},"definableWords":["righteous"],"peopleInVerse":[]},"63":{"text":"I am a companion of all them that fear thee, and of them that keep thy precepts.","ref":"Psalms 119:63","synthesized":"I am a friend to all who fear You, and to those who keep Your precepts.","sources":{"KJV":{"text":"I am a companion of all them that fear thee, and of them that keep thy precepts."},"BSB":{"text":"I am a friend to all who fear You, and to those who keep Your precepts."}},"definableWords":["fear","keep"],"peopleInVerse":[]},"64":{"text":"The earth, O LORD, is full of thy mercy: teach me thy statutes.","ref":"Psalms 119:64","synthesized":"The earth is filled with Your loving devotion, O LORD; teach me Your statutes.","sources":{"KJV":{"text":"The earth, O LORD, is full of thy mercy: teach me thy statutes."},"BSB":{"text":"The earth is filled with Your loving devotion, O LORD; teach me Your statutes."}},"definableWords":["earth","LORD"],"peopleInVerse":[]},"65":{"text":"Thou hast dealt well with thy servant, O LORD, according unto thy word.","ref":"Psalms 119:65","synthesized":"You are good to Your servant, O LORD, according to Your word.","sources":{"KJV":{"text":"Thou hast dealt well with thy servant, O LORD, according unto thy word."},"BSB":{"text":"You are good to Your servant, O LORD, according to Your word."}},"definableWords":["good","servant","LORD","word"],"peopleInVerse":[]},"66":{"text":"Teach me good judgment and knowledge: for I have believed thy commandments.","ref":"Psalms 119:66","synthesized":"Teach me good judgment and knowledge, for I believe in Your commandments.","sources":{"KJV":{"text":"Teach me good judgment and knowledge: for I have believed thy commandments."},"BSB":{"text":"Teach me good judgment and knowledge, for I believe in Your commandments."}},"definableWords":["good","judgment","knowledge"],"peopleInVerse":[]},"67":{"text":"Before I was afflicted I went astray: but now have I kept thy word.","ref":"Psalms 119:67","synthesized":"Before I was afflicted, I went astray; but now I keep Your word.","sources":{"KJV":{"text":"Before I was afflicted I went astray: but now have I kept thy word."},"BSB":{"text":"Before I was afflicted, I went astray; but now I keep Your word."}},"definableWords":["keep","word"],"peopleInVerse":[]},"68":{"text":"Thou art good, and doest good; teach me thy statutes.","ref":"Psalms 119:68","synthesized":"You are good, and You do what is good; teach me Your statutes.","sources":{"KJV":{"text":"Thou art good, and doest good; teach me thy statutes."},"BSB":{"text":"You are good, and You do what is good; teach me Your statutes."}},"definableWords":["good"],"peopleInVerse":[]},"69":{"text":"The proud have forged a lie against me: but I will keep thy precepts with my whole heart.","ref":"Psalms 119:69","synthesized":"Though the arrogant have smeared me with lies, I keep Your precepts with all my heart.","sources":{"KJV":{"text":"The proud have forged a lie against me: but I will keep thy precepts with my whole heart."},"BSB":{"text":"Though the arrogant have smeared me with lies, I keep Your precepts with all my heart."}},"definableWords":["keep","heart"],"peopleInVerse":[]},"70":{"text":"Their heart is as fat as grease; but I delight in thy law.","ref":"Psalms 119:70","synthesized":"Their hearts are hard and callous, but I delight in Your law.","sources":{"KJV":{"text":"Their heart is as fat as grease; but I delight in thy law."},"BSB":{"text":"Their hearts are hard and callous, but I delight in Your law."}},"definableWords":["law"],"peopleInVerse":[]},"71":{"text":"It is good for me that I have been afflicted; that I might learn thy statutes.","ref":"Psalms 119:71","synthesized":"It was good for me to be afflicted, that I might learn Your statutes.","sources":{"KJV":{"text":"It is good for me that I have been afflicted; that I might learn thy statutes."},"BSB":{"text":"It was good for me to be afflicted, that I might learn Your statutes."}},"definableWords":["good"],"peopleInVerse":[]},"72":{"text":"The law of thy mouth is better unto me than thousands of gold and silver.","ref":"Psalms 119:72","synthesized":"The law from Your mouth is more precious to me than thousands of pieces of gold and silver.","sources":{"KJV":{"text":"The law of thy mouth is better unto me than thousands of gold and silver."},"BSB":{"text":"The law from Your mouth is more precious to me than thousands of pieces of gold and silver."}},"definableWords":["law"],"peopleInVerse":[]},"73":{"text":"Thy hands have made me and fashioned me: give me understanding, that I may learn thy commandments.","ref":"Psalms 119:73","synthesized":"Your hands have made me and fashioned me; give me understanding to learn Your commandments.","sources":{"KJV":{"text":"Thy hands have made me and fashioned me: give me understanding, that I may learn thy commandments."},"BSB":{"text":"Your hands have made me and fashioned me; give me understanding to learn Your commandments."}},"definableWords":["made"],"peopleInVerse":[]},"74":{"text":"They that fear thee will be glad when they see me; because I have hoped in thy word.","ref":"Psalms 119:74","synthesized":"May those who fear You see me and rejoice, for I have hoped in Your word.","sources":{"KJV":{"text":"They that fear thee will be glad when they see me; because I have hoped in thy word."},"BSB":{"text":"May those who fear You see me and rejoice, for I have hoped in Your word."}},"definableWords":["fear","see","word"],"peopleInVerse":[]},"75":{"text":"I know, O LORD, that thy judgments are right, and that thou in faithfulness hast afflicted me.","ref":"Psalms 119:75","synthesized":"I know, O LORD, that Your judgments are righteous, and that in faithfulness You have afflicted me.","sources":{"KJV":{"text":"I know, O LORD, that thy judgments are right, and that thou in faithfulness hast afflicted me."},"BSB":{"text":"I know, O LORD, that Your judgments are righteous, and that in faithfulness You have afflicted me."}},"definableWords":["LORD","righteous"],"peopleInVerse":[]},"76":{"text":"Let, I pray thee, thy merciful kindness be for my comfort, according to thy word unto thy servant.","ref":"Psalms 119:76","synthesized":"May Your loving devotion comfort me, I pray, according to Your promise to Your servant.","sources":{"KJV":{"text":"Let, I pray thee, thy merciful kindness be for my comfort, according to thy word unto thy servant."},"BSB":{"text":"May Your loving devotion comfort me, I pray, according to Your promise to Your servant."}},"definableWords":["promise","servant"],"peopleInVerse":[]},"77":{"text":"Let thy tender mercies come unto me, that I may live: for thy law is my delight.","ref":"Psalms 119:77","synthesized":"May Your compassion come to me, that I may live, for Your law is my delight.","sources":{"KJV":{"text":"Let thy tender mercies come unto me, that I may live: for thy law is my delight."},"BSB":{"text":"May Your compassion come to me, that I may live, for Your law is my delight."}},"definableWords":["live","law"],"peopleInVerse":[]},"78":{"text":"Let the proud be ashamed; for they dealt perversely with me without a cause: but I will meditate in thy precepts.","ref":"Psalms 119:78","synthesized":"May the arrogant be put to shame for subverting me with a lie; I will meditate on Your precepts.","sources":{"KJV":{"text":"Let the proud be ashamed; for they dealt perversely with me without a cause: but I will meditate in thy precepts."},"BSB":{"text":"May the arrogant be put to shame for subverting me with a lie; I will meditate on Your precepts."}},"definableWords":[],"peopleInVerse":[]},"79":{"text":"Let those that fear thee turn unto me, and those that have known thy testimonies.","ref":"Psalms 119:79","synthesized":"May those who fear You turn to me, those who know Your testimonies.","sources":{"KJV":{"text":"Let those that fear thee turn unto me, and those that have known thy testimonies."},"BSB":{"text":"May those who fear You turn to me, those who know Your testimonies."}},"definableWords":["fear"],"peopleInVerse":[]},"80":{"text":"Let my heart be sound in thy statutes; that I be not ashamed.","ref":"Psalms 119:80","synthesized":"May my heart be blameless in Your statutes, that I may not be put to shame.","sources":{"KJV":{"text":"Let my heart be sound in thy statutes; that I be not ashamed."},"BSB":{"text":"May my heart be blameless in Your statutes, that I may not be put to shame."}},"definableWords":["heart"],"peopleInVerse":[]},"81":{"text":"My soul fainteth for thy salvation: but I hope in thy word.","ref":"Psalms 119:81","synthesized":"My soul faints for Your salvation; I wait for Your word.","sources":{"KJV":{"text":"My soul fainteth for thy salvation: but I hope in thy word."},"BSB":{"text":"My soul faints for Your salvation; I wait for Your word."}},"definableWords":["soul","salvation","wait","word"],"peopleInVerse":[]},"82":{"text":"Mine eyes fail for thy word, saying, When wilt thou comfort me?","ref":"Psalms 119:82","synthesized":"My eyes fail, looking for Your promise; I ask, “When will You comfort me?”","sources":{"KJV":{"text":"Mine eyes fail for thy word, saying, When wilt thou comfort me?"},"BSB":{"text":"My eyes fail, looking for Your promise; I ask, “When will You comfort me?”"}},"definableWords":["promise"],"peopleInVerse":[]},"83":{"text":"For I am become like a bottle in the smoke; yet do I not forget thy statutes.","ref":"Psalms 119:83","synthesized":"Though I am like a wineskin dried up by smoke, I do not forget Your statutes.","sources":{"KJV":{"text":"For I am become like a bottle in the smoke; yet do I not forget thy statutes."},"BSB":{"text":"Though I am like a wineskin dried up by smoke, I do not forget Your statutes."}},"definableWords":[],"peopleInVerse":[]},"84":{"text":"How many are the days of thy servant? when wilt thou execute judgment on them that persecute me?","ref":"Psalms 119:84","synthesized":"How many days must Your servant wait? When will You execute judgment on my persecutors?","sources":{"KJV":{"text":"How many are the days of thy servant? when wilt thou execute judgment on them that persecute me?"},"BSB":{"text":"How many days must Your servant wait? When will You execute judgment on my persecutors?"}},"definableWords":["days","servant","wait","judgment"],"peopleInVerse":[]},"85":{"text":"The proud have digged pits for me, which are not after thy law.","ref":"Psalms 119:85","synthesized":"The arrogant have dug pits for me in violation of Your law.","sources":{"KJV":{"text":"The proud have digged pits for me, which are not after thy law."},"BSB":{"text":"The arrogant have dug pits for me in violation of Your law."}},"definableWords":["law"],"peopleInVerse":[]},"86":{"text":"All thy commandments are faithful: they persecute me wrongfully; help thou me.","ref":"Psalms 119:86","synthesized":"All Your commandments are faithful; I am persecuted without cause—help me!","sources":{"KJV":{"text":"All thy commandments are faithful: they persecute me wrongfully; help thou me."},"BSB":{"text":"All Your commandments are faithful; I am persecuted without cause—help me!"}},"definableWords":[],"peopleInVerse":[]},"87":{"text":"They had almost consumed me upon earth; but I forsook not thy precepts.","ref":"Psalms 119:87","synthesized":"They almost wiped me from the earth, but I have not forsaken Your precepts.","sources":{"KJV":{"text":"They had almost consumed me upon earth; but I forsook not thy precepts."},"BSB":{"text":"They almost wiped me from the earth, but I have not forsaken Your precepts."}},"definableWords":["earth"],"peopleInVerse":[]},"88":{"text":"Quicken me after thy lovingkindness; so shall I keep the testimony of thy mouth.","ref":"Psalms 119:88","synthesized":"Revive me according to Your loving devotion, that I may obey the testimony of Your mouth.","sources":{"KJV":{"text":"Quicken me after thy lovingkindness; so shall I keep the testimony of thy mouth."},"BSB":{"text":"Revive me according to Your loving devotion, that I may obey the testimony of Your mouth."}},"definableWords":[],"peopleInVerse":[]},"89":{"text":"For ever, O LORD, thy word is settled in heaven.","ref":"Psalms 119:89","synthesized":"Your word, O LORD, is everlasting; it is firmly fixed in the heavens.","sources":{"KJV":{"text":"For ever, O LORD, thy word is settled in heaven."},"BSB":{"text":"Your word, O LORD, is everlasting; it is firmly fixed in the heavens."}},"definableWords":["word","LORD","everlasting","heavens"],"peopleInVerse":[]},"90":{"text":"Thy faithfulness is unto all generations: thou hast established the earth, and it abideth.","ref":"Psalms 119:90","synthesized":"Your faithfulness continues through all generations; You established the earth, and it endures.","sources":{"KJV":{"text":"Thy faithfulness is unto all generations: thou hast established the earth, and it abideth."},"BSB":{"text":"Your faithfulness continues through all generations; You established the earth, and it endures."}},"definableWords":["earth"],"peopleInVerse":[]},"91":{"text":"They continue this day according to thine ordinances: for all are thy servants.","ref":"Psalms 119:91","synthesized":"Your ordinances stand to this day, for all things are servants to You.","sources":{"KJV":{"text":"They continue this day according to thine ordinances: for all are thy servants."},"BSB":{"text":"Your ordinances stand to this day, for all things are servants to You."}},"definableWords":["stand","day","servants"],"peopleInVerse":[]},"92":{"text":"Unless thy law had been my delights, I should then have perished in mine affliction.","ref":"Psalms 119:92","synthesized":"If Your law had not been my delight, then I would have perished in my affliction.","sources":{"KJV":{"text":"Unless thy law had been my delights, I should then have perished in mine affliction."},"BSB":{"text":"If Your law had not been my delight, then I would have perished in my affliction."}},"definableWords":["law"],"peopleInVerse":[]},"93":{"text":"I will never forget thy precepts: for with them thou hast quickened me.","ref":"Psalms 119:93","synthesized":"I will never forget Your precepts, for by them You have revived me.","sources":{"KJV":{"text":"I will never forget thy precepts: for with them thou hast quickened me."},"BSB":{"text":"I will never forget Your precepts, for by them You have revived me."}},"definableWords":[],"peopleInVerse":[]},"94":{"text":"I am thine, save me; for I have sought thy precepts.","ref":"Psalms 119:94","synthesized":"I am Yours; save me, for I have sought Your precepts.","sources":{"KJV":{"text":"I am thine, save me; for I have sought thy precepts."},"BSB":{"text":"I am Yours; save me, for I have sought Your precepts."}},"definableWords":[],"peopleInVerse":[]},"95":{"text":"The wicked have waited for me to destroy me: but I will consider thy testimonies.","ref":"Psalms 119:95","synthesized":"The wicked wait to destroy me, but I will ponder Your testimonies.","sources":{"KJV":{"text":"The wicked have waited for me to destroy me: but I will consider thy testimonies."},"BSB":{"text":"The wicked wait to destroy me, but I will ponder Your testimonies."}},"definableWords":["wait"],"peopleInVerse":[]},"96":{"text":"I have seen an end of all perfection: but thy commandment is exceeding broad.","ref":"Psalms 119:96","synthesized":"I have seen a limit to all perfection, but Your commandment is without limit.","sources":{"KJV":{"text":"I have seen an end of all perfection: but thy commandment is exceeding broad."},"BSB":{"text":"I have seen a limit to all perfection, but Your commandment is without limit."}},"definableWords":["commandment"],"peopleInVerse":[]},"97":{"text":"O how love I thy law! it is my meditation all the day.","ref":"Psalms 119:97","synthesized":"Oh, how I love Your law! All day long it is my meditation.","sources":{"KJV":{"text":"O how love I thy law! it is my meditation all the day."},"BSB":{"text":"Oh, how I love Your law! All day long it is my meditation."}},"definableWords":["love","law","day"],"peopleInVerse":[]},"98":{"text":"Thou through thy commandments hast made me wiser than mine enemies: for they are ever with me.","ref":"Psalms 119:98","synthesized":"Your commandments make me wiser than my enemies, for they are always with me.","sources":{"KJV":{"text":"Thou through thy commandments hast made me wiser than mine enemies: for they are ever with me."},"BSB":{"text":"Your commandments make me wiser than my enemies, for they are always with me."}},"definableWords":["make"],"peopleInVerse":[]},"99":{"text":"I have more understanding than all my teachers: for thy testimonies are my meditation.","ref":"Psalms 119:99","synthesized":"I have more insight than all my teachers, for Your testimonies are my meditation.","sources":{"KJV":{"text":"I have more understanding than all my teachers: for thy testimonies are my meditation."},"BSB":{"text":"I have more insight than all my teachers, for Your testimonies are my meditation."}},"definableWords":[],"peopleInVerse":[]},"100":{"text":"I understand more than the ancients, because I keep thy precepts.","ref":"Psalms 119:100","synthesized":"I discern more than the elders, for I obey Your precepts.","sources":{"KJV":{"text":"I understand more than the ancients, because I keep thy precepts."},"BSB":{"text":"I discern more than the elders, for I obey Your precepts."}},"definableWords":[],"peopleInVerse":[]},"101":{"text":"I have refrained my feet from every evil way, that I might keep thy word.","ref":"Psalms 119:101","synthesized":"I have kept my feet from every evil path, that I may keep Your word.","sources":{"KJV":{"text":"I have refrained my feet from every evil way, that I might keep thy word."},"BSB":{"text":"I have kept my feet from every evil path, that I may keep Your word."}},"definableWords":["evil","keep","word"],"peopleInVerse":[]},"102":{"text":"I have not departed from thy judgments: for thou hast taught me.","ref":"Psalms 119:102","synthesized":"I have not departed from Your ordinances, for You Yourself have taught me.","sources":{"KJV":{"text":"I have not departed from thy judgments: for thou hast taught me."},"BSB":{"text":"I have not departed from Your ordinances, for You Yourself have taught me."}},"definableWords":[],"peopleInVerse":[]},"103":{"text":"How sweet are thy words unto my taste! yea, sweeter than honey to my mouth!","ref":"Psalms 119:103","synthesized":"How sweet are Your words to my taste— sweeter than honey in my mouth!","sources":{"KJV":{"text":"How sweet are thy words unto my taste! yea, sweeter than honey to my mouth!"},"BSB":{"text":"How sweet are Your words to my taste— sweeter than honey in my mouth!"}},"definableWords":[],"peopleInVerse":[]},"104":{"text":"Through thy precepts I get understanding: therefore I hate every false way.","ref":"Psalms 119:104","synthesized":"I gain understanding from Your precepts; therefore I hate every false way.","sources":{"KJV":{"text":"Through thy precepts I get understanding: therefore I hate every false way."},"BSB":{"text":"I gain understanding from Your precepts; therefore I hate every false way."}},"definableWords":["way"],"peopleInVerse":[]},"105":{"text":"Thy word is a lamp unto my feet, and a light unto my path.","ref":"Psalms 119:105","synthesized":"Your word is a lamp to my feet and a light to my path.","sources":{"KJV":{"text":"Thy word is a lamp unto my feet, and a light unto my path."},"BSB":{"text":"Your word is a lamp to my feet and a light to my path."}},"definableWords":["word","light"],"peopleInVerse":[]},"106":{"text":"I have sworn, and I will perform it, that I will keep thy righteous judgments.","ref":"Psalms 119:106","synthesized":"I have sworn and confirmed that I will keep Your righteous judgments.","sources":{"KJV":{"text":"I have sworn, and I will perform it, that I will keep thy righteous judgments."},"BSB":{"text":"I have sworn and confirmed that I will keep Your righteous judgments."}},"definableWords":["keep","righteous"],"peopleInVerse":[]},"107":{"text":"I am afflicted very much: quicken me, O LORD, according unto thy word.","ref":"Psalms 119:107","synthesized":"I am severely afflicted, O LORD; revive me through Your word.","sources":{"KJV":{"text":"I am afflicted very much: quicken me, O LORD, according unto thy word."},"BSB":{"text":"I am severely afflicted, O LORD; revive me through Your word."}},"definableWords":["LORD","word"],"peopleInVerse":[]},"108":{"text":"Accept, I beseech thee, the freewill offerings of my mouth, O LORD, and teach me thy judgments.","ref":"Psalms 119:108","synthesized":"Accept the freewill offerings of my mouth, O LORD, and teach me Your judgments.","sources":{"KJV":{"text":"Accept, I beseech thee, the freewill offerings of my mouth, O LORD, and teach me thy judgments."},"BSB":{"text":"Accept the freewill offerings of my mouth, O LORD, and teach me Your judgments."}},"definableWords":["LORD"],"peopleInVerse":[]},"109":{"text":"My soul is continually in my hand: yet do I not forget thy law.","ref":"Psalms 119:109","synthesized":"I constantly take my life in my hands, yet I do not forget Your law.","sources":{"KJV":{"text":"My soul is continually in my hand: yet do I not forget thy law."},"BSB":{"text":"I constantly take my life in my hands, yet I do not forget Your law."}},"definableWords":["life","law"],"peopleInVerse":[]},"110":{"text":"The wicked have laid a snare for me: yet I erred not from thy precepts.","ref":"Psalms 119:110","synthesized":"The wicked have set a snare for me, but I have not strayed from Your precepts.","sources":{"KJV":{"text":"The wicked have laid a snare for me: yet I erred not from thy precepts."},"BSB":{"text":"The wicked have set a snare for me, but I have not strayed from Your precepts."}},"definableWords":[],"peopleInVerse":[]},"111":{"text":"Thy testimonies have I taken as an heritage for ever: for they are the rejoicing of my heart.","ref":"Psalms 119:111","synthesized":"Your testimonies are my heritage forever, for they are the joy of my heart.","sources":{"KJV":{"text":"Thy testimonies have I taken as an heritage for ever: for they are the rejoicing of my heart."},"BSB":{"text":"Your testimonies are my heritage forever, for they are the joy of my heart."}},"definableWords":["joy","heart"],"peopleInVerse":[]},"112":{"text":"I have inclined mine heart to perform thy statutes alway, even unto the end.","ref":"Psalms 119:112","synthesized":"I have inclined my heart to perform Your statutes, even to the very end.","sources":{"KJV":{"text":"I have inclined mine heart to perform thy statutes alway, even unto the end."},"BSB":{"text":"I have inclined my heart to perform Your statutes, even to the very end."}},"definableWords":["heart"],"peopleInVerse":[]},"113":{"text":"I hate vain thoughts: but thy law do I love.","ref":"Psalms 119:113","synthesized":"The double-minded I despise, but Your law I love.","sources":{"KJV":{"text":"I hate vain thoughts: but thy law do I love."},"BSB":{"text":"The double-minded I despise, but Your law I love."}},"definableWords":["law","love"],"peopleInVerse":[]},"114":{"text":"Thou art my hiding place and my shield: I hope in thy word.","ref":"Psalms 119:114","synthesized":"You are my hiding place and my shield; I put my hope in Your word.","sources":{"KJV":{"text":"Thou art my hiding place and my shield: I hope in thy word."},"BSB":{"text":"You are my hiding place and my shield; I put my hope in Your word."}},"definableWords":["hope","word"],"peopleInVerse":[]},"115":{"text":"Depart from me, ye evildoers: for I will keep the commandments of my God.","ref":"Psalms 119:115","synthesized":"Depart from me, you evildoers, that I may obey the commandments of my God.","sources":{"KJV":{"text":"Depart from me, ye evildoers: for I will keep the commandments of my God."},"BSB":{"text":"Depart from me, you evildoers, that I may obey the commandments of my God."}},"definableWords":["God"],"peopleInVerse":[]},"116":{"text":"Uphold me according unto thy word, that I may live: and let me not be ashamed of my hope.","ref":"Psalms 119:116","synthesized":"Sustain me as You promised, that I may live; let me not be ashamed of my hope.","sources":{"KJV":{"text":"Uphold me according unto thy word, that I may live: and let me not be ashamed of my hope."},"BSB":{"text":"Sustain me as You promised, that I may live; let me not be ashamed of my hope."}},"definableWords":["live","hope"],"peopleInVerse":[]},"117":{"text":"Hold thou me up, and I shall be safe: and I will have respect unto thy statutes continually.","ref":"Psalms 119:117","synthesized":"Uphold me, and I will be saved, that I may always regard Your statutes.","sources":{"KJV":{"text":"Hold thou me up, and I shall be safe: and I will have respect unto thy statutes continually."},"BSB":{"text":"Uphold me, and I will be saved, that I may always regard Your statutes."}},"definableWords":[],"peopleInVerse":[]},"118":{"text":"Thou hast trodden down all them that err from thy statutes: for their deceit is falsehood.","ref":"Psalms 119:118","synthesized":"You reject all who stray from Your statutes, for their deceitfulness is in vain.","sources":{"KJV":{"text":"Thou hast trodden down all them that err from thy statutes: for their deceit is falsehood."},"BSB":{"text":"You reject all who stray from Your statutes, for their deceitfulness is in vain."}},"definableWords":[],"peopleInVerse":[]},"119":{"text":"Thou puttest away all the wicked of the earth like dross: therefore I love thy testimonies.","ref":"Psalms 119:119","synthesized":"All the wicked on earth You discard like dross; therefore I love Your testimonies.","sources":{"KJV":{"text":"Thou puttest away all the wicked of the earth like dross: therefore I love thy testimonies."},"BSB":{"text":"All the wicked on earth You discard like dross; therefore I love Your testimonies."}},"definableWords":["earth","love"],"peopleInVerse":[]},"120":{"text":"My flesh trembleth for fear of thee; and I am afraid of thy judgments.","ref":"Psalms 119:120","synthesized":"My flesh trembles in awe of You; I stand in fear of Your judgments.","sources":{"KJV":{"text":"My flesh trembleth for fear of thee; and I am afraid of thy judgments."},"BSB":{"text":"My flesh trembles in awe of You; I stand in fear of Your judgments."}},"definableWords":["flesh","stand","fear"],"peopleInVerse":[]},"121":{"text":"I have done judgment and justice: leave me not to mine oppressors.","ref":"Psalms 119:121","synthesized":"I have done what is just and right; do not leave me to my oppressors.","sources":{"KJV":{"text":"I have done judgment and justice: leave me not to mine oppressors."},"BSB":{"text":"I have done what is just and right; do not leave me to my oppressors."}},"definableWords":[],"peopleInVerse":[]},"122":{"text":"Be surety for thy servant for good: let not the proud oppress me.","ref":"Psalms 119:122","synthesized":"Ensure Your servant’s well-being; do not let the arrogant oppress me.","sources":{"KJV":{"text":"Be surety for thy servant for good: let not the proud oppress me."},"BSB":{"text":"Ensure Your servant’s well-being; do not let the arrogant oppress me."}},"definableWords":["servant"],"peopleInVerse":[]},"123":{"text":"Mine eyes fail for thy salvation, and for the word of thy righteousness.","ref":"Psalms 119:123","synthesized":"My eyes fail, looking for Your salvation, and for Your righteous promise.","sources":{"KJV":{"text":"Mine eyes fail for thy salvation, and for the word of thy righteousness."},"BSB":{"text":"My eyes fail, looking for Your salvation, and for Your righteous promise."}},"definableWords":["salvation","righteous","promise"],"peopleInVerse":[]},"124":{"text":"Deal with thy servant according unto thy mercy, and teach me thy statutes.","ref":"Psalms 119:124","synthesized":"Deal with Your servant according to Your loving devotion, and teach me Your statutes.","sources":{"KJV":{"text":"Deal with thy servant according unto thy mercy, and teach me thy statutes."},"BSB":{"text":"Deal with Your servant according to Your loving devotion, and teach me Your statutes."}},"definableWords":["servant"],"peopleInVerse":[]},"125":{"text":"I am thy servant; give me understanding, that I may know thy testimonies.","ref":"Psalms 119:125","synthesized":"I am Your servant; give me understanding, that I may know Your testimonies.","sources":{"KJV":{"text":"I am thy servant; give me understanding, that I may know thy testimonies."},"BSB":{"text":"I am Your servant; give me understanding, that I may know Your testimonies."}},"definableWords":["servant"],"peopleInVerse":[]},"126":{"text":"It is time for thee, LORD, to work: for they have made void thy law.","ref":"Psalms 119:126","synthesized":"It is time for the LORD to act, for they have broken Your law.","sources":{"KJV":{"text":"It is time for thee, LORD, to work: for they have made void thy law."},"BSB":{"text":"It is time for the LORD to act, for they have broken Your law."}},"definableWords":["LORD","law"],"peopleInVerse":[]},"127":{"text":"Therefore I love thy commandments above gold; yea, above fine gold.","ref":"Psalms 119:127","synthesized":"Therefore I love Your commandments more than gold, even the purest gold.","sources":{"KJV":{"text":"Therefore I love thy commandments above gold; yea, above fine gold."},"BSB":{"text":"Therefore I love Your commandments more than gold, even the purest gold."}},"definableWords":["love"],"peopleInVerse":[]},"128":{"text":"Therefore I esteem all thy precepts concerning all things to be right; and I hate every false way.","ref":"Psalms 119:128","synthesized":"Therefore I admire all Your precepts and hate every false way.","sources":{"KJV":{"text":"Therefore I esteem all thy precepts concerning all things to be right; and I hate every false way."},"BSB":{"text":"Therefore I admire all Your precepts and hate every false way."}},"definableWords":["way"],"peopleInVerse":[]},"129":{"text":"Thy testimonies are wonderful: therefore doth my soul keep them.","ref":"Psalms 119:129","synthesized":"Wonderful are Your testimonies; therefore I obey them.","sources":{"KJV":{"text":"Thy testimonies are wonderful: therefore doth my soul keep them."},"BSB":{"text":"Wonderful are Your testimonies; therefore I obey them."}},"definableWords":[],"peopleInVerse":[]},"130":{"text":"The entrance of thy words giveth light; it giveth understanding unto the simple.","ref":"Psalms 119:130","synthesized":"The unfolding of Your words gives light; it informs the simple.","sources":{"KJV":{"text":"The entrance of thy words giveth light; it giveth understanding unto the simple."},"BSB":{"text":"The unfolding of Your words gives light; it informs the simple."}},"definableWords":["light"],"peopleInVerse":[]},"131":{"text":"I opened my mouth, and panted: for I longed for thy commandments.","ref":"Psalms 119:131","synthesized":"I open my mouth and pant, longing for Your commandments.","sources":{"KJV":{"text":"I opened my mouth, and panted: for I longed for thy commandments."},"BSB":{"text":"I open my mouth and pant, longing for Your commandments."}},"definableWords":[],"peopleInVerse":[]},"132":{"text":"Look thou upon me, and be merciful unto me, as thou usest to do unto those that love thy name.","ref":"Psalms 119:132","synthesized":"Turn to me and show me mercy, as You do to those who love Your name.","sources":{"KJV":{"text":"Look thou upon me, and be merciful unto me, as thou usest to do unto those that love thy name."},"BSB":{"text":"Turn to me and show me mercy, as You do to those who love Your name."}},"definableWords":["mercy","love","name"],"peopleInVerse":[]},"133":{"text":"Order my steps in thy word: and let not any iniquity have dominion over me.","ref":"Psalms 119:133","synthesized":"Order my steps in Your word; let no sin rule over me.","sources":{"KJV":{"text":"Order my steps in thy word: and let not any iniquity have dominion over me."},"BSB":{"text":"Order my steps in Your word; let no sin rule over me."}},"definableWords":["word","sin","rule"],"peopleInVerse":[]},"134":{"text":"Deliver me from the oppression of man: so will I keep thy precepts.","ref":"Psalms 119:134","synthesized":"Redeem me from the oppression of man, that I may keep Your precepts.","sources":{"KJV":{"text":"Deliver me from the oppression of man: so will I keep thy precepts."},"BSB":{"text":"Redeem me from the oppression of man, that I may keep Your precepts."}},"definableWords":["man","keep"],"peopleInVerse":[]},"135":{"text":"Make thy face to shine upon thy servant; and teach me thy statutes.","ref":"Psalms 119:135","synthesized":"Make Your face shine upon Your servant, and teach me Your statutes.","sources":{"KJV":{"text":"Make thy face to shine upon thy servant; and teach me thy statutes."},"BSB":{"text":"Make Your face shine upon Your servant, and teach me Your statutes."}},"definableWords":["make","servant"],"peopleInVerse":[]},"136":{"text":"Rivers of waters run down mine eyes, because they keep not thy law.","ref":"Psalms 119:136","synthesized":"My eyes shed streams of tears because Your law is not obeyed.","sources":{"KJV":{"text":"Rivers of waters run down mine eyes, because they keep not thy law."},"BSB":{"text":"My eyes shed streams of tears because Your law is not obeyed."}},"definableWords":["law"],"peopleInVerse":[]},"137":{"text":"Righteous art thou, O LORD, and upright are thy judgments.","ref":"Psalms 119:137","synthesized":"Righteous are You, O LORD, and upright are Your judgments.","sources":{"KJV":{"text":"Righteous art thou, O LORD, and upright are thy judgments."},"BSB":{"text":"Righteous are You, O LORD, and upright are Your judgments."}},"definableWords":["righteous","LORD"],"peopleInVerse":[]},"138":{"text":"Thy testimonies that thou hast commanded are righteous and very faithful.","ref":"Psalms 119:138","synthesized":"The testimonies You have laid down are righteous and altogether faithful.","sources":{"KJV":{"text":"Thy testimonies that thou hast commanded are righteous and very faithful."},"BSB":{"text":"The testimonies You have laid down are righteous and altogether faithful."}},"definableWords":["righteous"],"peopleInVerse":[]},"139":{"text":"My zeal hath consumed me, because mine enemies have forgotten thy words.","ref":"Psalms 119:139","synthesized":"My zeal has consumed me because my foes forget Your words.","sources":{"KJV":{"text":"My zeal hath consumed me, because mine enemies have forgotten thy words."},"BSB":{"text":"My zeal has consumed me because my foes forget Your words."}},"definableWords":[],"peopleInVerse":[]},"140":{"text":"Thy word is very pure: therefore thy servant loveth it.","ref":"Psalms 119:140","synthesized":"Your promise is completely pure; therefore Your servant loves it.","sources":{"KJV":{"text":"Thy word is very pure: therefore thy servant loveth it."},"BSB":{"text":"Your promise is completely pure; therefore Your servant loves it."}},"definableWords":["promise","servant"],"peopleInVerse":[]},"141":{"text":"I am small and despised: yet do not I forget thy precepts.","ref":"Psalms 119:141","synthesized":"I am lowly and despised, but I do not forget Your precepts.","sources":{"KJV":{"text":"I am small and despised: yet do not I forget thy precepts."},"BSB":{"text":"I am lowly and despised, but I do not forget Your precepts."}},"definableWords":[],"peopleInVerse":[]},"142":{"text":"Thy righteousness is an everlasting righteousness, and thy law is the truth.","ref":"Psalms 119:142","synthesized":"Your righteousness is everlasting and Your law is true.","sources":{"KJV":{"text":"Thy righteousness is an everlasting righteousness, and thy law is the truth."},"BSB":{"text":"Your righteousness is everlasting and Your law is true."}},"definableWords":["righteousness","everlasting","law"],"peopleInVerse":[]},"143":{"text":"Trouble and anguish have taken hold on me: yet thy commandments are my delights.","ref":"Psalms 119:143","synthesized":"Trouble and distress have found me, but Your commandments are my delight.","sources":{"KJV":{"text":"Trouble and anguish have taken hold on me: yet thy commandments are my delights."},"BSB":{"text":"Trouble and distress have found me, but Your commandments are my delight."}},"definableWords":[],"peopleInVerse":[]},"144":{"text":"The righteousness of thy testimonies is everlasting: give me understanding, and I shall live.","ref":"Psalms 119:144","synthesized":"Your testimonies are righteous forever. Give me understanding, that I may live.","sources":{"KJV":{"text":"The righteousness of thy testimonies is everlasting: give me understanding, and I shall live."},"BSB":{"text":"Your testimonies are righteous forever. Give me understanding, that I may live."}},"definableWords":["righteous","live"],"peopleInVerse":[]},"145":{"text":"I cried with my whole heart; hear me, O LORD: I will keep thy statutes.","ref":"Psalms 119:145","synthesized":"I call with all my heart; answer me, O LORD! I will obey Your statutes.","sources":{"KJV":{"text":"I cried with my whole heart; hear me, O LORD: I will keep thy statutes."},"BSB":{"text":"I call with all my heart; answer me, O LORD! I will obey Your statutes."}},"definableWords":["heart","LORD"],"peopleInVerse":[]},"146":{"text":"I cried unto thee; save me, and I shall keep thy testimonies.","ref":"Psalms 119:146","synthesized":"I call to You; save me, that I may keep Your testimonies.","sources":{"KJV":{"text":"I cried unto thee; save me, and I shall keep thy testimonies."},"BSB":{"text":"I call to You; save me, that I may keep Your testimonies."}},"definableWords":["keep"],"peopleInVerse":[]},"147":{"text":"I prevented the dawning of the morning, and cried: I hoped in thy word.","ref":"Psalms 119:147","synthesized":"I rise before dawn and cry for help; in Your word I have put my hope.","sources":{"KJV":{"text":"I prevented the dawning of the morning, and cried: I hoped in thy word."},"BSB":{"text":"I rise before dawn and cry for help; in Your word I have put my hope."}},"definableWords":["word","hope"],"peopleInVerse":[]},"148":{"text":"Mine eyes prevent the night watches, that I might meditate in thy word.","ref":"Psalms 119:148","synthesized":"My eyes anticipate the watches of night, that I may meditate on Your word.","sources":{"KJV":{"text":"Mine eyes prevent the night watches, that I might meditate in thy word."},"BSB":{"text":"My eyes anticipate the watches of night, that I may meditate on Your word."}},"definableWords":["night","word"],"peopleInVerse":[]},"149":{"text":"Hear my voice according unto thy lovingkindness: O LORD, quicken me according to thy judgment.","ref":"Psalms 119:149","synthesized":"Hear my voice, O LORD, according to Your loving devotion; give me life according to Your justice.","sources":{"KJV":{"text":"Hear my voice according unto thy lovingkindness: O LORD, quicken me according to thy judgment."},"BSB":{"text":"Hear my voice, O LORD, according to Your loving devotion; give me life according to Your justice."}},"definableWords":["hear","voice","LORD","life","justice"],"peopleInVerse":[]},"150":{"text":"They draw nigh that follow after mischief: they are far from thy law.","ref":"Psalms 119:150","synthesized":"Those who follow after wickedness draw near; they are far from Your law.","sources":{"KJV":{"text":"They draw nigh that follow after mischief: they are far from thy law."},"BSB":{"text":"Those who follow after wickedness draw near; they are far from Your law."}},"definableWords":["law"],"peopleInVerse":[]},"151":{"text":"Thou art near, O LORD; and all thy commandments are truth.","ref":"Psalms 119:151","synthesized":"You are near, O LORD, and all Your commandments are true.","sources":{"KJV":{"text":"Thou art near, O LORD; and all thy commandments are truth."},"BSB":{"text":"You are near, O LORD, and all Your commandments are true."}},"definableWords":["LORD"],"peopleInVerse":[]},"152":{"text":"Concerning thy testimonies, I have known of old that thou hast founded them for ever.","ref":"Psalms 119:152","synthesized":"Long ago I learned from Your testimonies that You have established them forever.","sources":{"KJV":{"text":"Concerning thy testimonies, I have known of old that thou hast founded them for ever."},"BSB":{"text":"Long ago I learned from Your testimonies that You have established them forever."}},"definableWords":[],"peopleInVerse":[]},"153":{"text":"Consider mine affliction, and deliver me: for I do not forget thy law.","ref":"Psalms 119:153","synthesized":"Look upon my affliction and rescue me, for I have not forgotten Your law.","sources":{"KJV":{"text":"Consider mine affliction, and deliver me: for I do not forget thy law."},"BSB":{"text":"Look upon my affliction and rescue me, for I have not forgotten Your law."}},"definableWords":["law"],"peopleInVerse":[]},"154":{"text":"Plead my cause, and deliver me: quicken me according to thy word.","ref":"Psalms 119:154","synthesized":"Defend my cause and redeem me; revive me according to Your word.","sources":{"KJV":{"text":"Plead my cause, and deliver me: quicken me according to thy word."},"BSB":{"text":"Defend my cause and redeem me; revive me according to Your word."}},"definableWords":["word"],"peopleInVerse":[]},"155":{"text":"Salvation is far from the wicked: for they seek not thy statutes.","ref":"Psalms 119:155","synthesized":"Salvation is far from the wicked because they do not seek Your statutes.","sources":{"KJV":{"text":"Salvation is far from the wicked: for they seek not thy statutes."},"BSB":{"text":"Salvation is far from the wicked because they do not seek Your statutes."}},"definableWords":["salvation","seek"],"peopleInVerse":[]},"156":{"text":"Great are thy tender mercies, O LORD: quicken me according to thy judgments.","ref":"Psalms 119:156","synthesized":"Great are Your mercies, O LORD; revive me according to Your ordinances.","sources":{"KJV":{"text":"Great are thy tender mercies, O LORD: quicken me according to thy judgments."},"BSB":{"text":"Great are Your mercies, O LORD; revive me according to Your ordinances."}},"definableWords":["great","LORD"],"peopleInVerse":[]},"157":{"text":"Many are my persecutors and mine enemies; yet do I not decline from thy testimonies.","ref":"Psalms 119:157","synthesized":"Though my persecutors and foes are many, I have not turned from Your testimonies.","sources":{"KJV":{"text":"Many are my persecutors and mine enemies; yet do I not decline from thy testimonies."},"BSB":{"text":"Though my persecutors and foes are many, I have not turned from Your testimonies."}},"definableWords":[],"peopleInVerse":[]},"158":{"text":"I beheld the transgressors, and was grieved; because they kept not thy word.","ref":"Psalms 119:158","synthesized":"I look on the faithless with loathing because they do not keep Your word.","sources":{"KJV":{"text":"I beheld the transgressors, and was grieved; because they kept not thy word."},"BSB":{"text":"I look on the faithless with loathing because they do not keep Your word."}},"definableWords":["keep","word"],"peopleInVerse":[]},"159":{"text":"Consider how I love thy precepts: quicken me, O LORD, according to thy lovingkindness.","ref":"Psalms 119:159","synthesized":"Consider how I love Your precepts, O LORD; give me life according to Your loving devotion.","sources":{"KJV":{"text":"Consider how I love thy precepts: quicken me, O LORD, according to thy lovingkindness."},"BSB":{"text":"Consider how I love Your precepts, O LORD; give me life according to Your loving devotion."}},"definableWords":["love","LORD","life"],"peopleInVerse":[]},"160":{"text":"Thy word is true from the beginning: and every one of thy righteous judgments endureth for ever.","ref":"Psalms 119:160","synthesized":"The entirety of Your word is truth, and all Your righteous judgments endure forever.","sources":{"KJV":{"text":"Thy word is true from the beginning: and every one of thy righteous judgments endureth for ever."},"BSB":{"text":"The entirety of Your word is truth, and all Your righteous judgments endure forever."}},"definableWords":["word","truth","righteous"],"peopleInVerse":[]},"161":{"text":"Princes have persecuted me without a cause: but my heart standeth in awe of thy word.","ref":"Psalms 119:161","synthesized":"Rulers persecute me without cause, but my heart fears only Your word.","sources":{"KJV":{"text":"Princes have persecuted me without a cause: but my heart standeth in awe of thy word."},"BSB":{"text":"Rulers persecute me without cause, but my heart fears only Your word."}},"definableWords":["heart","word"],"peopleInVerse":[]},"162":{"text":"I rejoice at thy word, as one that findeth great spoil.","ref":"Psalms 119:162","synthesized":"I rejoice in Your promise like one who finds great spoil.","sources":{"KJV":{"text":"I rejoice at thy word, as one that findeth great spoil."},"BSB":{"text":"I rejoice in Your promise like one who finds great spoil."}},"definableWords":["promise","one","great"],"peopleInVerse":[]},"163":{"text":"I hate and abhor lying: but thy law do I love.","ref":"Psalms 119:163","synthesized":"I hate and abhor falsehood, but Your law I love.","sources":{"KJV":{"text":"I hate and abhor lying: but thy law do I love."},"BSB":{"text":"I hate and abhor falsehood, but Your law I love."}},"definableWords":["law","love"],"peopleInVerse":[]},"164":{"text":"Seven times a day do I praise thee because of thy righteous judgments.","ref":"Psalms 119:164","synthesized":"Seven times a day I praise You for Your righteous judgments.","sources":{"KJV":{"text":"Seven times a day do I praise thee because of thy righteous judgments."},"BSB":{"text":"Seven times a day I praise You for Your righteous judgments."}},"definableWords":["day","praise","righteous"],"peopleInVerse":[]},"165":{"text":"Great peace have they which love thy law: and nothing shall offend them.","ref":"Psalms 119:165","synthesized":"Abundant peace belongs to those who love Your law; nothing can make them stumble.","sources":{"KJV":{"text":"Great peace have they which love thy law: and nothing shall offend them."},"BSB":{"text":"Abundant peace belongs to those who love Your law; nothing can make them stumble."}},"definableWords":["peace","love","law","make"],"peopleInVerse":[]},"166":{"text":"LORD, I have hoped for thy salvation, and done thy commandments.","ref":"Psalms 119:166","synthesized":"I wait for Your salvation, O LORD, and I carry out Your commandments.","sources":{"KJV":{"text":"LORD, I have hoped for thy salvation, and done thy commandments."},"BSB":{"text":"I wait for Your salvation, O LORD, and I carry out Your commandments."}},"definableWords":["wait","salvation","LORD"],"peopleInVerse":[]},"167":{"text":"My soul hath kept thy testimonies; and I love them exceedingly.","ref":"Psalms 119:167","synthesized":"I obey Your testimonies and love them greatly.","sources":{"KJV":{"text":"My soul hath kept thy testimonies; and I love them exceedingly."},"BSB":{"text":"I obey Your testimonies and love them greatly."}},"definableWords":["love"],"peopleInVerse":[]},"168":{"text":"I have kept thy precepts and thy testimonies: for all my ways are before thee.","ref":"Psalms 119:168","synthesized":"I obey Your precepts and Your testimonies, for all my ways are before You.","sources":{"KJV":{"text":"I have kept thy precepts and thy testimonies: for all my ways are before thee."},"BSB":{"text":"I obey Your precepts and Your testimonies, for all my ways are before You."}},"definableWords":[],"peopleInVerse":[]},"169":{"text":"Let my cry come near before thee, O LORD: give me understanding according to thy word.","ref":"Psalms 119:169","synthesized":"May my cry come before You, O LORD; give me understanding according to Your word.","sources":{"KJV":{"text":"Let my cry come near before thee, O LORD: give me understanding according to thy word."},"BSB":{"text":"May my cry come before You, O LORD; give me understanding according to Your word."}},"definableWords":["LORD","word"],"peopleInVerse":[]},"170":{"text":"Let my supplication come before thee: deliver me according to thy word.","ref":"Psalms 119:170","synthesized":"May my plea come before You; rescue me according to Your promise.","sources":{"KJV":{"text":"Let my supplication come before thee: deliver me according to thy word."},"BSB":{"text":"May my plea come before You; rescue me according to Your promise."}},"definableWords":["promise"],"peopleInVerse":[]},"171":{"text":"My lips shall utter praise, when thou hast taught me thy statutes.","ref":"Psalms 119:171","synthesized":"My lips pour forth praise, for You teach me Your statutes.","sources":{"KJV":{"text":"My lips shall utter praise, when thou hast taught me thy statutes."},"BSB":{"text":"My lips pour forth praise, for You teach me Your statutes."}},"definableWords":["praise"],"peopleInVerse":[]},"172":{"text":"My tongue shall speak of thy word: for all thy commandments are righteousness.","ref":"Psalms 119:172","synthesized":"My tongue sings of Your word, for all Your commandments are righteous.","sources":{"KJV":{"text":"My tongue shall speak of thy word: for all thy commandments are righteousness."},"BSB":{"text":"My tongue sings of Your word, for all Your commandments are righteous."}},"definableWords":["word","righteous"],"peopleInVerse":[]},"173":{"text":"Let thine hand help me; for I have chosen thy precepts.","ref":"Psalms 119:173","synthesized":"May Your hand be ready to help me, for I have chosen Your precepts.","sources":{"KJV":{"text":"Let thine hand help me; for I have chosen thy precepts."},"BSB":{"text":"May Your hand be ready to help me, for I have chosen Your precepts."}},"definableWords":[],"peopleInVerse":[]},"174":{"text":"I have longed for thy salvation, O LORD; and thy law is my delight.","ref":"Psalms 119:174","synthesized":"I long for Your salvation, O LORD, and Your law is my delight.","sources":{"KJV":{"text":"I have longed for thy salvation, O LORD; and thy law is my delight."},"BSB":{"text":"I long for Your salvation, O LORD, and Your law is my delight."}},"definableWords":["salvation","LORD","law"],"peopleInVerse":[]},"175":{"text":"Let my soul live, and it shall praise thee; and let thy judgments help me.","ref":"Psalms 119:175","synthesized":"Let me live to praise You; may Your judgments sustain me.","sources":{"KJV":{"text":"Let my soul live, and it shall praise thee; and let thy judgments help me."},"BSB":{"text":"Let me live to praise You; may Your judgments sustain me."}},"definableWords":["live","praise"],"peopleInVerse":[]},"176":{"text":"I have gone astray like a lost sheep; seek thy servant; for I do not forget thy commandments.","ref":"Psalms 119:176","synthesized":"I have strayed like a lost sheep; seek Your servant, for I have not forgotten Your commandments.","sources":{"KJV":{"text":"I have gone astray like a lost sheep; seek thy servant; for I do not forget thy commandments."},"BSB":{"text":"I have strayed like a lost sheep; seek Your servant, for I have not forgotten Your commandments."}},"definableWords":["seek","servant"],"peopleInVerse":[]}}},"120":{"chapter":"120","title":"IN MY DISTRESS I CRIED","verses":{"1":{"text":"In my distress I cried unto the LORD, and he heard me.","ref":"Psalms 120:1","synthesized":"In my distress I cried to the LORD, and He answered me.","sources":{"KJV":{"text":"In my distress I cried unto the LORD, and he heard me."},"BSB":{"text":"In my distress I cried to the LORD, and He answered me."}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"Deliver my soul, O LORD, from lying lips, and from a deceitful tongue.","ref":"Psalms 120:2","synthesized":"Deliver my soul, O LORD, from lying lips and a deceitful tongue.","sources":{"KJV":{"text":"Deliver my soul, O LORD, from lying lips, and from a deceitful tongue."},"BSB":{"text":"Deliver my soul, O LORD, from lying lips and a deceitful tongue."}},"definableWords":["deliver","soul","LORD"],"peopleInVerse":[]},"3":{"text":"What shall be given unto thee? or what shall be done unto thee, thou false tongue?","ref":"Psalms 120:3","synthesized":"What will He do to you, and what will be added to you, O deceitful tongue?","sources":{"KJV":{"text":"What shall be given unto thee? or what shall be done unto thee, thou false tongue?"},"BSB":{"text":"What will He do to you, and what will be added to you, O deceitful tongue?"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Sharp arrows of the mighty, with coals of juniper.","ref":"Psalms 120:4","synthesized":"Sharp arrows will come from the warrior, with burning coals of the broom tree!","sources":{"KJV":{"text":"Sharp arrows of the mighty, with coals of juniper."},"BSB":{"text":"Sharp arrows will come from the warrior, with burning coals of the broom tree!"}},"definableWords":["tree"],"peopleInVerse":[]},"5":{"text":"Woe is me, that I sojourn in Mesech, that I dwell in the tents of Kedar!","ref":"Psalms 120:5","synthesized":"Woe to me that I dwell in Meshech, that I live among the tents of Kedar!","sources":{"KJV":{"text":"Woe is me, that I sojourn in Mesech, that I dwell in the tents of Kedar!"},"BSB":{"text":"Woe to me that I dwell in Meshech, that I live among the tents of Kedar!"}},"definableWords":["live"],"peopleInVerse":[]},"6":{"text":"My soul hath long dwelt with him that hateth peace.","ref":"Psalms 120:6","synthesized":"Too long have I dwelt among those who hate peace.","sources":{"KJV":{"text":"My soul hath long dwelt with him that hateth peace."},"BSB":{"text":"Too long have I dwelt among those who hate peace."}},"definableWords":["peace"],"peopleInVerse":[]},"7":{"text":"I am for peace: but when I speak, they are for war.","ref":"Psalms 120:7","synthesized":"I am in favor of peace; but when I speak, they want war.","sources":{"KJV":{"text":"I am for peace: but when I speak, they are for war."},"BSB":{"text":"I am in favor of peace; but when I speak, they want war."}},"definableWords":["peace"],"peopleInVerse":[]}}},"121":{"chapter":"121","title":"I LIFT UP MINE EYES","verses":{"1":{"text":"I will lift up mine eyes unto the hills, from whence cometh my help.","ref":"Psalms 121:1","synthesized":"I lift up my eyes to the hills. From where does my help come?","sources":{"KJV":{"text":"I will lift up mine eyes unto the hills, from whence cometh my help."},"BSB":{"text":"I lift up my eyes to the hills. From where does my help come?"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"My help cometh from the LORD, which made heaven and earth.","ref":"Psalms 121:2","synthesized":"My help comes from the LORD, the Maker of heaven and earth.","sources":{"KJV":{"text":"My help cometh from the LORD, which made heaven and earth."},"BSB":{"text":"My help comes from the LORD, the Maker of heaven and earth."}},"definableWords":["LORD","heaven","earth"],"peopleInVerse":[]},"3":{"text":"He will not suffer thy foot to be moved: he that keepeth thee will not slumber.","ref":"Psalms 121:3","synthesized":"He will not allow your foot to slip; your Protector will not slumber.","sources":{"KJV":{"text":"He will not suffer thy foot to be moved: he that keepeth thee will not slumber."},"BSB":{"text":"He will not allow your foot to slip; your Protector will not slumber."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Behold, he that keepeth Israel shall neither slumber nor sleep.","ref":"Psalms 121:4","synthesized":"Behold, the Protector of Israel will neither slumber nor sleep.","sources":{"KJV":{"text":"Behold, he that keepeth Israel shall neither slumber nor sleep."},"BSB":{"text":"Behold, the Protector of Israel will neither slumber nor sleep."}},"definableWords":["Israel"],"peopleInVerse":[]},"5":{"text":"The LORD is thy keeper: the LORD is thy shade upon thy right hand.","ref":"Psalms 121:5","synthesized":"The LORD is your keeper; the LORD is the shade on your right hand.","sources":{"KJV":{"text":"The LORD is thy keeper: the LORD is thy shade upon thy right hand."},"BSB":{"text":"The LORD is your keeper; the LORD is the shade on your right hand."}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"6":{"text":"The sun shall not smite thee by day, nor the moon by night.","ref":"Psalms 121:6","synthesized":"The sun will not strike you by day, nor the moon by night.","sources":{"KJV":{"text":"The sun shall not smite thee by day, nor the moon by night."},"BSB":{"text":"The sun will not strike you by day, nor the moon by night."}},"definableWords":["day","night"],"peopleInVerse":[]},"7":{"text":"The LORD shall preserve thee from all evil: he shall preserve thy soul.","ref":"Psalms 121:7","synthesized":"The LORD will guard you from all evil; He will preserve your soul.","sources":{"KJV":{"text":"The LORD shall preserve thee from all evil: he shall preserve thy soul."},"BSB":{"text":"The LORD will guard you from all evil; He will preserve your soul."}},"definableWords":["LORD","evil","soul"],"peopleInVerse":[]},"8":{"text":"The LORD shall preserve thy going out and thy coming in from this time forth, and even for evermore.","ref":"Psalms 121:8","synthesized":"The LORD will watch over your coming and going, both now and forevermore.","sources":{"KJV":{"text":"The LORD shall preserve thy going out and thy coming in from this time forth, and even for evermore."},"BSB":{"text":"The LORD will watch over your coming and going, both now and forevermore."}},"definableWords":["LORD"],"peopleInVerse":[]}}},"122":{"chapter":"122","title":"I WAS GLAD WHEN THEY SAID UNTO ME","verses":{"1":{"text":"I was glad when they said unto me, Let us go into the house of the LORD.","ref":"Psalms 122:1","synthesized":"I was glad when they said to me, “Let us go to the house of the LORD.”","sources":{"KJV":{"text":"I was glad when they said unto me, Let us go into the house of the LORD."},"BSB":{"text":"I was glad when they said to me, “Let us go to the house of the LORD.”"}},"definableWords":["house","LORD"],"peopleInVerse":[]},"2":{"text":"Our feet shall stand within thy gates, O Jerusalem.","ref":"Psalms 122:2","synthesized":"Our feet are standing in your gates, O Jerusalem.","sources":{"KJV":{"text":"Our feet shall stand within thy gates, O Jerusalem."},"BSB":{"text":"Our feet are standing in your gates, O Jerusalem."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"3":{"text":"Jerusalem is builded as a city that is compact together:","ref":"Psalms 122:3","synthesized":"Jerusalem is built up as a city united together,","sources":{"KJV":{"text":"Jerusalem is builded as a city that is compact together:"},"BSB":{"text":"Jerusalem is built up as a city united together,"}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"4":{"text":"Whither the tribes go up, the tribes of the LORD, unto the testimony of Israel, to give thanks unto the name of the LORD.","ref":"Psalms 122:4","synthesized":"where the tribes go up, the tribes of the LORD, as a testimony for Israel, to give thanks to the name of the LORD.","sources":{"KJV":{"text":"Whither the tribes go up, the tribes of the LORD, unto the testimony of Israel, to give thanks unto the name of the LORD."},"BSB":{"text":"where the tribes go up, the tribes of the LORD, as a testimony for Israel, to give thanks to the name of the LORD."}},"definableWords":["LORD","Israel","name","Lord"],"peopleInVerse":[]},"5":{"text":"For there are set thrones of judgment, the thrones of the house of David.","ref":"Psalms 122:5","synthesized":"For there the thrones of judgment stand, the thrones of the house of David.","sources":{"KJV":{"text":"For there are set thrones of judgment, the thrones of the house of David."},"BSB":{"text":"For there the thrones of judgment stand, the thrones of the house of David."}},"definableWords":["judgment","stand","house"],"peopleInVerse":["David"]},"6":{"text":"Pray for the peace of Jerusalem: they shall prosper that love thee.","ref":"Psalms 122:6","synthesized":"Pray for the peace of Jerusalem: “May those who love you prosper.","sources":{"KJV":{"text":"Pray for the peace of Jerusalem: they shall prosper that love thee."},"BSB":{"text":"Pray for the peace of Jerusalem: “May those who love you prosper."}},"definableWords":["peace","Jerusalem","love"],"peopleInVerse":[]},"7":{"text":"Peace be within thy walls, and prosperity within thy palaces.","ref":"Psalms 122:7","synthesized":"May there be peace within your walls, and prosperity inside your fortresses.”","sources":{"KJV":{"text":"Peace be within thy walls, and prosperity within thy palaces."},"BSB":{"text":"May there be peace within your walls, and prosperity inside your fortresses.”"}},"definableWords":["peace"],"peopleInVerse":[]},"8":{"text":"For my brethren and companions’ sakes, I will now say, Peace be within thee.","ref":"Psalms 122:8","synthesized":"For the sake of my brothers and friends, I will say, “Peace be within you.”","sources":{"KJV":{"text":"For my brethren and companions’ sakes, I will now say, Peace be within thee."},"BSB":{"text":"For the sake of my brothers and friends, I will say, “Peace be within you.”"}},"definableWords":["peace"],"peopleInVerse":[]},"9":{"text":"Because of the house of the LORD our God I will seek thy good.","ref":"Psalms 122:9","synthesized":"For the sake of the house of the LORD our God, I will seek your prosperity.","sources":{"KJV":{"text":"Because of the house of the LORD our God I will seek thy good."},"BSB":{"text":"For the sake of the house of the LORD our God, I will seek your prosperity."}},"definableWords":["house","LORD","God","seek"],"peopleInVerse":[]}}},"123":{"chapter":"123","title":"UNTO THEE LIFT I MINE EYES","verses":{"1":{"text":"Unto thee lift I up mine eyes, O thou that dwellest in the heavens.","ref":"Psalms 123:1","synthesized":"I lift up my eyes to You, the One enthroned in heaven.","sources":{"KJV":{"text":"Unto thee lift I up mine eyes, O thou that dwellest in the heavens."},"BSB":{"text":"I lift up my eyes to You, the One enthroned in heaven."}},"definableWords":["one","heaven"],"peopleInVerse":[]},"2":{"text":"Behold, as the eyes of servants look unto the hand of their masters, and as the eyes of a maiden unto the hand of her mistress; so our eyes wait upon the LORD our God, until that he have mercy upon us.","ref":"Psalms 123:2","synthesized":"As the eyes of servants look to the hand of their master, as the eyes of a maidservant look to the hand of her mistress, so our eyes are on the LORD our God until He shows us mercy.","sources":{"KJV":{"text":"Behold, as the eyes of servants look unto the hand of their masters, and as the eyes of a maiden unto the hand of her mistress; so our eyes wait upon the LORD our God, until that he have mercy upon us."},"BSB":{"text":"As the eyes of servants look to the hand of their master, as the eyes of a maidservant look to the hand of her mistress, so our eyes are on the LORD our God until He shows us mercy."}},"definableWords":["servants","LORD","God","mercy"],"peopleInVerse":[]},"3":{"text":"Have mercy upon us, O LORD, have mercy upon us: for we are exceedingly filled with contempt.","ref":"Psalms 123:3","synthesized":"Have mercy on us, O LORD, have mercy, for we have endured much contempt.","sources":{"KJV":{"text":"Have mercy upon us, O LORD, have mercy upon us: for we are exceedingly filled with contempt."},"BSB":{"text":"Have mercy on us, O LORD, have mercy, for we have endured much contempt."}},"definableWords":["mercy","LORD"],"peopleInVerse":[]},"4":{"text":"Our soul is exceedingly filled with the scorning of those that are at ease, and with the contempt of the proud.","ref":"Psalms 123:4","synthesized":"We have endured much scorn from the arrogant, much contempt from the proud.","sources":{"KJV":{"text":"Our soul is exceedingly filled with the scorning of those that are at ease, and with the contempt of the proud."},"BSB":{"text":"We have endured much scorn from the arrogant, much contempt from the proud."}},"definableWords":[],"peopleInVerse":[]}}},"124":{"chapter":"124","title":"IF IT HAD NOT BEEN THE LORD","verses":{"1":{"text":"If it had not been the LORD who was on our side, now may Israel say;","ref":"Psalms 124:1","synthesized":"If the LORD had not been on our side— let Israel now declare—","sources":{"KJV":{"text":"If it had not been the LORD who was on our side, now may Israel say;"},"BSB":{"text":"If the LORD had not been on our side— let Israel now declare—"}},"definableWords":["LORD","Israel"],"peopleInVerse":[]},"2":{"text":"If it had not been the LORD who was on our side, when men rose up against us:","ref":"Psalms 124:2","synthesized":"if the LORD had not been on our side when men attacked us,","sources":{"KJV":{"text":"If it had not been the LORD who was on our side, when men rose up against us:"},"BSB":{"text":"if the LORD had not been on our side when men attacked us,"}},"definableWords":["LORD","men"],"peopleInVerse":[]},"3":{"text":"Then they had swallowed us up quick, when their wrath was kindled against us:","ref":"Psalms 124:3","synthesized":"when their anger flared against us, then they would have swallowed us alive,","sources":{"KJV":{"text":"Then they had swallowed us up quick, when their wrath was kindled against us:"},"BSB":{"text":"when their anger flared against us, then they would have swallowed us alive,"}},"definableWords":["anger"],"peopleInVerse":[]},"4":{"text":"Then the waters had overwhelmed us, the stream had gone over our soul:","ref":"Psalms 124:4","synthesized":"then the floods would have engulfed us, then the torrent would have overwhelmed us,","sources":{"KJV":{"text":"Then the waters had overwhelmed us, the stream had gone over our soul:"},"BSB":{"text":"then the floods would have engulfed us, then the torrent would have overwhelmed us,"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Then the proud waters had gone over our soul.","ref":"Psalms 124:5","synthesized":"then the raging waters would have swept us away.","sources":{"KJV":{"text":"Then the proud waters had gone over our soul."},"BSB":{"text":"then the raging waters would have swept us away."}},"definableWords":["waters"],"peopleInVerse":[]},"6":{"text":"Blessed be the LORD, who hath not given us as a prey to their teeth.","ref":"Psalms 124:6","synthesized":"Blessed be the LORD, who has not given us as prey to their teeth.","sources":{"KJV":{"text":"Blessed be the LORD, who hath not given us as a prey to their teeth."},"BSB":{"text":"Blessed be the LORD, who has not given us as prey to their teeth."}},"definableWords":["blessed","LORD"],"peopleInVerse":[]},"7":{"text":"Our soul is escaped as a bird out of the snare of the fowlers: the snare is broken, and we are escaped.","ref":"Psalms 124:7","synthesized":"We have escaped like a bird from the snare of the fowler; the net is torn, and we have slipped away.","sources":{"KJV":{"text":"Our soul is escaped as a bird out of the snare of the fowlers: the snare is broken, and we are escaped."},"BSB":{"text":"We have escaped like a bird from the snare of the fowler; the net is torn, and we have slipped away."}},"definableWords":["bird"],"peopleInVerse":[]},"8":{"text":"Our help is in the name of the LORD, who made heaven and earth.","ref":"Psalms 124:8","synthesized":"Our help is in the name of the LORD, the Maker of heaven and earth.","sources":{"KJV":{"text":"Our help is in the name of the LORD, who made heaven and earth."},"BSB":{"text":"Our help is in the name of the LORD, the Maker of heaven and earth."}},"definableWords":["name","LORD","heaven","earth"],"peopleInVerse":[]}}},"125":{"chapter":"125","title":"MOUNT ZION CANNOT BE REMOVED","verses":{"1":{"text":"They that trust in the LORD shall be as mount Zion, which cannot be removed, but abideth for ever.","ref":"Psalms 125:1","synthesized":"Those who trust in the LORD are like Mount Zion. It cannot be moved; it abides forever.","sources":{"KJV":{"text":"They that trust in the LORD shall be as mount Zion, which cannot be removed, but abideth for ever."},"BSB":{"text":"Those who trust in the LORD are like Mount Zion. It cannot be moved; it abides forever."}},"definableWords":["trust","LORD","Zion"],"peopleInVerse":[]},"2":{"text":"As the mountains are round about Jerusalem, so the LORD is round about his people from henceforth even for ever.","ref":"Psalms 125:2","synthesized":"As the mountains surround Jerusalem, so the LORD surrounds His people, both now and forevermore.","sources":{"KJV":{"text":"As the mountains are round about Jerusalem, so the LORD is round about his people from henceforth even for ever."},"BSB":{"text":"As the mountains surround Jerusalem, so the LORD surrounds His people, both now and forevermore."}},"definableWords":["Jerusalem","LORD","people"],"peopleInVerse":[]},"3":{"text":"For the rod of the wicked shall not rest upon the lot of the righteous; lest the righteous put forth their hands unto iniquity.","ref":"Psalms 125:3","synthesized":"For the scepter of the wicked will not rest upon the land allotted to the righteous, so that the righteous will not put forth their hands to injustice.","sources":{"KJV":{"text":"For the rod of the wicked shall not rest upon the lot of the righteous; lest the righteous put forth their hands unto iniquity."},"BSB":{"text":"For the scepter of the wicked will not rest upon the land allotted to the righteous, so that the righteous will not put forth their hands to injustice."}},"definableWords":["scepter","rest","land","righteous"],"peopleInVerse":[]},"4":{"text":"Do good, O LORD, unto those that be good, and to them that are upright in their hearts.","ref":"Psalms 125:4","synthesized":"Do good, O LORD, to those who are good, and to the upright in heart.","sources":{"KJV":{"text":"Do good, O LORD, unto those that be good, and to them that are upright in their hearts."},"BSB":{"text":"Do good, O LORD, to those who are good, and to the upright in heart."}},"definableWords":["good","LORD","heart"],"peopleInVerse":[]},"5":{"text":"As for such as turn aside unto their crooked ways, the LORD shall lead them forth with the workers of iniquity: but peace shall be upon Israel.","ref":"Psalms 125:5","synthesized":"But those who turn to crooked ways the LORD will banish with the evildoers.   Peace be upon Israel.","sources":{"KJV":{"text":"As for such as turn aside unto their crooked ways, the LORD shall lead them forth with the workers of iniquity: but peace shall be upon Israel."},"BSB":{"text":"But those who turn to crooked ways the LORD will banish with the evildoers.   Peace be upon Israel."}},"definableWords":["LORD","peace","Israel"],"peopleInVerse":[]}}},"126":{"chapter":"126","title":"THEY THAT SOW IN TEARS","verses":{"1":{"text":"When the LORD turned again the captivity of Zion, we were like them that dream.","ref":"Psalms 126:1","synthesized":"When the LORD restored the captives of Zion, we were like dreamers.","sources":{"KJV":{"text":"When the LORD turned again the captivity of Zion, we were like them that dream."},"BSB":{"text":"When the LORD restored the captives of Zion, we were like dreamers."}},"definableWords":["LORD","Zion"],"peopleInVerse":[]},"2":{"text":"Then was our mouth filled with laughter, and our tongue with singing: then said they among the heathen, The LORD hath done great things for them.","ref":"Psalms 126:2","synthesized":"Then our mouths were filled with laughter, our tongues with shouts of joy. Then it was said among the nations, “The LORD has done great things for them.”","sources":{"KJV":{"text":"Then was our mouth filled with laughter, and our tongue with singing: then said they among the heathen, The LORD hath done great things for them."},"BSB":{"text":"Then our mouths were filled with laughter, our tongues with shouts of joy. Then it was said among the nations, “The LORD has done great things for them.”"}},"definableWords":["joy","nations","LORD","great"],"peopleInVerse":[]},"3":{"text":"The LORD hath done great things for us; whereof we are glad.","ref":"Psalms 126:3","synthesized":"The LORD has done great things for us; we are filled with joy.","sources":{"KJV":{"text":"The LORD hath done great things for us; whereof we are glad."},"BSB":{"text":"The LORD has done great things for us; we are filled with joy."}},"definableWords":["LORD","great","joy"],"peopleInVerse":[]},"4":{"text":"Turn again our captivity, O LORD, as the streams in the south.","ref":"Psalms 126:4","synthesized":"Restore our captives, O LORD, like streams in the Negev.","sources":{"KJV":{"text":"Turn again our captivity, O LORD, as the streams in the south."},"BSB":{"text":"Restore our captives, O LORD, like streams in the Negev."}},"definableWords":["LORD"],"peopleInVerse":[]},"5":{"text":"They that sow in tears shall reap in joy.","ref":"Psalms 126:5","synthesized":"Those who sow in tears will reap with shouts of joy.","sources":{"KJV":{"text":"They that sow in tears shall reap in joy."},"BSB":{"text":"Those who sow in tears will reap with shouts of joy."}},"definableWords":["joy"],"peopleInVerse":[]},"6":{"text":"He that goeth forth and weepeth, bearing precious seed, shall doubtless come again with rejoicing, bringing his sheaves with him.","ref":"Psalms 126:6","synthesized":"He who goes out weeping, bearing a trail of seed, will surely return with shouts of joy, carrying sheaves of grain.","sources":{"KJV":{"text":"He that goeth forth and weepeth, bearing precious seed, shall doubtless come again with rejoicing, bringing his sheaves with him."},"BSB":{"text":"He who goes out weeping, bearing a trail of seed, will surely return with shouts of joy, carrying sheaves of grain."}},"definableWords":["seed","joy"],"peopleInVerse":[]}}},"127":{"chapter":"127","title":"EXCEPT THE LORD BUILD THE HOUSE","verses":{"1":{"text":"Except the LORD build the house, they labour in vain that build it: except the LORD keep the city, the watchman waketh but in vain.","ref":"Psalms 127:1","synthesized":"Unless the LORD builds the house, its builders labor in vain; unless the LORD protects the city, its watchmen stand guard in vain.","sources":{"KJV":{"text":"Except the LORD build the house, they labour in vain that build it: except the LORD keep the city, the watchman waketh but in vain."},"BSB":{"text":"Unless the LORD builds the house, its builders labor in vain; unless the LORD protects the city, its watchmen stand guard in vain."}},"definableWords":["LORD","house","Lord","stand"],"peopleInVerse":[]},"2":{"text":"It is vain for you to rise up early, to sit up late, to eat the bread of sorrows: for so he giveth his beloved sleep.","ref":"Psalms 127:2","synthesized":"In vain you rise early and stay up late, toiling for bread to eat— for He gives sleep to His beloved.","sources":{"KJV":{"text":"It is vain for you to rise up early, to sit up late, to eat the bread of sorrows: for so he giveth his beloved sleep."},"BSB":{"text":"In vain you rise early and stay up late, toiling for bread to eat— for He gives sleep to His beloved."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Lo, children are an heritage of the LORD: and the fruit of the womb is his reward.","ref":"Psalms 127:3","synthesized":"Children are indeed a heritage from the LORD, and the fruit of the womb is His reward.","sources":{"KJV":{"text":"Lo, children are an heritage of the LORD: and the fruit of the womb is his reward."},"BSB":{"text":"Children are indeed a heritage from the LORD, and the fruit of the womb is His reward."}},"definableWords":["LORD"],"peopleInVerse":[]},"4":{"text":"As arrows are in the hand of a mighty man; so are children of the youth.","ref":"Psalms 127:4","synthesized":"Like arrows in the hand of a warrior, so are children born in one’s youth.","sources":{"KJV":{"text":"As arrows are in the hand of a mighty man; so are children of the youth."},"BSB":{"text":"Like arrows in the hand of a warrior, so are children born in one’s youth."}},"definableWords":["one"],"peopleInVerse":[]},"5":{"text":"Happy is the man that hath his quiver full of them: they shall not be ashamed, but they shall speak with the enemies in the gate.","ref":"Psalms 127:5","synthesized":"Blessed is the man whose quiver is full of them. He will not be put to shame when he confronts the enemies at the gate.","sources":{"KJV":{"text":"Happy is the man that hath his quiver full of them: they shall not be ashamed, but they shall speak with the enemies in the gate."},"BSB":{"text":"Blessed is the man whose quiver is full of them. He will not be put to shame when he confronts the enemies at the gate."}},"definableWords":["blessed","man"],"peopleInVerse":[]}}},"128":{"chapter":"128","title":"BLESSED IS EVERY ONE THAT FEARETH THE LORD","verses":{"1":{"text":"Blessed is every one that feareth the LORD; that walketh in his ways.","ref":"Psalms 128:1","synthesized":"Blessed are all who fear the LORD, who walk in His ways!","sources":{"KJV":{"text":"Blessed is every one that feareth the LORD; that walketh in his ways."},"BSB":{"text":"Blessed are all who fear the LORD, who walk in His ways!"}},"definableWords":["blessed","fear","LORD","walk"],"peopleInVerse":[]},"2":{"text":"For thou shalt eat the labour of thine hands: happy shalt thou be, and it shall be well with thee.","ref":"Psalms 128:2","synthesized":"For when you eat the fruit of your labor, blessings and prosperity will be yours.","sources":{"KJV":{"text":"For thou shalt eat the labour of thine hands: happy shalt thou be, and it shall be well with thee."},"BSB":{"text":"For when you eat the fruit of your labor, blessings and prosperity will be yours."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Thy wife shall be as a fruitful vine by the sides of thine house: thy children like olive plants round about thy table.","ref":"Psalms 128:3","synthesized":"Your wife will be like a fruitful vine flourishing within your house, your sons like olive shoots sitting around your table.","sources":{"KJV":{"text":"Thy wife shall be as a fruitful vine by the sides of thine house: thy children like olive plants round about thy table."},"BSB":{"text":"Your wife will be like a fruitful vine flourishing within your house, your sons like olive shoots sitting around your table."}},"definableWords":["wife","fruitful","house","sons"],"peopleInVerse":[]},"4":{"text":"Behold, that thus shall the man be blessed that feareth the LORD.","ref":"Psalms 128:4","synthesized":"In this way indeed shall blessing come to the man who fears the LORD.","sources":{"KJV":{"text":"Behold, that thus shall the man be blessed that feareth the LORD."},"BSB":{"text":"In this way indeed shall blessing come to the man who fears the LORD."}},"definableWords":["way","blessing","man","LORD"],"peopleInVerse":[]},"5":{"text":"The LORD shall bless thee out of Zion: and thou shalt see the good of Jerusalem all the days of thy life.","ref":"Psalms 128:5","synthesized":"May the LORD bless you from Zion, that you may see the prosperity of Jerusalem all the days of your life,","sources":{"KJV":{"text":"The LORD shall bless thee out of Zion: and thou shalt see the good of Jerusalem all the days of thy life."},"BSB":{"text":"May the LORD bless you from Zion, that you may see the prosperity of Jerusalem all the days of your life,"}},"definableWords":["LORD","bless","Zion","see","Jerusalem","days","life"],"peopleInVerse":[]},"6":{"text":"Yea, thou shalt see thy children’s children, and peace upon Israel.","ref":"Psalms 128:6","synthesized":"that you may see your children’s children.   Peace be upon Israel!","sources":{"KJV":{"text":"Yea, thou shalt see thy children’s children, and peace upon Israel."},"BSB":{"text":"that you may see your children’s children.   Peace be upon Israel!"}},"definableWords":["see","peace","Israel"],"peopleInVerse":[]}}},"129":{"chapter":"129","title":"MANY A TIME THEY AFFLICTED ME","verses":{"1":{"text":"Many a time have they afflicted me from my youth, may Israel now say:","ref":"Psalms 129:1","synthesized":"Many a time they have persecuted me from my youth— let Israel now declare—","sources":{"KJV":{"text":"Many a time have they afflicted me from my youth, may Israel now say:"},"BSB":{"text":"Many a time they have persecuted me from my youth— let Israel now declare—"}},"definableWords":["Israel"],"peopleInVerse":[]},"2":{"text":"Many a time have they afflicted me from my youth: yet they have not prevailed against me.","ref":"Psalms 129:2","synthesized":"many a time they have persecuted me from my youth, but they have not prevailed against me.","sources":{"KJV":{"text":"Many a time have they afflicted me from my youth: yet they have not prevailed against me."},"BSB":{"text":"many a time they have persecuted me from my youth, but they have not prevailed against me."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"The plowers plowed upon my back: they made long their furrows.","ref":"Psalms 129:3","synthesized":"The plowmen plowed over my back; they made their furrows long.","sources":{"KJV":{"text":"The plowers plowed upon my back: they made long their furrows."},"BSB":{"text":"The plowmen plowed over my back; they made their furrows long."}},"definableWords":["made"],"peopleInVerse":[]},"4":{"text":"The LORD is righteous: he hath cut asunder the cords of the wicked.","ref":"Psalms 129:4","synthesized":"The LORD is righteous; He has cut me from the cords of the wicked.","sources":{"KJV":{"text":"The LORD is righteous: he hath cut asunder the cords of the wicked."},"BSB":{"text":"The LORD is righteous; He has cut me from the cords of the wicked."}},"definableWords":["LORD","righteous"],"peopleInVerse":[]},"5":{"text":"Let them all be confounded and turned back that hate Zion.","ref":"Psalms 129:5","synthesized":"May all who hate Zion be turned back in shame.","sources":{"KJV":{"text":"Let them all be confounded and turned back that hate Zion."},"BSB":{"text":"May all who hate Zion be turned back in shame."}},"definableWords":["Zion"],"peopleInVerse":[]},"6":{"text":"Let them be as the grass upon the housetops, which withereth afore it groweth up:","ref":"Psalms 129:6","synthesized":"May they be like grass on the rooftops, which withers before it can grow,","sources":{"KJV":{"text":"Let them be as the grass upon the housetops, which withereth afore it groweth up:"},"BSB":{"text":"May they be like grass on the rooftops, which withers before it can grow,"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Wherewith the mower filleth not his hand; nor he that bindeth sheaves his bosom.","ref":"Psalms 129:7","synthesized":"unable to fill the hands of the reaper, or the arms of the binder of sheaves.","sources":{"KJV":{"text":"Wherewith the mower filleth not his hand; nor he that bindeth sheaves his bosom."},"BSB":{"text":"unable to fill the hands of the reaper, or the arms of the binder of sheaves."}},"definableWords":["fill","or"],"peopleInVerse":[]},"8":{"text":"Neither do they which go by say, The blessing of the LORD be upon you: we bless you in the name of the LORD.","ref":"Psalms 129:8","synthesized":"May none who pass by say to them, “The blessing of the LORD be on you; we bless you in the name of the LORD.”","sources":{"KJV":{"text":"Neither do they which go by say, The blessing of the LORD be upon you: we bless you in the name of the LORD."},"BSB":{"text":"May none who pass by say to them, “The blessing of the LORD be on you; we bless you in the name of the LORD.”"}},"definableWords":["blessing","LORD","bless","name","Lord"],"peopleInVerse":[]}}},"130":{"chapter":"130","title":"OUT OF THE DEPTHS","verses":{"1":{"text":"Out of the depths have I cried unto thee, O LORD.","ref":"Psalms 130:1","synthesized":"Out of the depths I cry to You, O LORD!","sources":{"KJV":{"text":"Out of the depths have I cried unto thee, O LORD."},"BSB":{"text":"Out of the depths I cry to You, O LORD!"}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"Lord, hear my voice: let thine ears be attentive to the voice of my supplications.","ref":"Psalms 130:2","synthesized":"O Lord, hear my voice; let Your ears be attentive to my plea for mercy.","sources":{"KJV":{"text":"Lord, hear my voice: let thine ears be attentive to the voice of my supplications."},"BSB":{"text":"O Lord, hear my voice; let Your ears be attentive to my plea for mercy."}},"definableWords":["Lord","hear","voice","mercy"],"peopleInVerse":[]},"3":{"text":"If thou, LORD, shouldest mark iniquities, O Lord, who shall stand?","ref":"Psalms 130:3","synthesized":"If You, O LORD, kept track of iniquities, then who, O Lord, could stand?","sources":{"KJV":{"text":"If thou, LORD, shouldest mark iniquities, O Lord, who shall stand?"},"BSB":{"text":"If You, O LORD, kept track of iniquities, then who, O Lord, could stand?"}},"definableWords":["LORD","Lord","stand"],"peopleInVerse":[]},"4":{"text":"But there is forgiveness with thee, that thou mayest be feared.","ref":"Psalms 130:4","synthesized":"But with You there is forgiveness, so that You may be feared.","sources":{"KJV":{"text":"But there is forgiveness with thee, that thou mayest be feared."},"BSB":{"text":"But with You there is forgiveness, so that You may be feared."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"I wait for the LORD, my soul doth wait, and in his word do I hope.","ref":"Psalms 130:5","synthesized":"I wait for the LORD; my soul does wait, and in His word I put my hope.","sources":{"KJV":{"text":"I wait for the LORD, my soul doth wait, and in his word do I hope."},"BSB":{"text":"I wait for the LORD; my soul does wait, and in His word I put my hope."}},"definableWords":["wait","LORD","soul","word","hope"],"peopleInVerse":[]},"6":{"text":"My soul waiteth for the Lord more than they that watch for the morning: I say, more than they that watch for the morning.","ref":"Psalms 130:6","synthesized":"My soul waits for the Lord more than watchmen wait for the morning— more than watchmen wait for the morning.","sources":{"KJV":{"text":"My soul waiteth for the Lord more than they that watch for the morning: I say, more than they that watch for the morning."},"BSB":{"text":"My soul waits for the Lord more than watchmen wait for the morning— more than watchmen wait for the morning."}},"definableWords":["soul","Lord","wait"],"peopleInVerse":[]},"7":{"text":"Let Israel hope in the LORD: for with the LORD there is mercy, and with him is plenteous redemption.","ref":"Psalms 130:7","synthesized":"O Israel, put your hope in the LORD, for with the LORD is loving devotion, and with Him is redemption in abundance.","sources":{"KJV":{"text":"Let Israel hope in the LORD: for with the LORD there is mercy, and with him is plenteous redemption."},"BSB":{"text":"O Israel, put your hope in the LORD, for with the LORD is loving devotion, and with Him is redemption in abundance."}},"definableWords":["Israel","hope","LORD","Lord","redemption"],"peopleInVerse":[]},"8":{"text":"And he shall redeem Israel from all his iniquities.","ref":"Psalms 130:8","synthesized":"And He will redeem Israel from all iniquity.","sources":{"KJV":{"text":"And he shall redeem Israel from all his iniquities."},"BSB":{"text":"And He will redeem Israel from all iniquity."}},"definableWords":["Israel","iniquity"],"peopleInVerse":[]}}},"131":{"chapter":"131","title":"LIKE A WEANED CHILD","verses":{"1":{"text":"Lord, my heart is not haughty, nor mine eyes lofty: neither do I exercise myself in great matters, or in things too high for me.","ref":"Psalms 131:1","synthesized":"My heart is not proud, O LORD, my eyes are not haughty. I do not aspire to great things or matters too lofty for me.","sources":{"KJV":{"text":"Lord, my heart is not haughty, nor mine eyes lofty: neither do I exercise myself in great matters, or in things too high for me."},"BSB":{"text":"My heart is not proud, O LORD, my eyes are not haughty. I do not aspire to great things or matters too lofty for me."}},"definableWords":["heart","LORD","great","or"],"peopleInVerse":[]},"2":{"text":"Surely I have behaved and quieted myself, as a child that is weaned of his mother: my soul is even as a weaned child.","ref":"Psalms 131:2","synthesized":"Surely I have stilled and quieted my soul; like a weaned child with his mother, like a weaned child is my soul within me.","sources":{"KJV":{"text":"Surely I have behaved and quieted myself, as a child that is weaned of his mother: my soul is even as a weaned child."},"BSB":{"text":"Surely I have stilled and quieted my soul; like a weaned child with his mother, like a weaned child is my soul within me."}},"definableWords":["soul","mother"],"peopleInVerse":[]},"3":{"text":"Let Israel hope in the LORD from henceforth and for ever.","ref":"Psalms 131:3","synthesized":"O Israel, put your hope in the LORD, both now and forevermore.","sources":{"KJV":{"text":"Let Israel hope in the LORD from henceforth and for ever."},"BSB":{"text":"O Israel, put your hope in the LORD, both now and forevermore."}},"definableWords":["Israel","hope","LORD"],"peopleInVerse":[]}}},"132":{"chapter":"132","title":"LORD, REMEMBER DAVID","verses":{"1":{"text":"Lord, remember David, and all his afflictions:","ref":"Psalms 132:1","synthesized":"O LORD, remember on behalf of David all the hardships he endured,","sources":{"KJV":{"text":"Lord, remember David, and all his afflictions:"},"BSB":{"text":"O LORD, remember on behalf of David all the hardships he endured,"}},"definableWords":["LORD","remember"],"peopleInVerse":["David"]},"2":{"text":"How he sware unto the LORD, and vowed unto the mighty God of Jacob;","ref":"Psalms 132:2","synthesized":"how he swore an oath to the LORD, and vowed to the Mighty One of Jacob:","sources":{"KJV":{"text":"How he sware unto the LORD, and vowed unto the mighty God of Jacob;"},"BSB":{"text":"how he swore an oath to the LORD, and vowed to the Mighty One of Jacob:"}},"definableWords":["LORD","mighty","one","Jacob"],"peopleInVerse":["Jacob"]},"3":{"text":"Surely I will not come into the tabernacle of my house, nor go up into my bed;","ref":"Psalms 132:3","synthesized":"“I will not enter my house or get into my bed,","sources":{"KJV":{"text":"Surely I will not come into the tabernacle of my house, nor go up into my bed;"},"BSB":{"text":"“I will not enter my house or get into my bed,"}},"definableWords":["house","or"],"peopleInVerse":[]},"4":{"text":"I will not give sleep to mine eyes, or slumber to mine eyelids,","ref":"Psalms 132:4","synthesized":"I will not give sleep to my eyes or slumber to my eyelids,","sources":{"KJV":{"text":"I will not give sleep to mine eyes, or slumber to mine eyelids,"},"BSB":{"text":"I will not give sleep to my eyes or slumber to my eyelids,"}},"definableWords":["or"],"peopleInVerse":[]},"5":{"text":"Until I find out a place for the LORD, an habitation for the mighty God of Jacob.","ref":"Psalms 132:5","synthesized":"until I find a place for the LORD, a dwelling for the Mighty One of Jacob.”","sources":{"KJV":{"text":"Until I find out a place for the LORD, an habitation for the mighty God of Jacob."},"BSB":{"text":"until I find a place for the LORD, a dwelling for the Mighty One of Jacob.”"}},"definableWords":["LORD","mighty","one","Jacob"],"peopleInVerse":["Jacob"]},"6":{"text":"Lo, we heard of it at Ephratah: we found it in the fields of the wood.","ref":"Psalms 132:6","synthesized":"We heard that the ark was in Ephrathah; we found it in the fields of Jaar.","sources":{"KJV":{"text":"Lo, we heard of it at Ephratah: we found it in the fields of the wood."},"BSB":{"text":"We heard that the ark was in Ephrathah; we found it in the fields of Jaar."}},"definableWords":["ark"],"peopleInVerse":[]},"7":{"text":"We will go into his tabernacles: we will worship at his footstool.","ref":"Psalms 132:7","synthesized":"Let us go to His dwelling place; let us worship at His footstool.","sources":{"KJV":{"text":"We will go into his tabernacles: we will worship at his footstool."},"BSB":{"text":"Let us go to His dwelling place; let us worship at His footstool."}},"definableWords":["worship"],"peopleInVerse":[]},"8":{"text":"Arise, O LORD, into thy rest; thou, and the ark of thy strength.","ref":"Psalms 132:8","synthesized":"Arise, O LORD, to Your resting place, You and the ark of Your strength.","sources":{"KJV":{"text":"Arise, O LORD, into thy rest; thou, and the ark of thy strength."},"BSB":{"text":"Arise, O LORD, to Your resting place, You and the ark of Your strength."}},"definableWords":["LORD","ark"],"peopleInVerse":[]},"9":{"text":"Let thy priests be clothed with righteousness; and let thy saints shout for joy.","ref":"Psalms 132:9","synthesized":"May Your priests be clothed with righteousness, and Your saints shout for joy.","sources":{"KJV":{"text":"Let thy priests be clothed with righteousness; and let thy saints shout for joy."},"BSB":{"text":"May Your priests be clothed with righteousness, and Your saints shout for joy."}},"definableWords":["righteousness","joy"],"peopleInVerse":[]},"10":{"text":"For thy servant David’s sake turn not away the face of thine anointed.","ref":"Psalms 132:10","synthesized":"For the sake of Your servant David, do not reject Your anointed one.","sources":{"KJV":{"text":"For thy servant David’s sake turn not away the face of thine anointed."},"BSB":{"text":"For the sake of Your servant David, do not reject Your anointed one."}},"definableWords":["servant","one"],"peopleInVerse":["David"]},"11":{"text":"The LORD hath sworn in truth unto David; he will not turn from it; Of the fruit of thy body will I set upon thy throne.","ref":"Psalms 132:11","synthesized":"The LORD swore an oath to David, a promise He will not revoke: “One of your descendants I will place on your throne.","sources":{"KJV":{"text":"The LORD hath sworn in truth unto David; he will not turn from it; Of the fruit of thy body will I set upon thy throne."},"BSB":{"text":"The LORD swore an oath to David, a promise He will not revoke: “One of your descendants I will place on your throne."}},"definableWords":["LORD","promise","one","throne"],"peopleInVerse":["David"]},"12":{"text":"If thy children will keep my covenant and my testimony that I shall teach them, their children shall also sit upon thy throne for evermore.","ref":"Psalms 132:12","synthesized":"If your sons keep My covenant and the testimony I will teach them, then their sons will also sit on your throne forever and ever.”","sources":{"KJV":{"text":"If thy children will keep my covenant and my testimony that I shall teach them, their children shall also sit upon thy throne for evermore."},"BSB":{"text":"If your sons keep My covenant and the testimony I will teach them, then their sons will also sit on your throne forever and ever.”"}},"definableWords":["sons","keep","covenant","throne"],"peopleInVerse":[]},"13":{"text":"For the LORD hath chosen Zion; he hath desired it for his habitation.","ref":"Psalms 132:13","synthesized":"For the LORD has chosen Zion; He has desired it for His home:","sources":{"KJV":{"text":"For the LORD hath chosen Zion; he hath desired it for his habitation."},"BSB":{"text":"For the LORD has chosen Zion; He has desired it for His home:"}},"definableWords":["LORD","Zion"],"peopleInVerse":[]},"14":{"text":"This is my rest for ever: here will I dwell; for I have desired it.","ref":"Psalms 132:14","synthesized":"“This is My resting place forever and ever; here I will dwell, for I have desired this home.","sources":{"KJV":{"text":"This is my rest for ever: here will I dwell; for I have desired it."},"BSB":{"text":"“This is My resting place forever and ever; here I will dwell, for I have desired this home."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"I will abundantly bless her provision: I will satisfy her poor with bread.","ref":"Psalms 132:15","synthesized":"I will bless her with abundant provisions; I will satisfy her poor with bread.","sources":{"KJV":{"text":"I will abundantly bless her provision: I will satisfy her poor with bread."},"BSB":{"text":"I will bless her with abundant provisions; I will satisfy her poor with bread."}},"definableWords":["bless"],"peopleInVerse":[]},"16":{"text":"I will also clothe her priests with salvation: and her saints shall shout aloud for joy.","ref":"Psalms 132:16","synthesized":"I will clothe her priests with salvation, and her saints will sing out in joy.","sources":{"KJV":{"text":"I will also clothe her priests with salvation: and her saints shall shout aloud for joy."},"BSB":{"text":"I will clothe her priests with salvation, and her saints will sing out in joy."}},"definableWords":["salvation","joy"],"peopleInVerse":[]},"17":{"text":"There will I make the horn of David to bud: I have ordained a lamp for mine anointed.","ref":"Psalms 132:17","synthesized":"There I will make a horn grow for David; I have prepared a lamp for My anointed one.","sources":{"KJV":{"text":"There will I make the horn of David to bud: I have ordained a lamp for mine anointed."},"BSB":{"text":"There I will make a horn grow for David; I have prepared a lamp for My anointed one."}},"definableWords":["make","one"],"peopleInVerse":["David"]},"18":{"text":"His enemies will I clothe with shame: but upon himself shall his crown flourish.","ref":"Psalms 132:18","synthesized":"I will clothe his enemies with shame, but the crown upon him will gleam.”","sources":{"KJV":{"text":"His enemies will I clothe with shame: but upon himself shall his crown flourish."},"BSB":{"text":"I will clothe his enemies with shame, but the crown upon him will gleam.”"}},"definableWords":["crown"],"peopleInVerse":[]}}},"133":{"chapter":"133","title":"HOW GOOD AND HOW PLEASANT — UNITY","verses":{"1":{"text":"Behold, how good and how pleasant it is for brethren to dwell together in unity!","ref":"Psalms 133:1","synthesized":"Behold, how good and pleasant it is when brothers live together in harmony!","sources":{"KJV":{"text":"Behold, how good and how pleasant it is for brethren to dwell together in unity!"},"BSB":{"text":"Behold, how good and pleasant it is when brothers live together in harmony!"}},"definableWords":["good","live"],"peopleInVerse":[]},"2":{"text":"It is like the precious ointment upon the head, that ran down upon the beard, even Aaron’s beard: that went down to the skirts of his garments;","ref":"Psalms 133:2","synthesized":"It is like fine oil on the head, running down on the beard, running down Aaron’s beard over the collar of his robes.","sources":{"KJV":{"text":"It is like the precious ointment upon the head, that ran down upon the beard, even Aaron’s beard: that went down to the skirts of his garments;"},"BSB":{"text":"It is like fine oil on the head, running down on the beard, running down Aaron’s beard over the collar of his robes."}},"definableWords":[],"peopleInVerse":["Aaron"]},"3":{"text":"As the dew of Hermon, and as the dew that descended upon the mountains of Zion: for there the LORD commanded the blessing, even life for evermore.","ref":"Psalms 133:3","synthesized":"It is like the dew of Hermon falling on the mountains of Zion. For there the LORD has bestowed the blessing of life forevermore.","sources":{"KJV":{"text":"As the dew of Hermon, and as the dew that descended upon the mountains of Zion: for there the LORD commanded the blessing, even life for evermore."},"BSB":{"text":"It is like the dew of Hermon falling on the mountains of Zion. For there the LORD has bestowed the blessing of life forevermore."}},"definableWords":["Zion","LORD","blessing","life"],"peopleInVerse":[]}}},"134":{"chapter":"134","title":"BLESS THE LORD, ALL YE SERVANTS","verses":{"1":{"text":"Behold, bless ye the LORD, all ye servants of the LORD, which by night stand in the house of the LORD.","ref":"Psalms 134:1","synthesized":"Come, bless the LORD, all you servants of the LORD who serve by night in the house of the LORD!","sources":{"KJV":{"text":"Behold, bless ye the LORD, all ye servants of the LORD, which by night stand in the house of the LORD."},"BSB":{"text":"Come, bless the LORD, all you servants of the LORD who serve by night in the house of the LORD!"}},"definableWords":["bless","LORD","servants","Lord","night","house"],"peopleInVerse":[]},"2":{"text":"Lift up your hands in the sanctuary, and bless the LORD.","ref":"Psalms 134:2","synthesized":"Lift up your hands to the sanctuary and bless the LORD!","sources":{"KJV":{"text":"Lift up your hands in the sanctuary, and bless the LORD."},"BSB":{"text":"Lift up your hands to the sanctuary and bless the LORD!"}},"definableWords":["bless","LORD"],"peopleInVerse":[]},"3":{"text":"The LORD that made heaven and earth bless thee out of Zion.","ref":"Psalms 134:3","synthesized":"May the LORD, the Maker of heaven and earth, bless you from Zion.","sources":{"KJV":{"text":"The LORD that made heaven and earth bless thee out of Zion."},"BSB":{"text":"May the LORD, the Maker of heaven and earth, bless you from Zion."}},"definableWords":["LORD","heaven","earth","bless","Zion"],"peopleInVerse":[]}}},"135":{"chapter":"135","title":"PRAISE YE THE NAME OF THE LORD","verses":{"1":{"text":"Praise ye the LORD. Praise ye the name of the LORD; praise him, O ye servants of the LORD.","ref":"Psalms 135:1","synthesized":"Hallelujah!   Praise the name of the LORD. Give praise, O servants of the LORD,","sources":{"KJV":{"text":"Praise ye the LORD. Praise ye the name of the LORD; praise him, O ye servants of the LORD."},"BSB":{"text":"Hallelujah!   Praise the name of the LORD. Give praise, O servants of the LORD,"}},"definableWords":["praise","name","LORD","servants","Lord"],"peopleInVerse":[]},"2":{"text":"Ye that stand in the house of the LORD, in the courts of the house of our God,","ref":"Psalms 135:2","synthesized":"who stand in the house of the LORD, in the courts of the house of our God.","sources":{"KJV":{"text":"Ye that stand in the house of the LORD, in the courts of the house of our God,"},"BSB":{"text":"who stand in the house of the LORD, in the courts of the house of our God."}},"definableWords":["stand","house","LORD","God"],"peopleInVerse":[]},"3":{"text":"Praise the LORD; for the LORD is good: sing praises unto his name; for it is pleasant.","ref":"Psalms 135:3","synthesized":"Hallelujah, for the LORD is good; sing praises to His name, for it is lovely.","sources":{"KJV":{"text":"Praise the LORD; for the LORD is good: sing praises unto his name; for it is pleasant."},"BSB":{"text":"Hallelujah, for the LORD is good; sing praises to His name, for it is lovely."}},"definableWords":["LORD","good","name"],"peopleInVerse":[]},"4":{"text":"For the LORD hath chosen Jacob unto himself, and Israel for his peculiar treasure.","ref":"Psalms 135:4","synthesized":"For the LORD has chosen Jacob as His own, Israel as His treasured possession.","sources":{"KJV":{"text":"For the LORD hath chosen Jacob unto himself, and Israel for his peculiar treasure."},"BSB":{"text":"For the LORD has chosen Jacob as His own, Israel as His treasured possession."}},"definableWords":["LORD","Jacob","Israel"],"peopleInVerse":["Jacob"]},"5":{"text":"For I know that the LORD is great, and that our Lord is above all gods.","ref":"Psalms 135:5","synthesized":"For I know that the LORD is great; our Lord is above all gods.","sources":{"KJV":{"text":"For I know that the LORD is great, and that our Lord is above all gods."},"BSB":{"text":"For I know that the LORD is great; our Lord is above all gods."}},"definableWords":["LORD","great","Lord"],"peopleInVerse":[]},"6":{"text":"Whatsoever the LORD pleased, that did he in heaven, and in earth, in the seas, and all deep places.","ref":"Psalms 135:6","synthesized":"The LORD does all that pleases Him in the heavens and on the earth, in the seas and in all their depths.","sources":{"KJV":{"text":"Whatsoever the LORD pleased, that did he in heaven, and in earth, in the seas, and all deep places."},"BSB":{"text":"The LORD does all that pleases Him in the heavens and on the earth, in the seas and in all their depths."}},"definableWords":["LORD","heavens","earth","seas"],"peopleInVerse":[]},"7":{"text":"He causeth the vapours to ascend from the ends of the earth; he maketh lightnings for the rain; he bringeth the wind out of his treasuries.","ref":"Psalms 135:7","synthesized":"He causes the clouds to rise from the ends of the earth. He generates the lightning with the rain and brings forth the wind from His storehouses.","sources":{"KJV":{"text":"He causeth the vapours to ascend from the ends of the earth; he maketh lightnings for the rain; he bringeth the wind out of his treasuries."},"BSB":{"text":"He causes the clouds to rise from the ends of the earth. He generates the lightning with the rain and brings forth the wind from His storehouses."}},"definableWords":["earth"],"peopleInVerse":[]},"8":{"text":"Who smote the firstborn of Egypt, both of man and beast.","ref":"Psalms 135:8","synthesized":"He struck down the firstborn of Egypt, of both man and beast.","sources":{"KJV":{"text":"Who smote the firstborn of Egypt, both of man and beast."},"BSB":{"text":"He struck down the firstborn of Egypt, of both man and beast."}},"definableWords":["Egypt","man"],"peopleInVerse":[]},"9":{"text":"Who sent tokens and wonders into the midst of thee, O Egypt, upon Pharaoh, and upon all his servants.","ref":"Psalms 135:9","synthesized":"He sent signs and wonders into your midst, O Egypt, against Pharaoh and all his servants.","sources":{"KJV":{"text":"Who sent tokens and wonders into the midst of thee, O Egypt, upon Pharaoh, and upon all his servants."},"BSB":{"text":"He sent signs and wonders into your midst, O Egypt, against Pharaoh and all his servants."}},"definableWords":["Egypt","Pharaoh","servants"],"peopleInVerse":["Pharaoh"]},"10":{"text":"Who smote great nations, and slew mighty kings;","ref":"Psalms 135:10","synthesized":"He struck down many nations and slaughtered mighty kings:","sources":{"KJV":{"text":"Who smote great nations, and slew mighty kings;"},"BSB":{"text":"He struck down many nations and slaughtered mighty kings:"}},"definableWords":["nations","mighty","kings"],"peopleInVerse":[]},"11":{"text":"Sihon king of the Amorites, and Og king of Bashan, and all the kingdoms of Canaan:","ref":"Psalms 135:11","synthesized":"Sihon king of the Amorites, Og king of Bashan, and all the kings of Canaan.","sources":{"KJV":{"text":"Sihon king of the Amorites, and Og king of Bashan, and all the kingdoms of Canaan:"},"BSB":{"text":"Sihon king of the Amorites, Og king of Bashan, and all the kings of Canaan."}},"definableWords":["king","King","kings","Canaan"],"peopleInVerse":["Canaan"]},"12":{"text":"And gave their land for an heritage, an heritage unto Israel his people.","ref":"Psalms 135:12","synthesized":"He gave their land as an inheritance, as a heritage to His people Israel.","sources":{"KJV":{"text":"And gave their land for an heritage, an heritage unto Israel his people."},"BSB":{"text":"He gave their land as an inheritance, as a heritage to His people Israel."}},"definableWords":["land","people","Israel"],"peopleInVerse":[]},"13":{"text":"Thy name, O LORD, endureth for ever; and thy memorial, O LORD, throughout all generations.","ref":"Psalms 135:13","synthesized":"Your name, O LORD, endures forever, Your renown, O LORD, through all generations.","sources":{"KJV":{"text":"Thy name, O LORD, endureth for ever; and thy memorial, O LORD, throughout all generations."},"BSB":{"text":"Your name, O LORD, endures forever, Your renown, O LORD, through all generations."}},"definableWords":["name","LORD","Lord"],"peopleInVerse":[]},"14":{"text":"For the LORD will judge his people, and he will repent himself concerning his servants.","ref":"Psalms 135:14","synthesized":"For the LORD will vindicate His people and will have compassion on His servants.","sources":{"KJV":{"text":"For the LORD will judge his people, and he will repent himself concerning his servants."},"BSB":{"text":"For the LORD will vindicate His people and will have compassion on His servants."}},"definableWords":["LORD","people","servants"],"peopleInVerse":[]},"15":{"text":"The idols of the heathen are silver and gold, the work of men’s hands.","ref":"Psalms 135:15","synthesized":"The idols of the nations are silver and gold, made by the hands of men.","sources":{"KJV":{"text":"The idols of the heathen are silver and gold, the work of men’s hands."},"BSB":{"text":"The idols of the nations are silver and gold, made by the hands of men."}},"definableWords":["nations","made","men"],"peopleInVerse":[]},"16":{"text":"They have mouths, but they speak not; eyes have they, but they see not;","ref":"Psalms 135:16","synthesized":"They have mouths, but cannot speak; they have eyes, but cannot see;","sources":{"KJV":{"text":"They have mouths, but they speak not; eyes have they, but they see not;"},"BSB":{"text":"They have mouths, but cannot speak; they have eyes, but cannot see;"}},"definableWords":["see"],"peopleInVerse":[]},"17":{"text":"They have ears, but they hear not; neither is there any breath in their mouths.","ref":"Psalms 135:17","synthesized":"they have ears, but cannot hear; nor is there breath in their mouths.","sources":{"KJV":{"text":"They have ears, but they hear not; neither is there any breath in their mouths."},"BSB":{"text":"they have ears, but cannot hear; nor is there breath in their mouths."}},"definableWords":["hear","breath"],"peopleInVerse":[]},"18":{"text":"They that make them are like unto them: so is every one that trusteth in them.","ref":"Psalms 135:18","synthesized":"Those who make them become like them, as do all who trust in them.","sources":{"KJV":{"text":"They that make them are like unto them: so is every one that trusteth in them."},"BSB":{"text":"Those who make them become like them, as do all who trust in them."}},"definableWords":["make","trust"],"peopleInVerse":[]},"19":{"text":"Bless the LORD, O house of Israel: bless the LORD, O house of Aaron:","ref":"Psalms 135:19","synthesized":"O house of Israel, bless the LORD; O house of Aaron, bless the LORD;","sources":{"KJV":{"text":"Bless the LORD, O house of Israel: bless the LORD, O house of Aaron:"},"BSB":{"text":"O house of Israel, bless the LORD; O house of Aaron, bless the LORD;"}},"definableWords":["house","Israel","bless","LORD","Lord"],"peopleInVerse":["Aaron"]},"20":{"text":"Bless the LORD, O house of Levi: ye that fear the LORD, bless the LORD.","ref":"Psalms 135:20","synthesized":"O house of Levi, bless the LORD; you who fear the LORD, bless the LORD!","sources":{"KJV":{"text":"Bless the LORD, O house of Levi: ye that fear the LORD, bless the LORD."},"BSB":{"text":"O house of Levi, bless the LORD; you who fear the LORD, bless the LORD!"}},"definableWords":["house","Levi","bless","LORD","fear","Lord"],"peopleInVerse":[]},"21":{"text":"Blessed be the LORD out of Zion, which dwelleth at Jerusalem. Praise ye the LORD.","ref":"Psalms 135:21","synthesized":"Blessed be the LORD from Zion— He who dwells in Jerusalem.   Hallelujah!","sources":{"KJV":{"text":"Blessed be the LORD out of Zion, which dwelleth at Jerusalem. Praise ye the LORD."},"BSB":{"text":"Blessed be the LORD from Zion— He who dwells in Jerusalem.   Hallelujah!"}},"definableWords":["blessed","LORD","Zion","Jerusalem"],"peopleInVerse":[]}}},"136":{"chapter":"136","title":"HIS MERCY ENDURES FOREVER","verses":{"1":{"text":"O give thanks unto the LORD; for he is good: for his mercy endureth for ever.","ref":"Psalms 136:1","synthesized":"Give thanks to the LORD, for He is good. His loving devotion endures forever.","sources":{"KJV":{"text":"O give thanks unto the LORD; for he is good: for his mercy endureth for ever."},"BSB":{"text":"Give thanks to the LORD, for He is good. His loving devotion endures forever."}},"definableWords":["LORD","good"],"peopleInVerse":[]},"2":{"text":"O give thanks unto the God of gods: for his mercy endureth for ever.","ref":"Psalms 136:2","synthesized":"Give thanks to the God of gods. His loving devotion endures forever.","sources":{"KJV":{"text":"O give thanks unto the God of gods: for his mercy endureth for ever."},"BSB":{"text":"Give thanks to the God of gods. His loving devotion endures forever."}},"definableWords":["God"],"peopleInVerse":[]},"3":{"text":"O give thanks to the Lord of lords: for his mercy endureth for ever.","ref":"Psalms 136:3","synthesized":"Give thanks to the Lord of lords. His loving devotion endures forever.","sources":{"KJV":{"text":"O give thanks to the Lord of lords: for his mercy endureth for ever."},"BSB":{"text":"Give thanks to the Lord of lords. His loving devotion endures forever."}},"definableWords":["Lord"],"peopleInVerse":[]},"4":{"text":"To him who alone doeth great wonders: for his mercy endureth for ever.","ref":"Psalms 136:4","synthesized":"He alone does great wonders. His loving devotion endures forever.","sources":{"KJV":{"text":"To him who alone doeth great wonders: for his mercy endureth for ever."},"BSB":{"text":"He alone does great wonders. His loving devotion endures forever."}},"definableWords":["great"],"peopleInVerse":[]},"5":{"text":"To him that by wisdom made the heavens: for his mercy endureth for ever.","ref":"Psalms 136:5","synthesized":"By His insight He made the heavens. His loving devotion endures forever.","sources":{"KJV":{"text":"To him that by wisdom made the heavens: for his mercy endureth for ever."},"BSB":{"text":"By His insight He made the heavens. His loving devotion endures forever."}},"definableWords":["made","heavens"],"peopleInVerse":[]},"6":{"text":"To him that stretched out the earth above the waters: for his mercy endureth for ever.","ref":"Psalms 136:6","synthesized":"He spread out the earth upon the waters. His loving devotion endures forever.","sources":{"KJV":{"text":"To him that stretched out the earth above the waters: for his mercy endureth for ever."},"BSB":{"text":"He spread out the earth upon the waters. His loving devotion endures forever."}},"definableWords":["earth","waters"],"peopleInVerse":[]},"7":{"text":"To him that made great lights: for his mercy endureth for ever:","ref":"Psalms 136:7","synthesized":"He made the great lights— His loving devotion endures forever.","sources":{"KJV":{"text":"To him that made great lights: for his mercy endureth for ever:"},"BSB":{"text":"He made the great lights— His loving devotion endures forever."}},"definableWords":["made","great"],"peopleInVerse":[]},"8":{"text":"The sun to rule by day: for his mercy endureth for ever:","ref":"Psalms 136:8","synthesized":"the sun to rule the day, His loving devotion endures forever.","sources":{"KJV":{"text":"The sun to rule by day: for his mercy endureth for ever:"},"BSB":{"text":"the sun to rule the day, His loving devotion endures forever."}},"definableWords":["rule","day"],"peopleInVerse":[]},"9":{"text":"The moon and stars to rule by night: for his mercy endureth for ever.","ref":"Psalms 136:9","synthesized":"the moon and stars to govern the night. His loving devotion endures forever.","sources":{"KJV":{"text":"The moon and stars to rule by night: for his mercy endureth for ever."},"BSB":{"text":"the moon and stars to govern the night. His loving devotion endures forever."}},"definableWords":["night"],"peopleInVerse":[]},"10":{"text":"To him that smote Egypt in their firstborn: for his mercy endureth for ever:","ref":"Psalms 136:10","synthesized":"He struck down the firstborn of Egypt His loving devotion endures forever.","sources":{"KJV":{"text":"To him that smote Egypt in their firstborn: for his mercy endureth for ever:"},"BSB":{"text":"He struck down the firstborn of Egypt His loving devotion endures forever."}},"definableWords":["Egypt"],"peopleInVerse":[]},"11":{"text":"And brought out Israel from among them: for his mercy endureth for ever:","ref":"Psalms 136:11","synthesized":"and brought Israel out from among them His loving devotion endures forever.","sources":{"KJV":{"text":"And brought out Israel from among them: for his mercy endureth for ever:"},"BSB":{"text":"and brought Israel out from among them His loving devotion endures forever."}},"definableWords":["Israel"],"peopleInVerse":[]},"12":{"text":"With a strong hand, and with a stretched out arm: for his mercy endureth for ever.","ref":"Psalms 136:12","synthesized":"with a mighty hand and an outstretched arm. His loving devotion endures forever.","sources":{"KJV":{"text":"With a strong hand, and with a stretched out arm: for his mercy endureth for ever."},"BSB":{"text":"with a mighty hand and an outstretched arm. His loving devotion endures forever."}},"definableWords":["mighty"],"peopleInVerse":[]},"13":{"text":"To him which divided the Red sea into parts: for his mercy endureth for ever:","ref":"Psalms 136:13","synthesized":"He divided the Red Sea in two His loving devotion endures forever.","sources":{"KJV":{"text":"To him which divided the Red sea into parts: for his mercy endureth for ever:"},"BSB":{"text":"He divided the Red Sea in two His loving devotion endures forever."}},"definableWords":["sea"],"peopleInVerse":[]},"14":{"text":"And made Israel to pass through the midst of it: for his mercy endureth for ever:","ref":"Psalms 136:14","synthesized":"and led Israel through the midst, His loving devotion endures forever.","sources":{"KJV":{"text":"And made Israel to pass through the midst of it: for his mercy endureth for ever:"},"BSB":{"text":"and led Israel through the midst, His loving devotion endures forever."}},"definableWords":["Israel"],"peopleInVerse":[]},"15":{"text":"But overthrew Pharaoh and his host in the Red sea: for his mercy endureth for ever.","ref":"Psalms 136:15","synthesized":"but swept Pharaoh and his army into the Red Sea. His loving devotion endures forever.","sources":{"KJV":{"text":"But overthrew Pharaoh and his host in the Red sea: for his mercy endureth for ever."},"BSB":{"text":"but swept Pharaoh and his army into the Red Sea. His loving devotion endures forever."}},"definableWords":["Pharaoh","sea"],"peopleInVerse":["Pharaoh"]},"16":{"text":"To him which led his people through the wilderness: for his mercy endureth for ever.","ref":"Psalms 136:16","synthesized":"He led His people through the wilderness. His loving devotion endures forever.","sources":{"KJV":{"text":"To him which led his people through the wilderness: for his mercy endureth for ever."},"BSB":{"text":"He led His people through the wilderness. His loving devotion endures forever."}},"definableWords":["people"],"peopleInVerse":[]},"17":{"text":"To him which smote great kings: for his mercy endureth for ever:","ref":"Psalms 136:17","synthesized":"He struck down great kings His loving devotion endures forever.","sources":{"KJV":{"text":"To him which smote great kings: for his mercy endureth for ever:"},"BSB":{"text":"He struck down great kings His loving devotion endures forever."}},"definableWords":["great","kings"],"peopleInVerse":[]},"18":{"text":"And slew famous kings: for his mercy endureth for ever:","ref":"Psalms 136:18","synthesized":"and slaughtered mighty kings— His loving devotion endures forever.","sources":{"KJV":{"text":"And slew famous kings: for his mercy endureth for ever:"},"BSB":{"text":"and slaughtered mighty kings— His loving devotion endures forever."}},"definableWords":["mighty","kings"],"peopleInVerse":[]},"19":{"text":"Sihon king of the Amorites: for his mercy endureth for ever:","ref":"Psalms 136:19","synthesized":"Sihon king of the Amorites His loving devotion endures forever.","sources":{"KJV":{"text":"Sihon king of the Amorites: for his mercy endureth for ever:"},"BSB":{"text":"Sihon king of the Amorites His loving devotion endures forever."}},"definableWords":["king"],"peopleInVerse":[]},"20":{"text":"And Og the king of Bashan: for his mercy endureth for ever:","ref":"Psalms 136:20","synthesized":"and Og king of Bashan— His loving devotion endures forever.","sources":{"KJV":{"text":"And Og the king of Bashan: for his mercy endureth for ever:"},"BSB":{"text":"and Og king of Bashan— His loving devotion endures forever."}},"definableWords":["king"],"peopleInVerse":[]},"21":{"text":"And gave their land for an heritage: for his mercy endureth for ever:","ref":"Psalms 136:21","synthesized":"and He gave their land as an inheritance, His loving devotion endures forever.","sources":{"KJV":{"text":"And gave their land for an heritage: for his mercy endureth for ever:"},"BSB":{"text":"and He gave their land as an inheritance, His loving devotion endures forever."}},"definableWords":["land"],"peopleInVerse":[]},"22":{"text":"Even an heritage unto Israel his servant: for his mercy endureth for ever.","ref":"Psalms 136:22","synthesized":"a heritage to His servant Israel. His loving devotion endures forever.","sources":{"KJV":{"text":"Even an heritage unto Israel his servant: for his mercy endureth for ever."},"BSB":{"text":"a heritage to His servant Israel. His loving devotion endures forever."}},"definableWords":["servant","Israel"],"peopleInVerse":[]},"23":{"text":"Who remembered us in our low estate: for his mercy endureth for ever:","ref":"Psalms 136:23","synthesized":"He remembered us in our low estate His loving devotion endures forever.","sources":{"KJV":{"text":"Who remembered us in our low estate: for his mercy endureth for ever:"},"BSB":{"text":"He remembered us in our low estate His loving devotion endures forever."}},"definableWords":["remembered"],"peopleInVerse":[]},"24":{"text":"And hath redeemed us from our enemies: for his mercy endureth for ever.","ref":"Psalms 136:24","synthesized":"and freed us from our enemies. His loving devotion endures forever.","sources":{"KJV":{"text":"And hath redeemed us from our enemies: for his mercy endureth for ever."},"BSB":{"text":"and freed us from our enemies. His loving devotion endures forever."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"Who giveth food to all flesh: for his mercy endureth for ever.","ref":"Psalms 136:25","synthesized":"He gives food to every creature. His loving devotion endures forever.","sources":{"KJV":{"text":"Who giveth food to all flesh: for his mercy endureth for ever."},"BSB":{"text":"He gives food to every creature. His loving devotion endures forever."}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"O give thanks unto the God of heaven: for his mercy endureth for ever.","ref":"Psalms 136:26","synthesized":"Give thanks to the God of heaven! His loving devotion endures forever.","sources":{"KJV":{"text":"O give thanks unto the God of heaven: for his mercy endureth for ever."},"BSB":{"text":"Give thanks to the God of heaven! His loving devotion endures forever."}},"definableWords":["God","heaven"],"peopleInVerse":[]}}},"137":{"chapter":"137","title":"BY THE RIVERS OF BABYLON","verses":{"1":{"text":"By the rivers of Babylon, there we sat down, yea, we wept, when we remembered Zion.","ref":"Psalms 137:1","synthesized":"By the rivers of Babylon we sat and wept when we remembered Zion.","sources":{"KJV":{"text":"By the rivers of Babylon, there we sat down, yea, we wept, when we remembered Zion."},"BSB":{"text":"By the rivers of Babylon we sat and wept when we remembered Zion."}},"definableWords":["Babylon","remembered","Zion"],"peopleInVerse":[]},"2":{"text":"We hanged our harps upon the willows in the midst thereof.","ref":"Psalms 137:2","synthesized":"There on the willows we hung our harps,","sources":{"KJV":{"text":"We hanged our harps upon the willows in the midst thereof."},"BSB":{"text":"There on the willows we hung our harps,"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"For there they that carried us away captive required of us a song; and they that wasted us required of us mirth, saying, Sing us one of the songs of Zion.","ref":"Psalms 137:3","synthesized":"for there our captors requested a song; our tormentors demanded songs of joy:   “Sing us a song of Zion.”","sources":{"KJV":{"text":"For there they that carried us away captive required of us a song; and they that wasted us required of us mirth, saying, Sing us one of the songs of Zion."},"BSB":{"text":"for there our captors requested a song; our tormentors demanded songs of joy:   “Sing us a song of Zion.”"}},"definableWords":["joy","Zion"],"peopleInVerse":[]},"4":{"text":"How shall we sing the LORD’s song in a strange land?","ref":"Psalms 137:4","synthesized":"How can we sing a song of the LORD in a foreign land?","sources":{"KJV":{"text":"How shall we sing the LORD’s song in a strange land?"},"BSB":{"text":"How can we sing a song of the LORD in a foreign land?"}},"definableWords":["LORD","land"],"peopleInVerse":[]},"5":{"text":"If I forget thee, O Jerusalem, let my right hand forget her cunning.","ref":"Psalms 137:5","synthesized":"If I forget you, O Jerusalem, may my right hand cease to function.","sources":{"KJV":{"text":"If I forget thee, O Jerusalem, let my right hand forget her cunning."},"BSB":{"text":"If I forget you, O Jerusalem, may my right hand cease to function."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"6":{"text":"If I do not remember thee, let my tongue cleave to the roof of my mouth; if I prefer not Jerusalem above my chief joy.","ref":"Psalms 137:6","synthesized":"May my tongue cling to the roof of my mouth if I do not remember you, if I do not exalt Jerusalem as my greatest joy!","sources":{"KJV":{"text":"If I do not remember thee, let my tongue cleave to the roof of my mouth; if I prefer not Jerusalem above my chief joy."},"BSB":{"text":"May my tongue cling to the roof of my mouth if I do not remember you, if I do not exalt Jerusalem as my greatest joy!"}},"definableWords":["remember","Jerusalem","joy"],"peopleInVerse":[]},"7":{"text":"Remember, O LORD, the children of Edom in the day of Jerusalem; who said, Rase it, rase it, even to the foundation thereof.","ref":"Psalms 137:7","synthesized":"Remember, O LORD, the sons of Edom on the day Jerusalem fell: “Destroy it,” they said, “tear it down to its foundations!”","sources":{"KJV":{"text":"Remember, O LORD, the children of Edom in the day of Jerusalem; who said, Rase it, rase it, even to the foundation thereof."},"BSB":{"text":"Remember, O LORD, the sons of Edom on the day Jerusalem fell: “Destroy it,” they said, “tear it down to its foundations!”"}},"definableWords":["remember","LORD","sons","Edom","day","Jerusalem"],"peopleInVerse":[]},"8":{"text":"O daughter of Babylon, who art to be destroyed; happy shall he be, that rewardeth thee as thou hast served us.","ref":"Psalms 137:8","synthesized":"O Daughter of Babylon, doomed to destruction, blessed is he who repays you as you have done to us.","sources":{"KJV":{"text":"O daughter of Babylon, who art to be destroyed; happy shall he be, that rewardeth thee as thou hast served us."},"BSB":{"text":"O Daughter of Babylon, doomed to destruction, blessed is he who repays you as you have done to us."}},"definableWords":["daughter","Babylon","blessed"],"peopleInVerse":[]},"9":{"text":"Happy shall he be, that taketh and dasheth thy little ones against the stones.","ref":"Psalms 137:9","synthesized":"Blessed is he who seizes your infants and dashes them against the rocks.","sources":{"KJV":{"text":"Happy shall he be, that taketh and dasheth thy little ones against the stones."},"BSB":{"text":"Blessed is he who seizes your infants and dashes them against the rocks."}},"definableWords":["blessed"],"peopleInVerse":[]}}},"138":{"chapter":"138","title":"I WILL PRAISE THEE WITH MY WHOLE HEART","verses":{"1":{"text":"I will praise thee with my whole heart: before the gods will I sing praise unto thee.","ref":"Psalms 138:1","synthesized":"I give You thanks with all my heart; before the gods I sing Your praises.","sources":{"KJV":{"text":"I will praise thee with my whole heart: before the gods will I sing praise unto thee."},"BSB":{"text":"I give You thanks with all my heart; before the gods I sing Your praises."}},"definableWords":["heart"],"peopleInVerse":[]},"2":{"text":"I will worship toward thy holy temple, and praise thy name for thy lovingkindness and for thy truth: for thou hast magnified thy word above all thy name.","ref":"Psalms 138:2","synthesized":"I bow down toward Your holy temple and give thanks to Your name for Your loving devotion and Your faithfulness; You have exalted Your name and Your word above all else.","sources":{"KJV":{"text":"I will worship toward thy holy temple, and praise thy name for thy lovingkindness and for thy truth: for thou hast magnified thy word above all thy name."},"BSB":{"text":"I bow down toward Your holy temple and give thanks to Your name for Your loving devotion and Your faithfulness; You have exalted Your name and Your word above all else."}},"definableWords":["holy","temple","name","word"],"peopleInVerse":[]},"3":{"text":"In the day when I cried thou answeredst me, and strengthenedst me with strength in my soul.","ref":"Psalms 138:3","synthesized":"On the day I called, You answered me; You emboldened me and strengthened my soul.","sources":{"KJV":{"text":"In the day when I cried thou answeredst me, and strengthenedst me with strength in my soul."},"BSB":{"text":"On the day I called, You answered me; You emboldened me and strengthened my soul."}},"definableWords":["day","soul"],"peopleInVerse":[]},"4":{"text":"All the kings of the earth shall praise thee, O LORD, when they hear the words of thy mouth.","ref":"Psalms 138:4","synthesized":"All the kings of the earth will give You thanks, O LORD, when they hear the words of Your mouth.","sources":{"KJV":{"text":"All the kings of the earth shall praise thee, O LORD, when they hear the words of thy mouth."},"BSB":{"text":"All the kings of the earth will give You thanks, O LORD, when they hear the words of Your mouth."}},"definableWords":["kings","earth","LORD","hear"],"peopleInVerse":[]},"5":{"text":"Yea, they shall sing in the ways of the LORD: for great is the glory of the LORD.","ref":"Psalms 138:5","synthesized":"They will sing of the ways of the LORD, for the glory of the LORD is great.","sources":{"KJV":{"text":"Yea, they shall sing in the ways of the LORD: for great is the glory of the LORD."},"BSB":{"text":"They will sing of the ways of the LORD, for the glory of the LORD is great."}},"definableWords":["LORD","glory","Lord","great"],"peopleInVerse":[]},"6":{"text":"Though the LORD be high, yet hath he respect unto the lowly: but the proud he knoweth afar off.","ref":"Psalms 138:6","synthesized":"Though the LORD is on high, He attends to the lowly; but the proud He knows from afar.","sources":{"KJV":{"text":"Though the LORD be high, yet hath he respect unto the lowly: but the proud he knoweth afar off."},"BSB":{"text":"Though the LORD is on high, He attends to the lowly; but the proud He knows from afar."}},"definableWords":["LORD"],"peopleInVerse":[]},"7":{"text":"Though I walk in the midst of trouble, thou wilt revive me: thou shalt stretch forth thine hand against the wrath of mine enemies, and thy right hand shall save me.","ref":"Psalms 138:7","synthesized":"If I walk in the midst of trouble, You preserve me from the anger of my foes; You extend Your hand, and Your right hand saves me.","sources":{"KJV":{"text":"Though I walk in the midst of trouble, thou wilt revive me: thou shalt stretch forth thine hand against the wrath of mine enemies, and thy right hand shall save me."},"BSB":{"text":"If I walk in the midst of trouble, You preserve me from the anger of my foes; You extend Your hand, and Your right hand saves me."}},"definableWords":["walk","anger"],"peopleInVerse":[]},"8":{"text":"The LORD will perfect that which concerneth me: thy mercy, O LORD, endureth for ever: forsake not the works of thine own hands.","ref":"Psalms 138:8","synthesized":"The LORD will fulfill His purpose for me.   O LORD, Your loving devotion endures forever— do not abandon the works of Your hands.","sources":{"KJV":{"text":"The LORD will perfect that which concerneth me: thy mercy, O LORD, endureth for ever: forsake not the works of thine own hands."},"BSB":{"text":"The LORD will fulfill His purpose for me.   O LORD, Your loving devotion endures forever— do not abandon the works of Your hands."}},"definableWords":["LORD","Lord","works"],"peopleInVerse":[]}}},"139":{"chapter":"139","title":"THOU HAST SEARCHED ME","verses":{"1":{"text":"O LORD, thou hast searched me, and known me.","ref":"Psalms 139:1","synthesized":"O LORD, You have searched me and known me.","sources":{"KJV":{"text":"O LORD, thou hast searched me, and known me."},"BSB":{"text":"O LORD, You have searched me and known me."}},"definableWords":["LORD"],"peopleInVerse":[]},"2":{"text":"Thou knowest my downsitting and mine uprising, thou understandest my thought afar off.","ref":"Psalms 139:2","synthesized":"You know when I sit and when I rise; You understand my thoughts from afar.","sources":{"KJV":{"text":"Thou knowest my downsitting and mine uprising, thou understandest my thought afar off."},"BSB":{"text":"You know when I sit and when I rise; You understand my thoughts from afar."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Thou compassest my path and my lying down, and art acquainted with all my ways.","ref":"Psalms 139:3","synthesized":"You search out my path and my lying down; You are aware of all my ways.","sources":{"KJV":{"text":"Thou compassest my path and my lying down, and art acquainted with all my ways."},"BSB":{"text":"You search out my path and my lying down; You are aware of all my ways."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"For there is not a word in my tongue, but, lo, O LORD, thou knowest it altogether.","ref":"Psalms 139:4","synthesized":"Even before a word is on my tongue, You know all about it, O LORD.","sources":{"KJV":{"text":"For there is not a word in my tongue, but, lo, O LORD, thou knowest it altogether."},"BSB":{"text":"Even before a word is on my tongue, You know all about it, O LORD."}},"definableWords":["word","LORD"],"peopleInVerse":[]},"5":{"text":"Thou hast beset me behind and before, and laid thine hand upon me.","ref":"Psalms 139:5","synthesized":"You hem me in behind and before; You have laid Your hand upon me.","sources":{"KJV":{"text":"Thou hast beset me behind and before, and laid thine hand upon me."},"BSB":{"text":"You hem me in behind and before; You have laid Your hand upon me."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Such knowledge is too wonderful for me; it is high, I cannot attain unto it.","ref":"Psalms 139:6","synthesized":"Such knowledge is too wonderful for me, too lofty for me to attain.","sources":{"KJV":{"text":"Such knowledge is too wonderful for me; it is high, I cannot attain unto it."},"BSB":{"text":"Such knowledge is too wonderful for me, too lofty for me to attain."}},"definableWords":["knowledge"],"peopleInVerse":[]},"7":{"text":"Whither shall I go from thy spirit? or whither shall I flee from thy presence?","ref":"Psalms 139:7","synthesized":"Where can I go to escape Your Spirit? Where can I flee from Your presence?","sources":{"KJV":{"text":"Whither shall I go from thy spirit? or whither shall I flee from thy presence?"},"BSB":{"text":"Where can I go to escape Your Spirit? Where can I flee from Your presence?"}},"definableWords":["Spirit"],"peopleInVerse":[]},"8":{"text":"If I ascend up into heaven, thou art there: if I make my bed in hell, behold, thou art there.","ref":"Psalms 139:8","synthesized":"If I ascend to the heavens, You are there; if I make my bed in Sheol, You are there.","sources":{"KJV":{"text":"If I ascend up into heaven, thou art there: if I make my bed in hell, behold, thou art there."},"BSB":{"text":"If I ascend to the heavens, You are there; if I make my bed in Sheol, You are there."}},"definableWords":["heavens","make"],"peopleInVerse":[]},"9":{"text":"If I take the wings of the morning, and dwell in the uttermost parts of the sea;","ref":"Psalms 139:9","synthesized":"If I rise on the wings of the dawn, if I settle by the farthest sea,","sources":{"KJV":{"text":"If I take the wings of the morning, and dwell in the uttermost parts of the sea;"},"BSB":{"text":"If I rise on the wings of the dawn, if I settle by the farthest sea,"}},"definableWords":["sea"],"peopleInVerse":[]},"10":{"text":"Even there shall thy hand lead me, and thy right hand shall hold me.","ref":"Psalms 139:10","synthesized":"even there Your hand will guide me; Your right hand will hold me fast.","sources":{"KJV":{"text":"Even there shall thy hand lead me, and thy right hand shall hold me."},"BSB":{"text":"even there Your hand will guide me; Your right hand will hold me fast."}},"definableWords":["fast"],"peopleInVerse":[]},"11":{"text":"If I say, Surely the darkness shall cover me; even the night shall be light about me.","ref":"Psalms 139:11","synthesized":"If I say, “Surely the darkness will hide me, and the light become night around me”—","sources":{"KJV":{"text":"If I say, Surely the darkness shall cover me; even the night shall be light about me."},"BSB":{"text":"If I say, “Surely the darkness will hide me, and the light become night around me”—"}},"definableWords":["darkness","light","night"],"peopleInVerse":[]},"12":{"text":"Yea, the darkness hideth not from thee; but the night shineth as the day: the darkness and the light are both alike to thee.","ref":"Psalms 139:12","synthesized":"even the darkness is not dark to You, but the night shines like the day, for darkness is as light to You.","sources":{"KJV":{"text":"Yea, the darkness hideth not from thee; but the night shineth as the day: the darkness and the light are both alike to thee."},"BSB":{"text":"even the darkness is not dark to You, but the night shines like the day, for darkness is as light to You."}},"definableWords":["darkness","night","day","light"],"peopleInVerse":[]},"13":{"text":"For thou hast possessed my reins: thou hast covered me in my mother’s womb.","ref":"Psalms 139:13","synthesized":"For You formed my inmost being; You knit me together in my mother’s womb.","sources":{"KJV":{"text":"For thou hast possessed my reins: thou hast covered me in my mother’s womb."},"BSB":{"text":"For You formed my inmost being; You knit me together in my mother’s womb."}},"definableWords":["formed","mother"],"peopleInVerse":[]},"14":{"text":"I will praise thee; for I am fearfully and wonderfully made: marvellous are thy works; and that my soul knoweth right well.","ref":"Psalms 139:14","synthesized":"I praise You, for I am fearfully and wonderfully made. Marvelous are Your works, and I know this very well.","sources":{"KJV":{"text":"I will praise thee; for I am fearfully and wonderfully made: marvellous are thy works; and that my soul knoweth right well."},"BSB":{"text":"I praise You, for I am fearfully and wonderfully made. Marvelous are Your works, and I know this very well."}},"definableWords":["praise","made","works"],"peopleInVerse":[]},"15":{"text":"My substance was not hid from thee, when I was made in secret, and curiously wrought in the lowest parts of the earth.","ref":"Psalms 139:15","synthesized":"My frame was not hidden from You when I was made in secret, when I was woven together in the depths of the earth.","sources":{"KJV":{"text":"My substance was not hid from thee, when I was made in secret, and curiously wrought in the lowest parts of the earth."},"BSB":{"text":"My frame was not hidden from You when I was made in secret, when I was woven together in the depths of the earth."}},"definableWords":["made","earth"],"peopleInVerse":[]},"16":{"text":"Thine eyes did see my substance, yet being unperfect; and in thy book all my members were written, which in continuance were fashioned, when as yet there was none of them.","ref":"Psalms 139:16","synthesized":"Your eyes saw my unformed body; all my days were written in Your book and ordained for me before one of them came to be.","sources":{"KJV":{"text":"Thine eyes did see my substance, yet being unperfect; and in thy book all my members were written, which in continuance were fashioned, when as yet there was none of them."},"BSB":{"text":"Your eyes saw my unformed body; all my days were written in Your book and ordained for me before one of them came to be."}},"definableWords":["saw","days","one"],"peopleInVerse":[]},"17":{"text":"How precious also are thy thoughts unto me, O God! how great is the sum of them!","ref":"Psalms 139:17","synthesized":"How precious to me are Your thoughts, O God, how vast is their sum!","sources":{"KJV":{"text":"How precious also are thy thoughts unto me, O God! how great is the sum of them!"},"BSB":{"text":"How precious to me are Your thoughts, O God, how vast is their sum!"}},"definableWords":["God"],"peopleInVerse":[]},"18":{"text":"If I should count them, they are more in number than the sand: when I awake, I am still with thee.","ref":"Psalms 139:18","synthesized":"If I were to count them, they would outnumber the grains of sand; and when I awake, I am still with You.","sources":{"KJV":{"text":"If I should count them, they are more in number than the sand: when I awake, I am still with thee."},"BSB":{"text":"If I were to count them, they would outnumber the grains of sand; and when I awake, I am still with You."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Surely thou wilt slay the wicked, O God: depart from me therefore, ye bloody men.","ref":"Psalms 139:19","synthesized":"O God, that You would slay the wicked— away from me, you bloodthirsty men—","sources":{"KJV":{"text":"Surely thou wilt slay the wicked, O God: depart from me therefore, ye bloody men."},"BSB":{"text":"O God, that You would slay the wicked— away from me, you bloodthirsty men—"}},"definableWords":["God","men"],"peopleInVerse":[]},"20":{"text":"For they speak against thee wickedly, and thine enemies take thy name in vain.","ref":"Psalms 139:20","synthesized":"who speak of You deceitfully; Your enemies take Your name in vain.","sources":{"KJV":{"text":"For they speak against thee wickedly, and thine enemies take thy name in vain."},"BSB":{"text":"who speak of You deceitfully; Your enemies take Your name in vain."}},"definableWords":["name"],"peopleInVerse":[]},"21":{"text":"Do not I hate them, O LORD, that hate thee? and am not I grieved with those that rise up against thee?","ref":"Psalms 139:21","synthesized":"Do I not hate those who hate You, O LORD, and detest those who rise against You?","sources":{"KJV":{"text":"Do not I hate them, O LORD, that hate thee? and am not I grieved with those that rise up against thee?"},"BSB":{"text":"Do I not hate those who hate You, O LORD, and detest those who rise against You?"}},"definableWords":["LORD"],"peopleInVerse":[]},"22":{"text":"I hate them with perfect hatred: I count them mine enemies.","ref":"Psalms 139:22","synthesized":"I hate them with perfect hatred; I count them as my enemies.","sources":{"KJV":{"text":"I hate them with perfect hatred: I count them mine enemies."},"BSB":{"text":"I hate them with perfect hatred; I count them as my enemies."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Search me, O God, and know my heart: try me, and know my thoughts:","ref":"Psalms 139:23","synthesized":"Search me, O God, and know my heart; test me and know my concerns.","sources":{"KJV":{"text":"Search me, O God, and know my heart: try me, and know my thoughts:"},"BSB":{"text":"Search me, O God, and know my heart; test me and know my concerns."}},"definableWords":["God","heart"],"peopleInVerse":[]},"24":{"text":"And see if there be any wicked way in me, and lead me in the way everlasting.","ref":"Psalms 139:24","synthesized":"See if there is any offensive way in me; lead me in the way everlasting.","sources":{"KJV":{"text":"And see if there be any wicked way in me, and lead me in the way everlasting."},"BSB":{"text":"See if there is any offensive way in me; lead me in the way everlasting."}},"definableWords":["see","way","everlasting"],"peopleInVerse":[]}}},"140":{"chapter":"140","title":"DELIVER ME FROM THE EVIL MAN","verses":{"1":{"text":"Deliver me, O LORD, from the evil man: preserve me from the violent man;","ref":"Psalms 140:1","synthesized":"Rescue me, O LORD, from evil men. Protect me from men of violence,","sources":{"KJV":{"text":"Deliver me, O LORD, from the evil man: preserve me from the violent man;"},"BSB":{"text":"Rescue me, O LORD, from evil men. Protect me from men of violence,"}},"definableWords":["LORD","evil","men"],"peopleInVerse":[]},"2":{"text":"Which imagine mischiefs in their heart; continually are they gathered together for war.","ref":"Psalms 140:2","synthesized":"who devise evil in their hearts and stir up war all day long.","sources":{"KJV":{"text":"Which imagine mischiefs in their heart; continually are they gathered together for war."},"BSB":{"text":"who devise evil in their hearts and stir up war all day long."}},"definableWords":["evil","day"],"peopleInVerse":[]},"3":{"text":"They have sharpened their tongues like a serpent; adders’ poison is under their lips. Selah.","ref":"Psalms 140:3","synthesized":"They sharpen their tongues like snakes; the venom of vipers is on their lips. Selah","sources":{"KJV":{"text":"They have sharpened their tongues like a serpent; adders’ poison is under their lips. Selah."},"BSB":{"text":"They sharpen their tongues like snakes; the venom of vipers is on their lips. Selah"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Keep me, O LORD, from the hands of the wicked; preserve me from the violent man; who have purposed to overthrow my goings.","ref":"Psalms 140:4","synthesized":"Guard me, O LORD, from the hands of the wicked. Keep me safe from men of violence who scheme to make me stumble.","sources":{"KJV":{"text":"Keep me, O LORD, from the hands of the wicked; preserve me from the violent man; who have purposed to overthrow my goings."},"BSB":{"text":"Guard me, O LORD, from the hands of the wicked. Keep me safe from men of violence who scheme to make me stumble."}},"definableWords":["LORD","keep","men","make"],"peopleInVerse":[]},"5":{"text":"The proud have hid a snare for me, and cords; they have spread a net by the wayside; they have set gins for me. Selah.","ref":"Psalms 140:5","synthesized":"The proud hide a snare for me; the cords of their net are spread along the path, and lures are set out for me. Selah","sources":{"KJV":{"text":"The proud have hid a snare for me, and cords; they have spread a net by the wayside; they have set gins for me. Selah."},"BSB":{"text":"The proud hide a snare for me; the cords of their net are spread along the path, and lures are set out for me. Selah"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"I said unto the LORD, Thou art my God: hear the voice of my supplications, O LORD.","ref":"Psalms 140:6","synthesized":"I say to the LORD, “You are my God.” Hear, O LORD, my cry for help.","sources":{"KJV":{"text":"I said unto the LORD, Thou art my God: hear the voice of my supplications, O LORD."},"BSB":{"text":"I say to the LORD, “You are my God.” Hear, O LORD, my cry for help."}},"definableWords":["LORD","God","hear","Lord"],"peopleInVerse":[]},"7":{"text":"O GOD the Lord, the strength of my salvation, thou hast covered my head in the day of battle.","ref":"Psalms 140:7","synthesized":"O GOD the Lord, the strength of my salvation, You shield my head in the day of battle.","sources":{"KJV":{"text":"O GOD the Lord, the strength of my salvation, thou hast covered my head in the day of battle."},"BSB":{"text":"O GOD the Lord, the strength of my salvation, You shield my head in the day of battle."}},"definableWords":["God","Lord","salvation","day"],"peopleInVerse":[]},"8":{"text":"Grant not, O LORD, the desires of the wicked: further not his wicked device; lest they exalt themselves. Selah.","ref":"Psalms 140:8","synthesized":"Grant not, O LORD, the desires of the wicked; do not promote their evil plans, lest they be exalted. Selah","sources":{"KJV":{"text":"Grant not, O LORD, the desires of the wicked: further not his wicked device; lest they exalt themselves. Selah."},"BSB":{"text":"Grant not, O LORD, the desires of the wicked; do not promote their evil plans, lest they be exalted. Selah"}},"definableWords":["LORD","evil"],"peopleInVerse":[]},"9":{"text":"As for the head of those that compass me about, let the mischief of their own lips cover them.","ref":"Psalms 140:9","synthesized":"May the heads of those who surround me be covered in the trouble their lips have caused.","sources":{"KJV":{"text":"As for the head of those that compass me about, let the mischief of their own lips cover them."},"BSB":{"text":"May the heads of those who surround me be covered in the trouble their lips have caused."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Let burning coals fall upon them: let them be cast into the fire; into deep pits, that they rise not up again.","ref":"Psalms 140:10","synthesized":"May burning coals fall on them; may they be thrown into the fire, into the miry pits, never to rise again.","sources":{"KJV":{"text":"Let burning coals fall upon them: let them be cast into the fire; into deep pits, that they rise not up again."},"BSB":{"text":"May burning coals fall on them; may they be thrown into the fire, into the miry pits, never to rise again."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Let not an evil speaker be established in the earth: evil shall hunt the violent man to overthrow him.","ref":"Psalms 140:11","synthesized":"May no slanderer be established in the land; may calamity hunt down the man of violence.","sources":{"KJV":{"text":"Let not an evil speaker be established in the earth: evil shall hunt the violent man to overthrow him."},"BSB":{"text":"May no slanderer be established in the land; may calamity hunt down the man of violence."}},"definableWords":["land","man"],"peopleInVerse":[]},"12":{"text":"I know that the LORD will maintain the cause of the afflicted, and the right of the poor.","ref":"Psalms 140:12","synthesized":"I know that the LORD upholds justice for the poor and defends the cause of the needy.","sources":{"KJV":{"text":"I know that the LORD will maintain the cause of the afflicted, and the right of the poor."},"BSB":{"text":"I know that the LORD upholds justice for the poor and defends the cause of the needy."}},"definableWords":["LORD","justice"],"peopleInVerse":[]},"13":{"text":"Surely the righteous shall give thanks unto thy name: the upright shall dwell in thy presence.","ref":"Psalms 140:13","synthesized":"Surely the righteous will praise Your name; the upright will dwell in Your presence.","sources":{"KJV":{"text":"Surely the righteous shall give thanks unto thy name: the upright shall dwell in thy presence."},"BSB":{"text":"Surely the righteous will praise Your name; the upright will dwell in Your presence."}},"definableWords":["righteous","praise","name"],"peopleInVerse":[]}}},"141":{"chapter":"141","title":"LET MY PRAYER BE SET FORTH AS INCENSE","verses":{"1":{"text":"Lord, I cry unto thee: make haste unto me; give ear unto my voice, when I cry unto thee.","ref":"Psalms 141:1","synthesized":"I call upon You, O LORD; come quickly to me. Hear my voice when I call to You.","sources":{"KJV":{"text":"Lord, I cry unto thee: make haste unto me; give ear unto my voice, when I cry unto thee."},"BSB":{"text":"I call upon You, O LORD; come quickly to me. Hear my voice when I call to You."}},"definableWords":["LORD","hear","voice"],"peopleInVerse":[]},"2":{"text":"Let my prayer be set forth before thee as incense; and the lifting up of my hands as the evening sacrifice.","ref":"Psalms 141:2","synthesized":"May my prayer be set before You like incense, my uplifted hands like the evening offering.","sources":{"KJV":{"text":"Let my prayer be set forth before thee as incense; and the lifting up of my hands as the evening sacrifice."},"BSB":{"text":"May my prayer be set before You like incense, my uplifted hands like the evening offering."}},"definableWords":["prayer","incense","offering"],"peopleInVerse":[]},"3":{"text":"Set a watch, O LORD, before my mouth; keep the door of my lips.","ref":"Psalms 141:3","synthesized":"Set a guard, O LORD, over my mouth; keep watch at the door of my lips.","sources":{"KJV":{"text":"Set a watch, O LORD, before my mouth; keep the door of my lips."},"BSB":{"text":"Set a guard, O LORD, over my mouth; keep watch at the door of my lips."}},"definableWords":["LORD","keep"],"peopleInVerse":[]},"4":{"text":"Incline not my heart to any evil thing, to practise wicked works with men that work iniquity: and let me not eat of their dainties.","ref":"Psalms 141:4","synthesized":"Do not let my heart be drawn to any evil thing or take part in works of wickedness with men who do iniquity; let me not feast on their delicacies.","sources":{"KJV":{"text":"Incline not my heart to any evil thing, to practise wicked works with men that work iniquity: and let me not eat of their dainties."},"BSB":{"text":"Do not let my heart be drawn to any evil thing or take part in works of wickedness with men who do iniquity; let me not feast on their delicacies."}},"definableWords":["heart","evil","or","works","men","iniquity"],"peopleInVerse":[]},"5":{"text":"Let the righteous smite me; it shall be a kindness: and let him reprove me; it shall be an excellent oil, which shall not break my head: for yet my prayer also shall be in their calamities.","ref":"Psalms 141:5","synthesized":"Let the righteous man strike me; let his rebuke be an act of loving devotion. It is oil for my head; let me not refuse it. For my prayer is ever against the deeds of the wicked.","sources":{"KJV":{"text":"Let the righteous smite me; it shall be a kindness: and let him reprove me; it shall be an excellent oil, which shall not break my head: for yet my prayer also shall be in their calamities."},"BSB":{"text":"Let the righteous man strike me; let his rebuke be an act of loving devotion. It is oil for my head; let me not refuse it. For my prayer is ever against the deeds of the wicked."}},"definableWords":["righteous","man","prayer"],"peopleInVerse":[]},"6":{"text":"When their judges are overthrown in stony places, they shall hear my words; for they are sweet.","ref":"Psalms 141:6","synthesized":"When their rulers are thrown down from the cliffs, the people will listen to my words, for they are pleasant.","sources":{"KJV":{"text":"When their judges are overthrown in stony places, they shall hear my words; for they are sweet."},"BSB":{"text":"When their rulers are thrown down from the cliffs, the people will listen to my words, for they are pleasant."}},"definableWords":["people"],"peopleInVerse":[]},"7":{"text":"Our bones are scattered at the grave’s mouth, as when one cutteth and cleaveth wood upon the earth.","ref":"Psalms 141:7","synthesized":"As when one plows and breaks up the soil, so our bones have been scattered at the mouth of Sheol.","sources":{"KJV":{"text":"Our bones are scattered at the grave’s mouth, as when one cutteth and cleaveth wood upon the earth."},"BSB":{"text":"As when one plows and breaks up the soil, so our bones have been scattered at the mouth of Sheol."}},"definableWords":["one","bones"],"peopleInVerse":[]},"8":{"text":"But mine eyes are unto thee, O GOD the Lord: in thee is my trust; leave not my soul destitute.","ref":"Psalms 141:8","synthesized":"But my eyes are fixed on You, O GOD the Lord. In You I seek refuge; do not leave my soul defenseless.","sources":{"KJV":{"text":"But mine eyes are unto thee, O GOD the Lord: in thee is my trust; leave not my soul destitute."},"BSB":{"text":"But my eyes are fixed on You, O GOD the Lord. In You I seek refuge; do not leave my soul defenseless."}},"definableWords":["God","Lord","seek","soul"],"peopleInVerse":[]},"9":{"text":"Keep me from the snares which they have laid for me, and the gins of the workers of iniquity.","ref":"Psalms 141:9","synthesized":"Keep me from the snares they have laid for me, and from the lures of evildoers.","sources":{"KJV":{"text":"Keep me from the snares which they have laid for me, and the gins of the workers of iniquity."},"BSB":{"text":"Keep me from the snares they have laid for me, and from the lures of evildoers."}},"definableWords":["keep"],"peopleInVerse":[]},"10":{"text":"Let the wicked fall into their own nets, whilst that I withal escape.","ref":"Psalms 141:10","synthesized":"Let the wicked fall into their own nets, while I pass by in safety.","sources":{"KJV":{"text":"Let the wicked fall into their own nets, whilst that I withal escape."},"BSB":{"text":"Let the wicked fall into their own nets, while I pass by in safety."}},"definableWords":[],"peopleInVerse":[]}}},"142":{"chapter":"142","title":"I CRIED WITH MY VOICE","verses":{"1":{"text":"I cried unto the LORD with my voice; with my voice unto the LORD did I make my supplication.","ref":"Psalms 142:1","synthesized":"I cry aloud to the LORD; I lift my voice to the LORD for mercy.","sources":{"KJV":{"text":"I cried unto the LORD with my voice; with my voice unto the LORD did I make my supplication."},"BSB":{"text":"I cry aloud to the LORD; I lift my voice to the LORD for mercy."}},"definableWords":["LORD","voice","Lord","mercy"],"peopleInVerse":[]},"2":{"text":"I poured out my complaint before him; I shewed before him my trouble.","ref":"Psalms 142:2","synthesized":"I pour out my complaint before Him; I reveal my trouble to Him.","sources":{"KJV":{"text":"I poured out my complaint before him; I shewed before him my trouble."},"BSB":{"text":"I pour out my complaint before Him; I reveal my trouble to Him."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"When my spirit was overwhelmed within me, then thou knewest my path. In the way wherein I walked have they privily laid a snare for me.","ref":"Psalms 142:3","synthesized":"Although my spirit grows faint within me, You know my way. Along the path I travel they have hidden a snare for me.","sources":{"KJV":{"text":"When my spirit was overwhelmed within me, then thou knewest my path. In the way wherein I walked have they privily laid a snare for me."},"BSB":{"text":"Although my spirit grows faint within me, You know my way. Along the path I travel they have hidden a snare for me."}},"definableWords":["spirit","way"],"peopleInVerse":[]},"4":{"text":"I looked on my right hand, and beheld, but there was no man that would know me: refuge failed me; no man cared for my soul.","ref":"Psalms 142:4","synthesized":"Look to my right and see; no one attends to me. There is no refuge for me; no one cares for my soul.","sources":{"KJV":{"text":"I looked on my right hand, and beheld, but there was no man that would know me: refuge failed me; no man cared for my soul."},"BSB":{"text":"Look to my right and see; no one attends to me. There is no refuge for me; no one cares for my soul."}},"definableWords":["see","one","soul"],"peopleInVerse":[]},"5":{"text":"I cried unto thee, O LORD: I said, Thou art my refuge and my portion in the land of the living.","ref":"Psalms 142:5","synthesized":"I cry to You, O LORD: “You are my refuge, my portion in the land of the living.”","sources":{"KJV":{"text":"I cried unto thee, O LORD: I said, Thou art my refuge and my portion in the land of the living."},"BSB":{"text":"I cry to You, O LORD: “You are my refuge, my portion in the land of the living.”"}},"definableWords":["LORD","land","living"],"peopleInVerse":[]},"6":{"text":"Attend unto my cry; for I am brought very low: deliver me from my persecutors; for they are stronger than I.","ref":"Psalms 142:6","synthesized":"Listen to my cry, for I am brought quite low. Rescue me from my pursuers, for they are too strong for me.","sources":{"KJV":{"text":"Attend unto my cry; for I am brought very low: deliver me from my persecutors; for they are stronger than I."},"BSB":{"text":"Listen to my cry, for I am brought quite low. Rescue me from my pursuers, for they are too strong for me."}},"definableWords":["strong"],"peopleInVerse":[]},"7":{"text":"Bring my soul out of prison, that I may praise thy name: the righteous shall compass me about; for thou shalt deal bountifully with me.","ref":"Psalms 142:7","synthesized":"Free my soul from prison, that I may praise Your name. The righteous will gather around me because of Your goodness to me.","sources":{"KJV":{"text":"Bring my soul out of prison, that I may praise thy name: the righteous shall compass me about; for thou shalt deal bountifully with me."},"BSB":{"text":"Free my soul from prison, that I may praise Your name. The righteous will gather around me because of Your goodness to me."}},"definableWords":["soul","praise","name","righteous"],"peopleInVerse":[]}}},"143":{"chapter":"143","title":"HEAR MY PRAYER, O LORD (II)","verses":{"1":{"text":"Hear my prayer, O LORD, give ear to my supplications: in thy faithfulness answer me, and in thy righteousness.","ref":"Psalms 143:1","synthesized":"O LORD, hear my prayer. In Your faithfulness, give ear to my plea; in Your righteousness, answer me.","sources":{"KJV":{"text":"Hear my prayer, O LORD, give ear to my supplications: in thy faithfulness answer me, and in thy righteousness."},"BSB":{"text":"O LORD, hear my prayer. In Your faithfulness, give ear to my plea; in Your righteousness, answer me."}},"definableWords":["LORD","hear","prayer","righteousness"],"peopleInVerse":[]},"2":{"text":"And enter not into judgment with thy servant: for in thy sight shall no man living be justified.","ref":"Psalms 143:2","synthesized":"Do not bring Your servant into judgment, for no one alive is righteous before You.","sources":{"KJV":{"text":"And enter not into judgment with thy servant: for in thy sight shall no man living be justified."},"BSB":{"text":"Do not bring Your servant into judgment, for no one alive is righteous before You."}},"definableWords":["servant","judgment","one","righteous"],"peopleInVerse":[]},"3":{"text":"For the enemy hath persecuted my soul; he hath smitten my life down to the ground; he hath made me to dwell in darkness, as those that have been long dead.","ref":"Psalms 143:3","synthesized":"For the enemy has pursued my soul, crushing my life to the ground, making me dwell in darkness like those long since dead.","sources":{"KJV":{"text":"For the enemy hath persecuted my soul; he hath smitten my life down to the ground; he hath made me to dwell in darkness, as those that have been long dead."},"BSB":{"text":"For the enemy has pursued my soul, crushing my life to the ground, making me dwell in darkness like those long since dead."}},"definableWords":["soul","life","ground","darkness"],"peopleInVerse":[]},"4":{"text":"Therefore is my spirit overwhelmed within me; my heart within me is desolate.","ref":"Psalms 143:4","synthesized":"My spirit grows faint within me; my heart is dismayed inside me.","sources":{"KJV":{"text":"Therefore is my spirit overwhelmed within me; my heart within me is desolate."},"BSB":{"text":"My spirit grows faint within me; my heart is dismayed inside me."}},"definableWords":["spirit","heart"],"peopleInVerse":[]},"5":{"text":"I remember the days of old; I meditate on all thy works; I muse on the work of thy hands.","ref":"Psalms 143:5","synthesized":"I remember the days of old; I meditate on all Your works; I consider the work of Your hands.","sources":{"KJV":{"text":"I remember the days of old; I meditate on all thy works; I muse on the work of thy hands."},"BSB":{"text":"I remember the days of old; I meditate on all Your works; I consider the work of Your hands."}},"definableWords":["remember","days","works","work"],"peopleInVerse":[]},"6":{"text":"I stretch forth my hands unto thee: my soul thirsteth after thee, as a thirsty land. Selah.","ref":"Psalms 143:6","synthesized":"I stretch out my hands to You; my soul thirsts for You like a parched land. Selah","sources":{"KJV":{"text":"I stretch forth my hands unto thee: my soul thirsteth after thee, as a thirsty land. Selah."},"BSB":{"text":"I stretch out my hands to You; my soul thirsts for You like a parched land. Selah"}},"definableWords":["soul","land"],"peopleInVerse":[]},"7":{"text":"Hear me speedily, O LORD: my spirit faileth: hide not thy face from me, lest I be like unto them that go down into the pit.","ref":"Psalms 143:7","synthesized":"Answer me quickly, O LORD; my spirit fails. Do not hide Your face from me, or I will be like those who descend to the Pit.","sources":{"KJV":{"text":"Hear me speedily, O LORD: my spirit faileth: hide not thy face from me, lest I be like unto them that go down into the pit."},"BSB":{"text":"Answer me quickly, O LORD; my spirit fails. Do not hide Your face from me, or I will be like those who descend to the Pit."}},"definableWords":["LORD","spirit","or"],"peopleInVerse":[]},"8":{"text":"Cause me to hear thy lovingkindness in the morning; for in thee do I trust: cause me to know the way wherein I should walk; for I lift up my soul unto thee.","ref":"Psalms 143:8","synthesized":"Let me hear Your loving devotion in the morning, for I have put my trust in You. Teach me the way I should walk, for to You I lift up my soul.","sources":{"KJV":{"text":"Cause me to hear thy lovingkindness in the morning; for in thee do I trust: cause me to know the way wherein I should walk; for I lift up my soul unto thee."},"BSB":{"text":"Let me hear Your loving devotion in the morning, for I have put my trust in You. Teach me the way I should walk, for to You I lift up my soul."}},"definableWords":["hear","trust","way","walk","soul"],"peopleInVerse":[]},"9":{"text":"Deliver me, O LORD, from mine enemies: I flee unto thee to hide me.","ref":"Psalms 143:9","synthesized":"Deliver me from my enemies, O LORD; I flee to You for refuge.","sources":{"KJV":{"text":"Deliver me, O LORD, from mine enemies: I flee unto thee to hide me."},"BSB":{"text":"Deliver me from my enemies, O LORD; I flee to You for refuge."}},"definableWords":["deliver","LORD"],"peopleInVerse":[]},"10":{"text":"Teach me to do thy will; for thou art my God: thy spirit is good; lead me into the land of uprightness.","ref":"Psalms 143:10","synthesized":"Teach me to do Your will, for You are my God. May Your good Spirit lead me on level ground.","sources":{"KJV":{"text":"Teach me to do thy will; for thou art my God: thy spirit is good; lead me into the land of uprightness."},"BSB":{"text":"Teach me to do Your will, for You are my God. May Your good Spirit lead me on level ground."}},"definableWords":["God","good","Spirit","ground"],"peopleInVerse":[]},"11":{"text":"Quicken me, O LORD, for thy name’s sake: for thy righteousness’ sake bring my soul out of trouble.","ref":"Psalms 143:11","synthesized":"For the sake of Your name, O LORD, revive me. In Your righteousness, bring my soul out of trouble.","sources":{"KJV":{"text":"Quicken me, O LORD, for thy name’s sake: for thy righteousness’ sake bring my soul out of trouble."},"BSB":{"text":"For the sake of Your name, O LORD, revive me. In Your righteousness, bring my soul out of trouble."}},"definableWords":["name","LORD","righteousness","soul"],"peopleInVerse":[]},"12":{"text":"And of thy mercy cut off mine enemies, and destroy all them that afflict my soul: for I am thy servant.","ref":"Psalms 143:12","synthesized":"And in Your loving devotion, cut off my enemies. Destroy all who afflict me, for I am Your servant.","sources":{"KJV":{"text":"And of thy mercy cut off mine enemies, and destroy all them that afflict my soul: for I am thy servant."},"BSB":{"text":"And in Your loving devotion, cut off my enemies. Destroy all who afflict me, for I am Your servant."}},"definableWords":["servant"],"peopleInVerse":[]}}},"144":{"chapter":"144","title":"BLESSED BE THE LORD MY STRENGTH","verses":{"1":{"text":"Blessed be the LORD my strength, which teacheth my hands to war, and my fingers to fight:","ref":"Psalms 144:1","synthesized":"Blessed be the LORD, my Rock, who trains my hands for war, my fingers for battle.","sources":{"KJV":{"text":"Blessed be the LORD my strength, which teacheth my hands to war, and my fingers to fight:"},"BSB":{"text":"Blessed be the LORD, my Rock, who trains my hands for war, my fingers for battle."}},"definableWords":["blessed","LORD"],"peopleInVerse":[]},"2":{"text":"My goodness, and my fortress; my high tower, and my deliverer; my shield, and he in whom I trust; who subdueth my people under me.","ref":"Psalms 144:2","synthesized":"He is my steadfast love and my fortress, my stronghold and my deliverer. He is my shield, in whom I take refuge, who subdues peoples under me.","sources":{"KJV":{"text":"My goodness, and my fortress; my high tower, and my deliverer; my shield, and he in whom I trust; who subdueth my people under me."},"BSB":{"text":"He is my steadfast love and my fortress, my stronghold and my deliverer. He is my shield, in whom I take refuge, who subdues peoples under me."}},"definableWords":["love"],"peopleInVerse":[]},"3":{"text":"LORD, what is man, that thou takest knowledge of him! or the son of man, that thou makest account of him!","ref":"Psalms 144:3","synthesized":"O LORD, what is man, that You regard him, the son of man that You think of him?","sources":{"KJV":{"text":"LORD, what is man, that thou takest knowledge of him! or the son of man, that thou makest account of him!"},"BSB":{"text":"O LORD, what is man, that You regard him, the son of man that You think of him?"}},"definableWords":["LORD","man","son"],"peopleInVerse":[]},"4":{"text":"Man is like to vanity: his days are as a shadow that passeth away.","ref":"Psalms 144:4","synthesized":"Man is like a breath; his days are like a passing shadow.","sources":{"KJV":{"text":"Man is like to vanity: his days are as a shadow that passeth away."},"BSB":{"text":"Man is like a breath; his days are like a passing shadow."}},"definableWords":["man","breath","days"],"peopleInVerse":[]},"5":{"text":"Bow thy heavens, O LORD, and come down: touch the mountains, and they shall smoke.","ref":"Psalms 144:5","synthesized":"Part Your heavens, O LORD, and come down; touch the mountains, that they may smoke.","sources":{"KJV":{"text":"Bow thy heavens, O LORD, and come down: touch the mountains, and they shall smoke."},"BSB":{"text":"Part Your heavens, O LORD, and come down; touch the mountains, that they may smoke."}},"definableWords":["heavens","LORD"],"peopleInVerse":[]},"6":{"text":"Cast forth lightning, and scatter them: shoot out thine arrows, and destroy them.","ref":"Psalms 144:6","synthesized":"Flash forth Your lightning and scatter them; shoot Your arrows and rout them.","sources":{"KJV":{"text":"Cast forth lightning, and scatter them: shoot out thine arrows, and destroy them."},"BSB":{"text":"Flash forth Your lightning and scatter them; shoot Your arrows and rout them."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Send thine hand from above; rid me, and deliver me out of great waters, from the hand of strange children;","ref":"Psalms 144:7","synthesized":"Reach down from on high; set me free and rescue me from the deep waters, from the grasp of foreigners,","sources":{"KJV":{"text":"Send thine hand from above; rid me, and deliver me out of great waters, from the hand of strange children;"},"BSB":{"text":"Reach down from on high; set me free and rescue me from the deep waters, from the grasp of foreigners,"}},"definableWords":["deep","waters"],"peopleInVerse":[]},"8":{"text":"Whose mouth speaketh vanity, and their right hand is a right hand of falsehood.","ref":"Psalms 144:8","synthesized":"whose mouths speak falsehood, whose right hands are deceitful.","sources":{"KJV":{"text":"Whose mouth speaketh vanity, and their right hand is a right hand of falsehood."},"BSB":{"text":"whose mouths speak falsehood, whose right hands are deceitful."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"I will sing a new song unto thee, O God: upon a psaltery and an instrument of ten strings will I sing praises unto thee.","ref":"Psalms 144:9","synthesized":"I will sing to You a new song, O God; on a harp of ten strings I will make music to You—","sources":{"KJV":{"text":"I will sing a new song unto thee, O God: upon a psaltery and an instrument of ten strings will I sing praises unto thee."},"BSB":{"text":"I will sing to You a new song, O God; on a harp of ten strings I will make music to You—"}},"definableWords":["God","make"],"peopleInVerse":[]},"10":{"text":"It is he that giveth salvation unto kings: who delivereth David his servant from the hurtful sword.","ref":"Psalms 144:10","synthesized":"to Him who gives victory to kings, who frees His servant David from the deadly sword.","sources":{"KJV":{"text":"It is he that giveth salvation unto kings: who delivereth David his servant from the hurtful sword."},"BSB":{"text":"to Him who gives victory to kings, who frees His servant David from the deadly sword."}},"definableWords":["kings","servant"],"peopleInVerse":["David"]},"11":{"text":"Rid me, and deliver me from the hand of strange children, whose mouth speaketh vanity, and their right hand is a right hand of falsehood:","ref":"Psalms 144:11","synthesized":"Set me free and rescue me from the grasp of foreigners, whose mouths speak falsehood, whose right hands are deceitful.","sources":{"KJV":{"text":"Rid me, and deliver me from the hand of strange children, whose mouth speaketh vanity, and their right hand is a right hand of falsehood:"},"BSB":{"text":"Set me free and rescue me from the grasp of foreigners, whose mouths speak falsehood, whose right hands are deceitful."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"That our sons may be as plants grown up in their youth; that our daughters may be as corner stones, polished after the similitude of a palace:","ref":"Psalms 144:12","synthesized":"Then our sons will be like plants nurtured in their youth, our daughters like corner pillars carved to adorn a palace.","sources":{"KJV":{"text":"That our sons may be as plants grown up in their youth; that our daughters may be as corner stones, polished after the similitude of a palace:"},"BSB":{"text":"Then our sons will be like plants nurtured in their youth, our daughters like corner pillars carved to adorn a palace."}},"definableWords":["sons","daughters"],"peopleInVerse":[]},"13":{"text":"That our garners may be full, affording all manner of store: that our sheep may bring forth thousands and ten thousands in our streets:","ref":"Psalms 144:13","synthesized":"Our storehouses will be full, supplying all manner of produce; our flocks will bring forth thousands, tens of thousands in our fields.","sources":{"KJV":{"text":"That our garners may be full, affording all manner of store: that our sheep may bring forth thousands and ten thousands in our streets:"},"BSB":{"text":"Our storehouses will be full, supplying all manner of produce; our flocks will bring forth thousands, tens of thousands in our fields."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"That our oxen may be strong to labour; that there be no breaking in, nor going out; that there be no complaining in our streets.","ref":"Psalms 144:14","synthesized":"Our oxen will bear great loads. There will be no breach in the walls, no going into captivity, and no cry of lament in our streets.","sources":{"KJV":{"text":"That our oxen may be strong to labour; that there be no breaking in, nor going out; that there be no complaining in our streets."},"BSB":{"text":"Our oxen will bear great loads. There will be no breach in the walls, no going into captivity, and no cry of lament in our streets."}},"definableWords":["great"],"peopleInVerse":[]},"15":{"text":"Happy is that people, that is in such a case: yea, happy is that people, whose God is the LORD.","ref":"Psalms 144:15","synthesized":"Blessed are the people of whom this is so; blessed are the people whose God is the LORD.","sources":{"KJV":{"text":"Happy is that people, that is in such a case: yea, happy is that people, whose God is the LORD."},"BSB":{"text":"Blessed are the people of whom this is so; blessed are the people whose God is the LORD."}},"definableWords":["blessed","people","God","LORD"],"peopleInVerse":[]}}},"145":{"chapter":"145","title":"GREAT IS THE LORD","verses":{"1":{"text":"I will extol thee, my God, O king; and I will bless thy name for ever and ever.","ref":"Psalms 145:1","synthesized":"I will exalt You, my God and King; I will bless Your name forever and ever.","sources":{"KJV":{"text":"I will extol thee, my God, O king; and I will bless thy name for ever and ever."},"BSB":{"text":"I will exalt You, my God and King; I will bless Your name forever and ever."}},"definableWords":["God","King","bless","name"],"peopleInVerse":[]},"2":{"text":"Every day will I bless thee; and I will praise thy name for ever and ever.","ref":"Psalms 145:2","synthesized":"Every day I will bless You, and I will praise Your name forever and ever.","sources":{"KJV":{"text":"Every day will I bless thee; and I will praise thy name for ever and ever."},"BSB":{"text":"Every day I will bless You, and I will praise Your name forever and ever."}},"definableWords":["day","bless","praise","name"],"peopleInVerse":[]},"3":{"text":"Great is the LORD, and greatly to be praised; and his greatness is unsearchable.","ref":"Psalms 145:3","synthesized":"Great is the LORD and greatly to be praised; His greatness is unsearchable.","sources":{"KJV":{"text":"Great is the LORD, and greatly to be praised; and his greatness is unsearchable."},"BSB":{"text":"Great is the LORD and greatly to be praised; His greatness is unsearchable."}},"definableWords":["great","LORD"],"peopleInVerse":[]},"4":{"text":"One generation shall praise thy works to another, and shall declare thy mighty acts.","ref":"Psalms 145:4","synthesized":"One generation will commend Your works to the next, and will proclaim Your mighty acts—","sources":{"KJV":{"text":"One generation shall praise thy works to another, and shall declare thy mighty acts."},"BSB":{"text":"One generation will commend Your works to the next, and will proclaim Your mighty acts—"}},"definableWords":["one","works","mighty"],"peopleInVerse":[]},"5":{"text":"I will speak of the glorious honour of thy majesty, and of thy wondrous works.","ref":"Psalms 145:5","synthesized":"the glorious splendor of Your majesty. And I will meditate on Your wondrous works.","sources":{"KJV":{"text":"I will speak of the glorious honour of thy majesty, and of thy wondrous works."},"BSB":{"text":"the glorious splendor of Your majesty. And I will meditate on Your wondrous works."}},"definableWords":["works"],"peopleInVerse":[]},"6":{"text":"And men shall speak of the might of thy terrible acts: and I will declare thy greatness.","ref":"Psalms 145:6","synthesized":"They will proclaim the power of Your awesome deeds, and I will declare Your greatness.","sources":{"KJV":{"text":"And men shall speak of the might of thy terrible acts: and I will declare thy greatness."},"BSB":{"text":"They will proclaim the power of Your awesome deeds, and I will declare Your greatness."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"They shall abundantly utter the memory of thy great goodness, and shall sing of thy righteousness.","ref":"Psalms 145:7","synthesized":"They will extol the fame of Your abundant goodness and sing joyfully of Your righteousness.","sources":{"KJV":{"text":"They shall abundantly utter the memory of thy great goodness, and shall sing of thy righteousness."},"BSB":{"text":"They will extol the fame of Your abundant goodness and sing joyfully of Your righteousness."}},"definableWords":["righteousness"],"peopleInVerse":[]},"8":{"text":"The LORD is gracious, and full of compassion; slow to anger, and of great mercy.","ref":"Psalms 145:8","synthesized":"The LORD is gracious and compassionate, slow to anger and abounding in loving devotion.","sources":{"KJV":{"text":"The LORD is gracious, and full of compassion; slow to anger, and of great mercy."},"BSB":{"text":"The LORD is gracious and compassionate, slow to anger and abounding in loving devotion."}},"definableWords":["LORD","anger"],"peopleInVerse":[]},"9":{"text":"The LORD is good to all: and his tender mercies are over all his works.","ref":"Psalms 145:9","synthesized":"The LORD is good to all; His compassion rests on all He has made.","sources":{"KJV":{"text":"The LORD is good to all: and his tender mercies are over all his works."},"BSB":{"text":"The LORD is good to all; His compassion rests on all He has made."}},"definableWords":["LORD","good","made"],"peopleInVerse":[]},"10":{"text":"All thy works shall praise thee, O LORD; and thy saints shall bless thee.","ref":"Psalms 145:10","synthesized":"All You have made will give You thanks, O LORD, and Your saints will bless You.","sources":{"KJV":{"text":"All thy works shall praise thee, O LORD; and thy saints shall bless thee."},"BSB":{"text":"All You have made will give You thanks, O LORD, and Your saints will bless You."}},"definableWords":["made","LORD","bless"],"peopleInVerse":[]},"11":{"text":"They shall speak of the glory of thy kingdom, and talk of thy power;","ref":"Psalms 145:11","synthesized":"They will tell of the glory of Your kingdom and speak of Your might,","sources":{"KJV":{"text":"They shall speak of the glory of thy kingdom, and talk of thy power;"},"BSB":{"text":"They will tell of the glory of Your kingdom and speak of Your might,"}},"definableWords":["glory","kingdom"],"peopleInVerse":[]},"12":{"text":"To make known to the sons of men his mighty acts, and the glorious majesty of his kingdom.","ref":"Psalms 145:12","synthesized":"to make known to men Your mighty acts and the glorious splendor of Your kingdom.","sources":{"KJV":{"text":"To make known to the sons of men his mighty acts, and the glorious majesty of his kingdom."},"BSB":{"text":"to make known to men Your mighty acts and the glorious splendor of Your kingdom."}},"definableWords":["make","men","mighty","kingdom"],"peopleInVerse":[]},"13":{"text":"Thy kingdom is an everlasting kingdom, and thy dominion endureth throughout all generations.","ref":"Psalms 145:13","synthesized":"Your kingdom is an everlasting kingdom, and Your dominion endures through all generations. The LORD is faithful in all His words and kind in all His actions.","sources":{"KJV":{"text":"Thy kingdom is an everlasting kingdom, and thy dominion endureth throughout all generations."},"BSB":{"text":"Your kingdom is an everlasting kingdom, and Your dominion endures through all generations. The LORD is faithful in all His words and kind in all His actions."}},"definableWords":["kingdom","everlasting","dominion","LORD"],"peopleInVerse":[]},"14":{"text":"The LORD upholdeth all that fall, and raiseth up all those that be bowed down.","ref":"Psalms 145:14","synthesized":"The LORD upholds all who fall and lifts up all who are bowed down.","sources":{"KJV":{"text":"The LORD upholdeth all that fall, and raiseth up all those that be bowed down."},"BSB":{"text":"The LORD upholds all who fall and lifts up all who are bowed down."}},"definableWords":["LORD"],"peopleInVerse":[]},"15":{"text":"The eyes of all wait upon thee; and thou givest them their meat in due season.","ref":"Psalms 145:15","synthesized":"The eyes of all look to You, and You give them their food in season.","sources":{"KJV":{"text":"The eyes of all wait upon thee; and thou givest them their meat in due season."},"BSB":{"text":"The eyes of all look to You, and You give them their food in season."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Thou openest thine hand, and satisfiest the desire of every living thing.","ref":"Psalms 145:16","synthesized":"You open Your hand and satisfy the desire of every living thing.","sources":{"KJV":{"text":"Thou openest thine hand, and satisfiest the desire of every living thing."},"BSB":{"text":"You open Your hand and satisfy the desire of every living thing."}},"definableWords":["living"],"peopleInVerse":[]},"17":{"text":"The LORD is righteous in all his ways, and holy in all his works.","ref":"Psalms 145:17","synthesized":"The LORD is righteous in all His ways and kind in all His deeds.","sources":{"KJV":{"text":"The LORD is righteous in all his ways, and holy in all his works."},"BSB":{"text":"The LORD is righteous in all His ways and kind in all His deeds."}},"definableWords":["LORD","righteous"],"peopleInVerse":[]},"18":{"text":"The LORD is nigh unto all them that call upon him, to all that call upon him in truth.","ref":"Psalms 145:18","synthesized":"The LORD is near to all who call on Him, to all who call out to Him in truth.","sources":{"KJV":{"text":"The LORD is nigh unto all them that call upon him, to all that call upon him in truth."},"BSB":{"text":"The LORD is near to all who call on Him, to all who call out to Him in truth."}},"definableWords":["LORD","truth"],"peopleInVerse":[]},"19":{"text":"He will fulfil the desire of them that fear him: he also will hear their cry, and will save them.","ref":"Psalms 145:19","synthesized":"He fulfills the desires of those who fear Him; He hears their cry and saves them.","sources":{"KJV":{"text":"He will fulfil the desire of them that fear him: he also will hear their cry, and will save them."},"BSB":{"text":"He fulfills the desires of those who fear Him; He hears their cry and saves them."}},"definableWords":["fear"],"peopleInVerse":[]},"20":{"text":"The LORD preserveth all them that love him: but all the wicked will he destroy.","ref":"Psalms 145:20","synthesized":"The LORD preserves all who love Him, but all the wicked He will destroy.","sources":{"KJV":{"text":"The LORD preserveth all them that love him: but all the wicked will he destroy."},"BSB":{"text":"The LORD preserves all who love Him, but all the wicked He will destroy."}},"definableWords":["LORD","love"],"peopleInVerse":[]},"21":{"text":"My mouth shall speak the praise of the LORD: and let all flesh bless his holy name for ever and ever.","ref":"Psalms 145:21","synthesized":"My mouth will declare the praise of the LORD; let every creature bless His holy name forever and ever.","sources":{"KJV":{"text":"My mouth shall speak the praise of the LORD: and let all flesh bless his holy name for ever and ever."},"BSB":{"text":"My mouth will declare the praise of the LORD; let every creature bless His holy name forever and ever."}},"definableWords":["praise","LORD","bless","holy","name"],"peopleInVerse":[]}}},"146":{"chapter":"146","title":"PRAISE THE LORD, O MY SOUL","verses":{"1":{"text":"Praise ye the LORD. Praise the LORD, O my soul.","ref":"Psalms 146:1","synthesized":"Hallelujah!   Praise the LORD, O my soul.","sources":{"KJV":{"text":"Praise ye the LORD. Praise the LORD, O my soul."},"BSB":{"text":"Hallelujah!   Praise the LORD, O my soul."}},"definableWords":["praise","LORD","soul"],"peopleInVerse":[]},"2":{"text":"While I live will I praise the LORD: I will sing praises unto my God while I have any being.","ref":"Psalms 146:2","synthesized":"I will praise the LORD all my life; I will sing praises to my God while I have my being.","sources":{"KJV":{"text":"While I live will I praise the LORD: I will sing praises unto my God while I have any being."},"BSB":{"text":"I will praise the LORD all my life; I will sing praises to my God while I have my being."}},"definableWords":["praise","LORD","life","God"],"peopleInVerse":[]},"3":{"text":"Put not your trust in princes, nor in the son of man, in whom there is no help.","ref":"Psalms 146:3","synthesized":"Put not your trust in princes, in mortal man, who cannot save.","sources":{"KJV":{"text":"Put not your trust in princes, nor in the son of man, in whom there is no help."},"BSB":{"text":"Put not your trust in princes, in mortal man, who cannot save."}},"definableWords":["trust","man"],"peopleInVerse":[]},"4":{"text":"His breath goeth forth, he returneth to his earth; in that very day his thoughts perish.","ref":"Psalms 146:4","synthesized":"When his spirit departs, he returns to the ground; on that very day his plans perish.","sources":{"KJV":{"text":"His breath goeth forth, he returneth to his earth; in that very day his thoughts perish."},"BSB":{"text":"When his spirit departs, he returns to the ground; on that very day his plans perish."}},"definableWords":["spirit","ground","day"],"peopleInVerse":[]},"5":{"text":"Happy is he that hath the God of Jacob for his help, whose hope is in the LORD his God:","ref":"Psalms 146:5","synthesized":"Blessed is he whose help is the God of Jacob, whose hope is in the LORD his God,","sources":{"KJV":{"text":"Happy is he that hath the God of Jacob for his help, whose hope is in the LORD his God:"},"BSB":{"text":"Blessed is he whose help is the God of Jacob, whose hope is in the LORD his God,"}},"definableWords":["blessed","God","Jacob","hope","LORD"],"peopleInVerse":["Jacob"]},"6":{"text":"Which made heaven, and earth, the sea, and all that therein is: which keepeth truth for ever:","ref":"Psalms 146:6","synthesized":"the Maker of heaven and earth, the sea, and everything in them. He remains faithful forever.","sources":{"KJV":{"text":"Which made heaven, and earth, the sea, and all that therein is: which keepeth truth for ever:"},"BSB":{"text":"the Maker of heaven and earth, the sea, and everything in them. He remains faithful forever."}},"definableWords":["heaven","earth","sea"],"peopleInVerse":[]},"7":{"text":"Which executeth judgment for the oppressed: which giveth food to the hungry. The LORD looseth the prisoners:","ref":"Psalms 146:7","synthesized":"He executes justice for the oppressed and gives food to the hungry. The LORD sets the prisoners free,","sources":{"KJV":{"text":"Which executeth judgment for the oppressed: which giveth food to the hungry. The LORD looseth the prisoners:"},"BSB":{"text":"He executes justice for the oppressed and gives food to the hungry. The LORD sets the prisoners free,"}},"definableWords":["justice","LORD"],"peopleInVerse":[]},"8":{"text":"The LORD openeth the eyes of the blind: the LORD raiseth them that are bowed down: the LORD loveth the righteous:","ref":"Psalms 146:8","synthesized":"the LORD opens the eyes of the blind, the LORD lifts those who are weighed down, the LORD loves the righteous.","sources":{"KJV":{"text":"The LORD openeth the eyes of the blind: the LORD raiseth them that are bowed down: the LORD loveth the righteous:"},"BSB":{"text":"the LORD opens the eyes of the blind, the LORD lifts those who are weighed down, the LORD loves the righteous."}},"definableWords":["LORD","Lord","righteous"],"peopleInVerse":[]},"9":{"text":"The LORD preserveth the strangers; he relieveth the fatherless and widow: but the way of the wicked he turneth upside down.","ref":"Psalms 146:9","synthesized":"The LORD protects foreigners; He sustains the fatherless and the widow, but the ways of the wicked He frustrates.","sources":{"KJV":{"text":"The LORD preserveth the strangers; he relieveth the fatherless and widow: but the way of the wicked he turneth upside down."},"BSB":{"text":"The LORD protects foreigners; He sustains the fatherless and the widow, but the ways of the wicked He frustrates."}},"definableWords":["LORD","widow"],"peopleInVerse":[]},"10":{"text":"The LORD shall reign for ever, even thy God, O Zion, unto all generations. Praise ye the LORD.","ref":"Psalms 146:10","synthesized":"The LORD reigns forever, your God, O Zion, for all generations.   Hallelujah!","sources":{"KJV":{"text":"The LORD shall reign for ever, even thy God, O Zion, unto all generations. Praise ye the LORD."},"BSB":{"text":"The LORD reigns forever, your God, O Zion, for all generations.   Hallelujah!"}},"definableWords":["LORD","God","Zion"],"peopleInVerse":[]}}},"147":{"chapter":"147","title":"GREAT IS OUR LORD","verses":{"1":{"text":"Praise ye the LORD: for it is good to sing praises unto our God; for it is pleasant; and praise is comely.","ref":"Psalms 147:1","synthesized":"Hallelujah!   How good it is to sing praises to our God, how pleasant and lovely to praise Him!","sources":{"KJV":{"text":"Praise ye the LORD: for it is good to sing praises unto our God; for it is pleasant; and praise is comely."},"BSB":{"text":"Hallelujah!   How good it is to sing praises to our God, how pleasant and lovely to praise Him!"}},"definableWords":["good","God","praise"],"peopleInVerse":[]},"2":{"text":"The LORD doth build up Jerusalem: he gathereth together the outcasts of Israel.","ref":"Psalms 147:2","synthesized":"The LORD builds up Jerusalem; He gathers the exiles of Israel.","sources":{"KJV":{"text":"The LORD doth build up Jerusalem: he gathereth together the outcasts of Israel."},"BSB":{"text":"The LORD builds up Jerusalem; He gathers the exiles of Israel."}},"definableWords":["LORD","Jerusalem","Israel"],"peopleInVerse":[]},"3":{"text":"He healeth the broken in heart, and bindeth up their wounds.","ref":"Psalms 147:3","synthesized":"He heals the brokenhearted and binds up their wounds.","sources":{"KJV":{"text":"He healeth the broken in heart, and bindeth up their wounds."},"BSB":{"text":"He heals the brokenhearted and binds up their wounds."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"He telleth the number of the stars; he calleth them all by their names.","ref":"Psalms 147:4","synthesized":"He determines the number of the stars; He calls them each by name.","sources":{"KJV":{"text":"He telleth the number of the stars; he calleth them all by their names."},"BSB":{"text":"He determines the number of the stars; He calls them each by name."}},"definableWords":["name"],"peopleInVerse":[]},"5":{"text":"Great is our Lord, and of great power: his understanding is infinite.","ref":"Psalms 147:5","synthesized":"Great is our Lord, and mighty in power; His understanding has no limit.","sources":{"KJV":{"text":"Great is our Lord, and of great power: his understanding is infinite."},"BSB":{"text":"Great is our Lord, and mighty in power; His understanding has no limit."}},"definableWords":["great","Lord","mighty"],"peopleInVerse":[]},"6":{"text":"The LORD lifteth up the meek: he casteth the wicked down to the ground.","ref":"Psalms 147:6","synthesized":"The LORD sustains the humble, but casts the wicked to the ground.","sources":{"KJV":{"text":"The LORD lifteth up the meek: he casteth the wicked down to the ground."},"BSB":{"text":"The LORD sustains the humble, but casts the wicked to the ground."}},"definableWords":["LORD","ground"],"peopleInVerse":[]},"7":{"text":"Sing unto the LORD with thanksgiving; sing praise upon the harp unto our God:","ref":"Psalms 147:7","synthesized":"Sing to the LORD with thanksgiving; make music on the harp to our God,","sources":{"KJV":{"text":"Sing unto the LORD with thanksgiving; sing praise upon the harp unto our God:"},"BSB":{"text":"Sing to the LORD with thanksgiving; make music on the harp to our God,"}},"definableWords":["LORD","make","God"],"peopleInVerse":[]},"8":{"text":"Who covereth the heaven with clouds, who prepareth rain for the earth, who maketh grass to grow upon the mountains.","ref":"Psalms 147:8","synthesized":"who covers the sky with clouds, who prepares rain for the earth, who makes grass to grow on the hills.","sources":{"KJV":{"text":"Who covereth the heaven with clouds, who prepareth rain for the earth, who maketh grass to grow upon the mountains."},"BSB":{"text":"who covers the sky with clouds, who prepares rain for the earth, who makes grass to grow on the hills."}},"definableWords":["earth"],"peopleInVerse":[]},"9":{"text":"He giveth to the beast his food, and to the young ravens which cry.","ref":"Psalms 147:9","synthesized":"He provides food for the animals, and for the young ravens when they call.","sources":{"KJV":{"text":"He giveth to the beast his food, and to the young ravens which cry."},"BSB":{"text":"He provides food for the animals, and for the young ravens when they call."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"He delighteth not in the strength of the horse: he taketh not pleasure in the legs of a man.","ref":"Psalms 147:10","synthesized":"He does not delight in the strength of the horse; He takes no pleasure in the legpower of the man.","sources":{"KJV":{"text":"He delighteth not in the strength of the horse: he taketh not pleasure in the legs of a man."},"BSB":{"text":"He does not delight in the strength of the horse; He takes no pleasure in the legpower of the man."}},"definableWords":["man"],"peopleInVerse":[]},"11":{"text":"The LORD taketh pleasure in them that fear him, in those that hope in his mercy.","ref":"Psalms 147:11","synthesized":"The LORD is pleased with those who fear Him, who hope in His loving devotion.","sources":{"KJV":{"text":"The LORD taketh pleasure in them that fear him, in those that hope in his mercy."},"BSB":{"text":"The LORD is pleased with those who fear Him, who hope in His loving devotion."}},"definableWords":["LORD","fear","hope"],"peopleInVerse":[]},"12":{"text":"Praise the LORD, O Jerusalem; praise thy God, O Zion.","ref":"Psalms 147:12","synthesized":"Exalt the LORD, O Jerusalem; praise your God, O Zion!","sources":{"KJV":{"text":"Praise the LORD, O Jerusalem; praise thy God, O Zion."},"BSB":{"text":"Exalt the LORD, O Jerusalem; praise your God, O Zion!"}},"definableWords":["LORD","Jerusalem","praise","God","Zion"],"peopleInVerse":[]},"13":{"text":"For he hath strengthened the bars of thy gates; he hath blessed thy children within thee.","ref":"Psalms 147:13","synthesized":"For He strengthens the bars of your gates and blesses the children within you.","sources":{"KJV":{"text":"For he hath strengthened the bars of thy gates; he hath blessed thy children within thee."},"BSB":{"text":"For He strengthens the bars of your gates and blesses the children within you."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"He maketh peace in thy borders, and filleth thee with the finest of the wheat.","ref":"Psalms 147:14","synthesized":"He makes peace at your borders; He fills you with the finest wheat.","sources":{"KJV":{"text":"He maketh peace in thy borders, and filleth thee with the finest of the wheat."},"BSB":{"text":"He makes peace at your borders; He fills you with the finest wheat."}},"definableWords":["peace"],"peopleInVerse":[]},"15":{"text":"He sendeth forth his commandment upon earth: his word runneth very swiftly.","ref":"Psalms 147:15","synthesized":"He sends forth His command to the earth; His word runs swiftly.","sources":{"KJV":{"text":"He sendeth forth his commandment upon earth: his word runneth very swiftly."},"BSB":{"text":"He sends forth His command to the earth; His word runs swiftly."}},"definableWords":["earth","word"],"peopleInVerse":[]},"16":{"text":"He giveth snow like wool: he scattereth the hoarfrost like ashes.","ref":"Psalms 147:16","synthesized":"He spreads the snow like wool; He scatters the frost like ashes;","sources":{"KJV":{"text":"He giveth snow like wool: he scattereth the hoarfrost like ashes."},"BSB":{"text":"He spreads the snow like wool; He scatters the frost like ashes;"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"He casteth forth his ice like morsels: who can stand before his cold?","ref":"Psalms 147:17","synthesized":"He casts forth His hail like pebbles. Who can withstand His icy blast?","sources":{"KJV":{"text":"He casteth forth his ice like morsels: who can stand before his cold?"},"BSB":{"text":"He casts forth His hail like pebbles. Who can withstand His icy blast?"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"He sendeth out his word, and melteth them: he causeth his wind to blow, and the waters flow.","ref":"Psalms 147:18","synthesized":"He sends forth His word and melts them; He unleashes His winds, and the waters flow.","sources":{"KJV":{"text":"He sendeth out his word, and melteth them: he causeth his wind to blow, and the waters flow."},"BSB":{"text":"He sends forth His word and melts them; He unleashes His winds, and the waters flow."}},"definableWords":["word","waters"],"peopleInVerse":[]},"19":{"text":"He sheweth his word unto Jacob, his statutes and his judgments unto Israel.","ref":"Psalms 147:19","synthesized":"He declares His word to Jacob, His statutes and judgments to Israel.","sources":{"KJV":{"text":"He sheweth his word unto Jacob, his statutes and his judgments unto Israel."},"BSB":{"text":"He declares His word to Jacob, His statutes and judgments to Israel."}},"definableWords":["word","Jacob","Israel"],"peopleInVerse":["Jacob"]},"20":{"text":"He hath not dealt so with any nation: and as for his judgments, they have not known them. Praise ye the LORD.","ref":"Psalms 147:20","synthesized":"He has done this for no other nation; they do not know His judgments.   Hallelujah!","sources":{"KJV":{"text":"He hath not dealt so with any nation: and as for his judgments, they have not known them. Praise ye the LORD."},"BSB":{"text":"He has done this for no other nation; they do not know His judgments.   Hallelujah!"}},"definableWords":["nation"],"peopleInVerse":[]}}},"148":{"chapter":"148","title":"PRAISE YE THE LORD FROM THE HEAVENS","verses":{"1":{"text":"Praise ye the LORD. Praise ye the LORD from the heavens: praise him in the heights.","ref":"Psalms 148:1","synthesized":"Hallelujah!   Praise the LORD from the heavens; praise Him in the highest places.","sources":{"KJV":{"text":"Praise ye the LORD. Praise ye the LORD from the heavens: praise him in the heights."},"BSB":{"text":"Hallelujah!   Praise the LORD from the heavens; praise Him in the highest places."}},"definableWords":["praise","LORD","heavens"],"peopleInVerse":[]},"2":{"text":"Praise ye him, all his angels: praise ye him, all his hosts.","ref":"Psalms 148:2","synthesized":"Praise Him, all His angels; praise Him, all His heavenly hosts.","sources":{"KJV":{"text":"Praise ye him, all his angels: praise ye him, all his hosts."},"BSB":{"text":"Praise Him, all His angels; praise Him, all His heavenly hosts."}},"definableWords":["praise"],"peopleInVerse":[]},"3":{"text":"Praise ye him, sun and moon: praise him, all ye stars of light.","ref":"Psalms 148:3","synthesized":"Praise Him, O sun and moon; praise Him, all you shining stars.","sources":{"KJV":{"text":"Praise ye him, sun and moon: praise him, all ye stars of light."},"BSB":{"text":"Praise Him, O sun and moon; praise Him, all you shining stars."}},"definableWords":["praise"],"peopleInVerse":[]},"4":{"text":"Praise him, ye heavens of heavens, and ye waters that be above the heavens.","ref":"Psalms 148:4","synthesized":"Praise Him, O highest heavens, and you waters above the skies.","sources":{"KJV":{"text":"Praise him, ye heavens of heavens, and ye waters that be above the heavens."},"BSB":{"text":"Praise Him, O highest heavens, and you waters above the skies."}},"definableWords":["praise","heavens","waters"],"peopleInVerse":[]},"5":{"text":"Let them praise the name of the LORD: for he commanded, and they were created.","ref":"Psalms 148:5","synthesized":"Let them praise the name of the LORD, for He gave the command and they were created.","sources":{"KJV":{"text":"Let them praise the name of the LORD: for he commanded, and they were created."},"BSB":{"text":"Let them praise the name of the LORD, for He gave the command and they were created."}},"definableWords":["praise","name","LORD","created"],"peopleInVerse":[]},"6":{"text":"He hath also stablished them for ever and ever: he hath made a decree which shall not pass.","ref":"Psalms 148:6","synthesized":"He established them forever and ever; He issued a decree that will never pass away.","sources":{"KJV":{"text":"He hath also stablished them for ever and ever: he hath made a decree which shall not pass."},"BSB":{"text":"He established them forever and ever; He issued a decree that will never pass away."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Praise the LORD from the earth, ye dragons, and all deeps:","ref":"Psalms 148:7","synthesized":"Praise the LORD from the earth, all great sea creatures and ocean depths,","sources":{"KJV":{"text":"Praise the LORD from the earth, ye dragons, and all deeps:"},"BSB":{"text":"Praise the LORD from the earth, all great sea creatures and ocean depths,"}},"definableWords":["praise","LORD","earth","great","sea"],"peopleInVerse":[]},"8":{"text":"Fire, and hail; snow, and vapours; stormy wind fulfilling his word:","ref":"Psalms 148:8","synthesized":"lightning and hail, snow and clouds, powerful wind fulfilling His word,","sources":{"KJV":{"text":"Fire, and hail; snow, and vapours; stormy wind fulfilling his word:"},"BSB":{"text":"lightning and hail, snow and clouds, powerful wind fulfilling His word,"}},"definableWords":["word"],"peopleInVerse":[]},"9":{"text":"Mountains, and all hills; fruitful trees, and all cedars:","ref":"Psalms 148:9","synthesized":"mountains and all hills, fruit trees and all cedars,","sources":{"KJV":{"text":"Mountains, and all hills; fruitful trees, and all cedars:"},"BSB":{"text":"mountains and all hills, fruit trees and all cedars,"}},"definableWords":["trees"],"peopleInVerse":[]},"10":{"text":"Beasts, and all cattle; creeping things, and flying fowl:","ref":"Psalms 148:10","synthesized":"wild animals and all cattle, crawling creatures and flying birds,","sources":{"KJV":{"text":"Beasts, and all cattle; creeping things, and flying fowl:"},"BSB":{"text":"wild animals and all cattle, crawling creatures and flying birds,"}},"definableWords":["cattle","birds"],"peopleInVerse":[]},"11":{"text":"Kings of the earth, and all people; princes, and all judges of the earth:","ref":"Psalms 148:11","synthesized":"kings of the earth and all peoples, princes and all rulers of the earth,","sources":{"KJV":{"text":"Kings of the earth, and all people; princes, and all judges of the earth:"},"BSB":{"text":"kings of the earth and all peoples, princes and all rulers of the earth,"}},"definableWords":["kings","earth"],"peopleInVerse":[]},"12":{"text":"Both young men, and maidens; old men, and children:","ref":"Psalms 148:12","synthesized":"young men and maidens, old and young together.","sources":{"KJV":{"text":"Both young men, and maidens; old men, and children:"},"BSB":{"text":"young men and maidens, old and young together."}},"definableWords":["men"],"peopleInVerse":[]},"13":{"text":"Let them praise the name of the LORD: for his name alone is excellent; his glory is above the earth and heaven.","ref":"Psalms 148:13","synthesized":"Let them praise the name of the LORD, for His name alone is exalted; His splendor is above the earth and the heavens.","sources":{"KJV":{"text":"Let them praise the name of the LORD: for his name alone is excellent; his glory is above the earth and heaven."},"BSB":{"text":"Let them praise the name of the LORD, for His name alone is exalted; His splendor is above the earth and the heavens."}},"definableWords":["praise","name","LORD","earth","heavens"],"peopleInVerse":[]},"14":{"text":"He also exalteth the horn of his people, the praise of all his saints; even of the children of Israel, a people near unto him. Praise ye the LORD.","ref":"Psalms 148:14","synthesized":"He has raised up a horn for His people, the praise of all His saints, of Israel, a people near to Him.   Hallelujah!","sources":{"KJV":{"text":"He also exalteth the horn of his people, the praise of all his saints; even of the children of Israel, a people near unto him. Praise ye the LORD."},"BSB":{"text":"He has raised up a horn for His people, the praise of all His saints, of Israel, a people near to Him.   Hallelujah!"}},"definableWords":["people","praise","Israel"],"peopleInVerse":[]}}},"149":{"chapter":"149","title":"SING UNTO THE LORD A NEW SONG (III)","verses":{"1":{"text":"Praise ye the LORD. Sing unto the LORD a new song, and his praise in the congregation of saints.","ref":"Psalms 149:1","synthesized":"Hallelujah!   Sing to the LORD a new song— His praise in the assembly of the godly.","sources":{"KJV":{"text":"Praise ye the LORD. Sing unto the LORD a new song, and his praise in the congregation of saints."},"BSB":{"text":"Hallelujah!   Sing to the LORD a new song— His praise in the assembly of the godly."}},"definableWords":["LORD","praise"],"peopleInVerse":[]},"2":{"text":"Let Israel rejoice in him that made him: let the children of Zion be joyful in their King.","ref":"Psalms 149:2","synthesized":"Let Israel rejoice in their Maker; let the children of Zion rejoice in their King.","sources":{"KJV":{"text":"Let Israel rejoice in him that made him: let the children of Zion be joyful in their King."},"BSB":{"text":"Let Israel rejoice in their Maker; let the children of Zion rejoice in their King."}},"definableWords":["Israel","Zion","King"],"peopleInVerse":[]},"3":{"text":"Let them praise his name in the dance: let them sing praises unto him with the timbrel and harp.","ref":"Psalms 149:3","synthesized":"Let them praise His name with dancing, and make music to Him with tambourine and harp.","sources":{"KJV":{"text":"Let them praise his name in the dance: let them sing praises unto him with the timbrel and harp."},"BSB":{"text":"Let them praise His name with dancing, and make music to Him with tambourine and harp."}},"definableWords":["praise","name","make"],"peopleInVerse":[]},"4":{"text":"For the LORD taketh pleasure in his people: he will beautify the meek with salvation.","ref":"Psalms 149:4","synthesized":"For the LORD takes pleasure in His people; He adorns the afflicted with salvation.","sources":{"KJV":{"text":"For the LORD taketh pleasure in his people: he will beautify the meek with salvation."},"BSB":{"text":"For the LORD takes pleasure in His people; He adorns the afflicted with salvation."}},"definableWords":["LORD","people","salvation"],"peopleInVerse":[]},"5":{"text":"Let the saints be joyful in glory: let them sing aloud upon their beds.","ref":"Psalms 149:5","synthesized":"Let the saints exult in glory; let them shout for joy upon their beds.","sources":{"KJV":{"text":"Let the saints be joyful in glory: let them sing aloud upon their beds."},"BSB":{"text":"Let the saints exult in glory; let them shout for joy upon their beds."}},"definableWords":["glory","joy"],"peopleInVerse":[]},"6":{"text":"Let the high praises of God be in their mouth, and a two-edged sword in their hand;","ref":"Psalms 149:6","synthesized":"May the high praises of God be in their mouths, and a double-edged sword in their hands,","sources":{"KJV":{"text":"Let the high praises of God be in their mouth, and a two-edged sword in their hand;"},"BSB":{"text":"May the high praises of God be in their mouths, and a double-edged sword in their hands,"}},"definableWords":["God"],"peopleInVerse":[]},"7":{"text":"To execute vengeance upon the heathen, and punishments upon the people;","ref":"Psalms 149:7","synthesized":"to inflict vengeance on the nations and punishment on the peoples,","sources":{"KJV":{"text":"To execute vengeance upon the heathen, and punishments upon the people;"},"BSB":{"text":"to inflict vengeance on the nations and punishment on the peoples,"}},"definableWords":["nations"],"peopleInVerse":[]},"8":{"text":"To bind their kings with chains, and their nobles with fetters of iron;","ref":"Psalms 149:8","synthesized":"to bind their kings with chains and their nobles with shackles of iron,","sources":{"KJV":{"text":"To bind their kings with chains, and their nobles with fetters of iron;"},"BSB":{"text":"to bind their kings with chains and their nobles with shackles of iron,"}},"definableWords":["kings"],"peopleInVerse":[]},"9":{"text":"To execute upon them the judgment written: this honour have all his saints. Praise ye the LORD.","ref":"Psalms 149:9","synthesized":"to execute the judgment written against them. This honor is for all His saints.   Hallelujah!","sources":{"KJV":{"text":"To execute upon them the judgment written: this honour have all his saints. Praise ye the LORD."},"BSB":{"text":"to execute the judgment written against them. This honor is for all His saints.   Hallelujah!"}},"definableWords":["judgment"],"peopleInVerse":[]}}},"150":{"chapter":"150","title":"PRAISE YE THE LORD","verses":{"1":{"text":"Praise ye the LORD. Praise God in his sanctuary: praise him in the firmament of his power.","ref":"Psalms 150:1","synthesized":"Hallelujah!   Praise God in His sanctuary. Praise Him in His mighty heavens.","sources":{"KJV":{"text":"Praise ye the LORD. Praise God in his sanctuary: praise him in the firmament of his power."},"BSB":{"text":"Hallelujah!   Praise God in His sanctuary. Praise Him in His mighty heavens."}},"definableWords":["praise","God","mighty","heavens"],"peopleInVerse":[]},"2":{"text":"Praise him for his mighty acts: praise him according to his excellent greatness.","ref":"Psalms 150:2","synthesized":"Praise Him for His mighty acts; praise Him for His excellent greatness.","sources":{"KJV":{"text":"Praise him for his mighty acts: praise him according to his excellent greatness."},"BSB":{"text":"Praise Him for His mighty acts; praise Him for His excellent greatness."}},"definableWords":["praise","mighty"],"peopleInVerse":[]},"3":{"text":"Praise him with the sound of the trumpet: praise him with the psaltery and harp.","ref":"Psalms 150:3","synthesized":"Praise Him with the sound of the horn; praise Him with the harp and lyre.","sources":{"KJV":{"text":"Praise him with the sound of the trumpet: praise him with the psaltery and harp."},"BSB":{"text":"Praise Him with the sound of the horn; praise Him with the harp and lyre."}},"definableWords":["praise"],"peopleInVerse":[]},"4":{"text":"Praise him with the timbrel and dance: praise him with stringed instruments and organs.","ref":"Psalms 150:4","synthesized":"Praise Him with tambourine and dancing; praise Him with strings and flute.","sources":{"KJV":{"text":"Praise him with the timbrel and dance: praise him with stringed instruments and organs."},"BSB":{"text":"Praise Him with tambourine and dancing; praise Him with strings and flute."}},"definableWords":["praise"],"peopleInVerse":[]},"5":{"text":"Praise him upon the loud cymbals: praise him upon the high sounding cymbals.","ref":"Psalms 150:5","synthesized":"Praise Him with clashing cymbals; praise Him with resounding cymbals.","sources":{"KJV":{"text":"Praise him upon the loud cymbals: praise him upon the high sounding cymbals."},"BSB":{"text":"Praise Him with clashing cymbals; praise Him with resounding cymbals."}},"definableWords":["praise"],"peopleInVerse":[]},"6":{"text":"Let every thing that hath breath praise the LORD. Praise ye the LORD.","ref":"Psalms 150:6","synthesized":"Let everything that has breath praise the LORD!   Hallelujah!","sources":{"KJV":{"text":"Let every thing that hath breath praise the LORD. Praise ye the LORD."},"BSB":{"text":"Let everything that has breath praise the LORD!   Hallelujah!"}},"definableWords":["breath","praise","LORD"],"peopleInVerse":[]}}}};